window.GENERALS = [{"id": 0, "name": "諸葛亮", "faction": 0, "role": "軍師参謀", "rarity": 5, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 3, 0, 6, 10, 10, 10], "p": [10, 7, 10, 10, 6, 10], "scores": {"W": 1.65, "B": 8.9, "S": 9.8, "A": 9.6, "G": 8.88, "K": 8.2}, "stat": {"dmg": 2.41, "area": 1.5, "cd": 0.96, "amount": 2, "knock": 0.89, "crit": 0.11, "duration": 5.0, "pwr": 9.6}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [39, 43, 46, 85, 87, 88, 89, 90, 99, 100], "chapN": 104, "bio": "劉備の軍師、舌戦群儒・草船借箭・借東風を演じる", "profile": "蜀漢の軍師にして丞相、字は孔明。臥龍の号を持ち、徐庶は「経天緯地の才、蓋し天下一人」と評し、司馬徽は彼を太公望や張良になぞらえた。だが演義の諸葛亮は終始一度として白兵に加わらない。常に綸巾に羽扇、道袍を身につけ車上に端坐して軍を指揮する、純然たる頭脳の人である。武勇の称号ではなく、智への称号を一身に集めた稀有な英雄として描かれる。\n\nその智謀は出廬前から際立つ。第三十八回、いまだ茅廬を出ぬ身でありながら、荊州・益州を跨ぎ、西は諸戎と和し南は彝越を撫で、外は孫権と結んで内は政理を修め、天下に変あらば一上将を宛・洛へ向かわせ、自らは益州の衆を率いて秦川に出るという天下三分の大構想を完成させる。劉備は図を示されて「頓開茅塞」と教わる側に回り、本文は「未だ茅廬を出でずして已に三分天下を知る、真に万古の人の及ばざるなり」と断じる。やがて第三十九回の博望坡では火計をもって初陣を飾り、第四十三回には舌戦群儒で張昭以下二十余名の江東文官を悉く論破し、孫権を抗曹へ踏み切らせて孫劉同盟を成立させる。赤壁を経て、第九十回の七擒七縦では孟獲を七たび擒えて七たび放ち、ついに南蛮を心服させて二度と叛かせなかった。第九十五回には空城計で焚香操琴のまま司馬懿の十五万を退け、第百二回では木牛流馬を発明して剣閣の険路に昼夜途切れぬ兵糧を通す。\n\n性格は冷静沈着、智謀の極みにありながら統治と人心掌握をも兼ねる。劍印を授かれば関羽・張飛も令に服し、鄧芝の意中を一瞬で見抜いて対呉の使者に抜擢した。一方で先帝が「不可大用」と戒めた馬謖をあえて用い、街亭を失う誤りも犯す。第八十五回、白帝城で劉備から「君才は曹丕に十倍す。もし嗣子輔くべくんば之を輔け、如し其れ不才ならば、君自ら成都の主と為れ」と託されると、「臣安んぞ敢えて股肱の力を竭くし、忠貞の節を効し、之を継ぐに死を以てせざらんや」と涙して誓った。直後には曹丕の五路五十万の侵攻を一人で読み切り、一兵も動かさず退ける。\n\n第九十一回の出師表では「親賢臣、遠小人」を国是として掲げ、蜀の法治と統治の原則を制度として遺した。そしてその死後すらなお、第百四回では木像を車に据えただけで司馬懿を「大驚失色」させて敗走させ、「死せる諸葛、生ける仲達を走らす」という諺を後世に残す。武の逸話を一切持たぬまま、戦術・戦略・統治・外交・危機管理のすべてで演義最高の密度を与えられた、智の化身そのものである。"}, {"id": 1, "name": "呂布", "faction": 3, "role": "武将", "rarity": 5, "weapon": "halberd", "kind": "orbit", "weaponName": "戟", "d": [9, 10, 9, 10, 3, 2, 1], "p": [1, 1, 1, 2, 1, 1], "scores": {"W": 9.3, "B": 3.3, "S": 2.55, "A": 3.1, "G": 1.15, "K": 1.0}, "stat": {"dmg": 2.35, "area": 1.46, "cd": 0.87, "amount": 1, "knock": 1.73, "crit": 0.15, "duration": 0, "pwr": 9.25}, "title": "戟の将", "skill": "戟", "skillDesc": "周囲を旋回する刃で薙ぐ", "voice": "", "hist": "", "chapters": [5, 8, 9, 11, 12, 13, 14, 15, 16, 17], "chapN": 28, "bio": "既に滅んだ群雄、曹操が擒にした強敵として言及される", "profile": "字は奉先、群雄の一人にして演義最強の武人。方天画戟を手に赤兎馬を駆り、「人中に呂布有り、馬中に赤兎有り」と謳われた。三叉束髪の紫金冠、獣面呑頭の連環鎧、弓箭を帯び画戟を持つその姿は、演義が描く武の極北そのものである。\n\n第五回、虎牢関の戦いがその武勇の絶頂を映す。河内の名将方悦を「両馬相交わること五合無くして、呂布の一戟に馬下に刺さる」と即殺し、穆順を突き伏せ、武安国の手腕を斬り落とす。やがて劉備・関羽・張飛の三英を同時に相手取ってなお敗れず、五路の諸侯が会して「呂布英雄、人の敵すべき無し」と慄き、八路の諸侯が一斉に当たってようやく退けた。第十六回の轅門射戟では、満を扯いて百五十歩先の戟の枝を射抜き、紀霊と劉備の手を執って「此れ天の汝両家をして兵を罷めしむるなり」と争いを解く。腕一本で戦を止めた、彼らしい解決であった。\n\nだが将としての呂布は、本文が「勇にして謀無く、利を見て義を忘れ、反覆して信無し」と断じる空洞である。陳宮という良謀の士を抱えながら、濮陽でも下邳でもその献策を退け、妻妾の涙に三日逡巡して掎角の計も断糧の好機もことごとく逃した。第三回では育ての主たる丁原を「布前に向かって一刀、丁原の首級を砍ち下す」、ついで義父子の誓いを結んだ董卓をも殺す。張飛が罵った「三姓家奴」の四字が、その生き方を言い尽くしている。\n\n第十九回、下邳に籠もるうち、布は配下を草芥のごとく扱い侯成を笞打った。怨みを抱いた宋憲・魏続・侯成は画戟と赤兎馬を盗み、眠る布を縛って曹操に献じた。「我、諸将を待つこと薄からず、汝等何ぞ忍びて背反するや」と問うても、もはや遅い。武の頂点に立ちながら、人を御す心を一片も持たなかったがために、最強の戟は自らの手から離れて地に落ちたのである。"}, {"id": 2, "name": "曹操", "faction": 1, "role": "君主", "rarity": 5, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [4, 3, 1, 5, 9, 10, 10], "p": [10, 10, 8, 5, 9, 9], "scores": {"W": 3.15, "B": 8.7, "S": 9.5, "A": 9.15, "G": 8.64, "K": 9.55}, "stat": {"dmg": 1.33, "area": 0.98, "cd": 0.87, "amount": 2, "knock": 0.91, "crit": 0.1, "duration": 0, "pwr": 3.05}, "title": "君主", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [21, 22, 25, 30, 43, 58, 59, 60, 67, 68], "chapN": 114, "bio": "百万を号する大軍を率い赤壁で大敗する権臣", "profile": "魏の君主、字は孟徳。許劭に人物を問うて「子は治世の能臣、乱世の奸雄なり」と評され、その言を聞いて大いに喜んだ男である。世人もまた「孟徳は奸雄」と口を揃え、彼に与えられた称号はつねに猛将や万人之敵ではなく、智謀と権謀の語であった。第一回で青州黄巾を相手に「斬首万余級」と書かれるのも麾下軍の戦果であり、名将を一騎打ちで斬る描写は演義全篇を通じて一つも無い。曹操の強さは個人の武ではなく、戦術・戦略・統率・人材登用に集約される。\n\nその戦略眼は天下を見渡す。第十四回、荀彧の進言を容れて天子を許都に迎え「天子を奉じて以て衆望に従う」を実行し、以後「天子を挟みて諸侯に令す」を全戦略の根幹に据えた。第二十一回の煮酒論英雄では袁紹・劉表・孫策を一刀両断し、「今天下の英雄は、惟だ使君と操とのみ」と劉備に向かって看破する。戦場でもその冴えは際立つ。第三十回の官渡では、敵方の謀士許攸が降ると履も履かず跣足で迎え地に拝し、その献策で烏巣を夜襲して兵糧を焼き、勝敗を逆転させた。勝利の後には袁紹への内通書簡を「紹の強きに当たりては、孤も亦た自ら保つ能わず、況んや他人をや」と言ってすべて焼き捨て、人心を収攬する。第五十九回の潼関では、韓遂と陣前で旧交を語り、抹書の計と合わせて馬超と韓遂を内部から分裂させ一挙に撃破した。\n\n統率にかけては演義屈指である。第十七回、自らの馬が麦を踏むと「吾自ら法を制し、吾自ら之を犯す」と言い、剣を抜いて自らの髪を斬り「髪を割きて権に首に代う」と三軍に示した。これに全軍は悚然として軍令に懍み従う。降った張郃・高覧を「微子の殷を去り、韓信の漢に帰するがごとし」と称えて偏将軍に封じ、沮授を惜しんで「吾若し早く足下を得ば、天下慮るに足らず」と嘆いた。敵将・降人を吸収する度量は群を抜く。北征の後には屯田を恒常的制度として運用し、覇府を奉天子から魏公、魏王、九錫へと段階を踏んで整え、国家機構を一つひとつ築き上げた。\n\nもっとも、その曹操も戦場では幾度も命からがら逃げる側であった。濮陽・宛城・潼関・漢中で危地に陥り、第七十二回では魏延の矢を受けて「操、身を翻して馬より落つ」と討たれかけている。臨終には曹洪・陳群・賈詡・司馬懿を枕頭に集め、四子の資質を冷徹に評して長子曹丕を後継と定めた。ただ一つ、三馬同槽の夢に示された司馬懿の野心だけは見抜けなかった。武勇の英雄ではなく、智謀と権謀をもって乱世を制した稀代の能臣にして奸雄、それが演義の曹操である。"}, {"id": 3, "name": "関羽", "faction": 0, "role": "武将", "rarity": 5, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [10, 10, 7, 9, 8, 6, 6], "p": [4, 3, 2, 3, 6, 2], "scores": {"W": 9.15, "B": 7.45, "S": 6.65, "A": 7.0, "G": 3.31, "K": 4.5}, "stat": {"dmg": 2.31, "area": 1.36, "cd": 0.7, "amount": 2, "knock": 1.54, "crit": 0.14, "duration": 0, "pwr": 9.0}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [25, 26, 27, 28, 50, 53, 66, 73, 74, 75], "chapN": 61, "bio": "劉備配下の猛将。長沙で黄忠を義釈し襄陽を取る", "profile": "蜀漢の猛将、字は雲長。八十二斤の青龍偃月刀を舞わせ、忠義と武勇を一身に体現する武神である。程昱は開口一番「雲長は万人の敵あり、智謀に非ざれば取る能わず」と評し、曹操は「将軍は真に神人なり」と讃え、孫権は「雲長は世の豪傑」と呼んだ。演義が個人の武勇に与えた称号の格は、呂布の「人中呂布」と並ぶ三国最上級である。\n\nその武の名場面は枚挙にいとまがない。第五回では温めた酒の冷めぬ間に華雄を斬って帰り、第二十五回では十万の河北軍の中へ単騎で突入し、上将顔良を一刀で刺殺、首級を取って「無人の境に入るが如し」と帰還する。続く第二十六回には文醜を「脳後一刀、文醜を斬りて馬下に下す」、第二十七回には過五関斬六将と、名将を討つ密度は演義最高峰を極める。第七十四回の水淹七軍では、于禁の七軍が低地罾口川に屯したのを見て各所の水口に堰を設け、襄江の増水を利して七軍を全滅させた。骨を矢毒に侵された折には、医者に骨を削らせながら「酒を飲み肉を食らい、談笑して棋を弈つ」という尋常ならざる豪胆も見せている。\n\nその武は神域に達したが、本文は同時に彼の強烈な驕りと統率の脆さを容赦なく描く。第七十三回、黄忠との同列を拒んで「大丈夫終に老卒と伍を為さず」と前将軍の印を一度は受けず、第七十五回では陸遜の卑謹な書を「仰面大笑」して油断し、荊州の守備兵を樊城へ抜いてしまう。後方の糜芳・傅士仁を「去る日吾を恨む」と遇さず離反させ、第七十六回には麦城手前で荊州の士卒が「兄を呼び弟を喚び、子を覓め爺を尋ね」、軍心ことごとく変じて応声して去り、三百余人にまで激減した。\n\n最期、孫権の降伏勧告を「玉は砕くべくして其の白を改むべからず、竹は焚くべくして其の節を毀つべからず」と拒んで死す。降漢不降曹の三事を守り、封金挂印して曹操の厚遇を捨てた、その義の貫きが死をもって完結した瞬間であった。武の頂点と将才の致命的欠陥とを同じ一身に抱えながら、なお漢室への忠義の象徴として後世に祀られ続ける――それが演義の関羽である。"}, {"id": 4, "name": "張飛", "faction": 0, "role": "武将", "rarity": 5, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [9, 10, 7, 10, 7, 3, 4], "p": [1, 2, 1, 1, 3, 2], "scores": {"W": 8.8, "B": 6.0, "S": 4.45, "A": 5.15, "G": 1.58, "K": 2.55}, "stat": {"dmg": 2.25, "area": 1.38, "cd": 0.78, "amount": 2, "knock": 1.58, "crit": 0.15, "duration": 0, "pwr": 8.65}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [1, 2, 14, 22, 28, 42, 52, 63, 64, 65], "chapN": 58, "bio": "劉備配下の猛将、長板橋で曹軍を一喝で退ける", "profile": "蜀漢の猛将、字は翼徳。丈八の蛇矛を造り、声は巨雷の若く、勢いは奔馬の如し。豹頭環眼、燕頷虎鬚の容貌が示す通りの猛々しさを誇る、桃園の義の末弟である。第四十二回、当陽橋でその名を聞いた曹操は、関羽の言を引いて「翼徳は百万軍中に上将の首を取ること、嚢中の物を探るが如し」と評し、軽々に敵すべからずと配下を戒めた。総帥がこの語で警戒するのは、呂布の「人中呂布」に並ぶ扱いである。\n\n通説の張飛は酒乱粗暴の猛将一辺倒だが、演義はその二面を鮮やかに描き分ける。武勇の極致は当陽橋の一喝にある。第四十二回、橋上に立ち塞がって張飛が吼えると、「曹軍之を聞きて尽く股栗し」、曹操の傍らの夏侯傑は「驚きて肝胆砕裂し、馬下に倒れ撞つ」。これに曹操は馬を返して走り、諸軍ことごとく西へ逃げ奔った。一声で百万の軍を退かせた、演義恐怖の頂点である。一方で第六十三回には嚴顔を「賣個破綻(わざと隙を見せて)」、一合で扯み捕って生擒し、その義気に感じ入った嚴顔を心服させて降した。第七十回の瓦口隘では偽の泥酔を演じて張郃を誘い出し草人の罠で撃破、孔明をして「此れ貪盃に非ず、乃ち張郃を敗る計なり」「能く謀を用う」と賀せしめている。「粗にして謀あり」――それが本文の張飛である。\n\nその統率には、しかし致命的な負の影がつきまとう。劉備自身が「你、一には酒後剛強にして士卒を鞭打し、二には事を作すこと軽易にして人の諫めに従わず」とその欠陥を明言した。第十四回には酒で曹豹を鞭打ちして徐州を失い、第八十一回でも「酒後暴怒、健児を鞭撻す」と諫められた直後に范彊・張達を鞭打つ。\n\nその最期は、まさにこの欠陥の帰結であった。怨みを抱いた二人は、鬚を逆立て目を張る張飛を前に手を出せずにいたが、雷の如き鼾を聞いてようやく近づき、短刀を腹に刺し入れた。「飛、大叫一声して亡ず」。閬中の車騎将軍にまで上り詰めた剛の将は、自らの身辺の危機すら御せぬまま、酒の怨みに斃れたのである。武の轟きと人の機微、その両極を生きた英雄であった。"}, {"id": 5, "name": "許褚", "faction": 1, "role": "武将", "rarity": 5, "weapon": "mace", "kind": "nova", "weaponName": "剛", "d": [9, 8, 10, 7, 3, 1, 4], "p": [1, 1, 1, 1, 3, 3], "scores": {"W": 8.85, "B": 3.75, "S": 2.1, "A": 2.45, "G": 1.5, "K": 2.5}, "stat": {"dmg": 2.3, "area": 1.42, "cd": 0.83, "amount": 1, "knock": 1.66, "crit": 0.12, "duration": 0, "pwr": 8.95}, "title": "剛の将", "skill": "剛", "skillDesc": "周囲を吹き飛ばす衝撃", "voice": "", "hist": "", "chapters": [12, 14, 21, 30, 31, 40, 42, 58, 59, 66], "chapN": 31, "bio": "曹操配下の猛将、護衛監戦使。長板橋で曹操を扶ける", "profile": "魏の猛将、字は仲康。曹操の身辺を守る虎衛の長であり、その剛力ゆえに全軍から「虎侯」、敵からは「虎痴」と呼ばれた。曹操は彼を「子は真に吾が樊噲なり」と讃え、護衛監戦の任を委ねた。一軍を率いる謀ではなく、ただ膂力と忠の一点で、曹操陣営に欠かせぬ存在となった男である。\n\nその怪力は演義屈指である。第十二回では「我両手にて二牛の尾を掣き、倒しまに行くこと百余歩」と、二頭の牛の尾を掴んで後ろ向きに引きずった逸話を持ち、飛石を投げれば百発百中、戦えば名将を立て続けに討つ。第十四回では李暹・李別の二将を斬り、第十七回には張先を三合で斬り、第三十一回の官渡では「力もて十数将を斬る」。その武勇の絶頂が第五十九回、馬超との一戦である。二百余合を渡り合って引き分け、ついには赤裸となって渾身の力で馬超の槍を素手で掴み折った。馬超ですら「吾、悪戦する者を見るに許褚に如くは莫し、真に虎痴なり」と恐れ入り、その威風に「敢えて動かず」となったほどである。\n\nただし、その本質はあくまで最強の親衛にして忠臣であって、方面軍の司令官ではない。計略や布陣、火攻といった会戦級の指揮の記録はなく、戦は曹操や賈詡・荀彧が立案し、許褚はその実行役を務めた。第七十二回には酔って張飛に肩を刺され、糧車を奪われるという負の一幕もある。\n\nそれでも、主君を守る一点における忠は本物であった。第六十六回、泥酔して無防備に臥す曹操の堂門を、許褚は剣を持して守り、宗族の有力者たる曹仁の入室すら遮った。「将軍は親しと雖も、乃ち外藩鎮守の官なり。許褚は疏なりと雖も、現に内侍に充つ」――内外の別をもって権限の秩序を体現し、曹操に「許褚は真に忠臣なり」と歎ぜしめる。第七十九回には虎衛軍三千を率いて臨淄を瞬時に制圧し、継承期の危機を電撃で鎮めた。軍略の人ではなく、ただ膂力と忠誠をもって主君の盾であり続けた、それが演義の許褚である。"}, {"id": 6, "name": "劉備", "faction": 0, "role": "君主", "rarity": 5, "weapon": "twin", "kind": "arc", "weaponName": "双", "d": [2, 2, 2, 2, 4, 6, 9], "p": [7, 10, 6, 5, 10, 8], "scores": {"W": 2.0, "B": 5.25, "S": 5.6, "A": 5.05, "G": 7.63, "K": 9.05}, "stat": {"dmg": 1.16, "area": 0.94, "cd": 1.01, "amount": 3, "knock": 0.84, "crit": 0.06, "duration": 0, "pwr": 2.0}, "title": "君主", "skill": "双", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [11, 16, 21, 34, 35, 36, 37, 54, 55, 60], "chapN": 108, "bio": "百姓を率いて江を渡る仁徳の主君、本バッチの中心人物", "profile": "蜀漢の君主、字は玄徳。雙股の剣を佩く仁徳の主君であり、本作の中心人物である。通説は「仁徳の君主」あるいは「泣くだけの弱将」と語るが、演義の劉備の本質は、武でも智謀でもなく、漢室の皇叔という正統性と、人を惹きつけてやまぬ人望によって立つ君主であった。\n\nその正統性は演義最強格である。第二十回、献帝が世譜を排べると劉備は帝の叔にあたり、左将軍宜城亭侯に拝され、以後「人皆な称して劉皇叔と為す」。第八十回の皇帝即位の祭文も「漢室の宗派、宜しく即ち正位すべし」を名分とし、漢室復興の大義をもって群雄と一線を画した。人望もまた屈指である。第四十一回、当陽で十数万の民が「我等死すと雖も、亦た願わくは使君に随わん」と従い、日に十余里しか進めずとも劉備は「大事を挙ぐる者は必ず人を以て本と為す。今人我に帰す、奈何ぞ之を棄てんや」と泣いて民を棄てなかった。徐庶の母すら「劉玄徳の仁義は四海に布く」と評している。\n\n人を見抜き迎える力は、第三十七回の三顧の礼に極まる。風雪を冒して三たび茅廬を訪ね、「來させればよい」と言う張飛を「孔明は当世の大賢なり、豈に召すべけんや」と叱して、自ら謙って臥龍を迎えた。入蜀の後には降将六十余人を「並びに皆な擢用」し、徐庶・龐統・法正らもその眼で見抜いて登用している。\n\nただし劉備は、大局戦略や献策の多くを孔明に依存した。天下三分の構想は第三十八回の隆中対であって、劉備は図を示されて「頓開茅塞」と教わる側であり、漢中攻略の用兵も「玄徳計を問えば、孔明曰く」と諮問する立場であった。個人の武も乏しく、第五回の三戦呂布では関羽・張飛の二人がかりに「斜裏より刺して也た来たり助戦す」と加勢する三人目に過ぎず、呂布に虚しく一戟を刺されて急ぎ身を躱す程度。袁術には「織席編屨の小輩」、曹操にも「織蓆小児」と侮られている。それでも荊州・西川を取って鼎足の一角を建国し、漢中王から皇帝へと正位を遂げた、実行の君主であった。\n\n最期は第八十五回の白帝託孤に集約される。孔明に「君才は曹丕に十倍す」と後事を託し、孔明をして「汗、遍体に流れ、叩頭して血を流す」忠誠を誓わせ、二王に「父を以て丞相に事えよ」と遺命して逝った。かつて曹操の下では「後園に菜を種え、親ら澆灌して以て韜晦の計と為す」と虎口を脱した男が、最後は人望と正統性のすべてを孔明に託して、蜀漢の未来を遺したのである。"}, {"id": 7, "name": "趙雲", "faction": 0, "role": "武将", "rarity": 5, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [10, 9, 6, 8, 6, 5, 8], "p": [3, 1, 2, 1, 5, 6], "scores": {"W": 8.6, "B": 6.85, "S": 5.7, "A": 5.8, "G": 2.74, "K": 4.65}, "stat": {"dmg": 2.22, "area": 1.29, "cd": 0.7, "amount": 2, "knock": 1.42, "crit": 0.13, "duration": 0, "pwr": 8.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [34, 41, 49, 52, 55, 61, 71, 87, 90, 92], "chapN": 50, "bio": "劉備配下の名将、長板坡で単騎阿斗を救う", "profile": "蜀漢の名将、字は子龍、常山の人。劉備配下にあって、武勇と節義をともに備えた「完璧無双の名将」と謳われる。だが演義の趙雲は単なる猛将ではない。白兵の鋭さに加え、武人の枠を超えた政道の感覚を一身に持つ、稀有な将として描かれる。\n\nその武の代表は第四十一回の長坂坡である。阿斗を懐に抱いて単騎で曹営の重囲を貫き、大旗二面を砍ち倒し槊三条を奪い、「曹営の名将五十余員を殺し死す」。これを見た曹操は「真に虎将なり、吾当に之を生致すべし」と全軍に冷箭を禁じ、生け捕りを命じたほどであった。武勇だけではない。第七十一回の漢水では空営の計を用い、寨門を閉じず旗槍を倒し金鼓を鳴らさず、ただ匹馬単槍で営門の外に立って曹操軍を自相踐踏に追い込み大勝した。劉備はこれを「子龍は一身都て是れ胆なり」と称え、虎威将軍の号を与えている。七十歳を超えた第九十二回でも韓徳の四子を独力で斬り、「独り四将を誅して来たりて陣を衝く」と老いてなお衰えぬ武威を示した。\n\n特筆すべきは、武辺の士に似合わぬその節義である。第五十二回、桂陽を得た折に樊氏との婚姻を勧められると退け、第六十五回、益州平定の後には「益州の人民、屢〻兵火に遭い、田宅皆な空し。今当に百姓に帰還し、安居復業せしむべし。宜しく奪いて私賞と為すべからず」と田宅の私賞を諫めた。そして第八十一回、伐呉に逸る先主に向かって「漢賊の讎は公なり、兄弟の讎は私なり」「願わくは天下を以て重しと為せ」と説き、討つべきは魏であって呉ではないと、国家の優先順位を進言する。武人にして政道を解する、その一語が彼の格を決定づけている。\n\n統御もまた抜群であった。第九十六回、街亭の敗退でただ独り殿軍を務め、一人一騎も損なわず軍資も失わず、孔明に「真の江軍なり」と讃えられながらも、褒賞を「三軍に尺寸の功無し、若し反って賞を受くれば、乃ち丞相の賞罰明らかならざるなり」と辞退して賞罰の公正を説いた。生涯にわたって離反の負の記録は皆無である。後主は「朕昔年幼く、子龍に非ざれば則ち乱軍の中に死せん」と、自らの存続が趙雲に拠ったことを明言した。武勇は関羽と並び、節義は群を抜き、しかも一度も主君を裏切らなかった――非の打ち所なき名将として、演義の中でひときわ清廉な輝きを放つ。"}, {"id": 8, "name": "陸遜", "faction": 2, "role": "武将", "rarity": 5, "weapon": "fire", "kind": "zone", "weaponName": "火計", "d": [2, 2, 1, 7, 10, 8, 9], "p": [4, 5, 3, 5, 3, 6], "scores": {"W": 2.25, "B": 8.5, "S": 8.55, "A": 8.65, "G": 4.28, "K": 5.2}, "stat": {"dmg": 2.26, "area": 1.42, "cd": 0.94, "amount": 2, "knock": 1.01, "crit": 0.12, "duration": 4.5, "pwr": 8.7}, "title": "火計の将", "skill": "火計", "skillDesc": "地を焼く炎を放つ", "voice": "", "hist": "", "chapters": [38, 44, 49, 50, 75, 83, 84, 85, 86, 96], "chapN": 20, "bio": "呉の若手武将、第五隊・先鋒として進軍", "profile": "呉の武将、字は伯言。孫策の女婿にして、夷陵の勝者・呉の柱石と謳われる名将である。だが演義の陸遜は徹頭徹尾「書生＝知略の人」として描かれる。一騎打ちや斬将といった個人白兵の記録は一つも無く、容貌も「身長八尺、面は美玉の如し」と書生然とした美形であって、その強さはすべて火攻と謀略、そして「忍辱負重」という指揮の心に集約される。\n\nその登場は軽侮から始まる。荊州の関羽は彼を「孺子(小僧)」「慮るに足らず」と侮り、呉の宿将たちも「一書生」と見くびった。だが陸遜は、その慢心こそを罠とした。第七十五回、卑謹を極めた書状と名馬・異錦・酒礼の贈物を樊城の関羽に遣わし、両家の和好を装って油断させ、荊州奪取の真の発案者として関羽の背後を取る。彼の名を世に轟かせたのは第八十四回の夷陵である。弱兵で誘って劉備を移営させ、韓当・周泰の軍に茅草を執らせ硫黄焔硝と火種を仕込ませて、順風に乗じて一斉に火を放った。連営七百里を焼き払い、劉備を白帝城へと追い詰めたこの一戦は、演義屈指の完成度を誇る。第九十六回の石亭でも、周魴の偽降に応じた曹休を山道に誘い込んで大破している。\n\nその将才の真価は、勝ちすぎを抑える危機管理にある。夷陵大勝の只中で深追いを断ち、「魏主曹丕、其の奸詐は父と異なる無し。今、吾が蜀兵を追趕するを知らば、必ず虚に乗じて来襲せん。吾若し深く西川に入らば、急に退き難し」と読み切って即座に班師し、現に曹丕三路の侵攻を予見して撃退した。第八十六回には曹丕四路の侵攻にも先回りの上策を献じ、孫権に「陸伯言は真に神算なり」と言わしめている。\n\nその統御の見せ場は第八十三回にある。韓当・周泰ら古参の宿将が「孺子を将とするとは、東呉休せん」と公然と不服を唱え嘲笑する最悪の初動から、陸遜は剣を握り「僕一介の書生と雖も、今主の重任を以て託さるるは、吾に尺寸の取るべき有り、能く辱を忍び重きを負うを以ての故なり」と説いて全軍を統御し、勝利をもってついに「諸将方纔(やっと)歎服」せしめた。寄せ集めの不服従の集団を、勝ちによって心服させたのである。ただ一度だけ、八陣図の前で諸葛亮に及ばぬと自認した――それが、この知略の人に演義が与えた唯一の格下げであった。"}, {"id": 9, "name": "黄忠", "faction": 0, "role": "武将", "rarity": 5, "weapon": "bow", "kind": "proj", "weaponName": "弓", "d": [9, 8, 8, 6, 7, 3, 5], "p": [1, 1, 1, 1, 2, 2], "scores": {"W": 8.25, "B": 6.05, "S": 4.35, "A": 4.8, "G": 1.25, "K": 2.25}, "stat": {"dmg": 2.13, "area": 1.28, "cd": 0.77, "amount": 2, "knock": 1.46, "crit": 0.11, "duration": 0, "pwr": 7.9}, "title": "弓の将", "skill": "弓", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [53, 62, 63, 64, 65, 70, 71, 72, 82, 83], "chapN": 23, "bio": "長沙の老将。関羽と引き分け、降って劉備配下の猛将に", "profile": "蜀漢の老将、字は漢升。もとは長沙の守将であり、関羽と一百余合を互角に渡り合った後に劉備へ降り、五虎大将の一に数えられた弓の名手である。孔明は「今年六旬に近しと雖も、却って万夫不当の勇有り、軽敵すべからず」と評し、二石の弓を開いて百発百中、百歩穿楊の能を持つと讃えた。「七旬有余、肉を食らうこと十斤、臂は二石の弓を開き、能く千里の馬に乗る」――老いてなお衰えぬ膂力が、この将の象徴である。\n\n通説は「老将の勇」一辺倒で語るが、演義の黄忠は白兵だけでなく計略で勝つ将であった。第七十回、張郃を相手に連敗を装う驕兵の計を用い、夜襲をかけて三寨を奪う。そしてその武の絶頂が第七十一回の定軍山である。法正と申し合わせ、山上に陣取って「以逸待労」、夏侯淵が百般に辱罵しても黄忠は午時を過ぎるまで一切出ず、曹兵が倦怠したと見るや法正が紅旗を招き展べ、その合図で「黄忠一馬当先、馳せて山を下る」。不意を突かれた夏侯淵は「未だ相迎うるに及ばず、黄忠の宝刀已に落ち、頭を連ね肩を帯びて、砍ちて両段と為す」。敵総帥を一刀で斬り捨てた、演義屈指の名場面である。この功で劉備は彼を征西大将軍に進めた。曹操は夏侯淵を斬られたことを「深く恨み」、自ら二十万の大軍で報讐に来たほどであった。\n\nその性格は、年齢を侮られると発奮するという一点で生涯一貫する。第七十回、張郃討伐に「某老いたりと雖も、両臂尚お三石の弓を開き、渾身還た千斤の力有り。豈に張郃匹夫に敵するに足らざらんや」と憤然と名乗りを上げた姿が、彼のすべてを物語る。\n\nその最期もまた、この気性ゆえであった。第八十二回から八十三回の夷陵で「老者無用」の一言に怒り、単騎で敵中へ突出して矢に倒れる。臨終、劉備に「臣は乃ち一武夫のみ、幸いに陛下に遇う」と忠勤を回顧し、「望むらくは陛下善く龍体を保ち、以て中原を図れ」と国家の将来を託して逝った。政治や構想の事績は持たぬ純粋な前線指揮官でありながら、老いを力に変え続けた発奮の将として、演義の中に鮮烈な印象を刻んでいる。"}, {"id": 10, "name": "馬超", "faction": 0, "role": "武将", "rarity": 5, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [9, 8, 7, 8, 5, 3, 3], "p": [1, 1, 1, 2, 3, 2], "scores": {"W": 8.2, "B": 4.75, "S": 3.75, "A": 4.2, "G": 1.53, "K": 2.15}, "stat": {"dmg": 2.17, "area": 1.32, "cd": 0.82, "amount": 1, "knock": 1.49, "crit": 0.13, "duration": 0, "pwr": 8.15}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [10, 58, 59, 64, 65, 67, 69, 70, 72, 73], "chapN": 29, "bio": "馬騰の長子。父の仇を討つべく曹操を潼関で破る西涼の勇将", "profile": "西涼の太守・馬騰の長子にして、字は孟起。「虎体猿臂、彪腹狼腰」「面は傅粉の如く、腰細く膀寛し」と評されるその偉丈夫ぶりは、白い錦の甲冑をまとった姿から「錦馬超」と呼ばれ、敵味方を問わず讃えられた。羌人の心を古くから得て「神威大将軍」と仰がれた、西方の地に根を張る勇将である。\n\nその武の片鱗は、わずか十七の歳に早くも現れた。第十回、父の旧縁に応じて参陣した彼は、王方をただ一槍に刺し殺し、続く李蒙を「軽く猿臂を舒べ」生け捕りにしてみせた。父・馬騰が許都で謀殺されると、馬超は仇討ちの兵を挙げる。第五十八回、潼関に攻め寄せた彼の前に、天下の曹操すら敗走を強いられた。曹操は袍を脱ぎ髭を断ち、舟で命からがら逃れ、後に兜を地に投げつけてこう吐露する——「馬児死なずば、吾に葬地無からん」。第五十九回には許褚と百余合、馬を換えてなお百余合渡り合って勝負つかず、曹操自ら「馬超の勇、呂布に減ぜず」と嘆じた。葭萌関では張飛と昼夜にわたり二百余合の死闘を演じ、玄徳に「錦馬超、名は虚伝ならず」と言わしめている。\n\n通説の描く「悲劇の貴公子」とは裏腹に、本文の馬超は腕っぷしで押し切る猛将であり、采配や駆け引きでは曹操の手のひらの上にあった。潼関では韓遂と作戦の主導権をめぐって対立し、賈詡の反間の計に嵌って同盟を瓦解させ、妻子十余口を失う。賈詡はその本質を「馬超は一勇夫、機密を識らず」と見抜いていた。冀城では降った韋康ら四十余人を皆殺しにし、歴城では城内の百姓を「尽く洗い」、姜叙の老母を自ら斬るなど、その猛りには暗い影もつきまとう。\n\n張魯のもとで孤立し、楊松の讒言に害されかけた末、馬超は劉備に帰順する。第六十五回、その武名そのものを看板に劉璋を城上から恫喝し、戦わずして降伏に追い込んでみせた。蜀漢では驃騎将軍に列し、漢中の諸関を鎮守する方面の重鎮となる。だが帰順後の彼の出番は急速に減り、第九十一回、静かに病でこの世を去る。孔明はその死を「馬孟起病故す、甚だこれを惜しむ、以て一臂を折るとなす」と惜しんだ。腕一本を失うに等しい——そう惜しまれたところに、彼の武の価値が凝縮されている。"}, {"id": 11, "name": "周瑜", "faction": 2, "role": "武将", "rarity": 5, "weapon": "fire", "kind": "zone", "weaponName": "火計", "d": [2, 4, 1, 3, 10, 8, 8], "p": [5, 6, 4, 3, 4, 7], "scores": {"W": 2.25, "B": 8.05, "S": 8.25, "A": 8.2, "G": 4.83, "K": 5.8}, "stat": {"dmg": 2.18, "area": 1.42, "cd": 0.95, "amount": 2, "knock": 0.82, "crit": 0.07, "duration": 4.5, "pwr": 8.2}, "title": "火計の将", "skill": "火計", "skillDesc": "地を焼く炎を放つ", "voice": "", "hist": "", "chapters": [44, 45, 46, 47, 49, 51, 54, 55, 56, 57], "chapN": 58, "bio": "呉の大都督、赤壁で火攻めを指揮し曹操を破る", "profile": "廬江舒城の人、姓は周、名は瑜、字は公瑾。「姿質風流、儀容秀麗」と謳われた江東の貴公子で、孫策とは同年の盟友、義兄弟の契りを結んだ仲である。世に「周郎」と呼ばれ、呉の大都督として三軍を束ねた。白兵の見せ場はほとんどなく、その真価は水軍の統御と、火を操る計略の冴えにある。\n\nその名を不朽にしたのが赤壁である。第四十四回、孫権の前で曹操南征の四つの弱点——北土未だ平らがず、水戦に慣れず、隆冬に馬草なく、疾病が兵を蝕む——を喝破し、抗戦の腹を決めさせた。続いて反間の計で蔡瑁・張允を曹操自身の手で斬らせ、苦肉の計で黄蓋を鞭打ち、偽りの降伏を仕込む。そして第四十九回、東南の風に乗って黄蓋の火船が突き進む。「火は風威に趁き、風は火勢を助け、船は箭の発するが如く、煙焔天を障う」——曹操百万の軍勢は、一夜にして焼き尽くされた。年長ゆえに彼を侮っていた副都督・程普すら、その兵の動かしぶりに「真の将才なり、我いかんぞ服せざらん」と心服し、自ら詫びている。\n\nだが演義の描く周瑜は、度量の広い英傑ではない。孔明の才を妬み、再三にわたってその命を狙い、味方の和を乱しかける狭量な天才として造形されている。南郡攻めでは自ら陣頭に立って弩の箭を左肋に受け、馬から転げ落ちた。曹仁の前に病を装って「曹仁匹夫、周郎を見るか」と現れる一幕はあるが、それも計略の演出にすぎない。彼の身体描写はもっぱら「鮮血を吐き」「金瘡迸裂す」といった、病と傷のそれであった。\n\n臨終の床で、周瑜は後事を魯粛に託す。「魯粛は忠烈、事に臨んで苟もせず、瑜の任に代わるべし」——人を見る眼は確かであった。遺書には曹操の脅威と、劉備という「虎を養うに似たり」の危うさを書き残し、益州を獲って天下を窺う構想まで遺している。しかし孔明に三たび謀られた無念は癒えず、天を仰いで「既に瑜を生みて、何ぞ亮を生むや」と幾度も叫び、息絶えた。才に恵まれながら、ただ一人の才に及ばなかった——その憤死が、彼を演義屈指の悲劇の天才たらしめている。"}, {"id": 12, "name": "孫権", "faction": 2, "role": "君主", "rarity": 5, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [3, 3, 2, 3, 4, 7, 8], "p": [7, 9, 5, 8, 8, 8], "scores": {"W": 2.75, "B": 5.3, "S": 6.15, "A": 5.6, "G": 7.44, "K": 8.05}, "stat": {"dmg": 1.76, "area": 1.21, "cd": 0.99, "amount": 2, "knock": 0.89, "crit": 0.07, "duration": 4.25, "pwr": 5.65}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [29, 38, 43, 54, 55, 61, 66, 67, 68, 75], "chapN": 65, "bio": "呉の君主。合淝で張遼と戦い、妹を劉備に嫁がせる", "profile": "字は仲謀。父・孫堅、兄・孫策が江東に築いた基業を継いだ呉の君主である。碧眼紫髯の堂々たる相貌をもち、後世「守成の凡庸な二代目」と見られがちだが、演義の描く孫権はむしろ、人を見出し時勢を読むことにかけて並ぶ者のない名君として一貫している。個人の武は弱く、むしろ将に守られる側だが、それを補ってあまりある度量と眼力の人であった。\n\nその本領は人を使うことにある。第三十八回、かつて自軍の凌操を討った甘寧が降ると、旧恨を一切問わず「興霸ここに来たる、大いに我が心を獲たり」と迎え入れた。赤壁の周瑜から魯粛へ、魯粛から呂蒙へ、そして夷陵では、張昭・顧雍ら重臣全員が反対する中で、無名に近い陸遜を独断で大都督に抜擢する。第八十三回、佩剣を陸遜に授けて「号令に聴かざる者あらば、先に斬って後に奏せよ」と全権を委ね、果たして劉備を破った。将兵の心の掴み方も見事で、第六十八回には二度自分を救った周泰の傷を一つひとつ指しながら酒を勧め、青羅の傘を賜って「卿は孤の功臣、孤まさに卿と栄辱を共にせん」と涙を流している。「孟徳に張遼あり、孤に甘興霸あり」と人材を誇ったその言葉に、彼の自負が表れている。\n\n胆力も並ではない。第六十一回、濡須口では碧眼紫髯のまま自ら騎兵を率いて曹操を撃ち、曹操に「子を生まば孫仲謀の如くなるべし、劉景升の児子の若きは豚犬のみ」と讃嘆させた。曹操はこの男を「等閑の人物に非ず、久しからずして帝王たらん」と恐れ、兵を退いている。一方で、母の呉国太には終始頭が上がらず、関羽を斬殺した後には「孤、計較を失えり」と慌てふためく脆さも、本文は隠さない。\n\n赤壁では連呉抗曹、荊州では白衣渡江、夷陵では陸遜抜擢——三度の大局を君主として裁可し、対魏には屈身して臣を称し九錫を受ける現実主義をも貫いた。曹操に通謀して関羽を討ち、自ら災禍を招いた判断の誤りもある。だが江東三世の政権を保ち、ついに帝号を建てた。後年、暴君となった孫皓と対比して、家臣の陸凱は「大帝の時、後宮の女は百に満たず」と、その倹約の治世を懐かしんでいる。武ではなく、人と時勢を読む眼で乱世を生き抜いた——それが演義の孫権の姿である。"}, {"id": 13, "name": "孫策", "faction": 2, "role": "君主", "rarity": 5, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [8, 8, 7, 8, 7, 7, 9], "p": [6, 8, 6, 6, 6, 8], "scores": {"W": 7.75, "B": 7.65, "S": 7.25, "A": 7.2, "G": 6.64, "K": 7.3}, "stat": {"dmg": 2.1, "area": 1.32, "cd": 0.75, "amount": 2, "knock": 1.49, "crit": 0.13, "duration": 0, "pwr": 7.7}, "title": "君主", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [7, 8, 15, 16, 17, 18, 28, 29, 44, 46], "chapN": 20, "bio": "孫権の亡兄、遺言『外事不決問周瑜』が回想される", "profile": "字は伯符。孫堅の長子にして孫権の兄。項羽になぞらえられた「小覇王」の異名をもつ、呉の創業者である。後世には猛将の印象が先行するが、演義の孫策は武勇・怪力・人を見る眼の三つを兼ね備えた、武と統治を両立させた稀有な君主として描かれる。\n\nその武は神亭嶺の決闘に極まる。第十五回、太史慈と相まみえた孫策は、五十合戦って勝負つかず、平地に移ってさらに五十合、最後は互いの槍を脇に挟み合い、二人もろとも馬から転げ落ちて組み打ちに及んだ。怪力もまた凄まじい。生け捕った于糜を脇に挟んだまま挟み殺し、背後から槍を突いてきた樊能を「声は巨雷の如し」の一喝で驚かせ、落馬させて頭を砕いた。この一日で一将を挟み殺し一将を喝殺したことから、人々は彼を「小覇王」と呼ぶようになる。曹操すらその強盛を聞いて「獅児、与に鋒を争い難し」と嘆じている。\n\nしかし孫策の真骨頂は、武で奪うだけでなく、徳で人を懐けたことにある。軍に略奪を一切許さず、鶏犬も驚かさぬ厳しい軍紀で民心を得た。第十五回、捕えた太史慈の縄を解いて錦袍を着せ、「兵を収めて期日に必ず戻る」というその約束を信じきって送り出す。翌日、日影が正午にかかる頃、太史慈は千余の兵を率いて約束通り帰参した。「衆皆、策の人を知るに服す」——本文はこう記す。二張を自ら訪ねて礼聘し、周瑜とは義兄弟を結び、虞翻や華佗までも招いた。\n\n弱点もまた本文は明記する。性急にして謀少なく、于吉という道士を斬殺した暴走がもとで、わずか二十六歳で横死する。臨終、孫策は即座に弟・孫権に印綬を授け、「内事決せずば張昭に問え、外事決せずば周瑜に問え」と輔弼の体制を定め、異心を抱く宗族は誅すと遺命に刻んだ。第四十四回、国難に際して孫権がこの遺言を拠り所とし、周瑜が「肝脳地に塗るとも知己の恩に報いん」と応えるとき、彼の遺した設計は確かに機能していた。一代で江東六郡を平らげ、呉三世の礎を築いた創業の英雄——それが小覇王・孫策である。"}, {"id": 14, "name": "鄧艾", "faction": 1, "role": "武将", "rarity": 5, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [4, 5, 5, 4, 8, 8, 7], "p": [6, 5, 5, 5, 4, 6], "scores": {"W": 4.45, "B": 7.15, "S": 7.7, "A": 7.55, "G": 5.21, "K": 5.4}, "stat": {"dmg": 1.96, "area": 1.32, "cd": 0.92, "amount": 3, "knock": 1.15, "crit": 0.08, "duration": 8.8, "pwr": 6.85}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [107, 110, 111, 112, 113, 114, 115, 116, 117, 118], "chapN": 12, "bio": "魏の兗州刺史、智勇兼備の名将", "profile": "魏の兗州刺史にして、智勇兼備をうたわれた方面の名将。演義に登場するのは物語の終盤、姜維の北伐を迎え撃つ魏将としてである。個人の白兵には乏しいが、計略を読み合う戦いで姜維を幾度も出し抜き、ついには蜀漢を一人で滅ぼす決定打を放った、晩成の智将であった。\n\nその智謀は対姜維戦に冴え渡る。第百十回、鄧艾の罠に嵌った姜維は「鄧艾の計に中れり」と叫ぶ。第百十三回には駱谷の伏火を看破して追撃を控え、味方から「将軍は真に神算なり」と讃えられた。第百十五回、洮陽の空城を逆手に取り、城下に出てきた夏侯霸を射殺してみせる。蜀の名将・廖化が出師を渋った理由に「魏には鄧艾あり、足智多謀」と挙げたほど、その名は蜀軍に恐れられていた。\n\nそして第百十七回、鄧艾は前人未到の賭けに出る。劍閣を避け、人跡絶えた陰平の小道を七百里にわたって踏破するのだ。「彼は我が成都を取り得ずと料る、我は偏えにこれを取らんと欲す」——七十近い老体で、自ら氈に身を包んで崖を転がり落ち、徒歩で嶺を越えた。全軍に「虎穴に入らずんば、いずくんぞ虎子を得ん。功を得れば富貴を共にせん」と説いて結束させ、ついに成都を衝いて蜀漢を降した。司馬昭の詔はこの功業を「白起の強楚を破り、韓信の勁趙を克つも、勳を比するに足らず」と歴史的偉業に擬えている。\n\n降伏処理においても鄧艾は政治家であった。第百十八回、降った後主・劉禅の縄を自ら解き、輿櫬を焼いて受降の礼を整え、驃騎将軍に拝して人心を安んじた。さらに製塩・冶金・造船を起こして兵站を整え、その勢いで呉まで併呑する戦後構想を上奏する。だが、この功と独断専行が災いを招く。「将、外に在りては君命も受けざる所あり」と専断を主張したことが、司馬昭に「鄧艾に自専の心あり」との疑いを抱かせた。鍾会と姜維の謀略によって囚われの身となった鄧艾は、かつて自らが幾度も斬ろうとした田続の手にかかって命を落とす。蜀を滅ぼした最大の功臣が、味方の疑念のうちに討たれる——その悲劇の幕切れが、鄧艾という男の影を深くしている。"}, {"id": 15, "name": "太史慈", "faction": 2, "role": "武将", "rarity": 5, "weapon": "bow", "kind": "proj", "weaponName": "弓", "d": [8, 7, 8, 6, 4, 2, 5], "p": [1, 2, 1, 2, 1, 3], "scores": {"W": 7.6, "B": 4.45, "S": 3.0, "A": 3.25, "G": 1.59, "K": 2.3}, "stat": {"dmg": 1.94, "area": 1.16, "cd": 0.84, "amount": 2, "knock": 1.46, "crit": 0.11, "duration": 0, "pwr": 6.75}, "title": "弓の将", "skill": "弓", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [11, 15, 44, 45, 49, 50, 53], "chapN": 7, "bio": "呉の猛将、群英会で監酒役、合淝方面の遮断を担う", "profile": "字は子義。呉に仕えた信義の弓将である。その武勇と義理堅さを演義は厚く描くが、最も鮮烈な戦場はむしろ孫策に仕える以前——孔融の救援と、神亭嶺の決闘にあった。\n\n弓の腕は演義中でも屈指である。第十五回、城上の敵将に向かい「我がこの廝の左手を射るを看よ」と予告するや、言い終わらぬうちに弦が鳴り、放った矢はその左手を射貫いて護梁に釘付けにした。第十一回、孔融の囲みを破って単騎で賊陣に突入した折には「八面これを射て、弦に応じて馬より落ちざる無し」と、四方の騎兵を片端から射落としている。\n\n白兵もまた一流であった。神亭嶺で孫策と相まみえた太史慈は、五十合戦って勝負つかず、平地でさらに五十合、ついには互いの槍を脇に挟み合い、戦袍を引き裂いて組み打ちに持ち込んだ。敵陣の小将が「太史慈は真の猛将なり」と感嘆し、孫策自身も「子義は真の丈夫なり」とその器を認めている。劉繇の敗亡後、太史慈は「兵を収めて期日に戻る」という約束を孫策と交わし、一千余の兵を率いて違わず帰参した。その信義こそ、彼の名を不朽にしたものである。\n\n最期は計略の失敗とともに訪れる。第五十三回、合淝で内応の火を合図に張遼を討つ策を立て、自ら外応を志願した。だが計は張遼に見破られ、乱箭を浴びて重傷を負う。死の床で太史慈はこう叫んだ——「大丈夫、乱世に生まれては、まさに三尺の剣を帯びて不世の功を立つべし。今、志未だ遂げざるに、奈何ぞ死せんや」。志半ばに倒れたその絶命の言葉は、純粋な前線武将として生きた彼の生き様を、そのまま映している。"}, {"id": 16, "name": "甘寧", "faction": 2, "role": "武将", "rarity": 5, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [8, 8, 6, 7, 7, 6, 6], "p": [2, 1, 1, 1, 2, 2], "scores": {"W": 7.4, "B": 6.7, "S": 6.3, "A": 6.45, "G": 1.47, "K": 2.6}, "stat": {"dmg": 2.03, "area": 1.26, "cd": 0.79, "amount": 2, "knock": 1.37, "crit": 0.12, "duration": 0, "pwr": 7.3}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [38, 39, 45, 46, 47, 49, 50, 51, 66, 67], "chapN": 16, "bio": "呉の先鋒猛将、三江口で蔡壎を射殺、烏林で蔡中らを斬る", "profile": "字は興霸。もとは長江を荒らした「錦帆賊」あがりの降将で、黄祖、劉表を経て孫権に仕えた呉の虎将である。義と勇を併せ持ち、単なる白兵屋にとどまらず、君主に覇業の構想を説くだけの戦略眼まで備えた、演義でも異彩を放つ猛将であった。\n\nその勇は数々の戦場に刻まれる。第三十八回には鄧龍を斬り、第三十九回には黄祖を背後から射て梟首した。赤壁の前哨・三江口では蔡壎を射倒し、烏林では馬延を一刀のもとに斬り、張顗を翻身落馬させている。第六十七回の皖城攻めでは、鉄練（鉄鎖）を手に矢石を冒して城壁をよじ登り、一打で守将・朱光を打ち倒した。圧巻は第六十八回、わずか百騎を率いて夜陰に曹操の本営へ斬り込み、一騎も損なわず生還してのける。孫権は「将軍この行、老賊をして驚駭せしむるに足る」とその胆を讃え、後にこう公言した——「孟徳に張遼あり、孤に甘興霸あり、以て相敵するに足るなり」。\n\n甘寧の特異なのは、武将の身でありながら大局を語ったことである。第三十八回、孫権に対し「今、漢祚日に危うく、曹操終には必ず簒竊せん」と天下の情勢を読み、黄祖を破って西へ鼓行し、楚関に拠って巴蜀を図れば覇業は定まる、と方面の構想を進言した。孫権はこれを「金玉の論なり」と称えている。彝陵を先取して南郡を取る策、皖城を先取してから合淝を攻める策など、会戦級の具体的な作戦案を自ら差し出すのも、ほかの猛将には見られない持ち味であった。\n\n義の人でもあった。かつて自らの命を救ってくれた蘇飛が罪を得たとき、甘寧は「その昔日の恩情を念い、願わくは官爵を納還して以て飛の罪を贖わん」と、自分の地位を投げ打ってでも恩人を助けようとした。凌統とは父を殺した殺さぬの確執があったが、孫権の取りなしで生死の交わりへと和解している。最期は痢疾を押して夷陵に従軍し、蛮王・沙摩柯の矢に倒れた。その屍を、群がる鴉が囲んだという。賊あがりの身から呉の上将にまで上りつめた一代の風雲児——それが甘寧である。"}, {"id": 17, "name": "荀彧", "faction": 1, "role": "軍師参謀", "rarity": 5, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 5, 9, 4], "p": [8, 9, 7, 6, 8, 8], "scores": {"W": 1.0, "B": 4.75, "S": 7.1, "A": 6.55, "G": 7.72, "K": 7.4}, "stat": {"dmg": 1.86, "area": 1.32, "cd": 1.1, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 4.75, "pwr": 6.3}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [10, 11, 14, 16, 17, 18, 22, 23, 24, 30], "chapN": 25, "bio": "曹操の謀士。張松の助命を諫める", "profile": "字は文若。曹操に仕えた謀臣の筆頭であり、「王佐の才」と称された王朝設計者である。演義の荀彧には白兵も武勇も一切なく、純然たる文官として描かれる。曹操は彼を初めて迎えたとき「これ吾が子房なり」——漢の張良に擬えて、その智を讃えた。\n\n荀彧の真骨頂は、覇業の青写真を描いたことにある。第十四回、彼は曹操に「天子を奉じて以て衆望に従う」を進言し、これを「不世の略なり」と説いて、魏の国家戦略の骨格を定めた。天子を擁して諸侯を従える——この一手こそ、後の魏の正統の土台となる。官渡では、糧尽きて退却を決しかけた曹操に一通の書を送り、こう諫めた。「至弱を以て至強に当たる……今、地を画して守り、その喉を扼せ。これ奇を用うるの時、断じて失うべからず」。荀彧の言葉が曹操を踏みとどまらせ、烏巣急襲の勝機を引き寄せたのである。\n\n人材を集める眼もまた卓越していた。荀攸を伴って曹操に投じ、程昱を薦め、その程昱を介して郭嘉を呼び寄せる。郭嘉が劉曄を、劉曄が滿寵・呂虔を、彼らが毛玠を呼ぶ——魏の頭脳集団は、荀彧が点火した推挙の連鎖から生まれた。「公の郷人に郭、名は嘉、字は奉孝、当今の賢士なり、何ぞ羅して致さざる」というその一言が、すべての始まりであった。出征のたびに許都を任され、兵糧と財政を一手に握る後方の要でもあった。\n\nだが演義は荀彧に、最も重い場面を用意していた。第六十一回、曹操が魏公の位と九錫を望んだとき、荀彧はただ一人これに反対する。「丞相は本、義兵を興して漢室を匡扶せり。まさに忠貞の志を秉り、謙退の節を守るべし」。天子を奉戴せよと説いたのは、ほかならぬ彼自身の献策であった。その同じ口で、漢室への忠を最後まで貫いたのである。曹操の殺意を悟った荀彧は、贈られた食盒の中身が空であることを見て、すべてを察し、毒を仰いで自ら命を絶った。覇業を設計した男が、その覇業の行きつく先を拒んで死ぬ——演義は彼を、漢室への忠を貫いた悲劇の謀臣として、深く造形している。"}, {"id": 18, "name": "典韋", "faction": 3, "role": "武将", "rarity": 5, "weapon": "twin", "kind": "arc", "weaponName": "双", "d": [6, 7, 10, 7, 2, 1, 2], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 7.3, "B": 2.5, "S": 1.65, "A": 2.0, "G": 1.12, "K": 1.35}, "stat": {"dmg": 2.05, "area": 1.41, "cd": 0.98, "amount": 2, "knock": 1.66, "crit": 0.12, "duration": 0, "pwr": 7.45}, "title": "双の将", "skill": "双", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [10, 11, 12, 14, 16, 17, 18, 58], "chapN": 8, "bio": "曹操配下の猛将、「古の悪来」と評される", "profile": "曹操配下の猛将にして、その帳前を守る最強の護衛。第十回、曹操はその威風凛々たる姿を見て「これ古の悪来なり」——殷の怪力の勇士になぞらえて讃え、ただちに帳前都尉に任じた。許褚と並ぶ虎衛の双璧として、典韋の本質は怪力と、身を捨てた護衛戦に凝縮されている。\n\nその膂力は、演義でも飛び抜けている。八十斤の双鉄戟を両脇に挟んで馬に乗り、「これを運使すること飛ぶが如し」。第十回、風で大旗が倒れかかり、大勢の兵が支えきれずにいる中、典韋はただ一人馬を下り、片手で旗竿を握りしめ、「風中に立ちて巍然として動かず」と微動だにしなかった。第十六回には素手で二人の兵を掴み、叩き殺している。黄巾との戦いでは副元師を三合と持たずに一戟で刺し落とし、敵陣へ飛戟を放てば「一戟一人馬より墜ち、並びに虚発無く、立ちどころに十数人を殺す」という有様であった。\n\n敵もまた、彼を恐れた。第十六回、典韋を討とうとした張繡は、その勇猛を「畏れて急に近づき難し」と見て、まともに戦うことを諦める。配下の胡車児が献じた策は正面からの一騎打ちではなく、「典韋の畏るべき者は双鉄戟のみ。その戟を盗まば、この人畏るるに足らず」というものだった。\n\nその最期は、宛城の壮絶な死闘に尽きる。張繡の夜襲を受けた典韋は、頼みの双戟を盗まれながらも寨門に立ちはだかった。「韋、身に片甲無く、上下に数十槍を被るも、なお死戦す」。素手で二十余人を斬り、矢を雨のように浴びてなお寨門を死守し、ついに倒れた。だが死してなお、敵兵は彼を恐れた——「死して半晌、なお一人として前門より敢えて入る者無し」。この捨て身の死守が、曹操に脱出の時を与えたのである。名のある敵将を斬る派手な戦果ではなく、主君を守って死ぬという一点に己のすべてを注いだ——それが古の悪来・典韋の生き様であった。"}, {"id": 19, "name": "司馬懿", "faction": 1, "role": "軍師参謀", "rarity": 5, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 8, 8, 7], "p": [5, 8, 3, 3, 7, 9], "scores": {"W": 1.1, "B": 6.75, "S": 7.6, "A": 7.35, "G": 5.68, "K": 7.2}, "stat": {"dmg": 2.03, "area": 1.36, "cd": 1.03, "amount": 2, "knock": 0.77, "crit": 0.06, "duration": 4.5, "pwr": 7.3}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [91, 94, 95, 98, 99, 100, 101, 102, 103, 104], "chapN": 29, "bio": "曹操の文学掾として登場", "profile": "字は仲達。曹操の文学掾として世に出た魏の謀臣であり、諸葛亮の最大の好敵手にして、後に晋王朝の礎を築いた梟雄である。通説の豪傑然とした印象とは異なり、演義の司馬懿は個人の武をほとんど持たない。彼を不世の名将たらしめたのは、緻密な計略と、底知れぬ隠忍であった。\n\nその計略の冴えは数々の場面に光る。第九十四回、孟達の謀反を察するや、奏聞を待たずに「一日に二日の路を行け、遅れれば即ち斬」と強行軍を命じ、孔明が一月の猶予を見込んでいた裏をかいて、電撃的に孟達を討ち取った。第百回には諸葛亮の八卦の陣を、休・生・傷・杜・景・死・驚・開の八門と看破してみせる。曹叡からは「卿の学識、孫・呉に過ぐ」とまで評された。\n\nだが演義は、彼を一方的な英雄として描きはしない。対孔明では、空城の計に欺かれて退き、添灶の法に騙され、女物の頭巾を送りつけられても挑発に乗って出ようとせず城を守り続けた。部下の魏平には「都督は兵を按じて動かず、蜀を畏るること虎の如し、天下に笑わるるを奈何せん」と面罵される始末である。第百三回には、廖化に追われて樹のまわりをぐるぐると逃げ回り、金の兜を投げ捨てて方向を欺き、辛うじて命からがら逃れている。彼が体現したのは、武の華々しさではなく、恥を忍んで勝ちを拾う粘りであった。\n\nその隠忍が極まったのが、晩年の政変である。第百六回、政敵・曹爽の探りに対し、司馬懿は冠を脱ぎ髪を振り乱し、被りを被って病重を装った。湯を襟元に流しこぼし、耳が聞こえぬふりをして、見舞いに来た李勝を完全に欺き、油断させる。そして曹爽が城外へ狩りに出た隙を突いて挙兵し、その一族を一掃して兵権を奪い取った。鄧艾の才を皆が笑う中で独りこれを見抜き軍機に参じさせた眼力も、この男のものである。二子・師と昭に権を継がせて晋への布石を完成させ、死後、子孫の代に「宣王」「宣帝」と追号され、七廟に祀られた。逃げ、耐え、欺き、そして最後にすべてを手にする——演義の司馬懿は、武ではなく智と忍の極北を体現した人物として描かれている。"}, {"id": 20, "name": "司馬昭", "faction": 1, "role": "その他", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 1, 0, 6, 7, 8, 6], "p": [6, 8, 2, 2, 8, 8], "scores": {"W": 1.7, "B": 6.35, "S": 7.45, "A": 7.35, "G": 5.58, "K": 7.3}, "stat": {"dmg": 1.72, "area": 1.33, "cd": 1.01, "amount": 2, "knock": 0.89, "crit": 0.11, "duration": 4.5, "pwr": 7.25}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [38, 94, 95, 108, 109, 110, 111, 112, 114, 115], "chapN": 31, "bio": "司馬懿の次子、街亭の偵察を担う", "profile": "司馬懿の次子。魏の権柄を握った司馬一族の二代目にして、子の司馬炎が晋を建てる地ならしを終えた人物である。演義では「司馬昭の心、路人も知る」の簒奪者像が独り歩きするが、本文をたどると個人の武勇を誇る場面はほとんどなく、軍を率いる将才と、人と権力を御す政略にこそ重みが置かれている。\n\nその将才の芽は若き日に現れる。第九十五回、街亭の戦いで彼は偵察に出て、馬謖が山上に布陣した誤りを父に報じ、父子で魏延・高翔を背後から囲み込む。「左に司馬懿、右に司馬昭」と並んで伏兵を指揮し、敵を垓心に陥れた。やがて第百十二回、寿春攻めでは鍾会の献策を容れ、石苞・周太を石頭城に伏せ、牛馬財物を撒いて呉兵の戦意を奪い、四面包囲で諸葛誕を撃滅する。ただし第百九回の鉄籠山では姜維に大都督として囲まれ、「吾、此の地に死せん」と窮地に陥る脆さも隠さず描かれた。\n\n権臣としての凄みは第百十四回に極まる。魏主曹髦は涙ながらに「司馬昭まさに篡逆を懐く、人の皆知るところ」と訴えて挙兵するが、昭は賈充・成済に弑逆を実行させ、自らは偽りの哭礼で名分を保ち、実行犯を三族滅ぼして責を転嫁した。群臣が九錫・晋公を奏すれば「吾が父子兄弟三人、魏に大功あり」と厲声を放ち、衆官は凜然として逆らえない。彼が掲げたのは「昔、文王は天下を三分してその二を有しながら殷に服事した」という思想で、簒奪という最後の一手はあえて子に委ねる構えであった。\n\n最期は天下統一の総仕上げにある。鄧艾と鍾会を互いに噛ませて制御し、衛瓘を監軍に据え、自ら長安へ親征して両者を封じ込めて蜀を併呑した。そして世子を攸か炎かと迷う群臣の諫言を裁き、長子炎を立てて継承を確定した直後、中風に倒れて世を去る。簒奪の完成を息子に託して死ぬ「文王」型の人物として、演義は彼を一貫して描き切った。"}, {"id": 21, "name": "賈詡", "faction": 1, "role": "軍師参謀", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 1, 0, 1, 9, 8, 3], "p": [3, 6, 2, 4, 7, 8], "scores": {"W": 0.3, "B": 6.05, "S": 7.4, "A": 7.4, "G": 4.69, "K": 5.55}, "stat": {"dmg": 1.71, "area": 1.39, "cd": 1.1, "amount": 2, "knock": 0.65, "crit": 0.05, "duration": 4.5, "pwr": 7.15}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [9, 10, 13, 16, 18, 23, 59, 67, 68, 78], "chapN": 21, "bio": "曹操の謀士。韓遂馬超の反間計を献ず", "profile": "魏の謀士。徹頭徹尾の献策型で、自ら剣を取る場面は一度もない。董卓亡き後の李傕・郭汜から張繡を経て曹操へと身を移し、行く先々で計を授けては的中させ続けた、演義屈指の冷徹な智嚢である。\n\nその本領を端的に示すのが第十八回、回題に「賈文和、敵を料りて勝を決す」と掲げられた一段だ。張繡が曹操軍を追おうとすると賈詡は止め、敗れて帰ってきたところで「今度追えば必ず大勝する、さもなくば吾が首を斬れ」と言い放つ。精兵で退兵を追えば必ず敗れ、敗卒で勝兵を撃てば必ず克つ——この二重の逆説をことごとく的中させ、劉表・張繡は「その高見に服す」と舌を巻いた。さらに第五十九回、潼関で馬超・韓遂を離間する反間の計を発案し、曹操に「文和の謀は、まさに吾が心中の事なり」と言わしめる。第六十七回には張魯配下の楊松の貪欲を見抜き、賄賂で離間して龐徳を取る策まで仕掛けた。\n\n大局を読む眼も並ではない。第九回では李傕に長安進攻の大方針を授けて天下大乱の起点を作り、第八十五回には魏の伐蜀を諫めて「ただ持守すべし、もって二国の変を待て」と説き、しかも「劉備死せば、必ず諸葛亮に託孤せん」と相手の出方まで言い当てた。人材を広く集める曹操型ではなく、相手の本質を一突きで見抜き、その隙を突くのが彼の流儀である。\n\n真骨頂は後継問題に表れる。第六十八回、曹操が世子を決めかねて問うと、賈詡は黙したまま答えない。理由を問われて「袁本初・劉景升父子のことを思っておりました」——長子を廃して家を滅ぼした二例を挙げただけで、曹操に曹丕擁立を決断させた。第八十回では受禅台を築いて天子自ら璽綬を奉らせる儀礼を設計し、「群疑を釈き衆議を絶つ」と禅譲の名分を演出して魏の正統を整えた。剣を抜かずして国の継承と建国の正統を支え、危機を未然に消し続けた人物として、演義に深く刻まれている。"}, {"id": 22, "name": "呂蒙", "faction": 2, "role": "武将", "rarity": 4, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [4, 3, 2, 4, 8, 7, 8], "p": [5, 5, 7, 4, 2, 6], "scores": {"W": 3.3, "B": 7.25, "S": 7.2, "A": 7.1, "G": 4.94, "K": 4.85}, "stat": {"dmg": 1.7, "area": 1.36, "cd": 0.9, "amount": 3, "knock": 0.94, "crit": 0.08, "duration": 9.2, "pwr": 7.05}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [38, 50, 61, 66, 67, 68, 73, 75, 76, 77], "chapN": 21, "bio": "呉の武将、烏林で甘寧に接応し放火", "profile": "呉の武将。白衣渡江の奇策で荊州を奪い、ついに関羽を討ち取った智将として知られる。演義もその核は同じだが、本文の呂蒙は個人の白兵の見せ場が驚くほど乏しく、その値打ちはほとんど計略と軍政、そして大局を見る眼に偏っている。\n\n数少ない武の一場面は第三十八回、烏林の戦いで小船に飛び乗り自ら櫓を漕いで船隊に突入し、岸へ上がろうとする陳就を「捨命して追いつき、胸元を一刀のもとに斬り倒した」場面である。だが彼の真価はそこにはない。第七十五回、荊州を狙うにあたり、彼は精兵八十余隻の快船に商人を装わせ、水に通じた者に白衣を着せて漕がせ、本物の兵を船倉に伏せた。烽火台を「誰にも気づかれぬまま」無血で制圧し、荊州を奪い取る。この白衣渡江は演義屈指の奇襲であった。第六十七回の皖城攻めでも「明朝、辰の刻に城を破る」と予告して時刻どおりに陥落させ、第七十七回には関羽の逃走路を読み、朱然・潘璋を伏せて生け捕りにしている。\n\n軍政と人心掌握の冴えはさらに際立つ。荊州を占領するや「みだりに一人を殺し、民間の一物を取る者は軍法に処す」と令を下し、同郷の兵が雨除けに民家の笠を取っただけで涙を呑んで斬り、三軍を粛然とさせた。同時に、出征した関羽軍の将兵の家族には月ごとに糧米を給し、病者には医者を遣わす。この厚遇が伝わると関羽軍は「皆、戦心なし」と内側から崩れ落ちた。後の第百十回でも、王肅が「呂蒙が荊州を襲い、将士の家属を撫恤したゆえ関公の軍勢瓦解せり」と統率の模範に引いている。\n\n大局の眼も確かで、孫権の徐州案を「陸戦に利あり水戦に不利、得ても保ち難し」と退け、長江を全據する構想を据えた。後任には無名の陸遜を見抜いて推挙し、関羽を油断させる人事まで仕組んでいる。だがその最期は華々しくない。第七十七回、勝利の宴の只中で関羽の怨霊に憑かれて狂い、血を吐いて横死する。勝者の余韻ではなく、因果応報の道具立てとして、演義は彼の死を冷ややかに描いた。"}, {"id": 23, "name": "郭嘉", "faction": 1, "role": "軍師参謀", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 7, 9, 1], "p": [2, 5, 1, 1, 1, 3], "scores": {"W": 1.0, "B": 4.9, "S": 7.3, "A": 7.1, "G": 2.26, "K": 2.25}, "stat": {"dmg": 1.65, "area": 1.37, "cd": 1.11, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 4.75, "pwr": 6.7}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [10, 11, 12, 16, 18, 21, 23, 24, 29, 33], "chapN": 17, "bio": "曹操が赤壁敗北後に号泣して惜しむ亡き謀士", "profile": "字は奉孝。曹操が生涯で最も惜しんだ謀士である。第十回で荀彧の郷里の賢士として招かれ、以後その献策の精度ひとつで物語に名を残した。剣を取って戦うことも、軍を率いることもなく、ただ読みの鋭さだけで曹操の覇業を支えた、純粋な智謀の人であった。\n\nその理論的支柱が第十八回の十勝十敗の論である。袁紹との決戦を前に怯む味方に向かい、郭嘉は「いま紹に十敗あり、公に十勝あり。紹兵盛んなりといえども、懼るるに足らず」と説いた。袁紹は謀多くして決断少なく、曹操は策を得れば即座に行う——彼はこうして勝因と敗因を一つひとつ腑分けし、軍心を引き締めた。戦術の場でも冴えは鈍らない。第十九回、下邳の呂布を攻めあぐねると、沂水・泗水を決して城を水攻めにする計を献じ、「二十万の師に勝る」と評された。\n\n最も恐ろしいのは大局を見通す眼である。第三十二回、袁氏の遺児たちを攻めあぐねると「急げば相救い、緩めれば相争う」と説いて兄弟の内紛を待たせ、まんまと自滅へ追い込んだ。さらに病身を押して烏桓遠征を断行させ、遼東については遺計を残す。その死後、公孫康が二袁の首を送ってきたとき、曹操の幕僚たちは「果たして奉孝の料りに出でず」と慄然とした。\n\nその郭嘉は遠征の途上、水土に合わず車中に臥したまま、三十八歳の若さで世を去る。曹操は「彼に後事を託そうと思っていたのに、中年で夭折し、吾が心腸は崩れ裂けた」と嘆いた。後年、赤壁で大敗を喫したとき、曹操が諸将を前に「奉孝在りせば、孤をしてこの大敗に至らしめざらん」と号泣したことが、何より雄弁にその価値を物語っている。"}, {"id": 24, "name": "王濬", "faction": 1, "role": "武将", "rarity": 4, "weapon": "fire", "kind": "zone", "weaponName": "火計", "d": [2, 2, 1, 3, 8, 7, 7], "p": [4, 1, 4, 2, 2, 2], "scores": {"W": 1.85, "B": 6.75, "S": 7.05, "A": 6.95, "G": 2.6, "K": 3.1}, "stat": {"dmg": 1.68, "area": 1.32, "cd": 0.99, "amount": 2, "knock": 0.82, "crit": 0.07, "duration": 4.25, "pwr": 6.95}, "title": "火計の将", "skill": "火計", "skillDesc": "地を焼く炎を放つ", "voice": "", "hist": "", "chapters": [120], "chapN": 1, "bio": "晋の龍驤将軍。楼船と火筏で鉄索を焼き石頭城を陥れ孫皓を降す", "profile": "晋の龍驤将軍。演義では最終回の第百二十回にのみ集中して登場し、三国の幕引きを現場で担った水師の名将である。一騎打ちの猛将ではなく、七年がかりで建造した水軍を率いて長江を下り、計と決断で呉を呑み込む将として描かれる。\n\nその見せ場は、呉が長江に張り巡らせた鉄索と鉄錐の防御を打ち破る一段だ。王濬は大笑して数十万の大筏を造り、上に草人を立てて甲冑を着せ武器を持たせ、川に流し下す。鉄錐はこの筏に引っかかって回収され、続いて麻油を灌いだ長さ十余丈の大松明を筏上に作り、鉄索に遇うたびこれを焼くと、索はたちまち断ち切れた。二段がかりのこの奇計は、演義屈指の障害突破である。\n\n伐呉に踏み切る決断もまた彼の言葉が動かした。「臣、船を造ること七年、日々に朽ち敗る。臣、年七十、死亡日無し。三者一つ乖けば、則ち図り難し」——好機は今をおいてないと上疏して晋帝の決断を促し、水陸二十万・戦船数万艘を統べて順流に下った。風雷の轟くなか、呉人は「旗を望んで降る」。石頭城を抜いて孫皓の降伏を受けると、その縛を解いて棺を焼き、王の礼で遇した。入城後は榜を出して民を安んじ、府庫・倉廩を封じて保全する。「楼船益州を下り、千尋の鉄鎖江底に沈む」と後世の詩に詠まれた天下統一の一幕を、その手で完遂した人物である。"}, {"id": 25, "name": "文鴦", "faction": 1, "role": "武将", "rarity": 4, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [7, 7, 6, 7, 4, 1, 3], "p": [1, 1, 1, 1, 2, 2], "scores": {"W": 6.75, "B": 3.75, "S": 2.25, "A": 2.75, "G": 1.25, "K": 1.85}, "stat": {"dmg": 1.65, "area": 1.25, "cd": 0.9, "amount": 1, "knock": 1.37, "crit": 0.12, "duration": 0, "pwr": 6.7}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [110, 111, 112], "chapN": 3, "bio": "文欽の子、単騎で魏軍を退ける猛将", "profile": "文欽の子。小字を阿鴦という、わずか十八歳の若武者である。父が毋丘倹とともに司馬師に叛いた淮南の乱に従い、第百十回から第百十二回にかけて、一点突破の猛勇で物語を駆け抜ける。父からは「万夫不当の勇あり」と称された。\n\nその名を不朽にしたのが第百十回、楽嘉城の単騎退兵である。身の丈八尺、腰に鋼鞭を懸け槍を綽って馬に乗り、彼は陣営の整わぬ隙を突けと父に進言して司馬師の本陣を夜襲した。父との合流に失敗して孤立しても怯まず、「鼠輩、何ぞ命を惜しまざる」と勃然と怒り、鞭を提げて魏将の群れに斬り込み、鞭で数人を打ち殺してはゆるりと馬を返す。追ってくる魏将百員を四度五度と、ただ一人で撃退した。鄧艾とも五十合を互角に渡り合っている。司馬師はこの夜襲の衝撃で、もとから患っていた眼の肉瘤が破れ、眼球が瘡口から迸り出て、ほどなく死んだ。後世の詩人はこの勇姿を「長坂、当年独り曹を拒ぎ、子龍此れより英豪を顕す。楽嘉城内争鋒の処、また見る文鴦の胆気の高きを」と、趙雲の長坂坡に並べて讃えた。\n\nただし指揮や統率の描写は乏しく、楽嘉でも部下の兵は各自逃げ散り、残ったのは彼ただ一騎であった。彼はあくまで父の反乱に従う一武将である。第百十二回、寿春で父文欽が諸葛誕に殺されると、弟の文虎とともに短刀を抜いて立ちどころに数十人を斬り、身をひるがえして城壁を躍り越え、壕を渡って魏の陣へ投降した。後に偏将軍・関内侯を授けられる。「楽嘉城の趙雲」として、武勇の一芸で記憶される将である。"}, {"id": 26, "name": "龐徳", "faction": 3, "role": "武将", "rarity": 4, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [8, 8, 3, 7, 3, 1, 4], "p": [1, 1, 1, 1, 7, 2], "scores": {"W": 6.65, "B": 3.65, "S": 2.1, "A": 2.45, "G": 1.9, "K": 3.55}, "stat": {"dmg": 1.61, "area": 1.15, "cd": 0.87, "amount": 1, "knock": 1.15, "crit": 0.12, "duration": 0, "pwr": 6.4}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [35, 58, 59, 64, 65, 67, 68, 72, 74, 75], "chapN": 11, "bio": "馬超配下の心腹校尉。長安攻略で活躍、馬超を救う猛将", "profile": "もとは馬超配下の心腹の校尉で、長安攻略などで馬超を救って活躍した西涼の勇将。のちに張魯を経て曹操に降る。樊城で関羽と死闘を演じ、棺を担いで出陣し、降らずに斬られた忠烈の士として演義に名を刻む。\n\nその個人武の高さは本物だ。第七十四回、樊城の戦いで彼は天下無敵の関羽と百余合を互角に渡り合い、「両軍おのおの見て癡呆たり」と敵味方を呆然とさせた。のみならず拖刀の計から放った冷箭で関羽の左臂を射抜いている。第六十七回には張郃・夏侯淵・徐晃・許褚という魏の名将四人が代わる代わる挑んできても、龐徳は「四将に力戦して、並びに懼怯なし」と微動だにしなかった。曹操はこの男を見て「関某は華夏に威を震わせて未だ対手に逢わざるに、いま令名に遇う、真に勁敵なり」と、関羽の真の好敵手と讃えている。\n\n一方で会戦の指揮や戦略、内政の記録はほとんどない。終始、先鋒・副将としての個人武人であり、樊城では地形の危険を察して移営を進言しながら、上官の于禁に阻まれて水攻めを防げず、七軍を失って囚われた。それでも彼は屈しない。出陣に先立って棺を造らせ、「殺せねば殺される、殺されずとも自ら死す。ゆえに先にこの棺を備え、空しく帰る理なきを示す」と死を誓い、降を勧める部将の董衡・董超をその場で斬り捨て、五百の手勢を死戦に結束させた。\n\n捕らえられてなお「吾むしろ刀下に死すとも、あに汝に降らんや」と関羽を罵り通し、斬られた。第七十九回では陵壁の図に「龐徳憤怒不屈」と描かれ、節を曲げて生き延びた于禁の姿と鮮やかに対比される。死に臨んで妻子に「吾が児、異相あり、長じて必ず吾が讎を報ぜん」と後事を託したその子龐会は、のちに父の遺志を継ぐことになる。臣下の節義をその身で体現した、忠烈の名将である。"}, {"id": 27, "name": "姜維", "faction": 0, "role": "武将", "rarity": 4, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [6, 7, 3, 6, 8, 6, 5], "p": [2, 2, 4, 3, 3, 6], "scores": {"W": 5.45, "B": 6.65, "S": 6.4, "A": 6.65, "G": 3.12, "K": 3.5}, "stat": {"dmg": 1.44, "area": 1.12, "cd": 0.87, "amount": 2, "knock": 1.1, "crit": 0.11, "duration": 0, "pwr": 5.25}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [93, 104, 107, 109, 111, 112, 113, 114, 115, 116], "chapN": 28, "bio": "天水の智勇兼備の将、孔明に降り後継者格となる", "profile": "蜀漢の大将軍。もとは魏の天水の将であったが、第九十三回で諸葛亮にその智勇を見込まれて降り、孔明の衣鉢を継ぐ知勇兼備の後継者となった。「事母至孝、文武双全、智勇足り備わる、真に当世の英傑なり」と孔明みずから歎じ、敵将の鄧艾さえ「真に将材なり」と称えた、悲劇の名将である。\n\nその剣槍の腕は確かだ。第九十三回では趙雲と数合戦って「維、精神倍々長ず」と互角以上に渡り合い、趙雲にその槍法を「他人とは大いに異なる」と誉められた。第百七回では司馬師を三合で破り、第百十六回では王頎を「戦うこと三合ならず」して敗走させ、楊欣の馬を一槍で刺している。もっとも、彼の真骨頂は腕力よりも陣法と計略にある。第百十三回、武侯八陣を変じて「長蛇捲地の陣」となし、鄧艾を核心に囲んで降伏寸前まで追い込んだ。第百十四回には王瓘の書を改竄する棄糧の計で鄧艾の五万を火攻に陥れ、夜襲を受けても「兵、夜にありて驚かず」と全軍を静粛に統御している。司馬昭が「姜維しばしば中原を犯し、剿除する能わず、これ吾が心腹の患なり」と恐れたのも当然であった。\n\nだがその一生は、構想と実りの落差に苦しむ。漢室復興を旗印に九たび中原を伐ち、沓中に屯田して持久を図ったが、本文上、北伐はほとんど成果なく終わる。廖化に「連年の征伐、軍民やすからず」と諫められ、蜀の人々の怨望を招き、ついには宦官黄皓の専権を抑えられず、漢中を失って蜀漢滅亡を招いた。降伏命令が下ったとき、麾下の将兵は刀で石を斬り、鬚髪を逆立てて「吾ら死戦せんに、何ゆえ先に降るか」と数十里に届くほど号泣したという。\n\nしかし彼は最後まで諦めなかった。第百十八回、滅亡の淵で「吾に一計あり、漢室を復すべし」と偽りの投降を仕掛け、鍾会を唆して鄧艾を除き、反を起こさせる。後主への密書には「願わくは陛下、数日の辱を忍びたまえ。維まさに社稷をして危うくして復た安からしめ、日月をして幽くして復た明らかならしめん。必ず漢室をして終に滅せしめざるなり」と記した。だがこの捨て身の一計も心疼の発作で頓挫し、彼は自刎して果てる。死後、魏兵がその腹を裂くと、胆は鶏卵ほども大きかったという。社稷再興の夢を最後の最後まで設計し続けた、蜀漢の忠臣であった。"}, {"id": 28, "name": "杜預", "faction": 1, "role": "武将", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 3, 1, 3, 7, 7, 7], "p": [6, 2, 4, 1, 3, 5], "scores": {"W": 2.05, "B": 6.3, "S": 6.8, "A": 6.6, "G": 3.58, "K": 4.35}, "stat": {"dmg": 1.63, "area": 1.29, "cd": 1.0, "amount": 2, "knock": 0.82, "crit": 0.07, "duration": 4.25, "pwr": 6.6}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [120], "chapN": 1, "bio": "晋の鎮南大将軍。羊祜に推挙され伐呉を指揮、破竹の勢いで呉を平定", "profile": "晋の鎮南大将軍。馬前に『左伝』を持たせるほどの「左伝癖」で知られた、老成練達の学者将である。演義では最終回の第百二十回にのみ登場し、羊祜の遺策を継いで伐呉の総大将を務め、呉を平定して三国の物語に幕を引いた。自ら白兵することはなく、その本領は全局を駆動する指揮の頭脳にあった。\n\nその采配は緻密だ。江陵に出ると、牙将の周旨に水手八百を率いさせて小舟で密かに長江を渡らせ、楽郷を夜襲。山林のあちこちに旌旗を林立させ、昼は砲を放ち鼓を擂り、夜は各所で火を挙げて疑兵を演じた。孫歆はこれに「北来の諸軍、すなわち飛んで江を渡るか」と驚愕する。わざと退いて敵を誘い込み、四面の伏兵で掩殺し、城上に火を挙げて孫歆を斬らせる——この連環の作戦で、巴山に翻る「晋鎮南将軍杜預」の大旗を見ただけで、敵将陸景は驚いて逃げ出した。\n\n決断の早さも際立つ。胡奮が「春水のうちは渡れぬ、来春に延期を」と説いたとき、杜預はこれを退けて言った。「昔、楽毅は済西の一戦で強斉を併せたり。いま兵威大いに震う、破竹の勢いのごとし。数節の後は、みな刃を迎えて解く」——あの「破竹の勢い」の語はここに生まれた。彼は檄を馳せて諸将を糾合し、表を上げて晋主の迷いを断ち、一気に建業へ攻め上る。\n\n十万を率い、王戎・胡奮ら諸将も「みな預の調用を聴く」と完全に統御した。沅・湘一帯から黄州の諸郡まで、守令たちは「望風して印を齎し降る」。彼は人に節を持たせて安撫し、秋毫も犯さず、建業入城後は倉を開いて呉の民を賑わせて安堵させた。賈充が「久労・水土不服ゆえ召還を」と退軍を主張して晋主が揺れた局面でも、急ぎ表を馳せて征進の命を引き出した。学識と決断をもって天下統一を成し遂げた、伐呉の指揮頭脳である。"}, {"id": 29, "name": "鍾会", "faction": 1, "role": "武将", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 3, 1, 3, 8, 7, 4], "p": [3, 3, 1, 2, 2, 3], "scores": {"W": 2.05, "B": 6.0, "S": 6.75, "A": 6.8, "G": 2.36, "K": 2.9}, "stat": {"dmg": 1.64, "area": 1.32, "cd": 1.03, "amount": 2, "knock": 0.82, "crit": 0.07, "duration": 4.25, "pwr": 6.65}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [107, 110, 112, 115, 116, 117, 118, 119, 120], "chapN": 9, "bio": "魏の鎮西将軍。蜀を攻め、姜維と謀反を起こして殺される", "profile": "魏の鎮西将軍。司馬昭から「真に吾が子房なり」と漢の張良に擬えられた一流の幕僚にして、伐蜀の総司令官である。武将として登場するが、その実像は個人の武勇よりも戦略と献策に重きを置く智将で、最後は姜維と謀反して乱箭に倒れる。\n\n献策家としての冴えは早くから光る。第百十二回の寿春攻囲では、城を三面から攻めて南門の大路だけを空け、賊を逃がしては撃つという囲師必闕の計を進言し、司馬昭に「君は真に吾が子房なり」と称えられた。利で呉兵を誘う計、城中の人心の離反を見抜いて「この時に乗じて城を攻むべし」と好機を捉える眼——会戦・作戦の献策が密に描かれる。そして第百十五回、朝臣がこぞって伐蜀に反対するなか、ただ一人「某、主公の蜀を伐たんと欲するを料り、すでに図本をここに画く」と進退・屯糧の地図まで携えて伐蜀を建策し、偽の伐呉態勢で呉を牽制する大局構想まで示して、蜀漢滅亡作戦の総設計者となった。\n\n一方で武の腕は描かれない。南鄭関では許儀の連弩に敗れて橋上で落馬しかけ、「会、馬を棄てて歩行す」と狼狽している。鎮西将軍として十万を率い「威声大いに震う」と一時は軍を掌握したが、その統率は最後に裏返る。蜀を併呑したのち、姜維に唆されて謀反を企て、郭太后の偽遺詔をでっち上げ、宴席で「令に違う者は斬る」と剣を抜いて諸将に署名を強いた。衆は恐れて従ったものの、誰も心服してはいない。\n\n第百十九回、司馬昭がみずから長安へ親征すると聞くや、鍾会は「これ我を疑うなり」とその意図を的確に読み取った。だが読みの鋭さとは裏腹に、彼が選んだ手は最悪の謀反であった。諸将を坑に埋めると脅して人心を完全に失い、丘建の密告から胡淵らの反乱を招き、全軍に背かれる。「吾ら、あに反臣に従わんや」と怒号する兵に囲まれ、自ら剣を掣いて数人を斬ったところを乱箭に射倒された。智で名を成しながら、その智を最後に自らへ向けて崩れ去った、皮肉な才人である。"}, {"id": 30, "name": "曹丕", "faction": 1, "role": "君主", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 3, 6, 5], "p": [7, 7, 4, 5, 8, 7], "scores": {"W": 1.1, "B": 3.7, "S": 4.95, "A": 4.5, "G": 6.29, "K": 6.9}, "stat": {"dmg": 1.33, "area": 1.14, "cd": 1.11, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 4.0, "pwr": 4.45}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [68, 72, 74, 78, 79, 80, 82, 85, 86, 103], "chapN": 46, "bio": "曹操の長子、甄氏を娶る", "profile": "魏の初代皇帝にして、曹操の長子。剣を振るう将ではなく、玉座の上で天下の地図を塗り替えた男である。演義の中で曹丕が自ら敵将を斬る場面は一度もない。彼の戦場はあくまで宮廷であり、その武器は権謀と名分だった。父譲りの才に恵まれた弟・曹植と世子の座を争ったとき、曹丕が選んだのは才を競うことではなかった。\n\n第六十八回、父の出征を見送る場で、弁舌を尽くす曹植に対し、曹丕はただ涙を流して拝するのみ。「惟曹丕辭父，只是流涕而拜，左右皆感傷」——居並ぶ者の胸を打ったその一幕に、曹操は曹植の巧みさを疑い、誠は曹丕に及ばぬと感じ取った。賈詡に学んだ、勝つために語らぬという計算がそこにあった。父の死後はさらに鋭さを増す。弟・曹彰が率いる十万の兵を弁士・賈逵の言葉で帰順させ、許褚を遣って曹植一党を一掃し、賈逵や華歆ら降臣を太尉・相国に据えて体制を一気に掌握した。「曹丕自繼位之後，法令一新，威逼漢帝，甚於其父」——その威圧ぶりは父をも上回ったと地の文が記す。\n\n第八十回、ついに彼は漢の献帝に玉璽を奉じさせ、堯舜の禅譲になぞらえて帝位に即く。「舜、禹之事，朕知之矣」と言い放ち、延康元年を黄初元年と改め、国号を大魏と定めた。三国鼎立の輪郭をはっきりと描き出した瞬間である。だがその裏で、彼は「篡竊の名を免れぬ」ことを自覚していた。語り手は最後まで彼を「簒」と断じる。兄弟を逼り、かつて関羽に降った于禁を陵屋の壁画で辱めて憤死させた陰湿さも、この皇帝の忘れがたい一面だ。\n\n戦の指揮者としての曹丕は冴えなかった。第八十六回、辛毗が「養兵屯田十年」の持久策を説くのを「迂儒の論」と退けて伐呉に親征するが、徐盛の蘆葦の偽城と魚油の火攻に龍舟を焼かれ、「魏に武士千群有りと雖も、用うる所無し」と嘆じて御用の品をことごとく捨て、慌てて小船で逃げ落ちた。死に臨んでは曹真・陳群・司馬懿の三人を顧命とし、「此の子年幼し、卿等三人、善く之を輔けよ」と幼主・曹叡を託す。継承は混乱なく整ったが、その輔政の座に司馬懿を据えたことが、やがて魏そのものを呑み込む布石となった——三馬同槽の夢が予示した皮肉である。"}, {"id": 31, "name": "龐統", "faction": 0, "role": "軍師参謀", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 2, 0, 1, 8, 7, 5], "p": [6, 3, 4, 2, 2, 2], "scores": {"W": 0.95, "B": 6.05, "S": 6.75, "A": 6.65, "G": 3.44, "K": 3.4}, "stat": {"dmg": 1.63, "area": 1.32, "cd": 1.05, "amount": 2, "knock": 0.65, "crit": 0.05, "duration": 4.25, "pwr": 6.55}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [35, 36, 47, 48, 57, 60, 61, 62, 63, 65], "chapN": 10, "bio": "鳳雛、連環の計を曹操に授け鉄環で船を繋がせる", "profile": "「伏龍・鳳雛、両人のうち一を得れば、天下を安んずべし」——第三十五回、水鏡先生が劉備に告げたこの言葉によって、臥龍・諸葛亮と並ぶ天才として世に名を轟かせた男が、鳳雛こと龐統である。蜀漢の軍師参謀。剣を取って戦うことはなく、その本領はもっぱら帳中で策を練り、献じることにあった。\n\n彼の名を不滅にしたのが、赤壁の連環の計だ。第四十七回、龐統は曹操の陣に潜り込み、揺れに弱い北の兵のため大小の船を鉄環で連ねるよう献策する。これが周瑜・黄蓋の火攻めの前提となり、曹操の大軍を炎の海へと導いた。やがて劉備に仕えると、最初は耒陽県令という小役に甘んじさせられるが、第五十七回、滞積していた百余日分の訴訟と銭糧を半日で裁き尽くす。「手中に批判し、口中に発落し、耳内に詞を聴き、曲直分明にして、並びに分毫の差錯無し」——役人として侮られたことへの、痛快な反証だった。\n\nその真骨頂は入蜀である。第六十回、迷う劉備に「益州は戸口百万、士広く財富めり、以て大業を資すべし」と説き、荊州の限界を国家規模で論じて決断を促した。第六十二回には成都を直衝する上策、涪関を奪う中策、荊州へ退く下策の三策を示して主君に選ばせ、楊懐・高沛を斬って涪関を兵を血に染めず奪い取る。魏延・黄忠に「関上より来る軍士、多少を問わず、一個も放ち回すこと休れ」と命じる指揮ぶりは鮮やかだった。一方で劉備とは再三衝突し、「公等奈何ぞ備を不義に陥れんと欲するや」と叱責されてもいる。\n\nしかし鳳雛の翼は、大功を立てきる前に折れた。第六十三回、孔明の凶兆を告げる警告を退け、自ら軍を雒城への道へ進めたところ、落鳳坡の地名にもかかわらず慢心の進軍をやめず、乗馬が前足をつまずかせて彼を振り落とす。「憐れむべし龐統、竟に乱箭の下に死す」——天下を安んずるはずの才は、降り注ぐ矢の中であえなく散った。実績は戦術と戦略に偏り、その幅を広げる時間は与えられなかったが、それでも臥龍と並び称された輝きは、演義の中で今も色褪せない。"}, {"id": 32, "name": "司馬炎", "faction": 1, "role": "君主", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 2, 1, 2, 4, 7, 6], "p": [6, 7, 4, 1, 8, 5], "scores": {"W": 0.85, "B": 4.45, "S": 5.9, "A": 5.4, "G": 5.23, "K": 6.65}, "stat": {"dmg": 1.46, "area": 1.21, "cd": 1.13, "amount": 2, "knock": 0.77, "crit": 0.06, "duration": 4.25, "pwr": 5.35}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [114, 119, 120], "chapN": 3, "bio": "司馬昭の長子。魏を簒奪して晋を建国し三国を統一する", "profile": "分かれて争った三国を、ついに一つに束ねた最後の勝者——晋の初代皇帝・司馬炎である。祖父・司馬懿、父・司馬昭が魏の内側から積み上げた力を受け継ぎ、その総仕上げとして天下統一を成し遂げた。剣を振るう武人ではない。彼が握ったのは、決断という名の権だった。\n\n第百十九回、彼は曹奐から禅譲を受ける。容貌は「人物魁偉、立髪地に垂れ、両手膝を過ぎ、聡明英武、胆量人に過ぐ」と評され、まさに天命を担うにふさわしい器として描かれる。「天禄永く終わり、天命晋に在り」の名分のもと、国号を大晋と定め、太始と改元し、七廟を立てて司馬懿を宣帝と追諡した。漢から魏、魏から晋へと連なる禅譲の歴史を踏襲した、王朝樹立の儀式だった。諫言した黄門侍郎・張節には「吾、漢家の為に讎を報ず、何の不可か有らん」と怒り、武士に命じて棍で打ち殺させる苛烈さも見せている。\n\n統一への最後の一歩、伐呉の決断こそが司馬炎の真価だった。第百二十回、羊祜・杜預・王濬・張華が呉を討つべしと説く一方、賈充らは「宜しく軍を召し還すべし」と反対する。両者が激しく衝突する岐路で、司馬炎は「此れは是れ朕の意なり、華は但だ朕と同じきのみ、何ぞ必ずしも争弁せん」と裁定を下し、出兵を断行する。杜預を大都督として江陵へ、水陸の兵二十余万・戦船数万艘を一斉に進めて建業を攻め、ついに呉を平定した。「三国晋帝司馬炎に帰し、一統の基と為る」——百年の乱世がここに終わる。\n\n勝利の宴で、彼は杯を執って涙を流した。「此れ羊太傅の功なり、惜しむらくは其れ親しく之を見ざるのみ」——統一の礎を築きながら、それを見ずに世を去った羊祜を悼んだのだ。呉を平らげた後は倉を開いて民を賑救し、安堵させた。臣下の献策を退けず採り、清廉な賢者を挙げることを是とした度量の君主。自ら天下を構想したのではなく、臣の力を結集して勝利へ導いた決断者として、三国の物語に幕を引いた人物である。"}, {"id": 33, "name": "荀攸", "faction": 1, "role": "軍師参謀", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 8, 7, 3], "p": [4, 6, 1, 5, 4, 6], "scores": {"W": 1.0, "B": 5.55, "S": 6.55, "A": 6.55, "G": 4.25, "K": 4.5}, "stat": {"dmg": 1.6, "area": 1.32, "cd": 1.08, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 4.25, "pwr": 6.35}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [2, 10, 14, 18, 23, 26, 30, 33, 41, 48], "chapN": 18, "bio": "曹操の謀士、蔡瑁登用や詐降策・連環警戒を進言", "profile": "曹操の幕下にあって、ひときわ鋭い知略を放った謀士・荀攸。一騎打ちも膂力の逸話も一切持たない、生粋の軍師である。禰衡からは「墓守りができる程度」と侮蔑されたが、その評こそが彼の本領が刃ではなく頭脳にあったことの裏返しだった。第十四回には曹操から「軍師」に任じられ、以後、数々の難局で計を献じていく。\n\n彼の知略が最も冴えたのは官渡である。第三十回、荀攸は「酸棗を取り鄴郡を攻め、黎陽を取って袁兵の帰路を断つ」と陽動を献じ、袁紹を驚惶させて兵を分散させ、その隙を突いて撃破する決め手を作った。さらに同じ戦いで韓猛の糧道を徐晃に断たせる策も具申している。極めつけは曹操との以心伝心ぶりだ。文醜に対し糧草を餌に敵を誘う計を、二人は言葉を交わすことなく通じ合い、曹操は「惟だ荀公達のみ吾が心を知る」と賞した。\n\n戦略眼も確かだった。第三十二回、袁譚と袁尚が骨肉相食む内紛に乗じ、「先に袁尚を除き、変を観て袁譚を滅ぼせば天下定まらん、此の機会失うべからず」と方面の大局を読み切る。人を見る目も鋭く、劉表への説客に誰を遣るかと問われれば即座に孔融を推挙し、糧道攻めの適任として徐晃を名指しした。赤壁では程昱が火攻を警戒するのに同調し、「仲徳の言は是なり、丞相何故に之を笑うか」と曹操に危機の芽を重ねて指摘してもいる。\n\nそんな荀攸の生涯を締めくくるのは、剛直なひと言だった。第六十六回、曹操が魏王に即こうとした際、彼は正面から「丞相、官は魏公に至り、栄は九錫を加え、位已に極まれり、今又王位に進陞するは、理に於いて不可」と諫めた。漢室の臣としての筋を最後まで通そうとしたのである。だがこの諫言は曹操の怒りを買い、荀攸は憂憤のうちに世を去った。智謀の人でありながら、最期に見せたのは知略よりも一本筋の通った気骨だった。"}, {"id": 34, "name": "魯肅", "faction": 2, "role": "軍師参謀", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 2, 8, 4], "p": [7, 7, 4, 9, 6, 6], "scores": {"W": 1.0, "B": 3.25, "S": 5.75, "A": 5.0, "G": 6.51, "K": 5.95}, "stat": {"dmg": 1.38, "area": 1.19, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 4.5, "pwr": 4.8}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [42, 43, 44, 45, 46, 49, 52, 54, 56, 57], "chapN": 23, "bio": "孫劉同盟を主導する呉の参謀、孔明と周瑜の橋渡し役", "profile": "呉の参謀・魯肅は、しばしば「お人好しのお使い役」として軽く扱われる。だが演義をよく読めば、その印象がいかに彼を見誤っているかが分かる。魯肅は、呉という国の骨格を最初に描いた戦略家であり、孫劉同盟という時代の枠組みを作り上げた立役者だったのだ。\n\nその第一の功績は、第二十九回の榻上策にある。孫権との初対面で彼はこう説いた——「窃かに料るに漢室復興すべからず、曹操卒かに除くべからず。将軍の為に計るに、惟だ鼎足江東して以て天下の釁を観るのみ」。長江を占拠して帝王を号し、天下を図れと。諸葛亮の隆中対に先んじて、呉の側から三分の天下を構想した国家設計だった。曹操が南下したときも、降伏論が満座を覆う中で彼は一人ひるまない。第四十三回、「衆人は皆な曹操に降るべきも、惟だ将軍は曹操に降るべからず」と孫権に迫り、「降れば南面して孤と称するを得んや」と君主の自立の利害を突きつけて、主戦の決意を固めさせた。\n\n外交家としての魯肅は出色である。第四十二回、劉表の弔喪を口実に江夏へ渡り、諸葛亮を呉へ伴って孫劉同盟を成立させた。これぞ連呉抗曹の盟の発案者にして実行者。後の第六十六回、単刀会では「保借荊州、西川を取るの後に帰還するを約す」と理を尽くして荊州返還を迫った。私財にも淡白で、かつて周瑜に米倉一棟、三千斛を指して贈った義侠の逸話も知られる。人を見る目も確かで、諸葛瑾を、そして龐統を孫権に推挙し、容れられぬと見るや「明珠暗投」を避けよと劉備への推薦状まで持たせた。\n\nもっとも、武においては徹底して非力に描かれる。江南の童謡に「伏路把関は子敬に饒し」と関所番しかできぬ者と揶揄され、単刀会では関羽に左手で握られて江辺まで引きずられ「魂、体に附かず」と呆然となる始末。計略の機微でも周瑜や孔明に毎度後れを取った。それでも孫権は晩年、彼を回顧してこう総括している。第七十七回、「曹操東下し、諸人皆な孤に降るを勧めしに、子敬独り孤に公瑾を召して逆え撃てと勧む、此れ二快なり」——危急の一瞬に正しい決断を促した者として、主君は確かに彼を信頼していた。地味ながら呉を支え続けた、本物の戦略家だった。"}, {"id": 35, "name": "丁奉", "faction": 2, "role": "武将", "rarity": 4, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [6, 4, 3, 4, 7, 6, 6], "p": [1, 2, 1, 1, 2, 6], "scores": {"W": 4.65, "B": 6.35, "S": 6.15, "A": 6.15, "G": 1.93, "K": 3.25}, "stat": {"dmg": 1.35, "area": 1.04, "cd": 0.87, "amount": 2, "knock": 1.01, "crit": 0.08, "duration": 0, "pwr": 4.6}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [49, 51, 55, 56, 76, 84, 86, 108, 113, 117], "chapN": 16, "bio": "呉の護軍校尉、七星壇に孔明を斬りに向かう", "profile": "呉の老将・丁奉は、赤壁から滅亡まで、この国の盛衰をほぼ丸ごと見届けた稀有な人物である。登場した当初は徐盛と組んで追撃を担う脇役にすぎなかったが、年を重ねるごとに存在感を増し、最後には「呉の最後の柱」と呼ぶにふさわしい総督へと成長していく。武勇と謀略、その二面を併せ持つ晩成の将だった。\n\n彼の生涯最大の見せ場は、第百八回の東興の戦いである。大雪と敵の油断を読み取った丁奉は、兵に甲冑を脱がせ兜を外させ、長槍大戟を捨てて短刀のみを帯びさせるという奇抜な軽装奇襲を自ら立案した。「大丈夫の功名を立つるは、正に今日に在り」と叫んで先頭を切り、三千の兵で胡遵の大軍を浮橋もろとも壊走させる。乱戦の中では魏将・韓綜が大戟を取って迎えるより早く懐に飛び込み、一刀のもとに斬り伏せ、突きかかる桓嘉の槍の柄を脇に挟んで刺し殺した。回題に「丁奉、雪中に短兵を奮う」と冠された、文字通りの白眉である。かつて第八十六回では、退く張遼の腰を一箭で射抜き、それが元で張遼は箭瘡を発して没している。\n\nだが晩年の丁奉の本領は、むしろ謀略と決断にあった。「老将丁奉、計略人に過ぎ、能く大事を断ず」——第百十三回、彼はこう評される。権臣・孫綝が禁兵を握って簒奪寸前という最大の危機に際し、丁奉は孫休に「陛下憂うる勿れ、臣に一計有り、国の為に害を除かん」と進言。魏邈・施朔を外応、張布を内応に配し、臘日の宴に孫綝を誘い出して誅殺、王朝を救った。\n\nその後も彼は呉軍の柱であり続けた。第百十七回には蜀救援軍五万の主帥となり、第百二十回では「沿江一帯、数百営を屯し、老将丁奉をして之を総べしむ」と長江防衛線全体を託される。離反も部隊崩壊もなく、最後まで国を守り抜いた。乱世の終わりを呉の側から看取った、息の長い忠臣であった。"}, {"id": 36, "name": "孫堅", "faction": 2, "role": "君主", "rarity": 4, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [6, 7, 6, 6, 6, 4, 6], "p": [2, 3, 2, 2, 4, 3], "scores": {"W": 6.2, "B": 5.7, "S": 4.8, "A": 5.0, "G": 2.58, "K": 3.75}, "stat": {"dmg": 1.57, "area": 1.23, "cd": 0.88, "amount": 2, "knock": 1.32, "crit": 0.11, "duration": 0, "pwr": 6.15}, "title": "君主", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [2, 5, 6, 7, 8, 15, 98, 108, 113, 120], "chapN": 10, "bio": "江東の猛将。玉璽を得るが劉表軍に討死", "profile": "「江東の猛虎」と恐れられた孫堅は、呉の礎を築いた男として語られる。だが演義の中の彼は、玉座に座る君主というより、誰よりも前線で刀を振るう生粋の先鋒武将である。孫武子の末裔という血を引き、若き日からその武勇は群を抜いていた。\n\n第二回、わずか十七歳のとき、孫堅は単身で海賊に立ち向かう。「奮力刀を提げて岸に上が」り賊を斬り、後には城に先登して二十余人を斬り、城壁の上から飛び身で敵将・趙弘の槊を空中で奪い取って刺し殺し、その馬に乗って縦横に賊を斬りまくった。第五回の反董卓連合では汜水関の先鋒を任され、袁紹も「文台、勇烈なり、此の任に当たるべし」と認める。第七回の対黄祖戦では、船を出して敵に矢を射尽くさせ、その矢を回収して順風に乗じて射返すという草船借箭さながらの計略で樊城を陥とした。董卓ですらその死に際して「吾、一心腹の患を除けり」と安堵したほど、敵の頭目から脅威と見なされた猛者だった。\n\nしかし孫堅は、君主としての顔をほとんど持たなかった。制度も民政も外交も本文にはほぼ描かれず、第五回ではむしろ袁術に兵糧を止められて「軍に食を缺き、軍中自ら乱る」と補給を他者に依存して破綻している。第六回には洛陽の井戸から伝国の玉璽を得るが、天を指して誓いを立てながらこれを密かに匿い、袁紹と決裂して劉表とも交戦するなど、同盟よりも孤立を招いた。「縦横天下」を口にはしても、それは国家構想ではなく、劉表への私怨を晴らすための言葉だった。\n\nその最期は、彼の猪突の気性そのものだった。第七回、弟が「江東は稍く寧んずるに、一小恨を以て重兵を起こすは宜しき所に非ず」と的確に諫めたが、孫堅は聞き入れない。旗竿が折れる凶兆も韓当の進言も無視して攻城を強行し、単騎で深追いしたところを蒯良の伏兵に誘い込まれ、岩と矢の雨を浴びて三十七歳で横死した。程普・黄蓋・韓当ら宿将が命がけで救い出そうとした忠義だけが、彼の人望を物語る。呉の覇業はこの猛虎の子、孫策と孫権が継いでいくことになる。第百二十回の巻末讃に「孫堅孫策、江左に起こる」と刻まれた、その起点となった人物である。"}, {"id": 37, "name": "張遼", "faction": 1, "role": "武将", "rarity": 4, "weapon": "halberd", "kind": "orbit", "weaponName": "戟", "d": [6, 7, 3, 5, 7, 3, 7], "p": [1, 2, 2, 4, 1, 2], "scores": {"W": 5.35, "B": 6.2, "S": 4.5, "A": 4.8, "G": 1.95, "K": 2.55}, "stat": {"dmg": 1.43, "area": 1.09, "cd": 0.85, "amount": 2, "knock": 1.06, "crit": 0.1, "duration": 0, "pwr": 5.15}, "title": "戟の将", "skill": "戟", "skillDesc": "周囲を旋回する刃で薙ぐ", "voice": "", "hist": "", "chapters": [18, 19, 21, 25, 26, 27, 30, 32, 50, 53], "chapN": 31, "bio": "曹操配下の名将、赤壁で曹操を救出し黄蓋を射る、合淝主将", "profile": "魏の五将筆頭に数えられる張遼は、勇猛さと将としての器量を兼ね備えた、曹操軍随一の名将である。もとは呂布の配下だったが、第二十回、下邳に敗れて捕らえられた際、その気概を惜しんだ曹操に降り、たちまち中郎将に任じられて頭角を現した。以後、追撃・包囲の一翼を担う使い勝手のよい先鋒として、各地の戦場を駆け抜けていく。\n\n白兵の戦果は確かなものだった。第三十三回には許褚・于禁・徐晃と四路に分かれて山を下り、馬を駆って冒頓を斬り落とす。第三十回では蔣奇を斬り、第三十二回では沮鵠を弓で射落として袁尚を破った。赤壁の混戦では退く曹操を守り、黄蓋を矢で射ている。一騎打ちでは張郃や凌統と五十合前後を渡り合うなど、無双というより堅実な強さの将だった。\n\nそして彼の名を永遠にしたのが、第六十七回の逍遥津である。張遼は伏兵の配置から小師橋を断つ呼吸まで自ら設計し、寡兵で孫権の十万の大軍を撃ち破り、孫権を橋上に追い詰めた。この一戦の後、江南では「張遼の大名を聞けば、小児も敢えて夜啼きせず」と語り継がれたという。孫権でさえ「孟徳に張遼有り、孤に甘興霸有り、以て相敵するに足る」とその武名を認めている。\n\nだが張遼の真価は、武勇以上に統御と弁舌にあった。逍遥津の前、不仲だった李典に対し、自ら死戦に赴く姿勢を示すと、李典は「将軍此くの如し、典豈に敢えて私憾を以て公事を忘れんや、願わくは指揮を聴かん」と感じ入り、共同作戦に応じた。第五十三回には勝利の後も「将たるの道、勝つを以て喜と為す勿れ、敗るるを以て憂と為す勿れ」と全軍に油断を戒め、夜襲の内応を未然に鎮めている。さらに第二十五回、土山に追い詰められた関羽を「三便三罪」の理で説き、三つの条件を関羽と曹操の間で往復して仲介・成立させた弁舌は、一武将の域を超えていた。最期は地味だった。第八十六回、丁奉に射られた腰の傷が癒えず、その箭瘡が裂けて病没する。戦場で散ることのなかった名将の、静かな幕引きである。"}, {"id": 38, "name": "文醜", "faction": 3, "role": "武将", "rarity": 4, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [6, 7, 6, 6, 3, 1, 3], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 6.2, "B": 3.15, "S": 1.95, "A": 2.3, "G": 1.0, "K": 1.4}, "stat": {"dmg": 1.57, "area": 1.23, "cd": 0.95, "amount": 1, "knock": 1.32, "crit": 0.11, "duration": 0, "pwr": 6.15}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [5, 6, 7, 22, 26, 27, 28, 41, 45, 49], "chapN": 12, "bio": "袁紹配下の亡将、関羽の白馬の戦功として言及される", "profile": "袁紹配下の文醜は、顔良と並んで「河北の双璧」と称された猛将である。孔融は袁紹陣営を評して「顔良・文醜、勇は三軍に冠たり」と最上級の賛辞を贈り、地の文も「文醜は河北の名将なり」と記す。その武名の高さは、演義の中でも一級のものだった。\n\n彼の武勇が最もよく表れているのは、第七回の磐河の戦いである。公孫瓚を一騎で追い詰め、十数合のうちに支えきれなくなった瓚に「快く馬を下りて降を受けよ」と迫り、馬を駆って中軍へ突入する。「文醜、馬を飛ばして逕ちに中軍に入り、往来衝突す。瓚が手下の健将四員、一斉に迎え戦う、文醜一鎗に一将を刺して馬より下し、三将俱に走る」——四人がかりの敵将を相手に一人を刺し落とし、残る三人を退かせた剛勇である。第二十六回の延津戦でも、鉄槍を構えたまま弓を引き、追う張遼の兜の簪纓を射落とし、続けて馬の面頬を射て張遼を落馬させる騎射の妙技を見せている。\n\nだが文醜の演義における真の役割は、関羽の引き立て役だった。すでに第七回で趙雲に止められた前歴があり、第二十六回、白馬・延津の戦いでついに関羽と相見える。三合と戦わぬうちに斬り落とされ、以後は「顔良を斬り文醜を誅す」という関羽の武功を称える枕詞として、名のみが繰り返し語られていくことになる。荀彧からは「匹夫の勇、一戦にして擒うべし」と見抜かれてもいた。\n\n統率の面では、その評価はさらに厳しい。延津で先鋒七万を率いたものの、曹操が前方に置いた糧草と馬の餌敵の計にまんまと乗り、軍は隊伍を乱して略奪に走った。「文醜、止遏すること能わず」——崩れた自軍を制止できず、伏兵に囲まれて兵は互いに踏み合い、河北軍は大半が水に落ちて壊滅する。沮授の「軽々しく河を渡るな」という諫めを袁紹が退けた咎もあったが、現場の指揮官として罠を見抜けなかった責は重い。最期は崩壊した軍を捨てて単騎で逃げ、その背を関羽に討たれた。武名ばかりが高く、戦術も統率も振るわぬまま散った、悲運の猛将である。"}, {"id": 39, "name": "程昱", "faction": 1, "role": "軍師参謀", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 7, 7, 5], "p": [4, 6, 3, 2, 3, 4], "scores": {"W": 1.0, "B": 5.6, "S": 6.5, "A": 6.3, "G": 3.79, "K": 4.3}, "stat": {"dmg": 1.58, "area": 1.29, "cd": 1.06, "amount": 2, "knock": 0.72, "crit": 0.05, "duration": 4.25, "pwr": 6.2}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [10, 11, 21, 23, 24, 25, 31, 36, 48, 49], "chapN": 24, "bio": "曹操の謀士、火攻めと黄蓋の詐降を見抜き警戒する", "profile": "曹操の五大謀臣の一人に数えられる程昱は、剛胆をもって鳴る策士である。白兵の記録は一切なく、終始、帳中で計を献じる謀士として描かれるが、その目は誰よりも冷静で、危機の影をいち早く嗅ぎ取る鋭さを持っていた。禰衡の人物評では「門を閉ざすに使うべし」と守りの人と評されたが、まさにその守りと洞察にこそ彼の真骨頂があった。\n\n彼の名を最初に高めたのは守城である。第十一回、呂布が兗州を急襲して曹操の本拠が崩れかけたとき、程昱は荀彧と謀って鄄城・東阿・范県の三城を死守した。「其の余は俱に破らるるも、止だ此の三処のみ、荀彧・程昱の設計によって死守し全きを得たり」——曹操が帰る場所を残したのは、この二人の踏ん張りだった。第二十回には献帝の廃立を企てる曹操を諫め、「明公の能く四方に威震し、天下に号令する所以の者は、漢家の名号を奉ずるが故なり」と、漢の名分を奉ずることの戦略的価値を説いて押しとどめている。\n\n対関羽の謀略でも程昱は冴えを見せた。第二十五回、降った関羽を顔良討伐に向かわせるよう進言し、「劉備若し在らば必ず袁紹に投ぜん、今若し雲長をして袁紹の兵を破らしめば、紹必ず劉備を疑いて之を殺さん」と、敵中の劉備を窮地に追い込む離間策を練る。劉備に対する警戒も終始一貫していた。第二十一回、「昔劉備豫州牧為りし時、某等之を殺さんことを請いしも、丞相聴かず、今日又之に兵を与う、此れ龍を海に放ち、虎を山に帰すなり」と諫め、後の蜀漢台頭を見通していたのである。\n\nそして赤壁。連環の船を前に諸将が安心する中、程昱ただ一人が危険を見抜いた。第四十八回、「船皆連鎖して、固より是れ平穏なり、但だ彼若し火攻を用いば、回避し難し、防がざるべからず」と警告し、東南の風が起これば堤防せよと進言する。翌第四十九回には黄蓋の詐降船を「来船必ず詐なり」と看破した。曹操がこの慧眼を容れていれば、あるいは歴史は変わっていたかもしれない。剛胆さと先見の明で曹操を支え続けた、魏の屋台骨のような謀士だった。"}, {"id": 40, "name": "司馬師", "faction": 1, "role": "武将", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [3, 3, 2, 5, 6, 6, 6], "p": [5, 6, 2, 1, 5, 7], "scores": {"W": 2.95, "B": 5.65, "S": 5.95, "A": 5.9, "G": 4.3, "K": 5.7}, "stat": {"dmg": 1.53, "area": 1.22, "cd": 0.99, "amount": 2, "knock": 0.98, "crit": 0.1, "duration": 4.0, "pwr": 5.9}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [1, 78, 94, 102, 103, 104, 106, 107, 108, 109], "chapN": 15, "bio": "司馬懿の長子、大志ある若者", "profile": "司馬懿の長子にして、魏の大将軍。父の遺した権柄をそのまま握り、やがて帝そのものを挿げ替えるに至る、三国末期の魏を一身に体現する権臣である。第百七回、その容貌は「圓面大耳、方口厚脣、左目の下に黒き瘤を生じ、瘤上に数十根の黒毛を生ず」と描かれる。怪異な相貌のこの男こそ、魏の天下が静かに司馬氏へ移ってゆくその蝶番であった。\n\n戦場での司馬師は、決して華々しい武人ではない。第百七回、退路を断とうと姜維に立ち向かうも、わずか三合で討ち敗られて逃げ帰る。一騎打ちで彼が刃を交える場面は演義中ここ一度きりで、しかも敗者の側に立つ。真骨頂は剣戟ではなく、政の場にある。第百八回、大将軍に封ぜられて尚書の機密大事を総領し、第百九回には伊尹・霍光の故事になぞらえて「別に新君を立て、以て社稷を保ち、天下を安んず、如何」と廃立を断行。帝曹芳を退け曹髦を擁立し、反対する李豊・夏侯玄・張緝らを三族もろとも誅滅して、群臣をして「誰か敢えて命に違わん」と従わせた。\n\nその威は、帝そのものを震わせた。第百九回、曹芳は司馬師が朝に入るたび「戦慄して已まず、針の背を刺すが如し」と怯え、「司馬師は朕を視ること小児の如く、百官を覷ること草芥の如し。社稷は早晩必ずこの人に帰せん」と泣いた。武で恐れられたのではなく、握った権そのものが帝を竦ませたのである。一方で第百八回の対呉では「呉兵は遠来し、人多く糧少なし。糧尽きれば自ら走らん」と敵の兵站の弱点を見抜くなど、采配を裁く司令官としての眼は確かだった。ただしその核心の計は傅嘏・虞松ら幕僚の献策で、彼は採否を決する立場にあった。\n\n最期は呆気ない。第百十回、毌丘倹・文欽の乱を平定する陣中、文鴦の夜襲を受けて狼狽し、病んでいた眼の肉瘤の瘡口から「眼珠の迸り出づる」ほどに驚愕する。その傷がもとで床に臥し、洛陽から弟司馬昭を呼び寄せて印綬を授け、「汝、我に継ぎてこれを為せ。大事は切に軽々しく他人に託すべからず、自ら滅族の禍を取るなかれ」と遺託して息絶えた。父懿の布石を継ぎ、弟昭へと権を渡す——司馬氏簒奪という大きな流れの、その中継ぎを果たした一人として、彼は演義に刻まれている。"}, {"id": 41, "name": "徐盛", "faction": 2, "role": "武将", "rarity": 4, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [4, 5, 1, 3, 7, 4, 6], "p": [1, 1, 1, 1, 5, 3], "scores": {"W": 3.35, "B": 5.8, "S": 4.9, "A": 5.05, "G": 1.76, "K": 3.5}, "stat": {"dmg": 1.49, "area": 1.25, "cd": 0.94, "amount": 3, "knock": 0.82, "crit": 0.07, "duration": 8.4, "pwr": 5.6}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [38, 49, 50, 51, 55, 56, 67, 68, 75, 84], "chapN": 15, "bio": "呉の護軍校尉、船で孔明を追うが趙雲に阻まれる", "profile": "呉の護軍校尉。孫氏に仕え、長く徐盛・丁奉の名で並び称された江東の将である。前半生はもっぱら副将・追撃役・護衛役に身を置き、赤壁前後では華々しい個人戦果に乏しい。だが後半、独立した指揮官へと昇格してからの徐盛は、火と疑兵で会戦を勝たせる司令官として、また国家への忠烈な気骨の人として、ぐっと厚みを増してゆく。\n\n赤壁の後、孔明を船で追ったものの趙雲に阻まれ、第五十一回では曹仁の正面突破を「迎え戦うも抵当する能わず」と許してしまう——そんな下積みを経て、彼の山場は第八十六回に訪れる。曹丕みずから大軍を率いて南征したとき、徐盛は都督として葦を束ねて人形を作り、ことごとく青衣を着せ旌旗を執らせて、一夜のうちに偽りの城楼を立て並べた。城上に無数の人馬を望み見た魏兵は「如何ぞ胆寒せざらん」と怯む。さらに淮河の葦に魚油を灌いで火を放ち、曹丕の親征軍を大いに破って「全く大功を獲」たのである。回目に「曹丕を破る徐盛、火攻を用う」と冠されるこの一戦が、彼の生涯の頂であった。\n\n人となりは、腕っぷしよりもまず気骨に表れる。第八十二回、孫権が魏から王の封爵を受けると聞くや、群臣のうちただ一人「放声して哭」し、「吾ら身を奮い命を捨て、主の為に魏を併せ蜀を呑むこと能わず、主公をして人の封爵を受けしむ。亦た辱ならずや」と訴えた。これを見た魏の使者邢貞すら「江東の将相かくの如し、終に久しく人の下に在る者に非ず」と感嘆したという。第八十六回には、孫権の縁者孫韶が軍令を破ったときも「法は臣の立つる所に非ず、亦た大王の立つる所に非ず、乃ち国家の典刑なり。親を以てこれを免さば、何を以て衆を令せん」と、軍法を君主の私情の上に置いて譲らなかった。\n\n戦わずして場を勝たせる知略と、君主にすら諫言を辞さぬ忠烈——その二つが徐盛という将の核である。独断渡江した孫韶を見捨てず、丁奉に密計を授け三千の兵で救援に向かわせた機転にも、その律儀さがにじむ。腕自慢の猛将ではなく、火と知恵で国境を守り抜いた、骨のある呉の指揮官として演義は彼を描いている。"}, {"id": 42, "name": "顔良", "faction": 3, "role": "武将", "rarity": 4, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [6, 7, 4, 6, 3, 2, 3], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 5.7, "B": 3.3, "S": 2.55, "A": 2.8, "G": 1.0, "K": 1.4}, "stat": {"dmg": 1.49, "area": 1.15, "cd": 0.95, "amount": 1, "knock": 1.18, "crit": 0.11, "duration": 0, "pwr": 5.55}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [5, 6, 7, 13, 22, 25, 26, 27, 28, 41], "chapN": 14, "bio": "袁紹配下の亡将、関羽が斬った武功として繰り返し言及される", "profile": "袁紹麾下の上将。文醜と並んで「勇は三軍に冠たり」と孔融に称された河北の筆頭格の猛将である。後世には「関羽に瞬殺された噛ませ犬」の印象がつきまとうが、演義本文の顔良は、その死の場面だけで語るには惜しい、本物の豪傑であった。\n\nその武勇が遺憾なく爆ぜるのが、第二十五回の白馬の一戦。横刀して馬を門旗の下に立てた顔良は、向かってきた呂布の旧将宋憲を「戦うこと三合ならず、手を起こし刀落ちて」斬り捨て、続く魏続を「交馬一合、頭を照らして一刀」のもとに馬下に劈き割る。さらに曹操が送り出した名将徐晃と二十合渡り合って、これを本陣へ敗走させた。この連戦を目の当たりにして曹操陣営の「諸将は慄然」とし、曹操自身も「連りに二将を折り、心中憂悶」して、その武威を「真の勇将なり」と認めざるを得なかった。\n\n人となりは、武勇は本物ながら、慎重さと統御の智には欠けるところがあった。白馬攻めの先鋒に任じられる際、沮授は「顔良は性狭く、驍勇なりと雖も、独り任ずべからず」と袁紹を諫めている。事実、彼は精兵十万の前部を率い「旗幟鮮明、鎗刀森布、厳整にして威あり」と陣容こそ整えたが、布陣や計略は袁紹の指図に従う実行役で、自前の奇略を見せる場面はない。荀彧が「匹夫の勇、一戦にして擒うべし」と評したのも、その一面を突いていた。\n\n最期は、白馬の戦場に赤兎馬で駆けつけた関羽による。圧倒的な速さと「措手不及」——備える間もない不意——のうちに斬られたもので、正面から力負けしたわけではない。だが顔良の名は、ここで終わらない。関羽がその後も折に触れて己の武功として「顔良・文醜を斬った」と繰り返し語ることで、彼は皮肉にも、関羽の強さを天下に証す引き立て役として、繰り返し演義に呼び戻される。討たれてなお、その名が消えぬほどの猛将であった、ということでもある。"}, {"id": 43, "name": "厳顔", "faction": 0, "role": "武将", "rarity": 4, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [6, 6, 5, 6, 6, 4, 5], "p": [1, 2, 2, 3, 4, 3], "scores": {"W": 5.75, "B": 5.45, "S": 4.7, "A": 4.95, "G": 2.31, "K": 3.2}, "stat": {"dmg": 1.51, "area": 1.18, "cd": 0.89, "amount": 2, "knock": 1.25, "crit": 0.11, "duration": 0, "pwr": 5.7}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [63, 64, 65, 70, 71, 72, 81], "chapN": 7, "bio": "元巴郡太守。張飛に降り蜀の老将として活躍", "profile": "もと巴郡太守。蜀へ降ってからは老将として活躍する、「断頭将軍」の名で知られる気骨の人である。だが演義の厳顔は、忠節を貫くだけのアイコンではない。守城と伏兵で張飛を三日翻弄する智、敵将を一刀で斬る現役の白兵、そして四十五の関を無血で開かせる招降の力——その三つを兼ね備えた、「老いて尚お奇功あり」の型の武将であった。\n\n劉璋が劉備を蜀へ招き入れたと聞いた瞬間、厳顔は胸を撫でて嘆じた。「此れ所謂る独り窮山に坐し、虎を引きて自ら衛る者なり」。来たるべき併呑を即座に見抜くその眼は、一地方の太守の域を超えている。張飛が攻め寄せたときも、城に拠って降旗を立てず、城楼から放った一矢で張飛の兜を射抜き、偽りの進軍を見破ったつもりで後路に伏兵を布いて三日のあいだ翻弄した。「善く硬弓を開き、大刀を使い、万夫不当の勇あり」と細作に評された老将の、衰えぬ気魄である。\n\nその名を不朽にしたのが、生け捕られて斬首寸前に放った一喝だ。第六十三回、張飛の前で「全く懼るる色無く」、逆に張飛を叱して言う。「汝ら義無く、我が州郡を侵す。但だ断頭将軍あるのみ、降将軍は無し」。首を斬られる将はあっても、降る将はない——この清冽な啖呵に張飛は感じ入り、礼をもって迎えた。降ってのちの厳顔は、自らの威信を使って雒城に至るまでの守将を次々と帰順させる。逡巡する者には「我すら且つ投降す、何ぞ況んや汝をや」と説き、四十五処の関隘を血を流さず開かせたのである。\n\n老いてなお、その刀は鈍らなかった。第七十回の天蕩山では、火を救いに来た夏侯徳を「手を起こし刀落ちて」一刀のもとに斬り、張郃軍を背後から抄って夾撃を成立させ、糧道を断って漢中攻略の足がかりを作る。黄忠の副将として漢中で実戦果を上げる姿は、もはや単なる忠臣の枠に収まらない。降ってのちは前将軍に列せられ、節義と武功の両方で蜀漢に厚遇された。白髪の老将が西蜀に身を寄せ、なお奇功を立てた——その姿は演義の中で、詩讚をもって長く称えられている。"}, {"id": 44, "name": "黄蓋", "faction": 2, "role": "武将", "rarity": 4, "weapon": "mace", "kind": "nova", "weaponName": "剛", "d": [5, 3, 3, 2, 7, 4, 6], "p": [2, 2, 3, 2, 2, 4], "scores": {"W": 3.8, "B": 5.85, "S": 4.85, "A": 4.95, "G": 2.42, "K": 3.1}, "stat": {"dmg": 1.24, "area": 0.99, "cd": 0.9, "amount": 2, "knock": 0.91, "crit": 0.06, "duration": 0, "pwr": 3.8}, "title": "剛の将", "skill": "剛", "skillDesc": "周囲を吹き飛ばす衝撃", "voice": "", "hist": "", "chapters": [5, 6, 7, 9, 15, 43, 44, 46, 47, 49], "chapN": 14, "bio": "呉の老将。周瑜の水軍に従い劉備を追撃", "profile": "呉の老将、字は公覆、零陵の人。孫堅・孫策・孫権の三世に仕えた宿将であり、自ら「破虜将軍に随いてより東南を縦横すること、已に三世を歴たり」と誇る、江東の屋台骨のひとりである。武勇の派手さよりも、忠義・献身・実行力で演義が厚く描く人物だ。\n\nその実戦果は早くから明確で、第七回では「喊声の天を震わすを聴き、水軍を引きて殺し来たり」、黄祖を「戦うこと両合ならず生擒」している。鉄鞭を得物とし、第六回では蔡瑁と数合渡り合って鞭で護心鏡を打ち据えた。だが黄蓋の名が三国の歴史に刻まれるのは、何といっても赤壁である。曹操の大軍を前に「彼れ衆く我れ寡なし、宜しく久しく持すべからず。何ぞ火攻を用いざる」と火計を発案したのは、ほかならぬ黄蓋であった。\n\nその火計を実らせるため、彼は自らの身を捧げる。いわゆる苦肉の計——周瑜の前で抗戦を主張し、罰として打ち据えられて偽りの恨みを装い、曹操へ降伏を申し出る大芝居を打ったのである。「某は孫氏の厚恩を受く。肝脳地に塗るとも、亦た怨悔無し」とは、その覚悟を述べた言葉だ。第四十九回、いざ決戦の日には「火船二十隻、船頭に密かに大釘を布き、船内に蘆葦乾柴を装載し、灌ぐに魚油を以てし、上に硫黄燄硝引火の物を鋪く」と自ら火船を仕立て、第三の火船の上に「ただ掩心甲を披り、手に利刃を提げ、旗上に大書して『先鋒黄蓋』」と記して、作戦の心臓を担って曹操の水寨へ突っ込んだ。\n\nその忠勤は、味方の固い結束に支えられていた。第五十回、火攻の最中に矢を受けて落水した黄蓋を、同僚の韓当が即座に「公義、我を救え」の声を頼りに引き上げる。大寒の時節に甲冑のまま水に落ちても泳ぎ切ったというその体は、長年戦場を駆けた老兵のしぶとさを物語る。腕自慢の猛将ではなく、国の存亡の一戦に己の身を投じてみせた献身の人——「苦肉の老将」の四字が、その生涯をよく言い表している。"}, {"id": 45, "name": "祝融夫人", "faction": 3, "role": "婦人", "rarity": 4, "weapon": "chakram", "kind": "proj", "weaponName": "戦輪", "d": [6, 6, 5, 5, 2, 1, 3], "p": [1, 1, 1, 1, 2, 2], "scores": {"W": 5.65, "B": 2.65, "S": 1.65, "A": 1.85, "G": 1.25, "K": 1.85}, "stat": {"dmg": 1.49, "area": 1.16, "cd": 0.96, "amount": 1, "knock": 1.2, "crit": 0.1, "duration": 0, "pwr": 5.6}, "title": "佳人", "skill": "戦輪", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [90], "chapN": 1, "bio": "孟獲の妻。飛刀の名手。張嶷馬忠を捕らえるが馬岱に擒われる", "profile": "南蛮王孟獲の妻にして、飛刀の名手。演義にただ一度、南征の章にのみ姿を見せる、ほぼ唯一の本格的な女武将である。「世々南蛮に居り、乃ち祝融氏の後なり。善く飛刀を使い、百発百中」と地の文に紹介される、火神の血を引くと謳われた女傑だ。\n\nその登場は鮮烈だった。蜀軍に手を焼いて慌てる孟獲を見るや、屏風の後ろから一人の婦人が大笑して現れ、「既に男子たり、何ぞ智無きや。我れは是れ一婦人と雖も、願わくは汝と出戦せん」と一喝する。背に五口の飛刀を差し、丈八の長標を手挺し、捲毛の赤兎馬にまたがって陣頭に立つその姿——宗党の猛将数百、洞兵五万を率いての出陣である。蜀将張嶷と数合斬り結ぶと、夫人はわざと馬を返して走り、追ってきた張嶷めがけて空中から飛刀を一閃。これが左臂を貫き、張嶷は身を翻して落馬・生擒された。続けて馬忠も馬を絆され擒となり、婦人ながら名のある蜀将二人を捕える殊勲を立てる。張嶷すら「暗暗に奇を称」したという。\n\nただし、その猛勇には脇の甘さも同居していた。初日こそ「埋伏あるを恐れ、兵を勒して回る」と慎重だったが、魏延の度重なる挑発についに怒り、伏兵を案じることなく山道へ突進。待ち構えていた馬岱の絆馬索に掛かって「鞍を仰いで馬より落ち」、あえなく擒となってしまう。計を仕掛ける側ではなく、孔明の誘導にまんまと嵌る側だったのである。捕えた蜀将を即座に斬ろうとした際も、孟獲に「諸葛亮は吾を放つこと五次。今番もし彼の将を斬らば、是れ不義なり」と諫められ、その言に従った。武の勇は本物ながら、智と慎みでは孔明の掌の上にあった——南征の一幕を彩る、勇ましくも人間味のある女傑である。"}, {"id": 46, "name": "張郃", "faction": 1, "role": "武将", "rarity": 4, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [5, 7, 5, 7, 5, 4, 5], "p": [1, 1, 1, 1, 2, 2], "scores": {"W": 5.6, "B": 4.95, "S": 4.5, "A": 4.7, "G": 1.25, "K": 2.25}, "stat": {"dmg": 1.48, "area": 1.21, "cd": 0.94, "amount": 1, "knock": 1.3, "crit": 0.12, "duration": 0, "pwr": 5.5}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [30, 31, 41, 50, 67, 69, 70, 71, 95, 98], "chapN": 23, "bio": "曹操配下の武将、長板坡で趙雲と戦い前軍紅旗を率いる", "profile": "魏の名将、河間の人。曹操に仕えて五子良将の一に数えられ、地形と変化を巧みに用いる宿将として、官渡から諸葛亮の北伐まで長く戦場を駆け抜けた。だがその実像は一筋縄ではない。堅守を進言する慎重な良将の顔と、敵を侮って突進する猪勇の顔が、一人の中に同居していた。\n\nそもそも張郃は、官渡で郭図の讒言と袁紹の敗勢を見切り、「袁紹は讒言を聴信し、必ず曹操の擒うる所と為らん。吾ら豈に坐して死を待つべけんや。如かず去って曹操に投ぜん」と、自ら身の処し方を定めて魏へ転じた将である。曹操に偏将軍・都亭侯として迎えられてのち、その武名はぐんぐん高まった。長坂坡では趙雲と三十余合、張遼とは四五十合渡り合って勝負つかず、第七十一回には劉備が「もし張郃を斬り得ば、夏侯淵を斬るに勝ること十倍なり」と、その首を総帥のそれの十倍に値すると評している。\n\n何より、その存在を最も重く見たのは敵将諸葛亮であった。「魏之名将、等閒の及ぶ所に非ず」と二度までも繰り返し警戒し、第九十九回には「吾れ今日これを見て、方にその勇を知るなり。もしこの人を留め下さば、必ず蜀中の害と為らん。吾れ当にこれを除くべし」と、生かしておけば蜀の禍になると断じて排除を決意した。一方で張郃自身は、対黄忠でも対孔明でも一貫して「堅く守るべし」と正しい守勢を進言する慎重さを持つ。だがその策はしばしば容れられず、攻勢に転じると逆に敗れる。瓦口関では詐敗伏兵の計を張飛に看破され、三万の兵のうち二万を失った。\n\nその最期は、まさにこの「猛勇ゆえに計に嵌まる」性が招いたものだった。第百一回、木門道で退く蜀軍を侮って猪突し、諸葛亮の仕掛けた伏弩の雨を浴びて、百余の部将もろとも射殺される。「大丈夫、身を捨てて国に報ゆ」と言い放っての、壮絶な戦死であった。その死に、司馬懿は「張雋義の身死せるは、吾の過なり」と慟哭し、魏主も涙を揮ったという。強くはあったが頂点ではなく、忠勇ゆえに散った——惜しまれる宿将として演義は彼を見送っている。"}, {"id": 47, "name": "劉曄", "faction": 1, "role": "軍師参謀", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 6, 7, 2], "p": [2, 1, 0, 4, 1, 5], "scores": {"W": 0.0, "B": 4.25, "S": 5.9, "A": 5.7, "G": 1.97, "K": 1.95}, "stat": {"dmg": 1.47, "area": 1.26, "cd": 1.15, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 4.25, "pwr": 5.45}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [10, 12, 14, 23, 30, 41, 67, 71, 82, 85], "chapN": 13, "bio": "曹操の謀士、徐庶を使者に立てる策を進言", "profile": "曹操・曹丕・曹叡の三代に仕えた魏の謀士。光武帝の嫡流を引く血筋で、郭嘉の推挙により曹操に迎えられた。一騎打ちも膂力の逸話もない、生粋の献策専門の文官であり、その値打ちはひとえに、戦機と大局を読む眼にある。\n\n技術的な献策にまず光るものがあった。官渡で袁紹が土山を築き弓櫓から矢を射かけてきたとき、劉曄は「発石車を作りて以てこれを破るべし」と進言。一夜のうちに数百乗を造らせ、これが後に袁軍から「霹靂車」と呼ばれて恐れられた。袁軍が地道を掘って攻めれば「営を遶りて長塹を掘るべし」と即座に正解を返し、濮陽戦では「布は無謀なりと雖も、陳宮は計多し。只だ其の中に詐あるを恐る」と伏兵を見抜いて三隊分進を説いている。\n\nだが劉曄の真価は、もっと大きな絵を描くところにあった。漢中を取った直後、彼は司馬懿とともに「少しく遅緩すれば、諸葛亮は国を治むるに明らかにして相と為り、関張らは勇三軍に冠して将と為り、蜀民既に定まれば関隘を据守し、犯すべからず」と、即座に益州を突くべしと進言する。曹操がこれを退けた結果、後に曹操自身が「当時、卿の言を用いざるを恨む」と悔やんだ。対呉でも「蜀呉交兵するは、乃ち天のこれを亡ぼすなり。呉亡べば則ち蜀孤ならん」と魏の天下取りの好機を読む。採られれば的中し、退けられれば後で君主が臍を噬む——そんな「容れられぬ名参謀」が、劉曄という人物の宿命だった。\n\n外交の使者としても功がある。第二十三回、曹操の使いとして張繡のもとへ赴き、賈詡を介して旧怨を解き、曹操の徳を盛んに称えて張繡・賈詡の許都投降を実現させた。曹叡の世には、伐蜀の献策をめぐって表では「無此事」と否定し、裏で「夫れ兵は詭道なり。事未だ発せざれば、切に宜しく之を秘すべし」と機密保持を説いて帝の信を勝ち得る。武の場には一度も立たぬまま、的中する策と巧みな世渡りで三代を生き抜いた——魏陣営の頭脳のひとりである。"}, {"id": 48, "name": "徐晃", "faction": 1, "role": "武将", "rarity": 4, "weapon": "axe", "kind": "arc", "weaponName": "斧", "d": [6, 6, 4, 4, 6, 4, 6], "p": [1, 1, 1, 1, 2, 1], "scores": {"W": 5.3, "B": 5.6, "S": 4.7, "A": 4.8, "G": 1.13, "K": 2.3}, "stat": {"dmg": 1.44, "area": 1.1, "cd": 0.88, "amount": 2, "knock": 1.08, "crit": 0.08, "duration": 0, "pwr": 5.2}, "title": "斧の将", "skill": "斧", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [14, 30, 32, 50, 56, 58, 59, 67, 71, 72], "chapN": 32, "bio": "曹操配下の武将、馬歩前軍紅旗、敗走の曹操を護衛", "profile": "曹操配下の名将、字は公明。五子良将の一に数えられ、知勇兼備と謳われる。大斧を得物とし、馬歩前軍の紅旗を率いて数多の戦場に立った。だがその実像は、無敵の猛将というより、規律と冷静と献策で光る「知将寄りの将才」にある。\n\n白兵の戦果は確かに多い。第十三回では崔勇を「ただ一合、馬下に斬」り、李楽を一斧で砍り倒し、汪昭・彭安らを次々と討っている。しかし超一流の壁の前では足踏みした。顔良には二十合で敗れ、関羽とは八十合戦って優位を取れず、趙雲を前にしては「心驚き胆戦き、敢えて迎え戦わず」と恐れる側に回る。狂言回しの禰衡には「猪を屠り狗を殺す」と罵られもした。だが曹操は彼を「真の良将なり」と称え、その評価の振れ幅の大きさが、かえって徐晃という将の輪郭を際立たせる。\n\nその真骨頂は白兵ではなく、規律と冷静、そして軍略にあった。潼関の戦いでは「一軍をして暗かに蒲阪津を渡らしめ、先ず賊の帰路を截たば、賊は両ながら相応ぜず、勢い必ず危うからん」と退路遮断策を曹操に献じ、「公明の言、正に吾が意に合す」と採られて馬超撃破の大局を作る。年若い曹洪が逸るのを諫めて守りに徹する冷静さも見せた。\n\n生涯の頂は、樊城の救援戦である。旗を偽った副将を陽動に立て、自らは精兵五百を率いて沔水沿いに迂回奇襲し、偃城・四冢の連寨を抜き、関羽が幾重にも構えた鹿角十重の囲みへ長駆して突き入り、全功を獲た。曹操はこれを「三十年の用兵にも為し得なんだ」と讃え、帰陣する徐晃の軍が「隊伍に按りて行き、並びに差乱無し」と寸分の乱れもなく進むのを見て、「徐将軍は真に周亜夫の風あり」と漢の名将になぞらえた。降伏のおりにも、旧主楊奉を殺して手土産にせよとの勧めを「臣を以て主を弑するは大いに不義なり、吾れ決して為さず」と退けて「義士」と称された男である。後に孟達討伐の途上で世を去るまで、規律と義をもって魏に仕え抜いた、五子良将らしい将であった。"}, {"id": 49, "name": "羊祜", "faction": 1, "role": "武将", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 3, 7, 8], "p": [5, 6, 6, 3, 2, 7], "scores": {"W": 1.1, "B": 4.6, "S": 5.85, "A": 5.15, "G": 4.93, "K": 5.2}, "stat": {"dmg": 1.44, "area": 1.18, "cd": 1.08, "amount": 2, "knock": 0.77, "crit": 0.06, "duration": 4.25, "pwr": 5.2}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [120], "chapN": 1, "bio": "晋の都督・襄陽守将。陸抗と徳を競い、伐呉と杜預を遺言して死す", "profile": "晋の都督にして襄陽の守将。演義の最終第百二十回、三国統一の幕引きへと舞台が傾くその場に登場し、天下を一つにする礎を築いた文治型の名将である。一騎打ちも白兵もまるで描かれない。鎮守・屯田・徳治・献策・後継推挙——そのすべてを静かに、しかし的確に積み上げてゆく姿こそが、羊祜という人の真骨頂だ。\n\n軍にあっても、彼はいつも軽やかだった。「軽裘を著け、寛帯を繋ぎ、鎧甲を披らず、帳前の侍衛者は十余人に過ぎず」。鎧を着けぬ文人の余裕をまといながら、その経営は確かである。辺境を守る卒を削って八百余頃の田を墾かせ、着任の当初は「軍に百日の糧無」かったものを、翌年には「軍中に十年の積あり」と転じてみせた。具体的な数字でもって示される、見事な兵站の手腕である。\n\n最大の見せ場は、敵将陸抗との「徳を以て相待つ」交わりにある。互いに国を背負って対峙しながら、羊祜は酒を送り薬を送り、狩りでも境界を越えなかった。陸抗はその軍を望み見て「羊将軍の兵は紀律あり、犯すべからず」と歎じ、ついに矛を交えることをしなかった。戦わずして相手を服させる、徳の応酬である。部将が奇襲を進言したときも「この人将と為る、我ら只だ自ら守るべし。其の内に変あるを候ちて、方に図り取るべし。もし時勢を審らかにせずして軽進すれば、此れ敗を取るの道なり」と退け、機の熟するを待つ眼を見せた。\n\nそして彼の真の功は、その死後に実った。第百二十回、伐呉の好機を説いた上表——「江淮の険は剣閣に如かず、孫皓の暴は劉禅に過ぎ、呉人の困は巴蜀より甚だし。而して大晋の兵力は往時より盛んなり。この際に四海を平一せざらんや」——は在世中こそ容れられなかったが、王濬の策が「羊都督と暗かに合す」と評され、青写真として受け継がれた。病の床で帝に呼ばれた羊祜は涙ながらに「臣死なん、敢えて愚誠を尽くさざらんや。右将軍杜預任ずべし」と後任を遺言し、その杜預が後に伐呉を成し遂げて天下統一を完成させる。鎮守の地では「軍民の心を甚だ得」、敵側の降人にも去就の自由を許したその徳ゆえ、死に際して「南州の百姓は市を罷めて哭」し、辺を守る将士は皆涙し、後に墮淚碑が立てられた。武で名を成したのではなく、徳と先見で時代を動かした——三国の物語を締めくくるにふさわしい、稀有な名臣である。"}, {"id": 50, "name": "夏侯惇", "faction": 1, "role": "武将", "rarity": 4, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [6, 6, 5, 4, 3, 3, 5], "p": [1, 2, 1, 1, 1, 2], "scores": {"W": 5.55, "B": 3.85, "S": 3.25, "A": 3.2, "G": 1.32, "K": 2.15}, "stat": {"dmg": 1.48, "area": 1.14, "cd": 0.93, "amount": 1, "knock": 1.15, "crit": 0.08, "duration": 0, "pwr": 5.5}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [6, 10, 12, 14, 16, 18, 28, 30, 31, 39], "chapN": 36, "bio": "曹操配下の宿将、水陸路接応使、後に襄陽を守る", "profile": "夏侯惇は曹操の挙兵期から付き従った魏の宿将である。槍を手に先鋒を駆け、後備を固め、糧草の押運から許都の巡警まで、曹操が委ねる任を黙々とこなす片腕として描かれる。曹操はこの男を「天下奇才」と称えた（第二十三回）。一方で、いっそ皮肉屋の禰衡には「完體將軍」とからかわれもする。称賛と揶揄の両極を背負うのが、この将の不思議な立ち位置である。\n\n戦場での彼を最も鮮烈に焼きつけるのは、第十八回の「拔矢啖睛」だろう。呂布配下の曹性に放たれた矢が左目に突き立ち、引き抜くと眼珠ごと抜け出た。夏侯惇は「父精母血、棄つべからず」と大喝し、そのまま眼を口に納めて呑み込み、槍を構えて曹性を討ち取った。両軍の兵は「見る者、駭然たらざるはなし」とただ慄くばかり。腕力の誇示ではなく、意志と気魄が肉体を超える瞬間だった。一騎打ちでは徐栄を馬下に刺し（第六回）、橋蕤を三合と戦わず突き殺している（第十七回）。\n\nただ、その剛勇には影もある。呂布には「抵敵すること能わず、馬を飛ばして陣に回る」と退かされ、関羽の前でも終始押された。指揮官としての汚点が博望坡である。第三十九回、韓浩や李典の伏兵警告を「敵かくの如し、十面埋伏ありとも何ぞ懼れんや」と退け、諸葛亮の火計に「四方八面、ことごとく是れ火」と大敗。後に曹操から「汝、幼より兵を用う、豈に狹處に火攻を防ぐを知らざるか」と叱責された。青州兵が民家を略奪して咎められたこともある。\n\nそれでも曹操の信任は揺るがなかった。典韋という猛士を見出して主君に推挙したのも彼であり（第十回）、耿紀らの謀反で許都に火が上がった夜には、即座に大軍で都を囲んで鎮めている（第六十九回）。華やかな武勲よりも、誤りながらも任を背負い続けた忠厚さ。その地味な信頼の厚みこそが、隻眼の宿将の本当の魅力である。"}, {"id": 51, "name": "王雙", "faction": 1, "role": "武将", "rarity": 4, "weapon": "mace", "kind": "nova", "weaponName": "剛", "d": [6, 5, 6, 4, 1, 1, 3], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 5.6, "B": 2.15, "S": 1.35, "A": 1.4, "G": 1.0, "K": 1.4}, "stat": {"dmg": 1.5, "area": 1.17, "cd": 0.98, "amount": 1, "knock": 1.22, "crit": 0.08, "duration": 0, "pwr": 5.65}, "title": "剛の将", "skill": "剛", "skillDesc": "周囲を吹き飛ばす衝撃", "voice": "", "hist": "", "chapters": [41, 85, 97, 98, 99, 112], "chapN": 6, "bio": "曹仁配下の将。濡須攻めに従軍", "profile": "王雙は曹真に推挙されて諸葛亮の北伐に立ちはだかった魏の先鋒、字は子全、隴西の人である。身の丈九尺、熊のような腰に虎のような背、六十斤の大刀を振るい、千里の征宛馬に跨り、両石の鉄胎弓を引き、暗に三つの流星鎚を秘めて百発百中。曹真は「万夫不当の勇あり」とこの男を朝廷に売り込んだ（第九十七回）。\n\n陳倉口に現れた王雙は、まさにその触れ込み通りに暴れた。蜀将謝雄と戦って三合せぬうちに一刀で斬り捨て、続く龔起も三合で斬り、さらに張嶷を流星鎚で打って負傷させる。張嶷は諸葛亮の前で「王雙、英雄無敵」と言上し、姜維すら「陳倉の城池は堅固、また王雙の助けを得、実に取るべからず」と進軍を諦めた（第九十七回）。諸葛亮にとっても二将を折られたのは痛手で、その対処に頭を悩ませた。\n\nだが「無敵」の正体は、武勇一色の猛将であった。計略も布陣も、彼の手の内には一つもない。第九十八回、蜀軍が退却すると見るや王雙は軍馬を大いに駆って二十余里まで追撃する。そこに待っていたのが諸葛亮の罠だった。営に火が放たれ、伏せていた魏延が躍り出る。流星鎚を秘めた剛の将は、なすすべもなく「措手不及」のうちに一刀で斬り捨てられた。\n\n前半であれほど誇張して強く描かれた男が、奇計の前に一瞬で崩れ去る。王雙は、諸葛亮の戦術の冴えを際立たせるために配置された猛将だったといえる。武の数値は本物でも、それを生かす知恵の手綱を持たなかった。その落差こそが、北伐の物語に独特の苦みを添えている。"}, {"id": 52, "name": "陳宮", "faction": 3, "role": "文官", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 7, 6, 4], "p": [4, 3, 1, 5, 2, 5], "scores": {"W": 1.0, "B": 5.2, "S": 5.8, "A": 5.75, "G": 3.27, "K": 3.35}, "stat": {"dmg": 1.5, "area": 1.25, "cd": 1.08, "amount": 2, "knock": 0.72, "crit": 0.05, "duration": 4.0, "pwr": 5.65}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [4, 5, 10, 11, 12, 13, 14, 15, 16, 17], "chapN": 12, "bio": "中牟県令、曹操を逃すが後に離反", "profile": "陳宮は中牟の県令から身を起こし、やがて呂布の幕下に入った文官である。剣を取って戦う将ではなく、ひたすら計を献ずる人。その実像を一言で言えば、「策はことごとく的中するのに、主君に容れられぬ献策者」だった。曹操陣営の劉曄でさえ「呂布は無謀なれど、陳宮は計多し」と警戒した。\n\nその智謀の冴えは随所に光る。曹操が東征して兗州が空くと見るや、陳宮は張邈に「呂布は当世の勇士、与に兗州を取らば伯業図るべし」と説き、実際に兗州・濮陽を奪取させた（第十一回）。濮陽では田氏を使った内応の罠を仕掛け、「四門に火を放ち、外に伏兵を設く」る策を立てる（第十二回）。下邳では将軍を外に屯せしめ自らは城を守り糧道を断つ「掎角之勢」を進言した（第十九回）。劉備を小沛に置いて羽翼となせと配置を説き（第十五回）、袁術との聯姻の裏を「玄徳の頭を取らんとするか」と即座に見抜く外交眼も持っていた（第十六回）。\n\nところが、その悉くが呂布の「吾、匹馬もて天下を縦横す」の一言で退けられ、不採用がそのまま敗北に直結する。武の記録は皆無に近く、唯一の手出しは下邳城頭から曹操の麾蓋に放った一矢、それも「曹操を奸賊と大罵」しながらの威嚇射撃だった（第十九回）。策士としての悲劇が、彼の生涯を貫いている。\n\n人物としての格が頂点に達するのは、白門楼の最期である。捕らえられた陳宮は命乞いをせず、従容として死に就いた。老母妻子の処遇を曹操に委ねるその姿は、武勇でも智謀でもなく、節義そのものの輝きだった。容れられぬ正論を抱いて散った義士。だからこそ後世、陳宮は呂布よりも深く惜しまれ続ける。"}, {"id": 53, "name": "曹彰", "faction": 1, "role": "その他", "rarity": 4, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [5, 6, 7, 3, 3, 2, 4], "p": [1, 1, 1, 1, 2, 2], "scores": {"W": 5.5, "B": 3.3, "S": 2.5, "A": 2.55, "G": 1.25, "K": 2.05}, "stat": {"dmg": 1.49, "area": 1.2, "cd": 0.98, "amount": 1, "knock": 1.25, "crit": 0.07, "duration": 0, "pwr": 5.55}, "title": "群雄", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [72, 78, 79, 110], "chapN": 4, "bio": "曹操の次子(卞氏所生)", "profile": "曹彰は曹操の次子、卞氏の生んだ猛将子である。字は子文、黄色い髭から「黄鬚兒」の異名を持つ。少くして騎射を善くし、「膂力人に過ぎ、能く手づから猛獣を格つ」――素手で猛獣を打ち殺すという身体の逸話を背負う（第七十二回）。「大丈夫まさに衛青・霍去病に学び、沙漠に功を立て、数十万の衆を長駆して天下を縦横すべし。何ぞ博士たるを能くせんや」と、ひたすら武人たらんと欲した男だった。\n\nその実戦の見せ場は、漢中の戦いに集約される。劉備配下の劉封と打ち合えば、わずか三合で劉封を大敗させて退ける。続いて呉蘭と交鋒し、数合のうちに一戟で馬下に刺し殺した（第七十二回）。父曹操も「黄鬚兒来らば、劉備を破ること必せり」と頼みにし、玄徳を「履を売る小児」と罵りながら、この息子の到来を待ち望んだ。烏桓・代郡の平定では「身、戦陣に先んじ、直ちに桑乾に殺し至り、北方皆平らぐ」と一行で要約される。\n\nただ、その武は「勇にして謀なし」と父自身に評された通り、計略や布陣の冴えは描かれない。平定も「先頭で突撃する」個人武勇の延長であった。そして第七十九回、曹操が没すると、十万の兵を率いて璽綬の所在を問い、即位の争いに加わる気配を見せる。だが諫議大夫賈逵が「家に長子あり、国に儲君あり、先王の璽綬は君侯の宜しく問うべき所にあらず」と正色して退けると、気勢を削がれてしまう。\n\n結局、曹彰は左右の将士を叱退し、隻身で城に入って曹丕に拝謁し、兄弟相抱いて大いに哭いて、本部の軍馬をことごとく曹丕に引き渡した。強そうに現れて、詰められると引く。武一辺倒の英傑というより、本文の彼は身を退く潔さでこそ印象を残す。鄢陵に帰って自守したその後半生に、猛将子の哀しみがにじむ。"}, {"id": 54, "name": "周泰", "faction": 2, "role": "武将", "rarity": 4, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [6, 5, 6, 3, 4, 2, 4], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 5.5, "B": 3.85, "S": 2.75, "A": 2.9, "G": 1.12, "K": 1.75}, "stat": {"dmg": 1.49, "area": 1.15, "cd": 0.93, "amount": 1, "knock": 1.18, "crit": 0.07, "duration": 0, "pwr": 5.55}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [15, 44, 48, 51, 55, 61, 68, 75, 82, 83], "chapN": 18, "bio": "呉の武将、張南に飛び乗り斬る", "profile": "周泰は呉に仕えた武将、その本領は敵将を斬ることよりも、身を捨てて主君を守る護衛の鑑にある。満身創痍の忠勇の士――この通説の像は、演義本文と寸分たがわず重なる。孫策に見出されて以来、彼は主君の盾であり続けた。\n\nその忠勇が刻まれたのが、二度の決死の救出である。宣城で孫権が囲まれた折、周泰は「赤体歩行、刀を提げて賊を殺し、十余人を砍殺」した。馬上の賊が槍で突きかかると、その槍を素手で掴んで賊を馬から引き倒し、馬と槍を奪い、血路を開いて孫権を救い出す。このとき身に十二の槍傷を負った（第十五回）。さらに濡須では三たび重囲に殺し入り、孫権と徐盛を救出。「槍を被ること数十、膚は刻畫の如し」、鎧を貫く矢を浴びてなお突き進んだ（第六十八回）。孫権は涙してその身体を一つ一つ指さし傷の由来を語らせ、青羅傘を賜い、「卿は孤の功臣なり、孤まさに卿と栄辱を共にし休戚を同じうすべし」と誓った。\n\n名のある敵将の確かな討ち取りは、夷陵で沙摩柯を二十余合で斬った一例にほぼ限られる（第八十四回）。多くは韓当や蔣欽と組んだ二人組、先鋒、伏兵の要員として動く分隊長格であり、献策をしても陸遜に却下されるのが常だった。夷陵の火攻でも、計を立てたのは陸遜で、周泰は江南岸の一軍を率いて茅草に硫黄を仕込み火を放つ実行部隊の長である。独立した方面の采配や国家構想は、彼の役どころではない。\n\nそれでよいのだ、と思わせるのが周泰という男だ。華々しい一騎打ちの無双でも、冴えた計略でもなく、傷だらけの身体そのものが彼の物語である。主を守るために何度でも死地に飛び込む――その捨て身の一点で、周泰は呉の武人たちのなかでひときわ忘れがたい光を放つ。"}, {"id": 55, "name": "李儒", "faction": 3, "role": "軍師参謀", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 6, 7, 0], "p": [6, 6, 3, 5, 6, 7], "scores": {"W": 0.1, "B": 3.8, "S": 5.75, "A": 5.7, "G": 5.43, "K": 4.95}, "stat": {"dmg": 1.46, "area": 1.26, "cd": 1.18, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 4.25, "pwr": 5.35}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [3, 4, 5, 6, 7, 8, 9], "chapN": 7, "bio": "董卓の女婿で謀士", "profile": "李儒は董卓の女婿にして謀士、その政治思想の核は「名正言順」――事を成すにはまず大義名分を整えよ、という冷徹な論理である。毒酒で少帝を弑する実行役として悪名高いが、本文を精読すれば、彼の本質は大局を読む理に適った策士であり、単なる悪役ではない。\n\nその献策は一貫して質が高い。初登場の第三回、上洛に際して「奉詔すといえども中間多く暗昧あり、何ぞ人を差して上表せざる、名正言順なれば大事図るべし」と進言し、董卓の行動に正統性の体裁を与える。第四回には廃立の策文を起草・宣読し、少帝廃位と陳留王擁立を「応天順人」の名分で正当化した。蔡邕を「名流を擢用して人望を収む」として登用させ、洛陽富戸の財産没収で軍資を捻出する策まで立てる。第六回の遷都長安は白眉で、関東諸侯連合に抗しきれぬ局面で本拠を西に移し政権を温存させる大判断であり、董卓に「汝が言にあらずんば、吾実に悟らず」と言わしめた。同じ第六回の滎陽の伏兵計では、追う曹操軍を放過させてから背後を断つ罠を授け、呂布に「李儒が料る所に出でず」と勝利を収めさせている。\n\n最も鋭いのは、危機を読む眼である。第九回、貂蟬をめぐって呂布の心が離れると察し、「太師、婦人の為に惑わさるべからず」「貂蟬を奉先に賜与せよ」と進言した。だが董卓が色をなして「貂蟬の事、再び言うなかれ、言わば必ず斬らん」と拒むや、李儒は退出して天を仰ぎ嘆いた――「吾等、皆な婦人の手に死せん」。その予言は、寸分たがわず的中する。\n\n戦闘の記録は皆無で、第九回ではむしろ自分が董卓を誤って撞き倒す側に回る。皮肉なのは、最良の進言を主君に拒まれた途端に自陣営の滅亡を正確に見通し、その通りに滅んでいく点だ。容れられぬ正論を述べて散った謀士――悪辣な毒役の顔の裏に、李儒はそんな哀しい賢さを隠している。"}, {"id": 56, "name": "法正", "faction": 0, "role": "軍師参謀", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 7, 6, 3], "p": [4, 3, 3, 5, 6, 6], "scores": {"W": 1.0, "B": 4.95, "S": 5.7, "A": 5.7, "G": 4.27, "K": 4.5}, "stat": {"dmg": 1.49, "area": 1.25, "cd": 1.09, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 4.0, "pwr": 5.55}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [60, 61, 62, 63, 64, 65, 70, 71, 73, 77], "chapN": 12, "bio": "益州の士。張松の盟友で劉備を内応で迎える", "profile": "法正は益州の士、賢士法真の子であり、張松の盟友として劉備を蜀に内応で迎え入れた人物である。演義における彼は「川取りの内応者」から「劉備の謀臣」へと立場を移す純然たる文官・参謀で、白兵も膂力も武名の描写も一切ない。剣ではなく策で歴史を動かす男だった。\n\nその戦術力の核は、定軍山にある。第七十一回、法正は夏侯淵を評して「淵は人と為り軽躁、勇を恃みて謀少なし。士卒を激励し、寨を抜きて前進し、歩歩営を為し、淵を誘いて来り戦わしめて之を擒にすべし。此れ乃ち反客為主の法なり」と説く。そして以逸待労、白旗と紅旗で機を計り、午の時に紅旗を振って黄忠に総攻めをかけさせ、ついに敵総帥夏侯淵を斬らせた。劉備が「天の賜なり」と益州奪取を決断したのも、漢中を取れば「進んでは賊を討つべく、退いては自ら守るべし」と方面戦略を描いて漢中平定へ繋げたのも、彼の大局眼の産物である（第六十、七十回）。\n\n人物としての陰影も本文は容赦なく描く。蜀郡太守となった法正は「平日一餐の徳、睚眦の怨、報復せざるは無し」――小さな恩も小さな怨みも必ず報いる狭量さで知られた（第六十五回）。寛刑を主張して諸葛亮に「君は其の一を知りて、其の二を知らず」と論破される場面もある。それでも孔明がこの男の「翼翼の功」ゆえに私怨を黙認したという逸話が、彼の複雑な魅力を際立たせている。\n\n劉備が最も信頼した参謀であったことは、その死後の一文が決定づける。夷陵の敗報に接した諸葛亮は怏々として楽しまず、群臣を顧みて嘆いた――「法孝直若し在らば、必ず能く主上の東行を制せん」（第八十一回）。君主の暴走を唯一止めえた男。生前、鄭度の焦土策を「劉璋必ず用うる能わず」と即座に見抜いたその眼が、もし夷陵の前に開かれていたら。法正の早すぎる死は、蜀漢の運命に深い影を落としている。"}, {"id": 57, "name": "関興", "faction": 0, "role": "武将", "rarity": 4, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [6, 6, 4, 5, 4, 2, 4], "p": [1, 1, 1, 1, 3, 2], "scores": {"W": 5.4, "B": 3.95, "S": 2.85, "A": 3.1, "G": 1.38, "K": 2.35}, "stat": {"dmg": 1.45, "area": 1.12, "cd": 0.93, "amount": 1, "knock": 1.13, "crit": 0.1, "duration": 0, "pwr": 5.3}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [81, 82, 83, 84, 92, 93, 94, 95, 98, 99], "chapN": 25, "bio": "関羽の次子、戦功文書を成都に届ける", "profile": "関興は関羽の次子、父の青龍偃月刀を継ぎ、蜀漢の若手二枚看板の一方として張苞と並び称された武将である。第九十一回には「龍驤将軍・左護衛使」の号を帯び、北伐の常設先鋒格に据えられる。劉備は彼ら甥にあたる若武者を見て「虎父に犬子なし」「二姪かくの如く英雄なり」と目を細めた。\n\nその白兵戦果は、夷陵の戦いで一気に開花する。李異を馬下に劈ち（第八十二回）、董禧を「吾が一刀に斬る」と討ち取り（第九十二回）、北伐では羌の越吉元帥を「交馬ただ一合、興、刀を挙げて大喝一声、馬下に砍死す」と斬り捨てた（第九十四回）。父の仇潘璋を討つ場面（第八十三回）は、関公の顕聖――亡き父の霊の加護のうちに描かれ、武功山では「龍驤将軍関興」の大旗を見ただけで魏兵が「甲を棄て戈を抛ちて走る」（第九十五回）。夷陵の後には「江南の諸将、胆を寒からしめざるはなし」と恐れられた。\n\nただし、その武勇は中堅猛将級にとどまる。孫桓と三十余合戦って勝ち切れぬこともあり、鉄車兵を前に「敵を破るの策なし」と自認する場面もある。北伐では先鋒・伏兵・接応を任されるが、計略を立てるのは常に諸葛亮で、関興は「かくの如くかくの如く」と密計を授かって実行する手駒だった。軍令を遵守し、勝手な追撃を慎む規律ある将――それが本文の彼の輪郭である。\n\n物語の上で関興がもつ重みは、武勲よりも血脈の象徴性にある。第八十一回、劉備は関興を見て関羽を想い号泣し、関興と張苞は帳前で折箭の誓いを立て、永く相救護せんと誓った。桃園の義を次代に継ぐ姿である。だが彼は第百二回で病没し、早くに退場する。父の偉大さを背負いながら、自らの物語を全うしきれなかった若き将。その短い生涯が、かえって関羽という巨星の余光の深さを物語っている。"}, {"id": 58, "name": "曹叡", "faction": 1, "role": "君主", "rarity": 4, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 1, 0, 3, 4, 5], "p": [3, 7, 2, 1, 6, 6], "scores": {"W": 0.25, "B": 3.2, "S": 3.65, "A": 3.3, "G": 4.07, "K": 5.55}, "stat": {"dmg": 1.18, "area": 1.05, "cd": 1.15, "amount": 1, "knock": 0.67, "crit": 0.04, "duration": 3.5, "pwr": 3.35}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [27, 91, 92, 93, 94, 95, 96, 103, 105, 106], "chapN": 16, "bio": "曹丕の子、魏の皇帝（明帝）", "profile": "曹叡は曹丕の子、魏の第二代皇帝・明帝である。甄夫人の実子にして郭后の養子、文帝の没後、曹真・陳群・司馬懿・曹休ら託孤の重臣に擁立されて大魏皇帝に即位した（第九十一回）。武力の描写は皆無で、純粋に君主としての器量を問われる人物――そして本文の彼は、賢と愚の混じり合った守成の天子として描かれる。\n\n最大の長所は人材を見抜く眼である。一度は反間計に乗って司馬懿を罷免したものの（第九十一回）、蜀の侵攻という危機に際して鍾繇の保挙でこれを復職させ、平西都督に加えて全権を委ねた（第九十四回）。孟達討伐の手際を見ては「卿の学識、孫・呉に過ぐ」と賞し、便宜行事の権まで与える。誤って退け、危機に再び用いる――その曲折を経てなお、結果として国家を支える人材を見抜き使い切った点で、曹叡の登用力は確かだった。蜀軍来寇には御駕親征し、合淝では自ら大軍を率い、群臣の撤兵諫言を退けて司馬懿への補給を貫いた統御の記録も複数残る。\n\nだが、その治世には濃い影が差す。後半の曹叡は明確に暴君化した。許昌で大いに土木を興し、「天下の巧匠三万余人、民夫三十余万を選び、昼夜を分かたずして造らしむ」、芳林園の造営には公卿にまで土を負い木を植えさせた。董尋や楊阜の諫言を退け、諫臣張茂を斬り、「民力疲困し、怨声絶えず」と本文は明記する。私情に駆られて毛皇后を賜死させもした。即位前には「仁徳の主」と讃えられた人が、晩年には民を疲弊させる失政の主に転じていく。\n\nその最期は、皮肉に満ちている。臨終の曹叡は司馬懿の手を執り、劉備の白帝託孤に倣って八歳の曹芳を司馬懿と曹爽に託した――「太尉および宗兄、力を竭して相輔け、朕が心に負くなかれ」（第百六回）。在位十三年、明帝として葬られ廟号を得た。だがこの託孤こそが、やがて司馬氏が魏を簒奪する布石となる。継承体制を組んだその一手が、王朝の墓穴を掘ったのだ。賢明と暗愚を一身に抱えたまま、曹叡は魏の黄昏へと幕を引いた。"}, {"id": 59, "name": "朱雋", "faction": 3, "role": "武将", "rarity": 4, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [2, 1, 1, 1, 7, 4, 6], "p": [2, 5, 2, 2, 5, 3], "scores": {"W": 1.45, "B": 5.5, "S": 4.8, "A": 4.85, "G": 3.11, "K": 4.45}, "stat": {"dmg": 1.44, "area": 1.25, "cd": 1.01, "amount": 3, "knock": 0.72, "crit": 0.05, "duration": 8.4, "pwr": 5.2}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [1, 2, 10, 13], "chapN": 4, "bio": "中郎将、黄巾討伐の将。後に曹操を推挙", "profile": "朱雋は後漢の中郎将、皇甫嵩と並ぶ黄巾討伐の名将である。演義での彼は、個人の白兵や武名ではなく、采配の知略でこそ光る純粋な指揮官型として描かれる。先鋒は終始、劉備・関羽・張飛や孫堅といった豪傑に委ね、自らは戦術を組み立てる司令官の座にあった。\n\nその本領は、黄巾平定の多彩な用兵に現れる。長社では「賊、草に依りて営を結ぶ、まさに火攻を用うべし」と、二更の後に一斉に火を放ち、皇甫嵩とともに賊寨を襲って「火焔天に張り、賊衆驚慌」たる大勝を得た（第一回）。張宝が妖術を操れば、豬羊狗の血と穢物を山頭から潑がせてその妖法を解く奇策で応じる。宛城では四面を囲んだうえで「東南を撤去し、独り西北を攻む」る心理戦を仕掛け、韓忠を城外に誘い出して殲滅した（第二回）。火攻、対妖術、囲城の誘出――異質な戦術を次々と成功させる将であった。\n\n人物眼にも見るべきものがある。山東の黄巾鎮圧には「曹孟徳にあらずんば不可」と曹操を朝廷に推挙し、曹操が青州兵三十万を編成して威名を確立する契機を作った（第十回）。頼って来た劉備三兄弟を厚遇して合兵し、孫堅を麾下で奮戦させ、配下を四門に振り分けて連携させ十数郡を平定する。離反や軍崩壊の負の記録は一つもない、堅実な統率者だった。\n\n終盤、朱雋は李傕・郭汜の専横という乱世の暗部に飲み込まれる。漢朝の大司農として献帝を救おうと曹操召致の計に加わるが、郭汜に監禁されて打開できず、楊彪と相抱いて「社稷の臣たり、君を匡し主を救う能わず、空しく天地の間に生くるのみ」と慟哭し、昏絶した。帰宅後、憤りのうちに病を発して死す（第十三回）。妖術を破り賊軍を焼き払った名将も、傾く漢室そのものは救えなかった。社稷を匡せぬまま憤死した忠臣――その無念が、英雄たちの黎明期を締めくくる影として残る。"}, {"id": 60, "name": "張昭", "faction": 2, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 1, 2, 2], "p": [5, 5, 5, 6, 7, 6], "scores": {"W": 0.1, "B": 1.3, "S": 1.7, "A": 1.55, "G": 5.53, "K": 5.15}, "stat": {"dmg": 0.81, "area": 0.91, "cd": 1.21, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.0, "pwr": 1.55}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [15, 29, 38, 43, 44, 53, 55, 61, 65, 82], "chapN": 25, "bio": "呉の第一の謀士、降伏論の筆頭で舌戦群儒に登場", "profile": "呉に仕えた文官の筆頭、字は子布。「経天緯地の才」と称えられた大儒であり、孫策が江東に覇を唱えた頃から右腕として政務を支えた、孫呉政権の屋台骨ともいうべき人物である。武の記録はほとんど無い。彼の戦場はあくまで朝堂であり、典礼であり、外交の卓であった。\n\n孫策が刺客に襲われ世を去る間際、張昭はその枕頭に呼ばれ「内事決せずんば張昭に問え」と後事を託される。事実上、江東の摂政役を委ねられたのである。第二十九回、主を喪って床前に泣き崩れる孫権に、彼は「今は将軍の哭する時に非ず」と諫め、一面に喪事を治め、一面に軍国の大事を理めよと立ち直らせた。慟哭する若き主君を実務へと引き戻すこの一場面に、彼の本質が凝縮されている。第四十三回の赤壁前夜、彼は「曹操は百万の衆を擁し天子の名を借る」として降を勧め、孫劉同盟を説く諸葛亮の前に立ちはだかる舌戦群儒の筆頭となった。第八十二回では、上国の天使と驕って車を下りぬ魏の使者邢貞を「江南に方寸の刃無しと思うか」と一喝し、慌てて下車させている。\n\n通説では「赤壁で降を唱えた腰抜けの大儒」と語られがちだが、本文の張昭は誤った臆病者というより、長江一河に拠る現実主義者として描かれる。だからこそ周瑜には「これ迂儒の論なり」と一蹴された。後の陸遜起用論議では「乃ち一書生のみ、劉備の敵手に非ず」と読み違える描写もあり、判断は常に正しいわけではない。それでも喪事の処理、国家の典礼、即位の進言、使者への弁舌と、統治の実務全般を一手に担い続けた重みは揺るがない。\n\n第九十八回、孫権の皇帝即位にあたっては「武昌東山に鳳凰来儀し、大江の中に黄龍屢々現る」と瑞祥を並べ、「徳は唐虞に配し明は文・武に並ぶ」と帝位を奉る正統性論を主導した。群臣はこぞって「子布の言、是なり」と応じたという。孫家三世の基業を典礼として完成させた立役者であり、戦場に一度も立たずして一国の背骨であり続けた、稀有な文官の姿である。"}, {"id": 61, "name": "陸抗", "faction": 2, "role": "武将", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 3, 1, 4, 6, 5, 6], "p": [1, 1, 2, 5, 1, 4], "scores": {"W": 2.15, "B": 5.35, "S": 5.3, "A": 5.3, "G": 2.14, "K": 2.45}, "stat": {"dmg": 1.28, "area": 1.18, "cd": 1.03, "amount": 2, "knock": 0.86, "crit": 0.08, "duration": 3.75, "pwr": 5.35}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [119, 120], "chapN": 2, "bio": "陸遜の子、鎮東大将軍。羊祜と徳で対峙するが孫皓に兵権を奪われる", "profile": "陸遜の子にして鎮東大将軍、呉が傾きゆく終盤に登場する最後の名将である。演義での出番は第百十九回・第百二十回のわずか二回。一騎打ちの猛将としてではなく、足智多謀の守将、そして敵将と徳を応酬しあう知将として描かれる。\n\n物語は晋の名将・羊祜との対峙に尽きる。第百二十回、陸抗は呉主の命を受けて西陵を攻め落とし、叛いた步闡とその将士数十人を斬った。これは彼自身の白兵ではなく、司令官としての会戦の戦果である。救援に向かった羊祜は「救うに及ばなかった」と認めた。二人の対峙はやがて武から徳へと移る。陸抗は「彼は専ら徳を以てし、我は専ら暴を以てす、是れ彼の将は戦わずして我を服せん」と見抜き、「今は宜しく各々疆界を保つのみ、細利を求むる無かれ」と軍を律した。羊祜が酒を贈れば斗酒を返し、薬を贈られれば疑わずに服す。「是れより人をして問を通ぜしめ、常に相往来す」と、戦わずして秩序を保つ君子の交わりが成立したのである。羊祜もまた「羊将軍の兵は紀律あり」と認め、晋軍全体が「自ら疆界を守る」守勢に回った。「此の人将たり、我等只だ自守すべきのみ、其の内に変あるを候ちて方めて図るべし」とは、敵将みずからが部下を戒めた言葉である。\n\nその実像は、戦わずして国境を安んじた知略の将であり、同時に悲運の臣でもあった。彼は「晋未だ伐つべからざるの状」を備さに述べ、孫皓に「徳を修め罰を慎み、内を安んずるを念とせよ、黷武を事とすべからず」と上奏する。国の長期の安定を見据えた諫言であったが、暴君孫皓には容れられず、かえって兵権を奪われ司馬に降格された。徳を以て国境を保った最後の柱が抜かれたとき、呉の命運もまた定まった。武ではなく智と徳で名を残した、滅びゆく国の掉尾を飾る将である。"}, {"id": 62, "name": "魏延", "faction": 0, "role": "武将", "rarity": 3, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [6, 6, 2, 4, 6, 5, 3], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 4.8, "B": 5.0, "S": 5.0, "A": 5.15, "G": 1.0, "K": 1.4}, "stat": {"dmg": 1.18, "area": 1.02, "cd": 0.92, "amount": 1, "knock": 0.94, "crit": 0.08, "duration": 0, "pwr": 4.6}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [62, 63, 65, 70, 87, 90, 98, 101, 102, 103], "chapN": 36, "bio": "義陽の人、襄陽で蔡瑁を罵り城門を開く、後に長沙の韓玄に身を寄せる", "profile": "義陽の人、蜀漢に仕えた大刀の猛将。「身の丈八尺、面は重棗の如し」と関羽を思わせる威容で描かれ、漢中王劉備が東川を委ねる漢中太守に、張飛を差し置いて抜擢したほどの実力者である。だがその名は、武勇と同じだけ「反骨」の二字で記憶されている。\n\n第五十三回の初登場からして印象的だ。長沙にあって主君の韓玄を斬り、城頭へ駆け上って「一刀韓玄を砍りて両段と為し、頭を提げて馬に上る」――そうして劉備に降った。孔明はその所作を見て、彼の脳後に反骨の相ありと断じる。以後の活躍は確かに華々しい。第九十八回では孔明の妙計を受けて伏兵を伏せ、魏将王雙を「延が一刀に砍りて馬下に」斬る。第八十七回では孟獲を生け捕り、第六十三回では冷苞を活捉した。第九十二回では「精兵五千を得て褒中に路を取り、秦嶺に循いて子午谷より北に投ぜば、十日を過ぎずして長安に到るべし」と、かの子午谷の奇策を献じている。武将みずから国家規模の大局を語る稀有な一幕だ。だが孔明は「万全の計に非ず」と一蹴した。\n\n通説では同情的に語られがちだが、本文の魏延はより両義的に描かれる。子午谷を退けられて「怏怏として悦ばず」、第百回では陳式を扇動して号令を公然と嘲り、「丞相若し吾が言を聴かば、長安は言うを休めよ、洛陽すら皆得たらん」とまで言い放つ。有能だが終始「心正しからず」「功を恃み高きを務む」問題の将――それが演義の核である。武勇は本物だが、その多くは孔明の密計の駒として動く、使い手次第の刃であった。\n\n第百五回、孔明が没すると魏延はついに楊儀への権限移譲を拒み、桟道を焼き、南鄭を攻めて反乱を起こす。「大丈夫、何ぞ自ら覇業を図らず、乃ち軽々しく人に膝を屈せんや」と。だが彼が率いた川兵は何平の一声で「大いに喊する一声、散じ去ること大半」と離れていった。最後は心助けと信じた馬岱に斬られ、「天下誰か敢えて我に敵せん」と三たび叫んだところで首を落とされる。人を見る目を欠き、人望を失って配下に討たれた最期は、武勇のみで名将たり得なかった彼の生涯を、皮肉なほど鮮やかに締めくくっている。"}, {"id": 63, "name": "張苞", "faction": 0, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [6, 5, 4, 4, 2, 1, 3], "p": [1, 1, 1, 1, 2, 1], "scores": {"W": 5.1, "B": 2.6, "S": 1.6, "A": 1.75, "G": 1.13, "K": 1.7}, "stat": {"dmg": 1.24, "area": 1.09, "cd": 0.96, "amount": 1, "knock": 1.08, "crit": 0.08, "duration": 0, "pwr": 5.05}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [81, 82, 83, 84, 91, 92, 93, 94, 95, 97], "chapN": 15, "bio": "張飛の長子。丈八矛を使い関興と義兄弟を結び奮戦", "profile": "張飛の長子、蜀漢の若き槍の将。父譲りの丈八点鋼矛を操り、声は巨雷の如しと描かれる。関興と義兄弟の契りを結び、蜀後期の若手双璧として「虎父に犬子なし」と讃えられた、勇将の血筋を象徴する存在である。\n\nその白兵は確かに鋭い。第八十二回、夷陵の戦いで「奮勇当先、呉軍に殺入し、正に謝旌に遇い、苞が一矛に刺し死す」と謝旌を貫き、崔禹を「交馬只だ一合、苞に生擒せられて回る」と捕らえた。第八十三回では夏恂が彼の大喝と巨雷の声に「心中驚懼」して逃げかかる。先主劉備みずから「虎父に犬子無きなり」と評したのもこの頃だ。第九十一回には「右護衛使虎翼将軍」の号を帯び、北伐では関興とともに各所で奮戦する。\n\nただし、その実像は単独で戦を完結させる名将というより、孔明の密計を確実にこなす前線の突撃・救援要員であった。「汝二人各々一軍を引き、祁山の要路に伏せよ」――張苞の戦は常にこうした孔明の分付を受けての伏兵・接応であり、自ら計略を立て布陣した記録は本文に無い。一騎打ちの相手も孫桓の部将や羌将の補佐ら中堅以下に集中し、超一流の将を独力で討った場面はない。それでも父の矛を継ぎ、国と父のため「万死辞せず」と誓ったその姿は、蜀の正統を継ぐ若武者の輝きを確かに放っていた。\n\n最期は戦場ではなく、不慮の事故によって訪れる。第九十九回、敗走する郭淮を追撃するさなか、谷あいへ「跌入し、頭已に跌破る」と落馬して大怪我を負い、ほどなく病に倒れた。成都から訃報が届くと、孔明は「放声大哭、口中血を吐き、地に昏絶す」――北伐の只中で稀代の軍師を昏倒させるほど、その早世は蜀にとって痛恨であった。猛将の血脈に懸けられた期待の大きさが、その死の重さに表れている。"}, {"id": 64, "name": "李典", "faction": 1, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [4, 4, 3, 2, 6, 3, 6], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 3.55, "B": 5.15, "S": 4.0, "A": 4.1, "G": 1.12, "K": 2.15}, "stat": {"dmg": 1.05, "area": 1.0, "cd": 0.95, "amount": 2, "knock": 0.91, "crit": 0.06, "duration": 0, "pwr": 3.5}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [6, 12, 14, 18, 24, 31, 33, 36, 39, 53], "chapN": 25, "bio": "曹操配下の武将、連環計を諸葛亮の詐謀と疑う、合淝副将", "profile": "曹操配下の古参の将、字は曼成。学を好む儒将として知られ、樂進と対をなす中堅の重鎮である。白兵で華々しく舞うより、敵情を冷静に測り、危険を予見する慎重さで描かれる「読みの将」だ。\n\nその真価は戦術眼にある。第三十六回、曹仁が劉備への軽進を逸ろうとすると、李典は「劉備は人傑なり、軽視すべからず」と二度諫め、趙雲・徐庶の智略と劫寨の備えを見抜いた――結果はことごとく的中する。第三十九回の博望坡では「南の道路は狭く、山川相逼り、樹木叢雑す、倘し彼火攻を用いなば奈何せん」と地形から火計の危険を言い当てた。一騎打ちでは、第三十六回で趙雲と十数合戦って「敵し難きを料り、馬を撥して陣に回る」と退く脇役だが、第十二回では黄劭を「乗勢飛馬して賊陣に直入し」生け捕り、第五十三回では宋謙の心の臓を一射で射落とす騎射の冴えも見せている。曹操が自軍を誇る際には「許褚・樂進・李典、勇当たるべからず、岑彭・馬武と雖も及ばず」と並べ称えられた。\n\nその人となりが最も鮮やかに出るのは、第六十七回の逍遥津である。李典は素より張遼と不仲であった。だが大事を前に「将軍此くの如くば、典豈に敢えて私憾を以て公事を忘れんや、願わくは指揮を聴かん」と慨然と立ち上がり、進んで伏兵を引き受ける。私情を公務に従わせるこの自制こそ、彼の将才の核である。少数で十万を破る連携を成立させた立役者でありながら、戦後の畏怖は「張遼の名を聞けば小児も夜啼を敢えてせず」と専ら張遼に帰された。脇に徹し、功を誇らぬ将であった。\n\n国家構想や内政、外交の表舞台に立つ人物ではなく、あくまで戦場の予見と自制で味方を支え続けた。武勇の主役は許褚・典韋・張遼に譲りながら、その冷静な読みと公私を弁えた気骨で、曹操軍の屋台骨を地味に、しかし確かに担い続けた古参の良将である。"}, {"id": 65, "name": "夏侯渕", "faction": 1, "role": "武将", "rarity": 3, "weapon": "bow", "kind": "proj", "weaponName": "弓", "d": [6, 5, 4, 3, 5, 4, 6], "p": [1, 1, 3, 1, 2, 2], "scores": {"W": 5.0, "B": 5.1, "S": 4.4, "A": 4.35, "G": 1.61, "K": 2.45}, "stat": {"dmg": 1.31, "area": 1.18, "cd": 0.89, "amount": 2, "knock": 1.03, "crit": 0.07, "duration": 0, "pwr": 5.65}, "title": "弓の将", "skill": "弓", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [6, 12, 18, 19, 24, 31, 58, 59, 64, 67], "chapN": 24, "bio": "曹操配下の武将、馬歩右軍白旗を率いる", "profile": "曹操配下の弓の将、字は妙才。馬歩右軍の白旗を率い、長安に屯して馬超を拒ぎ、漢中を任された「西涼の藩屏」である。曹操が他人に託さず単独で方面を委ねた数少ない将でありながら、本文での描かれ方は二面的だ。将才を認められる一方、大将の器に一歩届かぬ猛将――それが演義の夏侯淵である。\n\n身体技の見せ場は第五十六回、銅雀台の射芸大会にある。「紅袍隊中、一将飛馬して出で」、馬を駆けながら身を捻って射た矢が「四箭の真ん中、正に紅心に在り」――騎射の冴えで満座を沸かせた。白兵も巧い。第六十七回では昌奇を三合で斬り、楊任とは三十余合戦った末に佯敗して誘い込み、拖刀計で馬下に斬り落とした。馬超を追い、成宜を破り、戦果は確かに豊かである。だが孔明が「淵は深く韜略に通じ、善く兵機を暁る」と高く評させる一方、劉備は「乃ち一勇夫のみ」と切り捨て、曹操すら書状で「淵性太だ剛なり、剛柔相済うべし、徒らに其の勇を恃む勿れ、若し但だ勇を任ぜば則ち是れ一夫の敵のみ」と諫めている。\n\nその性の剛さが、最期を決した。第七十一回、定軍山にあって夏侯淵は法正の「反客為主」「以逸待労」の計に終始翻弄される。曹操は「妙才」の字を辱めるなと書状で命じたが、その妙才を発揮できぬまま、張郃の「堅守すべし」という再三の諫めを退けて出戦した。結果、黄忠に「頭から肩へかけて、砍りて両段と為す」と斬り落とされ、全軍は「曹兵大いに潰え、各自生を逃る」と崩壊する。妙才を観んと記された直後に妙才を示せず討たれる、皮肉な配置であった。\n\nただ将としての統治には堅実な一面もある。第六十四回では馬超を破った後、西涼諸州の人民を自ら安撫し、姜叙らに分守させ、楊阜を許都へ送る差配を見せた。後年、その四子は父の仇を報じようと志を継いでゆく。猛将ではあったが、剛に過ぎて方面を崩した――その生涯は、勇のみでは大将たり得ぬという、曹操の諫言そのものを体現している。"}, {"id": 66, "name": "田豊", "faction": 3, "role": "軍師参謀", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 6, 6, 2], "p": [4, 0, 1, 2, 3, 5], "scores": {"W": 0.0, "B": 4.1, "S": 5.3, "A": 5.2, "G": 2.35, "K": 2.65}, "stat": {"dmg": 1.23, "area": 1.22, "cd": 1.15, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 4.0, "pwr": 5.0}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [7, 22, 24, 25, 27, 30, 31], "chapN": 7, "bio": "袁紹の謀臣、諫言で殺される", "profile": "袁紹に仕えた河北の謀臣、別駕の任にあった軍師である。諫言を容れられぬまま非業の死を遂げた悲劇の名軍師――その通説は、演義本文とそのまま一致する。武勇の描写は皆無で、彼の働きはすべて献策にあった。\n\nその戦略眼は的確そのものだった。第二十二回、曹操への挙兵に際しては「兵起こりて連年、百姓疲弊し、倉廩に積無し」と国力の窮乏を見据え、まず天子に献捷して名分を得、黎陽に屯し舟楫軍器を繕い、精兵を辺鄙に分屯して「三年の中に大事定むべし」という段階的な長期構想を描いた。第二十五回・第三十回の官渡でも「久しきを以て之を持し、其の隙あるを待ちて後に動くべし」「今且く宜しく静守して天時を待つべし、妄りに大兵を興すべからず」と持久策を繰り返し進言する。だが袁紹はこれを退け、田豊の予言通り官渡で大敗した。\n\n正しい者が容れられぬ――それが彼の宿命であった。第七回では趙雲が衝き込んできた際、自ら武器を取るどころか「主公且く空牆の中に躲避せよ」と袁紹に退避を促す、根っからの非戦闘の文人である。孔融は彼を「皆忠臣なり」と評し、荀彧は「剛にして上を犯す」とその性格を見抜いていた。諫言が容れられず投獄されると、同僚の沮授が宗族を集め家財を散じて訣別の涙を流したという。\n\n最期は獄中に訪れる。田豊は「袁将軍は外寛にして内忌、忠誠を念わず。若し勝ちて喜ばば、猶お能く我を赦さん。今戦敗して羞ぢなば、吾生を望まず」と、自らの死すらも冷静に予見した。果たして敗れて帰った袁紹は彼を恥じ、田豊は獄中に自刎する。敗軍の将兵が「若し田豊の言を聴かば、我等怎ぞ此の禍に遭わん」と惜しんだのが、せめてもの手向けであった。判断は常に正しく、しかし決定権は持たぬ――諫言型参謀の悲哀を、これほど純粋に体現した人物はいない。"}, {"id": 67, "name": "陳泰", "faction": 1, "role": "武将", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [3, 2, 1, 2, 6, 4, 6], "p": [1, 2, 1, 1, 2, 3], "scores": {"W": 2.2, "B": 5.2, "S": 4.6, "A": 4.6, "G": 1.57, "K": 2.8}, "stat": {"dmg": 1.2, "area": 1.14, "cd": 0.99, "amount": 2, "knock": 0.77, "crit": 0.06, "duration": 3.5, "pwr": 4.7}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [107, 109, 110, 111, 114], "chapN": 5, "bio": "魏の雍州征西将軍、対蜀の智将", "profile": "魏の雍州征西将軍、対蜀戦線を担った智将である。鄧艾と並ぶ隴西の守将として知られるが、本文に描かれる陳泰は個人の武勇に頼る将ではない。断糧・断水・包囲で敵を干上がらせる方面の指揮官であり、良将と摩擦なく協働する調整型の知将であった。\n\nその采配は手堅い。第百七回、麴山では断水・断糧で句安・李歆を干上がらせ、牛頭山では「将軍は一軍を引いて洮水を取り、蜀兵の糧道を断絶せよ。吾は兵を分かちて牛頭山に逕往し、彼若し糧道已に絶つを知らば、必然自ら走らん」と自ら断糧策を立てて姜維を撤退に追い込んだ。第百九回では羌人に詐降する計で俄何焼戈を陥穽に落とし、第百十回では狄道城の東南に二十隊を伏せ、鼓角と烽火で蜀兵を脅す布陣を実行する。ただし姜維との一騎打ちでは「戦うこと三合ならず、泰敗走す」――これは誘兵の計の一環だが、白兵で押す将でないことは確かだ。鄧艾とは「忘年の交わり」を結び、その妙策に「真に神算なり」と感服し、功を再三朝廷に上奏して官爵を得させる度量も見せた。「吾隴西を守ること二三十年、未だ嘗て此くの如く地理を明察せず」とは、鄧艾の眼を一段上に置いた彼自身の言葉である。\n\n陳泰の真骨頂は、武略よりもむしろ最後の気骨にある。第百十四回、司馬昭の手の者によって魏帝曹髦が弒された大政変の折、群臣が揃う中ただ一人遅参した陳泰は、披麻帯孝して霊前に哭し、「独り賈充を斬らば、少しく以て天下に謝すべきのみ」と司馬昭に迫った。次善を問われても「これ以上のものはなく、その次は知らぬ」と退かない。「論者は泰を舅に比す、今舅は実に泰に如かざるなり」と大哭しながら、弒君に対して名分上の筋を一歩も曲げなかったのである。\n\n辺境を二三十年守り抜いた堅実な方面司令でありながら、最も劇的に記憶されるのは、君を弒した権臣の前で正論を吐いた一幕だ。武辺の派手さはないが、智謀と協働の確かさ、そして筋を通す義の心――この三つが、陳泰という将の輪郭を静かに、しかし鮮明に描き出している。"}, {"id": 68, "name": "朱桓", "faction": 2, "role": "武将", "rarity": 3, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [5, 4, 1, 3, 6, 3, 5], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 3.6, "B": 5.05, "S": 3.95, "A": 4.15, "G": 1.12, "K": 1.95}, "stat": {"dmg": 1.23, "area": 1.18, "cd": 0.93, "amount": 3, "knock": 0.82, "crit": 0.07, "duration": 8.0, "pwr": 5.0}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [38, 85, 96], "chapN": 3, "bio": "27歳の呉将。濡須で常雕を斬り曹仁を大敗させる", "profile": "わずか二十七歳にして「極めて胆略あり」と孫権に深く愛された、呉の若き伏兵の将である。登場は実質二戦のみと出番は薄いが、その短い活躍の中に、小物の名将を一刀で斬る白兵と、寡兵で大軍を破る智略の二面が鮮やかに刻まれている。\n\n第八十五回の濡須が彼の代表戦だ。曹仁が常雕ら五万の精兵を率いて押し寄せると、味方は「皆懼色あり」と怯えた。だが朱桓は剣を按じて「勝負は将に在り、兵の多寡に在らず」と動揺を鎮め、「曹仁千里を跋渉し、人馬疲困す。吾汝等と共に高城に拠り、南は大江に臨み北は山険を背にし、逸を以て労を待ち、主を以て客を制す、此れ乃ち百戦百勝の勢なり」と説く。そして全軍に旗を偃せ鼓を息めさせ、無人の城を装って五万を誘い込み、わずか五千で大勝した。攻め寄せた常雕には「横刀飛馬して出で、直ちに常雕を取る。戦うこと三合ならず、桓が一刀に常雕を馬下に斬」る武勇も見せている。第九十六回の石亭でも左都督として張普を一刀で斬り、火攻を成功させた。\n\n智将としての片鱗も確かにある。石亭で朱桓は「曹休を擒にして寿春を取り許・洛を窺わば、乃ち万世一時なり」と、戦果を国家規模の好機へ拡げる大局眼を示し、夾石・桂車の退路を塞ぐ伏兵策を献じた。だがこの献策は総大将の陸遜に容れられず、「不平を懐いて退く」不遇に終わる。\n\n智勇兼備の若将でありながら、独立した方面指揮や統治の記録は本文に残らず、その輪郭だけが鮮やかに浮かぶ。もし献策が容れられていればと惜しませる、呉の終盤を彩る早熟の才であった。"}, {"id": 69, "name": "沮授", "faction": 3, "role": "軍師参謀", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 5, 6, 3], "p": [4, 2, 1, 1, 2, 4], "scores": {"W": 1.0, "B": 4.05, "S": 5.2, "A": 5.0, "G": 2.35, "K": 2.8}, "stat": {"dmg": 1.21, "area": 1.19, "cd": 1.11, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 4.0, "pwr": 4.85}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [7, 22, 25, 26, 27, 30, 31, 32], "chapN": 8, "bio": "袁紹の謀臣（既に戦死、詩で言及）、沮鵠の父", "profile": "袁紹陣営最高の戦略家にして、官渡で正論をことごとく諫めながら容れられず散った悲劇の忠臣。通説のその像を、演義本文もまた概ね支持している。自ら兵を率いた戦果は無く、純粋な参謀型の謀士である。\n\nその大局眼は群雄陣営随一であった。第二十二回、曹操への挙兵に際して「勝を制するの策は強盛に在らず。曹操は法令既に行われ士卒精練す、公孫瓚の坐して困を受くる者とは同じからず」と説き、まず天子に献捷して名分を得てから動くべしという段階的な策を提示する。第二十六回でも「延津に留屯し、兵を官渡に分かつ、乃ち上策と為す」と方面配置を論じた。そして官渡では「彼の軍糧無く、利は急戦に在り。我が軍糧有り、宜しく且く緩守すべし。若し能く日月を曠くせば、則ち彼の軍戦わずして自敗せん」と的確な持久策を、さらに「烏巣は屯糧の所、備えざるべからず。宜しく速やかに精兵猛将を遣り、間道山路を巡哨せしめよ」と、敗北の急所そのものを事前に突く危機予見を進言している。\n\nしかし、その正論は終ぞ実を結ばなかった。袁紹に再三叱責されて鎖禁され、献策を実行に移す権限を持てぬまま官渡の崩壊を迎える。顔良を独任しようとする袁紹に「顔良は性狭く、驍勇なりと雖も独り任ずべからず」と諫めた人を見る目はあったが、許攸とは不和で内部の調整にも苦しんだ。同僚の田豊が投獄された折には、宗族を会して家財を尽く散じ「吾軍に随いて去る、勝たば則ち威加わらざる無く、敗れなば則ち一身保たれず」と訣別し、衆は皆涙して送ったという。\n\n最期もまた、その忠を貫いた。捕らえられても曹操に降らず、ついに処刑される。敵将でありながら曹操はその節義を惜しみ、「忠烈沮君の墓」を建てて葬ったと伝えられる。正しき策を持ちながら愚主に仕え、献ずるたびに退けられ、それでも節を曲げなかった――敵に墓を建てさせた忠義こそ、沮授という参謀の生涯を最もよく語っている。"}, {"id": 70, "name": "張任", "faction": 3, "role": "武将", "rarity": 3, "weapon": "bow", "kind": "proj", "weaponName": "弓", "d": [4, 4, 1, 4, 6, 3, 5], "p": [1, 1, 1, 1, 3, 2], "scores": {"W": 3.25, "B": 5.0, "S": 4.0, "A": 4.25, "G": 1.38, "K": 2.55}, "stat": {"dmg": 1.16, "area": 1.17, "cd": 0.96, "amount": 2, "knock": 0.86, "crit": 0.08, "duration": 0, "pwr": 4.45}, "title": "弓の将", "skill": "弓", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [60, 61, 62, 63, 64], "chapN": 5, "bio": "劉璋配下の将。劉備を警戒するよう進言", "profile": "劉璋に仕えた益州の将。蜀郡の生まれで、呉懿に「極めて胆略あり、軽く敵すべからず」と評され、入蜀してきた劉備を早くから警戒し、主君に油断せぬよう進言した、忠勇の士である。\n\nその名を天下に轟かせたのは、龐統を討った一戦だ。第六十三回、劉備軍が雒城へ迫ると、張任は城の東南の小路に三千の兵を伏せ、白馬に乗った大将こそ劉備と狙いを定める。だが馬を換えて進んだのは軍師龐統であった。強弓硬弩がいっせいに放たれ、漢軍は狭い道に押し合いひしめき、進むも退くもならず、死者は大半に及んだ。落鳳坡に龐統が斃れたこの伏射は、張任の真骨頂たる「待ち伏せ」の戦術がもたらした戦果である。続く第六十四回でも、彼は詐敗の計を自ら立て、張飛を雒城北へ誘い込んで中央を断ち切り、垓心に囲んでみせた。城内では吳蘭・雷同を北門から東門へ、自らは南門から西門へと門ごとに兵を配し、民にまで鼓を擂らせて指揮を執る、雒城防衛の事実上の総司令であった。\n\n通説では「龐統を射殺した蜀の名将」として語られるが、演義の本文を読むと、彼が刃で名のある敵将を斬る場面は一つもない。張飛と十数合渡り合って身を翻す地力はあるものの、強みはあくまで伏兵と強弓を操る戦術指揮にあった。武勇の人というより、地の利を読み、兵を伏せて勝つ将である。\n\n最期は孔明の計に落ち、捕らえられて尚、節を曲げなかった。「忠臣あに肯えて二主に事えんや」と目を見開いて叫び、降伏を拒む。孔明はその名を全うさせようとあえて斬らせ、後世は詩に「張君忠勇死して猶お生く」と讃えた。武勲より、主家への揺るがぬ忠節によって名を残した将である。"}, {"id": 71, "name": "曹休", "faction": 1, "role": "武将", "rarity": 3, "weapon": "bow", "kind": "proj", "weaponName": "弓", "d": [5, 6, 5, 2, 2, 3, 3], "p": [1, 2, 1, 1, 4, 2], "scores": {"W": 4.9, "B": 2.7, "S": 2.7, "A": 2.55, "G": 1.71, "K": 2.65}, "stat": {"dmg": 1.16, "area": 1.0, "cd": 1.0, "amount": 2, "knock": 1.06, "crit": 0.06, "duration": 0, "pwr": 4.45}, "title": "弓の将", "skill": "弓", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [56, 68, 69, 71, 80, 84, 85, 86, 91, 96], "chapN": 11, "bio": "曹操の族子。銅雀台で射芸、千里駒と称される", "profile": "曹操の族子にして、魏の宗族の若き猛将。曹操自らがその才を惜しみ「これ吾が家の千里の駒なり」と賞した、期待を一身に背負った男である。騎射に長け、宗族の身でありながら実戦の場に立ち続けた。\n\nその武勇は若き日に鮮やかに描かれる。第五十六回の銅雀台の射芸では、馬を飛ばして往来し三たび駆け抜けながら、矢をつがえ弓を引き絞り、放った一矢が見事に的の紅心を射貫いた。第六十八回では張遼の戦いに加わり、凌統の馬を冷箭で射倒す。第六十九回、許昌で耿紀・韋晃が叛乱を起こすと、千余の兵を率いて夜明けまで混戦を制し、これを鎮めた。第八十回の魏の受禅の場では、曹洪とともに帯剣して殿に進み、政権交代の実力行使に立ち会っている。\n\nだが将帥としての到達点は、第九十六回の石亭の大敗に集約されてしまう。揚州の都督として呉に攻め入った曹休は、周魴の偽りの降伏と、髪を断って誠を装う苦肉の計を見抜けず、深く敵地へ踏み込んだ。建威将軍の賈逵が「これは誘いの計です」と諫めると、曹休はかえって「我が功を奪う気か」と怒り、斬ろうとさえした。果たして陸遜・朱桓・全琮の逆夜襲を受け、自陣は大混乱に陥って同士討ちを始め、武器も輜重もことごとく失う。敵将朱桓には「曹休は親しき縁で任じられたのみ、智勇の将にあらず」と侮られた。武勇は本物だが、大局を読む眼と人を御す度量に欠けた将であった。\n\n帰国した曹休は、おのれの大敗を恥じ、気鬱のあまり背に疽を発して洛陽で世を去る。曹丕の臨終には「卿らは皆な国家の柱石の臣」と託された身でありながら、最も大きな戦で躓いた。輝かしい騎射の腕と、惜しまれた早世の落差にこそ、この宗族の駒の物語がある。"}, {"id": 72, "name": "陶謙", "faction": 3, "role": "君主", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 0, 0, 2, 2, 5], "p": [2, 5, 5, 5, 6, 7], "scores": {"W": 0.65, "B": 2.55, "S": 2.2, "A": 1.95, "G": 4.71, "K": 5.15}, "stat": {"dmg": 0.87, "area": 0.94, "cd": 1.13, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 2.1}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [5, 10, 11, 12, 13, 15, 120], "chapN": 7, "bio": "徐州刺史(太守)、曹操の父殺害の濡れ衣を着る", "profile": "徐州を治めた刺史にして太守。十八路諸侯の第十二鎮として董卓討伐に名を連ねた群雄の一人である。だがこの人の本質は戦場にはない。登場の冒頭から「人と為り温厚純篤」と評され、以後も陳宮に「仁人君子、利を好み義を忘るるの輩にあらず」、劉備に「陶恭祖は乃ち仁人君子なり」と、繰り返しその徳を讃えられる、まれな仁君であった。\n\n陶謙の徐州は富んでいた。糜竺の口で「徐州は殷富にして、戸口百万」と語られるほど栄え、人民は久しく彼の治世に恩を感じていた。だが運命は彼に過酷だった。曹操の父曹嵩が徐州を通る際、護送を任せた部下の張闓が私欲から曹嵩を殺害してしまう。これは陶謙のあずかり知らぬ独断であり、本文も陳宮や劉備の口を借りてその無実を明示するが、曹操は父の仇として大軍を率い徐州へ攻め寄せた。\n\n危機に際し、陶謙は配下に支えられて立つ。糜竺が「北海の孔融と青州の田楷へ救援を求めれば、曹操は必ず兵を退きましょう」と策を進言すると、これを容れ、書を二通したため、糜竺と陳登を使者に立てて両路の援軍を呼び寄せた。この救援要請が、ついに劉備をも徐州へ引き入れることになる。武の人ではなく、人を動かし、人に支えられる政治の君主であった。唯一の出陣の場面では、夏侯惇に名指しされるや早々と陣中へ逃げ込み、代わりに曹豹が槍を取って迎え撃っている。\n\n最期に至って、陶謙の徳は際立つ。病篤くなった彼は、二人の息子に州を継がせず、「我が長子・次子は皆その任に堪えず」と見極め、漢室の宗親たる劉備へ三たび徐州を譲った。「天下擾乱し、王綱振わず、公は乃ち漢室の宗親、まさに力めて社稷を扶くべし」と説き、孫乾を補佐に推挙し、遺表まで朝廷に申し送って世を去る。「陶恭祖三たび徐州を譲る」が回の題となるほど、私心なき後事の処理は演義屈指のものとして語り継がれている。"}, {"id": 73, "name": "張角", "faction": 3, "role": "その他", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 2, 0, 3, 3, 5, 6], "p": [6, 5, 6, 3, 6, 1], "scores": {"W": 1.6, "B": 3.95, "S": 4.5, "A": 4.15, "G": 4.75, "K": 5.05}, "stat": {"dmg": 1.13, "area": 1.09, "cd": 1.06, "amount": 1, "knock": 0.74, "crit": 0.07, "duration": 3.75, "pwr": 4.2}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [1, 2, 28, 29], "chapN": 4, "bio": "黄巾の首領、本バッチでは余党の回想として言及される故人", "profile": "演義の幕を開けた男。後漢末の天下大乱、その火種を放ったのが太平道の教祖、黄巾の首領たる張角である。みずから「天公将軍」と称し、漢の王朝そのものを揺るがした、政治と動員の人物であった。\n\nその力の源は武ではなく、民の心であった。張角は符水を施して病を癒やし、人々の病を治して「大賢良師」と自ら称する。疫病に苦しむ民にとって、それは確かな救いであり、こうして築いた支持の上に、彼は壮大な組織を立ち上げた。三十六方を編成し、大方は一万余、小方は六、七千、それぞれに渠帥を置いて将軍と称させる。「蒼天已に死す、黄天まさに立つべし」「歳は甲子に在り、天下大吉」という讖言を流し、黄巾を裹んで従う者は四方の百姓、実に四五十万に及んだ。「至って得難きものは民心なり。今や民心已に順う。勢いに乗じて天下を取らずんば、誠に惜しむべし」と二弟に語る、その大局の構想は演義冒頭の天下大乱の起点そのものであった。\n\n通説では「妖術使いの反乱者」と片づけられるが、本文に張角の一騎打ちは一つもない。彼は董卓の軍を破り、勢いに乗じて追ったところを、劉備・関羽・張飛の三人に衝かれて軍が乱れ、五十余里を敗走する。宦官の封諝へ金帛を贈って内応を取り付ける朝廷工作も試みたが、唐州の密告で露見した。刃を振るう英雄ではなく、信仰で人を束ね、数の力で漢室を傾けた組織者だったのである。\n\nその最期は戦死ですらない。皇甫嵩が攻め寄せた時、張角はすでに病で世を去っていた。後を継いだ弟の張梁・張寶は相次いで敗れて斬られ、黄巾は瓦解する。張角自身の棺は暴かれ、戮屍にされて梟首された。掲げた天命は本文に「訛言」と断じられ、四五十万を動かしながらも、ただの一日も天下を保つことはなかった。それでも、彼の蜂起なくして三国の物語は始まらない。"}, {"id": 74, "name": "王平", "faction": 0, "role": "武将", "rarity": 3, "weapon": "crossbow", "kind": "proj", "weaponName": "弩", "d": [4, 1, 1, 1, 6, 3, 6], "p": [1, 1, 1, 1, 3, 2], "scores": {"W": 2.35, "B": 5.1, "S": 3.95, "A": 4.0, "G": 1.38, "K": 2.75}, "stat": {"dmg": 1.11, "area": 1.19, "cd": 0.95, "amount": 5, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 4.0}, "title": "弩の将", "skill": "弩", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [71, 72, 87, 88, 89, 93, 95, 96, 97, 99], "chapN": 20, "bio": "巴西出身、徐晃の副先鋒だが趙雲・黄忠に降り蜀の偏将軍となる", "profile": "巴西の生まれ。もとは曹操配下、徐晃の副先鋒であったが、漢中の戦いで趙雲・黄忠に降り、蜀の偏将軍となった。武器を執れば確かな戦果を上げる一方、その真価はむしろ分別ある判断力と、身を惜しまぬ忠節にある中堅指揮官である。\n\n白兵の腕も侮れない。第九十二回では夏侯楙を一合で馬上から生け捕り、第百二回では岑威を一刀のもとに斬っている。だが王平が最も光るのは、戦場を読む眼だ。漢水の戦いで徐晃が背水の陣を布こうとすると、「昔、韓信がこの計を用いたのは、敵将を無謀と見切ったからです。今、将軍は趙雲・黄忠の腹を読めますか」と韓信の故事を引いて諫めた。そして街亭――馬謖が山上に布陣しようとした時、王平は「水を汲む道を断たれれば自壊します。要路を捨て山に屯すれば、魏兵が殺到して四面を囲むでしょう。何の策で守るのですか」と正確に危地を予見し、当道に城を築くよう進言する。容れられず、敗れた後、孔明は「汝、早く王平の言を聴かば、あに此の禍あらんや」とその的中を認めた。\n\n通説では「街亭で馬謖を諫めた無当飛軍の名将」として高名だが、本文の王平は一貫して副将・先鋒・牙門将の地位にある。個人武勇への大層な称号も、怪力の逸話もない。彼を支えるのは「謹慎」、すなわち軽はずみを慎む慎重さと、危地に進んで身を投じる忠誠であった。第九十九回、危険な役目に「某、願わくはこれに当たらん」と進み出た時、孔明は「王平、肯えて身を舍てて親しく矢石を冒す、真の忠臣なり」と嘆じている。\n\n孔明はその死に臨んで遺命を残し、馬岱・廖化・張翼らとともに王平を「忠諒死節の士、久しく戦陣を経、委用するに堪うべし」と名指しで信任した。街亭では孤軍を率いて十数度突撃し、魏延・高翔を救い出した。孔明亡き後は永安に屯し、呉の侵界に備えて蜀の辺境を守る。派手な無双ではなく、任せた一軍を堅く守り抜く、信頼に足る将であった。"}, {"id": 75, "name": "許攸", "faction": 3, "role": "軍師参謀", "rarity": 3, "weapon": "fire", "kind": "zone", "weaponName": "火計", "d": [0, 0, 0, 0, 7, 5, 2], "p": [1, 1, 1, 1, 1, 3], "scores": {"W": 0.0, "B": 4.4, "S": 4.95, "A": 5.05, "G": 1.24, "K": 1.5}, "stat": {"dmg": 1.22, "area": 1.21, "cd": 1.14, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.75, "pwr": 4.9}, "title": "軍師", "skill": "火計", "skillDesc": "地を焼く炎を放つ", "voice": "", "hist": "", "chapters": [7, 22, 30, 32, 33, 45, 108], "chapN": 7, "bio": "官渡で曹操に烏巣の糧を断つ策を授けた謀士として回想される", "profile": "官渡の勝敗を一手で決めた謀士。もとは袁紹に仕えていたが、容れられぬまま曹操の陣へ身を投じ、その一策が天下分け目の戦の帰趨を変えた。布衣の謀臣の、栄光と転落をともに体現する人物である。\n\n第三十回、糧尽きかけて窮した曹操のもとへ、許攸は夜陰に紛れて投じる。曹操は履も履かず跣で迎え、「子遠肯えて来たる、吾が事済れり」と歓喜した。許攸が授けた策こそ、烏巣劫糧であった。「袁紹の軍糧輜重はことごとく烏巣に積まれ、守る淳于瓊は酒を嗜んで備えなし。精兵を選び、袁将蔣奇の援軍と詐称してかの地へ赴き、隙に乗じて糧草を焼けば、紹の軍は三日ならずして自ら乱れましょう」と、詐称・奇襲・火攻を具体に組み立てた一手である。曹操は即座に容れ、袁紹百万の衆を「戦わずして自ら破る」に至らしめた。続く第三十二回では「漳河の水を決して之に渰がん」と、冀州攻略の水攻めまで献じている。袁紹にあった頃には「軽騎で許都を急襲し首尾相攻めよ」と進言しており、曹操をして「もし袁紹、子の言を用いば、吾が事敗れん」と言わしめた、危うい戦略眼の持ち主でもあった。\n\nだが許攸には、もう一つの顔があった。冀州にあった頃、民間の財をみだりに受け、子姪に税を私していたという貪欲。そして勝利の後の尊大である。第三十三回、冀州が落ちると、許攸は城門の前で「阿瞞、汝、我を得ずんば(この城を得られなかったろう)」と曹操の幼名を呼んで功を誇った。これを聞いた許褚が怒り、剣を抜いて一刀のもとに斬り捨て、その首を提げて曹操のもとへ参じる。敵に恐れられるどころか、味方に軽んじられて命を落とした。\n\n功は戦術の一点突破に集中し、武も統率も政も本文にはほとんど記されない。主を二度替えた布衣の謀士は、みずから「某、主を択ぶ能わず」と語る通り、節義の人ではなかった。一策で歴史を動かしながら、傲りによって自滅した――その鮮烈な明暗こそが、許攸という男の物語である。"}, {"id": 76, "name": "于禁", "faction": 1, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 3, 3, 2, 5, 3, 7], "p": [1, 1, 2, 1, 1, 2], "scores": {"W": 2.9, "B": 4.85, "S": 3.85, "A": 3.8, "G": 1.3, "K": 2.35}, "stat": {"dmg": 0.97, "area": 0.99, "cd": 0.99, "amount": 2, "knock": 0.91, "crit": 0.06, "duration": 0, "pwr": 2.9}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [10, 11, 16, 23, 26, 31, 39, 41, 46, 74], "chapN": 29, "bio": "曹操配下の武将、劉琮母子を殺害、後に水軍都督に", "profile": "曹操に仕えた宿将。泰山鉅平の生まれで、数百の兵を率いて曹操軍に投じた時、その「弓馬熟嫺、武芸衆に出づ」を見込まれ、典軍司馬に任じられた。厳格な軍規をもって鳴る将であったが、その生涯は栄光の絶頂から不忠の汚名へと転落していく、数奇なものであった。\n\n于禁の最大の見せ場は、第十六回の宛城である。曹操が張繡に夜襲されて総崩れとなる中、于禁は青州兵が略奪を働くのを見て軍法に照らしてこれを誅した。「民望を大いに失う、某ゆえにこれを殺す」と、讒言を浴びても弁明より布陣を優先し、堅塁を整えて敗勢を盛り返す。曹操はこれを「将軍、匆忙の中に在りて、能く兵を整え塁を堅くし、謗りに任じ労に任じて、敗を反して勝と為す。古の名将と雖も、何ぞ茲に加えん」と最大級に賞し、益寿亭侯に封じた。進言にも冴えがあり、濮陽西の寨を夜襲する「上策」を献じて容れられ、博望では李典の火攻警戒に同意して都督へ伝えている。\n\nところが、その厳格さと用兵は晩節を汚す。第七十四回の水淹七軍――龐徳の功を妬んだ于禁は、鳴金して軍を収め、大路を断って龐徳の働きを妨げた。督将の成何が地勢の低さと増水の危険を警告すると、「匹夫、吾が軍心を惑わすか」と一喝して握り潰す。果たして大水が押し寄せ七軍は壊滅、于禁は逃げ場を失い、わずか五六十人を残して「料るに逃るる能わず」と、口々に降を願って関羽に降ってしまった。三十年仕えた曹操は「于禁、孤に従いて三十年、何ぞ期せん、危に臨んで反って龐徳に如かざらんとは」と嘆いている。なお禰衡には早くから「于禁は版を負い牆を築くに使うべし」と土工人足のごとく嘲られており、一騎打ちでも張飛・馬超に数合で敗走するなど、個人武勇は決して高くなかった。\n\n呉から放還されて魏へ戻った于禁を待っていたのは、さらなる屈辱だった。曹丕は曹操の陵の事を董治させる一方、壁に降伏の様を描かせて辱め、于禁は羞じ悩んで病を発し世を去る。死を悼む詩は「三十年来旧交を説く、憐れむべし難に臨んで曹に忠ならず」と、その晩節をきびしく総括した。規律と統率に古の名将の風を見せながら、最後の一戦で私心と臆病に屈した――その落差が、于禁という将の哀しみである。"}, {"id": 77, "name": "程普", "faction": 2, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [6, 4, 4, 3, 4, 3, 6], "p": [2, 2, 2, 1, 2, 3], "scores": {"W": 4.8, "B": 4.5, "S": 3.55, "A": 3.5, "G": 1.97, "K": 2.95}, "stat": {"dmg": 1.21, "area": 1.06, "cd": 0.9, "amount": 2, "knock": 1.03, "crit": 0.07, "duration": 0, "pwr": 4.8}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [5, 6, 7, 15, 29, 44, 49, 51, 52, 53], "chapN": 21, "bio": "呉の老将筆頭、副都督。当初周瑜に不服も後に心服", "profile": "呉の老将筆頭。鉄脊蛇矛を操り、孫堅・孫策・孫権と孫家三代に仕え抜いた、江東の柱石である。武勇も確かだが、この宿将の真骨頂はむしろ、私情を捨てて軍を一つにまとめる度量にあった。\n\n白兵の戦果は本物だ。第五回、汜水関に拠る董卓軍と戦った折、華雄の副将胡軫が五千を率いて出てくると、程普は馬を飛ばし矛を挺げて直ちに斬りかかり、数合と戦わぬうちに胡軫の咽喉を刺し貫いて馬下に斃した。第七回でも呂公を一矛で刺し落としている。第十五回には太史慈と三十合渡り合い、その武を示した。孫家草創以来、大小数百戦をくぐり抜けてきた歴戦の士である。\n\nだが程普を語るうえで欠かせないのは、赤壁前の周瑜とのくだりだ。年長の程普は、若い周瑜が自分の上の爵位に就いたことを内心快く思っていなかった。ところが息子の程咨が陣営から戻り、周瑜の用兵が「動止法あり」と語るのを聞くや、程普は大いに驚いて言った。「吾、素より周郎を懦弱と欺り、将たるに足らずと思えり。今かくの如く能くす、真の将才なり。我いかんぞ服せざらん」――そして自ら行営へ赴いて謝罪し、軍を一つにまとめあげた。私情より大局を取るこの一場面こそ、演義が丁寧に描いた程普の度量である。曹操に降ろうという議が出た時には、「吾ら自ら孫将軍に随いて基を開き業を創り、大小数百戦して、わずかに六郡の城池を得たり。今この恥を受けんや。吾ら寧ろ死すとも辱められじ」と、主戦の気概を吐いている。\n\nそして程普は、幾度も主君の窮地を救った。第二十九回には瀕死の孫策を救い出し、第五十三回の合肥では、張遼に追われた孫権の前に割って入り、一陣を斬り散らして主君を救出した。赤壁では周瑜と詐死の計を練り、火船隊の中核を担っている。通説に言う「江東十二虎臣の筆頭」――それは個人の無双ゆえではなく、三代の主家を身を挺して支え続けた、その忠勇によるものであった。"}, {"id": 78, "name": "賈逵", "faction": 1, "role": "武将", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 7, 4, 4], "p": [1, 1, 1, 1, 6, 6], "scores": {"W": 1.1, "B": 4.95, "S": 4.65, "A": 4.85, "G": 2.25, "K": 3.85}, "stat": {"dmg": 1.21, "area": 1.16, "cd": 1.08, "amount": 2, "knock": 0.77, "crit": 0.06, "duration": 3.5, "pwr": 4.85}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [79, 96, 111, 116], "chapN": 4, "bio": "諫議大夫、曹彰を諭して曹丕に服させる", "profile": "魏の諫議大夫にして建威将軍。役職こそ武将に数えられるが、演義の賈逵は終始、智謀と節義をもって立つ文官型の人物である。一騎打ちも斬首の戦果もなく、刃を振るう場面は一つもない。彼が抜くのは剣ではなく、道理と先見であった。\n\n賈逵を象徴する場面は二つある。一つは第七十九回。曹操が世を去った直後、鄢陵侯の曹彰が兵を率いて入城し、先王の璽綬を求めてきた。継承の危機である。賈逵は臆せず曹彰に問うた。「君侯、此に来たるは喪に奔るを欲してか、位を争うを欲してか」と二択で意図を直撃し、さらに「異心なくんば、何故に兵を帯びて城に入る」と詰めて左右の将士を退けさせる。そして「家に長子あり、国に儲君あり。先王の璽綬は君侯の宜しく問うべき所にあらず」と、嫡長子相続の大義名分を正面から突きつけ、曹彰を黙然と語なからしめた。流血一つなく、曹丕の継承をめぐる最大の危機を収めたのである。\n\nもう一つは第九十六回、石亭の戦いだ。呉の周魴が降を願い出ると、賈逵はこれを「これ特に兵を誘うの詭計なり」と看破した。周魴が髪を断って誠を誓ったことについても、「昔、要離は臂を断ちて慶忌を刺殺せり。未だ深く信ずべからず」と要離の故事を引いて偽りを論証し、軽進せず夾攻すべしと曹休に諫言する。だが容れられず、それどころか曹休に功を奪う気かと疑われ、危うく斬られかけた。果たして曹休が大敗して敗走すると、賈逵は殿軍を引き受け、林木の盛んな所や険しい小径に旌旗を多く立てて疑兵となす。追ってきた呉将徐盛は、山坡の下に閃く旗角を見て伏兵を疑い、ついに追撃をためらって兵を収めた。看破し、代替策を出し、敗軍を救う――この一戦の唯一の正解者であった。\n\n通説では正史に名宰相格の能吏として知られるが、演義における賈逵の最大の見せ場は、この石亭の先見と殿軍にある。後に司馬氏の権を握る賈充の父としても言及されるこの人物は、武人というより、危機に冷静な道理を突きつける参謀にして諫臣であった。"}, {"id": 79, "name": "郭淮", "faction": 1, "role": "武将", "rarity": 3, "weapon": "bow", "kind": "proj", "weaponName": "弓", "d": [3, 2, 1, 1, 6, 4, 5], "p": [1, 3, 2, 3, 2, 3], "scores": {"W": 2.1, "B": 4.9, "S": 4.45, "A": 4.45, "G": 2.25, "K": 2.8}, "stat": {"dmg": 1.05, "area": 1.16, "cd": 1.0, "amount": 2, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 3.55}, "title": "弓の将", "skill": "弓", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [70, 93, 94, 95, 97, 98, 99, 101, 102, 107], "chapN": 13, "bio": "行軍司馬。張郃を弁護し計を授ける", "profile": "魏の対蜀防衛を担った西方の将。太原陽曲の生まれで、射亭侯に封じられ雍州刺史を領した。曹真の副都督として登場し、諸葛亮、そして姜維を相手に、長きにわたって西方の戦線に立ち続けた、息の長い方面の要員である。\n\n郭淮の持ち味は、個人の武勇よりも計議と防衛、とりわけ地勢を読んで敵の補給を断つ手腕にあった。第百七回の麴山の戦いでは、二城に拠った蜀兵に対し「この城は山勢高く、必ず水少なし。城を出でて水を取らん。その上流を断たば、蜀兵は皆な渇え死なん」と看破し、上流を堰き止める水攻めで蜀兵を渇死寸前へ追い込む。第九十八回には孫禮を用いて偽の糧で敵を誘き出す計を、第百二回には糧道を遮断して木牛流馬を奪う策を立てた。第九十四回には「西羌の人は太祖の時より連年入貢す」として、羌に和親を許して同盟させ、蜀の背後を衝かせる方面の構想も描いている。後にはその羌王迷當を擒え、厚言で撫慰して降伏させ、前部に起用する懐柔の手も見せた。\n\nもっとも、対孔明戦では振るわなかった。計はしばしば孔明に見破られ、第九十九回には「郭淮遁走」と敗走を記される。第九十五回、馬謖を破った司馬懿の機略を目の当たりにすると、「仲達の神機、吾及ばざるなり」と驚嘆し、趙雲を「英勇無敵」と警戒する側に回っている。個人の一騎打ちも分が悪く、第百七回では夏侯霸と渡り合うも十合せずして敗走した。地味だが粘り強く、勝ちきれぬまま戦線を支え続けた将であった。\n\nその最期は、皮肉にも自らの矢によって訪れる。第百九回、姜維を槍で追い詰めた郭淮は、姜維に矢がないと見て弓を執り射かけた。だが姜維はその矢を素手で受け止め、つがえて射返す。郭淮はこれをまともに受けて落命した。華々しい無双ではなく、西方の防衛に半生を費やし、最後は宿敵姜維との攻防の中で斃れた――それが、対蜀の柱石と呼ばれた将の結末である。"}, {"id": 80, "name": "郝昭", "faction": 1, "role": "武将", "rarity": 3, "weapon": "crossbow", "kind": "proj", "weaponName": "弩", "d": [2, 4, 4, 3, 6, 3, 5], "p": [1, 1, 2, 1, 2, 3], "scores": {"W": 3.0, "B": 4.75, "S": 3.95, "A": 4.15, "G": 1.55, "K": 2.4}, "stat": {"dmg": 1.04, "area": 1.14, "cd": 1.04, "amount": 5, "knock": 1.03, "crit": 0.07, "duration": 0, "pwr": 3.45}, "title": "弩の将", "skill": "弩", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [96, 97, 98], "chapN": 3, "bio": "鎮西将軍、陳倉城を堅守し孔明を阻む・病死", "profile": "魏の鎮西将軍にして、陳倉城を預かる守将。司馬懿が「身の丈九尺、猿臂にして善く射、深く謀略あり」とその器量を見込んで推挙した、攻め寄せる敵を一歩も通さぬ守りの名手である。北伐を続ける諸葛孔明の前に立ちはだかる、要害の関守としてその名を残した。\n\n最も知られるのが第九十六回から続く陳倉の攻防だ。孔明が雲梯を組んで四面から城に迫ると、郝昭は三千の兵に火箭を持たせて待ち構え、梯子が城壁に届く間際に一斉に射て焼き払う。衝車が押し寄せれば、石を運ばせ葛の縄に結んで打ちつけ、ことごとく叩き折る。蜀軍が地下に道を掘って攻め入ろうとすれば、城内に深い壕を横に掘って断ち切った。こうして昼夜の猛攻を二十余日も凌ぎきり、孔明をして「破るに計なし」と嘆かせたのである。第九十七回では、旧友の鄞祥を説客に立てて降伏を促されると、弓に矢を番えて「われ魏に仕え、汝は蜀に仕える。各々その主に仕えるのみ」と一喝し、頑として退けた。\n\nその人となりは、ひとえに守りと忠義に貫かれている。「魏の法度は兄の知るところ。われ国恩を受け、ただ死あるのみ」と言い切る潔さがあり、孔明に「大漢に順わず」と非難されても微塵も揺るがない。城を守る器械の采配にかけては鬼神のごとくだが、自ら馬を駆けて敵将と斬り結ぶような場面は描かれず、あくまで一城を死守する専守の将であった。\n\n最期は、惜しむべきものだった。守り抜いた陳倉だが、郝昭が病に伏した隙を孔明に突かれ、城は奇襲によって奪われる。主将を欠いた兵は乱れ、彼自身は驚きのうちに世を去ったと伝わる。司馬懿の対蜀防衛において、陳倉が蜀軍の糧道を塞ぐ要石として機能した功は大きく、たった三千で数十万を阻んだ守城の妙は、後世まで語り草となっている。"}, {"id": 81, "name": "兀突骨", "faction": 3, "role": "君主", "rarity": 3, "weapon": "mace", "kind": "nova", "weaponName": "剛", "d": [3, 4, 8, 6, 2, 1, 3], "p": [1, 1, 1, 2, 2, 1], "scores": {"W": 4.75, "B": 2.4, "S": 1.7, "A": 1.95, "G": 1.28, "K": 1.7}, "stat": {"dmg": 1.23, "area": 1.28, "cd": 1.08, "amount": 1, "knock": 1.46, "crit": 0.11, "duration": 0, "pwr": 4.95}, "title": "君主", "skill": "剛", "skillDesc": "周囲を吹き飛ばす衝撃", "voice": "", "hist": "", "chapters": [90], "chapN": 1, "bio": "烏戈国の国主。藤甲軍を率いるが盤蛇谷で焼き殺される", "profile": "南方の異域、烏戈国の国主。藤甲軍と呼ばれる無敵の兵団を率い、南蛮征伐に苦しむ孟獲が最後の頼みとして引き入れた、異形の蛮王である。\n\nその登場は第九十回ただ一度きりだが、強烈な印象を残す。身の丈は二丈、五穀を食らわず生きた蛇や猛獣を喰らい、体には鱗の甲を生やして刀剣も通さぬという。日月狼鬚の帽を戴き、金珠瓔絡を身にまとい、両脇から生鱗をのぞかせて巨象に跨り軍の先頭を進む姿は、まさに人の形を超えていた。率いる三万の藤甲軍は、桐油に浸して干した藤の鎧をまとい、刀も矢も弾き返し、川に落ちても沈まず流れに乗って渡る。蜀兵はその姿を遠くに望んで「人の形に似ず、はなはだ醜悪」と恐れおののき、呂凱は「たとえ勝っても益はない、早く兵を退きましょう」と進言し、孔明すら「われ社稷に功ありとも、必ず寿を損なわん」と嘆いたほどであった。\n\n孟獲の哀願に「われ洞の兵を起こし、汝のために讐を報いん」と応えて出陣した兀突骨は、緒戦で連勝を重ねる。だがそれはことごとく魏延の偽りの敗走に乗せられたものに過ぎなかった。\n\n最期は盤蛇谷で迎える。草木一本ない谷を見て「伏兵はあるまい」と安心して追撃に入った兀突骨は、孔明が仕込んだ火薬と地雷、乾いた柴の罠に三万もろとも突入する。藤甲は火に弱く、谷は火の海と化し、兵らは互いに抱き合ったまま焼け死んだ。烏戈国は種を残さず絶え、彼は「強敵」として現れ、ただ一度の戦で消えていった。装備と異形の威容にかけては演義屈指でありながら、計を見抜けず散った蛮王の最期である。"}, {"id": 82, "name": "傅僉", "faction": 0, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [6, 4, 3, 3, 5, 3, 5], "p": [1, 1, 2, 1, 4, 2], "scores": {"W": 4.55, "B": 4.7, "S": 3.7, "A": 3.8, "G": 1.69, "K": 2.85}, "stat": {"dmg": 1.17, "area": 1.02, "cd": 0.9, "amount": 1, "knock": 0.96, "crit": 0.07, "duration": 0, "pwr": 4.5}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [112, 113, 114, 115, 116], "chapN": 5, "bio": "蜀の勇将。陽平関で蔣舒に裏切られ死戦の末に自刎", "profile": "蜀漢末期、姜維がその胆勇を愛して漢中の防衛に用いた川出身の勇将。蔣舒とともに日々兵馬を操練し、滅びゆく国の最前線を支えた、智と武を兼ね備えた将である。\n\n第百十二回、姜維に従って魏軍と戦った傅僉は、敵将王真と渡り合うと、十合のうちにわざと隙を見せて誘い、突いてきた槍をかわしざま王真を馬上から生け捕った。さらに救援に駆けつけた李鵬には、隠し持った四稜の鉄簡を顔面に一撃。眼の珠が飛び出して落命したという、凄まじい一撃であった。この回では「まず長城の糧草を焼き、しかる後に秦川を取らば、中原は指日のうちに得られん」と進言し、その読みが姜維の構想と暗合する場面もある。第百十四回では、王瓘の偽りの降伏を見抜いた姜維の計に従い、伏兵を率いて鄧艾を壇山谷に誘い出す実行役を担い、「鄧艾匹夫、すでにわが主将の計に中れり」と大喝して迫った。\n\nその人物像は、ただ忠を叫ぶだけの将ではない。生け捕りと鉄簡の一撃に見るように戦の機微を心得た巧者であり、献策の見識も持つ。一方で、自らの判断には筋が通っており、危機にあって退くより打って出ることを選ぶ気概の人であった。\n\n最期は、第百十六回の陽平関に訪れる。鍾会の大軍が迫ると、傅僉は「魏兵は遠来ゆえ疲れている、ここで戦わねば漢・楽二城が危うい」と打って出るが、関を任せた副将の蔣舒が「われすでに魏に降れり」と裏切り、孤軍の死戦を強いられる。左に突き右に衝き、なお戦い続けた末、傅僉は天を仰いで「われ生きては蜀の臣、死しても蜀の鬼とならん」と叫び、自ら命を絶った。裏切り者の蔣舒と鮮やかに対をなす、蜀漢最後の忠節として、その死は今も胸を打つ。"}, {"id": 83, "name": "皇甫嵩", "faction": 3, "role": "武将", "rarity": 3, "weapon": "fire", "kind": "zone", "weaponName": "火計", "d": [2, 2, 1, 1, 6, 4, 5], "p": [2, 5, 4, 1, 5, 5], "scores": {"W": 1.65, "B": 4.8, "S": 4.45, "A": 4.45, "G": 3.56, "K": 4.55}, "stat": {"dmg": 1.17, "area": 1.14, "cd": 1.04, "amount": 2, "knock": 0.72, "crit": 0.05, "duration": 3.5, "pwr": 4.5}, "title": "火計の将", "skill": "火計", "skillDesc": "地を焼く炎を放つ", "voice": "", "hist": "", "chapters": [1, 2, 9], "chapN": 3, "bio": "中郎将、黄巾を破った将軍", "profile": "後漢朝廷の中郎将にして、黄巾の乱を鎮めた名将。物語の幕開けを飾る討伐軍の総司令官の一人であり、戦場では火攻で賊を焼き、朝廷にあっては節操を曲げぬ剛直の臣として描かれる、軍と政の両面を持つ将軍である。\n\nその武名を決定づけたのが、第一回の長社の戦いだ。黄巾賊が草に依って陣を結んでいるのを見抜いた皇甫嵩は、朱雋と謀って「火攻を用いるべし」と兵に草の束を持たせ、ひそかに伏せさせた。その夜、折よく大風が起こると、二更を過ぎて一斉に火を放つ。火炎は天を焦がし、賊は驚き慌てふためき、官軍は左右から攻め立てて大勝を収めた。続く第二回では、董卓がたびたび敗れた戦線を引き継ぎ、張角の弟・張梁を曲陽に「連勝七陣」して斬り、すでに死んでいた張角の棺を暴いて梟首し、残党をことごとく降伏させて黄巾の本隊を平定する。\n\nその人となりは、武功よりむしろ朝臣としての筋の通し方に光る。讒言で罪に落とされた盧植のために「功あって罪なし」と自ら上奏してその官位を回復させた。董卓誅滅の後には、王允の命を受けて郿塢を接収し、董卓一族を老幼問わず処断する一方、塢中に囲われていた良家の子女はことごとく解放した。略奪と民の保護を分ける、その分別が彼の品位を示している。\n\n通説の正史では名臣としてさらに高く評されるが、演義においても、十常侍が黄巾鎮圧の将に賄賂を要求した際、皇甫嵩は朱雋とともに断固これを拒み、その結果として官を罷免された。宦官の専横に屈せぬその姿は、乱世の入り口にあって、まだ漢に節義の臣が残っていたことを静かに物語っている。"}, {"id": 84, "name": "蒯良", "faction": 3, "role": "軍師参謀", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 6, 5, 3], "p": [2, 3, 1, 4, 1, 4], "scores": {"W": 1.0, "B": 4.35, "S": 4.85, "A": 4.85, "G": 2.43, "K": 2.4}, "stat": {"dmg": 1.2, "area": 1.18, "cd": 1.1, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.75, "pwr": 4.75}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [6, 7, 8, 18, 23, 34], "chapN": 6, "bio": "蒯越の兄、相馬の名手（言及）", "profile": "荊州の劉表に仕えた軍師参謀。弟の蒯越と並んで「蒯氏の兄弟」と称された荊州の智嚢の一翼であり、戦場での剣ではなく、謀をもって敵の主将を屠る型の知恵者である。\n\nその本領が発揮されるのが、第七回の孫堅との戦いだ。新たに敗れた直後には「深く溝を掘り壘を高くして、その鋒を避けよ」と守勢を説き、ひそかに袁紹へ救援を求めれば囲みは自ずと解けると献じた。やがて夜に天象を観て「一将の星まさに墜ちんとす」と孫堅の死期を読み取ると、呂公に五百の兵を授け、百人を山に登らせて石を準備させ、百人を林に伏せて弓弩を持たせ、追ってきた敵を曲がりくねった道で伏兵の地へ誘い込み、矢と石を一斉に浴びせる策を授けた。この計はそのまま発動し、孫堅は峴山で射殺される。会戦の趨勢を一計で決した、完結した謀略であった。\n\nその識見は戦だけにとどまらない。第八回では孫堅の死後すぐ、「子はみな幼く弱体の今こそ江東を一鼓に取れ、屍を返して兵を退けば、力を養われ荊州の患いとなる」と先を見越して進言した。第二十三回には、二心を疑われて斬られかけた韓嵩を「使いに出る前から、その忠の言があった」と弁護して救い、人を見る眼も示している。弟が後に「先の兄の蒯良、最も馬を相するに善し」と回顧したように、馬を見抜く目利きでも知られた人物だった。\n\n惜しむらくは、その的確な献策の多くが、優柔な劉表に容れられず実現しなかったことだ。江東を一鼓に取る策も、曹操への先制も、ことごとく主君の決断を欠いて流れた。荊州という大国に智者がありながら、それが活かされぬまま時が過ぎていく――蒯良の生涯は、名君を得られぬ知恵者のもどかしさを、そのまま映している。"}, {"id": 85, "name": "張魯", "faction": 3, "role": "君主", "rarity": 3, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [0, 0, 0, 1, 3, 4, 4], "p": [7, 4, 7, 2, 3, 5], "scores": {"W": 0.1, "B": 3.0, "S": 3.6, "A": 3.35, "G": 4.89, "K": 4.3}, "stat": {"dmg": 0.97, "area": 1.05, "cd": 1.16, "amount": 2, "knock": 0.65, "crit": 0.05, "duration": 7.6, "pwr": 2.9}, "title": "君主", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [16, 21, 34, 59, 60, 61, 62, 64, 65, 66], "chapN": 14, "bio": "漢中の漢寧太守。五斗米道の祖。西川侵攻を図る", "profile": "漢中に三十年も雄拠した漢寧太守にして、五斗米道の祖。師君と号して宗教と統治を一つに溶かした、群雄のなかでも異色の君主である。馬上で槍を振るう将ではなく、独自の制度と寛政で一国を保った政教一元の支配者として描かれる。\n\nその独創性は第五十九回に詳しい。漢中に拠った張魯は自ら「師君」と号し、道を学びに来る者を「鬼卒」、長たる者を「祭酒」、衆を多く統べる者を「治頭大祭酒」と階層づけ、官長を置かず一切を祭酒に管掌させた。さらに義舎を建て、米・薪・肉を備えて旅人に量に応じて自由に取らせ、誠信を主として欺詐を許さず、罪を犯した者も三度までは赦す。病者には三官手書の儀で救いを施した。「財富み糧足り、四面険固」と記されるその統治基盤こそ、彼が長く漢中を保ち得た理由であった。\n\n一方、軍事や危機の判断はもろい。曹操に攻められても自ら戦わず、弟の張衛を出して許褚に斬られ、戦は楊昂・楊任や龐德に任せきりで、本人は「慌てて文武を集めて評議する」君主に終始する。曹操は煮酒論英雄の席で張魯を「碌々たる小人、歯牙に掛けるに足らず」と一笑に付し、劉璋にとってもその侵犯は「癬疥の疾」に過ぎなかった。閻圃の進言に「大喜」して西川攻略を志し、馬超を婿に迎えようとしながら容れきれず劉備に去られ、貪欲な楊松の讒言を二度まで信じて、四将を相手取った勇将龐德すら離反させてしまう。龐德は「張魯は不仁なり」と言い捨てて曹操に降った。\n\nそれでも、滅びの際の身の処し方は見事だった。陽平関が陥ちて窮した張魯に、弟は倉庫を焼いて逃げよと勧めたが、彼はこれを退け「われもとより国家に帰命せんと欲す。倉廩府庫は国家のもの、廃すべからず」と封鎖して保全したまま降った。これを聞いた曹操は「心はなはだこれを憐れむ」と感じ入り、鎮南将軍として厚遇する。武では一度も主導権を握れなかったが、独自の制度を遺し、一族を軟着陸させて生き延びた――その身の処し方にこそ、この君主の本質がある。"}, {"id": 86, "name": "楊阜", "faction": 1, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [4, 2, 2, 1, 6, 4, 4], "p": [2, 3, 1, 1, 5, 6], "scores": {"W": 2.8, "B": 4.75, "S": 4.35, "A": 4.4, "G": 2.74, "K": 4.1}, "stat": {"dmg": 1.16, "area": 1.14, "cd": 0.98, "amount": 1, "knock": 0.79, "crit": 0.05, "duration": 3.5, "pwr": 4.4}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [59, 64, 92, 99, 105], "chapN": 5, "bio": "涼州参軍。曹操に馬超追討を進言、韋康を推薦", "profile": "魏に仕えた涼州の参軍にして、剛直の諫臣。文官でありながら自ら槍を取って戦場に立ち、謀をめぐらせて猛将馬超を一国から駆逐した、武と政の両面を持つ稀有な人物である。\n\nその名を高からしめたのが、第六十四回「楊阜兵を借りて馬超を破る」である。冀城が馬超に攻められた際、楊阜は主の韋康に降伏をやめるよう泣いて諫めた。城が落ちた後も「賊に従ったのは、残る命をとどめて主君のために冤を報じるため」と耐え忍び、馬超を「勇あって謀なし、図り易し」と看破する。そして姜敘の挙兵、梁寬・趙衢の内応、尹奉・趙昂との連携という多方面の同時挙事を仕込み、推挙して馬超の軍官に据えていた者たちを伏線として、ついに馬超を冀城から放逐した。さらに、馬超が城を棄てて逃れる道に自ら白袍で陣を張り、兄弟七人を率いて挑みかかる。槍を交え、兄弟は皆討たれ、楊阜自身も身に五槍を受けながら、なお死戦をやめなかった。馬超ですら彼を「この人は守義の者なり、斬るべからず」と重んじたほどであった。\n\nその人となりは「守義」「忠義」の一語に尽きる。第五十九回では曹操に「馬超は呂布の勇あり、深く羌人の心を得ている。今討たねば、いずれ隴上諸郡は国家のものでなくなる」と隴右の帰趨を見抜いて進言し、撤退しかけた兵を止めさせた。武勇そのものより、義のために身を賭す覚悟と、情勢を読む眼が彼の真骨頂である。\n\n後年は諫臣としてその本領を発揮する。第九十九回では魏軍の軽率な進撃を諫め、上疏によって曹真・司馬懿を還朝させて危機を回避した。第百五回では、宮室造営にふける明帝に対し、堯舜禹湯を法とし桀紂秦楚を戒めとせよと説き、「棺を叩いて沐浴し、伏して重誅を候つ」と死を賭して諫表を上げた。戦場では槍を取り、朝廷では棺を抱いて諫める――義に生きた一人の臣の、見事な一貫である。"}, {"id": 87, "name": "賈充", "faction": 1, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 3, 4, 3], "p": [4, 5, 2, 3, 6, 5], "scores": {"W": 1.1, "B": 2.9, "S": 3.55, "A": 3.4, "G": 4.07, "K": 4.75}, "stat": {"dmg": 1.03, "area": 1.05, "cd": 1.14, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 3.5, "pwr": 3.35}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [111, 114, 115, 118, 119, 120], "chapN": 6, "bio": "賈逵の子、司馬昭の謀臣。曹髦弑逆を成済に命じる", "profile": "魏の文官にして、司馬昭の腹心。府下の長史から中護軍へと進み、司馬氏の簒奪を陰で支えた実行参謀である。武勇とは無縁の、純然たる策謀の人として描かれ、物語の終幕で晋朝が立ち上がる過程の汚れ役を一手に引き受けた。\n\nその悪名を決定づけたのが、第百十四回の曹髦弑逆である。剣を抜いて司馬昭を討たんと宮中を出た幼帝曹髦に対し、賈充は数千の鉄甲の禁兵を率いて立ちはだかった。禁兵が天子を前にして「皆あえて動かず」と怯むなか、賈充は配下の成済を呼び「司馬公が汝を養うは何のためか――まさに今日のことのためなり」とけしかける。成済は曹髦を車前に刺し殺した。王経が後を追って「逆賊、安んぞあえて君を弑するか」と罵ったが、大逆はこうして成し遂げられた。\n\nその手腕は終始、宮廷の工作にある。第百十一回では諸葛誕のもとへ労軍を口実に潜入してその意中を探り、「徐ろに大事を図るべし」と司馬昭に説いた。第百十八回では鄧艾の驕りに対し「鍾会を封じてこれを制せよ」と武将同士を牽制させる策を献じて採用させ、衛瓘に監督させている。蜀が滅びた直後には成都へ先着し、安民の榜を出して城内の治安を鎮めた。\n\nそして晋建国の演出が、彼の最後の大仕事となる。第百十九回、裴秀とともに「曹丕の漢禅譲の故事に倣い、受禅台を築いて天下に布告し、即位なさいませ」と段取りを設計し、禅譲台の上では「漢の建安二十五年より魏が漢禅を受けて四十五年、今や天禄永く終わり、天命は晋にあり」と司馬氏の正統を高らかに宣言した。後継選定でも長子の司馬炎を立てよと進言し、晋の継承を方向づけている。後段、伐呉では「軍を還すべし」と退却を主張して張華に論破され、呉主孫皓に酷刑を問い詰めて逆にやり込められ「黙然としてはなはだ愧ず」とたじろぐ場面もあった。陳泰に「ただ賈充を斬らば、いささか天下に謝すべし」と名指しされた、最後まで一貫した簒奪劇の黒幕である。"}, {"id": 88, "name": "紀靈", "faction": 3, "role": "武将", "rarity": 3, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [5, 4, 5, 2, 3, 4, 3], "p": [1, 2, 1, 3, 1, 2], "scores": {"W": 4.5, "B": 3.3, "S": 3.55, "A": 3.4, "G": 1.62, "K": 1.75}, "stat": {"dmg": 1.18, "area": 1.08, "cd": 0.99, "amount": 1, "knock": 1.06, "crit": 0.06, "duration": 0, "pwr": 4.55}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [14, 15, 16, 17, 21], "chapN": 5, "bio": "袁術の先鋒、張飛に十合で刺し殺される", "profile": "袁術配下の上将にして、その先鋒を務めた大刀の将。五十斤の三尖刀をふるい、対劉備戦の主将として大軍を預かった猛将でありながら、袁術陣営の謀士的な一面も併せ持つ人物である。\n\n第十四回、劉備討伐の主将を任された紀靈は、関羽と渡り合い「一連三十合、勝負を分かたず」と引き分けた。これは確かに腕の証だが、関羽がわざと長引かせた含みもあり、その直後に副将の荀正はわずか一合で斬られている。武勇は中堅どころの将であった。むしろ知恵者としての見せ場は第十六回にある。呂布と劉備の結びつきを断つため、「主公に一子あり、人を遣わして呂布に縁組を求めよ。布が娘を主公に嫁がせれば、必ず劉備を殺すでしょう。これぞ疏は親を間てずの計なり」と婚姻による離間策を献じ、敵の分断を狙った。袁術が激情のまま親征しようとした際には、「軽々しくなさいますな。呂布は勇力人に過ぎ、徐州の地もあり、布と備が首尾相連なれば図り難し」と諫め、危機を一度抑えてもいる。\n\nだが戦場での実像は、通説で語られる「関羽と三十合分けた猛将」の像よりも辛い。轅門射戟の場では、和睦を演出しようとする呂布に「幼な児を提げるがごとく」つかみ戻され、面目を失った。第十七回の七路征徐州では「都救応使」の任を受けたものの、呂布軍に「紀靈大敗して走る」と敗走を重ねる。十万の兵を預かりながら、それを勝たせた記録は残らなかった。\n\n最期は第二十一回、あっけなく訪れる。袁術救援に出た紀靈は、張飛と渡り合うも「闘うこと十合に満たず」して馬上から刺し殺された。張飛は彼ら一行を「児戯のごとく見る」と侮っていたという。大軍を率いた一陣の主将でありながら、強者の前ではしばしば軽んじられた――その落差こそが、紀靈という武将の輪郭を形づくっている。"}, {"id": 89, "name": "辛毗", "faction": 1, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 3, 6, 2], "p": [1, 1, 4, 6, 3, 6], "scores": {"W": 1.1, "B": 2.95, "S": 4.65, "A": 4.35, "G": 3.15, "K": 2.55}, "stat": {"dmg": 1.13, "area": 1.14, "cd": 1.15, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 4.0, "pwr": 4.15}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [32, 33, 79, 86, 95, 97, 103], "chapN": 7, "bio": "侍中。屯田十年を進言し呉征を諫める", "profile": "魏に仕えた侍中・衛尉。「能言の士」と評された弁舌の文官であり、相手の勢いを読み、言葉でその心を動かすことを身上とした人物である。袁譚の使者から始まり、曹操を動かし、曹丕を諫め、司馬懿の真意を見抜く節使に至るまで、一貫して舌と読みで時局を渡った臣であった。\n\nその弁舌が冴え渡るのが、第三十二回である。袁譚の使者として単身曹操の陣に乗り込んだ辛毗は、「劉表には四方を望む志なし、最大の患いは河北にあり。まず袁尚を撃ち冀州を平らげれば、覇業は成りましょう」と、戦略の優先順位を説いた。袁氏の内輪もめを「土崩瓦解、天が袁氏を滅ぼす時」と見切るその情勢分析に、曹操は「辛佐治と相見ること晩きを恨む」と嘆じ、即日軍を返して冀州攻略に向かわせた。一回の説得で、覇者の方針そのものを転換させたのである。冀州入城の際には馬を躍らせて先頭を駆けたが、彼の手柄は剣ではなく、この弁にあった。なお冀州攻防では、審配によって一族八十余口を斬られるという悲劇の当事者でもあり、捕らわれた審配を鞭で指して「賊殺才、今日死せん」と歯がみした場面が、その私怨の深さを物語る。\n\nその後も、辛毗は要所で言葉を発し続ける。第八十六回では、呉征に逸る曹丕に「今日の計は、兵を養い屯田すること十年、食足り兵足りて後に用いれば、呉も蜀も破れましょう」と、国力の涵養を説いた。第百三回、五丈原で司馬懿が巾幗の辱めに怒る諸将を抑えかね、形ばかり出戦を請うた表を上げた時には、その真意を即座に見抜く。「司馬懿にもとより戦心なし、ただ諸将の心を遏めんがための表なり」と曹叡に進言し、自ら節を持って渭北に赴き、「再び出戦を言う者あらば、即ち違旨をもって論ぜん」と将の暴発を封じた。後にこれを知った司馬懿は「公まことにわが心を知れり」と認めたという。戦場で刀をふるう将ではなかったが、言葉一つで覇者を動かし、軍の暴走を抑えた――辛毗は、舌をもって乱世を生き抜いた知者であった。"}, {"id": 90, "name": "関平", "faction": 0, "role": "武將", "rarity": 3, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [6, 4, 3, 2, 4, 2, 5], "p": [1, 1, 1, 1, 2, 3], "scores": {"W": 4.45, "B": 4.05, "S": 2.8, "A": 2.85, "G": 1.37, "K": 2.4}, "stat": {"dmg": 1.16, "area": 1.0, "cd": 0.92, "amount": 1, "knock": 0.91, "crit": 0.06, "duration": 0, "pwr": 4.4}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [28, 31, 39, 62, 63, 65, 66, 73, 74, 75], "chapN": 15, "bio": "関羽の子。劉封と水路を断ち、西川入りに従軍", "profile": "蜀漢の武将、関羽の子。とはいえ演義の本文をたどると、関平は実子ではなく、第二十八回で関羽が義兄弟の旅の途上に立ち寄った関定の次子を見込み、養子としたのが始まりである。以後、彼は最後まで「関公義子関平」と呼ばれ続け、独立した武名や称号を一度も与えられない。父の威光のもとに立つ補佐役――それが演義の関平の立ち位置であり、政治の記録はほぼ皆無の、純然たる武人である。\n\nその腕は決して飾りではない。第七十四回、樊城の前で曹操が放った猛将龐徳と斬り結び、「戦三十合、不分勝負」と互角に渡り合っている。龐徳は彼を「疥癩の小児、吾汝を殺さず」と侮ったが、三十合を支えきった事実が反論になっている。第七十三回には曹将翟元を追いつめ「一刀斬之」と仕留めた確かな戦果もある。だが彼の真価は、討つことよりも、父を生かすことに発揮された。\n\nその性根は、孝と忠の二字に尽きる。第七十六回、偃城の徐晃が仕掛けた火計を「平、是れ計と知り」と見抜いて火急に退き、廖化と二路に分かれて重囲を破り、囲まれた父を救い出す。撤退に際しては麦城への一時退避を進言し、「軍心乱る。必ず城池を得て暫く屯し、以て援兵を待たん」と当座を凌ごうとした。光は乏しくとも、彼の眼はいつも父の安否に向いていた。\n\nそして第七十七回、臨沮で四方を伏兵に囲まれ、父子はともに力尽きて擒となる。父が「碧眼の小児、紫髯の鼠輩」と最後まで節を屈さぬ傍らで、関平もまた一言も降を口にせず、運命を分かち合った。武勲の数では五虎には遠く及ばぬ彼が、後世に名を残したのは、まさにこの一点――父と生死をともにしたその姿ゆえである。"}, {"id": 91, "name": "韓当", "faction": 2, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [6, 4, 3, 2, 4, 2, 5], "p": [1, 1, 1, 1, 2, 1], "scores": {"W": 4.45, "B": 4.05, "S": 2.8, "A": 2.85, "G": 1.13, "K": 2.1}, "stat": {"dmg": 1.16, "area": 1.0, "cd": 0.92, "amount": 1, "knock": 0.91, "crit": 0.06, "duration": 0, "pwr": 4.4}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [5, 7, 15, 44, 45, 48, 50, 51, 55, 61], "chapN": 20, "bio": "呉の武将。曹洪と戦い周瑜に従う", "profile": "呉の武将。孫堅・孫策・孫権の三代に仕えた江東の宿将で、第八十三回では自ら「吾、孫将軍に従いて江南を平定してより、数百戦を経たり」と語る、いぶし銀の老兵である。赤壁、南郡、濡須、夷陵と、呉の主立った戦のたびに前部先鋒や左翼を任され、戦場の最前線を絶えず歩み続けた、忠勇一徹の実戦派指揮官だ。\n\nその槍は確かに名を惜しまぬ。第七回では黄祖配下の張虎を「韓当の一刀に、半個の脳袋を削り去らる」と斬り、第五十回の赤壁前哨では焦触に対して「当、手を起こすこと一槍、焦触を刺殺す」と一突きで仕留めている。第六十一回の濡須では、周泰と二騎で曹操本人へ「直ちに衝かんとして将に上り来たる」と突進する勇姿を見せ、第四十八回では「掩心を胸に披り、長槍を手に執り、船頭に立つ」その姿が描かれた。\n\n人となりは、戦友への情に厚い。第五十回、赤壁で苦肉の計を果たし火傷を負って江中に落ちた黄蓋を、韓当は急ぎ救い上げ、「刀を用いて箭頭を剜り出し、旗を扯きて之を束ね」、さらに自らの戦袍を脱いで着せかけ、別船で本営へ後送した。この機転と情義こそ彼の真骨頂である。一方で、彼は常に程普・黄蓋とともに動く「三将」の一人、あるいは周泰との二人組であり、計略や統治を自ら立てる場ではない。第八十三回では劉備に向かい「陛下、今、蜀主たり、何ぞ自ら軽々しく出づるや」と呼びかけている。\n\nその武勇は信頼に足るが、大局を読む将ではなかった。夷陵において、陸遜の堅守の策に「この孺子を将と為さば、東呉休せん」と最も声高く不服を唱えたのは韓当である。だが結局その堅守が呉を救った。第八十四回の火攻めでは江北岸を攻める一軍を率い、陸遜の計の実行役として最後まで前線を担った。武に過ぎて謀に届かぬ――それでも三代の主に仕え抜いた古参の重みは、江東の歴史そのものである。"}, {"id": 92, "name": "審配", "faction": 3, "role": "軍師参謀", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 6, 3, 5], "p": [2, 2, 4, 1, 3, 3], "scores": {"W": 1.1, "B": 4.6, "S": 3.9, "A": 4.05, "G": 2.46, "K": 3.05}, "stat": {"dmg": 1.13, "area": 1.09, "cd": 1.08, "amount": 2, "knock": 0.77, "crit": 0.06, "duration": 3.25, "pwr": 4.15}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [11, 12, 13, 22, 24, 26, 30, 31, 32, 89], "chapN": 13, "bio": "袁尚を輔けた忠臣、冀州死守", "profile": "袁紹に仕えた河北の謀士。「智謀の士」と並び称される参謀の一人でありながら、本文の審配は計略の冴えよりも、城に殉じる剛直な忠臣として記憶される。荀彧には「審配、専にして謀無し」と評され、知略の人というより、ひとたび守ると決めた地を死力で守り抜く、守城型の硬骨漢であった。\n\nその手腕が最も光るのは籠城の戦術である。第三十回の官渡で、彼は弩手一万を両翼に伏せ、土山を築いて高櫓から矢を射下ろし、さらに「軍人をして鉄もて暗かに地道を打たしめ、直ちに曹営の内に透らしめ、号して掘子軍と為す」と地下からの奇襲まで連発した。兵站の眼も鋭く、「行軍は糧食を以て重しと為す。烏巣は乃ち屯糧の処、必ず重兵を得て之を守るべし」と急所を見抜いて進言している。だがいずれも劉曄の発石車と長塹に破られ、烏巣の警告も容れられぬまま焼かれた。\n\n性格は剛烈に過ぎた。許攸の子姪を獄に下す書を送って許攸を激発させ、彼を曹操の陣へ走らせたのは官渡敗北の致命傷となる。「忠言は耳に逆らう、豎子ともに謀るに足らず」――許攸のこの嘆きは、審配の硬さが招いた皮肉であった。第三十二回、冀州死守の局面では「法令甚だ厳」と軍を締め上げ、東門の馮礼が酒に酔って巡警を誤れば「痛く之を責む」。その厳しさが恨みを生み、馮礼は降り、甥の審栄の裏切りで城門はついに開かれる。\n\nそれでも審配の名が忠臣として残るのは、最期の一場面ゆえである。徐晃に生け捕られ城外へ引き出された彼は、屈することなく言い放った。「吾、生きては袁氏の臣、死しては袁氏の鬼、汝輩讒諂阿諛の賊に似ず。速やかに我を斬るべし」と。さらに「吾が主は北に在り、我をして南に面して死せしむべからず」と、北を向いて斬られたという。袁紹臨終の枕辺に呼ばれて遺嘱を執筆し袁尚擁立を担った彼は、結果として骨肉の争いの種を残してしまった。だが冀州とともに滅び、最後まで主家に背を向けなかったその姿は、敗者の側にあってなお凛とした忠烈の像を刻んでいる。"}, {"id": 93, "name": "曹仁", "faction": 1, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [5, 6, 2, 3, 4, 3, 4], "p": [1, 1, 1, 1, 2, 2], "scores": {"W": 4.25, "B": 3.9, "S": 3.35, "A": 3.4, "G": 1.25, "K": 2.05}, "stat": {"dmg": 1.11, "area": 1.0, "cd": 0.96, "amount": 1, "knock": 0.89, "crit": 0.07, "duration": 0, "pwr": 4.05}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [5, 14, 23, 35, 36, 40, 50, 51, 58, 66], "chapN": 43, "bio": "曹操の従弟、南郡を守備し敗走する曹操を迎える", "profile": "魏の武将、曹操の従弟にあたる宗族の重鎮。曹操からは第二十三回で「曹子孝は世間の福将」と評され、玄徳も第五十一回、周瑜の前で「曹仁の勇は当たるべからず」とその武を認めた。一方で同じ第二十三回には禰衡から「要銭の太守」と嘲られる負の評もつきまとう。地位も勇名もありながら、演義の曹仁には不思議と敗将の影が濃い。\n\nその武勇の白眉は、第五十一回の単騎救出にある。城上から味方の牛金が敵中に囲まれるのを見た曹仁は、「甲を披り馬に上り、麾下の壮士数百騎を引きて城を出で、力を奮いて刀を揮う」と呉陣へ斬り込み、徐盛を退けて牛金を救い出した。なお陣中に味方が残るのを見るや「遂に復た身を翻して殺し入り、重囲より救い出だす」と、二度までも突入してみせる。この捨て身の勇は紛れもなく本物であった。\n\nただ、采配となると影が差す。新野では諸葛亮の火計に二度まんまと惨敗し、第三十六回では味方の李典を疑って斬ろうとし「公、二心を懐くか」と詰る一幕すらある。南郡では周瑜に翻弄され、第七十四回の樊城では関羽の水攻めに将兵が「喪胆せざる無し」となるや、曹仁自身も「今日の危、力もて救うべきに非ず。舟に乗じて夜走すべし。城を失うと雖も、尚お身を全うすべし」と城を捨てる夜逃げを口にした。関羽を前にしては「胆戦き心驚き、あえて交鋒せず」と襄陽へ逃れている。\n\n赤壁の後、曹操から「荊州は汝に託して管領せしむ」と南郡を委ねられて以来、彼は魏の西南の鎮として長く前線を担った。樊城を曹操の援軍到着まで持ちこたえた粘りは確かだが、それは満寵の支えに負うところが大きく、最終の功は徐晃に帰せられている。それでも宗族の柱として遇され続け、第八十六回には「大司馬曹仁」――魏の最高軍職を帯びた身として世を去った。勝ち戦の少ない名将という、演義ならではの陰影を背負った人物である。"}, {"id": 94, "name": "徐庶", "faction": 1, "role": "軍師参謀", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 7, 3, 3], "p": [1, 8, 1, 4, 2, 3], "scores": {"W": 1.0, "B": 4.5, "S": 3.9, "A": 4.2, "G": 3.22, "K": 3.4}, "stat": {"dmg": 1.13, "area": 1.12, "cd": 1.09, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.25, "pwr": 4.2}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [35, 36, 37, 38, 39, 41, 48], "chapN": 7, "bio": "曹操陣中にあるが献策せず、龐統の助言で散関へ脱出", "profile": "劉備に仕えた軍師にして、後に曹操の陣中へと身を移す数奇な才人。世には「諸葛亮を薦めた人」「終身一計も献じなかった孝子」として知られる。だが演義の徐庶は単なる橋渡し役ではない。化名「単福」として劉備のもとに現れた彼は、新野の小勢を率いて連勝へ導いた、れっきとした実働の名軍師である。称えられるのは武ではなく、「奇才」「経天緯地の才」――その明晰な頭脳であった。\n\nその采配は鮮やかだった。第三十五回で劉備に軍師として迎えられ本部の人馬を調練すると、曹仁を二度まで撃破する。圧巻は第三十六回、曹仁が布いた八門金鎖の陣を高所から一望し、「八門は休・生・傷・杜・景・死・驚・開、今、中間還た主持を欠く。東南の角上、生門より撃ち入り、正西の景門より出づれば、其の陣必ず乱れん」と看破。趙雲に突破口を指示し、その通りに陣を破ってみせた。樊城の手薄を突く奇襲、夜襲を見越した火計と、短い間に密度の濃い勝ち戦を重ねている。\n\n人を見る眼が、彼の最大の功績を生む。やがて母を曹操に人質に取られ去る際、徐庶は劉備に一人の臥龍を遺していった。「この人、瑯琊陽都の人、覆姓は諸葛、名は亮、字は孔明……経天緯地の才有り、蓋し天下一人なり」と。自らを「駑馬」、孔明を「麒麟」と評し、三顧の礼を起動させたのである。後人はこの一件を「片言却って春雷の震うに似たり、能く南陽をして臥龍を起たしむ」と讃えた。\n\n魏に移ってからの徐庶は、自ら誓った通り口を閉ざす。第四十一回には曹操の使者として樊城に立つが、招降の弁を述べながら本心では「曹操、庶をして来たり使君を招降せしむは、乃ち假りに民心を買うなり」とその意図を暴き、逆に避難を勧めた。第四十八回の赤壁前夜には、龐統の連環計を見抜きながらあえて破らず、自ら流言を装って散関の守備を願い出て戦場を離脱する。「身は彼に在りと雖も、誓いて一謀をも設けず」――母の死後もその誓いを守り通したその姿は、才を惜しみながらも義に殉じた一人の人間の、静かな矜持として描かれている。"}, {"id": 95, "name": "王基", "faction": 1, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 1, 1, 1, 5, 4, 5], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 1.9, "B": 4.45, "S": 4.2, "A": 4.1, "G": 1.12, "K": 1.95}, "stat": {"dmg": 0.85, "area": 0.87, "cd": 1.01, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.9}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [69, 110, 111, 112], "chapN": 4, "bio": "安平太守。管輅の卜占逸話に登場", "profile": "魏の武将。司馬師・司馬昭による淮南三叛の討伐で、先鋒や監軍として安定した働きを見せる堅実な方面指揮官である。初出の第六十九回では名のみ――管輅に占いをさせる安平太守として顔を出すにとどまるが、後半生の戦役では実働の将として確かな存在感を放つ。\n\nその指揮は、戦場の急所を読む眼に支えられている。第百十回、毋丘倹の乱に際して王基は「南頓は極めて屯兵に好し、兵を提げて星夜に之を取るべし。遅ければ則ち毋丘倹必ず先に至らん」と要地の先取を進言し、実際に敵より先んじて占拠してその作戦を頓挫させた。さらに乱の本質を「淮南の反は、軍民の乱を思うに非ず、皆、毋丘倹の勢力に逼られて已むを得ず之に従うのみ」と看破し、持久策を退けて速攻で瓦解させる方針を示すと、司馬師は「この言、甚だ妙なり」と容れている。\n\n戦そのものでも手堅い。第百十一回、正先鋒として出馬し朱異と相対するや「戦うこと三合ならず、朱異敗走す」と退け、すかさず「兵を駆りて掩殺し」呉兵を五十里も後退させた。第百十二回の諸葛誕包囲戦では西門を攻め、呉将于詮と遭遇して「何ぞ早く降らざる」と大喝している。もっとも于詮はこれに激怒し、三十余合の死戦の末に乱軍の中で討たれた。王基自身が名将を斬って取る派手な武はなく、あくまで軍を動かす指揮の確かさが身上であった。\n\n伏撃、退路の遮断、攻城と、一連の戦局を破綻なく統御し、最後まで離反や崩壊の影を見せなかった。突出した武名や膂力の逸話はなく、人望で兵を心服させる類の英雄でもない。だが命じられた一翼を着実に勝ちへ運ぶ――そうした有能な前線指揮官として、王基は魏の屋台骨を静かに支えた。"}, {"id": 96, "name": "曹真", "faction": 1, "role": "武将", "rarity": 3, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [1, 1, 0, 2, 3, 3, 4], "p": [2, 4, 0, 0, 6, 5], "scores": {"W": 0.85, "B": 3.0, "S": 3.05, "A": 2.95, "G": 2.62, "K": 4.45}, "stat": {"dmg": 0.71, "area": 0.85, "cd": 1.13, "amount": 1, "knock": 0.7, "crit": 0.06, "duration": 0, "pwr": 0.8}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [84, 85, 86, 91, 93, 94, 95, 97, 98, 99], "chapN": 14, "bio": "魏の大将軍・大都督。南郡や陽平関を攻めるが敗れる", "profile": "魏の大将軍・大都督にして、曹氏宗族の柱石。文帝曹丕の臨終には陳群・司馬懿とともに枕辺へ呼ばれ、「文皇帝、孤を臣等数人に托す」と託孤の重臣に名を連ねた。曹叡の擁立を担い、二十万・四十万の大軍を委ねられた、地位だけを見れば魏の頂点に立つ人物である。だが演義の曹真は、その地位の高さに実績がまるで伴わない、やられ役の総大将として描かれている。\n\n戦場での彼は、ことごとく孔明の前に崩れる。第九十三回、郭淮の劫寨対策に「この計、吾と相合す」と乗れば結果は大敗。第九十七回の費耀の罠も、第九十八回の孫礼の糧車計も、悉く孔明に見破られて失敗に終わる。自前で機能した作戦は一つもなく、追撃に出れば「真、兵を引いて鼠竄して還る」と逃げ帰るばかり。先鋒の曹遵・朱讚・費耀・秦良が次々討たれても、曹真自身は一度も斬り合うことがない。費耀からは「曹都督は乃ち金枝玉葉」と評され、武人というより名門の御曹司として遇された。\n\n人を見る眼と政治の弁えは、武の不振を多少なりとも補っていた。副都督に郭淮を、先鋒に王雙を自ら推挙して採用させる権限と眼識はあり、第九十一回には司馬懿謀反の疑惑に対し「文皇帝、孤を臣等数人に托す。司馬仲達に異志無きを知ればなり。今、事の真假未だ知らず、遽爾として兵を加うるは、乃ち之を逼りて反かしむるなり」と、軽挙が反乱を招くと冷静に諫めてみせた。漢高祖が雲夢に偽り遊んだ故事を引くこの献策は、まさに当を得ていた。\n\nしかし武人としての最期はあまりに痛ましい。伐蜀を建議すれば長雨に阻まれ半月も谷を進めず撤退、ついには司馬懿が「あえて真をして兵を引かしめず」と指揮権を事実上取り上げる。第百回、視界に現れた人影に「真、胆戦き心驚く」――それは司馬懿であった。そして孔明から送られた嘲弄の書に「恨気胸に填ち」、陣中で憤死する。地位は最上級、武人としての描写は最下層という極端な落差。その縁が子の曹爽の出世へと繋がっていく伏線もまた、後の魏の運命を暗示している。"}, {"id": 97, "name": "董昭", "faction": 1, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 3, 6, 1], "p": [6, 2, 1, 4, 5, 2], "scores": {"W": 0.0, "B": 2.5, "S": 4.45, "A": 4.1, "G": 3.39, "K": 3.3}, "stat": {"dmg": 1.09, "area": 1.14, "cd": 1.2, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 4.0, "pwr": 3.85}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [14, 61, 73, 76], "chapN": 4, "bio": "許都遷都を進言した謀士、元袁紹・張揚従事", "profile": "魏の文官。もとは袁紹・張揚のもとに身を置いた策士で、後に曹操に仕え、曹魏の覇業の骨格を据えた謀臣である。剣を執る描写は一つもなく、終始帳中で献策する純然たる頭脳。だが彼が放った一手は、天下の流れそのものを変えた。\n\nその第一の功は、第十四回の遷都の進言にある。董昭は曹操に説いた。「明公、義兵を興して以て暴乱を除き、入朝して天子を輔佐す、此れ五伯の功なり……惟だ駕を移して許都に幸するを上策と為す。夫れ非常の事を行えば、乃ち非常の功有り。願わくは将軍、之を決計せよ」と。天子を許都に擁すること――これが後の「天子を挟みて諸侯に令す」という曹操覇府の起点となった。荀彧の奉天子論と並ぶ、国家規模の卓見である。\n\n策士としての真骨頂は、根回しと逆用の巧みさにある。遷都に際し楊奉らの変事を曹操に問われると、彼は即座に「易きなり」と答え、楊奉には書を送って懐柔し、大臣には「京師に糧無し」を口実に説いて遷都を呑ませた。第七十六回の樊城救援では、孫呉の密書を逆手に取る計を授けている。「人をして書を将て樊城に射入せしめ、以て軍心を寛め、且つ関公をして東呉の将に荊州を襲わんとするを知らしめよ。彼、荊州の失あらんことを恐れ、必ず速かに退兵せん。却って徐晃をして勢いに乗じて掩殺せしめば、全功を獲べし」と。曹操はこの謀に従った。\n\nそして簒奪へと至る階梯を、彼はためらいなく上っていく。第六十一回、董昭は曹操に魏公の位と九錫を授ける推戴を主導した。荀彧が「不可」と反対しても、「豈に一人を以て衆望を阻むべけんや」と押し切り、漢から魏への王朝交代へ一段、駒を進めたのである。武勇とは無縁の、しかし歴史を動かす謀臣――登場はわずか数場面ながら、董昭の残した手筋は曹魏の土台そのものとなった。"}, {"id": 98, "name": "袁紹", "faction": 3, "role": "君主", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 2, 1, 3, 3, 5, 4], "p": [3, 3, 3, 4, 6, 2], "scores": {"W": 1.85, "B": 3.45, "S": 4.3, "A": 4.05, "G": 3.42, "K": 3.95}, "stat": {"dmg": 1.11, "area": 1.09, "cd": 1.09, "amount": 1, "knock": 0.82, "crit": 0.07, "duration": 3.75, "pwr": 4.0}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [3, 5, 6, 7, 21, 22, 23, 24, 26, 28], "chapN": 41, "bio": "既に滅んだ群雄、曹操の旧敵として度々引き合いに出される", "profile": "四世三公の名門に生まれた河北最大の群雄。反董卓連合の盟主に推され、帯甲百万を擁して曹操と天下を争った、まさに「持てる者」であった。第五回では「四世三公、門に故吏多く、漢朝名相の裔、盟主と為すべし」とその家格を理由に諸侯の上に立つ。だが演義が描く袁紹の核心は、その豪奢な資本のことごとくを生かしきれぬ、「好謀無断」「外は寛にして内は忌む」優柔と猜忌の人物像である。\n\n武においては、名門の威儀に中身が伴わない。第七回の界橋では趙雲に陣を破られて空壁に追い込まれ、口では「大丈夫、願わくは陣に臨んで闘死せん、豈に牆に入りて活を望むべけんや」と勇むものの、実際は顔良の救援で脱出するだけ。第七回、劉備・関羽・張飛三騎の突撃を前にしては「紹、驚きて魂、天外に飛び、手中の宝刀、馬下に墜つ」と刀を取り落として逃げている。勇名が向くのは「勇は三軍に冠たり」と称される配下の顔良・文醜であって、袁紹本人ではない。\n\nそして悲劇の根は、忠言を仇で返す癖にあった。官渡では沮授の緩守策も許攸の許都急襲策も退け、烏巣救援という決定局面でも張郃の正論を捨てて郭図の浅策を採り、全軍崩壊を招く。正論を吐いた許攸を「本当に首を斬るべきところ、今、権り且く頭を項に寄せ置く。速やかに退き出でよ、今後相見ゆるを許さず」と讒言一つで罵り追放し、曹操のもとへ走らせた。忠臣沮授を鎖につなぎ、田豊を獄に下し、派閥の対立を放置する。荀彧の「紹は兵多くして整わず」という評は、あまりに的確であった。\n\n最も致命的だったのは、危機の局面で決断できぬことである。第二十四回、許都急襲の好機に幼子の疥瘡を理由をこれを捨て、田豊に「この遇い難きの時に遭いて、乃ち嬰児の病を以て此の機会を失う、大事去れり」と杖で地を打って嘆かれた。後継も「躊躇未決」のまま定めず、第三十一回に病死すると、三子一甥が相争う内訌の種だけが残った。後年、曹操は墓前で袁紹のかつての大言を回想する。「吾、河北に拠り、燕代を阻み、沙漠の衆を兼ね、南向して以て天下を争わん」と。だが曹操は「吾は天下の智力に任せ、道を以て之を御す、不可なる所無し」と即座に質の差で応じた。構想の大きさは随一でありながら、それを運用できずに自壊した――袁紹は、恵まれた者がいかにして敗れるかを体現する、忘れがたい敗者である。"}, {"id": 99, "name": "蒯越", "faction": 3, "role": "軍師参謀", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 1, 1, 1, 4, 5, 3], "p": [2, 2, 1, 6, 4, 4], "scores": {"W": 1.45, "B": 3.55, "S": 4.35, "A": 4.15, "G": 2.92, "K": 3.1}, "stat": {"dmg": 1.11, "area": 1.12, "cd": 1.09, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.75, "pwr": 4.05}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [6, 7, 34, 40, 41], "chapN": 5, "bio": "荊州の重臣、曹操に降り江陵太守樊城侯に封じられる", "profile": "荊州の重臣にして、劉表を支えた知謀の臣。字は異度。曹操が「吾、荊州を得るを喜ばず、異度を得るを喜ぶ」と評したほど、演義は彼を一流の知者として遇する。だがその才は、自勢力を築く構想ではなく、もっぱら去就の見極めと現実的な計議に注がれた。\n\n意外にも、初登場の彼は陣頭に立つ武官的な姿である。第六回、荊州境を侵す孫堅を迎え撃つにあたり、蒯越は「陣を将て擺き開き、当先して馬を出だ」した。問答こそ自ら交わすが斬り合いは蔡瑁が担い、彼の本領はむしろ伏兵の采配にある。両山の陰に兵を伏せ、追ってくる孫堅を「両山の後、伏兵斉しく起こり、背後に蒯越・蔡瑁趕い来たり、孫堅を垓心に困ましむ」と包囲してみせた。第三十四回には劉備暗殺の計議に加わり、「吾、趙雲の行坐玄徳を離れざるを見る、恐らくは手を下し難からん」と警戒を口にしている。\n\n彼の名を決定づけるのは、第四十回の弁舌である。曹操の大軍が南下するなか、若き劉琮に降伏を説いた一席――「夫れ逆順に大体有り、強弱に定勢有り。今、曹操、南征北討して、朝廷を以て名と為す。主公、之を拒まば、其の名順ならず」。さらに「主公新たに立ち、外患未だ寧からず、内憂将に作らんとす。荊・襄の民、曹兵の至るを聞かば、未だ戦わずして胆先ず寒し。安んぞ能く之と敵せん」と内憂外患を冷徹に列ね、傅巽・王粲をも巻き込んで降伏の合意を導いた。天下の形勢を読み切る眼の確かさが、ここに凝縮している。\n\n降伏に伴う混乱の収拾にも、彼は心を配った。第四十一回、降を罵る王威を「売国の徒、吾、汝の肉を生啖せざるを恨む」と蔡瑁が斬ろうとすると、蒯越はこれを諫め止め、無用の流血を抑えている。やがて曹操に帰順して江陵太守・樊城侯に封じられた。一国の進路を弁舌一つで定めた現実主義者――その判断は荊州の解体を意味したが、滅びゆく勢力にあってなお冷静に最善を読み続けた知者として、演義は彼に確かな敬意を払っている。"}, {"id": 100, "name": "馬謖", "faction": 0, "role": "軍師参謀", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 4, 5, 2], "p": [1, 2, 1, 1, 1, 2], "scores": {"W": 1.0, "B": 3.2, "S": 4.25, "A": 4.1, "G": 1.32, "K": 1.55}, "stat": {"dmg": 1.1, "area": 1.12, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.75, "pwr": 3.95}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [52, 65, 85, 87, 88, 91, 94, 95, 96, 99], "chapN": 10, "bio": "馬良の弟。馬氏五常の幼弟として名が挙がる", "profile": "蜀漢の参軍。馬良の弟であり、荊州の名門・馬氏の俊英「馬氏五常」の末弟として名を連ねた。武勇の士ではなく、机に向かって兵法を論じ、戦の構図を読み解く頭脳の人である。諸葛亮はこの若者を深く愛し、その献策に幾度も膝を打った。\n\nその才が最も輝いたのは南蛮平定の前夜だった。第八十七回、馬謖は「夫れ用兵の道は、心を攻むるを上と為し、城を攻むるを下と為す。心戦を上と為し、兵戦を下と為す。願わくは丞相ただ其の心を服せしむれば足れり」と説く。孔明はこれを全面的に容れ、後の七縦七擒——孟獲を七たび捕えて七たび放つ大方針はここから生まれた。孔明をして「幼常、よく吾が肺腑を知るなり」と嘆ぜしめた一言だった。第九十一回でも、曹叡の手で司馬懿を退けさせる離間の計を進言し、採用されている。献策の冴えは、誰もが認めるところだった。\n\nだが第九十五回、街亭。初めて単独の野戦指揮を委ねられた馬謖は、副将王平の「当道に砦を築くべし」という正論を退け、「此処の側の一山、四面みな相連ならず、且つ樹木きわめて広し、これ乃ち天の賜いし険なり」と山上に布陣した。兵法の「これを死地に置きて而る後に生く」を引いたが、その引用こそが誤りだった。司馬懿に汲水の道を断たれると軍はたちまち崩れ、馬謖が紅旗を振って号令しても兵は互いに押し付け合い、ついに「一人も敢えて動く無し」。激怒した馬謖は味方の将を二人斬ったが、兵は山を下って魏に降った。敵将司馬懿は冷ややかに笑った——「ただ虚名あるのみ、乃ち庸才のみ」。献策の鋭さと実戦指揮の壊滅、その乖離が街亭ですべて露わになった。\n\n第九十六回、敗軍の責を負って斬られる。死に臨んで馬謖は泣いて言った。「丞相、某を視ること子のごとし、某、丞相を以て父と為す。願わくは丞相、舜帝の鯀を殛して禹を用いし義を思え。某、死すといえども九泉に恨み無し」。北伐の咽喉を一手で瓦解させた失敗は重く、その名は後世「泣いて馬謖を斬る」の故事とともに語り継がれる。鋭い知恵と、それを実地に活かしきれなかった脆さ——両面を併せ持つがゆえに、忘れがたい人物である。"}, {"id": 101, "name": "周倉", "faction": 0, "role": "武将", "rarity": 3, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [4, 3, 6, 2, 1, 1, 2], "p": [0, 0, 0, 0, 1, 2], "scores": {"W": 4.1, "B": 1.6, "S": 1.15, "A": 1.15, "G": 0.37, "K": 1.0}, "stat": {"dmg": 1.14, "area": 1.1, "cd": 1.06, "amount": 1, "knock": 1.13, "crit": 0.06, "duration": 0, "pwr": 4.25}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [28, 31, 49, 63, 65, 66, 74, 77], "chapN": 8, "bio": "関羽の従将、華容道の伏兵に従う", "profile": "蜀漢の武将。関羽に従って大刀を捧げ持つ従将として、関羽の傍らに影のように寄り添った剛勇の士である。「黒面長身、槍を持して馬に乗り」と描かれ、もとは黄巾の残党、自ら「粗莽の夫、身を失して盗と為る」と称する野の者だった。\n\n第二十八回、臥牛山で関羽に出会った周倉は、「倉、隻身歩行し、将軍に跟随す。万里といえども辞せざるなり」と願い出て、その日から関羽の従者となった。以後、捧刀役として、標旗を振る合図役として、守城の留め置き役として、関羽の戦のあらゆる場面に侍る。第六十六回の単刀会では、階下から「天下の土地、ただ有徳者のみ之に居る。あに独り是れ汝が東呉のみ当に有るべけんや」と声を張り上げて場を威圧したが、関羽自身に「汝なんぞ敢えて多言する、速やかに去るべし」と叱られて退いている。\n\n最大の手柄は第七十四回、龐徳の生け捕りだった。「船上のかの将、跳びて水に下り、龐徳を生擒して船に上る。衆これを視るに、龐徳を擒えし者は乃ち周倉なり」。これは一騎打ちの武功ではない。「倉、もとより水性を知り、また荊州に住むこと数年、いよいよ慣熟を加う。さらに力大なるを兼ぬ。此に因りて龐徳を擒う」——その怪力と水練の腕で、水中の組討によって名将を絡め取ったのである。\n\n第七十七回、麦城の最期。落城の危急に王甫とともに孤城を守り、関羽父子の首級が示されるや「王甫、大いに一声を叫び、城に墜ちて死す。周倉、自刎して亡ず」。主の死を見て、迷わず後を追った。武功は限られ、独立した将としての戦果は乏しい。それでも周倉の名が消えないのは、ひとえにその忠義の純度ゆえである。関羽に殉じた大刀の将——その一点において、彼は完結している。"}, {"id": 102, "name": "諸葛瞻", "faction": 0, "role": "その他", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [6, 4, 1, 3, 3, 2, 5], "p": [1, 1, 1, 2, 2, 3], "scores": {"W": 4.05, "B": 3.65, "S": 2.6, "A": 2.6, "G": 1.52, "K": 2.4}, "stat": {"dmg": 0.95, "area": 0.97, "cd": 0.93, "amount": 1, "knock": 0.82, "crit": 0.07, "duration": 3.0, "pwr": 2.75}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [16, 19, 79, 105, 117, 118], "chapN": 6, "bio": "孔明の子、喪に服す", "profile": "蜀漢の将。丞相諸葛亮の子として生まれ、父の遺志を一身に背負った人物である。通説では「孔明の子だが凡才」と評されるが、演義に描かれる諸葛瞻はほぼ綿竹防衛戦の一点に凝縮され、そこに見えるのは凡庸さよりも、謀略には欠けるが忠義一徹の将の姿である。\n\n第百十七回、鄧艾が険を越えて成都に迫ると、瞻は成都の兵七万を率いて綿竹に出陣する。子の諸葛尚が「父親すでに大権を掌る、児、願わくは先鋒と為らん」と進み出て、父子で迎え撃った。瞻は「両掖の兵を指揮して衝き出で、魏陣の中に撞入し、左衝右突、往来して殺すこと数十番、魏兵大敗し、死者その数を計らず」。父孔明の木刻の遺像を車上に押し立てて魏軍を一度は退け、師纂・鄧忠の二将は「もとより孔明なお在り、我ら休せん」と汗を流して退いた。敵将鄧艾すら「蜀に諸葛瞻あり、よく父の志を継ぐ。二番、吾が一万余の人馬を殺す。今もし速やかに破らずんば、後かならず禍と為らん」と警戒した。\n\nだが瞻は「久しく守るは良図にあらず」と城を出て決戦を選び、これが鄧艾の伏兵に二度誘い出される敗着となった。「忽然として両下の伏兵殺し出で、蜀兵大敗」「四面の兵合し、瞻を垓心に困しむ」。演義はこの将を後の詩で「これ忠臣の独り謀少なきにあらず、蒼天意有りて炎劉を絶つ」と総括する——忠は満ちていたが、計略では完全に上回られた。\n\n鄧艾は使者を遣わし、降れば琅琊王に封じようと誘った。瞻は「読み畢わりて勃然として大いに怒り、その書を扯き碎き、武士を叱して来使を立ちどころに斬らしむ」。最後は「当に一死を以て国に報ゆべし」と自刎し、子の諸葛尚、尚書の張遵、黄崇、李球らも瞻に殉じて戦死した。「臣ら父子、先帝の厚恩、陛下の殊遇を蒙る」——その忠誠を綿竹の地で全うした。父ほどの智謀はなくとも、漢室に殉じた潔さにおいて、諸葛の名を辱めなかった将である。"}, {"id": 103, "name": "諸葛恪", "faction": 2, "role": "その他", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 3, 5, 4, 3], "p": [3, 2, 1, 3, 2, 3], "scores": {"W": 1.2, "B": 3.85, "S": 4.1, "A": 4.2, "G": 2.31, "K": 2.5}, "stat": {"dmg": 1.13, "area": 1.11, "cd": 1.11, "amount": 1, "knock": 0.82, "crit": 0.07, "duration": 3.5, "pwr": 4.15}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [98, 108, 113], "chapN": 3, "bio": "諸葛瑾の子、機知に富む幼少のエピソード・太子左輔", "profile": "呉の太傅。諸葛瑾の子であり、孫権の遺託を受けて幼帝を支えた重臣である。武勇の人ではなく、「字は元遜、身長七尺、極めて聡明にして応対を善くす」と評される知略と弁舌の才人。幼少より頓智で名を馳せ、驢馬に父の名を書かれてからかわれた席で機転を利かせた逸話など、その才覚は早くから知られていた。\n\n孫権の死に際し、「太傅諸葛恪、大司馬呂岱を召して榻前に至らしめ、後事を以て嘱す」——遺命を託された恪は、第百八回で孫亮を帝に立て、大赦を行い、大興元年と改元し、孫権に大皇帝の諡を奉って蔣陵に葬った。政権の枠組みを淀みなく執行する手腕は確かだった。続く東興防衛では、丁奉を先鋒として三路に接応する作戦を布き、「ただ連珠砲の響を聴かば、一斉に進兵せよ。吾みずから大兵を引きて後より至らん」と采配して、魏の三路軍を撃退してみせた。\n\nだが勝利は彼を驕らせた。蜀の姜維に使者を送って「平分天下」を約し、南北から魏を挟撃せんと二十万の大兵を起こして新城に攻め寄せる。白虹の凶兆も、諫言した蔣延を斬って退けた。ところが新城の張特の緩兵の計に欺かれ、矢傷を負い、軍中には病者が続出した。恪が「再び病を説く者は之を斬らん」と脅すと、「衆軍これを聞き知り、逃ぐる者数を無みす」。都督の蔡林は部軍を引いて魏へ寝返り、軍は心服どころか離反崩壊して、呉兵は大敗して帰った。\n\n帰朝後の恪は専権恣虐に走り、公卿を殺し、官僚は「内外こぞって悚懼せざるは無し」、孫亮すら「朕、此の人を見て、また甚だ恐怖す」と漏らした。「諸葛恪、専権恣虐、公卿を殺害し、まさに不臣の心あらんとす」と見なされた末、第百八回、孫峻の宴に招かれて、「大いに驚き、盃を地に擲ち、剣を抜いて之を迎えんと欲するも、頭すでに地に落つ」。剣を抜く間もなく斬られた。「家を保つの主にあらず」——孫権が案じた通り、一族もろとも誅滅された。聡明の才を恃みすぎ、警告のすべてを聞き流して身を滅ぼした、凋落の人である。"}, {"id": 104, "name": "董承", "faction": 3, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 1, 1, 2, 3, 3, 4], "p": [2, 5, 1, 3, 6, 2], "scores": {"W": 1.55, "B": 3.1, "S": 3.05, "A": 2.95, "G": 3.09, "K": 4.2}, "stat": {"dmg": 0.99, "area": 1.01, "cd": 1.09, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 3.25, "pwr": 3.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [2, 13, 14, 20, 21, 23, 24, 57, 69, 73], "chapN": 14, "bio": "献帝の外戚で衣帯詔の中心、曹操に一族皆殺しにされる車騎将軍", "profile": "後漢朝廷の車騎将軍。献帝の妃・董貴妃の兄にあたる国舅であり、衰えゆく漢室を支えようとした忠臣である。長安から脱出した献帝を東へ護送した救駕の功臣として、第十三回では楊奉とともに「両辺に死戦」して天子を守り、李傕・郭汜の劫駕の謀を察知すると、夜中に軍を布置して車駕を箕関へ奔らせた。\n\nその名を史上に刻んだのが衣帯詔である。第二十回、伏完の献策で、献帝は玉帯の裏に密詔を縫い込み、これを董承に密かに賜った。曹操を「殄滅して社稷を復安せん」とする血の誓いだった。董承は同志を糾合する。馬騰は詔を読んで「毛髪倒豎、歯を咬み脣を嚼み、満口に血を流」し、「公もし挙動あらば、吾すなわち西涼の兵を統べて外応と為らん」と誓った。皇叔劉備を夜陰に訪ねれば、「公すでに詔を奉じて賊を討つ、備あえて犬馬の労をなさざらんや」と応じ、義状に「左将軍劉備」と署名した。馬騰・劉備・王子服ら六人を集め、「共に十義を聚め、以て国賊を図らん」と、歃血して盟った。\n\nだが密謀は破れた。家奴の秦慶童が裏切って曹操に密告し、医者の吉平による毒殺の企ても露見する。第二十四回、衣帯詔の謀は曹操の知るところとなり、董承の一族七百余人がことごとく誅殺された。曹操をして「もし天の敗らずんば、吾すでに害を被らん」と言わしめた謀であったが、家奴一人すら御しきれなかった「事機の不密」が、すべてを台無しにした。\n\nその失敗は後の世まで反面教師として語られる。第六十六回、献帝は「昔、董承、事をなして密ならず、かえって大禍に遭う」と嘆き、第百九回でも曹芳が「武皇帝の董承を誅せしは、けだし機事の密ならざるが為なり」と引いている。忠義においては比類なく、漢室の大義名分を一身に体現した国舅だった。しかし秘事を守れなかった一点が、その忠を悲劇へと転じさせた。志は満点でありながら、保秘で破れた——衣帯詔の中心人物として、その名は永く惜しまれる。"}, {"id": 105, "name": "陳珪", "faction": 0, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 4, 5, 2], "p": [1, 3, 1, 4, 3, 5], "scores": {"W": 0.0, "B": 3.05, "S": 4.2, "A": 4.0, "G": 2.59, "K": 2.8}, "stat": {"dmg": 1.09, "area": 1.12, "cd": 1.18, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.75, "pwr": 3.85}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [16, 17, 18, 19, 21], "chapN": 5, "bio": "陳登の父、劉備に車冑の謀を知らせる", "profile": "徐州の老謀士。陳登の父として埋もれがちだが、その実態は呂布の陣営に潜り込み、内側から呂布を破滅へと導いた、智略一筋の老人である。武の記録は一切なく、「病を扶けて来たりて呂布に見ゆ」と描かれる病身の身でありながら、その頭脳は誰よりも冴えていた。\n\nその眼力が光ったのが第十六回、呂布と袁術の婚姻同盟だった。陳珪はこれを瞬時に見抜く——「これ乃ち『疏は親を間てざるの計』なり。玄徳危うし」。さらに呂布に説いた。「公もし之に応ぜば、これ奔命に疲れて、また人に怨みを結ぶ。もし其れ允さずんば、これ親を棄てて兵端を啓くなり。況んや聞く、袁術すでに称帝の意あり、これ造反なり。彼もし造反せば、則ち公は乃ち反賊の親属たり、天下の容れざる所と為る無からんや」。応じても拒んでも呂布が窮地に陥る構図を描き出し、同盟を解体してみせた。これが韓胤の処刑、袁術討伐の連鎖を生み、対呂布包囲の戦略を動かした。\n\n陳珪は子の陳登を曹操の内応者として送り込む策の背後にもいた。韓暹・楊奉を徐州に留めるべきと問う陳登に、「もし二人、呂布を協助せば、これかえって虎の為に爪牙を添うるなり」と隔離を指示し、敵戦力の増強を未然に防いだ。終始呂布を欺き続けたその工作は、陳宮に「面諛将軍、その心測るべからず」と疑われ、一時は弾劾されて捕縛されもしたが、計の歩みは止まらなかった。\n\n第十九回、呂布の敗勢を見るや「今、布まさに敗れんとす、すなわち之を図るべし」と決断し、糜竺と組んで城門を閉じ呂布を締め出す段取りを設計、徐州を劉備方へ取り戻す布石を完成させた。武器を一度も執ることなく、ただ言葉と謀だけで一人の猛将を滅ぼした老人——陳珪は、戦場の外で戦を決した智者の好例である。"}, {"id": 106, "name": "陳登", "faction": 0, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 6, 4, 2], "p": [2, 1, 2, 7, 5, 3], "scores": {"W": 0.0, "B": 3.8, "S": 4.1, "A": 4.2, "G": 3.06, "K": 2.85}, "stat": {"dmg": 1.12, "area": 1.14, "cd": 1.15, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.5, "pwr": 4.1}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [11, 12, 14, 16, 17, 19, 21, 22, 24, 78], "chapN": 10, "bio": "陳珪の子、劉備に袁紹への救援策を献じる謀士", "profile": "徐州を渡り歩いた文官・策士。陳珪の子で、字は元龍。陶謙から劉備、呂布、曹操、そしてふたたび劉備へと仕える先を変えながら、一貫して「吾は漢臣なり」を旗印に掲げ続けた、頭脳と弁舌の人である。白兵の記録は皆無で、むしろ第七十八回では「広陵太守陳登、心中煩懣し、面赤くして飲食する能わず」と病身に描かれ、名医華佗に虫を吐かされる病人として登場する。\n\nその真骨頂は謀略にある。第十九回、陳登は呂布を欺く三重の計を一人で完遂した。まず「徐州は四面に敵を受く、操かならず力攻せん、我まさに先ず退歩を思うべし。銭糧を下邳に移すべし」と説いて兵糧と妻小を分離させ、次いで蕭関で陳宮に偽情報を伝えて夜襲を誘い同士討ちさせ、「関上に就きて火を放ち起こし」て曹操軍を引き入れ、城を糜竺に守らせて呂布を締め出した。緻密に組み上げられた奇計だった。第十七回でも袁術の七路の兵を「正兵もて之を守り、奇兵を出して之に勝つ」の計で破っている。\n\n弁舌の外交もまた光る。第十七回、陳登は自ら使者となって韓暹・楊奉の陣に乗り込み、「某は大漢の公卿たり、何ぞ呂布の人と謂わんや。将軍のごときは、向に漢臣たりしに、今乃ち叛賊の臣と為る」と漢臣の名分を突いて、二将を寝返らせ袁術討伐の内応に成功させた。第二十二回でも鄭玄を介して袁紹の援軍を引き出すなど、相手を直に説き伏せる使者外交を幾度も設計している。第十六回には曹操に「呂布は豺狼なり、勇にして謀無し、去就に軽し、よろしく早く之を図るべし」と進言し、内応を約して東方経略の一翼を担い、曹操に「東方の事、すなわち以て相付せん」と任された。\n\n呂布からは「漢臣なり、いずくんぞ汝が反賊に事えんや」と城上から罵り、激怒した呂布に「吾かならず此の賊を殺さん」と憎まれた。最後は華佗の予言通り、その三年後に病で没する。武人ではなく、知略と名分と弁舌を武器に乱世を泳いだ策士——陳登の生涯は、戦わずして勢力の帰趨を動かした文官の見本である。"}, {"id": 107, "name": "凌統", "faction": 2, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [5, 4, 1, 3, 4, 2, 5], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 3.6, "B": 4.0, "S": 2.85, "A": 2.95, "G": 1.12, "K": 1.95}, "stat": {"dmg": 1.04, "area": 0.94, "cd": 0.95, "amount": 1, "knock": 0.82, "crit": 0.07, "duration": 0, "pwr": 3.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [38, 39, 44, 49, 50, 51, 53, 67, 68, 82], "chapN": 12, "bio": "呉の武将、第三隊・彝陵方面の伏兵を率いる", "profile": "呉の武将。槍を執り、孫権の盾となって死戦した忠勇の士である。江東の「良将」の一人に数えられ、承烈都尉に封ぜられた。名のある敵将を一騎打ちで討ち取る型ではないが、君主を守るためなら身を顧みず踏みとどまる、その決死の勇が凌統の本領だった。\n\nその勇名を不滅にしたのが、第六十七回の逍遥津である。張遼の二千騎に孫権が囲まれた窮地で、凌統は三百騎を率いて「翻身死戦」、身に数本の鎗を受けながら戦い抜いた。「凌統の領する所の三百余人、ことごとく殺し死せらる。統、身に数鎗を中り、殺して橋辺に到る」。自軍が全滅するまで踏みとどまり、「主公、何ぞ速やかに小師橋を渡らざる」と叫んで孫権を脱出させた。翌第六十八回でも、張遼と五十合、楽進と五十合をそれぞれ互角に渡り合っている。\n\n赤壁から烏林の敗走戦では、一隊を率いて火を合図に伏兵として襲いかかり、「凌統ここに在り」と名乗りを上げると、敗走中の曹操は「肝胆みな裂く」ほど慌てた。第五十一回の彝陵救援では周瑜の任を「十日を期と為す」と期限を切って代行し、後に漢陽郡を守るなど、一軍を委ねられる将才も備えていた。ただし計略や布陣を自ら設計するというより、与えられた任を堅実に果たす実行者だった。\n\n通説では甘寧との和解の物語で知られるが、これは父の仇という私讎を解いたもので、本文の凌統はあくまで戦場の人である。「虎将の才」の称号は甘寧に与えられたもので凌統のものではなく、武名を高々と称えられる立場ではなかった。それでも、自らの身を盾に主君を生かした逍遥津の死戦は、呉の武将の忠勇を語るとき必ず引かれる。名将を斬る派手な戦果より、君主のために命を投げ出す覚悟——そこに凌統の価値がある。"}, {"id": 108, "name": "張翼", "faction": 0, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 2, 1, 2, 4, 4, 5], "p": [2, 1, 1, 1, 3, 3], "scores": {"W": 2.2, "B": 4.05, "S": 4.0, "A": 3.85, "G": 1.72, "K": 2.85}, "stat": {"dmg": 0.88, "area": 0.9, "cd": 1.03, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.15}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [42, 64, 65, 71, 87, 89, 93, 99, 109, 110], "chapN": 38, "bio": "劉璋配下の将。劉瑰を斬って降伏、武陽人", "profile": "蜀漢の宿将。後期の蜀を支え、姜維の副将筆頭として最後まで戦い続けた武陽の人である。もとは劉璋配下の将だったが、第六十四回、城内で寝返って劉瑰を斬り、城門を開いて劉備方へ降った。「劉瑰を殺せし者は、乃ち武陽人張翼なり」——演義全編で張翼が自ら人を斬る描写は、実はこの内応の一撃がほぼ唯一である。\n\n以後の張翼は、趙雲の部将として、孔明の伏兵指揮官として、姜維の先鋒や後詰めとして、戦場を駆け回る。第九十九回では山谷の伏兵から「随後より掩殺し、魏兵大敗」と挟撃を成功させ、第百十回の洮西では夏侯霸とともに「魏兵の後に抄り、両路に分かれて殺し来たり、魏兵を垓心に囲」んだ。伏兵・挟撃・後詰めを堅実にこなす実行力ある中堅指揮官だった。一騎打ちの武勇では、第九十九回に孔明から張郃を相手に「汝は敵手にあらず」と評され、第百九回では徐質に「戦うこと数合ならずして、また敗れて陣に入る」と退いてもいる。武の英雄ではなかった。\n\nむしろ張翼の個性は、その抑制的な諫言にある。第百十回、姜維の出師に対して「蜀地は浅狭、銭糧は淺薄、遠征に宜しからず。険に拠りて分を守り、軍を恤れみ民を愛するに如かず、これ乃ち保国の計なり」と、国家の身の丈を見据えて反対した。勝利の後も「将軍の功績すでに成り、威声大いに震う、以て止むべし。今もし前進せば、もし意のごとくならずんば、まさに蛇足を画くがごときなり」と深追いを諫めている。第百十四回でも「兵を連ねて民に怨み有り、勝に乗じて人馬を収め民心を安んぜよ」と兵と民の負担を慮った。武辺よりも、国を持つ者の目で組織の暴走を抑えようとした諫臣型の将である。\n\nその忠誠は終生変わらなかった。劉璋を見限って漢室の側に身を投じてから、最後まで蜀漢に殉じ、第百十九回、「張翼らもまた乱軍の中に死す」。派手な武功はなく、独立した会戦を設計した実績も乏しい。だが伏兵戦を確実にこなし、姜維に従い、なお国の身の丈を諫め続けた——蜀の末期を支えた、信頼に足る方面将だった。"}, {"id": 109, "name": "孔融", "faction": 3, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 2, 2, 2], "p": [3, 5, 2, 3, 6, 3], "scores": {"W": 1.0, "B": 1.85, "S": 1.95, "A": 1.9, "G": 3.61, "K": 4.1}, "stat": {"dmg": 0.85, "area": 0.94, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 1.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [5, 11, 20, 22, 23, 40], "chapN": 6, "bio": "大中大夫、南征を諫め一族誅殺さる", "profile": "後漢朝廷の大中大夫。孔子二十世の孫にして建安七子の名士、譲梨の童子として後世に名高い文人である。だが演義に描かれる孔融は、武はまったくなく、正論を吐いては悉く退けられる悲劇の諫臣として終始する。「北海に居り、豪気長虹を貫く。坐上の客つねに満ち、樽中の酒空しからず。文章世俗を驚かし、談笑王公を侮る」——その風骨は称えられても、与えられたのは文人の徳であって武勇の称号ではなかった。\n\n北海太守だった頃、第十一回で黄巾の管亥に攻められると、孔融は部将の宗宝を出して迎え戦わせたが、「戦うこと数合ならずして、管亥の一刀に宗宝を馬下に砍られ」、本人は城へ逃げ込むほかなかった。「孔融、本部の人馬を出して賊と迎戦す」るも兵は乱れて潰走し、結局は太史慈と劉備の救援を待つよりなかった。劉備を動かすにあたっては「公は乃ち漢室の宗親なり、今曹操、百姓を残害し、強に倚りて弱を欺く、何ぞ融と同に往きて之を救わざる」と大義に訴え、「公、切に信を失う勿れ」と念を押している。\n\n許都に移ってからの孔融は、ひたすら道理で曹操を諫める人となる。官渡の前には「袁紹は勢大なり、与に戦うべからず、ただ与に和すべし」と説いて荀彧に論破され、楊彪が捕えられれば名分でこれを弁護した。第四十回、曹操が荊州征伐に乗り出すと、「劉備・劉表はみな漢室の宗親、軽々しく伐つべからず。今、丞相この無義の師を興さば、恐らくは天下の望を失わん」と諫めた。容れられず府を出た孔融は、天を仰いで嘆じた——「至不仁を以て至仁を伐つ、いずくんぞ敗れざるを得んや」。\n\nこの言が曹操の怒りを買い、孔融は廷尉に捕えられ、二子もろとも誅滅された。家にあって碁を打っていた幼い二子は、父の捕縛を聞いてなお動じず、「巣を覆すの下、いずくんぞ完き卵あらんや」と言い放ったという。この一語が、一族滅亡の象徴として語り継がれている。実権を伴わず、正論はついに一つも通らなかった。それでも漢朝の大義を最後まで代弁し、死をもって筋を通した名士——孔融の生涯は、滅びゆく漢室そのものの姿に重なる。"}, {"id": 110, "name": "沙摩柯", "faction": 3, "role": "武将", "rarity": 3, "weapon": "mace", "kind": "nova", "weaponName": "剛", "d": [4, 3, 5, 3, 2, 1, 3], "p": [1, 1, 1, 2, 1, 1], "scores": {"W": 3.95, "B": 2.35, "S": 1.55, "A": 1.65, "G": 1.15, "K": 1.4}, "stat": {"dmg": 1.11, "area": 1.09, "cd": 1.04, "amount": 1, "knock": 1.1, "crit": 0.07, "duration": 0, "pwr": 4.05}, "title": "剛の将", "skill": "剛", "skillDesc": "周囲を吹き飛ばす衝撃", "voice": "", "hist": "", "chapters": [82, 83, 84, 85, 86, 87, 89, 90], "chapN": 8, "bio": "五谿の蕃王。鉄蒺藜骨朵を使い甘寧を射殺するが周泰に討たれる", "profile": "五谿の蕃王。髪を振り乱し跣足で戦う異民族の兵、数万を率いる頭目として、劉備の夷陵出征に従い演義に現れる。第八十二回、蜀主みずから本国の大兵を率いて呉へ攻め下る際、その軍列に「蠻王沙摩柯番兵數萬」と名が連ねられる。指揮や計略を語る場面はほとんどなく、その存在感はすべて「異形の猛者」という一点に凝縮されている。\n\n第八十三回、彼の容貌が活写される。「面如噀血、碧眼突出」——顔は血を噴いたように赤黒く、青い目玉が眼窩から飛び出している。両手には鉄蒺藜骨朵という棘だらけの重い鈍器を握り、腰には弓を二張帯びる。「威風抖擻」と形容されるその姿は、まさに常人離れした膂力の持ち主であった。この回で彼は呉の宿将甘寧と相対する。甘寧はその勢いの大きさを見て交戦を避け、馬首を返して走った。だが逃げる甘寧の後頭部を、沙摩柯の放った一箭が貫く。名将甘寧を射倒したこの一矢こそ、彼の事績の核である。\n\nただし彼の武の物語はここで尽きてしまう。第八十四回、陸遜の試探に応じて山陰に伏し、淳于丹の進路を遮るが、これは蜀側が配した一駒にすぎない。その後、単騎で逃走する途中に呉将周泰と出くわし、二十余合戦った末に討ち取られた。弓の一射では名将を沈めても、白兵の斬り合いでは二十合で果てる——その落差が、彼の戦士としての輪郭をくっきりと残している。\n\n第八十五回、夷陵の戦死者の列に、その名が静かに連ねられた。指揮も統治も語られず、ただ甘寧討ちの一矢と、血の色の顔と碧の眼だけが記憶に焼き付く。物語の表舞台を駆け抜けた異族の王として、彼は短くも強烈な印象を演義に刻んだ。"}, {"id": 111, "name": "馬騰", "faction": 3, "role": "武将", "rarity": 3, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [2, 3, 2, 2, 3, 4, 4], "p": [2, 3, 1, 3, 6, 3], "scores": {"W": 2.2, "B": 3.25, "S": 3.65, "A": 3.45, "G": 2.81, "K": 3.95}, "stat": {"dmg": 0.88, "area": 0.95, "cd": 1.09, "amount": 1, "knock": 0.84, "crit": 0.06, "duration": 0, "pwr": 2.15}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [5, 10, 20, 21, 23, 24, 44, 48, 57, 58], "chapN": 14, "bio": "西涼の群雄、徐庶の流言と周瑜の四忌で曹操の後患として言及", "profile": "西涼に拠った群雄であり、後漢の伏波将軍馬援の後裔。征西将軍として一方を保ち、錦馬超の父としても知られる。「身長八尺、體貌雄異、稟性溫良、人多敬之」——背は高く風貌は雄々しく、しかも気性は温和で人に敬われた。その人物像は武勇よりもむしろ徳と人望で語られる。武人というより、漢室への忠義を体現する象徴として演義に配置された人物である。\n\n意外なことに、馬騰自身の白兵戦果はほとんど描かれない。第十回の討逆戦、馬騰・韓遂は勢いに乗じて追撃し大勝、隘口に迫って李蒙を斬首にかける。だがこの戦で実際に敵将を刺し、生け捕りにするのは一貫して子の馬超であり、馬騰は陣門で「背後に追手あり」と叫ぶ後方指揮の役回りだった。やがて賈詡の持久策にはまって兵糧が尽き、内応も漏れて西涼軍は撤退を余儀なくされる。彼の核心は「武」ではなく「忠」にあった。\n\nその忠が最も鮮烈に立ち上がるのが衣帯詔への参画である。第二十回、董承の密謀に加わった馬騰は酒を取り血をすすって盟い、「吾等誓死不負所約」と誓う。さらに豫州牧として身を寄せていた劉備を同盟に引き入れるよう推挙した。曹操を「賊」と断じ討たんとするその志は、周瑜が曹操の「一忌」に数え、曹操自身が「心中所憂者、韓遂・馬騰耳」と漏らし、諸葛亮が「操平生所慮者、乃西涼之兵也」と評するほど、天下の大局を揺るがす存在感となった。\n\n最期は楽観が仇となった。曹操の招きに、甥の馬岱は「曹操は心に叵測を懐く、叔父もし往かば必ず害される」と諫め、馬超も軽々しく入京するなと警告したが、馬騰は「諒んぞ敢えて我に害を加えんや」と赴いて誘殺される。曹洪・許褚・夏侯淵・徐晃に四方を囲まれ、奮戦むなしく次子馬鉄を失い、自らも捕らわれて処刑された。「我、国の為に賊を殺す能わず、是れ乃ち天なり」——その絶叫に漢臣の魂が宿る。後人は「父子齊芳烈、忠貞著一門」「嚼血盟言在、誅奸義狀存。西涼推世冑、不愧伏波孫」と詩に詠み、その一門の忠貞を称えた。長子馬超を西涼に残した配置は、やがて子の挙兵と曹操への報復へとつながっていく。"}, {"id": 112, "name": "韓遂", "faction": 3, "role": "武将", "rarity": 3, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [2, 2, 1, 3, 4, 4, 4], "p": [2, 3, 1, 3, 3, 2], "scores": {"W": 1.85, "B": 3.75, "S": 3.95, "A": 3.9, "G": 2.3, "K": 2.9}, "stat": {"dmg": 0.84, "area": 0.92, "cd": 1.08, "amount": 1, "knock": 0.82, "crit": 0.07, "duration": 0, "pwr": 1.8}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [10, 21, 23, 44, 48, 57, 58, 59, 120], "chapN": 9, "bio": "西涼の群雄、馬騰と共に許都を脅かすとの流言に使われる", "profile": "西涼の軍閥で、鎮西将軍。馬騰と義兄弟の契りを結び、反董卓・反曹の連合に名を連ねた方面の雄である。「初平中年、討賊有功を以て征西将軍に拝せられ、鎮西将軍韓遂と兄弟と為る」と語られるとおり、献帝の密詔を受けて討賊の大義を帯び、馬騰と並んで西涼に割拠した。第百二十回の総括詩でも「馬騰韓遂守西涼」と、群雄割拠の一角としてその名が刻まれている。\n\nもっとも、その地位の重さに比して、演義が描く韓遂の能動的な事績は乏しい。彼の存在はしばしば「曹操に警戒される名」として先行する。第四十四回で周瑜が「馬騰・韓遂は其の後患たり」と挙げ、第四十八回では曹操自身が南征の最中「心中所憂者、韓遂・馬騰耳」と漏らす。だが個人の武勇への畏怖ではなく、西涼方面軍を背後に抱える地政学的な脅威としての警戒だった。第二十一回、劉備が「張繡・張魯・韓遂らはいかに」と問うと、曹操は掌を打って大笑し「此等碌碌たる小人、何ぞ歯牙に挂くるに足らん」と一蹴している。\n\n戦場での彼は、むしろ救われる側として描かれる。第五十八回、曹操軍と渡河の機を争う潼関の戦いで、韓遂は「兵半渡して撃つべし」と兵法を引いて渡河中の曹操軍撃滅を献策し、馬超も「叔父の言、甚だ善し」と容れた。しかしこの一手で曹操を仕留めきれず、戦況は次第に不利へ傾く。やがて陥馬坑に落ちて「困在垓心」となり、龐德に歩行で救い出されるありさまだった。\n\n結末は痛ましい。賈詡の抹書反間計に踊らされ、楊秋ら諸将とともに盟友馬超を裏切ろうと図るが、機先を制された。第五十九回、馬超の一剣が韓遂の顔面めがけて斬りかかり、慌てて手で迎えた韓遂の左手は早くも斬り落とされる。残疾の身となった彼は、ついに曹操に降って西涼侯に封ぜられた。討賊の名分を帯びて起ちながら、盟を裏切って降る——その一貫しない去就に、老獪な軍閥の哀しさが滲む。"}, {"id": 113, "name": "楽進", "faction": 1, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [5, 4, 2, 3, 4, 2, 4], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 3.85, "B": 3.75, "S": 2.75, "A": 2.9, "G": 1.0, "K": 1.6}, "stat": {"dmg": 1.08, "area": 0.98, "cd": 0.96, "amount": 1, "knock": 0.89, "crit": 0.07, "duration": 0, "pwr": 3.75}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [6, 11, 12, 14, 16, 23, 24, 31, 33, 53], "chapN": 21, "bio": "曹操配下の将", "profile": "曹操旗下の宿将。第六回の董卓追撃という最初期から付き従い、許都奠定の際には李典・于禁・徐晃らとともに校尉に任じられた。多くは李典と並記され、「右軍」「埋伏第N隊」の列名要員として現れる地味な将だが、その勤続の厚さと弓の手練れは折り紙付きである。曹操は自軍を誇って「樂進・李典、勇は当たるべからず」と称えた。\n\nその弓と突撃の戦果は確かなものだ。第十二回、呂布配下の成廉を一箭で射殺し、第三十三回では并州攻めで郭図を射て城壕に陥れる。とりわけ鮮烈なのが第五十三回、合淝の戦いで「樂進一騎馬、一口刀、刺斜裏より逕ちに孫権を取る」——斜めから一騎で孫権めがけて斬りかかり、宋謙・賈華の画戟二本を断ち切った電光石火の突撃である。臧霸とは双鎗で三十余合、凌統とは五十余合と渡り合うが、いずれも引き分けに終わり、決定的な一騎打ちの勝利には恵まれなかった。\n\n合淝防衛で彼の真価が出る。第五十回、曹操は要地合淝の守りに張遼を主将、楽進と李典を副将として任じた。第六十七回、孫権来襲の際には曹操の密書で「樂将軍は城を守れ」と役を割り当てられ、本番では「不如堅守」と慎重論を述べた後、詐敗で甘寧を誘い込み、逍遙津で背後から追撃して呉兵を半減させる。作戦の主役は張遼だが、その計を確実に遂行するのが楽進の働きだった。一方で第六十八回、凌統と五十余合戦った末に顔面を一箭で射抜かれ、身を翻して落馬する負け場面も演義は隠さない。\n\n二面性も興味深い。第二十三回、曹操が彼を勇将と誇る同じ場面で、奇才禰衡は「樂進は状を取り詔を読ましむべし」——書類読みが関の山だと嘲っている。江南を震わせ小児の夜泣きまで止めたのは張遼の名であり、楽進は終始その副将であった。だが第六回から十面埋伏、合淝まで一隊を率い続けた忠勤は本物で、子の楽綝が「汝の父樂進、昔日魏国の大恩を受く」と魏への忠を継ぐ形で、その家の勤めは後代に残った。"}, {"id": 114, "name": "張紘", "faction": 2, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 3, 1], "p": [3, 4, 2, 6, 4, 6], "scores": {"W": 0.0, "B": 1.15, "S": 2.15, "A": 1.9, "G": 3.96, "K": 3.55}, "stat": {"dmg": 0.84, "area": 0.95, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.25, "pwr": 1.8}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [15, 29, 38, 44, 53, 61], "chapN": 6, "bio": "呉の文官、周瑜を訪ねる降伏派の一人", "profile": "呉の文官。張昭と並んで「二張」と称され、江東の開府を支えた参謀格である。武の事績は皆無で、その値打ちはすべて諌言・外交・国家構想という頭脳の働きにある。孫策・孫権の二代にわたって主君の身を案じ、危ういところを言葉で補正し続けた、典型的な江東の文臣であった。\n\n彼の真骨頂は主君への諌言にある。第五十三回、孫権が血気にはやって大敵を侮り、宋謙を失った直後、長史の張紘は「主公は盛壮の気を恃み、大敵を軽視す……願わくは賁育の勇を抑え、王霸の計を懐け」と諌めた。同じ将器論は孫策にも向けられている——「主将は三軍の命を繋ぐ所、軽々しく小寇を敵とすべからず」。君主の軽率を繰り返し戒め、その身を保たせようとする一貫した姿勢が、彼の人物像の芯をなす。\n\n外交でも確かな実績を残した。孫策の使者として許昌に赴いて戦捷を上表し、その重みゆえ曹操に留め置かれるほどだった。さらに第二十九回、孫策が急逝すると、曹操は喪に乗じて南征しようとする。これを張紘は「人の喪に乗じて伐つは義挙にあらず、もし克たずんば好を棄てて仇を成す」と説いて止め、かえって孫権を将軍・会稽太守に封じさせ、自らその印綬を携えて江東へ下った。武力を用いずに政権の正統な承認を取り次いだ手腕である。帰国後は張昭とともに政事を司り、人材を見る目も鋭く、顧雍を見出して孫権に推薦し、丞・行太守事として用いさせた。\n\n最期の建白が、呉の未来を決めた。第六十一回、臨終に際して張紘は上書し、秣陵の山川には帝王の気があるとして遷都を勧め、「以て万世の業と為せ」と説いた。孫権はこれを容れて即座に遷都を決め、後の建業——石頭城を築く礎が据えられた。一個の都城選定が国家の長い行く末を定める。武勲を一度も挙げぬまま、言葉と眼力で呉という国の輪郭を形づくった文人であった。"}, {"id": 115, "name": "鄧忠", "faction": 1, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [5, 4, 2, 2, 3, 1, 3], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 3.75, "B": 2.85, "S": 1.75, "A": 1.9, "G": 1.12, "K": 1.55}, "stat": {"dmg": 1.07, "area": 0.96, "cd": 0.99, "amount": 1, "knock": 0.84, "crit": 0.06, "duration": 0, "pwr": 3.65}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [111, 112, 113, 115, 117, 119], "chapN": 6, "bio": "鄧艾の子。父と共に蜀を攻め、最後は乱軍に死す", "profile": "魏の鄧艾の子。常に父の副将・先鋒として登場し、独立した名将像こそ薄いが、本文を読むと若き槍の使い手として鮮烈に描かれている。父子そろって蜀を攻め、最後は乱軍のなかに散る——その短い武人の生涯が、終盤の演義に悲劇の彩りを添える。\n\n最も光るのは第百十二回、姜維との一騎打ちである。「挺槍縱馬而出、年約二十餘歲、面如傅粉、脣似抹硃」——白粉を刷いたような顔に朱を抹したような唇の若武者が槍を構え、「鄧将軍を認むるか」と厲声で名乗りを上げた。姜維はこれを父の鄧艾と見誤ったほどだ。二人は精神を奮い立たせて三四十合を戦い、勝負はつかなかった。その槍法は「半点の放閒なし」と評される。さらに姜維が手綱に槍を掛けて雕弓に羽箭をつがえ、不意に射かけると、鄧忠は「眼乖」——目ざとくこれを見切り、身を前に倒して矢を躱した。名将姜維と互角に渡り合う若き武者ぶりである。\n\n戦場での彼は、父の計を黙々と実行する役回りが多い。第百十三回、地道奇襲で王含・蔣斌の左寨を内外から夾撃して破り、第百十七回には陰平越えの主役を担う。鄧艾はまず鄧忠に五千の精兵を率いさせ、甲冑を着けず斧や鑿を手に、険しい難所に至るたびに山を鑿ち橋を架けて道を開かせた。だが摩天嶺の西は峻壁絶崖、開削できず前の労が無に帰すと知り、鄧忠は兵もろとも泣き挫ける。それを「虎穴に入らずんば」と鼓舞して立たせたのは父鄧艾だった。父思いの一面もあり、鍾会と不和になりかけた父に「小不忍なれば則ち大謀を乱す」と忍耐を諫めている。\n\n結末は無残である。第百十九回、謀反の嫌疑をかけられた父とともに収監され、田続に斬られて乱軍のなかに死す。父の構想に従い、父の影として戦い、父とともに果てた——独立した名将にはなれずとも、姜維と互角に槍を交えたあの一場面が、鄧忠という若武者の確かな証として残る。"}, {"id": 116, "name": "馬岱", "faction": 0, "role": "武将", "rarity": 3, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [5, 4, 2, 2, 3, 2, 4], "p": [1, 1, 2, 1, 1, 3], "scores": {"W": 3.75, "B": 3.25, "S": 2.45, "A": 2.45, "G": 1.42, "K": 1.9}, "stat": {"dmg": 1.07, "area": 0.96, "cd": 0.98, "amount": 1, "knock": 0.84, "crit": 0.06, "duration": 0, "pwr": 3.65}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [57, 58, 59, 64, 65, 88, 90, 94, 100, 101], "chapN": 24, "bio": "馬騰の甥。馬超に従い曹操と戦う", "profile": "蜀漢の武将。馬騰の甥で、西涼一族の生き残りである。第五十七・五十八回、曹操に誘殺された馬騰一族のなかで唯一脱出を果たし、以後は従兄馬超に従って曹操と戦った。蜀漢に帰順してからは諸葛亮配下の信頼厚い分隊長として一貫し、火攻・伏兵・糧道遮断といった軍師の計を黙々と完遂する。その象徴は華々しい武勇の冠ではなく、命令を遂げきる実行力と揺るがぬ忠誠にあった。\n\n白兵の戦果は堅実である。第五十八回、西涼の前部先鋒として一万五千を率い、宝刀一口を揮って鍾繇と渡り合い、これを撃ち走らせた。第八十八回の南征では蛮将忙牙長と交鋒し、わずか一合で斬って落馬させる。同じ南征で祝融夫人や雅丹丞相を生け捕りにし、孟獲をも捕らえた。そして最大の一刀が第百五回——諸葛亮亡き後に反旗を翻した蜀の宿将魏延を、「手起刀落、魏延を馬下に斬る」。背後から名乗った「魏延を斬る者、乃ち馬岱なり」の一声に、衆は皆驚き慄いた。\n\nその武名は控えめに語られる。第八十八回、董荼那が孟獲に「馬岱は英雄、抵敵すること能わず」と評する一方、第六十五回では張飛に「早く帰れ、吾が対手にあらず」と一蹴され、孟獲には「量に此の小輩」と侮られもする。彼は決して無双の英雄ではない。諸葛亮の計を「受計して去る」役に徹し、第九十回の盤蛇谷では黒油車に「地雷」と名づけた火砲を仕込んで配置し、第九十四回には鉄車兵を破り、北伐では伏兵・劫寨を確実にこなした。自ら計略を立てる場面はほとんどなく、与えられた任務を寸分違わず遂げるのが彼の流儀だった。\n\nその忠実さが、最後に蜀の危機を救う。諸葛亮は臨終に際して馬岱に密計を授け、魏延が反逆の叫びを上げた瞬間に不意を突いて斬れと命じていた。第百五回、馬岱はこれを完遂し、魏延崩壊の混乱のなかでも「馬岱の領する三百人のみ動かず」と、その隊の結束を見せた。討逆の功により魏延の爵位を継いだ彼は、武勇の頂点に立つ将ではなく、最も信に値する刃として演義にその名を刻んだ。"}, {"id": 117, "name": "陳武", "faction": 2, "role": "武将", "rarity": 3, "weapon": "twin", "kind": "arc", "weaponName": "双", "d": [5, 3, 3, 2, 3, 1, 3], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 3.8, "B": 2.85, "S": 1.75, "A": 1.9, "G": 1.12, "K": 1.55}, "stat": {"dmg": 1.08, "area": 0.99, "cd": 0.99, "amount": 3, "knock": 0.91, "crit": 0.06, "duration": 0, "pwr": 3.8}, "title": "双の将", "skill": "双", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [15, 49, 50, 51, 55, 61, 67, 68, 113], "chapN": 9, "bio": "呉の武将、第四隊として火船を率い赤壁東から攻める", "profile": "呉の武将。字は子烈、「身長七尺、面黃睛赤、形容古怪」——背は七尺、顔は黄ばみ瞳は赤く、異相の持ち主であった。孫策に敬愛されて校尉に任じられ先鋒を務めた、江東の働き者である。後世「江東十二虎臣」の一人に数えられるが、演義での活躍は孫策に仕えた登場初期に集中し、以後は赤壁や濡須口の隊将として堅実に名を連ねる。\n\nその武の輝きは第十五回に凝縮されている。孫策に従って薛禮を攻めた際、陳武は「十数騎を引いて陣に突入し、斬首五十余顆」——わずかな騎兵で敵陣に斬り込み、五十余の首級を挙げた。同じ回で敵将張英を一鎗で刺殺し、薛禮は門を閉ざして出てこなかった。夜には短衣に刀を持ち、真っ先に城壁をよじ登って火を放つ。名のある敵将討ちと多数の斬殺を併せ持つ、勢いに満ちた猛将ぶりだった。\n\n以後の彼は、大戦の遂行役として働き続ける。第四十九回の赤壁では第四隊の領兵軍官として戦船三百隻を率いて東から火攻めに加わり、第六十八回の濡須口では一軍を引いて江岸を巡哨し出撃する。いずれも孫策・周瑜・孫権の作戦下にある一部隊長としての働きで、自ら会戦規模の計略を立てる場面はない。それでも与えられた持ち場を確実にこなす実直さが、彼の身上であった。\n\n最期は武勇の頂点ではなく、不運な戦死として描かれる。第六十八回、濡須口で龐德に追われた陳武は、袍の袖を木の株に引っ掛けて反撃できぬまま討たれてしまう。だが孫権は陳武の死を知り、董襲の入水死と併せて深く哀痛し、その亡骸を厚く葬った。骨肉の恩で報いられるほど信頼された忠勇の臣——派手な一騎打ちの栄光には縁が薄くとも、君主に心から惜しまれたその死に、陳武という武人の値打ちが滲んでいる。"}, {"id": 118, "name": "滿寵", "faction": 1, "role": "文官", "rarity": 3, "weapon": "fire", "kind": "zone", "weaponName": "火計", "d": [1, 1, 0, 1, 5, 3, 4], "p": [2, 2, 3, 6, 2, 5], "scores": {"W": 0.75, "B": 3.85, "S": 3.5, "A": 3.55, "G": 3.14, "K": 2.85}, "stat": {"dmg": 1.06, "area": 1.07, "cd": 1.1, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.25, "pwr": 3.6}, "title": "文官", "skill": "火計", "skillDesc": "地を焼く炎を放つ", "voice": "", "hist": "", "chapters": [10, 14, 20, 21, 23, 31, 32, 73, 74, 96], "chapN": 12, "bio": "曹操の従事、袁紹の動静を探って報告する", "profile": "魏の文官。曹操の従事として早くから仕え、敵情を探って報告する役から、許都令、対呉防衛の指揮まで広く担った。一騎打ちや武名とは無縁の、終始「謀る文官」である。禰衡には「滿寵は酒を飲み糟を食らわしむべし」と罵られる脇役扱いを受けるが、その実、弁舌・法務・参謀・夜襲指揮と多彩な実務をこなし、ここぞという局面で確かな能力を見せる人物だった。\n\nまず光るのが弁舌である。第十四回、滿寵は小卒に変装して敵営に潜り込み、「公の勇略は世に罕なり、何ぞ楊・韓の徒に屈身せん。曹将軍は当世の英雄、好賢礼士なるは天下の知る所なり」と説いて、楊奉配下の徐晃を曹操のもとへ降らせた。第七十三回には対呉の使者として孫権を訪れ、呉魏で挟撃して荊州を取る同盟を持ちかけている。使者として、説客として、言葉で局面を動かす腕は文官のなかでも際立つ。一方、第二十回では曹操の命を受け、袁術との通交を疑われた楊彪を按治する法吏の役も務めた。\n\n軍事でも実務家ぶりを発揮する。第百三回の合淝では「呉人は必ず我が遠来を軽んじ、未だ隄備せず、今夜虚に乗じて其の水寨を劫すべし、必ず全勝を得ん」と献策し、自ら張球と兵を分けて二更に湖口へ進発、一斉に喊声を上げて水寨へ斬り込んだ。呉兵は慌てて戦わずに逃げ、魏兵は大勝して凱旋する。作戦の立案から実行までを一手に担った、火攻・奇襲の成功である。\n\nそして危機管理。第七十四回、関羽の北上で樊城が水没寸前に陥り、曹仁が城を捨てて夜逃げしようとしたとき、滿寵はこれを止めた。「山水驟かに至るも豈に長存せんや、旬日ならずして自ら退くべし……今もし城を棄てて去らば、黄河以南は国家の有にあらず」。冷静に水の引き際を読み、樊城という方面の要衝を守らせたのである。曹仁をして「伯寧の教にあらずんば、幾ど大事を誤らん」と言わしめたこの一場面こそ、滿寵の判断力を最もよく物語る。罵られる脇役と見せて、肝心の場面で国の屋台骨を支えた、したたかな実務文官であった。"}, {"id": 119, "name": "孫資", "faction": 1, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 3, 5, 1], "p": [3, 6, 0, 0, 2, 7], "scores": {"W": 0.0, "B": 2.35, "S": 3.85, "A": 3.6, "G": 2.96, "K": 3.5}, "stat": {"dmg": 1.03, "area": 1.09, "cd": 1.2, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.75, "pwr": 3.4}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [96, 106], "chapN": 2, "bio": "尚書、対蜀持久策を献じる", "profile": "魏の文官。尚書から侍中・光禄大夫へと進んだ、御前で奏上する能吏である。武勇の描写は一切なく、演義での登場はわずか二場面。だがそのいずれもが国家の行方を左右する重い局面で、対蜀戦略の献策者として、また後継人事を握る権力中枢の調整者として、その頭脳の働きが際立つ。\n\n第九十六回、彼は対蜀の長期戦略を説く。天下の兵をことごとく起こして蜀を伐とうとすれば、東呉がまた入寇してくる——そう見抜いた孫資は、「現在の兵を以て、大将に命じて険要を拠守させ、精鋭を養い銳を蓄えよ」と守勢を進言した。さらに大局を読んで言う。「数年ならずして中国は日々盛んとなり、呉・蜀の二国は必ず自ら相残害す。その時に図らば、豈に勝算にあらずや」。全力での遠征より守って国力を養うこと、敵が自滅するのを待つこと——この読みを司馬懿は「孫尚書の言、極めて当たれり」と追認し、曹叡は国策として採用して遠征を取りやめた。\n\nもう一つの登場が、魏の命運を分ける第百六回である。曹叡の病が篤くなり、劉放とともに枢密院の一切の事務を任された孫資は、後継摂政体制の設計を主導する。臨終の曹叡が「宗族の内、何人か在るべき」と直々に諮ると、二人は曹真の子・曹爽を保奏して大将軍に据えた。そして天子の手詔を奉じ、燕王曹宇を国へ帰らせる詔を発出させる——「天子の手詔あり、燕王に命じて国に帰らしむ、即日就行を限る。詔なくんば入朝を許さず」。次代の最高権力者を実質的に選定し、朝廷の人事を一手に整えた。\n\nただしこの擁立には影がある。本文は二人が「久しく曹真の恵を得たり」と記しており、私恩に基づく人選であった。曹爽の擁立はやがて魏を傾け、司馬氏台頭への布石ともなっていく。武を一度も振るわず、御前の言葉だけで対蜀の国策を定め、次代の権力構造を組み上げた——孫資は、表に立たぬまま国家の枢機を握った、まさに陰の調整者であった。"}, {"id": 120, "name": "徐氏", "faction": 2, "role": "婦人", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 0, 2, 6, 1, 3], "p": [0, 2, 0, 1, 1, 7], "scores": {"W": 0.85, "B": 3.8, "S": 2.5, "A": 2.95, "G": 1.52, "K": 2.35}, "stat": {"dmg": 0.99, "area": 1.01, "cd": 1.1, "amount": 1, "knock": 0.7, "crit": 0.06, "duration": 2.75, "pwr": 3.05}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [38], "chapN": 1, "bio": "孫翊の妻、計略で夫の仇を討つ烈女", "profile": "呉の丹陽太守・孫翊の妻。後世「東呉の女丈夫」と詩に讃えられた烈女だが、その実像は刀槍を振るう勇婦ではなく、卜易に通じ、貞節を擬装した心理戦で夫の仇を討ち果たした謀略と段取りの人である。\n\n第三十八回。夫の孫翊は配下の媯覽・戴員らの手で殺され、家財を奪われ、徐氏自身まで媯覽に強占を迫られる。最大級の危地に置かれながら、彼女は取り乱さなかった。まず強占の求めを「詐許」して相手を安心させ、晦日まで猶予を稼ぐ。「亡き夫は常々あの二人を忠義の者と申しておりました」と、孫翊の旧将・孫高と傅嬰を密かに府内へ呼び寄せ、泣いて訴える。二人は「夫人の御命とあらば、敢えて力を尽くさぬことがありましょうや」と即座に命を賭す覚悟を示した。徐氏は彼らを密室の幃幕の陰に伏せ、自らは喪服を脱ぎ、沐浴して濃く化粧し、嫁ぐ女を完璧に演じて媯覽を酒に酔わせ、その密室へと誘い込む。喜んだ媯覽が酔って踏み入った刹那、徐氏が「孫、傅二将軍はいずこ」と一声大呼すると、二人が幃幕から刀を持って躍り出た。「媯覽措手不及」――抗う間もなく傅嬰の一刀に斬り倒され、孫高がもう一刀で討ち取る。続いて戴員も誅し、残党まで一掃した。\n\n詐許で時を稼ぎ、忠臣を集めて伏兵を仕込み、貞節と服従を演じて敵を無防備にし、合図一つで順に討たせる――小規模ながら設計と誘引が見事に噛み合った奇襲であった。事に先立ち「人を遣わして星夜に呉侯へ報知を」と孫権への急報も忘れていない。\n\n媯覽・戴員の首級は、孫翊の霊前に供えられた。自ら一太刀も振るわずして仇を雪いだ徐氏の鮮やかさは、極限の危機をその場で機会へ転じる対応力の冴えにあった。演義は彼女を、武勇ではなく才知と節義で讃え、「不及東呉女丈夫」と詩に留めている。"}, {"id": 121, "name": "越吉", "faction": 3, "role": "武将", "rarity": 3, "weapon": "mace", "kind": "nova", "weaponName": "剛", "d": [4, 3, 4, 3, 1, 1, 3], "p": [0, 0, 0, 0, 1, 0], "scores": {"W": 3.7, "B": 1.9, "S": 1.3, "A": 1.3, "G": 0.13, "K": 0.9}, "stat": {"dmg": 1.08, "area": 1.05, "cd": 1.05, "amount": 1, "knock": 1.03, "crit": 0.07, "duration": 0, "pwr": 3.75}, "title": "剛の将", "skill": "剛", "skillDesc": "周囲を吹き飛ばす衝撃", "voice": "", "hist": "", "chapters": [94], "chapN": 1, "bio": "西羌の元帥、鉄鎚の猛将・関興に斬られる", "profile": "西羌の元帥。羌王・徹里吉の下、十五万の羌兵と鉄車兵を率いて戦場に立った猛将である。鉄鎚を片手に挽き、宝雕弓を腰に懸け、馬を躍らせて勇を奮う威勢の将だが、その登場は第九十四回ただ一幕に限られる。\n\n魏の求援を受けた羌は、丞相・雅丹と越吉に十五万の兵を起こさせ、蜀へ攻め込ませた。陣頭に「躍馬奮勇而出」した越吉は、蜀軍に当たって初戦でこれを大いに破る。名将・関興を澗谷へと追い詰め、鉄鎚を打ちかかった。関興は咄嗟に身をかわしたが、鎚は馬の胯を直撃する。関興は「終に是れ胆寒し」、抵敵かなわず谷へと逃げ落ちた――名のある蜀将を肝を冷やさせるほどの勢いであった。\n\nだがこの猛勢こそ、孔明の引き立て役にすぎなかった。孔明は雪中に坑塹を掘り、疑兵で羌兵を誘う計を仕掛ける。越吉は「大いに怒り、兵を催して急追」し、まんまと罠へ突進。鉄車兵は大いに乱れ、自軍同士が踏み合って壊滅し、羌兵は四散して逃げ竄った。逃走する越吉に追いついたのは、先に辱められた関興である。両馬相交わること「只だ一合」、越吉は馬下に斬り殺された。\n\n豪勢な触れ込みと、あっけない最期。知略も統治の描写もなく、ただ羌の武を体する一将として現れ、孔明の計の前に崩れ、関興の手柄首として消えていった。"}, {"id": 122, "name": "衛瓘", "faction": 1, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 3, 2, 4], "p": [2, 3, 2, 1, 4, 6], "scores": {"W": 1.0, "B": 2.8, "S": 2.4, "A": 2.35, "G": 2.79, "K": 3.8}, "stat": {"dmg": 0.92, "area": 0.97, "cd": 1.13, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 2.45}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [116, 117, 118, 119], "chapN": 4, "bio": "監軍。鄧艾を捕縛し、鍾会姜維の乱を鎮め、田続に鄧艾を斬らせる", "profile": "魏の文官、監軍。蜀平定の最終局面で、司馬昭の意を体し、その手足となって動いた処理役である。白兵や武勇とは無縁だが、鄧艾父子の捕縛、鍾会の謀反鎮圧、鄧艾の誅殺、そして成都鎮守と、相次ぐ大混乱を収拾する実務において、その冷徹な手腕を発揮した。\n\n第百十八回、司馬昭は鍾会を司徒に封ずる一方、衛瓘に両路の軍馬を監督させ、手書を付して鍾会とともに鄧艾の動静を伺わせた。鄧艾を牽制する制衡の駒として、大局に組み込まれたのである。第百十九回、いざ鄧艾捕縛の段になると、衛瓘はまず檄文を二三十道も先に撒いた。「詔を奉じて艾を収む。其の余は各々問う所なし。早く帰来せば即ち爵賞を加え、敢えて出でざる者あらば三族を滅ぼさん」――こうして鄧艾配下を寝返らせ、檻車を備えて星夜に成都へ急行する。鶏鳴に乗じて数十人とともに突入し、「詔を奉じて鄧艾父子を収む」と大呼すると、鄧艾は大いに驚いて床から転げ落ち、衛瓘は武士に命じてこれを車上に縛らせた。一滴の血も流さぬ捕縛であった。\n\nやがて鍾会と姜維が乱を起こして倒れ、魏兵が混乱に陥ると、衛瓘は胡淵の謀に乗じて人馬を整え、丘建・胡烈を介して諸将を呼応させ、「衆軍各々営所に帰り、以て王命を待て」と号令して秩序を取り戻す。だがここで彼は冴えた危機管理を見せた。「艾を捉えたのは我だ。今もし生かしておけば、我に葬身の地なし」――鄧艾を恨む護軍・田続という最適の手駒を選び、五百兵で綿竹に追わせて確実に誅殺し、後顧の憂いを断ったのである。\n\n成都鎮守を委ねられたところで、衛瓘の演義での役回りは終わる。終始「奉詔」を盾とし、晋公の正統な権威を執行する者として動いた。彼自身が国家像を描くことはない。土壇場の混乱を片端から処理し、自らの身も守り抜いた、有能きわまる収拾役であった。"}, {"id": 123, "name": "献帝", "faction": 3, "role": "君主", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 2], "p": [1, 2, 0, 1, 8, 3], "scores": {"W": 0.0, "B": 0.65, "S": 0.8, "A": 0.6, "G": 2.17, "K": 3.8}, "stat": {"dmg": 0.7, "area": 0.84, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.65}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [13, 66, 80, 81, 82, 83, 85, 91, 105, 109], "chapN": 56, "bio": "後漢の皇帝。伏皇后を曹操に殺される", "profile": "後漢最後の皇帝。世に「悲劇の亡国の天子」と語り継がれる人物だが、演義の本文を逐語に追うと、彼の能動的な事績はほぼ皆無に等しい。九歳で董卓に擁立され、廃立の策文では「天子闇弱にして以て天下に君たるに足らず」と貶められて即位した、その出発からして器であった。\n\n李傕・郭汜の争いでは、車駕ごと賊たちに奪い合われる。洛陽への帰還の途上では「食を絶ち、晩に瓦屋の中に宿し」、野老の進める粟飯で飢えをしのぐありさまで、自らの食すら他人頼みであった。曹操に許都へ迎えられてからは「名は君に近しと雖も、実は吾が掌握の内に在り」と臣下に公言される傀儡となる。許田の田猟では帝の射た三矢がいずれも外れ、代わって兎を一箭で射抜くのは劉備であった。\n\n唯一の自発的抵抗が、衣帯詔である。曹操の専横に耐えかね、帝は自ら密詔を作り、指先を噛み破って血で書き、玉帯に縫い込ませて董承に託した。傀儡の身で示した最大の能動であった。だが計画は露見し、董承ら七百余人が誅され、懐妊五月の董貴妃までも母子ともに殺される。帝にできたのは、寵姫の死に「背に芒刺を負うが若し」と恐怖に耐えることだけであった。\n\n最後は曹丕の前に立たされる。受禅の場で華歆に龍袍を掴まれても「帝戦慄して答うる能わず」、玉璽を捧げて山陽公へと降った。「朕、不才と雖も、初め過悪なし。安んぞ忍びて祖宗の大業を等閑に棄てん」と泣訴するのみで、漢四百年の幕引きをただ見送るほかなかった。演義は彼を行為する主体としてではなく、董卓も曹操も曹丕も奪い合わずにはおれぬ「正統性という記号」として描いている。名分の格だけは限りなく高く、実権は終生ゼロのままであった。"}, {"id": 124, "name": "伊籍", "faction": 0, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 3, 2, 1], "p": [2, 6, 1, 6, 3, 5], "scores": {"W": 1.0, "B": 2.05, "S": 2.1, "A": 2.2, "G": 3.71, "K": 3.35}, "stat": {"dmg": 0.88, "area": 0.97, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 2.15}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [34, 40, 52, 63, 65, 67, 73, 76, 77, 80], "chapN": 10, "bio": "劉備配下の文官。馬良を推挙", "profile": "蜀漢の文官、字は機伯。元は荊州・劉表の客であったが、劉備に心を寄せ、危急のたびに身を挺してこれを救った荊州の義人である。武器を取る場面は終生なく、危機の通報者・人材の紹介者・対呉の使者という三つの顔で演義を生きた。\n\n劉備をはじめて救うのは第三十四回。蔡瑁が劉備を害そうと謀るのを探り知り、深夜ひそかに駆けつけて急を告げる。さらに襄陽の宴席でも、蔡瑁の罠を察するや「請う、更衣せん」と機転で席を立たせ、「ただ西門のみ走るべし。公よ宜しく急ぎ逃れよ」と二度目の危難から脱出させた。劉備という蜀の根幹を、続けて二度の死地から救い出したのである。\n\n人を繋ぐ働きも光る。第五十二回、伊籍は劉備に向かって「荊襄の馬氏兄弟五人、並びに才名あり。其の最も賢なる者、眉間に白毛あり、名は良、字は季常」と語り、「馬氏の五常、白眉最も良し」の諺を引いて馬良・馬謖の兄弟を推挙した。劉備はこれを容れて馬良を従事に登用し、伊籍はその副となる。蜀の重要な人材を確実に組織へ引き入れた一手であった。第四十回には、弔喪を名目に劉琮を誘い出して擒え荊州を奪う策を献じ、孔明にも「機伯の言、是なり」と是認されている。\n\n外交でも結果を出した。第六十七回、曹操の漢中進出という危局に際し、伊籍は自ら「某、往かんことを願う」と使者を志願。孫権のもとへ赴いて合淝攻撃を説き、孫権は実際に「之に従う」と挙兵を決した。曹操への対抗を呉に動かした、成功した単独の使者であった。\n\n最後は昭文博士という学者格の文官に列し、劉備に即位を勧める百官の末席に名を連ねる。剛勇の士ではない。だが見識を備え、節義に厚く、肝心の場面で必ず動く――劉備が荊州の地で得た、得難い良臣であった。"}, {"id": 125, "name": "鄂煥", "faction": 3, "role": "武将", "rarity": 3, "weapon": "halberd", "kind": "orbit", "weaponName": "戟", "d": [4, 3, 4, 2, 3, 1, 3], "p": [1, 1, 1, 2, 1, 2], "scores": {"W": 3.6, "B": 2.75, "S": 1.75, "A": 1.9, "G": 1.27, "K": 1.55}, "stat": {"dmg": 1.07, "area": 1.03, "cd": 1.03, "amount": 1, "knock": 0.98, "crit": 0.06, "duration": 0, "pwr": 3.65}, "title": "戟の将", "skill": "戟", "skillDesc": "周囲を旋回する刃で薙ぐ", "voice": "", "hist": "", "chapters": [87], "chapN": 1, "bio": "高定の部将。方天戟を使う。雍闓朱褒を刺し殺し降って牙将となる", "profile": "益州南方の反乱軍、高定配下の先鋒将。「身の丈九尺、面貌醜悪、一枝の方天戟を使い、万夫不当の勇あり」と豪傑然と紹介される巨漢である。だが触れ込みの勇名と実際の戦果には、大きな落差があった。\n\n第八十七回、南征の孔明軍と対峙した鄂煥は、魏延に当たって数合のうちに詐敗で釣り出され、あっさりと生け捕りにされてしまう。万夫不当の称号を、正面の一騎打ちで裏付けることはついぞなかった。\n\n彼の真の見せ場は、内なる謀略にあった。雍闓に異心ありと疑った高定に、鄂煥は計を献じる。「一席を設け、人をやって雍闓を請ぜしめよ。彼に異心なくば坦然と来り、来らずば必ず異心あり。我が主は其の前を攻め、某は寨後の小路に伏して之を候たば、闓擒うべし」――この策に従い、敗走する雍闓を伏兵で待ち受けると、「雍闓措手不及」、一戟に刺して馬下に倒し、その首を梟した。さらに朱褒が高定の詰問に「目瞪口呆」と狼狽するところへ、馬後から転じ出てこれをも刺殺している。\n\n孔明への帰順を勧めたのも鄂煥であった。「孔明は乃ち仁人なり、之に背くは不祥なり。我等の謀反作悪は皆な雍闓の故。如かず、闓を殺して以て孔明に投ぜんには」――この一言が高定陣営を蜀へ寝返らせる。功により孔明から牙将を授けられ、降将としてその身を全うした。豪傑の看板を背負いながら、対等の白兵では振るわず、不意打ちの内ゲバと帰順の判断で物語に名を残した一発屋の脇役である。"}, {"id": 126, "name": "陳群", "faction": 1, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 3, 3, 2], "p": [3, 1, 1, 1, 6, 6], "scores": {"W": 0.0, "B": 2.3, "S": 2.75, "A": 2.65, "G": 2.69, "K": 3.75}, "stat": {"dmg": 0.94, "area": 1.01, "cd": 1.19, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.25, "pwr": 2.6}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [58, 78, 79, 80, 91, 106], "chapN": 6, "bio": "治書侍御史。江南先取の策を献ず", "profile": "魏の文官、字は長文。史実では九品官人法を定めた制度家の代表格として名高いが、演義はその制度功績を一切描かない。本文の陳群は、献策の謀臣・名分づくりの実務官・二代に仕える託孤の重臣として登場する。\n\n智謀の見せ場は第五十八回。曹操に向かって、劉備と孫権を離間させる策を献じる。「今、劉備・孫権は唇歯を結ぶ。若し劉備、西川を取らんと欲せば、丞相は上将に命じて兵を提げ、合淝の衆を会して逕ちに江南を取らしむべし。然らば孫権は必ず救を劉備に求めん」――そして「若し江東を得ば、則ち荊州は一鼓にして平ぐべし。荊州既に平らげば、然る後に徐ろに西川を図らば、天下定まらん」と、江東から荊州、西川へと至る方面の順序まで示した。単発の作戦を超え、天下平定の見通しを含む大局構想であった。\n\n禅譲劇では名分の中核実務を担う。第七十八回には曹操に「殿下宜しく天に応じ人に順い、早く大位を正すべし」と即位を勧め、第七十九回では禅譲勧進の四十余人に名を連ね、第八十回ではついに魏が漢を継ぐ正統性を文書化する「禅国の詔」を自ら起草した。簒奪を堯舜の禅譲に擬する、その筆を執ったのである。\n\n魏の柱石としても重んじられた。第七十八回には曹操の臨終で後事を託される列に入り、第九十一回では死の床の曹丕が曹真・司馬懿と並べて指名する三人の託孤大臣の一人となり、「卿等三人、善く之を輔けよ」と幼主曹叡の補佐を遺託され、司空に就いた。もっとも第百六回では、司馬懿の用兵の意図を解しかねて問いただし、説明を受けて「陳群拝服す」と、智将の引き立て役に回る一幕もある。制度を作る顔は演義にはなく、献策と名分づくりに徹した、魏朝の実務の重臣であった。"}, {"id": 127, "name": "王允", "faction": 3, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 2, 2, 2], "p": [3, 7, 1, 3, 3, 4], "scores": {"W": 0.1, "B": 1.75, "S": 1.95, "A": 1.9, "G": 3.56, "K": 3.75}, "stat": {"dmg": 0.85, "area": 0.94, "cd": 1.2, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.0, "pwr": 1.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [3, 4, 8, 9, 10, 13, 120], "chapN": 7, "bio": "連環の計で董卓を誅した司徒", "profile": "後漢の司徒。連環の計をもって稀代の悪、董卓を誅した忠臣の智謀家として名高い。だがその智謀は貂蟬を介した離間と内応誅殺に集約され、いざ国を治め維持する段になると、半年と保たず破滅した――「謀を立てる人」であって「国を支える人」ではなかった、というのが演義の彫る像である。\n\n王允最大の見せ場が、第八回の連環計。董卓と呂布がともに好色の徒であると人物を見抜き、「先ず汝を呂布に許嫁し、後に董卓に献ぜん。汝、中に於いて便を取り、其の父子を間して反顔せしめ、布をして卓を殺さしめ、以て大悪を絶たん」と、養女・貂蟬を駒に父子を離間する。さらに官位への怨みを抱く李肅を見抜いて内応に用い、人を読み権力の構造を操る精度は演義屈指であった。董卓が宮門に誘い込まれ、呂布の戟が咽喉を直刺して果てたとき、漢室再興は目前に見えた。\n\nだが、ここから王允は崩れる。「卓の跋扈は皆な此の四人之を助く。今、大赦を天下に下すと雖も、独り此の四人を赦さず」と、李傕・郭汜ら董卓の残党への赦免を断固拒否。これがかえって彼らを反乱へと追い込んだ。賈詡の入れ知恵で結集した西涼兵への対応は呂布に丸投げし、頼みの呂布は家小を棄てて逃亡する。蔡邕を獄死させて人望をも失い、長安はあえなく陥落した。\n\n楼下に引き出された王允は、なお屈しなかった。「為に吾れ関東の諸公に謝せよ、努力して国家を以て念と為せ」と諸侯への遺言を託し、「逆賊、何ぞ必ずしも多言せん。我、王允、今日死あるのみ」と罵って斬られる。一族もろとも皆殺しとなった。漢室の大義名分を一身に背負い、身を以て国家に殉じた清節の士。だが一つの危機を解いた手で、自ら次の危機を作ってしまった人でもあった。"}, {"id": 128, "name": "董襲", "faction": 2, "role": "武将", "rarity": 3, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [3, 2, 3, 2, 4, 1, 5], "p": [1, 3, 1, 1, 1, 4], "scores": {"W": 2.7, "B": 3.6, "S": 2.2, "A": 2.35, "G": 1.76, "K": 2.65}, "stat": {"dmg": 0.95, "area": 0.98, "cd": 1.03, "amount": 1, "knock": 0.91, "crit": 0.06, "duration": 0, "pwr": 2.75}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [15, 38, 44, 49, 50, 53, 67, 68], "chapN": 8, "bio": "呉の武将、漢陽を取り漢川から曹寨を攻める", "profile": "呉の武将。身の丈八尺、面は方く口は闊い偉丈夫で、孫策に見出されて別部司馬に任じられた。一騎打ちで名将を討つ華々しさはなく、終始副将・脇役として働いたが、その本領は武勇よりもむしろ、死をもって職分を守り抜く忠節にあった。\n\n赤壁では火攻の一隊を担い、「董襲、三千兵を領して直ちに漢陽を取れ」と任を受け、潘璋とともに頭を分けて火を放ち喊声を上げた。江夏の戦いでは甘寧と並ぶ副将として艨艟の大索を断つ作戦に加わり、第五十三回には陸遜とともに、囲まれた太史慈を救い出している。第六十七回、危地に陥った孫権を船で迎えて渡したのも董襲であった。\n\n彼を不朽にしたのは、第六十八回の最期である。曹操四十万の来襲という国家的危機に際し、董襲は持ち場の大船を守って嵐に遭う。船が覆りかけ、兵たちが我先に脚艦へ飛び降りて逃げ命を図ると、董襲は剣を仗えて大喝した。「将は君命を受け、此に在りて賊を防ぐ。怎ぞ敢えて船を棄てて去らんや」――そう叫んで逃げようとする自軍の兵十余人を立ちどころに斬り、隊伍を保とうとした。だが風急にして船は覆り、董襲はついに江口の水中に没して死んだ。\n\n人を繋ぐ働きもあった。第十五回には賢士・虞翻を孫策に薦め、張昭とともにその招聘に赴いている。この縁がのちに名医・華佗を呼び寄せることになる。孫権は陳武と董襲をともに失ったことを知って哀痛きわまり、人を水中に潜らせてその屍を尋ね出させ、陳武と並べて厚く葬った。武功より、職分に殉じた忠の一字で演義に名を刻んだ将である。"}, {"id": 129, "name": "盧植", "faction": 3, "role": "武将", "rarity": 3, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [2, 2, 1, 2, 4, 3, 4], "p": [2, 2, 2, 1, 5, 4], "scores": {"W": 1.75, "B": 3.55, "S": 3.3, "A": 3.3, "G": 2.48, "K": 3.6}, "stat": {"dmg": 1.04, "area": 1.08, "cd": 1.08, "amount": 2, "knock": 0.77, "crit": 0.06, "duration": 7.6, "pwr": 3.45}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [1, 2, 3], "chapN": 3, "bio": "中郎将、劉備の師。黄巾討伐軍の将", "profile": "後漢の中郎将にして、劉備の師。黄巾討伐軍を率いた将でありながら、演義が前面に押し出すのは武人としての姿ではなく、賄賂を拒んで讒言され、董卓の暴挙に正面から諫言する、清廉な士大夫・諫臣としての像である。\n\n第一回、盧植は五万の官軍を率いて広宗に張角を包囲し、十五万の賊と対峙していた。慕って馳せ参じた弟子の劉備を帳前に留めて喜び、「我、今、賊を此に囲む。汝、本部の人馬を引き、我れ更に汝を助くるに千の官軍を以てせん。前みて潁川に去き消息を打探せよ」と、別働の連携を約す采配も見せる。賊を破滅寸前まで追い詰めながら、勝負未決のうちに、賄賂を求めた朝廷の使者に「軍糧なお欠く、安んぞ余銭ありて天使に奉承せん」と拒んだことが讒言を招き、檻車で護送される身となった。これを見た張飛が斬って救おうとし、関羽が嘆いたほど、彼は人に惜しまれる人望の士であった。\n\n盧植の本領が最も光るのは第三回、董卓が少帝の廃立を強行しようとした場面である。満座が口をつぐむなか、盧植ただ一人が立ち、太甲を廃した伊尹、昌邑王を廃した霍光の故事を引いて正面から論駁した。「今上は幼しと雖も、聡明仁智にして、並びに分毫の過失なし。公は乃ち外郡の刺史、素より国政に参与せず、又た伊・霍の大才なし。何ぞ強いて廃立の事を主とすべけんや」――董卓が怒って剣を抜き斬りかかろうとしたが、議郎・彭伯が「盧尚書は海内の人望なり。今、先んじて之を害さば、恐らくは天下震怖せん」と諫め、董卓もついに手を止めた。\n\n宮中の変では、甲冑を着け戈を持って閣下に立ち、何太后を劫かす段珪を「段珪逆賊、安んぞ敢えて太后を劫かさんや」と一喝して走らせ、太后を救っている。董卓が外兵として禁庭に入る危うさを早くに見抜き「之を止めて来らしむ勿かれ」と諫めた先見もあった。聞き入れられぬとなれば官を棄てて去る潔さも併せ持つ。武勲ではなく、正統を守る論と人望によって、乱世の幕開けに毅然と立った名臣であった。"}, {"id": 130, "name": "高順", "faction": 3, "role": "武将", "rarity": 3, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [4, 2, 1, 2, 4, 2, 4], "p": [1, 1, 1, 2, 1, 3], "scores": {"W": 2.65, "B": 3.6, "S": 2.7, "A": 2.8, "G": 1.39, "K": 1.9}, "stat": {"dmg": 1.07, "area": 1.08, "cd": 1.0, "amount": 2, "knock": 0.77, "crit": 0.06, "duration": 7.6, "pwr": 3.7}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [11, 12, 14, 15, 16, 17, 18, 19], "chapN": 8, "bio": "呂布配下の宿将、下邳で捕えられ斬られる", "profile": "呂布配下の宿将。侯成や張遼と肩を並べる主力の一人で、独立した一軍を任されるだけの信頼を主君から得ていた武将である。後世には精鋭部隊「陥陣営」を率いた忠臣として語り継がれるが、演義の物語の中で彼が背負うのは、もっと静かで重い役どころだった。\n\n戦場では確かな働きを見せる。第十八回、小沛攻めで一軍を率いた高順は、進み出てきた夏侯惇と槍を合わせ、四五十合を渡り合う。やがて支えきれず陣を退くものの、ひとたび味方が勢いに乗れば、夏侯惇が曹性を斬って馬を返したその背後から軍を率いて追い討ちをかけ、「麾軍齊上、曹軍大敗」と曹軍を打ち崩した。劉備を破って「得勝」を収め、呂布の大軍とともに小沛を圧した姿は、堅実な方面指揮官そのものだった。\n\nただし彼は最後まで自ら計を立てる人ではない。火攻も奇襲も布陣も、動くのは常に呂布や陳宮の指示の下であり、高順はそれを忠実に実行する役に徹した。袁術配下の紀霊と対面して約束の物資を催促する場面でも、交渉者というより使い走りの域を出ない。派手な見せ場の少ない、無口な働き手であった。\n\nその人となりが一点に凝縮されるのが、第十九回の最期である。下邳が落ち、西門で水に囲まれて逃げ場を失った高順は、張遼とともに曹兵に捕えられる。引き据えられた彼に曹操が「汝に何の言かある」と問うと、高順はただ一言、「不答」――黙したまま、弁明も命乞いもせず斬られた。命を乞うた呂布、言い訳を並べた宋憲らと対照を成すこの沈黙こそ、演義が高順という男に与えた唯一にして最大の人物像である。何も語らなかったがゆえに、かえって節操の人として記憶に残る将だ。"}, {"id": 131, "name": "董卓", "faction": 3, "role": "君主", "rarity": 3, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [2, 2, 3, 7, 2, 4, 3], "p": [1, 3, 1, 1, 2, 2], "scores": {"W": 2.75, "B": 2.8, "S": 3.55, "A": 3.55, "G": 1.65, "K": 2.25}, "stat": {"dmg": 0.96, "area": 1.08, "cd": 1.11, "amount": 1, "knock": 1.15, "crit": 0.12, "duration": 0, "pwr": 2.8}, "title": "君主", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [1, 2, 3, 4, 5, 6, 7, 8, 9, 13], "chapN": 27, "bio": "少帝を廃し献帝を立てた暴虐の権臣", "profile": "隴西臨洮の人、字は仲穎。河東太守から身を起こし、少帝を廃して献帝を立て、漢の都を意のままにした暴虐の権臣である。演義が彼に着せるのは「最強の暴君」の名だが、その実像は武人ではない。二十万の西涼軍と、呂布という最強の武力装置を握った――その権力構造そのものが董卓の強さであり、本人の腕はむしろ弱い。\n\n彼の登場はいつも武の場面で躓く。第一回、黄巾の張角に敗れて劉備ら三兄弟に救われ、第三回では丁原配下の呂布が「飛馬直殺過來」と突っ込んでくると「董卓慌走」、軍は大敗して三十里を退いた。第八回の鳳儀亭では、画戟を奪って呂布を追おうにも「卓肥胖趕不上(肥満で追いつけぬ)」始末。自ら誰かを白兵で斬る場面は、演義のどこにも無い。\n\n董卓の本領は別にある。少帝を廃し陳留王を立てる策文を李儒に読ませ、自らを伊尹・霍光になぞらえて簒奪を正当化する。相国となって剣履上殿の特権を握り、「公卿皆懼董卓、誰敢不到」と百官を恐怖で平伏させた。降卒の手足を斬り眼を抉り煮殺す宴に、居並ぶ官は「戰慄失箸」する。洛陽の富戸数千家を「反臣逆党」と称して財を奪い、「吾為天下計、豈惜小民哉(われ天下のために計る、豈に小民を惜しまんや)」と言い放って百姓数百万を長安へ強制移送し、溝壑に死なせた。治世ではなく、ただ恐怖と略奪だけの統治である。\n\nその破滅は自業自得だった。色欲に溺れて連環計の兆しを見過ごし、車が折れ馬が嘶く凶兆さえ吉と曲解して登朝する。頼みの呂布が車の後ろから「有詔討賊(賊を討つの詔あり)」と躍り出て、一戟がその咽喉を貫いた。後継の備えもなく一族は皆殺し、配下の李傕・郭汜は即座に逃げ散った。恐怖だけで束ねた天下は、束ねた本人もろとも、あっけなく瓦解したのである。"}, {"id": 132, "name": "司馬望", "faction": 1, "role": "武将", "rarity": 3, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 2, 0, 1, 5, 2, 3], "p": [1, 1, 1, 1, 2, 2], "scores": {"W": 1.4, "B": 3.55, "S": 2.8, "A": 3.0, "G": 1.25, "K": 1.85}, "stat": {"dmg": 0.78, "area": 0.84, "cd": 1.08, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 0, "pwr": 1.3}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [112, 113, 114, 115, 116, 119], "chapN": 6, "bio": "司馬昭の族兄、長城鎮守将軍。陣法で姜維と渡り合う。後に晋の司徒", "profile": "魏末の防衛型武将。司馬昭の族兄にあたり、長城鎮守将軍として国境を守った。武勇で名を馳せる将ではなく、その持ち味は陣法の知識と机上の知略にある「守りと智の将」だ。\n\n第百十二回、姜維の北伐を受けた長城戦が彼の登場の場である。出陣して「汝等無礼、数々上国を犯す。早く退かずんば、汝をして片甲も帰らざらしめん」と大声で啖呵を切るが、配下の王真・李鵬を討たれると、寨を棄てて城に籠もり門を閉ざすほかなかった。一騎打ちで誰かを斬った手柄は、彼の生涯に一つも無い。\n\n真価が輝くのは第百十三回だ。姜維が陣を変えて鄧艾を囲んだとき、司馬望は「吾、幼年に荊南に遊学し、かつて崔州平・石広元と友となり此の陣を講論せり」と語り、姜維の布いた陣を「長蛇捲地陣」と看破する。「その頭は西北にあり、ゆえに西北より撃たば自ら破れん」と読み切り、八陣の八十一変を誇って姜維と陣法を競い合い、鄧艾を救い出した。さらに黄皓を使う反間計を献じて姜維を退かせ、第百十五回の侯河の伏兵策にも同調する。蜀の「君臣不和、必ず内変あらん」と見抜く目もあった。ただし軍を動かす主は終始鄧艾であり、司馬望はその副将格として陣法と一計を添える立場にとどまる。\n\n最後は政治的栄達で締めくくられる。第百十九回、司馬炎が晋王の位に即くと、司馬望は司徒――三公の一に列せられた。継承を主導したのは何曾らで、彼自身は新体制の秩序の一角に名を連ねる受益者だったが、武で散らず文官として栄える締め方は、智の将らしい幕引きであった。"}, {"id": 133, "name": "闞沢", "faction": 2, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 1, 2, 1], "p": [1, 7, 1, 8, 1, 4], "scores": {"W": 0.1, "B": 1.05, "S": 1.6, "A": 1.5, "G": 3.61, "K": 2.65}, "stat": {"dmg": 0.79, "area": 0.91, "cd": 1.23, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.0, "pwr": 1.45}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [38, 46, 47, 49, 66, 83], "chapN": 6, "bio": "呉の参謀、黄蓋の詐降書を曹操に届ける弁士", "profile": "呉の参謀。武器を取って戦う将ではなく、弁舌と胆力、そして人を見抜く眼を武器とする純度の高い文官である。通説では「赤壁の詐降書を命がけで届けた弁士」として知られるが、本文を読めば、その肝の据わりようと鑑識眼は使者の一言では収まらない。\n\n最大の見せ場は第四十七回、赤壁の前夜だ。黄蓋の苦肉計を見抜いたうえで、闞沢は自ら詐降書を曹操の水寨へ届ける役を志願する。だが曹操は書を読むなり「降参の日時が書かれていない」と疑い、左右に引き据えさせて斬れと命じた。絶体絶命のその場で、闞沢は顔色一つ変えず天を仰いで大笑し、「『背主作竊、不可定期(主に背き竊を作すは、期を定むべからず)』と聞かざるか。今もし日を約さば、いざ手を下せぬ時にこちらが迎えに出て、事は必ず漏れる」と理を説いて、逆に曹操を屈服させ謝罪させた。敵の総帥を弁舌一つで欺き、火計の勝利の伏線を引いたのである。\n\nもう一つの顔は、人材を見抜く推挙者としての姿だ。第八十三回、夷陵で劉備の大軍が境を侵し、孫権が「大いに驚き、挙止を失措」して狼狽したとき、闞沢は班から進み出て「擎天の柱(天を支える柱)あり、如何ぞ用いざる」と叫ぶ。張昭・顧雍・歩騭ら群臣がこぞって反対する中、無名に近い陸遜を「名は儒生なりと雖も、実に雄才大略あり、周郎の下にあらず」と見抜き、「もし失あらば臣も同罪を願う」と一族の命を賭してまで大都督に推挙した。さらに築壇・假節鉞の正式な手順まで進言し、狼狽する呉の指揮体制を立て直す。この一度の推挙が、夷陵の大勝と呉の存亡を分けた。\n\n武の手柄は一つも無いが、命を賭けた弁論と、国運を変えた一人の推挙――その二つだけで、闞沢は三国の文臣の中でも忘れ難い輝きを放つ。胆と眼の人であった。"}, {"id": 134, "name": "孟達", "faction": 1, "role": "武将", "rarity": 3, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [2, 2, 1, 3, 3, 4, 2], "p": [1, 3, 2, 4, 1, 3], "scores": {"W": 1.85, "B": 2.8, "S": 3.5, "A": 3.45, "G": 2.27, "K": 1.9}, "stat": {"dmg": 0.84, "area": 0.92, "cd": 1.11, "amount": 1, "knock": 0.82, "crit": 0.07, "duration": 0, "pwr": 1.8}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [60, 62, 65, 70, 71, 72, 76, 77, 79, 85], "chapN": 15, "bio": "益州の士。法正の同郷。劉備を迎える使者となる", "profile": "益州の士。法正の同郷であり、もとは劉璋に仕えた。蜀漢から魏へ、そして再び叛こうとして滅ぶ――三国志に幾人もいる「反覆の臣」の典型である。武人の称号を帯びてはいるが、その真価は白兵ではなく、弁舌と保身の計略にあった。\n\n戦場での実力は二流にとどまる。第七十九回、劉封との一騎打ちでは「戦不三合、達敗走(三合と戦わず敗走)」、第七十回の葭萌関では張郃に「大敗而回」、第七十二回の曹彰戦も馬超の援護に乗っただけで自力の手柄は無い。むしろ彼が冴えるのは口先のほうだ。第七十六回、関羽が麦城で救援を求めたとき、孟達は利害を説いて劉封に出兵を断念させる。第七十九回には曹丕への降表で「殿下まさに伊呂の業を建て、桓文の功を追わんとす」と大義を飾り立て、巧みに身の置きどころを切り替えてみせた。\n\nだが、彼の計略はいつも詰めが甘い。第九十四回、魏で居場所を失い「日夜不安」となった孟達は、金城・新城・上庸の三郡の兵を起こして洛陽を突き、北伐する孔明に呼応して「両京大定せん」と壮大な再叛を企てる。しかし約した申耽・申儀の偽りの同調を見抜けず、心腹の李輔や外甥の鄧賢にまで内通された。孔明は早くから「達は司馬懿の対手にあらず、必ず擒にせらる」と見切っており、その言葉どおり司馬懿の急襲に対応できぬまま、申耽の一槍に刺し殺される。残る軍は「余軍皆降」とあっけなく降伏した。\n\n最期まで彼は機密を保てず、すべてが後手に回った。孔明はその死を「孟達、事を作すこと密ならず、死は固より当然なり」と評した。二人の主君を裏切り、名分を捨て、利と保身に賭け続けた末の、見透かされた破滅であった。"}, {"id": 135, "name": "曹洪", "faction": 1, "role": "武将", "rarity": 3, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [5, 4, 1, 1, 2, 1, 3], "p": [1, 1, 1, 1, 1, 4], "scores": {"W": 3.4, "B": 2.35, "S": 1.45, "A": 1.45, "G": 1.36, "K": 1.85}, "stat": {"dmg": 1.02, "area": 0.9, "cd": 1.0, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 3.25}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [5, 12, 14, 30, 31, 40, 41, 51, 58, 69], "chapN": 28, "bio": "曹操の族弟、水陸接応使。趙雲の名を問う", "profile": "曹操の族弟。水陸の接応使として戦場と宮中の両方を駆け、主君の身辺を守り続けた宗族の実働者である。後世には「曹操の命を二度救った忠勇の将」と称えられるが、本文を逐語に追えば、武の人というより「曹操のために身体を張る族弟」の像が立ち上がる。\n\n白兵の手柄は確かにある。第十二回では何曼を相手に詐り敗走し、追ってきたところを拖刀の背砍計――身を反して一刀を浴びせる技で斬り殺した。第六十九回には任夔と交鋒三合でこれを馬下に斬り、勢いに乗って掩殺している。第五十八回の潼関では、馬超を相手に「四五十合」を支え、曹操に「吾もし曹洪を殺さば、今日必ず馬超の手に死せん」と言わしめた命の恩人でもあった。「二人兵馬嫺熟、武芸精通」と評されるその腕は、確かに中堅級である。\n\n一方で、采配の場面では負の記録が目立つ。同じ潼関で、徐晃の「丞相の大軍を待たば必ず主画あらん」という諫めを退け、馬超の挑発に乗って関を出撃。伏兵にかかって兵の大半を失い、関を失陥して曹操に斬られかけ、服罪した。第七十回では味方の張郃が救援を乞うても「汝、吾が言を聴かず、強いて進兵し、緊要の隘口を失う」と私情で突き放し、郭淮に「三軍は得易く、一将は求め難し」と諫められてようやく思いとどまる。新野でも南郡でも、彼の率いた前隊はしばしば焼かれ敗れた。\n\nそれでも曹操の信任は篤かった。第七十八回、曹操の臨終には陳群・賈詡・司馬懿と並んで枕頭に召され、後事を託される一人となる。第八十回の禅譲では、剣を帯びて殿に入り帝を出させ、玉璽を索める実力部隊役を担った。政権移行という最大の局面で、論ではなく実力で継承を成立させた――。弁も計も派手ではないが、ここぞの場で身体を張り通したことこそ、この族弟の本領であった。"}, {"id": 136, "name": "木鹿大王", "faction": 3, "role": "武将", "rarity": 3, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [2, 3, 3, 5, 4, 1, 4], "p": [1, 2, 1, 2, 2, 1], "scores": {"W": 2.75, "B": 3.4, "S": 2.25, "A": 2.6, "G": 1.48, "K": 2.1}, "stat": {"dmg": 1.0, "area": 1.08, "cd": 1.08, "amount": 2, "knock": 1.06, "crit": 0.1, "duration": 7.6, "pwr": 3.15}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [90], "chapN": 1, "bio": "八納洞の洞主。象に乗り法術で猛獣を操るが孔明の偽獣に敗れ乱軍中に死す", "profile": "南蛮・八納洞の洞主。白象に騎り、呪術で猛獣を操る異形の蛮王として、第九十回ただ一度の登場で強烈な印象を残す。孟獲の救援要請に応じて出陣した、孔明の南征における最も奇怪な敵である。\n\nその登場の威容は凄まじい。腰に二振りの宝刀を挂け、金珠瓔絡を身にまとい、白象に騎って大旗の中から現れる。手にした蒂鐘を振り、口に呪文を念じると、にわかに狂風が起こって飛砂走石、画角の一声とともに虎豹豺狼・猛獣毒蛇が風に乗って躍り出た。歴戦の趙雲と魏延さえ「我ら上陣すること一生、未だ嘗て此くの如き人物を見ず」と沈吟し、蜀兵は総崩れになって三江の界路まで追い立てられた。配下には鉄甲を着けた三万の「神兵」を擁し、「蜀兵百万に敵するに足る」と豪語する。\n\nだが、その強さの正体は呪術一点突破であった。諸葛亮はあらかじめ、火と煙を仕込んだ木製の巨獣を用意していた。木鹿大王の呼んだ本物の猛獣たちは、口から火炎を吐く偽の巨獣に怯えて逆に蛮陣へ逃げ込み、彼の呪術はそっくり逆用される。「自ら無敵と謂う」慢心の蛮王は、頼みの一芸を破られた瞬間に為す術を失い、乱軍の中であえなく討死した。\n\n主が倒れると、八納洞の孟獲一党は宮闕を棄て、山を越え嶺を越えて逃げ散る。後事を託す相手も、立て直す備えもなかった。猛獣使いの恐ろしさと、それを支えにした者の脆さ――その両方を一回の登場で見せ切った、忘れ難い異形の敵である。"}, {"id": 137, "name": "黄権", "faction": 0, "role": "文官", "rarity": 3, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 3, 4, 3], "p": [2, 2, 1, 5, 4, 4], "scores": {"W": 1.0, "B": 2.85, "S": 3.5, "A": 3.3, "G": 2.77, "K": 3.1}, "stat": {"dmg": 1.02, "area": 1.05, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.5, "pwr": 3.25}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [60, 62, 64, 65, 80, 81, 82, 83, 84, 85], "chapN": 10, "bio": "劉璋府下主簿。劉備招請に強く反対し門歯を折る", "profile": "もと劉璋府下の主簿。のちに蜀帝・劉備の参謀となった文臣である。後世には夷陵の後に魏へ降ったことで「節を全うできなかった惜しい忠臣」と語られがちだが、演義の本文で描かれる黄権は、終始一貫して「先見の明」と「忠節」の二本柱で立つ、諫言の人であった。\n\nその忠節が血で示されるのが第六十回だ。劉璋が劉備を益州へ招き入れようとしたとき、黄権は「主公此に去かば、必ず劉備に害せられん」と必死に諫める。叩首して血を流し、進み出て口に劉璋の衣を啣えて引き止めようとし、劉璋が怒って衣を扯いて立ち上がってもなお放さず、ついに門歯を二本まで落とした。身を捨てて主を諫めるその姿は、忠臣の鑑である。\n\n外交と先見の眼も鋭い。第六十四回、張魯のもとへ使者として赴いた黄権は、「東西両川は実に脣歯為り。西川もし破れなば、東川も亦た保ち難し」と地政学の理を説き、二十州の割譲を約して援軍を引き出してみせた。第八十四回の夷陵では、「水軍沿江して下らば、進むは易く、退くは難し。臣願わくは前駆と為らん、陛下宜しく後陣に在るべし」と進軍の危険を見抜いて諫める。だがこの献策は容れられなかった。\n\n劉備は彼に江北の兵を督させ魏寇に備えさせたが、夷陵の敗戦で陸遜に退路を断たれ、黄権は蜀へ帰る路も呉へ降る道も失う。やむなく魏へ身を投じた彼は、曹丕の前で泣いて「臣、蜀帝の恩を受くること殊遇甚だ厚し……帰蜀に路無く、降呉も不可なり」と訴えた。家族が誅されたという噂にも、なお主君を信じて疑わなかったという。劉璋には死を賭して諫め、蜀帝とは推誠相信で結ばれながら、最後は別朝に仕える矛盾を後人の詩に責められる――その引き裂かれた身の上こそ、忠と運命の狭間に立った文臣の哀しさを伝えている。"}, {"id": 138, "name": "楊鋒", "faction": 3, "role": "武将", "rarity": 3, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [2, 2, 2, 3, 4, 2, 4], "p": [1, 2, 1, 2, 2, 2], "scores": {"W": 2.1, "B": 3.45, "S": 2.75, "A": 2.9, "G": 1.6, "K": 2.25}, "stat": {"dmg": 1.02, "area": 1.08, "cd": 1.08, "amount": 2, "knock": 0.89, "crit": 0.07, "duration": 7.6, "pwr": 3.3}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [89, 90], "chapN": 2, "bio": "銀冶洞二十一洞主。五子と共に孟獲を捕らえて孔明に献じる", "profile": "南蛮・銀冶洞の二十一洞主。第八十九回・第九十回に登場し、孟獲とその弟・孟優を捕えて孔明に献じた蛮族の長である。一場面の脇役だが、その実像は白兵で戦う武人ではなく、宴席を罠に変える「謀略と寝返り」の人であった。\n\n三万の兵を率いて援軍と称し孟獲の陣へ現れた楊鋒は、まず「吾に精兵三万あり、皆鉄甲を披る。能く山を飛び嶺を越え、以て蜀兵百万に敵するに足る」と威を示し、五人の子を率いて拝礼させる。子らは「彪躯虎体、威風抖擻」と精悍そのものだった。だが、これはすべて段取りである。「軍中に楽少なし、吾に蛮姑あり、善く刀牌を舞いて以て一笑を助けん」と余興を申し出て、刀と盾を持つ蛮姑を帳上に配し、二人の子に盃を運ばせる。孟獲と孟優が盃を受けて飲もうとしたその隙に、楊鋒が大喝一声――子らはたちまち二人を座から引きずり下ろし、逃げようとした朵思大王までその場で生け捕った。刀牌の蛮姑は帳の上を横に塞ぎ、「誰敢近前(誰も近づけぬ)」と一瞬で場を制圧する見事な手際だった。\n\nその動機は恩義にある。捕えた者たちを孔明の前に引き据え、楊鋒は「某等が子姪、皆な丞相の恩徳を感ず、ゆえに孟獲・孟優らを擒えて呈献す」と述べた。かつて命を救われた諸葛亮への報恩――「今、汝反叛す、何ぞ擒え献ぜざらん」と、孟獲を反逆者と断じて自らを正義の側に置く名分も忘れない。会戦でも舌戦でもなく、一席の宴を舞台にした寝返りの妙だけで、彼は南征史に名を刻んだ。一族五子をひと声で動かす結束と、機を読む段取りの才――それが銀冶洞の洞主の持ち味であった。"}, {"id": 139, "name": "廖化", "faction": 0, "role": "武将", "rarity": 3, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [5, 3, 1, 2, 3, 3, 4], "p": [1, 1, 1, 1, 2, 3], "scores": {"W": 3.3, "B": 3.4, "S": 3.05, "A": 2.95, "G": 1.37, "K": 2.2}, "stat": {"dmg": 1.01, "area": 0.91, "cd": 0.98, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 3.2}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [27, 60, 73, 76, 97, 100, 102, 103, 109, 113], "chapN": 25, "bio": "西川出発時に降って関羽を補佐する", "profile": "蜀漢の生き字引というべき将。第二十七回、黄巾の余党として山に拠っていた頃に劉備に降り、関羽を補佐したのを皮切りに、第百十九回で蜀の滅亡を看取って憂死するまで、演義を最も長く生き抜いた一人である。個人無双の英雄ではなく、忠実・長命・実務遂行を核とする、頼れる働き手だ。\n\n白兵の手柄は地道に重ねている。初登場では無礼な杜遠を斬り、第百回では秦良を「一刀斬下於馬下」、第百十三回では鄭倫を「一刀、斬鄭倫於馬下」と、名のある敵を着実に討ち取った。圧巻は第百三回、五丈原で司馬懿を単騎で追い詰めた場面だ。慌てた司馬懿が樹を回って逃げるのを、廖化は「一刀砍去」――惜しくも刀は樹に食い込み、抜くうちに懿は林の外へ走り去ったが、あと一歩で敵の大将を斬る寸前まで迫った。長く生きたぶん、その名は誰もが知るところとなった。\n\n戦の采配では、自前の作戦を立てる司令官ではなく、主帥の計を忠実に遂行する駒であった。第七十三回では関羽の計を受けて詐敗の囮を務め、第百九回では伏兵で徐質を焼き討つ一翼を担う。晩年は姜維軍の先鋒筆頭として、「将は外に在り、君命に受けざる所あり」と的確な大局判断を述べ、連年の北伐に「軍民寧からず。兼ねて魏に鄧艾あり、智足り謀多し」と国力消耗を見据えた諫言も残した。助言は冴えていたが、それを将軍として形にする立場にはなかった。\n\n彼の本領は、何より裏切らぬ忠実さにある。第七十六回、関羽が麦城に囲まれたとき、重囲を突いて上庸へ救援を求める決死の使者に「某願往」と自ら名乗り出たのが廖化だった。諸葛亮は遺命にあたって彼を「忠諒死節の士、委用に堪う」と名指しし、後事を託せる将に数えている。離反の記録は一つも無い。蜀漢の興りから滅びまでをその目で見届け、最後は「託病不起、皆な憂死す」と、滅びゆく国とともに静かに世を去った。長く忠実に在り続けたこと――それこそが、この老将の何より雄弁な物語である。"}, {"id": 140, "name": "公孫瓚", "faction": 3, "role": "君主", "rarity": 2, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [2, 4, 1, 3, 4, 3, 2], "p": [2, 4, 3, 3, 3, 1], "scores": {"W": 2.25, "B": 3.1, "S": 3.15, "A": 3.3, "G": 2.74, "K": 2.55}, "stat": {"dmg": 0.78, "area": 0.94, "cd": 1.1, "amount": 1, "knock": 0.82, "crit": 0.07, "duration": 0, "pwr": 2.1}, "title": "君主", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [1, 2, 5, 6, 7, 11, 18, 21, 22, 28], "chapN": 11, "bio": "易京楼に拠るも袁紹に滅ぼされ妻子を殺して自縊する群雄", "profile": "幽州北平に拠った群雄。羌族との戦いで白馬ばかりを先鋒に揃えて「白馬将軍」の異名を取り、羌人は白馬の影を見るだけで逃げ散ったという。北辺の雄として一方に割拠した、漢末群雄の一人である。\n\nただし演義が描く公孫瓚は、勇名のわりに矛先が振るわない。第五回の汜水関では呂布と数合も戦わぬうちに敗走し、第七回では文醜に追われて弓矢を取り落とし、兜まで地に落として逃げる。彼の名が三国志の物語に刻まれた最大の場面は、皮肉にもその逃走の途中だ。文醜の槍が迫ったその時、一人の若武者が割って入って文醜と渡り合い、公孫瓚を救う。常山真定の趙雲、字は子龍。公孫瓚はこの天下の名将を陣中に得て大いに喜び、また旧知の劉備を朝廷に表薦して平原令に推すなど、人を見出す目だけは確かだった。だがその趙雲を心腹とせず後軍に置いて活かしきれず、やがて去られてしまう。\n\n人となりは、守りに入ると徹底して殻に閉じこもる質だった。袁紹に唆されて韓馥を攻める駒となり、漁夫の利を奪われる。趙雲には「忠君救民の心なし、袁紹らの輩に過ぎぬ」と早々に見限られていた。袁紹との戦いに利あらず、易京楼という高さ十丈の籠城塔を築き、三十万斛の粟を蓄えて引きこもる。包囲された配下が救援を求めても「一人を救えば、後の者は皆助けを当てにして死戦せぬ」と言い放ち、見殺しにした。結果、人心は離れ、袁紹が攻め寄せると配下は次々と降っていった。\n\n最期は第二十一回。地下道を掘られての火攻めに易京楼を破られ、逃げ場を失った公孫瓚は、まず自らの手で妻子を殺し、然る後に首をくくった。一族もろとも炎に焼かれて滅びる。後に物語は彼を「陶謙・張繡・公孫瓚、各々雄才を逞しくして一方を占む」と総括する。一方の主たりえた器量を持ちながら、守りの殻の中で自滅していった、滅びゆく群雄の典型として記憶される人物である。"}, {"id": 141, "name": "楊奉", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 2, 1, 2, 4, 3, 3], "p": [1, 2, 1, 3, 6, 3], "scores": {"W": 2.2, "B": 3.4, "S": 3.2, "A": 3.25, "G": 2.39, "K": 3.4}, "stat": {"dmg": 0.79, "area": 0.9, "cd": 1.05, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.15}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [13, 14, 17], "chapN": 3, "bio": "騎都尉、献帝を護送。後に袁術へ。劉備に斬られる", "profile": "後漢朝廷の騎都尉。李傕・郭汜が長安で天子を私する乱世にあって、李傕に背き、献帝を東へ護送した武将である。\n\n第十三回、楊奉は「大漢楊奉」と大書した一面の大旗を掲げ、千余騎を率いて駆けつける。郭汜の将・崔勇が「反賊楊奉」と罵ると、楊奉は陣中に向かって「公明はいずこにあるか」と呼ばわる。応じて大斧を提げた一将が躍り出て、崔勇を一刀のもとに斬り落とした。河東楊郡の徐晃、字は公明。楊奉の旗の下には、後に曹操の五子良将に列するこの猛将がいた。黄河を渡る難所では、馬の手綱を解いて天子の腰に結びつけ、船で対岸へ渡したという機転も見せる。帝はその功を深く嘉して「卿、朕の躬を救う、その功小さからず」と賜った。\n\nだが楊奉自身の将器は心もとない。李傕との戦いには勝てず、洛陽還都も董承が主導し、曹操が天子を奉じて頭角を現すと「曹操が大権を握れば我らを容れまい」と韓暹と謀って兵を退いた。曹操の伏兵にかかって完敗し、頼みの徐晃にも「楊奉・韓暹は事を立つる人にあらず」と見限られて去られる。董昭からは「無謀の輩」と評された。\n\n行き場を失った楊奉は袁術のもとへ身を寄せる。だが第十七回、陳登の書簡工作に乗って呂布の内応に転じ、袁術討伐に加わったあと、最後は劉備の謀によって騙し討ちにされ斬られた。天子を救った旗印の輝きと、それを支える将器の乏しさ。その落差のうちに生きて死んだ、乱世の忠臣武将である。"}, {"id": 142, "name": "袁尚", "faction": 3, "role": "君主", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [4, 3, 3, 2, 3, 2, 2], "p": [2, 2, 1, 1, 3, 2], "scores": {"W": 3.35, "B": 2.65, "S": 2.25, "A": 2.35, "G": 1.8, "K": 2.3}, "stat": {"dmg": 0.92, "area": 0.99, "cd": 1.04, "amount": 1, "knock": 0.91, "crit": 0.06, "duration": 0, "pwr": 3.35}, "title": "君主", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [30, 31, 32, 33, 106], "chapN": 5, "bio": "袁紹の三子、後継者、遼東で斬らる", "profile": "河北の雄・袁紹の三男。父の偏愛によって後継者に立てられた末子であり、長兄を差し置いて大司馬将軍となり、冀・青・幽・并の四州を領した。暗愚な敗者として語られがちだが、演義はこの若君に意外な武勇を与えている。\n\n第三十一回、官渡に敗れた袁紹の前で、袁尚は「父の前で腕を見せん」と双刀を振るって馬を駆り、敵陣を縦横に駆け回った。曹操の将・史渙が追ってくると、袁尚は弓に矢をつがえ、身をひるがえして背中越しに射放つ。矢は史渙の左目を射抜き、馬から転げ落ちて死んだ。この背射の一矢以来、袁尚は「自ら其の勇を負む」ようになる。\n\nしかしその自負が身を滅ぼした。第三十二回、兄たちの到着を待たず数万を率いて単独で討って出ると、張遼にわずか三合で打ち破られる。曹操の将略にはことごとく手を読まれ、西山の小路から夜襲をかける策も「もし西山の小路から来れば、一戦にして擒にできる」と先回りされ、漳水を引かれて冀州を落とされた。さらに兄・袁譚との骨肉の争いがあった。郭嘉の「長を廃して幼を立てた、兄弟必ず権を相併せん」という離間策にかかって袁氏は内から崩れ、呂曠・呂翔ら配下も次々と曹操に降っていく。父の死後、寵妾の一族を先んじて誅殺するなど猜疑も深かった。\n\n兄弟ともども敗れ、行き場を失った袁尚は遼東の公孫康のもとへ逃げ込む。「遼東の地を奪い、力を養って中原に抗し、河北を復さん」と大言を吐いたが、それは敗残の身の空論にすぎなかった。公孫康に「鳩が鵲の巣を奪う心」と見抜かれ、逆に首を斬られて曹操へ献じられる。河北四州の大を継ぎながら、偏愛が生んだ亡国の後継者として果てた。"}, {"id": 143, "name": "孫韶", "faction": 2, "role": "武将", "rarity": 2, "weapon": "bow", "kind": "proj", "weaponName": "弓", "d": [3, 4, 1, 3, 4, 2, 3], "p": [1, 1, 1, 1, 2, 1], "scores": {"W": 2.7, "B": 3.3, "S": 2.65, "A": 2.85, "G": 1.13, "K": 1.7}, "stat": {"dmg": 0.92, "area": 1.04, "cd": 1.05, "amount": 2, "knock": 0.82, "crit": 0.07, "duration": 0, "pwr": 3.35}, "title": "弓の将", "skill": "弓", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [7, 86, 102], "chapN": 3, "bio": "孫権の甥(元俞氏)。揚威将軍。軍令を犯すが曹丕軍を破る", "profile": "呉の揚威将軍。もとは兪氏の出だが、孫策に深く愛されて孫姓を賜り、孫氏の一族に列した。広陵の守りを務めた、血気盛んな若年の猛将である。\n\nその勇名が一度だけ大きく立つのが第八十六回。魏帝・曹丕が大軍を率いて南下したとき、呉の都督・徐盛は偽城と疑兵を立てる慎重策を取った。これに真っ向から反対したのが孫韶である。「往年、広陵に在って地理を深く知る。かの地で曹丕を迎え撃たねば、長江を渡られて東呉は危うい」と訴え、徐盛の軍令を再三犯して、本部三千の精兵を率い夜陰に乗じてひそかに渡江した。曹丕の竜舟が淮河に入ろうとしたその時、突如として鼓角が鳴り響き、喊声とともに孫韶の一軍が斜めから斬りかかる。魏兵は支えきれず大半を討ち取られ、溺死する者は数知れなかった。\n\nその気性は「年幼にして気を負い、極めて胆勇あり」と評される。命令違反をしてでも結果を出すたちで、軍規を乱したため孫権からは「今後は再び用いるな」と叱責されもした。だが孫権はこうも言った――「この子は本姓こそ兪氏なれど、我が兄(孫策)が甚だ愛し、孫姓を賜うた。我にも功績あり、今これを殺さば兄の義に背く」と。一族の情によって命を救われた、若き突撃の将である。第百二十回(原文では百二回)では呉蜀同盟下の出兵の将として名が挙がるが、その武名を物語に刻んだのは、ひとえに淮河の奇襲の一戦であった。"}, {"id": 144, "name": "劉表", "faction": 3, "role": "君主", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 3, 2, 4], "p": [2, 2, 5, 4, 6, 1], "scores": {"W": 1.1, "B": 2.85, "S": 2.45, "A": 2.45, "G": 3.24, "K": 3.45}, "stat": {"dmg": 0.83, "area": 0.97, "cd": 1.13, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 3.0, "pwr": 2.55}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [6, 7, 18, 23, 28, 31, 33, 34, 35, 39], "chapN": 35, "bio": "亡き荊州の主、劉備が墓前で慟哭する", "profile": "荊州九郡を領した群雄。漢室の宗親にして荊州刺史、兵強く糧足り、賢を礼して士を下す名門の大守として、乱世のなかでひときわ豊かな一州を治めた。劉備が頼って身を寄せ、その死に墓前で慟哭するほど、慕われもした主である。\n\nだがその豊かさとは裏腹に、演義の劉表像は終始「坐談の客」である。第六回、孫堅と矛を交えようとするが「方に交兵せんと欲して、劉表便ち退く」と、自らは戦わず伏兵に委ねる。孫堅を討つ妙計も腹心の蒯良の発案であり、劉表はそれを採るだけ。第十八回の安衆では張繡と組んで曹操を攻めるも、奇兵にあっさり大破され、賈詡の追撃策にも「疑慮して肯んぜず」と乗れなかった。曹操の軍師・郭嘉は「劉表は坐談の客のみ。自ら才の劉備を御するに足らざるを知る」と断じ、彼を遠征の障害にすら数えなかった。\n\nその人となりを、去りゆく徐庶は鋭く言い当てる――「善を善とすれど用うる能わず、悪を悪とすれど去る能わざる者なり」。劉備が許昌の空虚を衝く好機を進言しても「我、坐して荊州に拠るに足る、豈に別図すべけんや」と天下構想を自ら放棄した。甘寧もまた「劉表に遠慮なし、その子また愚劣」と評している。軍権は後妻・蔡氏の一族に握られ、自身は何ごとも決めかねた。\n\n最大の崩壊は後継問題に表れる。「長を廃して幼を立てんとすれば礼法に礙り、長子を立てんとすれば蔡氏が皆軍務を掌り後に必ず乱を生ぜん。因りて委ね決すること下らず」――劉備に「長を廃し幼を立つるは乱を取るの道」と諫められてもなお決めかね、そのまま病に倒れた。死後、蔡夫人は遺命を封じ、内門を閉ざして蔡瑁・張允に外門を守らせ、偽りの遺言で劉琮を立て、ついには荊州を曹操に献じてしまう。豊かな土地だけが取り柄で、構想も人材活用も後継設計も、ことごとく自らの手から零れ落ちた。守りに守って一州を保ちながら、その守りごと他人に簒われた、悲運の名門である。"}, {"id": 145, "name": "孫靜", "faction": 2, "role": "その他", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 1, 5, 2, 3], "p": [1, 1, 2, 1, 3, 3], "scores": {"W": 1.0, "B": 3.45, "S": 2.8, "A": 3.0, "G": 1.68, "K": 2.3}, "stat": {"dmg": 0.66, "area": 0.87, "cd": 1.11, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "群雄", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [7, 15, 29, 39, 75, 108], "chapN": 6, "bio": "孫氏一族、孫策の喪事を取り仕切る", "profile": "呉の孫氏一族。孫堅の弟にして字は幼台。武勇の人ではなく、出師を諫める長老役と、一計を献じる軍師格として物語に立つ宗室である。\n\n第七回、孫堅が小さな遺恨から重兵を起こそうとしたとき、孫靜は子らを引き連れて馬前に列拝し、こう諫めた――「今、董卓権を専らにし天子懦弱、海内大いに乱れて各々一方に霸たり。江東は方に稍く寧んず。一小恨を以て重兵を起こすは、宜しき所にあらず。願わくは兄これを詳らかにせよ」。大局を見据えた節度ある諫言だったが、孫堅には退けられた。\n\n彼が一度だけ鮮やかに光るのが第十五回、孫策の会稽攻めである。王朗が城に拠って固く守り、攻めあぐねた局面で、孫靜は進み出て計を授けた――「王朗は固きを負みて城を守り、卒かには抜き難し。会稽の銭糧、大半は査瀆に屯す。その地ここを離るること数十里、兵を以て先ずその内に拠るに如かず。所謂、其の無備を攻め、其の不意に出づるなり」。糧倉を衝くこの奇襲策に孫策は「叔父の妙用、賊を破るに足る」と膝を打ち、ついに会稽を陥とした。東路平定の後、孫策はこの叔父に守備を委ねている。\n\n以後は呉会の留守を守る後方の柱に徹した。第二十九回、孫策が急逝して権力に空白が生じると、宗室の長老として喪事を取り仕切り、張昭の差配のもと孫権が文武の謁賀を受けて家督を継ぐ場を整えた。江東三世の安定を陰で支えた人である。自ら名分を発する主役ではなかったが、その血脈は孫皎・孫峻・孫綝らへと連なり、呉の宗室として後世にまで名を残した。"}, {"id": 146, "name": "張松", "faction": 3, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 2, 4, 1], "p": [3, 5, 3, 6, 2, 1], "scores": {"W": 0.0, "B": 1.75, "S": 3.0, "A": 2.75, "G": 3.48, "K": 2.4}, "stat": {"dmg": 0.84, "area": 1.02, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.5, "pwr": 2.6}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [60, 62, 63], "chapN": 3, "bio": "益州別駕。曹操に侮られ西川を劉備に売り渡す", "profile": "益州の別駕。劉璋に仕える文官でありながら、西川を劉備に売り渡した内応者にして、一読すれば忘れぬ「過目不忘」の奇才として知られる人物である。\n\nその容貌は振るわなかった。「額は鉄槌のごとく頭は尖り、鼻は反り歯は露わ、身の丈五尺に満たず、言語は銅鐘のごとし」。第六十回、曹操のもとを訪れた張松は、この風采ゆえに「人物猥瑣」と冷遇される。だが舌鋒は鋭かった。曹操が自著と誇る『孟徳新書』を、張松は一読しただけで暗誦してみせ「これは戦国の無名氏の作。曹丞相が盗んで己の能と為し、足下を瞞すのみ」と論破する。さらに曹操の面前で濮陽・宛城・赤壁・華容・潼関・渭水と、その敗戦をことごとく並べ立てて気骨を示した。乱棒で打ち出されるほど侮られた張松は、この一事で曹操を見限る。\n\nひるがえって劉備の歓待には、心を奪われた。張松は益州の地理図を献じ、「遠近・闊狭、山川の険要、府庫の銭糧、一一倶に明白に載す」という精密きわまる西川の全図を差し出す。そして「益州は険塞、沃野千里、民殷んに国富む。荊襄の衆を起こして長駆西指せば、覇業成すべく、漢室興すべし」と入蜀の大計を説き、法正・孟達という益州の人材まで橋渡しした。この一連の働きが、後の劉備の益州取りの起点となる。\n\nだが智者の最期は、あまりに詰めが甘かった。第六十二回、内応の密書を兄・張肅の前で袖に隠そうとした張松は、酒席の応酬のさなかにそれをぽろりと取り落とす。書は拾われて露見し、密告によって一族もろとも斬られた。天下の地理を諳んじた才人が、たった一通の書一枚を御しきれずに身を滅ぼす――その智と詰めの落差が、この人物の忘れがたい読みどころである。"}, {"id": 147, "name": "司馬徽", "faction": 3, "role": "その他", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 2, 1], "p": [1, 8, 0, 1, 3, 4], "scores": {"W": 0.0, "B": 0.55, "S": 1.3, "A": 1.05, "G": 2.84, "K": 3.45}, "stat": {"dmg": 0.66, "area": 0.88, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.0}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [35, 36, 37, 38, 57], "chapN": 5, "bio": "潁川の隠士、伏龍鳳雛を劉備に示す", "profile": "水鏡先生と称された襄陽の隠者。「松形鶴骨、器宇凡ならず」という痩身仙風の賢士で、生涯出仕せず山野に遊んだ。だがその一言が、三国志後半の物語をまるごと起動させる。劉備を諸葛亮へと導いた、人材の流れの源である。\n\n第三十五回、難を逃れて荘を訪れた劉備に、水鏡先生は天下の人材を見透かして告げる――「伏龍・鳳雛、両人一を得れば、以て天下を安んずべし」。いまだ世に出ぬ諸葛亮と龐統を、その号だけで指し示したのだ。さらに劉備陣営をこう診断する――「関・張・趙雲は皆万人の敵なれど、惜しむらくは之を善く用うる人なし」。自身が助力を請われても「我より十倍勝る者の来りて公を助くるあらん」と退け、決して表には立たない。\n\nその識見は、人物だけでなく時勢にも及んだ。第三十七回、諸葛亮を世に送り出すにあたって水鏡先生はこう嘆息する――「臥龍はその主を得たれど、その時を得ず。惜しいかな」。諸葛亮を歴史上の名軍師に擬えつつ、天下の趨勢の険しさを早くも見抜いていた。徐庶が曹操の偽計の書に騙されて許昌へ行こうとしたときも「今もし去らば、母必ず死せん」と結果を正確に言い当て、その計を看破している。童謡を解いて「蓋し将軍に応ずるなり」と劉備に天命の正統を読み解いてみせもした。\n\n戦わず、治めず、用いず――自らは何ひとつ成さない。それでいて、誰よりも先に人と時を見通した。人材の扉を開けるだけ開けて静かに去る、純粋な賢士として、物語の転換点に立つ人物である。"}, {"id": 148, "name": "馬良", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 3, 4, 2], "p": [4, 1, 2, 4, 2, 6], "scores": {"W": 1.0, "B": 2.6, "S": 3.4, "A": 3.25, "G": 3.02, "K": 2.7}, "stat": {"dmg": 0.9, "area": 1.05, "cd": 1.15, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.5, "pwr": 3.15}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [52, 63, 65, 66, 73, 75, 76, 77, 81, 83], "chapN": 14, "bio": "馬氏五常の最賢。荊州経略の策を献ず", "profile": "蜀漢の文官。荊州の名族・馬氏五兄弟の最も賢き者である。兄弟はみな字に「常」の字を持ち、なかでも眉間に白い毛のある馬良が抜きん出ていた。郷里にいわく「馬氏の五常、白眉最も良し」。武を取らぬ純然たる参謀として、生涯を諸葛亮と劉備のそばで過ごした。\n\n荊州時代、四面を敵に囲まれた地勢を見抜いた馬良は、劉備に「久遠の計」を献じる――劉琦を荊州刺史に奏して民心を安んじ、武陵・長沙・桂陽・零陵の南方四郡を取り、銭糧を蓄えて根本と為せ、と。劉備はこれを採り、取郡の順序まで進言どおりに進めた。以後は関羽の参軍として荊州を輔佐し、また諸葛亮の意を奉じる連絡使を幾度も務める。第七十五回、関羽が刮骨療毒で華佗に腕の骨を削らせる名場面では、その痛みに軍心が乱れぬよう、馬良が関羽の碁の相手を務めて場を支えていた。\n\nその良識が最も際立つのが夷陵の役である。第八十三回、陸遜の率いる呉軍を前に、馬良は再三にわたって劉備を諫めた――「陸遜の才、周郎に亜がず、未だ軽敵すべからず」「兼ね聴けば則ち明、偏り聴けば則ち蔽わる。願わくは陛下これを察せよ」。みずから連営の陣図を描いて成都の諸葛亮に諮問させようとまでした、危機を最も早く正確に見抜いた人である。だがその諫言は容れられず、蜀軍は陸遜の火計に大敗を喫した。\n\n馬良の死は、物語のなかで直接には描かれない。後の第八十七回、弟・馬謖が喪に服しているくだりで「兄馬良の新たに亡くなりしが為に」と、その死がそっと後追いで語られるのみである。白眉の名と、聞き入れられなかった忠言と。乱世に最も賢く、最も惜しまれた参謀として記憶される。"}, {"id": 149, "name": "夏侯霸", "faction": 0, "role": "武将", "rarity": 2, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [3, 2, 2, 1, 4, 3, 3], "p": [1, 2, 1, 2, 3, 2], "scores": {"W": 2.35, "B": 3.35, "S": 3.15, "A": 3.15, "G": 1.73, "K": 2.35}, "stat": {"dmg": 0.81, "area": 0.92, "cd": 1.05, "amount": 1, "knock": 0.79, "crit": 0.05, "duration": 0, "pwr": 2.35}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [102, 103, 104, 106, 107, 109, 110, 111, 113, 114], "chapN": 11, "bio": "夏侯淵の長子、後に蜀漢へ投降し姜維の参謀", "profile": "夏侯淵の長子。もとは曹魏の将であったが、後に蜀漢へ亡命し、姜維の参謀となった降将である。司馬懿はその来歴を「夏侯淵の子、弓馬熟嫻」と評した。\n\n魏将であった前半生では、司馬懿配下として伏兵や先鋒を務める。武勇の片鱗を見せたのが第百六回、遼東討伐の戦いだ。敵将・卑衍が馬を出すと、夏侯霸も馬を縦にして刀を揮い迎え撃ち、戦うこと数合、卑衍を一刀のもとに斬り落とした。遼兵は大いに乱れる。これが本文で彼が個人の武で名のある敵将を斬る、ただ一度の鮮烈な場面である。\n\n運命が転じるのは第百七回。司馬懿が曹爽の一族を誅し、曹氏の宗族たる夏侯霸にも矛先を向けると、彼は「司馬懿は我が曹氏の宗族を滅ぼし、また我を取らんとす。早晩必ず篡位を思わん。吾、義を仗みて賊を討つ、何の反かこれあらん」と叫び、本部三千を率いて造反、漢中へ亡命した。姜維はこれを古の微子になぞらえ「公、能く漢室を匡扶せば、古人に愧じざるなり」と迎える。\n\n蜀に降ってからの夏侯霸は、自ら敵を斬る将ではなく、見識を進言する軍師役へと変わった。隴右の地理と羌人の事情に通じた降将ならではの知見で、姜維に数々の作戦を授ける。牛頭山に出て雍州の背後を衝き麴山の囲みを解く「囲魏救趙」の策、羌人と結ぶ献策、「南安の銭糧最も広し、先ず取りて本と為せ」という方面構想――。また鍾会・鄧艾という魏の二人材を「妙齢の大患、深く畏るべし」と早くから見抜き、姜維に警告した眼も鋭い。\n\n最期は凡庸だった。第百十五回、洮陽を攻めた夏侯霸は、それが空城の計であることを見抜けず、前部五百を率いて軽々しく城下へ突入し、矢を浴びて射殺される。曹氏の遺臣として義を貫いて亡命した気骨と、降将としての見識、そして詰めの甘い最期。武の人というより、見識をもって姜維を支えた降将として、その生涯を閉じた。"}, {"id": 150, "name": "李厳", "faction": 0, "role": "文官", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [4, 3, 3, 1, 2, 3, 3], "p": [1, 1, 3, 3, 1, 5], "scores": {"W": 3.25, "B": 2.55, "S": 2.65, "A": 2.45, "G": 2.14, "K": 2.0}, "stat": {"dmg": 0.91, "area": 0.97, "cd": 1.04, "amount": 1, "knock": 0.86, "crit": 0.05, "duration": 0, "pwr": 3.25}, "title": "文官", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [14, 64, 65, 66, 85, 87, 91, 94, 100, 101], "chapN": 15, "bio": "尚書令。白帝城を守り、孟達と生死の交わり。託孤の臣", "profile": "蜀漢の尚書令にして、白帝城の託孤を諸葛亮とともに受けた重臣。字は正方。文官の肩書を負いながら、その出自は紛れもなく武であった。劉備の益州攻めにあって劉璋方の将として現れた李厳は、敵を畏れぬ膂力で蜀軍の前に立ちはだかる。\n\n第六十五回、綿竹のほとりで老将黄忠と馬を交えた李厳は、四五十合を戦って勝負がつかなかった。名将黄忠を相手にこれだけ持ちこたえた将は数えるほどしかいない。陣中でこれを見ていた孔明は「吾已に李厳の武藝を見たり、力を以て取るべからず」と評し、力攻めを退けて計をめぐらせる。やがて李厳は孔明の詐敗に誘われて山谷へ深入りし、前方に魏延の伏兵が展開するのを見て「猛然と省悟」、ついに馬を下り甲を卸いで降った。降伏するや、劉備の命を受けてただちに綿竹城の費観のもとへ赴き、「某と甚だ密なり」と旧縁を頼って城を開かせている。\n\n実のところ、演義の李厳は「武で世に出て、兵站でつまずいた」境界の人物である。第八十七回、南征に向かう孔明は後顧の備えを問われ、「李厳、白帝城に在り、此の人は陸遜に当たるべきなり」と言い切った。対呉防衛の要として、あの陸遜を抑えうる将と見込まれていたのだ。第八十五回には諸葛亮と並んで永安宮に召され、劉備臨終の遺命を受ける託孤の臣に列している。\n\nところがその信頼は、北伐の兵糧督運という地味な任務で裏切られる。第百回から百一回、孔明が祁山に陣を張る最中、運糧の責めを負った李厳は催促されても米を届けず、ついには偽りの急報で全軍を引き返させてしまう。孔明はこれを「匹夫、一己の故を為に、国家の大事を廃す」と断じ、李厳は庶人に貶された。一騎で名将と渡り合った男が、最後は兵站の不全で身を滅ぼす——その落差こそが、演義における李厳の忘れがたい影である。"}, {"id": 151, "name": "朱然", "faction": 2, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 3, 1, 2, 4, 2, 3], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 2.4, "B": 3.25, "S": 2.6, "A": 2.75, "G": 1.12, "K": 1.55}, "stat": {"dmg": 0.8, "area": 0.91, "cd": 1.05, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.3}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [75, 77, 82, 84], "chapN": 4, "bio": "呂蒙配下、麦城北で関羽を伏撃する", "profile": "呉の中堅武将。呂蒙の配下として荊州攻略の伏兵を担い、のちに夷陵の戦いでは右都督に任じられた。槍を得物とし、「虎威将軍」の号を帯びる。\n\n第七十七回、関羽が麦城を脱して落ちのびる夜、呂蒙は「朱然をして精兵五千を引き、麦城の北二十里に伏せしめよ。彼の軍至らば、敵すべからず、ただ随後に掩殺すべし」と命じた。その作戦どおり朱然は伏兵を伏せ、関羽捕縛の網の一端を担う。馬上から「雲長休すな、早く投降せば一死を免れん」と呼ばわるものの、関羽が応じて向かってくると「朱然便ち走る」——自らは戦わず退いた。関羽を擒えたのはあくまで伏兵全体の功であって、朱然個人の白兵の手柄ではない。\n\n第八十二回、夷陵で孫権は孫桓を左都督、朱然を右都督に封じ、水軍を委ねた。だが朱然は蜀の小卒が仕掛けた偽りの降兵にまんまと乗せられ、部将崔禹を送り出した末に「大いに江中に敗れ」、船を率いて五六十里も退く失態を演じる。知略でしてやられる側に立たされたのである。\n\n最後は趙雲の手にかかった。第八十四回、夷陵で蜀軍を蹴散らす趙雲の前に「忽ち朱然に遇い、便ち交鋒す。一合ならずして、一鎗もて朱然を馬下に刺し、呉兵を殺散す」。たった一合で討たれ、退場する。通説では呉の宿将として名を残す朱然だが、演義の筆は彼を「謀で出し抜かれ、武で討たれる脇役」として、容赦なく簡潔に描き切った。"}, {"id": 152, "name": "周魴", "faction": 2, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 5, 3, 2], "p": [1, 1, 1, 4, 1, 2], "scores": {"W": 0.0, "B": 3.2, "S": 3.25, "A": 3.35, "G": 1.57, "K": 1.35}, "stat": {"dmg": 0.91, "area": 1.07, "cd": 1.16, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.25, "pwr": 3.3}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [96], "chapN": 1, "bio": "鄱陽太守、断髪の偽降で曹休を欺く", "profile": "呉の文官、鄱陽太守。演義にはただ一度、第九十六回の石亭の戦いに登場するのみだが、その一回が忘れがたい。断髪の苦肉の計をもって魏の大司馬曹休を欺き、陸遜の大勝の口火を切った「智謀の士」である。\n\n魏に偽りの降を申し入れた周魴は、ひそかに七つの事を陳べ、魏兵を呉の重地へと誘い込もうとする。だが曹休は疑った。疑われた周魴は、ここで捨て身の演技に出る。「大いに哭し、急に従人の佩ぶる所の剣を掣きて自刎せんと欲す」——曹休に止められると、今度は「剣を用いて髪を割き地に擲ちて」言い放った。「吾、忠心を以て公を待つに、公、吾を以て戯れと為す。吾、父母の遺す所の髪を割き、以て此の心を表す」。身体髪膚を父母から受けた当時、髪を断つことは命を削るに等しい。この一挙が曹休の疑念を一掃した。\n\n魏の賈逵は「曹休もし賈逵の言を用いば、則ち東呉敗れん。今、天、我をして功を成さしむるなり」と、曹休が忠言を退けたことを敵ながら惜しんだという。周魴の詐降が、まさにその分かれ目を作ったのだ。\n\nただし、伏兵も陣形も追撃も、采配はすべて陸遜が握っていた(「吾自ら妙用有り」)。周魴は計の起爆装置を担った囮役であって、戦そのものを動かしたのは陸遜である。戦いが決すると周魴は「数十人を引き、何処へか去り、知れず」と、煙のように戦場から姿を消した。たった一度の登場で、捨て身の演技ひとつをもって魏の大軍を陥れた——演義の周魴は、それだけで十分に鮮烈な男である。"}, {"id": 153, "name": "吳班", "faction": 0, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 2, 4, 2, 4], "p": [1, 1, 1, 1, 2, 2], "scores": {"W": 1.1, "B": 3.3, "S": 2.7, "A": 2.8, "G": 1.25, "K": 2.05}, "stat": {"dmg": 0.67, "area": 0.89, "cd": 1.11, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 1.1}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [38, 71, 81, 82, 83, 84, 91, 98, 99, 100], "chapN": 14, "bio": "張飛の部将から先鋒に。各地を降し孫桓を破る", "profile": "蜀漢の武将。槍を執り、はじめは張飛の部将として仕え、やがて先鋒の印を帯びて各地を降した堅実な中堅指揮官である。劉備の東征、そして孔明の北伐と、蜀の主だった戦役にまたがって働き続けた。\n\n第八十二回、夷陵へ向かう蜀軍の先鋒として、吳班は「川を出でて以来、到る所、望風して降り、兵、刃に血ぬらず、直ちに宜都に到る」という快進撃を見せた。同じ章では、朱然を陥れる劫寨の計を自ら献じてもいる。「先ず小卒をして、詐りて降兵と作し、却って劫寨の事を朱然に告げ知らしめん。然、火起こるを見れば、必ず来たりて救応せん。却って伏兵をして之を撃たしめば、則ち大事済らん」——この計は当たり、朱然は江中に大敗した。馮習・張南とともに孫桓の陣へ斬り込んだのも吳班である。\n\nもっとも、第八十四回には陸遜から「吾、此等の兵を視ること児戯のごとし」と弱兵を侮られ、第八十三回では劉備の発案で「万余の弱兵」を率いて山谷に伏せる誘いの駒に使われる。吳班自身が敵将を斬る一騎打ちの戦果は、演義の本文に一文も残されていない。常に劉備や孔明の命を受けて部隊を動かす、被指揮型の将なのである。\n\n最期は地味だが、任務に殉じる将らしい幕引きだった。北伐の最中、浮橋を焼く任にあたっていた吳班は「箭に中りて水に落ちて死す」。猛将の派手な討死ではなく、与えられた仕事の途中で矢に倒れる——そのつましさこそ、演義が描いた吳班という実働の将の輪郭である。"}, {"id": 154, "name": "孫禮", "faction": 1, "role": "武将", "rarity": 2, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [3, 2, 3, 2, 4, 2, 3], "p": [1, 1, 2, 1, 1, 2], "scores": {"W": 2.7, "B": 3.25, "S": 2.6, "A": 2.75, "G": 1.3, "K": 1.55}, "stat": {"dmg": 0.85, "area": 0.98, "cd": 1.05, "amount": 1, "knock": 0.91, "crit": 0.06, "duration": 0, "pwr": 2.75}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [95, 97, 98, 99, 101, 102, 103], "chapN": 7, "bio": "魏の上将、運糧の偽計や雍城守備を担う", "profile": "魏の上将軍。曹真の心腹として信任され、対蜀防衛戦に剣を執って臨んだ武人である。猛虎を一刀のもとに斬り捨てた胆力で世に知られ、知略の一面も持つが、その計はことごとく孔明に見破られた。\n\n第九十八回、御前に異変が起こる。「忽ち一猛虎を驚起し、直ちに御前に奔る」——その刹那、孫禮は馬を下り、剣を抜いて虎を斬った。この功により上将軍に封ぜられ、曹真の心腹として遇される。彼の武勇のすべては、この一刀に凝縮されている。\n\n知恵者としての見せ場もこの章にあった。孫禮は曹真に火攻めの偽糧計を献じる。「某、祁山に去きて虚しく運糧の兵を装い、車上に尽く乾柴・茅草を装い、硫黄・燄硝を以て之に灌ぎ……蜀兵糧無くば、必ず然らず来たりて搶わん。其の中に入るを待ちて、火を放ちて車を焼き、外に伏兵を以て之に応ぜば、勝つべし」。曹真は「此の計、大いに妙なり」と膝を打った。だが孔明は一目で看破し、「彼、乃ち此の計を以て我を誘わんと欲するか」と逆手に取る。孫禮は伏兵に囲まれ「大いに驚き」、煙を冒し火を衝いて逃げ、馬を棄てて山を這い登る羽目になった。\n\n第百二回には、蜀軍が渭水を越え北原に拠って隴道を絶つ危険を見抜き、「大いに虞るべきなり」と進言する戦略眼も一度だけ見せている。雍・涼の二十万を率いて来援し、隴西軍馬の総督を任されもした。だが彼が指揮した戦は北原でも祁山でも敗走に終わる。猛虎を斬る豪胆と、孔明に翻弄され続ける宿命——その落差が、演義の孫禮という対蜀戦の脇役を形づくっている。"}, {"id": 155, "name": "鄧芝", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 2, 1, 2, 3, 3, 4], "p": [3, 1, 1, 8, 3, 5], "scores": {"W": 1.75, "B": 3.1, "S": 3.05, "A": 2.95, "G": 3.23, "K": 3.1}, "stat": {"dmg": 0.88, "area": 1.01, "cd": 1.09, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 3.25, "pwr": 3.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [65, 85, 86, 91, 92, 95, 96, 100, 105], "chapN": 9, "bio": "劉璋から降った官員(擢用名簿)", "profile": "蜀漢の文官。もとは劉璋から降った官員だが、その本領は弁舌と判断にあった。趙雲の副将・参軍として戦場を駆ける一方、呉蜀同盟を結びなおした名使者として、演義屈指の外交場面に主役を張る。戸部尚書の肩書も帯びる。\n\nその名を不滅にしたのは第八十六回、呉への使いである。孫権は鄧芝を試そうと、宮門の前に「両行の武士、威風凜凜、各おの鋼刀・大斧・長剣・短戟を持」たせ、殿前まで並べた。さらには油を煮えたぎらせた鼎まで据える。だが鄧芝は「其の意を暁り、並びに懼るる色無く、昂然として行く」。そして言い放った。「吾は乃ち蜀中の一儒生、特に呉国の利害の為に来たる。乃ち兵を設け鼎を陳ね、以て一使を拒む。何ぞ其の局量の物を容るる能わざるや」。この一言が孫権を惶愧させ、上殿を許させた。「天に二日無く、民に二王無し」と説いて二主分治の誘いを退けると、孫権は「卿、鄧芝に亜がず」と後世まで引かれる評を残す。脣歯の連和は、こうして成った。\n\nその下地は第八十五回にあった。新帝即位直後、民心未だ安からぬ折に、鄧芝は「当に東呉と連合し結びて脣歯と為し、先帝の旧怨を一洗すべし。此れ乃ち長久の計なり」と説き、孔明に「吾、之を思うこと久し……今日方に得たり」と国家方針の同志と認められている。\n\n戦場では趙雲を支える堅実な副将だった。第九十六回、箕谷からの撤退戦では、功を「子龍、独り自ら断後し、将を斬りて功を立つ」と趙雲に譲りつつ、「一人一騎をも折らず、輜重等の器も亦た遺失無し」と全軍を整然と退かせ孔明に賞される。第百回には陳式・魏延の暴走を再三諫め、聞かれぬとただちに孔明へ飛報した。胆力と弁、そして命令系統を守る冷静——鄧芝は、武の主役ではなくとも蜀外交の顔として確かに輝いている。"}, {"id": 156, "name": "文聘", "faction": 1, "role": "武将", "rarity": 2, "weapon": "bow", "kind": "proj", "weaponName": "弓", "d": [3, 4, 3, 2, 2, 1, 4], "p": [1, 1, 1, 1, 3, 2], "scores": {"W": 3.1, "B": 2.45, "S": 1.6, "A": 1.6, "G": 1.38, "K": 2.35}, "stat": {"dmg": 0.9, "area": 1.0, "cd": 1.06, "amount": 2, "knock": 0.91, "crit": 0.06, "duration": 0, "pwr": 3.2}, "title": "弓の将", "skill": "弓", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [34, 41, 42, 48, 49, 50, 56, 71, 86], "chapN": 9, "bio": "元荊州の将で曹操に降る、江夏太守。魏延と戦い黄蓋船を制止し被弾", "profile": "魏の将。弓を得物とする。もとは荊州劉表に仕え、のちに曹操へ降って江夏太守となった。武勲は控えめながら、旧主への臣節の厚さで曹操に「真の忠臣なり」と涙して称えられた、忠誠の人である。\n\n降伏の場面が、その人物を最もよく伝える。第四十一回、荊州が曹操の手に落ちたとき、文聘は遅れて参じ、その理由を問われてこう答えた。「人臣と為りて其の主をして境土を保全せしむること能わず、心実に悲慚し、顔無くして早く見ゆるのみ」——主を守れなかった恥を語る姿に、曹操は深く感じ入ったという。\n\n戦場の文聘は、派手な討取とは縁が薄い。第四十一回では魏延と襄陽で「巳より未に至る」まで戦いながら決着がつかず、手下の兵卒はみな討ち尽くされた。長坂坡では趙雲を追うものの、張飛の虎鬚・環眼と伏兵の疑いに気圧されて「馬を勒し、敢えて近前せず」。赤壁では水軍五色旗の左軍青旗を任され、火船を疑って止めに志願するも、黄蓋の火計を見抜けず左腕を射られて大乱を招いた。彼の身体の見せ場はもっぱら射法にあり、第五十六回では「弓を拈り馬を縦り一箭、亦た紅心に中つ」と、馬上から的の中心を射抜く腕前を見せている。\n\nその忠誠が最も鮮やかに発露したのは第八十六回。曹丕の龍舟が転覆寸前となるや、文聘は「龍舟に跳び上がり、丕を負いて小舟に下り、河港に奔り入る」。帝を背負って急場を脱したのである。武勲は地味でも、主君を守らんとする一念だけは終生変わらなかった——それが演義の描く文聘という実務型の忠臣である。"}, {"id": 157, "name": "臧霸", "faction": 1, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [4, 4, 1, 1, 3, 2, 4], "p": [1, 2, 1, 1, 1, 2], "scores": {"W": 2.95, "B": 3.1, "S": 2.4, "A": 2.35, "G": 1.32, "K": 1.95}, "stat": {"dmg": 0.86, "area": 0.9, "cd": 1.01, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 2.8}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [11, 12, 17, 18, 19, 20, 22, 48], "chapN": 8, "bio": "曹操配下の武将、徐庶と共に散関へ先鋒として赴く", "profile": "魏の武将。槍を執る。もとは呂布配下「八員健将」の一人で、張遼に次ぐ序列第二に名を連ねた猛将である。泰山の出で、のちに曹操へ降って瑯琊相となり、青・徐の沿海を守った。\n\nその武の頂点は第十一回にある。呂布が「臧霸を叫びて出馬し戦を搦めしむ」と、曹操軍の名将楽進と一騎打ちに及んだ場面だ。「両馬相交わり、双鎗斉しく挙がる。戦うこと三十余合、勝負分かれず」。曹操配下の勇将を相手に三十余合を持ちこたえた骨のある描写だが、引き分けで敵将を討つには至らなかった。八員健将の一人として、姓名・字・出身まで「第二個、泰山華陰の人、姓は臧、名は霸、字は宣高」と丁寧に記されるあたり、演義が彼を相応の猛将として扱っていたことがうかがえる。\n\n呂布の滅びとともに、臧霸の生き方は転機を迎える。下邳が陥落したのち、彼は同郷の張遼の招安に応じて曹操に降り、さらに孫観・呉敦・尹礼ら泰山の頭目たちを「招安して来降せしめ」、自陣営へ取り込んだ。曹操は「臧霸を封じて瑯琊相と為し」、孫観らにも官を加えて青・徐の沿海地面を守らせる。第二十二回、官渡で袁紹と対峙する危機にあっては、降将の身でありながら青・徐の守備を委ねられ、後方を固めた。\n\n群盗から身を起こし、敵将と互角に渡り合い、やがて同輩を束ねて一方面の安定を担う——演義の臧霸は派手な討取の山場こそ持たないが、序列・降伏・方面起用という筋の中で、独立性の高い実力者としての風格を確かに刻んでいる。"}, {"id": 158, "name": "潘璋", "faction": 2, "role": "武将", "rarity": 2, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [4, 2, 1, 2, 4, 1, 3], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 2.65, "B": 3.2, "S": 2.0, "A": 2.25, "G": 1.0, "K": 1.4}, "stat": {"dmg": 0.84, "area": 0.9, "cd": 1.01, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.6}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [38, 44, 49, 50, 51, 55, 61, 67, 75, 77], "chapN": 13, "bio": "呉の武将、白旗を掲げ漢陽で董襲に接応", "profile": "呉の武将。大刀を得物とする。字は文珪。後世には「関羽を捕えた呉将」として悪名を負うが、演義の本文をたどると、その実像はやや異なる。\n\n第三十八回、孫権が「又た良将数人を得たり」とされる折に、徐盛らと並んで名が挙がるのが潘璋の登場である。同じ章では、黄祖配下の蘇飛が落ち延びるところを「正に東呉の大将潘璋に遇い、両馬相交わり、戦うこと数合ならず、璋に生擒せらる」——名のある敵将を数合で生け捕る、確かな戦果を一つ残している。\n\n関羽捕縛の場面で、潘璋が果たした役は伏兵の指揮であった。第七十七回、呂蒙の作戦下で「潘璋をして精兵五百を引き、臨沮の山僻の小路に伏せしむ」る配置を担う。そして「関公、身を翻して馬より落ち、潘璋の部将馬忠の獲る所と為る」——関羽を実際に生け捕ったのは、潘璋ではなくその部将馬忠だったのである。第八十三回でも先鋒として黄忠を包囲へ誘い込む囮の役を務めた。\n\nただ、その武は中堅にとどまる。黄忠とは「交馬数合、勝負分かれず」と渡り合うが「敵を料るに過ぎず、馬を撥して便ち走る」と敗走を繰り返し、関羽相手にも「只だ三合、潘璋敗走す」。そして最期、第八十三回で因果はめぐる。関興に「按剣して大喝、反賊休すな」と一喝されると「身を回して便ち出」で、関羽の顕聖に「神魂驚散」したところを、関興の一刀に斬られて果てた。父を討たれた関興の手で討たれる——その筋立てこそ、演義が潘璋に与えた退場の構図である。"}, {"id": 159, "name": "顧雍", "faction": 2, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 2, 3, 1], "p": [3, 3, 3, 4, 3, 4], "scores": {"W": 0.0, "B": 1.6, "S": 2.4, "A": 2.25, "G": 3.27, "K": 2.75}, "stat": {"dmg": 0.79, "area": 0.98, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.25, "pwr": 2.15}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [29, 38, 43, 44, 56, 61, 65, 68, 82, 83], "chapN": 13, "bio": "呉の文官、降伏論に賛同する謀士", "profile": "呉の文官、のちの丞相。字は元歎。無口で公正、目立たぬ実務家——その人物像は演義でも揺るがない。第二十九回の人物評そのままに「其の人と為り、言語少なく、酒を飲まず、厳厲正大」な行政家として、十三章にわたり一貫して評議の席に座り続けた。自ら軍を率いる場面も、白兵の描写も、ついに一度もない。\n\n孫権の創業期、顧雍は「丞と為し、太守の事を行わ」しめられ、その治世のもとで「孫権、威、江東に震い、深く民心を得たり」と本文に記される。地味だが、民の心をつかむ統治の地ならしを担ったのである。\n\n数少ない見せ場は、すべて評議の進言にあった。第五十六回には、曹操と劉備を反間の計で相争わせ、呉がその隙に乗じて図ろうという大局の構想を説き、孫権に「元歎の言、甚だ善し」と容れられている。その際、曹操が敬慕する華歆を使者に推して外交を実際に動かしたのも顧雍だ。第六十一回には、劉備が入蜀に手を取られた隙を突いて「川口を截り、其の帰路を断ち」、荊襄を一気に取る奇襲案を献じた。\n\n人を見る眼も確かだった。対蜀・対魏の大任が論じられるたび、顧雍は陸遜を推す。「陸伯言に非ざれば此の重任に当たるべからず」と。第八十二回には、魏帝の封爵を受けようとする孫権を諫め、「主公、宜しく自ら上将軍・九州伯の位を称すべし、当に魏帝の封爵を受くべからず」と、呉が魏の下風に立たぬ独立した名分を主張した(容れられはしなかったが)。\n\nそして第九十八回、危機と継承の局面で、顧雍は「丞相と為」り、陸遜とともに太子を輔けて武昌を守る後継体制の柱に据えられる。剣を執らず、声を荒げず、ただ的確な進言と人物の推挙を積み重ねて呉の屋台骨を支えた——派手さとは無縁の、しかし得難い名宰相の姿が、演義の顧雍にはある。"}, {"id": 160, "name": "孟獲", "faction": 3, "role": "君主", "rarity": 2, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [1, 2, 2, 2, 3, 3, 4], "p": [2, 2, 2, 3, 4, 3], "scores": {"W": 1.55, "B": 3.0, "S": 3.05, "A": 2.95, "G": 2.53, "K": 3.15}, "stat": {"dmg": 0.72, "area": 0.94, "cd": 1.13, "amount": 1, "knock": 0.84, "crit": 0.06, "duration": 0, "pwr": 1.55}, "title": "君主", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [82, 84, 85, 86, 87, 88, 89, 90, 91], "chapN": 9, "bio": "南蛮の王。諸葛亮に七擒七縱され、ついに心服する", "profile": "南中の地に世々根を張る蛮王。両川の地が他人のものであったように、この南方の山河もまた孟獲一族が代々居してきた土地である。「吾は世々此処に居る、汝らこそ無礼にも我が土地を侵す者ではないか」と言い放つその言葉に、彼の立ち位置がよく表れている。漢に従う反逆者ではなく、自らの郷土を守る者として、十万の蛮兵を率いて諸葛亮の前に立ちはだかった。\n\n第八十七回、孟獲は十万の蛮兵を起こして蜀の境を侵す。「人は皆、諸葛亮は用兵に巧みと言うが、この陣を見れば旌旗は乱れ隊伍は錯綜し、刀槍の器械、一つとして我に勝るものはない」と豪語する。だが言葉とは裏腹に、彼は戦うたびに捕らえられた。魏延に正面から組み伏せられて生擒され、ある時は配下の洞主の裏切りで、ある時は陥穽に落ちて、ある時は酒に酔わされて。第八十九回では犀皮の鎧をまとい朱紅の兜をかぶり、左手に牌、右手に刀、赤毛の牛にまたがって口汚く罵りながら現れるが、その威勢もまた擒となって終わる。\n\n七たび捕らえられ、七たび放たれた。彼を支えたのは個人の武勇ではない。白兵で名のある敵将を討った記録は一つもなく、戦場の働きはむしろ妻の祝融夫人や鄂煥・忙牙長ら部将が担った。彼自身の強みは、十万規模の兵を繰り返し動員し、董荼那・朵思大王・木鹿大王・烏戈国の兀突骨まで、複数の洞主や外国を糾合する求心力にあった。号令一下、各洞の酋長が動く。だがその結束は脆く、董荼那ら配下にたびたび裏切られ、「孟獲を殺して孔明に投じ、洞中の百姓を塗炭の苦しみから救いたい」とまで言われる始末だった。\n\n最後の擒となったとき、孟獲はついに肌脱ぎして謝罪し、「南人、二度と叛かず」と心から降った。武においては失敗の連続、構想においては自領防衛と報讐に終始した男だが、敗れてなお何度も次の拠り所へと移って再起を図り続けた執念と、最後に心服へ至るまでの一部始終こそが、諸葛亮の攻心の戦いを照らし出す。彼が屈しなかったからこそ七擒七縱の物語は成り立ち、南方平定の見せ場が生まれた。"}, {"id": 161, "name": "閻圃", "faction": 3, "role": "軍師参謀", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 3, 4, 1], "p": [3, 3, 1, 0, 2, 3], "scores": {"W": 0.0, "B": 2.2, "S": 3.25, "A": 3.1, "G": 2.06, "K": 2.3}, "stat": {"dmg": 0.87, "area": 1.05, "cd": 1.2, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.5, "pwr": 2.95}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [59, 64, 65, 67], "chapN": 4, "bio": "張魯の謀臣。西川を先取する策を進言", "profile": "漢中に拠る張魯麾下の謀臣。巴西の出で、白兵を執ったことは一度もない、純然たる諫言役の文官である。正しい献策を述べるが主に容れられない——それがこの参謀の宿命であった。\n\n第五十九回、張魯が早急に王を称そうとしたとき、閻圃はこれを諫めて言う。「漢川の民は戸口十万余、財富も糧も足り、四面は険固。今、馬超は敗れたばかりで、西涼の民が子午谷から漢中へ逃れて来る者、数万を下らない。思うに益州の劉璋は昏弱、まず西川四十一州を取って本拠とし、然る後に王を称しても遅くはありません」。地勢と人口と財力を分析し、拡張の順序まで踏まえたこの構想は、群雄の一謀臣としては視野の広いものだった。\n\n第六十七回、曹操軍が迫ると、閻圃は埋もれていた人材を見出す。「某、一人を保証します。曹操配下の諸将に当たれましょう」——南安の龐徳である。馬超に従って降ったが、馬超が西川へ去る際に龐徳は病に臥して従わず、いま主公の恩養を受けている。この推挙は的中し、龐徳は張郃・夏侯淵・徐晃・許褚の四将と互角に渡り合った。だがその龐徳が楊松の讒言で冤罪に問われ斬られかけると、閻圃は苦諫してこれを止めようとし、張魯の無謀な出撃にも「出るな」と諫める。\n\nしかし彼の諫言はことごとく聴かれなかった。張魯は諫めを振り切って軍を出し、交鋒する前に後軍が崩れ去った。漢中はついに曹操の手に落ちる。賢い助言者でありながら、その賢さを主に届けることができなかった男。それでも最後には曹操に列侯として封ぜられた。乱世にあって、容れられぬ正論を述べ続けた一人の参謀として、その姿は静かに記憶される。"}, {"id": 162, "name": "孫桓", "faction": 2, "role": "武将", "rarity": 2, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [3, 2, 2, 2, 3, 1, 5], "p": [1, 1, 1, 1, 3, 2], "scores": {"W": 2.45, "B": 3.15, "S": 1.95, "A": 2.0, "G": 1.38, "K": 2.55}, "stat": {"dmg": 0.82, "area": 0.94, "cd": 1.04, "amount": 1, "knock": 0.84, "crit": 0.06, "duration": 0, "pwr": 2.45}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [82, 83, 84], "chapN": 3, "bio": "孫策が孫姓を賜った宗族。25歳で左都督となるが夷陵で囲まれる", "profile": "呉の若き宗室の将。孫策に愛され孫姓を賜ったため呉王の宗族に列なり、「主上の姪」とも呼ばれた。弓馬に熟練し、常に呉王に従って征討し、たびたび奇功を立てて武衛都尉に任ぜられる。夷陵の役のとき、わずか二十五歳であった。\n\n第八十二回、孫桓は二万五千の軍馬を率い、宜都の界口に屯して前後を三営に分け、蜀兵を拒んだ。だがここから彼の試練が始まる。麾下の李異・謝旌・譚雄を次々と失い、関興と三十余合斬り結ぶも「気力加わらず、大いに敗れて陣に回る」。張苞からは「孫桓の豎子め、死を目前にしてなお天兵に抗おうとは」と罵られ、先主からは「小児」と侮られた。将士を多く損ない、力尽き勢い孤立して、ついに本国へ救援を乞う。\n\nところが、この敗将に対する評価は意外なところから来る。第八十三回、総帥の陸遜は救援を求める声を退けてこう言った。「吾は素より知る、孫安東は深く軍心を得ている、必ず堅守できよう。救うには及ばぬ。蜀を破った後、彼は自ずと出てくる」。果たして孫桓は彝陵の城を堅く守り抜き、最終局面の第八十四回、陸遜の勝勢に乗じて城から討って出て、張南・馮習を挟撃で討つ反攻を担った。\n\n武勇単体では関興に敗れ、敵に侮られる凡庸な若武者であった。だが敗勢のただ中で軍を崩さず保ち、最後に再び戦場へ出てゆけた——その粘り強さこそが、陸遜の見立てた「軍心を得た守将」の実像である。与えられた宗族の身分に始まり、自らの守りでそれに応えた若き将として、夷陵の物語に確かな一筆を残した。"}, {"id": 163, "name": "孫休", "faction": 2, "role": "君主", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 2, 3, 2], "p": [1, 3, 1, 4, 4, 6], "scores": {"W": 0.1, "B": 1.9, "S": 2.55, "A": 2.4, "G": 2.84, "K": 3.25}, "stat": {"dmg": 0.81, "area": 0.98, "cd": 1.2, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.25, "pwr": 2.35}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [15, 113, 117, 118, 119, 120], "chapN": 6, "bio": "孫権の六男、瑯琊王。即位して孫綝を誅殺。蜀滅亡を聞き憂死", "profile": "呉の第三代皇帝、孫権の第六子。瑯琊王であったが、権臣の孫綝に擁立されて帝位に就いた。再三の謙譲を経てようやく玉璽を受け、文武百官の朝賀を済ませ、天下に大赦して永安と改元する。だが彼を立てた孫綝は丞相・荊州牧に封ぜられ、禁兵を握って権勢を振るう。傀儡として始まった治世であった。\n\nその孫休が単なる飾りでないことを示したのが、演義最大の見せ場である。孫綝の篡奪の気配を察した孫休は驚き、急ぎ張布を召して計議し、さらに丁奉を内に呼んで密かにこれを告げる。丁奉は「陛下、憂うることなかれ。臣に一計あり、国のために害を除きましょう」と奏した。臘日の大宴の席で、魏邈・施朔を外事に、張布を内応に配し、一挙に孫綝を捕らえる。第百十三回、孫休は擒となった孫綝を一喝した。「なぜ滕胤・呂據・王淳を遠ざけ殺したのか」——そして「これを推し下して斬れ」と命じた。三族を滅ぼし、禁兵を握る一党を一掃する。事後には張布に詔を宣べさせ「罪は孫綝一人にあり、余は皆問わず」として人心を安んじた。傀儡を脱する鮮烈な政変であった。\n\nその目は大局にも届いていた。司馬昭がやがて魏を簒奪し、威を示すために呉・蜀を侵すであろうと予見し、成都へ書を送って「彼此おのおの宜しく準備すべし」と呉蜀双方の備えを促す。第百十七回、蜀の告急が届くや「蜀中すでに危急、孤、豈に坐視して救わざるべけんや」と即断し、老将丁奉を主帥として五万を三路に分かち救援に向かわせた。唇歯の同盟を実地に動かした決断である。\n\nしかし時勢は彼の味方をしなかった。蜀はついに滅び、その報せを聞いた孫休は憂いのうちに病み伏す。最期は幼い太子の臂を取り、手で字を指し示しながら世を去った。後事を託したその子は立てられず、孫皓が擁立されることとなる。危機を脱する力を見せながら、後継の脆さに泣いた皇帝——その短い生涯は、傾きゆく呉の終焉を予感させる。"}, {"id": 164, "name": "費禕", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 2, 3], "p": [3, 2, 1, 6, 3, 6], "scores": {"W": 0.0, "B": 1.5, "S": 1.75, "A": 1.5, "G": 3.25, "K": 3.25}, "stat": {"dmg": 0.72, "area": 0.91, "cd": 1.2, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.55}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [65, 87, 90, 91, 96, 99, 101, 102, 103, 104], "chapN": 13, "bio": "長史。南征に従軍し置官の是非を諫言", "profile": "蜀漢の重臣、長史。諸葛亮の信頼篤い純然たる文臣で、出師表に「良実、志慮忠純」と名指しされた。武器を執る場面は演義全篇を通じて一度もない。常に侍中・長史・尚書として帳中の議論や使者、調停の場に現れ、「治国は奉法を重んずる」と口にする官僚として描かれる。蔣琬の次に蜀を担うべき者として、諸葛亮自身が継承順位に組み込んだ人物である。\n\nその本領が最も光るのは、対呉の使者としての弁舌であった。第百二回、費禕は孔明の使者として単身建業へ赴き、孫権に北伐の書を呈して三十万の出兵約定を取り付ける。宴席で孫権から蜀の先鋒は誰かと問われ「魏延が首」と答えると、孫権は笑って「この者、勇は有り余るが心が正しくない。もし一朝孔明が亡くなれば、必ず禍となろう」と評した。費禕は拝謝して「誠にその通りなら、中原は遠からず自ずと破れましょう」と応じる。同盟外交を一身に背負って完遂した、彼の生涯屈指の場面である。\n\n人柄は終始、法理を重んじる秩序の人であった。第九十六回、街亭の敗の後、「臣聞く、国を治むる者は必ず奉法を重しと為す。法もし行われずば、何をもって人を服せしめん。丞相の敗績により自ら貶降するは、正にその宜しきところ」と奏し、諸葛亮みずからの降格を法の筋として支持した。私情ではなく法によって国を立てる——その理念を体現する声であった。\n\nそして彼の真価は、危機の最前線で発揮される。第百四回、諸葛亮の臨終直後、費禕は兵符を携えて魏延を訪ね、撤退と兵権の移譲を説いた。「丞相は一切の大事をことごとく楊儀に託し、用兵の密法は皆、姜伯約に授けられた。この兵符は楊儀の令である」——後継の体制を伝え、動乱を抑えにかかったのである。魏延に怒鳴られ詰め寄られながらも、彼は崩れゆく蜀の継承秩序を必死に繋ぎ止めようとした。武の人ではなく、言葉と法と忠誠で国家を支えた文臣として、その姿は諸葛亮亡き後の蜀漢の屋台骨を映している。"}, {"id": 165, "name": "楊儀", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 4, 3, 3], "p": [2, 2, 5, 2, 3, 6], "scores": {"W": 1.0, "B": 3.15, "S": 3.15, "A": 3.15, "G": 3.15, "K": 3.1}, "stat": {"dmg": 0.9, "area": 1.04, "cd": 1.13, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.25, "pwr": 3.15}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [91, 95, 97, 98, 100, 101, 102, 104, 105], "chapN": 9, "bio": "長史、孔明の軍務を補佐", "profile": "蜀漢の長史。諸葛亮の軍務を補佐し、糧草と軍機を一手に担った文官である。個人の武勇は皆無で、蔣琬をして「楊儀は乃ち文人なり」と言わしめた。だが兵站と軍機の参贊においては、孔明の片腕として確かな働きを見せた。\n\nその実務の眼は、兵糧の流れを読むことに長けていた。第百回、孔明の退兵に際して竈の数が増えるのを見た楊儀は「昔、孫臏は龐涓を擒にするのに添兵減竈の法を用いました。今、丞相が兵を退くのになぜ竈を増やすのですか」と問う。第百一回には自ら持久の策を献言する。「二十万の衆を、十万だけ祁山に出して三月留め、その後この十万と入れ替え、循環して相転ずれば、兵力は乏しからず。然る後に徐々に進めば、中原も図るべし」——兵力枯渇を防ぐこの循環交替案は採用された。長史として「糧米は皆、剣閣に在り、人夫牛馬の搬運不便、如之何せん」と補給の難所を見通すのも彼の役目であった。\n\nそして彼の生涯最大の働きが、諸葛亮の死という最大の危機に訪れる。遺命を受けた楊儀は喪を発せず、軍を二手にまとめて柩を扶けながら徐々に退き、姜維に殿軍を命じて全軍を崩さず漢中へ帰した。錦囊を取り出して封を開き、その計に従って魏延を誅し——魏延を陣前で挑発し、実際に斬ったのは馬岱であったが——動乱を未然に鎮めた。後主は「大事を保全せしは、皆、卿の力なり」と称えた。遺託を全うした執行の力は、本作で具体的に描かれる彼の最大の功績である。\n\nだが、その功が彼を滅ぼした。楊儀は自らの官歴が蔣琬より先であるのに位は琬の下に置かれ、功高きに重賞なきを恨んで口に怨言を吐く。「いっそ全軍を率いて魏に投ずべきだった」とまで放言したことが咎められ、下獄・廃黜の末に羞慚のうちに自刎した。序列の不満を御せず派閥に破れて自滅した結末は、危機を執行する手腕と、人を御し己を御する器量とが別物であることを、無言のうちに語っている。"}, {"id": 166, "name": "胡遵", "faction": 1, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [4, 1, 1, 2, 3, 2, 4], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 2.45, "B": 3.15, "S": 2.45, "A": 2.45, "G": 1.0, "K": 1.6}, "stat": {"dmg": 0.82, "area": 0.89, "cd": 1.01, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [106, 108, 110, 112], "chapN": 4, "bio": "魏の将、遼東・呉討伐の先鋒", "profile": "魏の征東将軍。司馬懿・司馬師・司馬昭三代の手足として、遼東・東興・淮南の各戦線で先鋒や三路総領を任された実働の武将である。地味ながら歴戦の宿将であり、政治の事績は一切ない、戦場一筋の人であった。\n\nその武の見せ場は、第百十二回に集中する。淮南で反逆した諸葛誕が、魏兵がすでに城内に入ったと知って慌て、数百人を率いて城中の小路から突出し、吊橋のほとりに至ったところで、ちょうど胡遵に出くわした。「手起こり刀落ち、誕を馬下に斬る」——反逆の首魁を一刀で討ち取り、従う数百人も皆捕縛された。正面の一騎打ちではなく突出してきた敗将を仕留めた形だが、確実な一撃で大将首を挙げた働きであった。\n\n一方で、彼には苦い敗北も描かれる。第百八回、東興の戦いで司馬昭は胡遵を先鋒とし、三路の兵を総領させて浮橋を架け、東興の大堤を取らせた。だが雪中の宴に油断していたところへ、呉の丁奉が連珠砲の合図とともに刀を抜いて先頭を切り、岸に躍り上がる。兵らは皆短刀を抜いて魏の寨に斬り込み、「魏兵、手を措くに及ばず」と完敗した。胡遵自身は帳中で「三千人に過ぎぬ、何ぞ懼るるに足らん」と敵を侮っていたが、その直後にこの大敗を喫し、浮橋が崩れて多くの兵を失う皮肉な場面となった。\n\n胡遵に与えられた評価語はなく、その立場は常に司馬氏の作戦の一駒であった。青州の諸軍を率いて帰路を断て、と方面を割り当てられ、先鋒として襄平へ先入する。勝った戦も負けた戦もある、等身大の前線指揮官——派手な武名や構想を持たぬからこそ、司馬氏の天下取りを足元で支えた歴戦の将として、その確かな存在感が淮南の決着の場に刻まれている。"}, {"id": 167, "name": "王威", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 1, 1, 4, 3, 2], "p": [1, 1, 1, 1, 2, 3], "scores": {"W": 1.45, "B": 3.0, "S": 3.05, "A": 3.1, "G": 1.37, "K": 1.8}, "stat": {"dmg": 0.71, "area": 0.87, "cd": 1.1, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [34, 41, 69], "chapN": 3, "bio": "劉琮の旧将、曹操奇襲を進言し劉琮母子と共に殺される", "profile": "荊州の主・劉琮に仕えた故将。一般には忠義の人として知られるが、演義での実像は「献策の眼」と「忠義の死」の二点に凝縮される。第三十四回では文聘と並ぶ宴席の警護要員として名が出るのみだが、第四十一回でその真価を見せる。\n\n曹操が大軍で迫り、劉琮が降伏に傾いたとき、王威は主君に進言した。「将軍すでに降り、玄徳もまた走れば、曹操は必ず懈弛して無備となりましょう。願わくは将軍、奇兵を整え、険所に伏せてこれを撃てば、操を擒にできます」。降伏という最悪の局面のただ中で、敵の油断の隙を読み、地形を利用し、曹操本人を標的に据えた具体的な伏撃案であった。さらに彼は一戦の波及まで見通す。「操を獲れば威は天下に震い、中原は広しといえども、檄を伝えて定むべし」。荊州一隅の故将としては、驚くほど視野の広い戦略眼の片鱗である。\n\nだがこの献策は容れられなかった。降伏を進める蔡瑁が「汝は天命を知らず、安んぞ妄言を敢えてするか」と叱ると、王威は怒って罵った。「売国の徒め、吾は恨むらくは汝の肉を生きながら啖わざるを」。降伏を売国と断じ、荊州を保つべしと訴える気概は本物であったが、彼を恐れる者はなく、むしろ殺されかける側であった。\n\n最後まで王威は主に殉じた。劉琮母子の護送に故将として随行し、于禁の襲撃を受けるや「忿怒し、力を奮って相闘う」も、衆軍に囲まれて斬られ、討死を遂げる。名のある敵将を一人も討てぬまま乱戦に没した、無名に近い荊州の一武将。だがその献策の鋭さと、最後まで主を守って死んだ忠義の姿は、降伏に呑まれゆく荊州の中で、ひときわ凛とした光を放っている。"}, {"id": 168, "name": "馮習", "faction": 0, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 1, 1, 4, 2, 3], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 1.45, "B": 3.1, "S": 2.55, "A": 2.65, "G": 1.12, "K": 1.55}, "stat": {"dmg": 0.71, "area": 0.87, "cd": 1.09, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [81, 82, 83, 84, 85], "chapN": 5, "bio": "東征の副将・先鋒。連営を移し火攻で乱戦死する", "profile": "蜀漢の武将、夷陵の役における東征軍の先鋒・副将。通説では「連営移転を進言して大敗を招いた戦犯」の印象が強いが、本文を読むと、移営を決断したのは先主その人であり、馮習はあくまで実務を担った将であった。\n\n緒戦では確かな働きを見せる。第八十二回、呉の孫桓が敗れたとき、馮習は張南とともに呉班に向かって「目今、呉兵は勢い敗る、正に虚に乗じて寨を劫すべし」と夜襲を発議した。その夜、馮習・張南・呉班は兵を三路に分けてまっすぐ孫桓の寨へ斬り込み、四面に火を起こす。詐降の計と伏兵によって崔禹を生擒し朱然を退ける勝利の一翼を、彼は確かに担ったのである。\n\nところが第八十三回、運命を分ける進言が彼の口から出る。「即今、天気は炎熱、軍を赤火の中に屯すれば、水を取るに深く不便なり」——この訴えが、連営を移すという致命的な決断の遠因となった。だが移営そのものを命じたのは先主であり、馮習は旨を奉じて作業を実行した者にすぎない。やがて陸遜の火攻が連営を焼き、戦線は崩壊する。\n\n最期は乱軍の中であった。第八十四回、馮習は慌てて馬に乗り数十騎を引いて走るが、呉将徐盛の軍に行き当たって斬り合う。徐盛は馮習を捨てて先主を追ったほどで、彼は脅威とは見なされなかった。張南とともに「力を奮って衝突する」も脱することかなわず、ついに乱軍の中に死す。後人は詩にこう詠んだ——「馮習、忠に二無く、張南、義に双び少なし」。武勲ではなく忠義をもって記憶される将。王事に殉じたその死は、夷陵の悲劇を彩る一人の忠臣の最期として、静かに語り継がれる。"}, {"id": 169, "name": "王甫", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 2, 1, 2], "p": [1, 6, 1, 1, 1, 7], "scores": {"W": 0.1, "B": 1.6, "S": 1.35, "A": 1.4, "G": 2.72, "K": 3.1}, "stat": {"dmg": 0.71, "area": 0.9, "cd": 1.2, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.75, "pwr": 1.45}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [73, 75, 76, 77], "chapN": 4, "bio": "関羽の随軍司馬、烽火台や人事で諫言、麦城で城と運命を共にし墜城死", "profile": "関羽の随軍司馬を務めた蜀漢の文官。独立した将才や統治の実績は持たず、正しい献策を述べるが容れられず、最後は麦城に殉じて城から身を投げた忠臣である。荊州防衛をめぐる危機の予見にその長所が集中する。\n\nその先見は演義屈指のものであった。第七十三回、襄陽攻略の直後、王甫は呂蒙の動きを見抜いて関羽に問う。「今、東呉の呂蒙は陸口に屯兵し、常に荊州を呑み併せんとの意あり。もし兵を率いてまっすぐ荊州を取ったなら、いかにこれを奈せん」。そして沿江に二十里三十里おきに烽火台を置き、各台に五十軍を守らせ、呉兵が江を渡れば夜は火を明らかにし昼は煙を挙げて合図とする警戒網を進言した。さらに人事にも鋭い眼を向ける。「潘濬は平生、忌むこと多く利を好む、任用すべからず。軍前都督糧料官の趙累にこれを代えるべし。趙累は人となり忠誠廉直、この人を用いれば万に一失なし」——潘濬の性格的欠陥を見抜き、忠直の士を推したのである。\n\nだが関羽は、これらの献策を容れなかった。後に潘濬の不忠が現実となり、王甫の人物鑑識眼の確かさが裏付けられる。第七十六回、関羽は自ら「悔ゆらくは足下の言を聴かざりしを」と的中を認め、第七十五回でも地の文が「従前、王甫は良言なりき」と二重にその慧眼を保証した。正しさが、いつも一歩遅れて証明される——それが彼の悲劇であった。\n\n最期まで王甫は城を捨てなかった。「某、部卒百余人とともに、死してこの城に拠る。城破るるとも、身は降らじ」と麦城死守を誓う。そして関羽の首級が呉に渡ったと知るや、第七十七回、「大いに一声叫び、城より墮ちて死す」——城とともに命を絶った。容れられぬ正論を述べ続け、的中してなお破局を防げず、最後は身を投げて主に殉じた文官。その忠と先見は、関羽の悲劇をいっそう深く照らし出している。"}, {"id": 170, "name": "吳太夫人", "faction": 2, "role": "婦人", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 1], "p": [2, 4, 0, 1, 3, 6], "scores": {"W": 0.0, "B": 0.4, "S": 0.7, "A": 0.55, "G": 2.5, "K": 3.1}, "stat": {"dmg": 0.61, "area": 0.84, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.55}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [7, 29, 38, 54], "chapN": 4, "bio": "孫権の母、周瑜・張昭に後事を託す", "profile": "孫堅の妻にして、孫策・孫権を産んだ呉氏。江東に覇を築いた孫一族の母であり、戦場に立つ人ではなく、君主の内側にあって諫め、裁き、遺命を託す「母后」として演義に描かれる。武勇の逸話は一つもない。だが孫氏の天下取りの節目には、必ず彼女の意志が一枚噛んでいる。\n\n第二十九回、于吉という道士を斬った孫策が祟りに苦しむと、見舞いに来た母は「吾が兒、神仙を屈殺す、故にこの禍を招く」と、わが子の非を率直に責める。第三十八回、曹操が人質を求めてきたとき、周瑜が「質を送らず、ゆるりと変を観るべし」と説くと、彼女は「公瑾の言、是なり」と裁可した。この一言が江東の自立路線を定め、孫権が曹操に屈せぬ国の骨格となる。そして同じ第三十八回、病が篤くなった彼女は周瑜と張昭を枕辺に呼び、「今、江東の基業を権に付す。望むらくは公等、心を同じくしてこれを助けよ。吾死すとも朽ちざらん」と後事を託した。孫権には「汝、子布・公瑾に事えること師傅の礼を以てし、怠慢すべからず」と命じ、二大重臣の権威を母の遺命で保証している。\n\n第五十四回では、周瑜が劉備を呉に誘い込んで拘留する美人計を仕掛けると、彼女は母后の権威でこれを罵り、自ら甘露寺に出向いて劉備を検分した。「我いまだ劉皇叔を認め得ず、明日、甘露寺に約して相見えん」——そして劉備の人品を見定め、これを婿と認めた。娘の良縁を案じる私情が動機ではあったが、結果として孫劉の縁戚という同盟の紐帯を、君主の謀略を覆す形で成立させている。\n\n戦った記録は一つもない。それでも彼女は、子の暴走を諫め、外交方針を裁可し、臨終には継承の秩序まで整えた。剣ではなく、母としての権威ひとつで江東の運命を幾度も動かした人である。"}, {"id": 171, "name": "冷苞", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 4, 1, 2, 4, 1, 2], "p": [1, 1, 1, 2, 1, 1], "scores": {"W": 2.6, "B": 2.85, "S": 1.9, "A": 2.2, "G": 1.15, "K": 1.2}, "stat": {"dmg": 0.82, "area": 0.92, "cd": 1.06, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [60, 61, 62, 63], "chapN": 4, "bio": "劉璋配下の将。劉備を防ぐよう進言する一班", "profile": "劉璋配下の将で、雒城防衛を任された川兵の一翼。魏延の口を借りて「冷苞・鄧賢は蜀中の名将、血気方剛なり」と紹介され、一見、名のある武人として登場する。だが本文での実態は、その看板に届かぬ苦戦の連続だった。\n\n第六十二回、魏延と馬を交えて三十合を渡り合い、のちには黄忠とも十余合戦う。場数こそ踏むが、名のある敵将を一人として討てず、いつも「抵敵すること住まらず、後ろを望んで便ち走る」と劣勢に追い込まれ、ついには二度までも生け捕られてしまう。彼の唯一の見せ場は白兵ではなく策にあった。敵陣が山裾の低地で涪江に靠っているのを見抜き、「某、五千の軍を乞い、各々鍬鋤を帯びて前去し、涪江の水を決すれば、ことごとく劉備の兵を淹れ死なすべし」と水攻めを献じる。地形を読んだ見事な発想だったが、彭羕にたちまち看破され、実行の最中に魏延に捕られて不発に終わった。\n\n捕われたあとは「劉瑰・張任は某と生死の交わり、もし某を放ち回らせば、二人を招きて降らせ、雒城を献ぜん」と降伏交渉を持ちかける。だがこれは命惜しさの偽りで、城に帰るとすぐ翻し、再び決水を企てた。第六十三回、その背信を「吾、仁義を以て相待し、汝を放ち回らせしに、何ぞ敢えて我に背くか」と咎められ、引き出されて斬られる。\n\n「名将」と呼ばれながら、誰も討てず、計も見破られ、二度捕われて処断された将。それでも涪江を堰き止めようとした一献策には、地形を読む確かな眼が光っている。"}, {"id": 172, "name": "張濟", "faction": 3, "role": "武将", "rarity": 2, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [3, 2, 1, 2, 3, 3, 3], "p": [2, 1, 3, 4, 3, 3], "scores": {"W": 2.2, "B": 2.95, "S": 2.95, "A": 2.9, "G": 2.53, "K": 2.45}, "stat": {"dmg": 0.79, "area": 0.9, "cd": 1.06, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.15}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [3, 5, 9, 10, 13, 16], "chapN": 6, "bio": "董卓配下の将", "profile": "董卓配下の将で、董卓亡きあとは李傕・郭汜・樊稠と並ぶ残党カルテットの一員として動く。西涼出身の武人ではあるが、演義の張済は個人の白兵戦果がほとんどなく、四人ひと括りで名を呼ばれる「李傕の手駒」として扱われることが多い。むしろ周旋と兵站に光る、調停型の人物として描かれる。\n\n武の場面は乏しい。第十回、李傕・郭汜の命で馬騰の軍を追撃するが、「馬超、後に在りて死戦し、張済を殺退す」と、若き馬超に押し返されて敗走する。同じ第十回、席上で樊稠が斬られた瞬間には「張済を嚇して地に俯伏せしむ」——同僚が誅される修羅場で即座に身を低くして恭順を示し、李傕の猜疑を解いて生き延びた。そのうえ樊稠の軍まで「管領」を任され、保身という形で危機を切り抜けている。\n\n彼の最大の見せ場は戦場ではなく、調停の場にある。第十三回、李傕と郭汜が長安で殺し合いを続けると、張済は陝西から大軍を率いて来り、「従わざる者は兵を引きてこれを撃つ」と圧をかけて両者に和議を呑ませた。さらに「天子の駕、弘農に幸せんことを請う」と表を上げて献帝の東遷を実現し、帝から驃騎将軍に封じられる。混乱のさなか、飢えた朝廷のために「糧食酒肉を進め、百官に供給」したのも彼で、武よりも物資と仲裁で朝廷機能を辛うじて支えた。\n\n最期は南陽攻めで流矢に当たって戦死し、部衆は姪の張繡が継いだ。華々しい武名は残さなかったが、内戦を収めて天子を動かし、百官に飯を回した周旋の手腕は、董卓残党の中ではひときわ異彩を放つ。"}, {"id": 173, "name": "曹髦", "faction": 1, "role": "君主", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 1, 2, 2], "p": [1, 1, 1, 1, 6, 3], "scores": {"W": 1.1, "B": 1.45, "S": 1.75, "A": 1.65, "G": 1.89, "K": 3.0}, "stat": {"dmg": 0.73, "area": 0.91, "cd": 1.18, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 3.0, "pwr": 1.65}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [109, 110, 111, 114], "chapN": 4, "bio": "文帝の孫、司馬師に擁立され魏帝となる", "profile": "魏の文帝曹丕の孫であり、司馬師に擁立されて帝位に就いた若き天子。第百九回で太后に「帝王の相」を認められ、人柄は「温恭克讓」と評された。だが実権はすべて司馬氏が相府で握り、「一応の事務は朝廷に奏せず、相府にて裁処す」という傀儡の身であった。彼が記憶されるのは、強さではなく、節義に殉じた死による。\n\nその死は第百十四回に描かれる。司馬昭の簒奪の野心がいよいよ露わになると、曹髦は王沈・王経・王業の三人を召して計議し、「司馬昭、将に篡逆を懐く、人の共に知る所なり。朕、坐して廃辱を受けず、卿等、朕を助けてこれを討つべし」と決起を宣言した。王経は「今、陛下、数百人を領して昭を伐つは、羊を駆りて虎口に入るのみ、空しく死して益なし」と諫めたが、彼は「是れ忍ぶべくんば、孰れか忍ぶべからざるや。朕の意已に決す、便ち死すとも何ぞ懼れん」と退ける。そして護衛の焦伯と、殿中の宿衛・蒼頭・官童三百余人を集め、鼓を鳴らして南闕へ車を駆った。\n\n劍を仗りて輦に升り、左右を叱して進む天子の前に、禁兵は「皆、敢えて動かず」と立ちすくむ。「吾は乃ち天子なり、汝等、宮庭に突入し、君を弒せんと欲するか」と大喝するも、賈充の一言で成済が一戟に前胸を刺し、即死させた。召した三人のうち王沈と王業は早々に司馬昭へ密告しており、王経は一人節を守って母とともに笑って刑死している。\n\n勝算は最初から無かった。だが「吾は乃ち天子なり」と大義を掲げて散った姿は、司馬孚が「王礼を以て葬る」を請うほどに名分を重からしめた。武功も統治も外交も演義は彼に描かない。それでも、傀儡として座して廃されることを拒み、自ら剣を取って死んだ気概こそが、曹髦という人を後世に刻んでいる。"}, {"id": 174, "name": "譙周", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 2, 1], "p": [2, 0, 0, 3, 6, 5], "scores": {"W": 0.0, "B": 0.55, "S": 1.3, "A": 1.05, "G": 2.27, "K": 3.05}, "stat": {"dmg": 0.66, "area": 0.88, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [65, 80, 91, 101, 102, 105, 112, 115, 118, 119], "chapN": 10, "bio": "巴西西充国人。天文に通じ劉備降伏を勧める", "profile": "巴西西充国の人で、天文に通じた蜀漢の太史。武器は一切取らず、その力はすべて弁舌と天象を読む知識にあった。劉備即位から蜀の滅亡まで、国の節目ごとに「天の声」として立ち会い、最後には後主に魏への降伏を説いて降書を作る——蜀漢の幕引きに最も深く関わった文官である。\n\nその登場は祝福から始まる。第六十五回で劉備の入蜀を「帝王の象、天道に逆らうべからず」と予言し、第八十回では「これ正に漢中王、当に帝位に即き、以て漢統を継ぐべきに応ず、更に復た何ぞ疑わん」と、天象をもって劉備即位の正統性を保証し、その壇上で祭文を高らかに朗読した。一方で北伐には常に不利を奏する諫臣でもあった。第百十二回の「讎国論」では、「大国に処して患なき者は恆に慢多く、小国に処して憂ある者は恆に善を思う」と説き、周文王の養民、句践の恤衆を範に「弱を以て強を斃す」べしと唱える。武を極めて征伐を黷せば「智者ありと雖も、これを謀る能わず」——不戦と国力の温存を旨とする国家論だった。\n\nそして第百十八回、鄧艾が成都に迫る存亡の危機。譙周は南中への逃亡、呉への投降、魏への降伏の三案を比較し、「呉に臣を称するは一辱なり。もし呉、魏に呑まるれば、陛下、再び魏に臣を称す、是れ両番の辱なり」と論じる。「不如、呉に投ぜずして魏に降るに。魏は必ず土を裂きて陛下を封ぜん」と、国際情勢を読み切って後主に降魏を選ばせた。北地王劉諶からは「偷生の腐儒、豈に妄りに社稷の大事を議すべけんや」と面罵されながら、それでも降書を成して蜀漢を畳む。\n\n漢統の正統を天象で寿いだその同じ口が、最後にはその漢統の放棄を説いた——譙周の生涯には、この両義性がついて回る。戦って社稷に殉ずる道を捨て、延命を選んだ消極の人として後世に「蜀を売った腐儒」の悪名を背負うが、二度の辱を避けるという冷徹な計算で国の進退を決した弁舌は、間違いなく蜀の最後を動かした。"}, {"id": 175, "name": "喬國老", "faction": 2, "role": "その他", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 0], "p": [1, 3, 1, 6, 5, 4], "scores": {"W": 0.0, "B": 0.0, "S": 0.0, "A": 0.0, "G": 3.03, "K": 2.85}, "stat": {"dmg": 0.55, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.0}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [54], "chapN": 1, "bio": "二喬の父。劉備の婚姻を後押しする長老", "profile": "二喬の父にして、南徐の長老。武人ではなく、登場は第五十四回のただ一度きり。だがその一度で、孫劉の婚姻同盟の成否を内側から動かす、見事な仲介役を演じてみせる。\n\n周瑜の美人計が動き出したとき、それを破ったのが喬国老だった。劉備が呉へ婿入りに来たという情報をつかむや、彼は使いを立てて呉国太に知らせ、賀喜を述べさせる。国太が事を知らずにいたところへ「令愛、已に劉玄徳に許して夫人と為す、今、玄徳已に到る、何故に相瞞すや」と切り込み、計の存在を表沙汰にして、内側から美人計を崩した。さらに国太には「事、已に此くの如し。劉皇叔は乃ち漢室の宗親、真個に彼を招きて婿と為すに如かず、出醜を免れん」と進言し、縁談を本物に変えてしまう。劉備を「漢室宗親」「劉皇叔」「当世の豪傑」と正統性の語で持ち上げ、「この女婿を招き得ば、また令妹を辱めず」と、縁組を体面の問題として枠づける手際も鮮やかだった。\n\n役目はそれだけにとどまらない。劉備が「江左の人、多く劉備を害せんと要する者あり、恐らくは久しく居る能わず」と身の危険を訴えると、喬国老は「玄徳、心を寛うせよ。吾、公の為に国太に告げ、護持を作さしめん」と、自ら取り次いで暗殺の危機まで回避させた。\n\n兵を率いることも、天下を論じることもない。動かしたのは一個の縁談と、国太の意志ひとつ。それでも周瑜の謀略を内側から破り、孫劉の縁戚という同盟の礎を据えた長老の働きは、たった一回の登場とは思えぬ存在感を残している。"}, {"id": 176, "name": "蔣琬", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 2, 2, 3], "p": [3, 3, 3, 2, 2, 5], "scores": {"W": 0.0, "B": 1.95, "S": 2.0, "A": 1.85, "G": 2.96, "K": 3.0}, "stat": {"dmg": 0.76, "area": 0.94, "cd": 1.19, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [63, 64, 65, 87, 88, 89, 91, 96, 98, 101], "chapN": 14, "bio": "零陵出身の名士、書記として入川に従う", "profile": "零陵湘郷の人で、荊襄の名士。書記・参軍として劉備の入川に従い、のちに諸葛亮の後継として蜀漢の政を担う宰相となる。演義では帳中で議を交わす文官として描かれ、武勇の場面は一つもない。その真価は、孔明が自ら名指しした「正しい後継者」という一点と、孔明亡きあとの危機での的確な判断に集約される。\n\n参軍時代から、地勢を読む眼の片鱗は見えていた。第八十八回の南征では、呂凱の築いた寨を見て「正に昔日、先帝、東呉に敗れし時の地勢に犯す。もし蛮兵、瀘水を偸渡し、来りて寨を劫し、火攻を用いば、如何にして解救せん」と、火攻めの危険を孔明に問うている。孔明には「公、多疑することなかれ」と笑って一蹴されたが、敗戦の地形を重ねて見抜く慎重さがそこにあった。第九十一回には丞相府の参軍として国政の中枢に名を連ね、北伐期の留守体制を支えている。\n\n彼が歴史の前面に出るのは孔明の死とともにだった。第百四回、臨終の孔明は「吾死するの後、大事を任すべき者は、蔣公琰、其れ宜しきなり」と、真っ先に彼の名を挙げる。遺言に従い丞相大将軍・録尚書事に任じられた蔣琬は、続く第百五回、魏延の乱に際して「臣、願わくは全家の良賤を将って、楊儀の反せざるを保せん、実に敢えて魏延を保せず」と、一族すべてを賭けて反逆者を正しく見抜いた。楊儀の処分を「廃して庶人と為す」に抑えて政権の動揺を最小化し、対呉の危機には「王平・張嶷をして兵数万を引いて永安に屯せしめ、以て不測に防ぐ」と即応の人事を進言、報喪の使者を呉に送って同盟の動静まで探らせている。\n\n孔明のように三分の天下を構想したわけでも、自ら大軍を率いて勝利を導いたわけでもない。だが孔明が後事を託すに足ると見込んだだけのことはあり、危機の只中で人を見抜き、体制を安定させた。派手さはなくとも、蜀漢を繋いだ堅実な後継宰相である。"}, {"id": 177, "name": "華歆", "faction": 1, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 1, 0], "p": [1, 3, 0, 4, 6, 3], "scores": {"W": 0.1, "B": 0.2, "S": 0.65, "A": 0.6, "G": 2.56, "K": 3.0}, "stat": {"dmg": 0.61, "area": 0.84, "cd": 1.25, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.75, "pwr": 0.55}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [29, 56, 66, 69, 78, 79, 80, 91, 94, 99], "chapN": 10, "bio": "呉の使者として劉備を荊州牧に表薦、後に曹操に仕える", "profile": "かつて管寧・邴原とともに「一龍」と称され、その龍頭と謳われた文名の士。だが演義の華歆は、その学識の誉れとは裏腹に、漢から魏への簒奪を支える実働部隊として一貫して描かれる。本文は彼を「兇を逞しくし謀る」「虐けを助け虎に翼を添う」と断罪し、徳望の名臣どころか、計算ずくの悪役儒官として造形している。\n\nその所業は容赦がない。第六十六回、伏皇后が壁の中に隠れると、華歆は「親ら手を動かして后の頭髻を揪んで拖き出す」——自ら皇后の髪を掴んで引きずり出した。第七十八回には曹操急死の混乱に飛馬で駆けつけ、漢帝から詔命を取り付けて曹丕の嗣位を一手早く確定させる。第七十九回には「子建、才を懐き智を抱く、終に池中の物に非ず、もし早く除かずんば、必ず後患と為らん」と、曹植の除去を曹丕に進言した。そして第八十回、禅譲の演出をすべて回したのも彼である。「陛下、一台を築くべし、名づけて受禪台と曰う」と段取りを整え、献帝に迫っては「縦歩して前に向かい、龍袍を扯住し、色を変じて」「許すと許さざると、早く一言を発せよ」と恫喝し、帝を「戦慄して答うる能わず」の有様に追い込む。「一帝を立て、一帝を廃するは、古の常道なり」——この一言が、新王朝を正統に見せる論理そのものだった。\n\n武の記録は皆無である。皇后を引き出したのも、献帝を脅したのも、武勇ではなく権勢を背にした暴虐と威迫にすぎない。第九十一回には太祖の「鷹視狼顧」の言を引いて司馬懿の誅殺を勧め、結果としてその罷免に手を貸している。第五十六回では孫権の使者として許都に立ち、劉備を荊州牧に表薦する反間の使を務めた前歴もあった。\n\n堯舜の故事と三辞の礼で禅譲を粉飾し、曹丕の政権に大義名分を着せた——その手腕は確かに政権交代を正統に見せる工作の中心だった。だが演義が彼に与えた評価は、終始冷ややかである。文名の龍頭が、簒奪の段取り屋として記憶される。それが演義の華歆という人物像だ。"}, {"id": 178, "name": "郭汜", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 2, 0, 3, 4, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 2.05, "B": 2.9, "S": 1.95, "A": 2.3, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.76, "area": 0.88, "cd": 1.06, "amount": 1, "knock": 0.74, "crit": 0.07, "duration": 0, "pwr": 1.95}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [3, 5, 6, 9, 10, 11, 13, 14, 57, 112], "chapN": 10, "bio": "董卓配下の将、李傕と長安を奪う", "profile": "董卓配下の四将の一人で、董卓の死後は李傕とともに長安を奪い、天子を弄んだ西涼の軍閥。だが演義の郭汜には、武名らしい武名が一切与えられない。終始「郭亜多は盜馬賊なるのみ」と蔑称で呼ばれ、彼を象徴するのは破壊と内輪揉めである。\n\n個人の白兵の見せ場は、皮肉にも仲間との同士討ちだった。第十三回、李傕と「二人便ち陣前に就いて廝殺し、戦うこと十合、勝負を分かたず」——名のある敵将を一人も討たぬまま、味方と決着のつかぬ一騎打ちを演じる。徐晃には「大いに汜の軍を敗り」、楊奉・董承・李楽にも連敗を重ね、軍勢を保てない。第十三回には自軍の二将を独断で斬り捨て、統御すらおぼつかぬ姿を晒した。わずかな戦術らしい働きは、衣服を道に撒いて敵兵の隊列を崩した小計で、「楽の軍、衣服の地に満つるを見て、争いて往きてこれを取り、隊伍尽く失う」と李楽軍を破ったが、これも独自の発案ではなく混戦に乗じたものだった。\n\n政治の場では破壊しか残さない。李傕とともに大将軍を「自ら為し」、横行して憚らず、朝廷には誰も口を開く者がいなかった。「到る処、百姓を劫掠し、老弱者はこれを殺し、強壮者は軍に充つ」と民を収奪し、和議に来た公卿六十余人を逆に監禁してしまう。李傕が「弘農に至りて漢君を殺し、天下を平分せん」と誘えば「汜、喜びて諾す」と乗るだけで、自前の構想は何もない。\n\n最期も自滅だった。妻の反間計を見抜けず、毒を盛られるとの疑心から李傕と全面戦争に突入し、長安で五十余日も殺し合って「死者、其の数を知らず」の惨状を招く。妻の再三の諫めにも聴く耳を持たなかった。武人としても政治家としても見るべきものはなく、ただ破壊と内輪揉めを繰り返した災厄の象徴——それが演義の郭汜である。"}, {"id": 179, "name": "傅彤", "faction": 0, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [4, 3, 1, 2, 2, 1, 3], "p": [1, 1, 1, 1, 2, 1], "scores": {"W": 2.85, "B": 2.3, "S": 1.5, "A": 1.55, "G": 1.13, "K": 1.7}, "stat": {"dmg": 0.85, "area": 0.91, "cd": 1.04, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.75}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [81, 84, 85], "chapN": 3, "bio": "中軍護尉。馬鞍山で殿軍を務め、降伏を拒み吐血して死す", "profile": "蜀漢の中軍護尉として劉備の東征に従った将。登場は第八十一回・第八十四回・第八十五回のわずか三章だが、夷陵の敗走で殿軍を志願し、最後まで降らずに陣中で血を吐いて死んだ忠烈の士として、強く記憶される。\n\n第八十一回、東征軍が編成されると、傅彤は張翼とともに中軍護尉に任じられる。武の見せ場は第八十四回、陸遜配下・淳于丹の夜襲を受けたときだった。「蜀営内より傅彤、兵を引いて殺し出で、鎗を挺して直ちに淳于丹を取る。丹、敵すること住まらず、馬を撥して便ち回る」——敵を退け、奮戦してみせる。そして夷陵の総崩れの中、彼は身を捨てて先主を逃がす道を選んだ。「臣、願わくは死を以てこれに当たらん」と殿軍を志願し、張苞とともに馬鞍山の山口を死守する。\n\n最期の戦いは壮絶だった。八方を囲まれてなお「鎗を挺し馬を縦せ、蜀軍を率いて奮力死戦し、下らざること百余合、往来衝突するも、脱するを得ず」と戦い抜く。敵将の丁奉が降伏を迫ると、傅彤は叱して言い放った。「吾は乃ち漢将なり、安んぞ肯えて呉狗に降らんや」——漢の臣としての名分を掲げ、ついに力尽きて陣中に血を吐いて死す。\n\n名将を討ち取る派手な武功はなく、戦略を語る場面もない。彼の評価の重心は、ただ一点「忠死」に集まる。後人の讚詩は「傅彤、漢将軍に愧じず」とその節義を讃えた。降ることを潔しとせず、わが身を盾にして主君を白帝城へ逃がし、漢将の名のままに死んだ——その一途な忠烈こそが、傅彤という武将の全てである。"}, {"id": 180, "name": "劉琦", "faction": 0, "role": "その他", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 2], "p": [1, 1, 1, 2, 6, 3], "scores": {"W": 0.0, "B": 1.1, "S": 1.05, "A": 0.95, "G": 2.04, "K": 3.0}, "stat": {"dmg": 0.66, "area": 0.87, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 1.0}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [34, 35, 39, 40, 41, 42, 43, 49, 52, 53], "chapN": 13, "bio": "劉表の長子、江夏を領し劉備に船で接応する", "profile": "荊州牧・劉表の長子。後に劉備へ身を寄せる蜀漢方の一人だが、その立ち位置は「悲運の貴公子」という言葉に尽きる。継母である蔡夫人に疎まれ、異母弟を立てようとする蔡氏一派から命を狙われる立場に置かれ、自らの兵を動かして天下を争うような器ではなかった。江夏一万の兵を名目上は率いながら、ついに一度も自ら剣を取って戦うことはない。\n\n彼の見せ場は戦場ではなく、第三十九回の一室にある。継母の害から逃れる術を諸葛亮に乞うても、孔明はなかなか教えようとしない。追い詰められた劉琦は「先生はどうしても琦に教えてくださらぬのか。ならば、いっそ先生の前で死にましょう」と剣を抜き、自ら首を刎ねる素振りまで見せる。その必死さがついに孔明の口を開かせた。授けられたのは、晋の申生と重耳の故事──内にとどまれば危うく、外に出れば安し、という一手。これに従って江夏の鎮守を願い出ることで、劉琦は刃の届かぬ土地へと身を退いた。命を盾にしてまで活路をもぎ取った、この受け身の中の能動性こそが彼の本領だった。\n\nその後の劉琦は、自ら立てた策を持たない。第四十二回、長坂に追われる劉備を救うべく、白袍銀鎧に身を包んで船首に立つ凜々しい姿を見せるが、これも孔明の段取りに沿った接応役にすぎない。第四十九回でも武昌の岸口に布陣せよと孔明に命じられ、ただ持ち場へ戻るだけ。彼が動かすのではなく、彼の存在そのものが動かされていく。\n\nしかしその存在には、戦場の武功には換えがたい重みがあった。劉表の正統な長子という血筋が、劉備の荊州領有を正当化する大義名分そのものになったのである。第五十二回、東呉から荊州返還を迫られると、孔明は病み衰えた劉琦を屏風の陰から扶け出してまで魯粛に見せ、「公子がおられる限り、一日でもこの地は守られる」と返還要求を退けた。生きた名分の盾として使われたのである。だがその病は重く、嘔血して半年ともたぬと予言された通り、第五十三回に病没する。自らは戦わず、自らは語らず、ただその血筋によって時代の一局面を支えた、儚くも欠かせぬ公子であった。"}, {"id": 181, "name": "公孫康", "faction": 3, "role": "君主", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 3, 3, 3], "p": [2, 2, 1, 4, 3, 4], "scores": {"W": 1.1, "B": 2.75, "S": 2.95, "A": 2.9, "G": 2.49, "K": 2.8}, "stat": {"dmg": 0.87, "area": 1.01, "cd": 1.14, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 3.25, "pwr": 2.9}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [33, 106], "chapN": 2, "bio": "遼東太守、二袁を斬り首を曹操に送る", "profile": "遼東太守。襄平の人で、武威将軍・公孫度の子として、中原から遠く離れた辺境に数万の兵を擁する一勢力を継いだ君主である。槍を振るう猛将でもなければ天下を論じる謀臣でもなく、その評価は生涯ただ一つの政治的決断によって定まる、計算高い辺境の領主として描かれる。\n\nその決断の舞台が第三十三回。官渡・倉亭で敗れた袁紹の遺児、袁熙・袁尚の兄弟が、行き場を失って遼東へ転がり込んでくる。曹操に追われた二袁は、内心では公孫康を殺して遼東を奪う腹積もりでいた。一方、曹操の参謀・郭嘉は死の床から「遼東を急いで攻めてはならぬ、放っておけば公孫康がみずから二袁の首を斬って差し出す」と遺計を残す。世に言う「郭嘉の遺計」だが、本文を読めば公孫康自身も同じ読みに独力で到達していた。彼は属官を集めて謀り、細作を放って曹操の動きを探らせ、「曹兵が攻め寄せれば二袁を盾に留め置く、動かなければ二袁を殺して曹公に献ずる」という条件分岐の策を立てていたのである。郭嘉の予言と公孫康の判断は、別々に同じ結論へ達していた。\n\nそして曹操が動かぬと見るや、公孫康は二袁を席に招き入れる。座を求める袁尚に、目を瞋らせて言い放つ。「貴様らの首は万里を行くのだ、席など何に使う」。伏せておいた刀斧手が躍り出て、その場で二人の首を打ち落とす。首は木匣に納められ、易州の曹操のもとへ送られた。袁尚の「大驚」は、座を求めた直後に殺意を浴びせられた者の驚愕だった。\n\nこの一手の見返りは大きかった。曹操は使者を厚く賞し、公孫康を襄平侯・左将軍に封じた。強者に首を差し出すことで、彼は遼東の自立を確保したのである。武で天下を争うのではなく、状況を読んで生殺を切り替え、辺境一郡を守り抜く──それが公孫康の生き方だった。第百六回に至るまで、その死後も弟の公孫恭が職を継ぎ、一族の地位は保たれた。派手さはないが、誰よりも冷徹に己の生存を計算しきった君主であった。"}, {"id": 182, "name": "諸葛誕", "faction": 1, "role": "武将", "rarity": 2, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [2, 1, 1, 2, 2, 3, 5], "p": [2, 2, 3, 4, 3, 2], "scores": {"W": 1.55, "B": 2.9, "S": 2.9, "A": 2.65, "G": 2.61, "K": 2.9}, "stat": {"dmg": 0.9, "area": 1.07, "cd": 1.09, "amount": 2, "knock": 0.77, "crit": 0.06, "duration": 8.0, "pwr": 3.2}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [43, 55, 60, 72, 76, 110, 111, 112], "chapN": 8, "bio": "魏の鎮東将軍、淮南討伐に参加・後の征東大将軍", "profile": "武侯・諸葛亮の族弟にして、魏に仕えた重鎮。征東大将軍・都督揚州として両淮の軍馬を一手に総攬する。同じ諸葛の血を引きながら蜀ではなく魏に身を置き、しかも演義で唯一、司馬昭の簒奪に正面から牙を剝いた忠義の反乱者として、その名は淮南の地に刻まれる。\n\n事の起こりは、司馬昭の腹心・賈充の打診だった。禅譲への意向を探られた諸葛誕は、きっぱりと撥ねつける。「朝廷に難あらば、吾まさに死を以てこれに報いん」。司馬氏の専横を見抜いた彼は、両淮の屯田戸口十余万を結集し、司馬昭の罪を数え上げる上表を掲げて挙兵した。第百十一回、楽綝の討伐では配下の驍騎が城壁をよじ登って門を開き、城を奪い取る。さらに子の諸葛靚を呉へ人質として送り、孫綝から全懌・全端ら七万の援兵を引き出した。魏室への忠義に殉ずるその志は、まぎれもなく大きかった。\n\nだが諸葛誕は、志の大きさに見合う将ではなかった。第百十二回、司馬昭が牛馬驢騾を野に撒く誘敵の計を仕掛けると、彼は堅城を捨てて野に大軍を駆り出し、まんまと誘い込まれて大敗する。寿春に逃げ込んで籠城するも、頼みは淮水の氾濫を待つだけの後手の策。そのうえ猜疑の心が強く、籠城の苦境を諫めた蔣班・焦彝を「異心ありや」と斬ろうとし、ついには味方の文欽を「我を謀る気か」と斬殺して、内側から人心を瓦解させてしまう。城を巡って「殺すことを威となす」その姿は、敵を恐れさせるどころか自軍を崩す自滅の刃であった。\n\nそれでもなお、彼の人望には光るものがあった。寿春陥落の際、城を出たところを胡遵に斬られ三族みな滅ぼされるという凄惨な最期を迎えるが、その配下数百は一人として降らず、「諸葛公と死を同じうせん、決して汝には降らぬ」と叫んで悉く殉じた。戦術判断は拙く、猜疑が身を滅ぼしたが、死してなお部下を引きつけて離さぬ求心力──それが、簒奪の世に一人立った諸葛の血を引く将の、忘れがたい矜持であった。"}, {"id": 183, "name": "王肅", "faction": 1, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 4, 3, 1], "p": [2, 2, 3, 0, 3, 3], "scores": {"W": 0.0, "B": 2.5, "S": 2.9, "A": 2.95, "G": 2.13, "K": 2.25}, "stat": {"dmg": 0.86, "area": 1.04, "cd": 1.19, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.25, "pwr": 2.85}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [99, 109, 110, 119], "chapN": 4, "bio": "黄門侍郎、長雨での撤兵を上疏", "profile": "魏の朝廷に仕えた文官。黄門侍郎から太尉へと昇り、献策の士として要所に顔を出す。剣を取る場面は一度もなく、その本領はもっぱら時勢を読んだ的確な進言にあった。やがて娘が司馬昭に嫁ぎ、彼自身が簒奪者の岳父となっていくあたりは、司馬氏に静かに取り込まれていく魏官僚の典型でもある。\n\n第九十九回、魏が大挙して蜀へ出兵した折、折からの長雨が陣を泥濘に沈める。王肅は上疏して撤兵を説いた。「千里に糧を饋れば士に飢色あり」と古典を引き、深く険阻に分け入って路を鑿ちながら進む軍の労苦は平地の百倍に及ぶと論じる。そして武王の伐紂、武帝・文帝の征討の先例を挙げ、「悦んで難を犯せば、民はその死を忘る」──兵を労わって時を待ち、後日の隙を衝けと諫めた。魏主はこれを容れ、曹真・司馬懿を還朝させる。兵站の機微を見抜く目と、時勢に従う冷静さが光る一幕である。\n\n第百九回、曹髦が即位する場では礼法を正す。新帝が臣下に答礼しようとすると、「主上は答礼なさるべきではありませぬ」と君臣の名分を諫めた。秩序を守る古典の士としての面目躍如である。\n\nそして第百十回、毋丘儉の乱で淮南が告急すると、司馬師が真っ先に相談を持ちかけた相手が王肅だった。彼はかつて関羽が威を華夏に震わせた折、呂蒙が荊州を襲って将士の家族を撫恤し、それゆえ関公の軍勢が瓦解した故事を引く。「いま淮南の将士の家族は皆中原におります。急ぎこれを撫恤し、さらに兵で帰路を断てば、必ず土崩の勢いとなりましょう」。司馬師は「公の言、きわめて是なり」と容れ、果たして淮南は平定された。自ら布陣も指揮もせぬが、その着眼は常に的を射る。武功とは無縁ながら、王朝の岐路ごとに正しい一手を囁き続けた、影の参謀であった。"}, {"id": 184, "name": "劉岱", "faction": 1, "role": "武将", "rarity": 2, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [3, 2, 1, 2, 3, 2, 3], "p": [1, 1, 2, 2, 2, 2], "scores": {"W": 2.2, "B": 2.8, "S": 2.35, "A": 2.4, "G": 1.58, "K": 1.85}, "stat": {"dmg": 0.79, "area": 0.9, "cd": 1.06, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.15}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [5, 6, 15, 22, 23, 24], "chapN": 6, "bio": "元兗州刺史の曹操配下、王忠と徐州を攻め張飛に生け捕られる", "profile": "かつての兗州刺史にして、後の曹操配下の偏将。反董卓連合に名を連ねた一鎮の諸侯という、いかにも立派な肩書きを持ちながら、演義での実像は肩書きだけが残った凋落型の人物である。\n\n第五回で十七鎮の一に数えられたその出発点はまだ華々しい。第六回には非情の一面ものぞかせる。兗州太守として糧の不足に窮した劉岱は、東郡太守の喬瑁に借糧を求めるが、断られるや軍を率いて喬瑁の営に突入し、これを殺して兵をことごとく降して自軍に編入してしまう。同盟者を斬って糧と兵を奪うこの荒業が、彼の数少ない「戦果」だった。だがそれは奇襲であって武勇ではなく、外交を自らの手で叩き壊した愚行でもあった。\n\nやがて兗州は曹操に奪われ、劉岱は降って一介の偏将に身を落とす。第二十二回、王忠とともに徐州攻めの先陣を任されるが、ここで器の小ささが露わになる。誰が先に攻めるかをめぐって押し付け合い、あろうことか籤引きで決めようと言い出すのである。劉備は「劉岱は昔の兗州刺史、虎牢で董卓を伐った折は一鎮の諸侯であった、軽んじてはならぬ」と一応持ち上げるが、張飛は「この程度の輩、論ずるに足りぬわ」と一蹴した。その評は的中する。王忠が擒えられたと知った劉岱は堅く守って出ようとせず、毎日寨前で罵る張飛の声を聞いては、ますます出る勇気を失っていく。\n\n結末はあっけない。張飛の偽の劫寨の計にまんまと乱され、潰走する中で残兵を率いて血路を開こうとしたところ、よりにもよって張飛と狭い道で鉢合わせ、馬を交えてわずか一合で生け捕られてしまう。曹操は斬ろうとしたが、孔融が「二人はもとより劉備の敵ではない、斬れば将士の心を失いましょう」と諫めたため、命だけは助かり、爵禄を奪われて放逐された。自力で危機を切り抜けたことは一度もなく、最後まで他者の手の上で転がされた──「一鎮の諸侯」の看板だけが、空しくその名に残った将である。"}, {"id": 185, "name": "毋丘儉", "faction": 1, "role": "武将", "rarity": 2, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [2, 1, 1, 2, 3, 3, 2], "p": [1, 1, 1, 2, 3, 2], "scores": {"W": 1.55, "B": 2.6, "S": 2.85, "A": 2.85, "G": 1.53, "K": 1.95}, "stat": {"dmg": 0.82, "area": 0.97, "cd": 1.11, "amount": 2, "knock": 0.77, "crit": 0.06, "duration": 6.8, "pwr": 2.45}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [108, 109, 110], "chapN": 3, "bio": "魏の鎮東将軍、司馬師の廃立に反し挙兵", "profile": "揚州刺史・鎮東将軍。魏の方面を預かる将でありながら、演義では珍しく、台頭する司馬氏に正面から反旗を翻した人物として描かれる。河南聞喜の出。志は大きく、しかし決断の鈍さがその志を裏切った、悲運の挙兵者である。\n\n第百八回、東興の役では諸葛恪の退却に乗じ、大兵を起こして掩殺し、呉兵を大敗させる働きを見せた。だが彼の名が歴史の表舞台に立つのは第百十回である。司馬師が斉王・曹芳を廃して帝を立て替えるその専横に憤った毋丘儉は、「太后の密詔を奉ず」と称し、文欽とともに「仗義討賊」の旗を掲げて淮南に六万を挙兵した。司馬師は大逆不道であると宣言し、諸郡へ檄を移して共同決起を呼びかける。簒奪に真っ向から抗するその構想の規模は、群小の武将とは比べものにならない。\n\nしかし旗の下の実態は脆かった。掲げた密詔は詐称であり、檄に応じる郡もない。魏の謀臣・鄭褒は毋丘儉を「好謀にして無断」──謀を好むが決断できぬ、と看破した。その評の通り、彼は項城に屯して動けぬうちに南頓を司馬師に先取りされ「施すべき計なし」と立ち往生し、樂嘉の攻めは文欽父子に丸投げして敗れる。さらに王基には「淮南の反は民が乱を望むにあらず、皆毋丘儉の勢力に逼られて已むを得ず従うのみ。大軍が臨めば必ず瓦解する」と、その軍の本質まで見抜かれていた。果たして司馬師・鄧艾・王基・胡遵の四面の挟撃を受け、先鋒の葛雍は鄧艾に一合で斬られ、江淮の兵は大乱に陥る。\n\n主役の座は、単騎で魏軍を退ける息子の文鴦に奪われたまま、毋丘儉は十数騎で戦場を落ち延びていく。たどり着いた慎県では、県令の宋白が門を開いて迎え入れた。だがそれは罠だった。宴に招かれて大いに酔い、油断したところを討たれ、その首は司馬氏へ献じられる。仗義の旗を立てながら、決断の遅さと偽りの名分ゆえに衆を結びきれず、自滅していった──志ばかりが大きく、実を結ばなかった敗将であった。"}, {"id": 186, "name": "王朗", "faction": 1, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [3, 2, 1, 1, 2, 2, 2], "p": [2, 3, 1, 3, 4, 2], "scores": {"W": 2.1, "B": 2.05, "S": 1.95, "A": 1.9, "G": 2.43, "K": 2.8}, "stat": {"dmg": 0.76, "area": 0.94, "cd": 1.09, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 1.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [15, 56, 79, 80, 91, 93, 97], "chapN": 7, "bio": "銅雀台で詩を献じた文官", "profile": "魏の文官。會稽太守から司空、司徒へと上り詰めた老臣で、後世には「孔明に罵り殺された道化」として記憶される。だが本文を丹念に追えば、その像はもう少し奥行きを持つ。前半は剣を取って戦う武人の一面すら見せ、中盤は曹丕の禅譲を理論で支える魏の中核文官、後半は人事と国策に口を挟む重臣として描かれる。実務に通じた老練の士が、最後の一席で全てを台無しにした──それが王朗の生涯である。\n\n意外なのは第十五回。會稽太守だった王朗は、攻め寄せる孫策の軍に対し、自ら馬を駆って刀を舞わせ、猛将・太史慈と斬り結ぶ。文官にしては破格の白兵描写だが、数合で味方の周昕が加勢に出るほどで、寡兵では衆に敵わず、血路を開いて城へ逃げ込むのが精一杯だった。剣を取る男ではあったが、剣で名を成す男ではなかった。\n\n彼の真価は弁と筆にある。第七十九・八十回、曹丕が漢から帝位を受ける場面で、王朗は「漢室相伝四百余年、いま陛下に至りて気数すでに尽きたり、早く退避すべし、遅れれば変を生ず」と漢の退位を督促し、禅譲の表を起草するなど、新王朝の正統化を一身に担うイデオローグとして働いた。朝廷では曹真を大都督に推挙し、また経戦の経験なき夏侯楙の起用には反対するなど、人事への目配りも見せている。\n\nだが彼の名を不滅にしたのは、その最期である。第九十三回、軍師として孔明との対陣に臨んだ王朗は、「老夫みずから出て、ただ一席の話で、諸葛亮をして手を拱いて降らしめてみせよう」と豪語した。陣前に進み出て、桓帝・霊帝以来の乱から曹魏の天命へと至る天下の趨勢を滔々と説く。しかし孔明の舌鋒はそれを完膚なきまでに打ち砕き、辱められた老臣は怒りと羞恥に堪えかね、馬から落ちて息絶えた。屍は棺に納められ、長安へ送り返された。先見も実務も備えながら、最後にただ一度の弁論勝負を見誤って命を落とす──その鮮烈な幕切れが、王朗という人物の全てを上書きしたのである。"}, {"id": 187, "name": "李肅", "faction": 3, "role": "武将", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 1, 1, 1, 4, 2, 2], "p": [1, 2, 1, 6, 2, 3], "scores": {"W": 1.45, "B": 2.85, "S": 2.45, "A": 2.6, "G": 2.32, "K": 2.0}, "stat": {"dmg": 0.84, "area": 1.0, "cd": 1.1, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 2.6}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [3, 5, 9], "chapN": 3, "bio": "董卓配下、赤兎馬で呂布を寝返らせる虎賁中郎将", "profile": "董卓配下の虎賁中郎将。武将の職にありながら、その武器は槍でも戟でもなく、巧みな弁舌だった。人の心の隙を読み、偽詔をもって相手を動かす──説得と離間にかけては群を抜く、実務型の遊説家である。\n\n李肅の名を高めたのは、第三回の呂布調略である。董卓が呂布を欲したとき、李肅は名馬・赤兎と黄金珠玉を手土産に、呂布のもとへ乗り込んだ。呂布とは同郷のよしみ。酒席で巧みに語を継ぎ、「良禽は木を択びて棲み、賢臣は主を択びて事う。機を見ること早からざれば、悔ゆとも晩し」と心理を突く。果たして呂布は養父の丁原を斬り、董卓のもとへ走った。馬一頭と弁舌一つで、当代無双の猛将を寝返らせてみせたのである。\n\nその手腕は第九回でも光る。王允・呂布が董卓誅殺を企てたとき、董卓に官職を遷されぬ恨みを抱く李肅が適任と見込まれ、偽詔の使者に立った。「天子は病が癒え、未央殿に文武を会して太師に禅位せんと議しておられます」──この甘言に董卓は喜んで信じ、郿塢から誘い出される。そして禁中で呂布の戟が董卓の咽喉を貫いた直後、李肅はすかさず首を斬り取って手にした。董卓を斬る一手にも、彼は確かに加わっている。\n\nだが弁の冴えとは裏腹に、将としての李肅は凡庸だった。董卓誅殺の後、五万を率いて牛輔に当たるも、夜襲を受けて軍は乱れ散り、三十余里を敗走して軍の大半を失う。呂布のもとへ逃げ帰ると、「貴様、味方の鋭気を挫いたな」と大いに怒られ、斬られて首を軍門に懸けられた。二度までも人を寝返らせた稀代の遊説家は、いざ兵を統べると脆くも崩れ、その雄弁を惜しまれることもなく消えていった。"}, {"id": 188, "name": "秦宓", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 2, 0], "p": [2, 0, 0, 7, 6, 5], "scores": {"W": 0.1, "B": 0.35, "S": 1.25, "A": 1.1, "G": 2.87, "K": 2.85}, "stat": {"dmg": 0.66, "area": 0.88, "cd": 1.25, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.0, "pwr": 1.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [65, 80, 81, 86], "chapN": 4, "bio": "広漢綿竹人。簡雍を叱責した蜀中の人物", "profile": "蜀漢に仕えた益州の学士。広漢綿竹の人で、剣も馬も知らぬ純然たる文人だが、その舌は刃よりも鋭かった。武功の記録はただの一つもなく、彼の見せ場はすべて言葉の戦場にある。命を懸けた諫言と、国の威信を背負った弁論──この二場面に、秦宓という人物のすべてが凝縮されている。\n\n第八十一回。関羽の仇を討たんと、劉備が全軍を挙げて呉へ東征しようとしたとき、秦宓は身を投げ出して諫めた。「陛下は万乗の身を捨てて小義に殉ぜんとなさる。これは古人の取らざるところ。願わくは思い直されませ」。地に伏して退かぬその姿に劉備は激怒し、斬罪を申し渡す。だが秦宓は顔色一つ変えず、振り返って笑いながら言った。「臣、死すとも恨みはありませぬ。ただ惜しむらくは、新たに創った基業がまた覆らんとすることのみ」。胆は微塵も揺らがず、見据えていたのは自分の命ではなく新興国家の存亡だった。その諫言の正しさは、やがて夷陵の大敗によって証明されることになる。\n\nそしてもう一つが、第八十六回の天弁である。呉蜀通好の使者として訪れた呉の名士・張溫が、酒席で蜀の格を試そうと難問を浴びせる。「天に頭はあるか」「天に耳はあるか」「天に姓はあるか」。秦宓は『詩』を引いて澱みなく答え、姓を問われれば「劉なり、天子の姓は劉、ゆえに天に姓ありと知る」と返した。漢室劉氏こそ天の正統という蜀漢の大義名分を、機知の一言に込めてのける。その語り口は清朗、答問は流れるごとく、満座は驚き静まった。さらに秦宓は逆に問い返す。「共工氏が天柱を折ったとき、なにゆえ天は西北に傾いたのか」。張溫は言葉に詰まり、席を避けて謝した。演義屈指の弁論勝利であった。\n\n武の場には一度も立たず、軍を率いることも知らぬ。それでも秦宓は、言葉だけで君主の暴走に抗い、言葉だけで一国の威信を守ってみせた。蜀中の知に、こういう士がいた──そう思わせる、痛快無比の弁舌の人である。"}, {"id": 189, "name": "文欽", "faction": 1, "role": "武将", "rarity": 2, "weapon": "mace", "kind": "nova", "weaponName": "剛", "d": [2, 3, 1, 2, 3, 2, 3], "p": [1, 2, 1, 2, 3, 2], "scores": {"W": 1.95, "B": 2.7, "S": 2.35, "A": 2.4, "G": 1.73, "K": 2.35}, "stat": {"dmg": 0.75, "area": 0.91, "cd": 1.1, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 1.85}, "title": "剛の将", "skill": "剛", "skillDesc": "周囲を吹き飛ばす衝撃", "voice": "", "hist": "", "chapters": [109, 110, 111, 112], "chapN": 4, "bio": "揚州刺史、毋丘儉と挙兵・後に呉へ投降", "profile": "魏の揚州刺史。「勇」のラベルを背負いながら、その勇の見せ場をことごとく息子に奪われた、不遇の将である。世には単騎で魏軍を退ける猛将・文鴦の父として知られるが、演義本文の文欽自身は、武勇の実演をほとんど与えられず、最後は味方の手にかかって果てる受動的・悲劇的な人物として描かれる。\n\n第百十回、毋丘儉が司馬師の廃立に憤って淮南に挙兵すると、文欽は「死を捨てて相助けん」と馳せ参じ、自軍二万を遊兵として往来接応する任に就いた。樂嘉の魏営を夜襲する策が立てられるが、それを発案したのは「萬夫不当の勇」を持つ息子の文鴦であり、文欽はただ「これに従う」だけ。しかも当の文欽は山路の険しさに迷い込み、谷中をさまよって夜を明かし、戦果を挙げることなく「戦わずして退いた」。武勲は丸ごと、北壘へ斬り込む息子のものとなった。彼に与えられた武評は、魏の鄭褒が下した「文欽は勇あれども智なし」の一言に尽きる。勇の名はあるが、智と並べて貶められる勇だった。\n\n敗走した文欽は東呉の孫峻に身を投じ、後には呉軍の郷導として再起を図り、諸葛誕の挙兵に呼応して寿春へ入る。だがその結末は、味方の刃という最も惨いものだった。第百十二回、寿春の籠城は糧草が尽き果て、兵卒は飢えに損なわれていく。文欽は現実的な策を進言する。「北方の兵をことごとく城外へ放ち、その食を省くべし」。だがこの言いようが諸葛誕の猜疑を招いた。「貴様、我に北軍をすべて去らせ、我を謀ろうという気か」──諸葛誕は大いに怒り、文欽を引き出して斬らせた。\n\n兵糧を保たせるための真っ当な策が、進言の仕方ひとつで身の破滅を招いた。勇将と呼ばれながらその勇を証す機会に恵まれず、反乱の道具として用いられ、最後は仲間に疑われて命を落とす。文欽の生涯は、息子の光に照らされてなお影に沈む、報われぬ父の物語であった。"}, {"id": 190, "name": "孫峻", "faction": 2, "role": "武将", "rarity": 2, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [4, 2, 1, 3, 2, 1, 2], "p": [1, 2, 1, 1, 2, 1], "scores": {"W": 2.75, "B": 2.1, "S": 1.45, "A": 1.6, "G": 1.33, "K": 1.7}, "stat": {"dmg": 0.85, "area": 0.92, "cd": 1.05, "amount": 1, "knock": 0.82, "crit": 0.07, "duration": 0, "pwr": 2.7}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [30, 33, 108, 110, 111, 113], "chapN": 6, "bio": "孫静の曾孫、諸葛恪を謀殺し丞相大将軍に", "profile": "孫峻、字は子遠。呉の祖たる孫堅の弟・孫静の曾孫にあたる宗室の出で、孫恭の子である。生前の孫権に深く愛され、御林の軍馬を掌る要職を任された、いわば皇族の信任を一身に集めた近衛の将であった。\n\nその名が演義に刻まれるのは第百八回、太傅・諸葛恪を斬るただ一幕に尽きる。専権をふるい公卿を害して不臣の心を抱く諸葛恪を、太常卿の滕胤が憎み、「公は宗室の身、何ぞ早く図らざる」と孫峻をそそのかす。孫峻は「我れ是の心あること久し」と応じ、天子孫亮に奏して誅戮の勅を請うた。計は決した。宴席に諸葛恪を招き、壁の帷の内に武士を伏せ、杯を擲つを合図とする。場が整うと孫峻は殿を下りて長服を脱ぎ、短衣の下に環甲を着込み、利刃を提げて殿に上がるや大喝した。「天子に詔あり、逆賊を誅す」。諸葛恪は驚いて杯を地に擲ち、剣を抜いて迎えようとしたが、その首はすでに地に落ちていた。傍らの張約が斬りかかると、孫峻は身を翻して一刀、その右腕を断ち、武士たちが一斉に湧き出て張約を肉泥となるまで斬り刻んだ。\n\nこの一撃をもって、呉の権柄はことごとく孫峻の手に帰した。孫亮は彼を丞相大将軍・富春侯に封じ、中外諸軍事を総督させる。しかし演義が描く孫峻は、戦場で兵を率いる名将でも国を構える政治家でもない。第百八回の末には、諸葛恪の妻の侍女に怨霊が憑き、「吾は諸葛恪なり、奸賊孫峻に謀殺さる」と叫ぶ怪異が記され、その権勢は畏れと怨みの色を帯びていた。\n\n第百十回では壽春へ兵を渡し襲うとの一報があるのみで、戦果は語られない。第百十一回、孫峻は病に倒れて世を去り、権は従弟の孫綝へと横滑りしていった。さらに第百十三回では、その墳墓が掘り暴かれ、屍が戮される末路まで描かれる。演義における孫峻とは、権臣というより、一刀をもって主を斬り権を奪い、ほどなく自らも怨みの中に消えた、簒奪の刺客の像なのである。"}, {"id": 191, "name": "邢道榮", "faction": 3, "role": "武将", "rarity": 2, "weapon": "axe", "kind": "arc", "weaponName": "斧", "d": [2, 3, 4, 2, 3, 1, 2], "p": [1, 1, 1, 2, 1, 1], "scores": {"W": 2.7, "B": 2.3, "S": 1.65, "A": 1.85, "G": 1.15, "K": 1.2}, "stat": {"dmg": 0.85, "area": 1.03, "cd": 1.11, "amount": 1, "knock": 0.98, "crit": 0.06, "duration": 0, "pwr": 2.75}, "title": "斧の将", "skill": "斧", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [52], "chapN": 1, "bio": "零陵の猛将。開山大斧を使うが趙雲に討たれる", "profile": "邢道榮は、零陵太守・劉度に仕えた一郡の武将である。手にするは開山大斧、主君の子・劉賢からは「本州上邢道榮、力は万人に敵し、以て抵対すべし」と頼みの綱として称えられた、零陵随一を謳われた猛者であった。\n\nその勇名がためされるのは第五十二回、ただ一度きりである。劉賢とともに万余の兵を率い、城を離れること三十里、山に依り水を靠にして寨を構えた。邢道榮は馬を出し、開山大斧を提げて声を励まし叫ぶ。「反賊、安んぞ敢えて我が境界を侵すか」。だが立ち向かった張飛と戦うこと数合、たちまち気力およばず、馬首を返して逃げ出した。逃げる先に立ちふさがる将が大喝する。「常山の趙子龍を認め得るか」。邢道榮は敵わぬと悟り、逃げ場もなく、馬を下りて降を請うほかなかった。\n\nいったん趙雲に降ってからは、劉賢のもとへ戻って「計を将て計に就く」伏兵の策を進言する。だがその計は孔明にことごとく看破され、罠は逆しまに自らを縛る。最後は趙雲の一槍に貫かれ、馬下に討たれて果てた。「力は万人に敵す」と謳われながら、実戦では一度も善戦を見せられなかった――触れ込みと実態の落差こそが、演義における邢道榮の姿である。"}, {"id": 192, "name": "徐母", "faction": 3, "role": "婦人", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 1, 3, 0, 0, 0], "p": [0, 0, 0, 0, 8, 3], "scores": {"W": 0.55, "B": 0.15, "S": 0.15, "A": 0.3, "G": 1.4, "K": 2.85}, "stat": {"dmg": 0.58, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.82, "crit": 0.07, "duration": 2.5, "pwr": 0.3}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [36, 37], "chapN": 2, "bio": "徐庶の母、節義を貫き縊死", "profile": "徐母は、劉備の知謀の臣・徐庶の母である。武勲も官職もなき一個の婦人でありながら、演義屈指の烈女として、その名は重く刻まれている。\n\n第三十六回、曹操は徐庶の才を惜しみ、孝心篤いその母を人質に取って息子を呼び寄せようと図る。だが面前に引き出された徐母は怯まなかった。「汝は名を漢相に託すといえども、実は漢賊たり。乃ち反って玄徳を以て逆臣と為し、吾が児をして明を棄て暗に投ぜしめんと欲す。豈に自ら恥じざらんや」――曹操を漢室を簒う賊と看破し、劉備こそ中山靖王の後・孝景皇帝の玄孫たる漢室の正統と言い切ったのである。言い終わるや石硯を取って曹操に投げつけた。曹操は激怒し、武士に命じて引き出し斬らせようとする。臣の程昱が「丞相に触忤するは、死を求むるなり」と諫めて、辛うじて刑は止まった。徐母のその一身からほとばしる気迫は、覇者曹操を斬刑の寸前まで追い込むほどであった。\n\nその剛直は、息子をも容赦しなかった。やがて偽りの書状に騙された徐庶が曹操のもとへ赴いてしまうと、徐母は息子を「明を棄て暗に投じた愚夫」と痛烈に叱責する。\n\nそして第三十七回、ある日家人が報じた。「老夫人、梁間に縊る」。偽書に欺かれた息子の汚名が祖宗の名を穢すことを恐れ、自ら命を断ったのである。一介の婦人が命を賭して漢室の正統を証言し、家の名誉を守って死す――武も政も持たぬながら、義と節をもって演義に屹立する、母の姿である。"}, {"id": 193, "name": "雷同", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 1, 1, 1, 4, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.9, "B": 2.8, "S": 1.85, "A": 2.1, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.76, "area": 0.87, "cd": 1.06, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.9}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [62, 63, 64, 65, 69, 70], "chapN": 6, "bio": "劉璋配下の副将、降伏後は蜀将として張飛と従軍、瓦口で張郃に討たれる", "profile": "雷同は、もとは益州牧・劉璋に仕えた武将である。演義では常に呉蘭と一対で「呉蘭、雷同」と並び称される副将として現れ、劉璋配下では雒城防衛戦の一翼を担った。雒城が陥ちた後は劉備に降り、降った文武の一人として重賞を受け、名爵を定め擬せられて、蜀漢の将に列なった。\n\n降ってのちは張飛の配下となり、その戦ぶりに一段の見せ場が訪れる。第七十回、巴西に魏の張郃が攻め寄せると、雷同は自ら地形を読んで進言した。「閬中は地悪しく山険なり、以て埋伏すべし」。続けて「我れ奇兵を出して相助けば、郃は擒にすべし」と奇兵の計を献ずる。張飛はこれを容れ、精兵五千を割いて雷同に授けた。果たしてこの策は機能する。張飛が後ろから掩殺すれば、前面からは雷同が兵を引いて殺し出で、両下より挟み攻めて「郃の兵大いに敗る」――張郃を初戦で打ち破ったのである。単なる雑兵ではなく、奇兵戦術を発案する一面を演義が与えた中堅の将であった。\n\nだが詰めは甘かった。張郃は詐り負けて伏兵を仕掛ける。その計を見抜けなかった雷同は罠に乗せられ、ついに張郃の槍に「雷同を馬下に刺す」一突きで討たれて果てた。怒った張飛が後を追って報讐する。地形を読む眼を持ちながら、敵の偽計に沈んだ――それが演義に描かれた雷同の最期である。"}, {"id": 194, "name": "諸葛瑾", "faction": 2, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 3, 3, 3], "p": [1, 3, 1, 7, 2, 3], "scores": {"W": 0.0, "B": 2.55, "S": 2.85, "A": 2.7, "G": 2.67, "K": 2.4}, "stat": {"dmg": 0.85, "area": 1.01, "cd": 1.18, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.25, "pwr": 2.7}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [37, 43, 44, 66, 73, 76, 81, 82, 85, 98], "chapN": 18, "bio": "孫権の参謀、孔明の実兄。弟を説得しようとして逆に説かれる", "profile": "諸葛瑾、字は子瑜。瑯琊南陽の人で、かの諸葛亮の実兄にあたる。博学多才にして母に孝なること至れりと評され、第二十九回、魯粛の推挙によって孫権に見え、上賓として迎えられた。以後、呉の朝廷にあって対蜀・対関羽外交を一手に担う専任の使者として、演義に幾度も登板する文官である。\n\nその登板はいずれも要所に集中する。第六十六回には荊州返還の交渉に立ち、第七十三回には関羽との縁談を持ちかけるが、「虎の女を豈に犬の子に嫁がせんや」と一蹴される。第七十六回には麦城に孤立した関羽の招降に向かい、ここでも「汝が弟の面を看ざれば、力めて汝が首を斬らん」と退けられた。圧巻は第八十一・八十二回、夷陵に向け呉を伐たんとする劉備への罷兵説得である。「陛下は乃ち漢朝の皇叔なり。今、漢帝すでに曹丕に篡奪さる。剿除を思わず、却って異姓の親の為に万乗の尊を屈す。是れ大義を捨てて小義に就くなり」――漢室の論理をもって正面から説く弁舌は、外交弁論の格の高さを示す。だが交渉はことごとく決裂し、成約に至った例はついになかった。\n\n軍事においては、第八十五回に陸遜の副将格として南郡に伏兵を置き、内外呼応して曹真・夏侯尚を破る分け前を得た。しかし第百三回では単独で滿寵の夜襲を受け、呉兵慌乱して戦わずして走り、敗兵を率いて沔口へ逃げる潰走を喫している。彼の真価は能力よりも人格にあった。「誠実の君子」「真の忠臣なり」と評され、弟が蜀に仕えてもなお「弟すでに玄徳に事う、義は二心無し。弟の留まらざるは、なお瑾の往かざるがごとし」と忠を疑われぬ人物として、孫権から「生死易えざるの盟」「神交」と最大級の信任を寄せられた。\n\n人を見る眼もあった。第百八回には、わが子・諸葛恪の才が外に露わなのを見て、「此の子は家を保つの主に非ず」と将来の破滅を嘆じている。果たして恪は後に誅殺され、その予見は的中した。能力ゆえでなく、その誠と忠ゆえに重んじられた――それが演義における諸葛瑾の像である。"}, {"id": 195, "name": "蔣濟", "faction": 1, "role": "軍師参謀", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 3, 3, 2], "p": [1, 2, 0, 2, 0, 5], "scores": {"W": 0.1, "B": 2.35, "S": 2.8, "A": 2.75, "G": 1.52, "K": 1.7}, "stat": {"dmg": 0.85, "area": 1.01, "cd": 1.19, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.25, "pwr": 2.7}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [75, 86, 107], "chapN": 3, "bio": "曹丕呉征の参謀", "profile": "蔣濟は、魏に仕えた文官・参謀である。演義では一貫して献策する幕僚として現れ、武勇や一騎打ちの記録は持たない。司馬懿に並んで朝政を支え、ことに晩年の政変では重きをなした能吏として描かれる。\n\nその登場は要所に三度。第七十五回、主簿として、関羽の背後を呉に突かせる司馬懿の連呉策に賛同し、「仲達の言は是なり。今すぐ使を東呉に発すべし、遷都して衆を動かすに及ばず」と即断で後押しする。第八十六回には、曹丕の南征に劉曄とともに参謀として従う。そして第百七回、高平陵の政変――司馬懿が曹爽を打倒したクーデターの核心に、太尉として参画した。\n\nこの第百七回こそ、蔣濟の最も光る場面である。司馬懿に急かされて尚書令・司馬孚とともに弾劾の上奏文を起草し、黄門に持たせて城外の天子のもとへ送り届けた。曹爽が智謀の士・桓範を用いようとしないのを見て取り、「駑馬は棧豆を恋う、必ず用うる能わざるなり」と看破する。飼い葉桶のまぐさに未練を残す駄馬のごとく、曹爽は安逸を捨てられぬと喝破したのである。果たしてその読みは当たり、蔣濟は洛水の誓いの連名者として政変を成功へと導いた。\n\n人を見る眼も備えていた。司馬懿と並んで、若き日の鍾会の才を見抜き、これを称えている。独自の国家構想や民政の事績こそ本文に描かれないが、司馬懿を補佐して情勢を読み、実務を処理する――そうした堅実な参謀として、蔣濟は演義に位置づけられている。"}, {"id": 196, "name": "劉璋", "faction": 3, "role": "君主", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 1, 0, 0, 1, 2, 2], "p": [1, 2, 3, 3, 5, 2], "scores": {"W": 0.2, "B": 1.25, "S": 1.65, "A": 1.45, "G": 2.5, "K": 2.75}, "stat": {"dmg": 0.71, "area": 0.91, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.45}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [16, 21, 38, 54, 56, 59, 60, 61, 62, 63], "chapN": 15, "bio": "益州牧、劉焉の子。懦弱で劉備を援軍に招き入れる", "profile": "劉璋、字は季玉。父・劉焉の跡を継いだ益州牧であり、漢の魯恭王の血を引く宗室である。蜀の沃野「天府の地」を領し、「民殷んに国富む」と繰り返し称される豊かな土地を治めた一方の君主であった。その人物像は、単なる暗愚というよりも、過度の温情と決断の鈍さが亡国を招いた仁弱の君として、演義に描かれている。\n\nその器量は、しばしば天下の英傑から低く評された。第二十一回、曹操は劉備との対話の中で「劉璋は宗室なりといえども、乃ち戸を守るの犬のみ、何ぞ英雄たるに足らんや」と切り捨てる。孔明もまた益州を「徳政挙がらず、威刑粛まらず」と断じた。臣下の張松からは「季玉は益州の地有りといえども、稟性暗弱にして、賢に任じ能を用うる能わず」と評され、その評の通り、彼は有能の士を御することができなかった。黄権が諫言の途中で門歯を二本も落とされてなお従わず、王累は城門に逆さ吊りとなり死をもって諫めた。それでも劉璋は「吾が意すでに決す、汝何ぞ吾に逆らう」と忠言を退け続けたのである。\n\n亡国の引き金は、第六十回、張松の進言を容れて劉備を外援に招き入れたことであった。黄権・王累はこれを「虎を引きて室に入る」と看破して諫めたが聞き入れられず、ついに四十一州を失う自滅の道を開いた。馬超が来襲した折には「驚いて面、土色のごとく、城上に気倒る」と気絶するばかりで、戦は配下の張任や冷苞らに委ねるほかなかった。さらに有効策をも自ら潰している。鄭度が献じた堅壁清野――民を遷し田野を焼いて敵を兵糧攻めにする焦土戦を、「動民以備敵」として拒み、百姓を遷さなかった。\n\n最後の選択にこそ、その人柄が表れる。成都には兵三万、一年を支えるだけの銭帛糧草がなお残っていた。それでも劉璋は籠城を選ばなかった。「吾が父子蜀に在ること二十余年、恩徳の以て百姓に加うる無し。攻戦三年、血肉を草野に捐つ、皆な我が罪なり」と自らを責め、「降を投じて以て百姓を安んずるに如かず」と城を開いたのである。仁弱が国を滅ぼし、その同じ仁が民の犠牲を止めた――奪われる側の宗室として、演義に刻まれた君主の像である。"}, {"id": 197, "name": "張繡", "faction": 1, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 2, 1, 1, 3, 2, 3], "p": [1, 2, 1, 3, 3, 2], "scores": {"W": 1.65, "B": 2.65, "S": 2.3, "A": 2.3, "G": 1.88, "K": 2.35}, "stat": {"dmg": 0.73, "area": 0.88, "cd": 1.1, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.6}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [16, 17, 18, 21, 23, 60, 65, 68, 91, 120], "chapN": 10, "bio": "賈詡の進言で曹操に降る西涼出身の群雄", "profile": "張繡は、叔父・張済の遺した軍勢を継ぎ、名軍師・賈詡を謀士に擁して宛城に拠った一方の群雄である。やがて賈詡の進言によって曹操に降り、揚武将軍に封ぜられた。世には「曹操に二度勝ち、その長子曹昂と猛将典韋を死なせた男」として知られるが、演義を読めば、その勝利の頭脳はことごとく賈詡に負っていたことがわかる。\n\n事の起こりは第十六回、劉表と結んで宛城に屯し、いったん曹操に降りながら夜襲をかけて曹軍を破ったことであった。だがこの宛城の夜襲も、第十八回の再攻略も、安眾での追撃も、発案はすべて賈詡の計である。張繡は「繡喜びて其の計に従う」「繡之を信ず」と従って実行する役にとどまった。彼自身の武勇はといえば、第十七回に曹操が許褚を出陣させると、張繡は配下の張先を出して迎え戦わせたが、わずか三合で張先は許褚に斬り落とされ、繡の軍は大いに敗れている。本人が名のある敵将を討つ場面は、ついに一つもない。第十八回には「親ら勇壮を駆りて殺し来り」曹軍を数十里追い崩す統率は見せるものの、その勝敗の鍵は常に賈詡の判断が握っていた。\n\nその評価も芳しくはない。第二十一回、劉備が「張繡・張魯・韓遂らの輩はいかに」と問うと、曹操は掌を撫って大笑し、「此らは碌々たる小人、何ぞ歯に挂くるに足らん」と一蹴している。\n\n身の処し方の妙は、最後に発揮された。曹操とは、叔父の妻を奪われ典韋・曹昂を死なせた仇敵の間柄である。それでも袁紹強く曹操弱しと見えた危機の局面で、賈詡の説く三つの利を容れ、袁紹の招安使を退けて曹操へ降る道を選んだ。許都に至って曹操に拝謁すると、曹操は急ぎ扶け起こし、その手を執って「小過失あり、心に記する勿れ」と言い、揚武将軍に封じた。演義巻末の総括詩には、陶謙・公孫瓚と並んで「各々雄才を逞しくして一方を占む」と記される。賈詡という名軍師を抱え、その計に言聴計従して身を保った――それが演義における張繡の姿である。"}, {"id": 198, "name": "李傕", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 2, 1, 3, 2, 3, 2], "p": [2, 2, 1, 2, 3, 2], "scores": {"W": 1.85, "B": 2.2, "S": 2.65, "A": 2.6, "G": 1.95, "K": 2.3}, "stat": {"dmg": 0.75, "area": 0.92, "cd": 1.13, "amount": 1, "knock": 0.82, "crit": 0.07, "duration": 0, "pwr": 1.8}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [3, 5, 6, 9, 10, 11, 13, 14, 17, 57], "chapN": 11, "bio": "董卓配下の将、長安を犯し政権を握る", "profile": "李傕は、董卓配下の将であり、董卓亡き後にその後継として長安を犯し、天子を擁して一時の権を握った男である。世には暴虐の賊魁として知られるが、演義を精読すれば、その権勢の土台は自身の武略ではなく、賈詡の献策に乗ったところから始まっている。\n\n董卓が呂布に討たれ、その残党が散ろうとしたとき、活路を開いたのは賈詡の一言であった。「事済らば、朝廷を奉じて以て天下を正す。若し其れ勝たずんば、走るもまた遅からず」――陝の人々を糾合して長安へ攻め込めという策である。李傕は「然り、其の説」とこれに乗り、長安を陥として朝政を秉る道に入った。呂布との戦いにおいてすら、真っ向勝負を避けて谷口に拠り、毎日誘い出して疲弊させる戦法を採る。その馬騰・呂布相手の勝因も、すべて賈詡の「深溝高塁」「重爵で釣る」献策によるものと、本文は明記している。第十三回には自ら「吾に呂布を敗るの大功あり、輔政すること四年、多く勲績を著す、天下共に知る」と誇るが、直後に皇甫酈から羿の故事を引いて滅亡を予言され、その自負は即座に論破された。\n\n掌権ののちの治世は、破壊そのものであった。郭汜との内訌に陥り、妻の嫉妬を突いた反間の計に易々と乗って、天子を奪い合う。長安では五十余日にわたって市街戦を続け、死者は数知れず、居民を擄掠した。天子に対しては腐肉と朽ちた糧しか与えず、献帝が「逆賊、直に此のごとく相欺くか」と罵り、楊彪が「傕は性残暴、その鋒に攖るべからず」と諫めるほどの凶暴ぶりであった。女巫の妖術を信じて重く賞し、命がけで戦った将兵には恩賞を与えなかったため、騎都尉の楊奉は「吾ら出生入死、身に矢石を冒す、功反って女巫に及ばざるか」と怒って離反する。賈詡が羌兵に密かに帰郷を勧めると軍心は次第に渙散し、配下からは降る者が相次いだ。\n\n人を御することもできなかった。讒言一つを信じ、韓遂を見逃した樊稠を宴席で「樊稠、何故に韓遂と交通し、謀反せんと欲す」と難じ、刀斧手に斬らせて兵を奪う。やがて諫める賈詡には剣を抜いて斬ろうとし、賈詡を出奔させた。猜疑による粛清が自陣営の結束をさらに蝕んでいったのである。第十七回、李傕はついに段煨に斬られ、一族二百余口が処刑された。危機を自ら拡大し、何一つ残せず滅んだ――それが演義に描かれた、無謀にして自滅する賊の像である。"}, {"id": 199, "name": "吳懿", "faction": 0, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 2, 1, 1, 3, 2, 3], "p": [1, 1, 1, 1, 3, 2], "scores": {"W": 1.65, "B": 2.65, "S": 2.3, "A": 2.3, "G": 1.38, "K": 2.15}, "stat": {"dmg": 0.73, "area": 0.88, "cd": 1.1, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.6}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [62, 63, 64, 65, 77, 91, 98, 99, 100, 101], "chapN": 13, "bio": "劉璋の舅。雒城防衛後に降伏", "profile": "吳懿は、もとは益州牧・劉璋の舅にあたる外戚であり、雒城防衛戦ののち劉備に降って蜀漢の将となった武人である。演義では、孔明の密計を吳班とセットで受領し、伏兵や橋焼き、割麦の援護を担う旅団指揮官として描かれる。\n\nその個人武を象徴するのが、第六十四回の一騎打ちである。劉璋方として雒城に拠っていた吳懿は、ただ一度だけ自ら刃を交えるが、立ちはだかった常山の趙雲に槍を挺して馬を躍らせ来られ、わずか「只だ一合」で生擒されてしまう。趙雲は吳懿を縛って劉備の前に引き出した。劉備が「汝降るや否や」と問うと、吳懿は「我れ既に捉えらる、如何ぞ降らざらん」と即座に降を表明した。雒城が陥ちた後は、外水方面の州郡平定を任され、蜀の将として歩み始める。\n\n降ってのちは、外戚としての処遇がその身を彩る。第七十七回、漢中王となった劉備に、吳懿の妹――美にして且つ賢――が王妃として納れられ、姻戚として政権の正統に連なった。将としては、第九十一回以降の北伐において孔明の密計を受け、吳班とともに伏兵を伏せ、橋を焼き、麦を刈る兵を援護するなど、丞相の差配を実直に遂行する役を担い続ける。自ら計を立てて勝ちを収める主体的な献策の場面は乏しいものの、与えられた任を堅く果たす将であった。\n\nそして第百五回、孔明の遺言によって吳懿は車騎将軍に加えられ、節を仮されて漢中を督することとなる。姜維とともに漢中に出屯し、魏兵に備えるという、対魏防衛の一翼を任される地位に上りつめた。華々しい戦功の描写を伴わずとも、外戚として、そして孔明に信を託された宿将として、蜀漢の屋台骨の一隅を支えた――それが演義に刻まれた吳懿の姿である。"}, {"id": 200, "name": "蔣欽", "faction": 2, "role": "武将", "rarity": 2, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [3, 3, 2, 1, 3, 1, 3], "p": [1, 2, 1, 1, 1, 1], "scores": {"W": 2.55, "B": 2.6, "S": 1.7, "A": 1.8, "G": 1.2, "K": 1.6}, "stat": {"dmg": 0.83, "area": 0.93, "cd": 1.06, "amount": 1, "knock": 0.79, "crit": 0.05, "duration": 0, "pwr": 2.5}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [15, 44, 45, 49, 50, 51, 55, 56, 67, 68], "chapN": 12, "bio": "呉の武将、右翼として曹軍に突入", "profile": "字は公奕、九江壽春の人。孫策の草創期から呉に仕え、赤壁、南郡、荊州奪取まで一貫して戦場に立ち続けた東呉の中堅宿将である。韓当・周泰・甘寧らと肩を並べ、しばしば第二隊・右翼・合後の一翼を担う、堅実な働き手だった。\n\n呉への参陣そのものが彼らしい。第十五回、孫策を「江東の豪傑、能く賢を招き士を納る」と見込み、党三百余人を引き連れて自ら身を投じた。その同じ章で本領を示している。寨の後ろから火を放った二人の健将の一人として現れ、敵将陳橫を一箭で射倒したのである。「陳橫は蔣欽に一箭にて射殺せらる」――弓と水戦の腕は、こうして劈頭から印象づけられた。第五十一回では五千の精鋭を率いて南郡の先鋒を志願し、第五十五回では劉備追撃にあたって「徐・丁二将軍に飛報し、水路に快船を棹さしめて追い趕(お)わしめよ、我ら四人は岸上にて追い趕わん」と、水陸分進の追撃案を自ら立てて指図する。突撃要員の枠を一歩越えた作戦判断を見せた場面だ。第六十八回では周泰とともに濡須口の守備を託され、孫権の信任を背負う。\n\nただし通説で語られる呂蒙への器量逸話のたぐいは、演義の本文には見当たらない。本文の蔣欽は、突出した武勇や知略の英雄というより、与えられた隊列をきっちり遂行する量産型の良将である。劉備追撃の指図も孔明に出し抜かれて空振りし、南郡の先鋒は曹仁に敗れた。\n\n最も雄弁なのは第七十六回だろう。関羽に向かって「雲長、何ぞ早く降らざる」と挑発を放つが、刃を交えれば「三合に及ばず、欽敗走す」。トップ級の前ではあっさり退かされる、その等身大の姿こそが蔣欽である。それでも、孫策に見込まれて投じた一人の男が、草創から荊州まで呉とともに在り続けた。派手な無双こそ無いが、東呉という船を漕ぎ続けた確かな櫓の一本だった。"}, {"id": 201, "name": "袁術", "faction": 3, "role": "君主", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 1, 1, 1, 2, 2, 1], "p": [3, 2, 3, 3, 4, 1], "scores": {"W": 1.45, "B": 1.7, "S": 1.85, "A": 1.85, "G": 2.69, "K": 2.4}, "stat": {"dmg": 0.75, "area": 0.94, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 1.8}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [3, 5, 6, 7, 11, 14, 15, 16, 17, 19], "chapN": 22, "bio": "既に滅んだ群雄、曹操が滅ぼした雄として言及される", "profile": "四世三公の名門に生まれ、淮南に拠った群雄。地は広く糧は多く、孫策から質に入れられた伝国の玉璽までその手にあった。条件だけなら天下を窺うに足る男が、誰よりも鮮やかに自滅していく――それが演義の描く袁術である。\n\n破滅の芽は反董卓の連合に早くも見える。糧草を司る督でありながら、孫堅の戦功を妬んで兵糧を断ち、味方を敗北させた。孫堅は使者を通じて詰った。「将軍は讒言を聴き、糧草を発せず、堅をして敗績せしむ。将軍何ぞ安んぜん」と。私情が大局に先んじる、その性根がここに露わになる。やがて淮南で「地広く糧多く、又た孫策の質する所の玉璽あり」を恃み、「代漢者は当塗高なり」の讖を根拠に、ついに僭号へ踏み切る。「吾が家は四世三公、百姓の帰する所。吾れ天に応じ人に順い、九五に正位せんと欲す」。仲氏と号を建て、臺省の官を置き、南北郊を祀り、后を立て東宮を立てる――建国のしぐさだけは一通り揃えた。\n\nだが、それは正統性なき空虚な制度ごっこだった。主簿の閻象は周の文王と殷の紂を引いて諫める。「漢室微なりと雖も、未だ殷紂の暴の若くならず。此の事決して行うべからず」。袁術はこれを「多言の者は斬る」と一喝で封じ、従わぬ太尉の金尚を殺した。諫言を斬る独善が、彼を孤立へと追い込んでいく。\n\n武人としての見せ場も虚しい。第十七回、金甲を身にまとい両刀を腕に懸けて陣前に立ち、呂布を「背主の家奴」と大罵したが、白兵は配下の李豐が代わり、本人は一合も交えぬまま「袁術慌走」。曹操には「塚中の枯骨、吾れ早晩必ず之を擒えん」と嘲られる始末だった。徐州へ向けて二十余万を七路に分けた大作戦も、陳登に「術が兵は衆しと雖も、皆烏合の師」と見抜かれ、内応と火計で総崩れ。最期は壽春の旱魃に糧食尽き、麦三十斛を残すのみ。蜜水すら得られず、床上で一声大叫して倒れ、血を斗余も吐いて死んだ。名分の道具を最も多く握りながら、その全てを自ら手放した、反面教師としての群雄である。"}, {"id": 202, "name": "朱治", "faction": 2, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 1, 2, 3, 3], "p": [3, 2, 3, 1, 2, 2], "scores": {"W": 1.0, "B": 2.25, "S": 2.65, "A": 2.45, "G": 2.25, "K": 2.35}, "stat": {"dmg": 0.66, "area": 0.87, "cd": 1.15, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [15, 44], "chapN": 2, "bio": "呉の将、呂範と共に四方巡警使を務める", "profile": "字は君理。孫堅の旧き従事官であり、孫家二代に仕えた古参の臣である。図鑑では槍の将に数えられるが、演義の本文に白兵や一騎打ちの描写は一つもない。彼の真価は刃ではなく、孫家の危急に差し込まれた一手の進言にあった。\n\n父孫堅を失い、人の下に身を寄せて泣く若き孫策の前に、朱治は現れる。第十五回――「尊父在りし日、多く曾て我を用う。君若し決せざる事あらば、何ぞ我に問わざる、乃ち自ら哭するや」。そして核心を突いた。「君何ぞ袁公路に告げ、兵を借りて江東に往き、吳璟を救うに名を仮(か)りて、実は大業を図らざる、而して乃ち久しく人の下に困しむや」。袁術への依存を脱し、救援を口実に江東で独立の旗を立てよ――呉という国の発端は、この古参の囁きから動き出した。\n\n孫策はこれに応えて江東を平定し、朱治を吳郡太守に任じる。「朱治をして吳郡太守と為し、軍を收めて江東に回らしむ」。一郡を委ねられる文官・行政の将として、彼は後方を支えた。のちの赤壁では呂範とともに四方巡警使を務め、六隊の督促にあたる。表に出て敵を斬る役ではなく、軍を回す歯車の一つである。\n\n派手な武勇譚は持たぬ。だが孫策が淪落していた最も心細い局面で「我に問え」と現れ、自立への一歩を授けたこの旧臣の役回りは、孫家にとって決して小さくない。世代を跨いで主家を支えた、堅実な献策者であり郡守だった。"}, {"id": 203, "name": "劉焉", "faction": 3, "role": "君主", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 2], "p": [1, 3, 1, 0, 4, 2], "scores": {"W": 0.0, "B": 1.1, "S": 1.05, "A": 0.95, "G": 1.76, "K": 2.65}, "stat": {"dmg": 0.66, "area": 0.87, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 1.0}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [1, 59, 77, 120], "chapN": 4, "bio": "劉璋の父。元の益州牧", "profile": "江夏竟陵の人、漢の魯恭王の後裔。のちに益州牧に至り、巴蜀に拠った群雄であり、劉璋の父にあたる。だが演義の劉焉は、物語の前面で割拠を演じる人物ではない。彼の出番は、ある一人の英雄をこの世に送り出す扉としての一場面に凝縮されている。\n\n第一回、幽州太守として黃巾の来襲を受けた劉焉は、校尉鄒靖と議し、榜を出して義兵を募集する。「劉焉、其の説を然りとし、随即(ただち)に榜を出して義兵を招募す」。そこへ応じてきたのが、無名の劉備だった。劉焉は玄德の宗派を聞いて大いに喜び、姪と認める。「玄德宗派を説き起こすに、劉焉大いに喜び、遂に玄德を認めて姪と為す」。そして鄒靖に劉備ら三人を従えさせ、五百の兵で敵を破らせた。凱旋すれば「親しく自ら迎接し、軍士を賞労す」。劉備を最初に世へ押し出した「使い手」――それが演義における劉焉の最大の役割である。\n\n自身は一度も剣を抜かず、計略を口にすることもない。黄巾討伐の手柄はことごとく鄒靖・劉備・関羽・張飛のものだ。漢室宗親の血筋という大義の素地は持つが、それを能動的に運用する場面もない。\n\nその死すら、過去形で淡々と語られる。第五十九回に「後に焉、官は益州牧に至り、興平元年、病疽を患いて死す」とあるのみ。巴蜀割拠の内実は本文に描かれず、第百二十回の総括詩に「劉焉父子は巴蜀に拠る」と一行触れられて終わる。それでも、桃園の三傑が世に出る最初の一歩を開いたのは、この物静かな宗親だった。"}, {"id": 204, "name": "步騭", "faction": 2, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 3, 3, 1], "p": [2, 0, 0, 6, 1, 4], "scores": {"W": 0.0, "B": 2.05, "S": 2.65, "A": 2.6, "G": 1.95, "K": 1.4}, "stat": {"dmg": 0.82, "area": 1.01, "cd": 1.2, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.25, "pwr": 2.5}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [43, 44, 68, 73, 83], "chapN": 5, "bio": "呉の文官、孔明を蘇秦張儀になぞらえ論難する", "profile": "字は子山、孫呉に仕えた文官。演義の步騭は、終始「議論する人」である。剣を交える描写は一つもなく、朝議での発言と一度の使者役だけで物語に名を刻む。だがその舌と眼は、呉の進退を左右する局面に幾度も顔を出した。\n\n初登場は第四十三回、諸葛亮を迎えた呉の群儒舌戦の一員としてだった。ここでは孔明に論破されて黙然となる側に回る。だが彼の本領は弁舌より、現実を計る冷たい目算にあった。第六十八回、曹操の圧迫を前にした孫権の使者として曹営に赴き、歳貢を条件に講和をまとめ上げる。「步騭をして曹営に往きて和を求めしめ、年に歳貢を納れんと許す。操、江南急には未だ下すべからずと見て、乃ち之に従う」。外交の実務を単独で果たし、確かな成果を持ち帰った一手である。\n\nその眼の鋭さが最も光るのは第七十三回。曹操が呉に蜀討伐をけしかけてきた時、步騭は意図を見抜く。「曹操久しく漢を篡わんと欲す、懼るる所の者は劉備なり。今使を遣わして来り呉をして兵を興し蜀を呑ましむるは、此れ禍を呉に嫁するなり」。そのうえで逆手に取る策を献じた。曹仁に先んじて荊州を取らせ、雲長を樊城へ釣り出し、その隙に荊州を暗取せよ――関羽の悲劇の伏線となる、本文上きわめて鋭い嫁禍の計である。\n\nもっとも、その見識には限界もあった。第八十三回、陸遜の登用に際して「遜は才、郡を治むるに堪うるのみ。若し託するに大事を以てせば、其の宜しきに非ず」と低く評し、孫権に却下されている。人を見抜く眼の躓きを、本文自身が書き留めているのだ。その同じ章で、彼は危機の鎮静策も献じる。劉備の大軍が迫る中、仇人と張飛の首を蜀へ送って講和せよと進言し、孫権はこれを容れた。武功は無くとも、講和と謀略で呉の難所を渡らせた、実務派の議論家だった。"}, {"id": 205, "name": "郭図", "faction": 3, "role": "軍師参謀", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 3, 3, 1], "p": [1, 1, 1, 3, 3, 2], "scores": {"W": 0.0, "B": 2.05, "S": 2.65, "A": 2.6, "G": 1.68, "K": 1.75}, "stat": {"dmg": 0.82, "area": 1.01, "cd": 1.2, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.25, "pwr": 2.5}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [19, 22, 26, 27, 28, 30, 31, 32, 33, 57], "chapN": 10, "bio": "袁紹の謀士、出兵を主張し張郃高覧を讒言する", "profile": "袁紹に仕えた謀士の一人。孔融が「許攸・郭圖・審配・逢紀、皆な智謀の士」と数え上げたほどの顔ぶれの中にあって、郭図に与えられた役回りは、皮肉にも袁氏を内側から崩していく「逆神参謀」だった。献策はする。しかし、ことごとく裏目に出る。\n\nその悪名が決定づけられたのが官渡である。第三十回、曹操が烏巢の糧を焼きに出たと知るや、郭図は救援ではなく逆を説いた。「不可なり。曹軍糧を劫すは、曹操必然親ら往かん。操既に自ら出ずれば、寨必ず虚空ならん。兵を縦(はな)ちて先ず曹操の寨を撃つべし……此れ孫臏が囲魏救趙の計なり」。張郃の正論を退けて選んだこの策は惨敗を招く。さらに敗戦の責を逃れんと、郭図は張郃・高覽を讒言した。「張郃・高覽、主公の兵敗るるを見て、心中必ず喜ばん」――この一言が、二人の名将を曹操のもとへ追いやってしまう。袁氏の屋台骨を、味方の参謀が自ら抜いたのである。\n\n袁紹の死後も、その手は止まらない。郭図は袁譚に付き、「三子の中、譚は長たり……主公若し長を廃して幼を立てば、此れ乱の萌(きざし)なり」と長幼の序を説いて後継争いを焚きつけた。屯兵観望、逢紀の留置、偽降の計――次々と策を繰り出すが、いずれも兄弟相争いを深め、ついに袁譚を滅亡へと導いていく。曹操を主敵と見て孫策との連携を進言する大局眼や、檄文で名分を整える筆など、見るべき場面が無いではない。だが構想は実を結ばず、後半は内紛工作に費やされた。\n\n最期は、その生涯にふさわしく惨めだった。第三十三回、陣の大いに乱れるを見て城中へ馳せ入ろうとしたところを、樂進が弓に箭をつがえて城壕に射落とす。「人馬倶(とも)に陥る」。敵を一人も斬らぬまま、逃走の途中で射られて果てた。智謀の士に数えられながら、その智謀がすべて主家の毒となった――そんな参謀である。"}, {"id": 206, "name": "崔琰", "faction": 1, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 2, 0, 1, 1], "p": [2, 1, 1, 0, 6, 1], "scores": {"W": 0.2, "B": 0.5, "S": 0.8, "A": 0.75, "G": 1.72, "K": 2.65}, "stat": {"dmg": 0.63, "area": 0.84, "cd": 1.24, "amount": 1, "knock": 0.7, "crit": 0.06, "duration": 2.75, "pwr": 0.75}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [33, 39, 68], "chapN": 3, "bio": "清河の名士、曹操に仕え別駕", "profile": "清河の名士。あごひげを蓄え、虎のような目を持つ堂々たる風采の文臣で、曹操に仕えて別駕從事・西曹掾・尚書を歴任した。演義での出番はわずか三場。しかしその三場は、一人の人物を「漢室に忠を尽くして諫死した剛直の臣」という一点へと、見事に純化していく。\n\n最初の登場は第三十三回。冀州を平定した曹操が戸籍を数えて兵力を算じようとした時、崔琰は統治の根本を説いて諫めた。「今、天下分崩し、九州幅裂し、二袁兄弟相争い、冀民、骨を原野に暴(さら)す。丞相、急に風俗を存問し其の塗炭を救わずして、先ず戸籍を計校するは、豈に本州士女の明公に望む所ならんや」。算盤より先に、塗炭に苦しむ民を救え――政治の優先順位を主君に突きつける、その姿勢が早くも刻まれる。\n\nそして真骨頂は第六十八回にある。文武百官がこぞって曹操の魏王即位を議する中、ただ一人「不可なり」と力説したのが崔琰だった。投獄されてもなお屈せず、虎のような目とあごひげをそびやかして曹操を罵り続ける。「琰は虎目虯髯、只だ是れ曹操を大罵して君を欺く奸賊と」。ついに彼は獄中で杖殺された。\n\n満朝の沈黙の中で漢室の正統を守り、最後まで奸賊と叫んで死んだその姿に、演義は賛詩を捧げている。「天性堅剛」「鉄石の心腸」「忠心、漢主に、千古、名揚す」と。武勇も軍略もこの人物には縁がない。だが、時流に流されず一身を賭して大義を貫いた純度において、崔琰は演義の文臣の中でも屈指の存在である。最期に彼が放った一言が、すべてを物語る――「時なるかな、時なるかな。会(かなら)ず当に変有るべし。任(まか)せて自ら之を為せ」。"}, {"id": 207, "name": "董允", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 1, 2, 2], "p": [2, 2, 3, 1, 3, 4], "scores": {"W": 1.0, "B": 1.4, "S": 1.7, "A": 1.55, "G": 2.4, "K": 2.6}, "stat": {"dmg": 0.72, "area": 0.91, "cd": 1.18, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 1.55}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [85, 91, 105, 107, 115], "chapN": 5, "bio": "黄門侍郎。杜瓊と共に丞相府を訪う", "profile": "蜀漢の黃門侍郎・侍中を務めた文官。諸葛亮が出師表で名を挙げた信頼の臣であり、宮中の事をまかされて劉禅を正し、佞臣を抑えた補佐役である。戦場での記録は持たぬが、国の内側を律する柱として、その名は蜀の人々の記憶に残った。\n\nその評価の根は出師表にある。第九十一回、諸葛亮は北伐に出るにあたって後事を託す臣を列挙し、「侍中侍郎、郭攸之・費褘・董允等、此れ皆な良実にして、志慮忠純なり。是を以て先帝簡抜して以て陛下に遺(のこ)す」と記した。「宮中府中、倶に一体と為す」という方針のもと、宮中の事を委ねられたのである。設計者は諸葛亮であり、董允はその執行を担う側だった。\n\n危機の場面で、その確かさが光る。第八十五回、五路の兵が蜀へ迫る国難の中、太后が軽率に丞相府へ駆けつけようとするのを董允は諫止する。「娘娘、未だ軽々しく往くべからず。臣料るに丞相必ず高明の見有らん。且く主上の先ず往くを待て」。手順を整え、動揺を抑え込んだ。第百五回、諸葛亮の死後に魏延が乱を起こした際にも、その本質を正確に見抜いている。「魏延は功高きを自恃し、常に不平の心有り……今丞相新たに亡び、機に乗じて乱を為すは、勢いの必然なる所なり」。後主は彼に假節を授け、撫慰の任を委ねた。\n\nその死は、蜀の屋台骨が一本失われたことを意味した。第百七回、費褘は嘆く。「近者、蔣琬・董允、皆な相継いで亡び、内治に人無し」と。具体的な治績こそ本文に描かれぬが、彼が蜀の内政の柱であったことを、この一言が雄弁に裏づける。さらに後年、黃皓の専横に苦しんだ後主は、かつて董允がこの佞臣を切歯して憎んだことを思い返す。「昔者、董允、毎(つね)に歯を切りて皓を恨む。朕、甚だ之を怪しむ」。佞臣を見抜き退けようとした目の確かさは、彼を失ってから初めて惜しまれた。表に立つ将ではない。だが、宮中を清く保ち続けた静かな良臣だった。"}, {"id": 208, "name": "全琮", "faction": 2, "role": "武将", "rarity": 2, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [3, 1, 0, 1, 3, 1, 3], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.65, "B": 2.6, "S": 1.7, "A": 1.8, "G": 1.0, "K": 1.4}, "stat": {"dmg": 0.85, "area": 1.01, "cd": 1.06, "amount": 2, "knock": 0.65, "crit": 0.05, "duration": 7.2, "pwr": 2.7}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [96], "chapN": 1, "bio": "綏南将軍・右都督、石亭で薛喬を破る", "profile": "綏南将軍・右都督として呉に仕えた武将。演義での出番は第九十六回、石亭の戦いただ一場のみだが、その一戦で曹休の大軍を打ち砕く一翼を堂々と担っている。\n\n陸遜が曹休迎撃の陣を布くにあたり、「奮威将軍朱桓、綏南将軍全琮の二人、輔佐と為すべし」と推したことで、全琮は右都督に任じられた。「即ち朱桓を命じて左都督と為し、全琮を右都督と為す」。陸遜の下命は明快だった――「汝二人、各々三万の軍を引き、石亭山より曹休の寨後に抄り到り、火を放ちて号と為せ」。三万を率いて山を迂回し、敵の背後へ回り込む奇襲である。\n\nその遂行は鮮やかだった。曹休の寨の後ろへ抄り到った全琮は、まともに薛喬の陣に突き当たる。「全琮一軍を引きて魏寨の後に抄り到り、正に薛喬の陣裏に撞かり、就(すなわ)ち那裡(そこ)に在りて大いに一陣を殺す。薛喬敗走し、魏兵大いに損ず」。後方からは朱桓と二路で殺到し、「曹休の寨中大いに乱れ、自ら相衝撃す」――敵を同士討ちの混乱に陥れた。戦後、徐盛・朱桓とともに数万の降兵を収める大勝に与っている。\n\n計略そのものを描いたのは陸遜であり、全琮はその指示を破綻なく実行した実行者である。一騎打ちの武名も、膂力の逸話も本文には無い。だが、三万の軍を迂回奇襲に率いて寸分の狂いもなく成功させた手腕は、まぎれもなく右都督の器であった。石亭で曹休を破った将の一人――それが演義に刻まれた全琮の姿である。"}, {"id": 209, "name": "夏侯尚", "faction": 1, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 2, 1, 1, 3, 1, 3], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 1.65, "B": 2.5, "S": 1.7, "A": 1.8, "G": 1.12, "K": 1.55}, "stat": {"dmg": 0.73, "area": 0.88, "cd": 1.1, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.6}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [70, 71, 76, 79, 85], "chapN": 5, "bio": "夏侯惇の甥。張郃を助け黄忠と戦う", "profile": "夏侯惇の姪にして夏侯淵の縁戚。魏の宗族の血を引く槍の将だが、演義における夏侯尚は、漢中の戦場で黃忠を、のちに南郡で陸遜を、それぞれ引き立てる役回りに徹した武将である。一騎打ちの勝利も、敵将を討った記録も、本文には一つもない。\n\n漢中戦での彼は、ほとんど一方的な敗将として描かれる。第七十回、夏侯惇の姪として降将韓浩とともに五千の兵を率いて加勢に現れるが、まず張郃の正しい警告を恫喝で退けた。「汝、此(かく)の如く胆怯なり、屢々戦敗するを知るべし。今再び多言する休(なか)れ、吾二人の功を建つるを看よ」。だがその夜、黃忠の二更の夜襲を受け、「人は甲に及ばず、馬は鞍に及ばず、二将各々自ら命を逃れて走り、軍馬自ら相踐踏し、死者数を知らず」――全軍を壊滅させてしまう。第七十一回には、夏侯淵の囮策を受けて出哨し、黃忠と交えるも「只だ一合にして、夏侯尚を生擒して寨に帰る」。捕虜交換の最中には、背中に箭まで受ける始末だった。\n\n漢中以降は、もっぱら副将として動く。第七十六回には徐晃とともに襄陽を守って関羽の軍を遏(とど)め、第七十九回には上庸方面で劉封を挟撃する伏兵戦に加わるが、指揮の主体はいずれも徐晃である。そして第八十五回、曹真の副将として南郡を攻めた折には、陸遜の伏兵と諸葛瑾の伏兵に内外から挟み撃たれて大敗する。「曹真・夏侯尚、南郡を囲み、陸遜に内に伏兵せられ……内外夾攻し、因りて大いに敗る」。\n\n通説では魏の名将格に数えられることもあるが、演義が彼に与えたのは、黃忠と陸遜という二人の名将の武勲を際立たせる踏み台の役である。それでも、敗れてなお戦場に立ち続けた夏侯一族の一人として、漢中から南郡まで、魏の苦しい戦線にその名は記されている。"}, {"id": 210, "name": "馬忠", "faction": 0, "role": "武将", "rarity": 2, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [2, 2, 1, 1, 3, 1, 3], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.65, "B": 2.5, "S": 1.7, "A": 1.8, "G": 1.0, "K": 1.4}, "stat": {"dmg": 0.82, "area": 1.01, "cd": 1.1, "amount": 2, "knock": 0.72, "crit": 0.05, "duration": 7.2, "pwr": 2.5}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [77, 81, 83, 87, 88, 89, 90, 98, 99, 100], "chapN": 13, "bio": "潘璋の部将、関羽を生け捕り赤兎馬を得る", "profile": "蜀漢の中堅武将。奮威将軍・博陽亭侯の官位を帯び、諸葛亮の幕下で南蛮征伐から北伐まで一貫して従軍した、指示を確実に果たす実務型の将である。なお、関羽を生け捕って赤兎馬を得た呉の同名の馬忠とは別人で、こちらはあくまで孔明配下の蜀将として描かれる。\n\nその働きは、王平・張嶷・馬岱らと組んで伏兵や夾攻の一翼を担う、地味だが堅実なものだった。第九十八回では、張嶷とともに伏せ、火を上げて寄せてきた孫礼の魏兵を「両路兵」で取り囲み、核心に追い込んでいる。第百一回では張翼と並んで鹵城の留守を任され、二千・五千の兵を率いて伏兵・夾攻を遂行する一軍の将として描かれる。\n\nもっとも、自ら名のある敵将を斬る一騎打ちや、独自の作戦立案は本文には見当たらない。むしろ第九十回、捕らえられた張嶷を救おうと飛び出した先で、祝融夫人へ向かったところを坐下の馬を絆られ、あえなく生け捕られてしまう――個人の戦闘描写としてはこの失態がもっとも目立つ。\n\n通説では「忠実な実務将」と語られがちだが、演義の馬忠は、華々しい武功や智謀ではなく、孔明の手足として伏兵の駒を堅実に務め続けた点にこそ味がある。離反など負の記録は一切なく、最後まで蜀漢の軍に欠かせぬ歯車であり続けた中堅の将である。"}, {"id": 211, "name": "高幹", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 1, 3, 2, 3], "p": [1, 1, 1, 2, 2, 1], "scores": {"W": 1.0, "B": 2.55, "S": 2.3, "A": 2.3, "G": 1.28, "K": 1.7}, "stat": {"dmg": 0.66, "area": 0.87, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [31, 32, 33], "chapN": 3, "bio": "袁紹の外甥、并州守、壺関で敗死", "profile": "袁紹の外甥にして并州刺史。第三十一回で叔父袁紹を助けるべく「兵五万を引き、并州より冀州に至りて助戦す」と登場する、袁氏陣営の一方を担う立場の人物である。\n\nその生涯は、官渡敗北後の袁氏とともに転落していく。倉亭の戦いで矢傷を負い、やがて曹操軍の本格的な北上を迎える。唯一の見せ場は第三十三回、楽進・李典・張燕の三将を相手に壺口関を「守住」し、「下す能わず」と足止めしたことだった。要害に拠った堅守である。\n\nだがその関も、知略によってあっさり奪われる。荀攸の詐降の計を見抜けず、降ってきた呂曠・呂翔を一度は疑いながらも結局信じ、その誘いに乗って軍を出して劫寨をかけ、伏兵に潰されて関を失った。逃げた先の左賢王には拝伏して「曹操、疆土を呑併す……万乞救援」と同盟を乞うが、にべもなく叱り退けられる。袁氏の権威に従属するばかりで、自前の大局構想も人を見る目も描かれない受動的な敗者であった。\n\n最期は哀れである。劉表のもとへ身を寄せようと落ちのびる途上、上潞にて無名の都尉・王琰に斬られ、首は曹操へ送られた。立派な肩書を持ちながら、計に嵌まり続け、頼る相手にことごとく拒まれて滅んでいく――袁氏一門の落日を体現する一人といえる。"}, {"id": 212, "name": "張衛", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 1, 3, 2, 3], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 1.0, "B": 2.55, "S": 2.3, "A": 2.3, "G": 1.12, "K": 1.55}, "stat": {"dmg": 0.66, "area": 0.87, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [59, 65, 67], "chapN": 3, "bio": "張魯の弟。挙兵を共に謀る", "profile": "五斗米道の主・張魯の弟にして、漢中の守備を担う武将。第五十九回で兄とともに挙兵を謀る場面から登場し、漢中防衛の要を任される立場にある。\n\nその本領は守りにあった。第六十五回、馬超が漢中へ流れてくると、張魯の命を受けて隘口の守備につき、「軍を七路に分けて隘口を堅守し、馬超の兵を入れず」と、進退きわまらせるほどに防ぎきっている。第六十七回、曹操の大軍が迫った際には「漢中もっとも険なるは陽平関に如くは無し」と説き、関の左右に山に依り林に傍いて十余の寨柵を布く防衛策を立案。これを見た曹操に「かくの如く堅固、急切に下し難し」と言わしめた。\n\nだがその堅塁も長くは保たなかった。楊昂・楊任ら諸将が敗れ諸営が崩れると、張衛は半夜のうちに関を棄てて逃げ去ってしまう。兄が降伏を望んだときも一人「肯んぜず」と意地を張り、府庫を焼いて巴中へ退こうとは進言したものの、これは兄に「倉廩府庫は国家の有なり、廃すべからず」と退けられた。\n\n最期は第六十七回、張魯に命じられて出陣し、許褚と交鋒するも一合で「馬下に斬らる」。立案した寨柵の堅固さだけが光り、白兵では何一つ示せぬまま漢中とともに散った、守り一辺倒の将であった。"}, {"id": 213, "name": "伏皇后", "faction": 3, "role": "婦人", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 1, 1, 1], "p": [1, 3, 0, 2, 4, 3], "scores": {"W": 0.1, "B": 0.9, "S": 1.0, "A": 1.0, "G": 2.0, "K": 2.6}, "stat": {"dmg": 0.66, "area": 0.87, "cd": 1.23, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.75, "pwr": 1.0}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [13, 20, 24, 66, 78, 109], "chapN": 6, "bio": "献帝の皇后、董貴妃の助命を乞う", "profile": "後漢の献帝の正皇后。曹操の専横が極まる朝廷にあって、漢室の正統を体現する立場に身を置いた女性である。通説では「曹操に殺された悲劇の皇后」という受け身の犠牲者像が強いが、演義の彼女はむしろ、自ら反曹操の謀議を起こす能動的な策謀者として描かれる。\n\n第二十回、董承の衣帯詔の一件では、満朝の公卿に向かって「満朝の公卿、ともに漢禄を食む、ついに一人として国難を救う能う者無きか」と問いを投げ、漢室回復の工作に深く関わる。やがて第六十六回、曹操が魏王たらんとして簒奪が近いと見るや、「妾の父伏完、つねに操を殺すの心有り、妾いままさに書一封を修め、密かに父とこれを図らん」と、自ら密書を発起する。\n\nここで光るのが人を見る目である。曹操の心腹だらけの宮中で、彼女は「宦官の忠義託すべき者、穆順に如くは莫し」と的確に見抜き、密命を託した。穆順は書を髪に蔵して禁宮を抜け、伏完の宅へ届ける。江東の孫権・西川の劉備と外から兵を起こさせ、内外で曹操を討つ――その壮大な構想の起点を、後宮の一身が作ったのである。\n\nしかし「昔、董承事を密にせざりて、かえって大禍に遭う」という前例の教訓は活かしきれなかった。穆順の帽子のほつれから密書が露見し、計はすべて破綻する。第六十六回、彼女は髪を振り乱し跣足のまま、華歆に髻を掴まれて引きずり出され、「願わくは我が一命を免せ」と命を乞うも容れられず、地位ごと曹操の娘に取って代わられた。後の世は第百九回の詩「当年伏后宮門を出で、跣足哀号して至尊に別る」にその悲哀を留めている。坐視せず先んじて動いた主体性と、二度の情報漏洩で潰えた無念とが、この皇后の像を忘れがたいものにしている。"}, {"id": 214, "name": "李恢", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 2, 2, 2, 2], "p": [1, 1, 3, 7, 2, 2], "scores": {"W": 1.1, "B": 1.9, "S": 2.0, "A": 2.0, "G": 2.51, "K": 1.65}, "stat": {"dmg": 0.77, "area": 0.94, "cd": 1.16, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 3.0, "pwr": 2.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [60, 65, 91, 97, 102], "chapN": 5, "bio": "建寧の士。劉備招請に反対して諫める", "profile": "蜀漢の文官。建寧の士で、のちに安漢将軍・建寧太守に列せられる。演義における李恢の核は二つ、すなわち主君に命を賭して直諫する忠臣と、敵陣へ単身乗り込む弁士という顔である。武勇の描写はまったく無く、その武器はもっぱら舌と胆にあった。\n\nまず忠臣として。第六十回、劉璋が劉備を蜀へ招き入れようとした際、李恢は叩首して「ひそかに聞く、君に諍臣あり、父に諍子ありと……もし劉備を川に容れなば、これ虎を門に迎うるがごとし」と諫める。容れられはしなかったが、臣節を貫く姿がここにある。\n\n最大の見せ場は第六十五回、馬超の説得である。馬超は「われ知る、李恢は弁士なり、いままさに来たりてわれを説かん」と、刀斧手二十人を伏せて待ち受けた。死地に踏み込んだ李恢は、笑って「将軍の禍遠からず……ただ恐る、新たに磨ぐの剣、わが頭を試す能わず、まさにみずから試さんとするを」と切り返し、相手を慚じ入らせて刀斧手を退かせる。そして「曹操と父を殺すの讐あり、隴西にまた切歯の恨みあり……目下四海容れ難く、一身主無し」と利害を滔々と説き、ついに馬超を劉備帰順へと導いた。演義屈指の使者外交の成功例である。\n\n以後は北伐の軍団に名を連ね、第九十七回で街亭の小路を王平とともに二千兵で守り、第百二回で斜谷道口の糧草運搬を任されるが、いずれも名のみで実描写は薄い。要するに李恢は、外交・弁舌・胆力に一点突破する型の人物であり、馬超を降した一事だけで蜀漢の版図拡大に確かな貢献を刻んだ文官である。"}, {"id": 215, "name": "司馬孚", "faction": 1, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 1, 1], "p": [2, 2, 0, 0, 4, 3], "scores": {"W": 0.1, "B": 0.45, "S": 0.75, "A": 0.65, "G": 1.72, "K": 2.55}, "stat": {"dmg": 0.62, "area": 0.84, "cd": 1.24, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.75, "pwr": 0.65}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [78, 107, 109, 114, 119], "chapN": 5, "bio": "中庶子、曹操死後に早く嗣王を立てるよう進言", "profile": "魏の文官。司馬懿の弟であり、のちの晋建国を支える一族の一人。演義では一貫して朝堂上の官僚として描かれ、武戦の場面は一切ない。司馬一族が権臣として伸し上がっていく過程に静かに寄り添いつつ、最後は魏への忠を口にする――そんな両義的な人物である。\n\nその登場は、いずれも政権の節目に立ち会う。第七十八回、曹操の死で天下が震動したとき、孚は「魏王すでに薨ず、天下震動す。まさに早く嗣王を立て、もって衆心を安んずべし。なんぞただ哭泣せんや」と、いたずらに泣くばかりの群臣を制して後継擁立を促した。第百七回、兄司馬懿のクーデターに際しては、太尉蒋済・尚書令とともに上表文を共同で執筆し、その動きを文書の面から支えている。第百九回では太后の曹髦擁立案を後押しし、帝の人選という権力調整にも加わった。\n\n人となりを最もよく示すのは、終盤の二場面だろう。第百十四回、曹髦が弑された際、太傅司馬孚は屍に駆け寄り、その股を枕にして哭き、「陛下を弑する者は、臣の罪なり」と叫んだ。そして司馬昭に願い出て曹髦を王礼をもって葬らせている。\n\nそして第百十九回、晋への禅譲の場。司馬孚は司馬炎の前に哭拝し、「臣、身は魏臣たり、ついに魏に背かざるなり」と宣して、与えられた安平王の封をも辞退し、受けずに退いた。一族の天下取りを支える官僚でありながら、滅びゆく魏への名分的な忠誠を象徴的に体現する――その複雑な立ち位置こそが、後世まで語り継がれる司馬孚の魅力である。"}, {"id": 216, "name": "申耽", "faction": 1, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 1, 1, 1, 3, 2, 2], "p": [1, 1, 2, 2, 1, 2], "scores": {"W": 1.9, "B": 2.5, "S": 2.2, "A": 2.25, "G": 1.45, "K": 1.35}, "stat": {"dmg": 0.76, "area": 0.87, "cd": 1.08, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.9}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [73, 76, 79, 94, 95], "chapN": 5, "bio": "上庸太守、当初劉備に降るが孟達と共に魏へ寝返る", "profile": "上庸の太守。蜀漢から魏へと寝返った変節の将として知られるが、演義の申耽は単なる裏切り者では終わらない。投魏の計を授ける策士であり、逃げる旧友をみずからの手で討つ実戦の手も見せる、なかなかに食えない地方司令である。\n\n第七十三回、劉備が劉封・孟達・王平らに上庸諸郡を攻め取らせると、曹操が漢中を棄てて走ったと聞いた申耽は弟の申儀ともども降伏し、蜀の旗下に入った。だが第七十九回、関羽を見殺しにして立場を失った孟達に、「われら兄弟、魏に投ぜんと欲すること久し。公、一表を作り、漢中王を辞して魏王曹丕に投ぜよ、丕かならず重用せん」と説き、自分たちも後から降ると約して投魏へと誘い込む。\n\nその立ち回りの非情さが際立つのが第九十四回である。孟達が魏に背いて挙兵すると、申耽兄弟は表向き同意して内応の機を待った。司馬懿の急襲で人馬ともに困憊した孟達が、申耽の軍を救援と誤認して城門を開けた刹那、申耽は「反賊休走、早早受死」と叫び、一鎗で孟達を馬下に刺し殺し、その首を梟した。\n\n第九十五回の街亭では司馬懿に従い、弟と二路の兵で馬謖の籠もる山を囲み、汲水の道を断つ围山部隊を担当している。武勇も知略も中位の、地方を実効支配する司令でありながら、その政治的本質は終始「保身のための寝返り」に集約される。降っては裏切り、友を売って生き延びた――乱世の現実をなまなましく映す一将である。"}, {"id": 217, "name": "呂範", "faction": 2, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 1, 1, 1, 2, 2, 3], "p": [1, 2, 1, 7, 2, 3], "scores": {"W": 1.45, "B": 2.2, "S": 2.05, "A": 1.95, "G": 2.47, "K": 2.2}, "stat": {"dmg": 0.77, "area": 0.94, "cd": 1.11, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 2.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [15, 29, 44, 54, 76, 77, 85], "chapN": 7, "bio": "呉の文官、四方巡警使。降伏派の議論に加わる", "profile": "呉の文官。通説では甘露寺の縁談を取り持つ地味な脇役という印象が強いが、本文を読むと、孫氏に最初期から仕えた参謀格にして、弁舌の使者、占術の担い手、さらには名目上の防衛司令と、意外なほど多面的な人物である。字は子衡、汝南細陽の人。\n\nその縁は孫策の創業期に遡る。第十五回、もとは袁術の謀士だった呂範を孫策が見出し「延坐して共に議す」と迎えると、呂範は「公路これを得んと欲すること久し。これをもって相質とせば、かならず兵を発さん」と進言、伝国の玉璽を質に袁術から兵を借りるという現実的な一手を後押しした。\n\n最大の見せ場は第五十四回、呉蜀の縁談である。媒として荊州へ赴いた呂範は、劉備に向かって「人もし妻無くんば、屋に梁無きがごとし……もし両家ともに秦晋の好を結ばば、すなわち曹賊あえて東南を正視せず。この事、家国両便なり」と説き伏せた。同盟形成の実働を担う外交官としての面目躍如である。もっとも、これが周瑜の計の一環であり、結局は孔明に裏をかかれることになるのは、呉にとって誤算であった。\n\n赤壁では「四方巡警使」を務め、占術の役も担う。第二十九回では于吉に祈雨を進言し、第七十六・七十七回の関公追討の局面では揲蓍して「地水師卦」を立て「敵人遠奔」を当て、再び卜して「亥時かならず擒えん」と予言するなど、危機の判断材料を孫権に供した。第八十五回には三路防衛の一翼として曹休を「殺敗」した戦果も記される。白兵の武勇とは無縁ながら、弁・占・防衛と多彩な引き出しで呉に仕え続けた、味わい深い文官である。"}, {"id": 218, "name": "左慈", "faction": 3, "role": "その他", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 1, 3, 6, 1, 1, 1], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 2.45, "B": 1.35, "S": 1.25, "A": 1.5, "G": 1.0, "K": 1.0}, "stat": {"dmg": 0.72, "area": 0.87, "cd": 1.15, "amount": 1, "knock": 1.1, "crit": 0.11, "duration": 2.75, "pwr": 1.5}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [68, 69], "chapN": 2, "bio": "道士。曹操を術で翻弄する仙人", "profile": "道号を烏角先生という道士。武将でも政治家でもなく、遁甲天書に通じた異人として、曹操を術で翻弄するためだけに演義に現れる、神仙譚の住人である。\n\nその妖術尽くしは第六十八回でほぼ完結する。曹操の前に現れた左慈は、酒を求めれば五斗飲んでも酔わず、肉を求めれば全羊を食らっても飽きぬという常軌を逸した異能を見せた。「日に千羊を食らうも、また尽くす能う」と豪語する。さらに季節外れの密柑を出し、龍の肝・牡丹・松江の鱸魚を幻術で取り寄せ、宴席を妖しく彩る。曹操が捕らえて斬らせれば身を分けて死なず、許褚に追われても「慈すなわち見えず」と掻き消えてしまう。\n\n圧巻は、斬られたはずの屍が自らの首を提げて曹操に打ちかかる場面である。これには「文官武将、面を掩いて驚倒し、おのおの相顧みず」と満座が恐慌をきたし、曹操自身も「驚いて地に倒る」「驚いて疾を成す」と、病みつくほどに怯えた。武人の威ではなく、人智を超えた術への純粋な恐れが、魏の朝堂を一斉に震え上がらせたのである。\n\nその言にわずかに政治の色がにじむのは、曹操に向かって「益州の劉玄徳はすなわち帝室の冑なり、なんぞこの位をこれに譲らざる」と迫り、「飛剣をもって汝の頭を取らん」と脅し、あるいは「大王、位は人臣を極む、なんぞ退歩して、貧道に跟いて峨嵋山中に往き修行せざる」と勧めたところだろう。だがいずれも国家構想ではなく、道士の挑発であり点悟の言である。左慈は終始、権力の頂に立つ者をからかい、その慢心を術であざ笑う――乱世にあって唯一、曹操を本気で怖がらせた異形の存在であった。"}, {"id": 219, "name": "韓徳", "faction": 1, "role": "武将", "rarity": 2, "weapon": "axe", "kind": "arc", "weaponName": "斧", "d": [2, 3, 3, 1, 1, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 2.35, "B": 1.35, "S": 1.1, "A": 1.05, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.81, "area": 0.97, "cd": 1.14, "amount": 1, "knock": 0.86, "crit": 0.05, "duration": 0, "pwr": 2.35}, "title": "斧の将", "skill": "斧", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [92], "chapN": 1, "bio": "西涼の大将・開山大斧の使い手、趙雲に斬られる", "profile": "魏の夏侯楙配下、西涼の大将。「善く開山大斧を使い、万夫不当の勇あり」と豪傑然たる前評判を与えられ、西羌諸路の兵八万を率いて第九十二回に登場する、斧の使い手である。\n\nその鳴り物入りの登場とは裏腹に、本文での出番は趙雲の引き立て役に費やされる。鳳鳴山で蜀兵と相対した韓徳は、四人の子とともに陣を布いて挑むが、その四子はことごとく趙雲の手にかかって討たれてしまう。子らを失った韓徳は「肝胆みな裂け」、自ら陣中へ逃げ込む始末だった。\n\nそれでも父の意地で「わが四子を殺すの讐、いかんぞ報いざらん」と、馬を縦てて開山大斧を輪し、趙雲に直取する。だが「反国の賊、あえてわが境界を犯すか」と大喝したのも束の間、二度目の交戦で「戦うこと三合ならず、鎗起こる処、韓徳を馬下に刺殺す」と、あっけなく討ち取られた。続いて鄧芝が蜀兵を率いて掩殺すると、西涼兵は大敗して走り、韓徳の率いた八万は崩壊する。\n\n立派な称号を与えられながら、それが本文で即座に裏切られ、瞬く間に消費される――韓徳は、老いてなお戦場に立った趙雲の武勇を際立たせるために配された、典型的な噛ませ役である。前評判の「万夫不当」と、三合と持たずに散った実像との落差そのものが、彼の役どころであった。"}, {"id": 220, "name": "楊彪", "faction": 3, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 1], "p": [1, 4, 0, 3, 3, 3], "scores": {"W": 0.0, "B": 0.4, "S": 0.7, "A": 0.55, "G": 2.22, "K": 2.5}, "stat": {"dmg": 0.61, "area": 0.84, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.55}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [3, 6, 13, 14, 20, 22, 60], "chapN": 7, "bio": "太尉、遷都を諫める", "profile": "後漢朝廷に仕える老臣。太尉・司徒・侍中を歴任した漢室の重鎮であり、後に曹操の謀臣となる楊修の父でもある。乱世にあって武を執ることは一度もなく、傾きゆく漢朝の名分をただ一身に背負い続けた文臣の典型である。\n\nその忠骨が最初に試されるのは第六回、董卓が長安への遷都を強行しようとした時だ。司徒であった楊彪は「関中は荒れ果て、いま故なく宗廟を捨て皇陵を棄てれば百姓は驚き動く。天下を乱すは至易、安んずるは至難」と大局を説いて諫める。だが諫言は容れられず、その場で官を奪われ庶民に落とされた。さらに第十三回、長安を二分して争う李傕と郭汜を前に、楊彪は「郭汜の妻は嫉妬深い」と聞き及び、その妻を介して両者を離間させる反間の計を献じる。やがて自ら馬を駆って両軍の陣前に割って入り、「二将しばし休まれよ、老夫が諸官を率いて講和に参った」と叫んで一度は両者を兵を退かせた。朝廷の官僚六十余人を糾合して郭汜の営へ和議に赴いたが、郭汜は逆に官僚を残らず監禁してしまう。\n\n楊彪の人となりは「社稷の臣たりながら君を匡し主を救えぬは、いたずらに天地の間に生きるのみ」という嘆きに尽くされる。腐肉を送りつけられて激怒する献帝には「李傕は残暴、いまはこらえてその鋒に逆らうな」と忍従を説き、絶食する帝に随い、安邑への遷都を請い、終始一貫して漢朝の名分を守ろうと身を粉にした。だがその力は実権を伴わず、賊に翻弄される受け身の立場を出られない。\n\n最期は語られないが、第二十回には袁術内通の冤罪を着せられて曹操に投獄される姿が描かれる。傾く王朝に殉じようとした清廉な老臣として、楊彪は演義の漢室落日の場面に静かな悲哀を添えている。"}, {"id": 221, "name": "呂凱", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 2, 3, 2], "p": [1, 1, 3, 1, 2, 2], "scores": {"W": 0.0, "B": 1.85, "S": 2.5, "A": 2.3, "G": 1.61, "K": 1.65}, "stat": {"dmg": 0.8, "area": 0.98, "cd": 1.2, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.25, "pwr": 2.25}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [87, 88, 89, 90, 91], "chapN": 5, "bio": "永昌の功曹。平蛮指掌図を献じ行軍教授・郷導官となる", "profile": "蜀漢に仕える永昌郡の功曹。武勇も陣頭指揮も持たぬ純然たる文官でありながら、諸葛亮の南征を地理の側から支えた「南方の頭脳」として描かれる。\n\n呂凱の真骨頂は第八十七回、南征に臨んだ諸葛亮への献上品にある。「某は仕えて以来、南人がいずれ反くと久しく知っておりました。ゆえにひそかに人を境内へ送り込み、兵を屯し戦うべき地を踏査し、一図にまとめました。名づけて『平蛮指掌図』と申します」。孔明はこの図によって敵の各寨の配置をことごとく把握し、「呂凱の図本を見れば、もはや各人の構えた寨はわかる」と南征全体の作戦基盤に据えた。さらに第八十九回、西洱河で筏が沈み大軍が渡れぬ難局に陥ると、呂凱は「上流の山に大竹が多い。これを伐って河に竹橋を架ければ軍馬を渡せます」と具体的な工兵策を出し、孔明はそのまま実行して全軍を渡した。瀘水の酷暑下では命を受けて陰涼の地に二つの寨を築き、草棚で人馬を暑気から守る宿営の差配も担っている。\n\n人物像を最もよく示すのは、南方四郡のうち建寧・牂牁・越雋の三郡の太守がこぞって雍闓に降り反く中で、ただ永昌郡だけが落ちなかった一事である。「永昌郡太守の王伉のみ反かず」――呂凱は王伉とともに百姓を集め、孤立無援の城を死守し続けた。大義を声高に論じる弁論は描かれないが、叛逆の只中で蜀漢への忠を黙して貫いた姿そのものが、彼の名分であった。\n\n南方平定の後、孔明は呂凱を王伉とともに四郡の守りに残し、平定地の安定を委ねた。一兵も斬らず、ただ地理の知識と籠城の忠とで南征の土台を築いた功臣として、呂凱は影ながら確かな存在感を残している。"}, {"id": 222, "name": "孫夫人", "faction": 2, "role": "婦人", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 3, 3, 4, 3, 1, 2], "p": [1, 1, 1, 3, 3, 3], "scores": {"W": 2.2, "B": 2.3, "S": 1.75, "A": 2.05, "G": 1.8, "K": 2.1}, "stat": {"dmg": 0.78, "area": 0.93, "cd": 1.15, "amount": 1, "knock": 1.01, "crit": 0.08, "duration": 2.75, "pwr": 2.1}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [54, 55, 56, 61, 62, 77, 82, 84], "chapN": 8, "bio": "孫権の妹、劉備の妻。剛勇で劉備を呉から連れ出す", "profile": "孫権の妹にして劉備の正室。幼い頃から武事を好み、侍婢数百を従え常に刀を帯び、その部屋には兵器が所狭しと並ぶ――「男子も及ばぬ」と評される剛勇の郡主である。だが演義本文に彼女が武器を執って人を斬る場面はなく、その強さは気質と胆力、そして将兵を怯ませる気魄に集約される。\n\n物語に登場するのは第五十四回、周瑜の美人計から。荊州を奪う餌として劉備に嫁がされた彼女だが、その役割は劉備の智激によって反転する。第五十五回、呉から劉備を脱出させる際、孫夫人は「元旦の拝賀の折、江辺で祖を祭ると称し、告げずに去る」という計を自ら案じて成功させる。追手の陳武・潘璋ら四将が彼女の前に現れると、四将はやむなく下馬し拱手して立った。「玄徳は大漢の皇叔、わが夫である」と劉備の正統を盾に、郡主の威をもって関を強行突破するさまは、まさに剛気の梟姫の面目躍如である。第六十一回では阿斗を連れ去ろうとするが、趙雲に船上で阻まれ、懐の阿斗を奪い返される。\n\nその武は将兵を行動で怯ませる気威にあり、第五十五回には「諸将みな懼る」とも記される。一方で国家構想や人材登用、民政といった能動的な政治の記録はなく、第八十二回では呉が孫劉再同盟の条件として「夫人を送り返す」ことを持ち出すように、同盟の紐帯・象徴として扱われる客体の側面も色濃い。\n\n最期は第八十四回。呉にあって夷陵の敗報を聞き、劉備が軍中に没したとの誤報が伝わると、孫夫人は車を駆って江辺に至り、西に向かって遥かに哭し、身を投じて死んだ。後に烈女として梟姫の祠に祀られる。武人ではなく剛気の婦人として、その節義の鮮烈さで人の心に残る一人である。"}, {"id": 223, "name": "宋憲", "faction": 1, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 3, 1, 1, 2, 1, 2], "p": [1, 1, 1, 2, 1, 2], "scores": {"W": 2.3, "B": 1.9, "S": 1.35, "A": 1.4, "G": 1.27, "K": 1.35}, "stat": {"dmg": 0.79, "area": 0.89, "cd": 1.09, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 2.2}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [11, 16, 17, 18, 19, 25], "chapN": 6, "bio": "呂布の旧将、顔良に一刀で斬られる", "profile": "もとは呂布配下の八健将の一人に数えられた部将。後に曹操に降って魏の陣営に属するが、その名は武勲よりも「主を売った下剋上」と「顔良に瞬殺された弱さ」の二点で語り継がれる。\n\n最大の見せ場は皮肉にも、その死の場面である。第二十五回、白馬の戦いで顔良が魏軍を圧倒すると、曹操は「お前は呂布配下の猛将と聞く、いま顔良と一戦せよ」と宋憲に命じた。宋憲は槍を取って馬を駆り陣前へ出るが、顔良は大喝一声、馬を縦って迎え撃ち――「戦うこと三合に至らず、手起こり刀落ち、宋憲を陣前に斬る」。曹操に「猛将」と呼ばれた称号は、わずか三合で看板倒れに終わった。\n\nしかし宋憲を真に記憶させるのは、その前の第十九回である。下邳が水攻めで陥落寸前となった夜、宋憲は魏続に「呂布は仁も義もない。我らこれを棄てて去ってはどうか」と持ちかけ、魏続が「むしろ呂布を擒えて曹公に献じよう」と応じる。やがて門楼で椅子に凭れて眠り込んだ呂布から、宋憲はまず画戟を盗み、魏続とともに縄をかけて固く縛り上げ、城門を開いて曹操に引き渡した。これは白兵の武功ではなく、追い詰められた末の保身の裏切りであった。\n\n第十六回には呂布の娘を袁術へ嫁がせる縁談で韓胤に同行し護送役を務め、山東へ良馬三百余匹を買い付けに出された記録もある。だが結局のところ宋憲は、命じられて動く一隊長の域を出ず、自らの忠誠を語る場面はついになかった。咬ませ犬と背反者――演義はこの将に、乱世の駒の哀れを背負わせている。"}, {"id": 224, "name": "蔡瑁", "faction": 3, "role": "武将", "rarity": 2, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [2, 1, 0, 1, 3, 2, 2], "p": [1, 1, 3, 1, 1, 2], "scores": {"W": 1.2, "B": 2.4, "S": 2.2, "A": 2.25, "G": 1.48, "K": 1.35}, "stat": {"dmg": 0.8, "area": 0.97, "cd": 1.11, "amount": 2, "knock": 0.65, "crit": 0.05, "duration": 6.8, "pwr": 2.3}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [6, 7, 31, 34, 35, 39, 40, 41, 45, 46], "chapN": 11, "bio": "荊州の将で曹操に降る水軍大都督、反間の計で誅される", "profile": "荊州の名族の出で、劉表の後妻・蔡夫人の兄として外戚の権を握った将。武人の顔、陰謀家の顔、水軍都督の顔という三つの相を持つが、演義が最も濃く描くのは荊州内の権力闘争に明け暮れる政争の人である。\n\n武人としての蔡瑁は連戦連敗の弱将だ。第六回では黄蓋に鞭で護心鏡を打たれて撤退し、第七回では程普と数合と戦わぬうちに敗走している。その本領はむしろ陰謀にあった。第三十一回で身を寄せた劉備を讒言して斥け、第三十四回には檀溪で劉備暗殺を画策、第四十回には劉表の死に乗じて蔡夫人らと偽の遺言をしたため、長子劉琦を廃して次子劉琮を荊州の主に立てる。これを「遺命を偽り、長を廃して幼を立てる」と糾弾した李珪は、激怒した蔡瑁の命で斬られた。\n\n唯一の戦術的見せ場は水軍都督としての手腕である。第四十五回、長江沿いに二十四座の水門を分かち、大船を外に城郭の如く据え、小船を内に置いて往来を通じた水寨の布陣は、視察した周瑜をして「これ深く水軍の妙を得たり」と驚嘆させた。荊州の軍勢を問われれば「馬軍五万、歩軍十五万、水軍八万、あわせて二十八万。銭糧の大半は江陵にあり」と即座に正確に答える軍政の把握も見せる。だが三江口では呉軍に敗れ、曹操に「東呉の兵は少ないのに敗れたのは、お前たちが心を用いぬからだ」と責められた。\n\n最期は第四十五回以降、蒋幹の持ち帰った偽書による反間の計に曹操が乗せられ、張允とともに帳下で斬られる。荀攸に「諂佞の徒」、魏延に「売国の賊」と罵られた通り、忠臣の評を一度も得ぬまま、自らが弄した策謀と同じ謀略によって首を落とされた。"}, {"id": 225, "name": "雍闓", "faction": 3, "role": "武将", "rarity": 2, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [2, 1, 1, 1, 3, 2, 2], "p": [1, 1, 1, 2, 1, 1], "scores": {"W": 1.45, "B": 2.4, "S": 2.2, "A": 2.25, "G": 1.15, "K": 1.2}, "stat": {"dmg": 0.71, "area": 0.87, "cd": 1.11, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [86, 87], "chapN": 2, "bio": "建寧太守。雍齒の後裔。孟獲と結び反乱、孔明の離間で高定に斬られる", "profile": "建寧太守。漢の什邡侯・雍齒の末裔という肩書きを持ち、南蛮の反乱の名目上の主謀者として登場する。十万の蛮兵を背景に四郡を揺るがす立場にありながら、その実像は孔明の南征を引き立てるための損な役回りに徹している。\n\n第八十六回、蛮王孟獲が十万の蛮兵を起こして境を侵すと、建寧太守の雍闓はこれと結んで反旗を翻し、牂牁郡太守の朱褒、越雋郡太守の高定を造反に引き入れ、両者に城を献じさせた。だが彼の挙兵を、蜀の王連は「雍闓らは疥癬の疾(取るに足らぬ皮膚病)に過ぎず、丞相は一大将を遣わして討たせれば必ず成功する」と一蹴する。その格付けは、そのまま彼の結末を言い当てていた。\n\n第八十七回、孔明みずから大軍を率いて来ると知った雍闓は、高定・朱褒と諮って三路に分兵し、自らは左軍を引いて迎え撃つ布陣を立てる。ところがいざ三万の兵を率いて出迎えてみれば、魏延と戦うこと数合で馬を返して逃げ出し、二十余里も追撃される始末。やがて孔明の反間計が放たれると、捕えて放たれた兵たちが高定の徳を慕い、雍闓の軍中には次々と高定へ寝返る心が広がっていく。決戦の夜、雍闓の軍は「戦わずして自ら乱れ」、彼は馬に乗って山路へ逃れようとした。\n\nその逃走の途上、同盟者であったはずの高定の部将・鄂煥に不意を突かれ、「一戟で馬の下に刺し落とされ、首級を梟された」。部下の兵はことごとく高定に降り、その勢力は一夜で消え去った。武も智も統率も、描かれた端から崩される――反乱連合を一応は組み上げながら、大義の旗も国家の構想も持たぬまま、雍闓は南征譚の最初の捨て駒として散った。"}, {"id": 226, "name": "劉封", "faction": 0, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 2, 1, 1, 3, 1, 2], "p": [1, 1, 1, 1, 2, 1], "scores": {"W": 2.1, "B": 2.35, "S": 1.6, "A": 1.75, "G": 1.13, "K": 1.5}, "stat": {"dmg": 0.78, "area": 0.88, "cd": 1.08, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 2.05}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [36, 39, 40, 41, 49, 62, 70, 71, 72, 76], "chapN": 19, "bio": "劉備の養子、孔明と江夏へ援軍を求めに行く", "profile": "劉備の養子。第三十六回で義子に取り立てられて以来、博望坡・白河・益州・漢中と、要所の戦に遊軍や接応役として顔を出す。だがその後世の名は、関羽を見殺しにして誅された悲運の養子という一点に集約される。\n\n戦場での劉封は、孔明の指示のもとで堅実に駒を務める実行役であった。第四十回では糜芳とともに二千の軍を率い、半ばを紅旗、半ばを青旗に染めて新野城外の鵲尾坡に屯し、敵を疑わせる陽動を担う。第七十一回には定軍山の奪取に加わり、米倉山の路から討って出て敵の糧草に火を放った。だが独力の武功には乏しい。一騎打ちでは徐晃に敵し切れず馬を返して逃げ、第七十二回には曹彰と戦うこと三合で大敗して帰る。本文が彼に冠する語も「螟蛉の子」「仮子」といった出自を貶める呼称ばかりで、関羽からは「将軍は螟蛉の子、僭立すべからず」と血筋を突かれ、曹操には「履を売る小僧」の付属物扱いされた。\n\n転落は上庸から始まる。第七十六回、漢中王から副将軍に加えられ孟達とともに上庸を守るが、麦城に窮した関羽からの救援要請を、孟達の讒言に流され「この山城は初めて附いたばかりで、兵を分けて救えぬ」と拒んだ。蜀漢最大級の危機に最悪の判断を下し、関羽父子の死を招く。\n\n第七十九回、今度は孟達が魏に寝返り招降状を送りつけると、劉封は「この賊、わが叔姪の義を誤らせ、わが父子の親を間し、われを不忠不孝の人とせんとす」と激怒して書を破り、使者を斬った。だが配下の申耽・申儀兄弟に背かれ、城を魏に明け渡され、自軍は百余騎を残すまで崩れ去る。「われすでに魏に降れり」と城上から叫ばれて立ち尽くす姿に、使い勝手の良い駒が拠るべき足場を失った末路が凝縮されている。成都へ帰った後、関羽不救の咎によって処断された。"}, {"id": 227, "name": "趙咨", "faction": 2, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 2, 1], "p": [1, 1, 1, 8, 2, 3], "scores": {"W": 0.0, "B": 1.0, "S": 1.55, "A": 1.4, "G": 2.42, "K": 1.6}, "stat": {"dmg": 0.7, "area": 0.91, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.35}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [82], "chapN": 1, "bio": "中大夫。魏に使者として赴き曹丕に呉主を弁じ称臣を取り付ける", "profile": "呉の中大夫。演義では第八十二回ただ一度の登場ながら、その一幕で外交弁舌の白眉を演じ、強い印象を残す使者である。\n\n夷陵に向けて蜀の大軍が押し寄せ、孫権が「江南危うし」と動揺する国家の危機に、趙咨は「某に一計あり、この危を解くべし」と進み出る。「主公、一表をしたためられよ。某みずから使者となって魏帝曹丕に会い、利害を陳べ、漢中を襲わせれば蜀兵は自ずから危うくなりましょう」。背後から魏を動かして蜀の圧力を逸らす――この献策を携え、趙咨は「もし些細の差失あらば、すなわち江に投じて死なん」と命懸けの覚悟で魏へ赴いた。\n\n魏の朝廷で待っていたのは曹丕の挑発的な連問であった。「呉侯はいかなる主か」「呉は魏を畏れるか」「東呉に大夫のような者は幾人いるか」。趙咨は一歩も退かず切り返す。「呉侯は魯肅を凡庸の中から取り立てた、その聰なり。呂蒙を行陣より抜いた、その明なり。于禁を獲て害さなかった、その仁なり。荊州を兵を血ぬらずに取った、その智なり。三江に拠って天下を虎視する、その雄なり。陛下に身を屈する、その略なり」と、孫権を聰明仁智雄略の主として六徳で論証してみせた。さらに呉を畏れるかと問われれば「帯甲百万、江漢を池となす、何の畏るるところあらんや」と気概を崩さない。称臣を「略(戦略的な方便)」と言い切って江東の体面を保ちつつ、ついに曹丕に「『四方に使いして君命を辱めず』、卿はこれに当たるべし」と称賛させ、孫権の王封と九錫を引き出した。\n\n武も統治も語られぬが、ただ一場の弁舌で国難を逸らし、敵帝の口から賛辞を勝ち取る――趙咨は「使いして君命を辱めず」という言葉を体現した、呉の能弁の士である。"}, {"id": 228, "name": "辛評", "faction": 3, "role": "軍師参謀", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 2, 2, 1], "p": [1, 2, 1, 3, 4, 3], "scores": {"W": 0.0, "B": 1.45, "S": 1.8, "A": 1.75, "G": 2.13, "K": 2.4}, "stat": {"dmg": 0.74, "area": 0.94, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.7}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [7, 31, 32, 33], "chapN": 4, "bio": "袁譚派の謀臣、辛毗の兄", "profile": "袁譚派の謀臣。曹操に厚遇された辛毗の兄であり、兄弟が敵味方に分かれた悲劇でも知られる。だが演義に描かれる辛評の核は、能臣の才よりも「袁氏への忠に殉じた側近」の純度にある。\n\nその読みの鋭さが光るのは第三十二回。袁尚への加勢に急ぐべきかを諮る場で、辛評は「審配・逢紀の二人は必ず謀を仕組んでいる。いま急いで往けば、必ずその禍に遭う」と慎重論を進言する。敵の機先を読む眼は確かだが、この一言が容れられることは少なく、彼が前面に立って計略を成すことはなかった。第七回でも韓馥が冀州を袁紹に譲る場面に二謀士の一人として居合わせるが、献策の主体は荀諶であり、辛評は同席にとどまる。第三十一回の後継争いでは、審配・逢紀が袁尚を、辛評・郭図が袁譚を輔け、「四人おのおの其の主のためにす」と、袁氏を二分する派閥の一翼として名を連ねる。\n\n辛評が最も光るのは最期、第三十三回である。南皮を包囲され絶体絶命となった袁譚は、辛評を使者として曹操のもとへ送り降伏を約させた。曹操が辛評に「お前の弟は今わが幕下にある」と寝返りを誘うと、辛評はきっぱりと拒む。「丞相は誤っておられる。某は聞く、主貴ければ臣栄え、主憂うれば臣辱しと。某は久しく袁氏に事えてきた、どうしてこれを背けようか」。だが交渉は曹操に「袁譚の小僧は反覆無常、信じがたい」と退けられ、成果なく終わる。\n\nその帰陣を待っていたのは、皮肉にも主君袁譚からの猜疑であった。曹操に通じたのではと二心を疑われた辛評は、第三十三回、「気は胸に満ち満ちて、地に昏絶」し、扶け出されてまもなく死んだ。君臣の名分を貫いた末に、その忠を疑われて憤死する――辛評は袁氏の落日に殉じた、忠義の臣の最も悲しい形である。"}, {"id": 229, "name": "陳矯", "faction": 1, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 2, 1, 1], "p": [1, 2, 1, 1, 3, 5], "scores": {"W": 0.1, "B": 1.35, "S": 1.25, "A": 1.35, "G": 1.94, "K": 2.4}, "stat": {"dmg": 0.7, "area": 0.9, "cd": 1.21, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.75, "pwr": 1.35}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [51, 78, 79], "chapN": 3, "bio": "曹仁配下の謀臣。兵符を諸葛亮に奪われる", "profile": "魏の文官。曹仁配下の幕僚として登場し、後に兵部尚書として曹丕の代に重きをなす。武人としての描写は一切なく、その姿は前半の「敗ける智嚢」と後半の「果断な危機対応者」という、対照的な二相に分かれている。\n\n前半は第五十一回。南郡をめぐる攻防で、曹仁の参謀として「彝陵が失われれば南郡も守れぬ。速やかに救うべし」と進言し、また劫寨(夜襲)を「この計、速やかに行え、遅れてはならぬ」と急かす。だが彝陵救援は甘寧の囮に乗せられ、夜襲は周瑜の罠で曹軍が大敗。陳矯自身も「些少の軍士」を率いて守る城ごと諸葛亮に生け捕られ、兵符を奪われてしまう。この兵符が孔明の手に渡ったことで、荊州・襄陽は労せず劉備の手に落ちた。計が悉く裏目に出る、敗ける参謀の典型であった。\n\n後半で人物が一変する。第七十八回、曹操が外地で急死し、世子の即位を待つべきか群臣が逡巡する継承の危機に、兵部尚書の陳矯は声を上げる。「王、外に薨じ、愛子私かに立たば、彼此に変を生じ、社稷危うし」。そして剣を抜いて自らの袍の袖を断ち切り、厲声して言い放った。「即日、世子に位を嗣がしめよ。異議ある者あらば、この袍をもって例とせん」。百官は悚懼し、曹彰・曹植らの争位の芽は未然に封じられ、曹丕の即時嗣位が断行された。\n\n第七十九回には華歆・王朗・賈詡・陳群ら四十余人の文武とともに内殿へ入り、漢の献帝に魏王曹丕への禅譲を奏請する一人として、魏の正統樹立にも名を連ねる。敗将としての失態と、継承危機での演義屈指の果断さ――その振幅の大きさが、陳矯という文官を忘れがたいものにしている。"}, {"id": 230, "name": "黄祖", "faction": 3, "role": "武将", "rarity": 2, "weapon": "bow", "kind": "proj", "weaponName": "弓", "d": [2, 2, 1, 1, 3, 1, 2], "p": [1, 1, 1, 1, 2, 2], "scores": {"W": 1.65, "B": 2.25, "S": 1.6, "A": 1.75, "G": 1.25, "K": 1.65}, "stat": {"dmg": 0.79, "area": 0.98, "cd": 1.11, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 2.15}, "title": "弓の将", "skill": "弓", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [7, 8, 18, 23, 29, 38, 39], "chapN": 7, "bio": "劉表配下の江夏の将、禰衡を斬る", "profile": "荊州の劉表に仕え、長江の要衝・江夏を預かった太守である。一地方の守りを任された重臣ではあったが、演義が描く黄祖の姿は終始「敗れる側」のそれだ。武勇を讃える称号も、勇猛を形容する一言も与えられず、与えられるのは老いと貪欲をめぐる辛辣な評言のみ。荊州の長期戦略は劉表と蒯良が握り、黄祖はその盤上に置かれた一個の駒として動く。\n\nその実像が最もよく現れるのが第七回、孫堅との江夏の戦いである。黄祖は江辺に弓弩手を伏せて孫堅の船を迎え撃つが、誘いの計に乗って矢を撃ち尽くし、十数万本の矢をそっくり逆用された挙句、三面から攻め立てられて大敗する。野戦では張虎・陳生を前に押し出すばかりで自らは戦わず、程普に組み伏せられそうになると「兜と馬を捨て、歩兵に紛れて命からがら逃げる」。さらに同じ回で黄蓋に二合で生け捕られる始末で、孫堅に弓弩で討たれたという通説の悪名とは裏腹に、本文の孫堅を射殺すのは呂公の伏兵であり、黄祖自身はただ捕われ続けるばかりだ。\n\n人物像の核を突いたのは、後に呉へ走る甘寧の言葉である。第三十八回、甘寧は黄祖を「今や年老いて昏く、利得に汲々とし、吏民を苛んで人心はみな怨み、武具は手入れもされず、軍に法律もない」と評した。黄祖は自らを再三推挙してくれた蘇飛の言を退け、有能な甘寧を「劫江の賊、重く用いるべきでない」と侮って手放した。第二十三回では禰衡を斬った狭量を、詩に「黄祖は長者の儔にあらず」と謗られる。人を見抜けず、人を富ませられず、人を恐れさせもしない将であった。\n\n最期は、自ら手放したその甘寧によって訪れる。第三十八回から三十九回、孫権軍に夏口・江夏を破られると、黄祖は守り切れぬと悟って江夏を棄て荊州へ逃れようとするが、追い詰められて捕えられ、梟首された。逃がした逸材を敵に回し、その手で滅ぼされる——人材の取り違えがそのまま身の破滅を招いた、ひとつの戒めとして演義に刻まれた将である。"}, {"id": 231, "name": "丁原", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 2, 1, 2, 2, 2, 3], "p": [1, 2, 1, 1, 3, 1], "scores": {"W": 1.75, "B": 2.25, "S": 2.1, "A": 2.05, "G": 1.46, "K": 2.2}, "stat": {"dmg": 0.74, "area": 0.9, "cd": 1.11, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 1.7}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [3, 9, 19], "chapN": 3, "bio": "荊州刺史、呂布の養父。呂布に殺される", "profile": "後漢末、刺史として一軍を率い、当代最強の呂布を養子に従えた武人である。演義での登場はわずかに第三回のみだが、その一場面に彼の生涯のすべてが凝縮されている。董卓が幼帝の廃立を専断しようとしたとき、満座の群臣が口をつぐむなか、ただ一人面と向かって異を唱えたのが丁原だった。\n\n「天子は先帝の嫡子、初めより過ちなし。何ぞ妄りに廃立を議せん。汝、篡逆をなさんと欲するか」——宦官の専横と廃立の非を真っ向から突き、董卓を「篡逆」と断じたその気迫は、漢室の大義をもっとも早く明確に掲げたものだった。董卓が「我に順う者は生き、逆らう者は死ぬ」と凄んでも怯まない。翌日には軍を率いて城外に陣を布き、董卓を一度は三十余里も敗走させてみせる。\n\nだが、その勝利の中身はすべて呂布のものだった。董卓の謀臣・李儒が見やったのは、丁原の背後に立つ「器宇軒昂、威風凜々として方天画戟を手にする」呂布であって、丁原ではない。董卓が園に潜んで避けたのも呂布だった。義気の士として軍を動かしはしても、丁原個人の武勇を語る描写は本文に一つもない。\n\nそして悲劇が訪れる。董卓は赤兎の名馬と金珠をもって呂布を釣り、丁原を裏切らせる。第三回、灯火のもとで書を読んでいた丁原は、近づく呂布に「吾が児、何の用あって来たか」と問うた、その瞬間に一刀のもとに首を斬り落とされる。呂布が「丁原は不仁、すでに討った」と叫ぶと、軍士はその大半が四散した。最も近しい養子の裏切りを最後まで察知できず、無防備に討たれたその死は、以後の第九回・第十九回でも「呂布の不義の最初の犠牲者」として、董卓と並ぶ「殺された養父」の象徴として語り継がれていく。義の言を吐いた最初の一人が、義を知らぬ刃に最初に倒れた——その皮肉が、丁原という人物を忘れがたくしている。"}, {"id": 232, "name": "糜竺", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 1], "p": [1, 2, 2, 5, 2, 3], "scores": {"W": 0.0, "B": 0.4, "S": 0.7, "A": 0.55, "G": 2.35, "K": 1.8}, "stat": {"dmg": 0.61, "area": 0.84, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.55}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [11, 12, 14, 18, 19, 22, 28, 35, 39, 41], "chapN": 22, "bio": "劉備配下の文臣、長板で趙雲に救われ後に呉へ使者に立つ", "profile": "劉備をその草創の困窮期から支え続けた、蜀漢きっての忠厚な文臣である。徐州の大富豪であり、家財を惜しみなく投じて流浪の劉備に賭け、妹を嫁がせて外戚にもなった。剣を取って敵を斬る将ではない。水鏡先生が第三十五回で「白面の書生のみ、経綸済世の才にあらず」と評したとおり、演義は彼を天下を経営する智者としてではなく、主君の窮地に必ず駆けつける実務の忠臣として描いている。\n\nその忠誠は、まず私財として現れる。第十一回、徐州が曹操に攻められた危急のとき、糜竺は自ら北海の孔融と青州の田楷へ救援を請うべく名乗りを上げ、人的なつてを動かして劉備を救った。同じ頃、彼は「広く家財を捨て、貧を済い苦を抜く」——己の富を惜しまず民を救う後援者でもあった。第十九回、呂布が城に乱入したときには、城上から呂布に啖呵を切りつつ、劉備の妻子の助命を説いてみせる。\n\n糜竺の真骨頂は、使者としての働きにある。第四十五回、赤壁を前にして彼は自ら志願し、軍をねぎらう名目で東呉の周瑜の陣営へ赴き、その虚実を探った。劉備と孫権を繋ぐ往還の役を幾度も担い、舌戦で同盟を結ぶ弁士ではないにせよ、信を託されて敵中へ身を運ぶ実務使者としての登場頻度は、全人物のなかでも際立って高い。\n\n戦場では救われる側だった。第四十一回の長坂では曹仁配下の淳于導に捕らえられ、まさに手柄として引き立てられようとしたところを趙雲に助け出される。陶謙は臨終に際し、第十二回で糜竺に劉備への忠勤を託した。その託を糜竺は終生違えず、第八十回、劉備が漢中王から帝位へと昇るとき、安漢将軍として奉戴の重臣の列に名を連ねる。華々しい戦功も計略もない。だが、誰よりも早く劉備を信じ、最も長くその傍らに在り続けた——その一点において、糜竺は蜀漢の屋台骨を支えた人物として記憶される。"}, {"id": 233, "name": "李楽", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 1, 2, 3, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.55, "B": 2.3, "S": 1.65, "A": 1.85, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.72, "area": 0.89, "cd": 1.11, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 1.55}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [13, 14], "chapN": 2, "bio": "白波の賊帥、献帝を護送するも専横し劫駕を謀る", "profile": "山林に徒党を嘯き集めた白波の賊の頭目である。第十三回、長安を脱した献帝の護送のために召し出されるが、武将としてよりも、賊性と専横をもって描かれる人物だ。\n\nその振る舞いは終始あくどい。渡河の場面では、船縁を争って集まる人々の指を斬り落とす残虐を見せ、安邑では百官をところかまわず殴り罵り、入墨者や雑卒二百余名を勝手に官に保挙する。印が間に合わぬと錐で刻む始末で、本文は「全く体統を成さず」と切って捨てる。献帝には故意に濁り酒と粗末な飯を送りつけ、御前で官人を打ち据えて専権を振るった。\n\n軍の将としても無残である。渭陽の戦いでは、敵が道に撒いた衣服に兵が群がって隊伍をすっかり失い、四面から混戦に巻き込まれて大敗した。挙句の果てには李傕・郭汜と密かに通じ、天子を奪い取ろうと自ら追撃に乗り出す。第十四回、その名を詐称して「車駕、行くな、李傕・郭汜ここにあり」と叫び、献帝を心胆寒からしめるが、迎え撃った徐晃と馬を交えるや、わずか一合で斧の下に斬り落とされた。天子を護るべく召されながら、自ら天子の危機を作り出して滅んだ、専横の小物として演義に刻まれている。"}, {"id": 234, "name": "鄧賢", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 3, 0, 0, 3, 1, 2], "p": [0, 0, 0, 0, 1, 0], "scores": {"W": 1.5, "B": 2.2, "S": 1.55, "A": 1.65, "G": 0.13, "K": 0.7}, "stat": {"dmg": 0.7, "area": 0.83, "cd": 1.11, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 1.35}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [60, 61, 62, 94, 95], "chapN": 5, "bio": "劉璋配下の将。劉備を防ぐよう進言する一班", "profile": "益州の劉璋に仕えた武将で、本文に「蜀中の名将」と紹介される一人である。第六十回、劉備の入蜀に際し、劉瑰・冷苞・張任らとともに「劉備は柔の中に剛あり、その心は測りがたし、なお之を防ぐべし」と主君に進言した一班に名を連ねる、忠勤の士であった。\n\nだが、その「名将」の称号と実際の戦果は大きく食い違う。第六十二回、雒城の前面に冷苞とともに二万の兵を分け、出寨して劉備軍を防ぐ。敗走する魏延を山谷に伏兵で待ち伏せ、背後から截ち切って「魏延、早く馬を下りて降れ」と一喝したまでは、勇ましかった。\n\nところが、魏延の馬が前足をつまずかせて主を投げ落とし、まさに鄧賢が槍を構えて突き刺そうとしたその刹那、弓弦が鳴り、黄忠の一矢を受けて鄧賢のほうが馬から転げ落ちる。槍は一突きも入らぬまま、彼は斬られた。出陣前の前評判だけが高く、矢一本であっけなく討たれた——名と実の乖離を地で行く役どころで、その死とともに寨は劉備に奪われ、川兵は大いに乱れた。「名将」と呼ばれた将が、ただ一矢で物語から退場する、その鮮やかな噛ませ役として演義に残る。"}, {"id": 235, "name": "蘇飛", "faction": 3, "role": "武将", "rarity": 2, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 2, 1, 2], "p": [1, 5, 1, 1, 1, 3], "scores": {"W": 1.0, "B": 1.7, "S": 1.35, "A": 1.4, "G": 2.04, "K": 2.3}, "stat": {"dmg": 0.66, "area": 0.87, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [38, 39], "chapN": 2, "bio": "黄祖の都督、甘寧を厚遇、後に処刑され甘寧が哭す", "profile": "江夏太守・黄祖に仕えた都督であり大将である。だが演義が蘇飛に与えた見せ場は、武勇ではなく人を見る眼にある。\n\n武将としての戦果は乏しい。第三十八回、孫権軍の侵攻に際して大将に任じられるが、艨艟と大索で沔口を封じる布陣は陳就・鄧龍が主体で、甘寧に索を斬られて瓦解する。蘇飛自身は岸上での接応に失敗して祖軍の大敗を招き、落ち延びる途中で呉の潘璋と馬を交え、わずか数合で生け捕られてしまう。\n\nしかし、蘇飛という人物の真価は別のところにある。彼は埋もれていた甘寧の才を見抜き、黄祖に幾度も推挙した。黄祖が「劫江の賊、重く用いるべきでない」と退け、甘寧が恨みを抱いていると察するや、蘇飛は自宅に酒席を設けて甘寧を招き、「私が鄂県の長に保挙しよう、自ら去就の計を立てよ」と進路を開いてやった。のちに東呉の名将となるその器を、黄祖が侮ったその逸材を、蘇飛だけが見抜いていたのである。\n\nこの施した恩が、めぐって己の命を救う。第三十九回、江夏が陥ちて蘇飛が檻車に囚われ処刑を待つ身となったとき、彼は密かに使いを送って甘寧に救いを求めた。甘寧は「飛が言わずとも、私がどうしてあの恩を忘れよう」と答え、孫権に哭いて訴え、蘇飛の赦免を勝ち取る。武で名を成した将ではない。だが、人を見抜き恩を施した一事が、敗将の命をつないだ——演義における恩義の物語を体現する人物である。"}, {"id": 236, "name": "管亥", "faction": 3, "role": "武将", "rarity": 2, "weapon": "podao", "kind": "arc", "weaponName": "大刀", "d": [3, 2, 1, 2, 2, 1, 3], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 2.2, "B": 2.2, "S": 1.5, "A": 1.55, "G": 1.0, "K": 1.4}, "stat": {"dmg": 0.79, "area": 0.9, "cd": 1.08, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.15}, "title": "大刀の将", "skill": "大刀", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [11], "chapN": 1, "bio": "黄巾の賊将、北海を囲み關羽に斬られる", "profile": "数万の群寇を率いて北海を囲んだ黄巾の賊将である。登場は第十一回ただ一度きり、太史慈の弓と関羽の青龍刀を引き立てるために現れる役どころだ。\n\nその動機は卑近そのもので、「北海に糧が多いと聞いた、一万石を借りればすぐ兵を退こう、さもなくば城を破って老幼も残さぬ」と恫喝する。これに対し孔融が「我は大漢の臣、大漢の地を守る身、何ぞ糧米を賊に与えんや」と撥ねつけると、管亥は大いに怒り、馬を駆って刀を振るい孔融に迫った。出てきた城将の宗宝を、数合のうちに一刀で斬って落とすあたり、賊将としての腕は確かにある。\n\nしかし、相手が悪かった。包囲を破って単騎駆け込んだ太史慈、続いて駆けつけた関羽・張飛が「虎の羊群に入るがごとく縦横に当たるなし」と賊勢を蹴散らすと、城上の孔融はこれを見て兵を出し、両面から挟み撃つ。管亥は数十合のうちに関羽に斬り伏せられた。頭目が討たれた途端、「降る者数知れず、余党は潰え散る」——数万を動員しながら、結束は脆く、首魁ひとり倒れれば瞬く間に崩れる。賊の素朴な力攻めが英傑の前に砕け散る、その典型として演義に名を留めている。"}, {"id": 237, "name": "張嶷", "faction": 0, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 2, 1, 2, 2, 1, 3], "p": [1, 1, 2, 1, 1, 2], "scores": {"W": 2.2, "B": 2.2, "S": 1.5, "A": 1.55, "G": 1.3, "K": 1.55}, "stat": {"dmg": 0.79, "area": 0.9, "cd": 1.08, "amount": 1, "knock": 0.77, "crit": 0.06, "duration": 0, "pwr": 2.15}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [87, 88, 90, 91, 93, 97, 98, 99, 100, 101], "chapN": 16, "bio": "蜀将。南征で活躍、祝融夫人に捕らえられる", "profile": "孔明の南征から姜維の北伐へと、蜀漢の二代にわたって戦陣を渡り歩いた忠勇の士である。派手な武名を持つ将ではない。本文の張嶷は一貫して、伏兵・接応・運糧といった実働をこなす、命令に忠実な働き手として描かれる。だが、その「忠勇」と「死節」こそが、彼の人物像を際立たせている。\n\n戦場での個人の武功はむしろ敗北が目立つ。第九十回の南征では祝融夫人の飛刀を左腕に受けて「身を翻して落馬」し、第九十七回では王雙の流星鎚を背に受けて「血を幾口も吐き」、戻って孔明に「王雙、英雄無敵なり」と報告するほどだった。名のある敵将を討ち取った描写はない。彼の戦いは、董荼那・阿会喃の擒拿、盤蛇谷の伏兵、孫礼の糧車焼き討ちと、いずれも「孔明、張嶷を喚びて分付す」と指示を受けて動く、実行役のそれである。\n\nそれでも蜀の宿将たちは、張嶷を深く信頼した。孔明は臨終の遺言で、馬岱・王平・廖化・張翼と並べて彼を「忠諒死節の士、久しく戦陣を経て、多く勤労を負う、委用するに堪えたり」と評した。第百五回、孔明亡き後の国家の危機には、東呉の盟破りに備え王平とともに永安へ数万を率いて屯することを蔣琬に保挙される。離反も命令違反もない、信に足る将であった。\n\nその生涯は、最も張嶷らしい死で閉じられる。第百十一回、盪寇将軍となっていた彼は、姜維が魏軍の重囲に陥ったと聞くや、わずか数百騎を率いて囲みの中へ突き入った。姜維はその勢いに乗じて脱出を果たすが、張嶷自身は魏兵の乱箭を浴びて戦死する。主帥を救うために我が身を投げ出したのである。後主は「忠勇にして王事に没す」とその死を悼み、子孫に官位を贈った。武名ではなく死節をもって名を残した、蜀漢の良将である。"}, {"id": 238, "name": "杜瓊", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [2, 1, 1, 1, 3, 1, 2], "p": [1, 1, 1, 1, 3, 4], "scores": {"W": 1.45, "B": 2.25, "S": 1.6, "A": 1.75, "G": 1.62, "K": 2.25}, "stat": {"dmg": 0.75, "area": 0.93, "cd": 1.11, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 2.75, "pwr": 1.8}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [80, 85, 91, 100], "chapN": 4, "bio": "議曹、劉備即位を奏する官僚の一人", "profile": "蜀漢に仕えた中堅の文官で、議曹から諫議大夫を歴任した諫官である。演義での登場は四場面にとどまるが、ただ官名を連ねるだけの端役ではなく、国家の危機局面で君主と丞相を繋ぐ実務を担った点に存在感がある。\n\n第八十回、劉備が漢中王として帝位へ昇るとき、杜瓊は議曹として文武百官の奉戴の列に名を連ね、漢室正統の擁立に一票を添える。その真価が現れるのが第八十五回である。曹丕が五路の大軍をもって蜀へ攻め寄せた国家存亡の危機に、病と称して出仕しない丞相孔明のもとへ、杜瓊は諫議大夫として登り詰めて事情を質し、「陛下、自ら丞相府へ赴いて計を問われよ」と後主に奏上した。危機打開の主役は孔明だが、君主の親臨問計という一手を動かしたのは杜瓊の働きである。\n\n第九十一回、孔明が北伐に出るにあたっての留守の人事でも、杜瓊は諫議大夫として蜀中の政務に与る。そして第百回、彼は文官の枠を出て戦場にも立つ。魏延・張嶷・陳式とともに四将の一人として二万の兵を率い、箕谷へ進んだ。敗走する陳式を張嶷とともに引兵して接応し、魏兵を退けてみせる——筆を執る官僚が、いざというとき軍の一翼を担う。諫言で政を支え、危機には実働で応えた、蜀漢の堅実な官人として演義に名を留めている。"}, {"id": 239, "name": "張譲", "faction": 3, "role": "宦官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 0, 0, 2, 1, 1, 1], "p": [2, 3, 1, 0, 3, 2], "scores": {"W": 0.65, "B": 1.05, "S": 1.05, "A": 1.1, "G": 1.85, "K": 2.3}, "stat": {"dmg": 0.67, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.7, "crit": 0.06, "duration": 2.75, "pwr": 1.1}, "title": "宦官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [1, 2, 3, 115], "chapN": 4, "bio": "十常侍の首領格、何進を殺す", "profile": "後漢を腐敗の底へ引きずり込んだ十常侍の筆頭宦官であり、霊帝に「阿父」とまで呼ばせた、宮廷の闇の主である。武人ではない。彼の武器は賄賂と讒言、後宮の操作と垂簾聴政の画策——剣ではなく謀略によって天下の権を握った政争の人だ。\n\nその手口は第二回に凝縮されている。董太后に「娘娘、朝に臨み、簾を垂れて政を聴くべし」と垂簾聴政の体制を献じ、皇子・協を王に封じ、外戚に軍権を配分させて朝廷の権力を自派に組み替えていく。趙忠ら十三人を列侯に封じさせ、従わぬ者を罷免し、何苗を賄賂で抱き込む。黄巾平定の将士からは金帛を強奪し、応じぬ者の職を奪う。人を金と官で繋いで党派を御す、その黒い権力調整に彼は長けていた。何太后にも「張譲らがいなければこの富貴は享けられぬ」と言わせ、「我、当に汝を保たん」と庇護を取り付ける——他者の権威に巧みに寄生する技術は確かに高かった。\n\n破滅の伏線は、外戚との確執だった。第三回、自らの一族滅亡の危機を察した張譲は、太后の詔を装って何進を宮中に誘い込む。長楽宮の嘉徳門内に刀斧手五十人を伏せ、「厲声」で何進を叱責したのち、伏甲に命じて「何進を斬って両段とす」。だが自らは刃を取らず、罠に嵌めた優位からの誘殺にすぎない。\n\nそして報いは即座に訪れた。何進殺害を知った袁紹・袁術ら外鎮の軍が宮中に乱入し、宦官を見つけ次第斬り捨てる掃討が始まる。張譲は太后・少帝・陳留王を人質に劫し取って北宮へ脱し、さらに北邙山まで逃れるが、もはや逃げ場はない。「逆賊、走るな」と閔貢に追い詰められた張譲は、事ここに極まって河に身を投げて果てた。天子の権威に寄生して栄華を極め、後継の体制も築けぬまま、奪った天子もろとも追われて入水する——朝政を腐らせ天下の大乱を招いた元凶の、ふさわしい末路であった。"}, {"id": 240, "name": "張闓", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 0, 1, 3, 1, 2], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 1.2, "B": 2.25, "S": 1.6, "A": 1.75, "G": 0.0, "K": 0.4}, "stat": {"dmg": 0.68, "area": 0.83, "cd": 1.11, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 0, "pwr": 1.15}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [10, 11], "chapN": 2, "bio": "陶謙配下の都尉、曹嵩一家を殺す元黄巾", "profile": "陶謙配下の一都尉。もとは黄巾の余党で、勉強ずくで陶謙に降っただけの身であり、忠誠も恩義も持ち合わせない。演義に登場するのはわずか二回、第十回と第十一回のみだが、その一夜の凶行が天下を揺るがす大事件の引き金となる、いわば歴史の触媒のような男である。\n\n第十回、曹操の父・曹嵩の一行が徐州を通る際、陶謙はもてなしの上で五百の兵をつけて護送させた。その任を負ったのが張闓である。だが彼は道中、手下の頭目を人目につかぬ場所に集めてこう囁く。「我々はもともと黄巾の残党、やむなく陶謙に降ったが何の得もない。今この曹嵩一行は財宝を山と積んでいる。今夜三更、一斉に斬り込んで一家を皆殺しにし、財を奪って山に入り賊となろう。この計はどうだ」。一同はこれに応じた。雨のやまぬ夜、油断しきった曹嵩のもとに四方から喊声が上がる。曹徳が剣を提げて様子を見に出たところを突き殺され、「張闓は曹嵩の一家をことごとく殺し、財物を奪い、寺に火を放って、五百人とともに淮南へ逃げ去った」。\n\nこの一件が曹操の徐州大虐殺を招き、後に劉備が徐州へ関わる端緒ともなる。だが当人にそんな大局の意図は微塵もない。動機は富貴ひとつ、相手は武装した名将ではなく無抵抗の老人と女子供。一騎打ちも会戦の指揮も、彼には何ひとつ記録がない。あるのは「気の緩んだ護送対象を雨の夜に襲う」という、盗賊の悪知恵だけである。\n\n陶謙すら「あなたの父上の遭難は張闓の悪事であって、私の罪ではない」と弁明したように、彼の名は徹頭徹尾「悪事を働いた者」として処理される。淮南へ逃げ去ったきり、その後の消息も最期も演義は語らない。一夜の強盗のために歴史を動かし、そのまま物語から消えた使い捨ての小悪党。それが張闓という男の、すべてである。"}, {"id": 241, "name": "許靖", "faction": 3, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 0], "p": [2, 1, 0, 1, 4, 4], "scores": {"W": 0.0, "B": 0.15, "S": 0.6, "A": 0.5, "G": 1.79, "K": 2.3}, "stat": {"dmg": 0.6, "area": 0.84, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.45}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [65, 73, 77, 80], "chapN": 4, "bio": "蜀郡太守。城を越えて降伏、後に左将軍長史", "profile": "蜀の文官にして典礼の名望家。もとは蜀郡太守として劉璋に仕えたが、後に劉備の麾下に転じ、左将軍長史から太傅、そして司徒へと昇る。戦場に立つことは生涯なく、演義における許靖の役どころは、新政権の正統性を整え、上表に名を連ねる「名望の保証人」である。武勇とは縁遠い、しかし新たな国家の節目には必ず姿を見せる男だ。\n\nその初出は第六十五回、劉備が益州を攻める局面でのこと。「蜀郡太守の許靖、城を踰えて出で降れり」――劉璋を見限り、城壁を乗り越えて劉備に降ったのである。以後の彼の真価は、ここぞという儀礼の場で発揮される。第七十三回、劉備が漢中王に推戴される際、許靖は法正とともに玄徳を壇上へ請じ、冠冕と璽綬を進め、南面して座る玄徳が文武百官の拝賀を受けるその式典を取り仕切った。一州一国の主が王を称するという重大な手続きを、名士の権威をもって正統なものに仕立て上げる――それが彼の務めである。\n\n人となりは控えめで、自ら計を案じ局面を動かす型ではない。第七十七回、荊州が陥ちて関羽が死んだ報を、いち早く孔明に伝えたのも彼であった。そして第八十回、曹丕が漢の帝位を簒奪すると、許靖は孔明・譙周とともに「天下は一日も君主なきを得ず」と協議し、固辞する劉備に幾度も上表を重ねる。「主上は漢室の苗裔、理として統を継ぐべし」――漢統の継承を理屈の上から正当化し、蜀漢建国の体裁を支えた。\n\n国家の大計を描いたのは孔明であり、大義そのものは漢室の血を引く劉備自身に属する。許靖はその傍らで、名望を担保とし、上表に署名を添える役に徹した。華々しい武功も奇策もないが、新しい国が生まれるたびにその正統を整える――地味ながら、新政権の体面を支え続けた典礼の臣であった。"}, {"id": 242, "name": "吉平", "faction": 3, "role": "その他", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 0, 1], "p": [0, 0, 1, 0, 6, 2], "scores": {"W": 0.1, "B": 0.3, "S": 0.15, "A": 0.15, "G": 1.2, "K": 2.3}, "stat": {"dmg": 0.57, "area": 0.8, "cd": 1.24, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.2}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [23, 28, 69, 78], "chapN": 4, "bio": "洛陽の名医、董承に加わり曹操毒殺を企てるが露見し拷問死する", "profile": "後漢朝廷に仕える洛陽出身の名医、太醫。本文も「当時の名医なり」と記すとおり、その本分は医術にあり、戦場や統治とは無縁の人物である。だが演義における吉平の名は、武人や名将を凌ぐ重みをもって後章にまで残る。それは漢室への忠に殉じた、ただ一点の壮絶さによる。\n\n第二十三回、董承らが密かに掲げた衣帯詔――曹操打倒の謀議に、吉平は薬をもって加担する。曹操が病で薬を求めた折、毒を盛って一気に除こうとしたのだ。だが計画は家僕の密告で露見する。曹操は薬に毒があると見抜き、吉平に飲んでみよと迫る。事の漏れたるを悟った吉平は、「歩を縦にして前に向かい、操の耳を扯みて之に灌がんとす」。曹操が薬を払いのけると、敷石が砕け散るほどの騒ぎとなった。捕えられた吉平は苛烈な拷問にかけられる。指を截たれ、舌を割かれてなお、「天が我をして逆賊を殺さしむ」「なお口あれば賊を呑むべく、舌あれば賊を罵るべし」と言い放ち、共謀者の名は一人として吐かなかった。「我は自ら汝を殺さんと欲したのみ、誰が我を使わしたものか」と、すべての罪を一身に引き受けたのである。\n\n通説は彼を「忠臣の鑑」と呼ぶが、演義の吉平はまさにその名にふさわしい。最期、彼は身を起こして宮闕を望んで拝し、「臣、国家のために賊を除くこと能わざるは、乃ち天数なり」と言うや、階に頭を撞きつけて自ら命を絶った。史官は「誓いを立てて姦党を除き、軀を捐てて聖明に報ゆ……千秋、異名を仰がん」とその義烈を讃えている。\n\nその忠は一代で終わらなかった。第六十九回、遺児の吉邈・吉穆の兄弟が父の遺志を継いで討曹に立つ。さらに第七十八回、曹操が名医華佗を疑う場面では「まさに吉平と異なるなし」と引かれ、その名は義烈の代名詞として生き続けた。無官の医者でありながら、漢に殉じた純度において、吉平は数多の名将にも劣らぬ存在として記憶される。"}, {"id": 243, "name": "孫綝", "faction": 2, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 2, 3, 2, 1], "p": [1, 4, 0, 2, 1, 1], "scores": {"W": 0.2, "B": 2.0, "S": 2.15, "A": 2.3, "G": 1.57, "K": 1.6}, "stat": {"dmg": 0.8, "area": 0.97, "cd": 1.2, "amount": 1, "knock": 0.7, "crit": 0.06, "duration": 3.0, "pwr": 2.25}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [111, 112, 113], "chapN": 3, "bio": "呉の権臣。孫亮を廃し孫休を立てるが、丁奉の計で誅殺される", "profile": "呉の末期に権を握った権臣。字は子通。演義は地の文で「人と為り強暴」と容赦なく断じる。一族五侯がみな禁兵を握り、その権勢は人主をも凌いだ。だが、その暴威は戦場の武勇に由来するものではない。殺戮と廃立によって朝廷を支配し、最後は自らの専横が招いた計略にあえなく斃れる――それが孫綝という暴君の実像である。\n\n第百十一回、彼は大司馬の滕胤や将軍の呂據・王惇らを殺して権を固める。同年、魏で諸葛誕が反旗を翻し援軍を請うと、孫綝はこれを容れ、全懌・全端を主将、于詮を後詰め、朱異・唐咨を先鋒、文欽を郷導とし、七万の兵を三隊に分けて派遣した。だが彼自身は前線に出ず、戦は朱異の敗退に終わる。第百十二回、敗れて戻った朱異を孫綝は「累兵の将、汝を要いて何の用かあらん」と罵り、軍士に命じて引き出し斬らせた。これに恐れをなした全氏一族は次々と魏へ降り、自軍を自ら瓦解させていく。\n\n第百十三回、孫綝の専横はついに頂点に達する。彼は呉主孫亮を廃そうと文武百官の前で宣言した。「汝ら諸文武、敢えて従わざる者あらば、謀叛をもって論ぜん」。一同は「将軍の令に従わん」と畏れ従うほかなかった。剣を抜いて尚書の桓懿を朝堂で斬り、孫亮を会稽王に落として琅琊王孫休を擁立する。だがその恐怖は武威ではなく、妄殺と専権が生む政治的なものに過ぎなかった。\n\n天網は彼を見逃さない。孫休は内心その専横を恐れ、丁奉・張布と謀って計を仕掛ける。狂風や故なく倒れる凶兆、家人の制止を、孫綝は「我ら兄弟みな禁兵を典る、誰が身に近づけよう」と一蹴して宴へ赴き、たやすく生け捕られた。「願わくは交州に徙りて田里に帰らん」と命乞いするも、孫休は一喝してこれを斬らせ、宗族数百が三族もろとも誅滅された。詩に「乱賊は伊尹を誣い、奸臣は霍光に充つ」と謳われたとおり、簒臣として果てたその名は、君を凌いだ者の末路を示す反面教師として刻まれている。"}, {"id": 244, "name": "劉繇", "faction": 3, "role": "君主", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 0, 1, 2, 2, 2], "p": [2, 1, 1, 2, 4, 1], "scores": {"W": 0.75, "B": 1.85, "S": 1.95, "A": 1.9, "G": 1.76, "K": 2.25}, "stat": {"dmg": 0.76, "area": 0.94, "cd": 1.16, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.0, "pwr": 1.9}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [11, 15, 79, 97], "chapN": 4, "bio": "揚州刺史、漢室宗親。孫策に敗れ豫章へ逃れる", "profile": "字は正礼、東萊牟平の人。漢室の宗親であり、太尉劉寵の甥、兗州刺史劉岱の弟という申し分ない血筋に、漢から任ぜられた揚州刺史の官職を帯びる。肩書だけを見れば堂々たる正統の君主である。だが演義の劉繇は、その立派な名分とは裏腹に、人を見抜けず決断できぬ凡庸の主として、終始一貫して敗者の側に描かれる。\n\nその凡庸さが最も象徴的に表れるのが、第十五回、孫策との江東をめぐる攻防である。麾下に身を寄せた猛将・太史慈に対し、劉繇はこう言い放つ。「お前はまだ年若い、大将には任せられぬ。ただ私の側にあって命を聴いておればよい」。当世屈指の勇士を雑用役に留めたのだ。やがて孫策が攻め寄せても、劉繇は「これは必ず孫策の誘いの計だ、追ってはならぬ」と臆して動かない。前に出て戦うのは部将の于糜や樊能ばかりで、劉繇本人は号令と退却に終始する。神亭嶺で陣を構えれば受け身に崩れ、張英を牛渚に置けば十万の兵糧もろとも焼かれ、曲阿でも敗れて、「劉繇の軍兵大いに敗れ、衆みな四紛五落す」と散り散りになった。\n\n人材を見る目のなさは、敵にすら見抜かれていた。勝った孫策は劉繇をこう斬って捨てる。「劉繇は愚かな輩、太史慈を大将に用いることもできず、それでこの敗を招いたのだ」。太史慈はといえば、将令を待たず独断で馬に乗って出撃し、諸将も劉繇の号令を笑って従わぬありさま。軍そのものが、もはや主を主と仰いでいなかった。\n\n基業を失った劉繇は「我が家の基業はすでに失われた、長く留まるべきではない」と漏らし、笮融とともに豫章へ逃れ、劉表を頼った。漢室の宗親という最上の名分を持ちながら、それを保つ器を欠いたために一州をまるごと失う。後の第九十七回でも、王朗と並べて「劉繇・王朗、各おの州に拠る」と引かれ、孫氏に江東を併呑された負け組の代名詞として語り継がれることになる。"}, {"id": 245, "name": "張邈", "faction": 3, "role": "君主", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 2, 2, 2], "p": [2, 3, 1, 2, 2, 2], "scores": {"W": 1.0, "B": 1.85, "S": 1.95, "A": 1.9, "G": 2.02, "K": 2.2}, "stat": {"dmg": 0.76, "area": 0.94, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 1.9}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [5, 7, 10, 11, 12], "chapN": 5, "bio": "陳留太守。陳宮らが身を寄せる。十八鎮の一", "profile": "陳留太守。董卓討伐に集った十八路諸侯の一鎮にも名を連ねた群雄の一人である。後世には「呂布を担いで兗州を奪った反曹操の首謀者」として語られがちだが、演義の張邈を丁寧に読むと、その印象はだいぶ違ってくる。自ら計を立て天下を狙う野心家ではなく、周囲に乗せられて動く受け身の小君主――それが本文の姿だ。\n\n第五回、「第六鎮、陳留太守張邈」として華々しく登場するものの、彼に自前の武勇や奇策の見せ場はない。転機は第十一回。流浪の末に行き場を失った呂布が張邈のもとへ転がり込み、ちょうどそこへ弟の張超が陳宮を連れて現れる。陳宮は説く。「今や天下は分崩し英雄並び起こる。君は千里の衆を擁しながら、かえって人に制せられている。何と鄙しいことか」。そして曹操が東を征して兗州が空なる隙に、呂布とともにこれを奪えば覇業も図れる、と。張邈はこれを聞いて「大いに喜び」、呂布に命じて兗州を襲わせ、濮陽に拠った。\n\nだが立案したのは陳宮であり、当世の勇士と称えられるのも担ぎ上げた呂布のほうで、張邈自身は採用して号令しただけに過ぎない。陳宮に「人に制せられている」と侮られる側であり、内政も外交も自前の事績は何ひとつ描かれない。演義における彼の役割は、煎じ詰めれば「呂布という勇士を迎え入れる器――兵と地盤」の提供者であった。\n\n最期もまた、主体性を欠いたまま訪れる。第十二回、曹操の反攻を受けると呂布の火攻めに頼るが、伏兵の計に敗れて瓦解。弟の張超は自ら火に身を投じて果て、張邈本人は配下を立て直すこともなく、ただ一人袁術のもとへ逃げ去って物語から退場する。立派な肩書を持ちながら、最後まで誰かの計に乗って動き、誰かに縋って消えていった――そういう君主であった。"}, {"id": 246, "name": "鍾繇", "faction": 1, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 2, 2, 2], "p": [2, 3, 1, 1, 2, 2], "scores": {"W": 1.0, "B": 1.85, "S": 1.95, "A": 1.9, "G": 1.87, "K": 2.2}, "stat": {"dmg": 0.76, "area": 0.94, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 1.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [56, 58, 68, 69, 94, 107], "chapN": 6, "bio": "長安郡守。馬超に長安を奪われ潼関へ退く。銅雀台で詩も献ず", "profile": "魏に仕える文官。長安・潼関の郡守を務め、後には国家最高位の相国にまで昇る重臣である。後世には能書家にして関中経営の功臣として名高いが、演義の鍾繇はおおむね二つの顔で描かれる。ひとつは前線で手痛い敗北を喫する将としての顔、もうひとつは曹操の傍らで詔を草し詩を献じ、要所で人を見抜く事務官としての顔である。\n\n将としての一面は、率直に言えば苦い。第五十八回、馬超・韓遂が長安に迫ると、迎え撃った鍾繇は馬岱と馬上で渡り合うも「一合と持たず大敗して奔走」、馬岱に刀を提げて追われる始末。弟の鍾進も龐德に一刀のもとに斬られ、関は破られ鎖は断たれて、鍾繇は東門から城を棄てて逃げ去った。籠城に転じても龐德の偽りの退却にまんまと欺かれ、城門を開いたところを再び襲われて入城を許してしまう。守城の動きはあれども、計には終始後手を踏まされる役回りであった。\n\nだが文官としての鍾繇には、確かな見せ場がある。第五十六回では銅雀台で曹操に詩を献じてその功徳を称え、第六十八回では献帝の命を受けて曹操を魏王に冊立する詔を起草し、第六十九回には相国の位に就いた。そして彼の真価が最も輝くのが第九十四回。曹真が蜀に連敗して長安が危うくなった国家の危機に際し、鍾繇は進言する。「臣、全家の良賤を以て一人を保挙す、蜀兵を退くべし」。一族郎党すべてを担保に挙げたその一人こそ、驃騎大将軍司馬懿であった。諸葛亮が最も懼れるこの人物を再び起用すれば蜀は自ずと退く、と彼は大局を見抜いていた。\n\nこの一挙によって、魏は対蜀の柱石を得る。戦場では振るわず、能書や屯田といった史実上の功績も演義には現れないが、決定的な一人を見抜いて世に出した――その人物眼ひとつにおいて、鍾繇は確かに国家の趨勢を左右した臣であった。"}, {"id": 247, "name": "伏完", "faction": 3, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 3, 0], "p": [1, 3, 0, 3, 4, 2], "scores": {"W": 0.1, "B": 0.5, "S": 1.85, "A": 1.6, "G": 2.03, "K": 2.25}, "stat": {"dmg": 0.71, "area": 0.93, "cd": 1.25, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.25, "pwr": 1.45}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [20, 66, 78], "chapN": 3, "bio": "伏皇后の父、董承に衣帯詔の計を進言", "profile": "後漢朝廷の文官にして、伏皇后の父、献帝の皇丈――すなわち国舅である。通説では曹操打倒に身を捧げた忠義の士とされるが、演義の伏完は自ら剣を取る力を持たない。彼の武器は、宮廷の奥で巡らす謀略の構想ひとつ。漢室を守らんとする一念から反曹の計を練り続け、ことごとく破れて一族滅亡へと至る、純然たる謀臣である。\n\nその謀の発端が第二十回。曹操の専横を憂えた伏完は、自らの限界をはっきりと認めていた。「許田の射鹿の事、誰か之を見ざらん。されど満朝の中、操の宗族にあらずんば則ち其の門下。国戚にあらずんば誰か肯えて忠を尽くし賊を討たんや。老臣は権なく、此の事を行い難し」。曹操の縁者と腹心が朝廷を固める現実を見抜いた上で、討賊を託すに足る人物として車騎将軍・国舅の董承を推挙する。ここから、あの衣帯詔の謀議が動き出すのである。\n\n第六十六回、伏皇后からの密書を受け取った伏完は、なおも慎重を崩さない。「操賊の心腹は甚だ衆し、遽かに図るべからず」と短慮を戒めつつ、一計を授ける。「江東の孫権、西川の劉備、この二処に外より兵を起こさせ、操が自ら往くその時、朝中の忠義の臣と一同に謀り、内外より夾攻すれば、庶わくは済すべし」。外の二大勢力と朝廷内の忠臣を連動させて曹操を挟み撃つ――構想だけ見れば壮大な大戦略だが、実行する力も信頼できる伝達路もなく、密書を運んだ穆順の線からあえなく露見してしまう。\n\n謀は破れ、伏氏は三族二百余口が皆殺しの憂き目に遭う。だが物語は彼を見捨てない。第七十八回、曹操が病に伏す場面では、伏皇后・董貴人・二皇子、そして伏完・董承ら二十余人が血にまみれて愁雲のうちに立ち現れ、命を索める声を響かせる。生前は敵を畏れさせる力など微塵もなかった国舅が、死してなお怨霊となって曹操を驚倒させるのだ。国戚の名分を一身に背負い、その名分ゆえに一族を滅ぼした――伏完は、漢への忠が悲劇へと反転する物語を体現した人物である。"}, {"id": 248, "name": "朵思大王", "faction": 3, "role": "武将", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 0, 2, 3, 1, 2], "p": [0, 1, 1, 1, 0, 1], "scores": {"W": 0.85, "B": 2.2, "S": 1.65, "A": 1.85, "G": 0.65, "K": 0.75}, "stat": {"dmg": 0.76, "area": 0.93, "cd": 1.15, "amount": 1, "knock": 0.7, "crit": 0.06, "duration": 2.75, "pwr": 1.9}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [89, 90], "chapN": 2, "bio": "禿龍洞の洞主。四毒泉で蜀軍を阻むが三江城で乱軍中に死す", "profile": "南蛮の禿龍洞を治める洞主。孟獲の弟・孟優と親しく、追い詰められた孟獲が頼った相手である。「毒泉と地形で蜀軍を罠にかける南蛮の知恵者」という像で語られるが、本文の朵思は一騎打ちも斬獲もなく、武勇を示す描写を一切持たない。実態は、険しい己の土地を活かして一手の計を授ける守備の献策役であった。\n\n第八十九回、孟獲を迎えた朵思は、禿龍洞の地の利を頼みに策を巡らせる。「東北の大路を壘斷し、大王はゆるりと敝洞に居れ。蜀兵は東路が截たれれば必ず西路から入る。その路には水なく、四つの泉を見れば必ず飲むであろう。百万の衆といえども、みな帰る者なからん。何ぞ刀兵を用いんや」。洞中には啞泉・滅泉ら四つの毒泉があり、これを飲ませて蜀軍を戦わずして壊滅させようという――地の利に立った、確かに気の利いた一手である。洞丁には牛馬を屠って大盤振る舞いし、士気を上げて突撃させようともした。\n\nだが、その自慢の毒泉も孔明の前には通じなかった。蜀軍は解毒の法を得、甘泉を掘り当てて、四毒泉を無傷で越えていく。これを目の当たりにした朵思は「之を見て、毛髪聳然とし」、孟獲を振り返って「此れ乃ち神兵なり」と叫んだ。敵を恐れさせるどころか、自らが恐怖を抱く側に回ってしまったのである。頼みの計は不発に終わった。\n\n最期もまた呆気ない。援軍に来た楊鋒に裏切られて一度は生け捕られ、その後、孟獲に命じられて三江城の守りに就くも、その城が陥落する際、「朵思大王、乱軍の中に死す」――名のある一騎打ちもないまま、混戦の中で討たれて果てた。険しい土地と一発の計略に頼った脇役の、これが結末である。"}, {"id": 249, "name": "呂虔", "faction": 1, "role": "武将", "rarity": 2, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [3, 2, 1, 1, 2, 1, 2], "p": [1, 2, 2, 1, 1, 1], "scores": {"W": 2.1, "B": 1.9, "S": 1.35, "A": 1.4, "G": 1.38, "K": 1.4}, "stat": {"dmg": 0.78, "area": 0.88, "cd": 1.09, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 2.05}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [10, 11, 12, 14, 18, 23, 26, 32, 48, 86], "chapN": 10, "bio": "曹操配下の武将、後軍皂旗を率いる", "profile": "曹操配下の武将。後軍の皂旗を率い、合後や護衛を任される、いわば曹操軍の堅実な実働要員である。正史では泰山を鎮め、佩刀を王祥に授けた名鎮守として知られるが、演義の呂虔は固有の見せ場に乏しく、十回もの登場を数えながら、その多くを列名と脇役に費やす量産型の脇役として描かれる。\n\nそれでも、白兵の見せ場が皆無というわけではない。第十二回、呂布配下の薛蘭を追った場面では、「呂虔、飛馬して趕い来たり、一箭にして馬下に射落とす、軍みな潰散す」――騎射で名のある敵将を射落とし、その軍を崩している。これは彼の数少ない武功だ。もっとも、一騎打ちで斬り取った実績はなく、第十一回では張遼・臧霸を相手に曹洪と組んで戦うも「利あらず」と退き、第十八回では張繡戦で負傷し、高順にも敗れて退却するなど、敗北の記録のほうがむしろ目につく。\n\nその立ち位置を端的に物語るのが、第二十三回、舌鋒鋭い禰衡の人物評である。曹操軍の将を次々こき下ろす中で、禰衡は呂虔を「磨刀鑄剣に使うべし」――刀を研ぎ剣を鋳るのに使える、と嘲った。武名を讃えるどころか、実務雑用扱いの皮肉である。第二十六回でも、曹操が兵糧をわざと敵に見せて誘う計を巡らせた際、呂虔は「糧草が先、軍兵が後とは、何の意ぞ」とその意図を解せず問い返し、引立役を務めている。\n\nとはいえ、無用の人物だったわけではない。第十回では満寵とともに名士の毛玠を推挙し、人を見出す一件を残しており、自身も「軍中の従事」として登用され、後には校尉に任ぜられるなど、行政事務官の顔も持っていた。華々しい武勇伝こそ持たぬが、列名献策と堅実な後詰めをもって曹操軍を地道に支え続けた――そんな実直な駒が、演義の呂虔である。"}, {"id": 250, "name": "陳式", "faction": 0, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 2, 1, 1, 2, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 2.1, "B": 1.9, "S": 1.35, "A": 1.4, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.78, "area": 0.88, "cd": 1.09, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 2.05}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [71, 98, 100], "chapN": 3, "bio": "黄忠配下の牙将、夏侯淵に生け捕られ後に交換で戻る", "profile": "陳式は蜀漢に仕えた牙将で、もとは老将黄忠の配下として戦場に現れる。「失敗将の見せしめ」という後世の通り名が先に立つ人物だが、演義の初登場では自ら名乗りを上げて前へ出る、気概のある一兵将として描かれている。\n\n第七十一回、定軍山の戦いがその最初の見せ場である。黄忠が出迎えを案じたとき、陳式は「将軍は動かれますな、それがしが当たりましょう」と進み出て、「忠と陳式の両人夾攻し、混殺一陣、張郃敗走す」と、黄忠と挟み撃ちにして魏の名将張郃を退ける働きを見せた。だがその後、夏侯尚と斬り結んで偽りの敗走を追ううち、両側の山から擂石・砲石を浴びせられて進むに進めず、引き返そうとした背後を夏侯淵に突かれ、ついに生け捕られて魏陣へ連れ去られてしまう。後にこの陳式は捕虜交換で蜀へ戻ることになる。\n\nその人となりは、驕慢で軍令を軽んじる質だった。第百回、諸葛亮が「伏兵あり、進むな」と正しい計を授けたとき、陳式は「丞相がまことに多謀ならば、街亭の失はあるまい」と笑ってこれを退け、鄧芝が再三止めるのも振り切って、独断で五千の兵を率い箕谷へと進んでしまう。\n\n結末は苛烈だった。果たして四面から伏兵が現れ、五千の兵はわずか四、五百の手負いにまで討ち減らされる。なおも陳式は罪を魏延に転嫁しようとするが、諸葛亮は「彼はお前を救ったのに、お前は逆に彼を引き込むか。将令に違えたこと、巧みな弁を要さぬ」と言い放ち、武士に命じて引き出させ斬らせた。軍規というものの重さを、その死をもって示した将である。"}, {"id": 251, "name": "馬遵", "faction": 1, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 3, 1, 2], "p": [1, 2, 1, 1, 2, 2], "scores": {"W": 1.0, "B": 2.15, "S": 1.6, "A": 1.75, "G": 1.45, "K": 1.85}, "stat": {"dmg": 0.75, "area": 0.93, "cd": 1.15, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 2.75, "pwr": 1.8}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [92, 93], "chapN": 2, "bio": "天水太守、姜維の主君だが彼を疑い羌中へ逃げる", "profile": "馬遵は魏の天水郡太守。演義においては、後に蜀の大黒柱となる姜維を世に出すための引き立て役として登場する、優柔不断で猜疑心の強い地方官として描かれている。\n\n第九十二回、馬遵は夏侯楙が南安城に囲まれたと聞き、「文武百官を聚めて商議」する。まさに兵を起こそうとしたそのとき、一人が外から駆け込んで「太守、諸葛亮の計に中られましたぞ」と叫ぶ。馬遵が孔明の偽計に乗りかけたところを、麾下の姜維がからくも救った場面である。続く第九十三回では、その姜維の伏兵と前後挟撃の計を採用し、「遵その計を用い、精兵を姜維に付して去らしめ、然る後みずから梁虔と引きて城を出でて等候す」と実行に移し、趙雲を一度撃退する戦果まで挙げた。だがそれは姜維の知略であって、馬遵自身の才ではない。\n\nその器の小ささは、肝心の場面で露わになる。孔明の離間の計にかかった馬遵は、稀代の人材であるはずの姜維を疑い、「これは姜維が我が城門を賺かんとするものぞ」と言って城上より乱箭を浴びせ、射殺そうとする。梁緒・尹賞にまで疑心を向け、結果として彼らの離反を招いてしまう。\n\n最後は哀れである。第九十三回、「夏侯楙、馬遵驚慌し、数百人を引きて西門を出で、城を棄てて羌中に投じて去る」――守るべき城も人も手放し、敗走の先として羌中へ逃げ込むほかなかった。家臣の力に動かされるばかりで、自らは何ひとつ掴めなかった、受け身の太守として演義に名を残す。"}, {"id": 252, "name": "張揚", "faction": 3, "role": "君主", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 1, 2, 3], "p": [1, 1, 3, 2, 3, 2], "scores": {"W": 1.0, "B": 1.65, "S": 1.8, "A": 1.6, "G": 1.89, "K": 2.15}, "stat": {"dmg": 0.73, "area": 0.91, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 1.65}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [11, 13, 14, 19, 103], "chapN": 5, "bio": "河内→大司馬。呂布を匿い救おうとして部将に殺される", "profile": "張揚は後漢末の河内太守であり、後に大司馬にまで上った地方軍閥。演義では群雄の一人に数えられるが、一騎打ちも計略も派手な指揮も持たない。その代わりに彼を彩るのは、窮地の者を見捨てぬ義理堅さと、滅びゆく旧主を救いに行って命を落とすという、武人離れした恩義の物語である。\n\n第十一回、徐州を追われ行き場を失った呂布が「乃ち去きて張揚に投じ、揚これを納る」――張揚は落ち目の呂布を黙って迎え入れた。第十三回、天下が大荒れに荒れ、献帝の朝廷が飢えに苦しんでいたとき、「河内太守張揚、米肉を献じ、河東太守王邑、絹帛を献じ、帝やや寧きを得たり」と、わずかな食糧を朝廷に差し出して帝の窮乏を一時しのがせた。続く第十四回でも「太守張揚、粟帛を具えて駕を軹道に迎う」と車駕を出迎え、その功により帝から大司馬を封じられている。\n\nそして第十九回、下邳に追い詰められた呂布を救おうと、張揚は「兵を東市に出だし、呂布を救わんと欲す」――かつて自分を頼ってきた男のために、自ら兵を動かした。だがその志は遂げられぬまま、部将楊醜に殺される。「部将楊醜これを殺し、頭を将って丞相に献ぜんと欲す」――首を曹操に差し出そうとする裏切りであった。\n\nもっとも、義の連鎖はそこで途切れなかった。張揚の心腹の将であった眭固が、主を殺した楊醜を討つのである。張揚自身が描いた策ではなく結果ではあるが、彼が人に向けた義理が、死してなお人を動かした。戦果も大局構想も乏しいが、「困った者を匿い、飢えた帝に食を献じ、旧主のために死んだ好漢」として、その人柄だけは確かに演義に刻まれている。"}, {"id": 253, "name": "朱靈", "faction": 1, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 1, 3, 1, 2], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 1.0, "B": 2.15, "S": 1.6, "A": 1.75, "G": 1.12, "K": 1.35}, "stat": {"dmg": 0.66, "area": 0.87, "cd": 1.15, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [21, 58, 59], "chapN": 3, "bio": "徐晃と共に河西を襲う曹操配下", "profile": "朱靈は曹操配下の脇役武将。後の世には一軍を率いた宿将として知られるが、演義の本文では名を連ねて指示を実行するだけの、控えめな随伴の将に留まっている。\n\n最初の登場は第二十一回。劉備が徐州出征に発つとき、曹操は朱靈と路昭の二人を同行させた。曹操いわく「我に朱靈・路昭あり、二人彼に在り、料るに玄徳いまだ敢えて心変りせざらん」――劉備の離反を防ぐための監視役としての差し向けである。対袁術戦では「玄徳兵を三路に分かち、朱靈・路昭は左に、関・張は右に、玄徳みずから兵を引きて中に居る」と左翼の一隊を任されるが、敵将紀霊を実際に刺し殺すのは張飛であり、朱靈は配置されるだけで個人の戦果はない。そして劉備はまんまと曹操の手を振り切り、朱靈は許都へ帰されることになる。\n\n渭水・河西の戦いでは、名将徐晃の副将格として組み込まれた。第五十八回「便ち徐晃をして精兵四千を引き、朱靈と同に去きて逕に河西を襲わしむ」、第五十九回「曹操、馬超は計を以て破るべしと料り、乃ち密かに徐晃・朱靈に令して尽く河を渡り西に営を結ばしめ、前後夾攻す」――前後挟撃の一翼を担う実行役である。計を立てたのは徐晃と曹操であり、朱靈はその密命を受けて結営し、挟み撃ちを担うのみであった。\n\n派手な見せ場こそ持たないが、上位者の作戦を確実に動かす駒として、要所要所に名を刻む。演義のなかでは、主役の影で盤面を支え続けた、堅実な随行の将である。"}, {"id": 254, "name": "孫乾", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 1], "p": [1, 2, 0, 6, 3, 2], "scores": {"W": 0.0, "B": 0.85, "S": 0.95, "A": 0.9, "G": 2.15, "K": 1.95}, "stat": {"dmg": 0.65, "area": 0.87, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [16, 18, 19, 22, 24, 27, 28, 31, 35, 54], "chapN": 25, "bio": "劉備配下の文臣、関羽と江夏へ救援を求めに行く", "profile": "孫乾、字は公祐。劉備陣営における使者・外交官の代表格であり、放浪の歳月を通じて主君の口となり足となり続けた純然たる説客・幕賓である。第三十五回で水鏡先生司馬徽に「孫乾・糜竺の輩のごときは、乃ち白面の書生のみ、経綸済世の才に非ず」と評された通り、戦場で剣をふるう人物ではない。第二十八回でも関羽の護送に従って「孫乾、車仗を保ちて前行す」と荷を護るのみで、戦うのは常に関羽の側であった。\n\nその真価は弁舌と胆力にある。孫乾の最大の見せ場は第三十一回、荊州での一幕だ。劉表に身を寄せようとした際、蔡瑁が「孫乾の首を斬るに如かず」と斬首を主張するなか、孫乾は正色して退かず、「乾は死を懼るるの人に非ざるなり。劉使君は忠心国の為にし、曹操・袁紹・呂布等の比に非ず」と劉備の大義を弁じ切り、ついに劉表に迎え入れさせた。袁紹のもとへ、孫権のもとへ、張魯のもとへ、そして曹操のもとへ――劉備陣営の外交はことごとく彼の双肩にかかっていた。第五十四回で孔明が呉との婚姻の縁組をまとめさせたのも、この孫乾である。\n\n策士・補佐としての働きも見過ごせない。第二十二回には「徐州は受敵の地、久しく居るべからず。兵を分かちて小沛に屯し、邳城を守り、犄角の勢を為して以て曹操を防ぐに如かず」と布陣を献じ、第十六回には窮地の主君に「城を棄てて許都に走り、曹操に投奔し、軍を借りて布を破る、これ上策たり」と進言する。第五十七回では、耒陽県で龐統を擒えようとした張飛を「龐士元は乃ち高明の人、未だ軽忽すべからず」と諫め、結果として龐統の登用を救った。\n\n流浪の時代、孫乾はいつも離散と再結集の段取りをつける人であった。第二十八回、関羽が単身で危地に踏み込もうとするのを「将軍未だ軽々しく入るべからず、ただ此間に在りて暫く歇え。某まず入りて皇叔に見え、別に商議を作さん」と先導し、敗走に沈む主君を「成敗は時あり、必ずしも傷心せざれ」と慰撫する。華々しい武功とは無縁ながら、劉備が幾度も窮地から立ち直れたその裏には、いつもこの忠実な使者の影があった。"}, {"id": 255, "name": "高翔", "faction": 0, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 2, 1, 1, 2, 1, 3], "p": [1, 1, 3, 1, 1, 1], "scores": {"W": 1.65, "B": 2.05, "S": 1.45, "A": 1.45, "G": 1.36, "K": 1.4}, "stat": {"dmg": 0.73, "area": 0.88, "cd": 1.11, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.6}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [91, 93, 95, 96, 102, 103], "chapN": 6, "bio": "蜀漢の将、列柳城を守備", "profile": "高翔は蜀漢の将で、官位は右将軍・玄都侯。五虎将に次ぐ宿将格に並べられることもあるが、演義の本文ではその高い官爵とは裏腹に、終始諸葛亮配下の二線級指揮官として描かれる。北伐の戦場で、一城・一隊を任されて動く実行役である。\n\n最も知られるのは街亭の戦いの後始末だ。第九十五回、列柳城を守る高翔は街亭の失陥を聞くと「列柳城の兵を尽く起こし、前み来たりて救応す」と全軍を挙げて魏延・王平の救援に駆けつける。「今晩、魏寨を劫し、再び街亭を復さん」と劫寨を提案するが、これは魏の伏兵にかかってしまう。「忽然一声砲響き、火光天を沖し、鼓声地を震わす。魏兵斉しく出で、魏延・高翔を垓心に囲む。二人尽力衝突するも、身を脱するを得ず」――高翔は魏延ともども囲まれ、脱出すら自力では叶わず王平に救い出される。孔明自身も第九十五回で「高翔は張郃の対手に非ず」と、その武をはっきり格付けしている。\n\n北伐後期になると、高翔は兵站の要として用いられる。第百二回、「孔明、右将軍高翔をして、一千兵を引き木牛流馬を駕せしめ、剣閣より直ちに祁山の大寨に抵り、往来して糧草を搬運し、蜀兵の用に供せしむ」――木牛流馬による糧草運搬の現場責任者である。第百三回でも運糧の囮役を担い、補給線を支える駒として働いた。\n\n一騎打ちや敵将討ち取りの華は持たず、勝てる軍を作る将でもない。だが街亭では全軍を挙げて味方を救いに走り、後年は補給という地味で不可欠な役を黙々と担った。官位の高さと実戦描写の薄さがどこか噛み合わない――そのちぐはぐさもまた、北伐という長い戦の一断面である。"}, {"id": 256, "name": "楊大将", "faction": 3, "role": "軍師参謀", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 3, 2, 1], "p": [1, 1, 2, 1, 1, 2], "scores": {"W": 0.0, "B": 1.9, "S": 2.05, "A": 2.1, "G": 1.3, "K": 1.15}, "stat": {"dmg": 0.78, "area": 0.97, "cd": 1.2, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 2.05}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [15, 16, 17], "chapN": 3, "bio": "袁術の長史、対劉備・防衛策を献じる", "profile": "楊大将は袁術配下の長史、すなわち帳下で策を献じる文官参謀である。演義での出番は第十五回から第十七回に集中し、白兵や武勇とはまったく無縁の、筋の通った献策で身を立てる人物として描かれる。\n\nその代表が第十六回の対劉備策である。「劉備の軍は小沛に屯し、取りやすしと雖も、奈ともしがたきは呂布の徐州に虎踞すること。先には許せし金帛糧馬、今に至るまで与えず、恐らくは其れ備を助けん。今まさに人をして糧食を送り与え、以て其の心を結び、其れをして兵を按じて動かざらしむべし。則ち劉備擒うべし。先に劉備を擒え、後に呂布を図らば、徐州得べきなり」――呂布を兵糧で懐柔して劉備を孤立させ、まず劉備を擒え、しかる後に呂布を図るという順序立てた戦略である。理は通っていたが、実戦では呂布が轅門射戟をもって逆に劉備を救い、策は不発に終わった。\n\n第十七回には大局を見る目も見せる。袁術が孫策を「黄口の孺子」と侮って無謀な出兵をしようとしたとき、「長史楊大将、力諫して方めて止む」と暴走を押しとどめた。さらに曹操十七万の大軍が四面から迫る危機に際しては、「寿春は水旱連年、人みな食を缺く。今また兵を動かして民を擾さば、民すでに怨みを生じ、兵至らば以て敵を拒みがたし。如かず軍を寿春に留めて戦うを必とせず、彼の糧尽くるを待たば必ず変を生ぜん。陛下しばらく御林軍を統べて淮を渡れ。一には熟に就き、二にはしばらく其の鋭を避く」と進言する。旱魃に苦しむ民情を的確に捉え、決戦を避けて糧尽きを待ち、主君を淮の南へ退避させる持久策だ。袁術も「術その言を用う」とこれを容れた。\n\n献じる策はいずれも堅実で、民の苦しみを見落とさぬ目もあった。だが採用されても結果はついてこず、仕える主君が僭号の袁術であったことも災いした。地味ながら筋の通った進言を重ねた、不遇な参謀である。"}, {"id": 257, "name": "陳琳", "faction": 3, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 2, 2, 1], "p": [1, 1, 1, 3, 4, 2], "scores": {"W": 0.1, "B": 1.5, "S": 1.85, "A": 1.85, "G": 1.81, "K": 2.05}, "stat": {"dmg": 0.75, "area": 0.94, "cd": 1.21, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.0, "pwr": 1.8}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [2, 3, 22, 32, 56], "chapN": 5, "bio": "銅雀台で詩を献じた文官", "profile": "陳琳、字は孔璋。建安七子に数えられる名筆として知られ、演義でもその核は「文章の威力」にある。だが本文の陳琳は単なる文人ではない。乱世の帰趨を読む先見を備えた諫臣であり、袁紹から曹操へと陣営を渡り歩いた筆の人でもあった。\n\nその先見は物語の早い段階で示される。第二回、大将軍何進が宦官を誅さんとして外の軍勢を都に招こうとしたとき、陳琳は「但だまさに速やかに発し、権を行いて立ちどころに断ずべし、則ち天人これに順わん。却って反って外もて大臣に檄し、京闕に臨み犯さば、英雄聚会して各々一心を懐かん。いわゆる干戈を倒しまに持ち、人に柄を授くるなり」と諫めた。刃を逆さに握って柄を相手に渡すような自滅だ、という警告である。容れられず、果たして都は大乱に陥った。第三回でも、太后の召し出しに対し「この詔は必ず十常侍の謀、切に去くべからず。去かば必ず禍あらん」と罠を見抜いている。\n\n陳琳の名を不朽にしたのは、第二十二回の檄文である。袁紹が曹操討伐を起こすにあたり、「明公の大いに操を伐つを以て、必ず須らく操の悪を数え、檄を各郡に馳せ、罪を声して討を致し、然る後に名正しく言順うべし」として一篇の檄文を草した。そこでは曹操の出自から専横、先帝陵墓の発掘までを並べ立てて正統性を全否定し、「操の首を得る者は五千戸侯に封じ、銭五千万を賞す。降る部曲には問う所あること勿れ」と懸賞と宣撫を天下に布告する。この檄文を読んだ曹操は「これを見て、毛骨悚然とし、一身の冷汗を出だし、覚えず頭風頓に愈ゆ」――持病の頭痛が吹き飛ぶほどに震撼した。敵将を斬る代わりに、一篇の文が大将軍の身を震わせたのである。\n\n冀州が陥ちて捕らえられたとき、陳琳はなお機転で身を救う。かつて主君を罵倒した檄文を咎められても、「箭は弦上に在り、発せざるを得ざるのみ」――矢は弦に番えられた以上、放たぬわけにはいかなかった、と即妙に弁じてのけた。曹操はその才を惜しんで赦し、陳琳は新たな陣営で筆を執り続ける。剣を持たずして乱世を揺るがした、まさに文事の人であった。"}, {"id": 258, "name": "楊秋", "faction": 3, "role": "武将", "rarity": 2, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 1, 2, 2, 2], "p": [1, 1, 1, 3, 1, 2], "scores": {"W": 1.0, "B": 1.85, "S": 1.95, "A": 1.9, "G": 1.42, "K": 1.35}, "stat": {"dmg": 0.66, "area": 0.87, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [58, 59], "chapN": 2, "bio": "韓遂麾下八部の一将。曹操への投降を仲介し西涼太守となる", "profile": "楊秋は西涼の韓遂麾下「八部」の一将。馬超・韓遂の反曹挙兵に加わるが、演義の本文での実像は武勇の人ではなく、求和を勧め、使者となり、寝返りを発案して自ら通報役を買って出る、謀議と降伏交渉の幕僚である。\n\n第五十八回、韓遂の八部の面々――「侯選、程銀、李堪、長横、梁興、成宜、馬玩、楊秋」――の末尾に名を連ねて挙兵に加わる。だが渭水の戦いが思わしくなくなると、楊秋の本領が出る。第五十九回、彼は韓遂に向かってこう説いた。「馬超は勇武に倚仗し、常に主公を欺凌するの心あり、便たい曹操に勝つを得るとも、怎んぞ肯えて相譲らんや。某の愚見を以てするに、暗かに曹公に投ずるに如かず、他日封侯の位を失わじ」――味方の馬超を割って曹操に内応しようという調略である。「事すでに此に至る、然らざるを得ず」と覚悟を語り、自ら使者を二度買って出て、求和の使い、そして暗投の使いを務めた。「誰か以て消息を通ずべき」と問う韓遂に「某往かんと願う」と進み出て、密書を携え曹操の寨へ赴いたのである。\n\nだがこの寝返りの計は馬超に察知される。「韓遂が引きて侯選・李堪・梁興・馬玩・楊秋の五将、陣を出ず」――その場に楊秋の「事遅きに宜しからず、速やかにこれを行うべし」という声が漏れ聞こえると、馬超は「群賊いずくんぞ敢えて我を謀害せんや」と大喝して剣を揮い斬り込む。馬玩・梁興は斬られ、楊秋ら三将は「各自逃生」と逃げ散った。恐れられるのは馬超であり、楊秋は怯える側であった。\n\nそれでも、この男の処世は最後まで筋を通した。敗勢を早々に読んで曹操へ転じた楊秋は、「侯選とともに皆列侯に封ぜられ、渭口を守らしむ」――西涼太守・列侯の地位を得て、乱世を生き延びた。武で名を残せなかった代わりに、見切りの早さと交渉で身を立てた、したたかな一将である。"}, {"id": 259, "name": "董厥", "faction": 0, "role": "文官", "rarity": 2, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 2, 2, 2], "p": [1, 1, 1, 1, 2, 3], "scores": {"W": 1.0, "B": 1.85, "S": 1.95, "A": 1.9, "G": 1.37, "K": 1.8}, "stat": {"dmg": 0.76, "area": 0.94, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 3.0, "pwr": 1.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [87, 91, 99, 116, 117, 118, 119], "chapN": 7, "bio": "掾史として南征に従軍", "profile": "董厥は蜀漢の文官。諸葛亮の掾史・丞相令史として出発し、後には輔国将軍にまで上る。演義における彼の像は、孔明のもとで文書を扱う書記役から始まり、亡国の最後まで漢室に節を守り抜いた忠臣として閉じる。\n\n最初の登場らしい登場は第九十一回、「董厥をして祭文を読ましむ」――軍の祭礼で祭文を読み上げる文書役である。武器を執る将ではなく、筆と言葉の人としての出発であった。\n\n蜀の末期、董厥は輔国将軍として剣閣の防衛を託される。第百十七回、「輔国将軍董厥、魏兵十余路境に入るを聞き、乃ち二万兵を引きて剣閣を守住す」。塵頭が大きく起こるのを見て魏兵かと疑い、急ぎ関口を固める慎重な構えを見せ、近づいてきたのが姜維・廖化・張翼の味方と知ると大いに喜んで関上に迎え入れた。この剣閣で董厥は、ひとつ鋭い洞察を口にする。「此の関は守るべしと雖も、争奈せん成都に人無きを。倘し敵人の襲う所と為らば、大勢瓦解せん」――関は守り切れても、肝心の成都が空であれば、そこを衝かれて全体が崩れる、という警鐘である。これは後に鄧艾の陰平奇襲によって、そのまま現実となった。\n\n最期は、文官の節義をもって締めくくられる。蜀が滅んだ後、董厥は姜維とともに鍾会への偽降に加わるが、その計も潰える。第百十九回、「廖化・董厥、皆病に託して起たず、後に皆憂死す」――魏に仕えることを病と称して拒み、憂いのうちに世を去った。華々しい武功も国家を動かす権も持たなかったが、危機を見抜く目と、亡国に殉じる忠とを併せ持った、蜀後期を支えた重臣の一人である。"}, {"id": 260, "name": "韓暹", "faction": 3, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 1, 1, 2, 2, 2], "p": [1, 1, 1, 2, 3, 1], "scores": {"W": 1.45, "B": 1.95, "S": 1.95, "A": 1.9, "G": 1.41, "K": 1.8}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.13, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [13, 14, 17], "chapN": 3, "bio": "白波帥、献帝救援に来る。後に劉備に斬られる", "profile": "韓暹は、もとは白波の賊軍を束ねた頭目──白波帥である。後漢の朝廷が李傕・郭汜の乱に追われ、献帝が長安を脱して東へ逃げ落ちる窮地に陥ったとき、第十三回で「急ぎ故の白波帥韓暹、李樂、胡才の三処の軍兵を召して前来り救応せしむ」と、河東の賊軍を率いて天子の護衛に馳せ参じた。山賊の身から一転、征東将軍に封じられ、漢室の最後の楯の一人へと成り上がった、乱世ならではの人物である。\n\nだが、その「天子の功臣」という看板は長くは保たなかった。安邑に落ち着くと、韓暹は李樂と連名で、入れ墨者・部曲・巫医・走卒のたぐい二百余名を勝手に校尉や御史に取り立て、官位を私物化する。挙句に兵を放って民を掠めさせ、「人々嗟き怨む」と本文に記される失政を重ねた。やがて曹操が天子を迎えに来ると聞くや恐れをなして逃げ、袁術のもとへ走る。董昭は彼を「無謀の輩」と切り捨て、曹操も「楊奉・韓暹は誠に道うに足らず」と歯牙にもかけなかった。\n\n第十七回では、陳登の弁舌一つで今度は呂布へ寝返る。「向に漢臣たりしに、今乃ち叛賊の臣となるか」と諭され、「吾れ漢に帰せんと欲するも、恨むらくは門無きのみ」と応じて内応を承知した。火を合図に反戈し、呂家の軍を寨へ引き入れて袁術軍を破る働きはあったが、立案者は陳登であり、韓暹はあくまで実行の駒にすぎない。\n\n最期はあっけない。劉備に招かれた偽りの宴で斬られ、その首は「これ韓暹・楊奉の首級なり」と差し出された。関中で天子を守った功も、玄徳の言を借りれば「烏有に化す」。一度は漢の正統に与しながら、節を守れず流された風見鶏の末路であった。"}, {"id": 261, "name": "公孫渕", "faction": 3, "role": "君主", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 0, 1, 2, 2, 2], "p": [2, 1, 0, 2, 2, 1], "scores": {"W": 0.75, "B": 1.85, "S": 1.95, "A": 1.9, "G": 1.32, "K": 1.65}, "stat": {"dmg": 0.68, "area": 0.94, "cd": 1.16, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.0, "pwr": 1.9}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [105, 106, 114], "chapN": 3, "bio": "遼東の太守、燕王を自称し反乱・司馬懿に滅ぼされる", "profile": "公孫淵は、遼東に割拠した独立の君主である。地の文には「淵は長大、文武兼備、性剛にして闘いを好む」と一言されるが、その「剛好闘」が真っ先に向いた相手は外敵ではなく身内であった。叔父・公孫恭の位を奪い取って遼東の主の座に就いた簒奪者──それが演義の描く公孫淵の出発点である。\n\n魏から大司馬・楽浪公の爵を受けながら、それに飽き足らず、第百五回で自ら燕王を号し、「紹漢」と改元して宮殿を建て官職を立て、ついに兵を起こして魏へ侵攻した。漢を継ぐという名分を借りた僭称だが、地の文も幽州刺史の上表も、これを一様に「造反」「反賊」と断じている。十五万の大軍を擁したものの、討伐に向かった司馬懿の前では構想の浅さがことごとく露呈した。\n\n第百六回、公孫淵は卑衍・楊祚に八万を分け、遼隊に塹壕を掘り鹿角をめぐらせて二十余里にわたる堅陣を布く。だが司馬懿は「賊我と戦わず、我が兵を老いさせんと欲するのみ」と意図を看破し、空巣を突いて崩した。会戦も計略もすべて読み切られ、配下の卑衍は夏侯霸に一刀で斬られ、公孫淵自身は敗兵を率いて襄平城へ逃げ込み、門を閉じて固く守るほかなかった。籠城中に糧は尽き、兵は牛馬を屠って食らい、「人々怨恨し、各々守る心無く」、ついには主君の首を斬って城を献じようとする者まで現れる。\n\n諫言する忠臣・賈範と倫直を市で斬り捨てた暴君は、降伏を乞うても拒まれ、最後は息子の公孫修とわずか千の兵で南門を開いて夜陰に逃げた。が、父子もろとも擒えられて斬られ、宗族七十余名も皆殺しにされる。呉の孫権から燕王の封と財宝を引き出しながら、魏を恐れてその使者を斬り首を曹叡へ送る──そんな二股の軽信外交を重ねた末の、孤立無援の滅亡であった。「遼東の雄」という通説の像とは裏腹に、演義の公孫淵は、自ら戦う場面すら一度もないまま敗亡していく、典型的な反逆君主として描かれている。"}, {"id": 262, "name": "諸葛緒", "faction": 1, "role": "武将", "rarity": 1, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [1, 1, 0, 1, 2, 2, 2], "p": [0, 0, 1, 0, 0, 1], "scores": {"W": 0.75, "B": 1.85, "S": 1.95, "A": 1.9, "G": 0.3, "K": 0.55}, "stat": {"dmg": 0.67, "area": 0.94, "cd": 1.16, "amount": 2, "knock": 0.65, "crit": 0.05, "duration": 6.8, "pwr": 1.8}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [116, 117], "chapN": 2, "bio": "雍州刺史。姜維の退路を断つ任を負うが計に欺かれ、鍾会に檻車送りにされる", "profile": "諸葛緒は、魏の雍州刺史。鄧艾が蜀を伐つ大軍を起こしたとき、その一翼を担って戦場に現れる将である。第百十六回、鄧艾は「雍州刺史諸葛緒を遣わし、兵一万五千を引きて、先ず姜維の帰路を断たしむ」と命じた。陰平の橋頭を押さえて姜維の退路を塞ぐ──伐蜀全体の成否を左右しかねない重い役目だが、演義における諸葛緒の役回りは、終始一貫して「しくじる役」であった。\n\n姜維はその裏をかく。孔函谷へ兵を入れ、雍州を奪うと見せかけたのである。報を受けた諸葛緒は「雍州は吾が合兵の地なり。もし疎かにせば、朝廷必ず罪を問わん」と大いに驚き、慌てて本隊を引き抜いて雍州の救援へ向かわせ、橋頭にはわずかな兵を残すのみとした。その隙に橋頭は奪われ、寨柵は焼かれる。偽計をまんまと見抜けず、要衝をやすやすと明け渡した。\n\n第百十七回、剣閣の下では姜維と正面からぶつかる。だが姜維が五千の兵を率いて関を駆け下り、まっすぐ魏陣へ突き入って「左に衝き右に突き」暴れ回ると、諸葛緒は「大敗して走り」、数十里も退いて寨を構えるありさまだった。名のある敵を一人も討てぬまま、ただ突き崩される側に立ち続ける。\n\n最期も自らの武功ではなく、味方の咎めによって退場する。鍾会は「吾、汝をして陰平の橋頭を守らしめ、以て姜維の帰路を断たしむ。如何ぞ失えるや。今また吾が令を得ずして擅自に進兵し、以てこの敗を致す」と激怒し、諸葛緒を檻車に乗せて洛陽へ送り、その一万五千の兵まで取り上げて自らの配下に組み入れてしまった。猛将でも知将でもなく、姜維の鮮やかな用兵を引き立てるために配された、敗者の役どころである。"}, {"id": 263, "name": "毛玠", "faction": 1, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 0, 1, 2, 2, 2], "p": [2, 2, 3, 0, 0, 1], "scores": {"W": 0.75, "B": 1.85, "S": 1.95, "A": 1.9, "G": 1.5, "K": 1.25}, "stat": {"dmg": 0.68, "area": 0.94, "cd": 1.16, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 3.0, "pwr": 1.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [10, 11, 14, 24, 39, 45, 46, 48, 50], "chapN": 9, "bio": "曹操配下の武将、于禁と共に水軍都督となる", "profile": "毛玠、字は孝先。陳留平邱の人で、曹操に仕えた文官である。第十回、満寵と呂虔がそろって一人の士を薦め、曹操もこれを招いて従事とした──それが毛玠の初登場である。正史では「天子を奉じて不臣を令す」と曹操に進言し、屯田を建議した清廉な人事の名臣として知られるが、演義はその国家構想や人事の功をほとんど描かない。代わりに描かれるのは、銭糧をつかさどり、後にとんでもない大役を背負わされる実務官僚の姿である。\n\n第十四回では任峻とともに典農中郎将に任じられ、銭糧の催督──兵糧と軍資の調達督促という、後方を支える地味だが要の職に就く。第二十四回には占いめいた一面も見せ、東南の風に青紅の牙旗が折れた凶兆から「愚意以為らく、今夜必ず人の来たりて寨を劫かす有らん」と曹操に進言し、劉備軍の夜襲を事前に察知させた。文官らしい勘の冴えを覗かせる場面である。\n\nところが赤壁の戦いで、毛玠の立場は一変する。第四十五回、曹操は蔡瑁・張允を失った後、衆将の中から毛玠と于禁を選んで水軍都督に据えた。水戦の素人二人にである。劉曄は「この両個の手の裏にては、好歹水軍の性命を送らん」と早くもその破滅を予告する。第四十六回の草船借箭では、南軍の急襲を恐れて弓弩手にひたすら矢を射させ、結果として孔明に十万本の矢を献上してしまう。第四十八回には「大小の船隻、俱に已に配搭連鎖して停当たり」と船を鎖で繋ぎ整えるが、それは龐統の連環の計に乗せられた準備に過ぎなかった。\n\nそして第五十回、赤壁の業火に水軍は壊滅する。敗走の最中、毛玠が戦場で動く唯一の描写が訪れる。「正に走るの間、毛玠、文聘を救い得て、十数騎を引きて到る」──敵将を斬るでも単騎で奮戦するでもなく、味方の文聘を救って十数騎で合流するだけの、退却の一齣であった。清廉硬骨の名臣という通説の像と、水軍指揮で大敗を喫する脇役という演義の像。その落差にこそ、演義の毛玠の味わいがある。"}, {"id": 264, "name": "高定", "faction": 3, "role": "武将", "rarity": 1, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [1, 1, 1, 1, 2, 1, 3], "p": [1, 2, 1, 1, 1, 2], "scores": {"W": 1.0, "B": 1.95, "S": 1.45, "A": 1.45, "G": 1.32, "K": 1.75}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.15, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [87], "chapN": 1, "bio": "越雋太守。反乱に加わるが離間策で雍闓を斬り降伏、益州太守となる", "profile": "高定は越雋郡の太守。建寧太守の雍闓、牂牁太守の朱褒と結び、孟獲に与して南方三郡の反乱の一角を成した武将である。第八十七回、諸葛亮の南征においてのみ登場する人物だが、その描かれ方は終始「計略にかけられる駒」であった。\n\n反乱軍は三路に分かれ、雍闓主導の合議のもと、高定は中路を割り当てられる。だが戦場で自ら刃を交える場面はない。白兵を振るうのはもっぱら部将の鄂煥である。身の丈九尺、面貌醜悪、方天戟を使って「万夫不当の勇」を持つこの猛将に、高定はすべての武働きを委ねていた。自軍は孔明の伏兵に「殺傷大半」され、あえなく大敗する。\n\n高定を動かしたのは、孔明の仕掛けた反間の計である。捕えた兵を解き放ち、雍闓の軍中に高定への帰心を植えつけ、二人の間に疑いを生じさせた。鄂煥は「闓を殺して以て孔明に投ずるに如かず」と進言し、高定はこれに従う。宴を設けて雍闓を招き、鄂煥に後路を伏せさせて討たせ、続いて朱褒も鄂煥が刺し殺した。降伏に逆らう兵には「順わざる者は皆これを戮さん」と一喝し、烏合の軍を一斉に拝伏させている。\n\n孔明はかねて「吾、高定は乃ち忠義の士なるを知る。今、雍闓に惑わされ、以てかくの如きに致るのみ」と評していた。武勇ではなく「義」を見込まれたのである。雍闓の首を帳下に献じて降った高定は、その忠義を買われ、鄂煥を牙将として従え、益州太守に任じられて三郡を総摂することになった。とはいえそれも、すべては孔明の手のひらの上での処遇である。自立した武将というより、巧みに使われ、巧みに生かされた寄り親──それが演義の高定の姿であった。"}, {"id": 265, "name": "吳國太", "faction": 2, "role": "婦人", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 1, 2], "p": [1, 2, 0, 3, 2, 3], "scores": {"W": 0.1, "B": 0.7, "S": 0.85, "A": 0.7, "G": 1.69, "K": 2.0}, "stat": {"dmg": 0.57, "area": 0.84, "cd": 1.23, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.75, "pwr": 0.75}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [3, 7, 9, 43, 44, 54, 55, 61], "chapN": 8, "bio": "孫権の叔母(継母格)、孫策の遺言を孫権に思い出させる", "profile": "呉国太は、孫権の叔母にして継母格にあたる江東の老母である。武器を取ることも軍を率いることもないが、演義は彼女を「孫呉の家内における最終決裁者」として、要所要所に登場させる。骨肉の論理を盾に、男たちの政治判断をひっくり返してしまう女性の権力者──それが呉国太である。\n\nその触媒としての働きは、赤壁開戦の起点にまで及ぶ。第四十四回、開戦をためらう孫権に向かって、彼女は亡き姉の遺言を思い起こさせる。「先姉の遺言に云う、『伯符臨終に言有り、内事決せざれば張昭に問い、外事決せざれば周瑜に問え』と」。この一言が周瑜召還の引き金となり、呉の戦意を定めた。\n\n呉国太の真骨頂は、第五十四回の甘露寺にある。周瑜の偽装婚姻の計を逆手に取り、彼女は劉備を本物の婿に迎えると決めた。「吾、いまだ劉皇叔を識らず、明日約して甘露寺に相見えん。もし吾が意に中らずんば、汝らの行事に任せん。もし吾が意に中らば、吾自ら女児をこれに嫁せん」。そして劉備を一目見るや「真に吾が婿なり」と大喜びする。廊下に刀斧手を伏せた孫権を「玄徳すでに我が婿たり、即ち我が児女なり。何故ぞ刀斧手を伏す」と叱責し、仕掛けた賈華を斬れと命じ、刀斧手は「頭を抱えて鼠竄して去る」。この肝の据わった一喝が、孫劉の婚姻同盟を実体のあるものに変え、天下三分の鼎の足を一本立たせたのである。\n\n第六十一回でも、その家長権は冴えわたる。孫夫人と阿斗を呉に取り戻して荊州と交換しようという危うい策が持ち上がった折、彼女は屏風の裏から大喝して躍り出る。「この計を進むる者は斬るべし。吾が女の命を害せんと欲するか」。さらに荊州奪取をもくろむ孫権を「汝、父兄の業を掌り、坐ながら八十一州を領して、なお自ら足らず、乃ち小利を顧みて骨肉を念わず」と叱りつけ、計画を握り潰した。孫権も「老母の訓、豈に敢えて違う有らんや」と諾々と従うほかない。軍略も武力も持たぬ一人の老母が、骨肉の情と家長の権威だけを武器に、孫呉の重要局面を幾度も動かした。賢母というだけでは収まらない、したたかな女性権力者である。"}, {"id": 266, "name": "何進", "faction": 3, "role": "武将", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 2, 2], "p": [1, 2, 0, 0, 3, 1], "scores": {"W": 0.0, "B": 1.25, "S": 1.65, "A": 1.45, "G": 1.13, "K": 2.0}, "stat": {"dmg": 0.64, "area": 0.91, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.45}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [1, 2, 3, 4, 13, 22, 120], "chapN": 7, "bio": "屠殺業出身の大将軍。外兵を招き宦官に殺される", "profile": "何進は、後漢末の大将軍。「大将軍」の肩書ゆえ武人と思われがちだが、その実像は武とはほど遠い。もとは肉を売る屠殺業の出で、妹が宮中に入って貴人となり、やがて皇后にのぼった縁故によって権を得た外戚である。「進は身を屠家に起こす。妹の宮に入りて貴人となるに因り……進は是れに由りて権重任を得たり」と本文に記される通り、武功ではなく姻戚関係で成り上がった人物であった。\n\n権力の頂点に立った一瞬はある。霊帝が崩じた折、何進は何顒・荀攸・鄭泰ら大臣三十余員を率いて宮中へ駆け込み、霊帝の柩前で甥にあたる太子・弁を擁立し、蹇碩や董太后の一派を退けて参録尚書事として朝政の中枢を握った。しかしそこから先が、ことごとく裏目に出る。\n\n最大の過ちが、宦官誅滅の手段である。十常侍を一掃しようと図った何進は、「四方の英雄の人士を召し、兵を勒して京に来たらしめ、尽く閹豎を誅せん」と、外の軍勢──董卓を都へ招き寄せる愚策を選んだ。陳琳は「目を掩いて燕雀を捕らうるが如し」と諫め、曹操は宦官誅滅などその獄吏一人で足りると説き、盧植・鄭泰も止めたが、何進は「これ懦夫の見なり」「汝ら小輩、安んぞ朝廷の大事を知らんや」と忠言をすべて退けた。地の文は彼を「沒決断の人」と評し、その優柔不断ぶりを繰り返し突いている。\n\n最期は哀れというほかない。宦官の罠と知らず、太后の召しに応じて「吾、天下の権を掌る。十常侍敢えて如何せん」と昂然と宮中へ入った何進は、伏せられた甲士に囲まれ、なすすべもなく「両段に砍られて」絶命した。その死は宦官と董卓の専横を招き、漢室崩壊の引き金そのものとなる。物語の幕を閉じる第百二十回の総括の詩にも「何進無謀にして中貴乱れ、涼州の董卓朝堂に居る」と、乱世の元凶として名指しされている。優柔不断ゆえに天下を傾けた、断罪され続ける外戚である。"}, {"id": 267, "name": "虞翻", "faction": 2, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 1, 1, 1], "p": [1, 2, 1, 5, 1, 2], "scores": {"W": 1.0, "B": 1.0, "S": 1.0, "A": 1.0, "G": 1.92, "K": 1.35}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 2.75, "pwr": 1.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [15, 29, 43, 75], "chapN": 4, "bio": "呉の文官、舌戦群儒で孔明に論難する", "profile": "虞翻は、呉に仕えた文官。会稽の郡吏の出で、一貫して弁舌と人脈をもって働く実務的な説客として描かれる。もとは王朗に仕え、「孫策に降れ」と諫めたが容れられず去った。後に董襲の推挙によって孫策の功曹として迎えられる。\n\nその登場早々の手柄が、人を結ぶことであった。第十五回、周泰が深手を負ったとき、虞翻は「この人は沛国譙郡の人、姓は華、名は佗、字は元化。真に当世の神医なり。当に引きてこれを見えしむべし」と、名医・華佗を孫策に引き合わせ、周泰を癒させている。賢郡吏・賢士と評されるのは、この見識を買われてのことであった。\n\n弁舌の士としての見せ場は、しかし二度に分かれて明暗を分ける。第四十三回、赤壁を前に孔明が呉の群臣と渡り合う舌戦群儒の場では、虞翻も冷笑を浮かべて孔明に噛みついた。だが鋭く切り返されて「対うる能わず」と論破され、苦杯をなめている。その雪辱を果たすのが第七十五回である。関羽討伐戦のさなか、虞翻は自ら志願して「某、三寸不爛の舌を憑りて、公安の傅士仁を説きて来降せしめん、可なるか」と申し出た。\n\n幼少の頃からの傅士仁との旧交を恃み、利害を説いて心を動かす。「某、幼きより士仁と交わり厚し。今もし利害を以てこれを説かば、彼必ず帰らん」──書状を矢に結んで城中へ射込むという手まで使い、ついに傅士仁を印綬持参で投降させてみせた。血を流さず一城を収めたこの説得は、荊州奪取直後の呉の攻勢を確かなものにした、鮮やかな一手であった。白兵も軍略も国家構想も持たぬ虞翻だが、三寸不爛の舌一枚で局面を動かした、演義屈指の実務的説客である。"}, {"id": 268, "name": "史渙", "faction": 1, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [3, 1, 1, 1, 2, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.9, "B": 1.9, "S": 1.35, "A": 1.4, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.68, "area": 0.87, "cd": 1.09, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.9}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [19, 30, 31, 32], "chapN": 4, "bio": "徐晃の部将、袁尚に射殺さる", "profile": "史渙は、徐晃の部将。官渡の戦いの前後にだけ姿を見せる、魏の端役の偏将である。本文が彼に与える肩書は終始「徐晃部将」のみで、武勇を讃える称号の類は一切ない。その出番は三つの場面に尽きる。\n\n一つは、曹操の遣い手としての働き。第十九回、曹操は「即ち史渙を遣わして眭固を追斬せしむ」と命じ、史渙は眭固を追って斬る役を担った。とはいえこれは命令文として記されるのみで、本人がいかに斬ったかという白兵の描写はない。二つめは、官渡における焼き働きである。第三十回、徐晃に従って烏巣ならぬ韓猛の糧車を襲い、「史渙便ち人夫を殺散し、火を放ちて糧車を焼く」と、荀攸が立て徐晃が率いた糧道遮断の作戦を、実働役として手堅く果たした。\n\nそして三つめが、彼の最期となる。第三十一回、倉亭の戦いで史渙は袁尚に挑みかかった。だが「両騎相交わり、三合せざるに、尚馬を撥して斜めに走る」と袁尚が逃げにかかり、振り向きざまに放った一矢が「正に史渙の左目に中たり、馬より墜ちて死す」。三合と渡り合うこともなく、左の眼を射抜かれて即死してしまう。武勇の見せ場を持たぬまま、噛ませ犬として戦場に散った一将であった。"}, {"id": 269, "name": "呂曠", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [3, 1, 1, 1, 2, 1, 2], "p": [1, 1, 1, 2, 1, 1], "scores": {"W": 1.9, "B": 1.9, "S": 1.35, "A": 1.4, "G": 1.15, "K": 1.2}, "stat": {"dmg": 0.68, "area": 0.87, "cd": 1.09, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.9}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [32, 33, 35], "chapN": 3, "bio": "袁尚の大将、後に曹操へ降る、呂翔の兄弟", "profile": "呂曠は、もと袁尚配下の「大将」。弟の呂翔と一組で登場する、河北の雑兵級の武将である。一見すると勇将らしき見せ場もあるが、その実態は、降伏と寝返りを重ねながら媒酌・招安・詐降の道具として使い回された末に討たれる、典型的な噛ませ犬であった。\n\n唯一の武功は緒戦にある。第三十二回、「大将呂曠、馬を拍ち刀を舞わせて、来たりて岑璧と戦う。二将戦うこと無数合、曠、岑璧を馬下に斬る」と、敵将の岑璧を馬上から斬り落とした。だがこの一勝の後、呂曠の歩みは降参の連続となる。袁尚から袁譚へ降り、さらに曹操へと再び降る。曹操は彼を列侯に封じ、河北の人心を手なずける駒として重宝した。\n\n以後の出番は、もっぱら曹操の指し手の実行役である。第三十二回では曹操と袁譚の婚姻の媒、すなわち仲人を命じられ、馬延・張顗の招安にも遣わされて降兵を率いてこさせた。第三十三回では高幹を相手に、甲を脱ぎ馬を棄てて偽りの投降を演じ、「曹軍新たに到る、その軍心未だ定まらざるに乗ずべし、今夜寨を劫かさん。某ら先に当たらん」と誘い込みの詐降に加担する。いずれも策を立てたのは曹操であり、呂曠はただ命のままに動く実行役にすぎなかった。\n\nその最期は、緒戦の威勢が嘘のようにあっけない。第三十五回、新野で趙雲と相対した呂曠は、「吾は乃ち大将呂曠なり。丞相の命を奉じ、特に来たりて汝を擒えん」と名乗りを上げたものの、数合も渡り合えぬうちに一突きで刺し殺された。一勝はあれど返り討ちに終わる、独立した武名を持たぬ三流武将であった。"}, {"id": 270, "name": "牛金", "faction": 1, "role": "武将", "rarity": 1, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [3, 2, 0, 1, 1, 0, 2], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 1.85, "B": 1.3, "S": 0.5, "A": 0.55, "G": 0.0, "K": 0.4}, "stat": {"dmg": 0.67, "area": 0.84, "cd": 1.1, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 0, "pwr": 1.75}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [51], "chapN": 1, "bio": "曹仁配下の驍騎。南郡で吉吋に出戦", "profile": "魏の曹仁配下に属した驍騎、牛金。「勇猛な騎将」を意味するその一語だけが、演義に残された彼の肩書である。登場は第五十一回のただ一場のみ。赤壁の戦の後、南郡をめぐって曹仁と周瑜が攻防を繰り広げる、その戦場で牛金は血気盛んな突撃の将として姿を現す。\n\n城下に呉軍が迫っても曹仁が打って出ようとせぬのを見て、牛金は奮然と進み出て言う。「兵が城下まで迫りながら戦わぬのは臆病。いわんや我が軍は敗れたばかり、まさに鋭気を取り戻すべき時。某に精兵五百を借りたまえ、一死を決して戦い申す」と。願いは容れられ、彼は五百騎を率いて城門を躍り出る。だが呉将丁奉がこれを迎え、四、五合と斬り結んだところで偽りの敗走を装う。牛金は勢いに乗って深追いし、敵陣の真っただ中へ引き込まれた。気づけば四方は呉兵の囲み。「左右に衝突するも、出るを得ず」――猛り立った突撃は、そのまま重囲の罠へと変わっていた。危ういところを曹仁自らが駆けつけ救い出す。\n\n血の気の多さでは人後に落ちぬが、戦果はついに伴わなかった。後に城中から討って出て周瑜を生け捕りにせんと迫る場面もあるが、これも徐盛・丁奉の二将に命がけで阻まれて果たせない。退路を断たれた逃走では、呂蒙の読みどおり小道へ追い込まれ、乱れた柴に道をふさがれて馬を捨てて逃げる始末。呉軍は捨てられた馬五百余匹を悠々と手に入れた。\n\n名のある敵将を一人も討たぬまま、牛金は終始「落とされ役」を務める。だがその猛々しい出撃の願いと、囲みの中で左右に斬り込み続けた姿には、戦果には恵まれずとも前へ出ようとする一騎の気概が確かに刻まれている。"}, {"id": 271, "name": "孫亮", "faction": 2, "role": "君主", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 1], "p": [1, 2, 0, 0, 3, 2], "scores": {"W": 0.0, "B": 0.25, "S": 0.1, "A": 0.05, "G": 1.25, "K": 1.95}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.1}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [108, 111, 113], "chapN": 3, "bio": "孫権の三子、潘夫人の生・呉帝となる", "profile": "呉の第二代皇帝、孫亮。孫権の三子にして潘夫人の生んだ末子であり、十歳前後で帝位に即いた幼帝である。父孫権の死後、諸葛恪に擁立されて立つが、その治世は終始、諸葛恪・孫峻・孫綝と相次ぐ権臣に握られ、玉座にありながら国政の実権は一度も自らの手に帰さなかった。聡明と無力が同居する、悲運の少年君主であった。\n\nその聡明さを示す唯一の見せ場が、第百十三回の蜜の逸話である。蜜の中に鼠の糞が混じっていたのを、孫亮は供した者の仕業か、それとも蜜を管理する者の仕業かを推理によって言い当てた。幼くして鋭い知恵を備えていたことが、この小さな一幕に凝縮されている。だが時代は、その知恵に活躍の場を与えなかった。\n\n主体性を見せた数少ない場面は二度ある。第百八回、専横を極めた諸葛恪の誅殺にあたり、孫亮は孫峻・滕胤の忠義を見込んで「卿らに真の忠義あらば、ひそかにこれを図れ」と密命を下す。だがこの一件の後、権柄はそのまま孫峻へと移った。やがて孫綝の専権が極まると、孫亮は「孫綝は権を専らにし、みだりに人を殺し、朕を欺くこと甚だし。今これを図らずば必ず後患となろう」と禁兵を起こして討とうとするが、計画は全尚の妻の密告で漏れる。剣を抜いて出ようとした帝は近臣に衣を引かれて止められ、孫綝に「無道の昏君」と罵られて廃され、会稽王へと落とされた。文武百官は帝ではなく権臣に従い、ただ「願わくは将軍の令に従わん」と頭を垂れるばかりであった。\n\n江東三世の正統な血を引きながら、その名分は遂に機能しなかった。聡明な少年が傀儡として立てられ、傀儡のまま退けられる――孫亮の生涯は、衰えゆく呉の権力構造そのものを映す鏡であった。"}, {"id": 272, "name": "王子服", "faction": 3, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 2, 1, 1], "p": [1, 2, 0, 0, 3, 2], "scores": {"W": 0.0, "B": 1.3, "S": 1.2, "A": 1.25, "G": 1.25, "K": 1.95}, "stat": {"dmg": 0.62, "area": 0.9, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 1.25}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [20, 21, 23, 24], "chapN": 4, "bio": "工部侍郎、衣帯詔の同盟者で曹操に捕えられる", "profile": "後漢朝廷の工部侍郎、王子服。曹操の専横に抗した衣帯詔の同盟者の一人として、忠臣の列に名を連ねる文官である。代々漢の禄を食んできた家柄を誇りとし、「吾が祖宗は世々漢禄を食む、豈に忠心無からんや。願わくは兄を助けて一臂の力をなし、共に国賊を誅せん」と董承に応じて義状に署名した。\n\nその忠義には、しかし一筋縄ではいかぬ顔がある。第二十回、衣帯詔の謀を知った直後、王子服は董承に向かって「吾まさに出首すべし(密告するぞ)」と二度までも脅しをかけてみせる。聖人然とした忠臣像とは少し違う、挑発癖をのぞかせる人物として描かれているのだ。連判には自ら吳子蘭を「吾と至厚」と見込んで引き入れ、同志に名を連ねさせた。\n\n彼の最大の献策は第二十三回にある。劉表と袁紹、馬騰と韓遂が大軍を起こして許昌へ迫り、曹操が兵馬をことごとく出して迎え撃ち城中が手薄になった――その隙を読み、「今夜、府中の大宴、元宵を慶賞するに乗じ、府を囲み突入してこれを殺せ。この好機を失うべからず」と、元宵の宴に乗じた曹操暗殺を立案する。五家の僮僕を糾合すれば千余人は動かせると皮算用までしてみせた。だが計画は、家僕の中から出た離反者・秦慶童の密告によって、実行を前にあえなく瓦解する。\n\n捕えられた王子服は、曹操の取り調べに「並びて未だ甚事を商議せず(何も相談などしておらぬ)」と白を切り、秦慶童との対質にも「主を誣う、聴くべからず」と反証を試みる。だが「皆な招きて証明白なり」と崩され、衣帯詔の同志もろとも処刑された。漢室への忠心を掲げて立ち、計画は実らず散った――除奸の志に殉じた、失敗の臣であった。"}, {"id": 273, "name": "黄奎", "faction": 3, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 1], "p": [1, 1, 0, 2, 4, 1], "scores": {"W": 0.0, "B": 0.85, "S": 0.95, "A": 0.9, "G": 1.36, "K": 1.9}, "stat": {"dmg": 0.58, "area": 0.87, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [57, 58], "chapN": 2, "bio": "門下侍郎。馬騰と曹操暗殺を謀るが妾の密通で露見、処刑", "profile": "後漢朝廷の門下侍郎、黄奎。曹操に仕える文官でありながら、その胸の内には深い反曹の炎を燃やしていた。父の黄琬を李傕・郭汜の乱で失った私怨と、漢室への忠とが重なり合い、曹操を「君を欺く者は操賊なり」と奸賊と断じて、その打倒を志した人物である。後人の詩は彼を「藎臣(忠なる臣)」と讃えており、その忠の純度こそが演義に刻まれた黄奎の姿である。\n\n第五十七回、曹操は西涼の馬騰を都へ招き、行軍参謀の役を黄奎に命じた。黄奎はこの任を逆手に取る。馬騰の陣へ労軍の使者として赴いた彼は、その場で本心を明かし、「操、公を城に入れ君に面せしめんと欲す、必ず好意にあらず」と告げて、馬騰と曹操暗殺の密約を結ぶ。衣帯詔の大義を持ち出し、「公、竟に衣帯詔を忘れ却るか」と馬騰を奮い立たせた。「曹操が城を出て点兵する場で、これを斬らん。されば大事成る」――これが二人の描いた段取りであった。\n\nだが、この謀は外敵にではなく、最も身近な場所から崩れた。黄奎は酔った勢いで愛妾の李春香に計画の全容を漏らしてしまう。妾は妻の弟である苗澤と私通しており、苗澤を通じてこの密謀はそのまま曹操の耳へと届けられた。「妾、苗澤に告げ、澤、曹操に報知す」――家庭内の保秘すら御せなかった一点が、すべてを奈落へと引き落とす。\n\n計画は露見し、黄奎は一族もろとも捕えられた。「無罪!」と大叫しながらも、彼に弁明の余地は残されておらず、ことごとく斬に処せられた。隠忍して機をうかがう司馬懿とはまさに正反対の、保秘崩壊の典型である。それでもなお、父の仇と漢室への忠を最後まで曲げなかったその一徹さゆえに、後世は彼を忠臣と呼んで惜しんだのである。"}, {"id": 274, "name": "簡雍", "faction": 0, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 1], "p": [1, 1, 1, 6, 1, 2], "scores": {"W": 0.0, "B": 0.85, "S": 0.95, "A": 0.9, "G": 1.87, "K": 1.15}, "stat": {"dmg": 0.58, "area": 0.87, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [18, 19, 22, 24, 28, 31, 35, 39, 41, 45], "chapN": 14, "bio": "劉備配下の文臣、陰陽に通じ長板で趙雲に助けられる", "profile": "蜀漢の文臣、簡雍。劉備が微賤の頃から付き従った古参の幕賓であり、弁舌と使者の役を得意とする文官である。陰陽の術にも通じ、人前でも臆さぬ飄々とした風があった。ただし第三十五回で水鏡先生司馬徽は、関羽・張飛・趙雲を「皆な万人の敵」と武の側に挙げる一方、簡雍ら文臣を「白面の書生、経綸済世の才にあらず」と断じている。演義自身が、彼を天下を経営する器とは見ていないのだ。\n\nその簡雍の本領は、ただ一点、弁舌の場にある。第六十五回、益州平定の大詰め、劉備に降るかどうか迷う劉璋を前にして、簡雍は単身その城門へ乗り込んだ。「傲睨自若(あたりを睥睨して泰然たり)」――敵地にあって少しも臆さぬその様で劉璋にまみえ、「玄徳の寛洪大度、並びに相害するの意なし」と説き、ついに劉璋に降伏を決意させた。劉璋は彼を厚くもてなしたという。第十八回の許都への救援使、第二十八回の劉表説得使も同じ系譜で、口先一つで局面を動かすのが彼の働きであった。\n\n戦場での彼は、まるで逆の姿を見せる。博望坡の火計では「慶喜の筵席を準備し、功労簿を整えて伺候せよ」と命じられる、宴と帳簿の係であった。第四十一回、当陽の長坂では陰陽の課を占って「これ大凶の兆なり、応は今夜に在り、主公速やかに百姓を棄てて走るべし」と凶事を言い当てるが、占って当てるだけで策はなく、本人は逃げ遅れて一将に槍で刺され、馬から転げ落ちる。これを救い出したのが趙雲であった。守城を任されても第二十四回には城を守りきれず棄てて走っている。\n\n第六十五回で秦宓には「小輩、志を得て傍若無人」と叱られる、そんな憎めぬ毒気もまた彼らしい。武も統率も国家構想も持たぬ。だが微賤の昔から劉備の傍らにあり、ここ一番の交渉でだけは敵地に堂々と乗り込んで一郡を無血で動かしてみせる――簡雍とは、そういう弁舌一芸の老臣であった。"}, {"id": 275, "name": "袁譚", "faction": 3, "role": "君主", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 0, 0, 1, 2, 2, 1], "p": [0, 1, 0, 3, 3, 1], "scores": {"W": 0.55, "B": 1.6, "S": 1.85, "A": 1.85, "G": 1.16, "K": 1.45}, "stat": {"dmg": 0.55, "area": 0.82, "cd": 1.18, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 0, "pwr": 0.55}, "title": "君主", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [1, 10, 11, 16, 22, 24, 31, 32, 33, 41], "chapN": 14, "bio": "袁紹の長子、青州守、南皮で討死", "profile": "袁紹の長子、字は顕忠、青州刺史を務めた袁譚。河北四州に号令した名門袁氏の嫡男として生まれながら、その生涯は父の遺産を兄弟で食い潰す内訌に費やされ、最後は敗者の典型として南皮に斃れた。\n\n父袁紹が官渡の敗戦の傷を引きずって世を去ると、河北は後継争いに揺れる。袁譚は「我は長子なるに、反って父の業を承くる能わず…心実に甘んぜず」と、弟袁尚に後嗣の座を奪われたことへの不満を抱え、ついに骨肉相食む内戦に踏み込んだ。だが弟に勝てぬと見るや、彼は仇敵であるはずの曹操に降る道を選ぶ。曹操は娘を袁譚に許婚して縁を結び援軍を出すが、参謀の郭図にすら「恐らくは真意にあらず」と見抜かれたとおり、袁譚は二心を抱えたまま、結局は曹操に利用されるだけに終わった。「反覆無常」――これが曹操の下した評であった。\n\n戦そのものは、敗走の連続である。曹操との対陣で前に出るのは部将の彭安であり、その彭安も徐晃に一合で斬られる。袁譚自身が名のある敵を討つ場面は、終始一つもない。謀略の見せ場とされる「刀斧手を伏せてこれを殺す」一計も、自らの智慧ではなく郭図の献策であった。諫言した忠臣の別駕王修を逐い、辛評は曹操に去られて憤死する。後に曹操は「惜しむべし、袁氏は人を用うる能わず」と、この一族が人材を活かしきれぬさまを嘆いている。\n\nそして最期。南皮を曹操の大軍に囲まれた窮地で、袁譚は郭図の献策により城中の百姓を夜陰に駆り立て、これを盾として前へ押し出すという非道な策に出る。だが軍も民もろともに大敗し、袁譚自身は陣中で曹洪に斬り殺された。血統と地位だけは持ちながら、大義名分も器量も伴わず、私情の内戦で名門河北を自滅へ導いた――それが袁紹の長子の結末であった。"}, {"id": 276, "name": "高沛", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 3, 1, 1, 2, 1, 2], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 1.4, "B": 1.7, "S": 1.35, "A": 1.4, "G": 1.12, "K": 1.35}, "stat": {"dmg": 0.62, "area": 0.89, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.3}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [61, 62], "chapN": 2, "bio": "涪水関を守る劉璋の名将。劉備に斬られる", "profile": "劉璋配下の白水都督、高沛。楊懐と並んで蜀の咽喉たる涪水関を守る重将であり、軍師龐統からも「楊懐・高沛は蜀中の名将、各々強兵を仗みて関隘を拒守す」と評された、看板だけは堂々たる蜀の名将である。\n\nその名将ぶりが試されたのが第六十二回。葭萌関へ引き返す劉備を前に、楊懐とともに高沛は危険を察知し、「玄徳まさに死すべし。我ら各々利刃を身に蔵し、行を送る処にてこれを刺さん、以て吾が主の患を絶たん」と、送別の宴に乗じた劉備暗殺を謀る。二人はそれぞれ懐に短刀を忍ばせ、二百の兵を従え、羊を牽き酒を担いで見送りを装い、劉備の軍前へと進み出た。\n\nだがこの企ては、龐統に完全に読まれていた。劉備陣営はわざと無防備を装って二人を油断させる。「並びに準備無きを見て、心中に暗喜し、以て計中ると為す」――高沛が罠に嵌ったと思い込んだその瞬間こそ、彼自身が罠の中にいた瞬間であった。いざ事を起こさんと争おうとした刹那、劉封と関平がそれぞれ一人ずつを難なく取り押さえる。短刀は鞘を払う間もなく、高沛は楊懐とともに斬られた。\n\n主将を失った涪水関の蜀兵は、もはや一戦も交えなかった。城上の兵は味方の軍と聞くやただちに門を開き、刃に血ぬらずして降った――関はあっけなく瓦解したのである。「蜀中の名将」という称号と、暗殺を企てて即座に捕えられ斬られたという実態。その落差にこそ、看板を背負わされた地方守将の悲哀がにじむ。"}, {"id": 277, "name": "蔡邕", "faction": 3, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 1], "p": [1, 3, 0, 0, 2, 2], "scores": {"W": 0.0, "B": 0.4, "S": 0.7, "A": 0.55, "G": 1.32, "K": 1.85}, "stat": {"dmg": 0.55, "area": 0.84, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.55}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [1, 4, 9, 29, 40, 71], "chapN": 6, "bio": "中郎、王粲の才を見抜いた逸話（言及）", "profile": "後漢末の文人、蔡邕。当代随一の大儒にして「曠世の逸才」「孝行素より著る」と讃えられた学者であり、書・史・人物鑑識の三道に通じた、乱世の中の文の体現者である。武勇とも権謀とも無縁な、純粋な学者として演義に描かれる。\n\n彼の学者としての姿は、いくつもの逸話に結晶している。曹娥碑に刻まれた八字の隠語を解いた書の素養、漢の正史を続成せんと願い続けた史家の志、そして何より人を見抜く眼。第四十回、まだ無名の少年であった王粲が訪ねてきたとき、蔡邕は履を倒さかしまに履いてまで迎え出る「倒履迎之」の礼をもって遇し、「此の子、異才あり、吾は及ばざるなり」と感嘆した。後の名士顧雍もまた「中郎蔡邕の徒」、その門下から世に出ている。後進の才を見抜き、世に押し出す士林の目利き――それが文人蔡邕の真骨頂であった。\n\n政治の舞台での彼は、しかし不器用であった。第一回、天変地異の理由を問われた蔡邕は、災異の因は「婦寺(宦官)の政に干かる」にありと、宦官の専横を真っ向から弾劾する上疏を奉る。その言葉はあまりに切直であったがゆえに、彼はたちまち左遷の憂き目に遭う。正論を直言して退けられる――これが彼の政治家としての数少ない記録であった。\n\nそして悲劇の最期。董卓が誅された後、蔡邕は董卓の屍に向かって思わず哭いてしまう。これを王允に咎められ、彼は「邕、不才なりと雖も、亦た大義を知る。豈に肯えて国に背きて卓に向かわんや。只だ一時知遇の感に因り、覚えず之が為に一哭す」と弁明し、なお「黥首刖足を受くるとも、漢史を続成して以て其の辜を贖わん」と、刑を受けてでも史書を完成させたいと請うた。だがその願いは容れられず、衆官が才を惜しんで救おうとし、士大夫が涙を流す中、彼は獄に縊られて死んだ。一人の知遇への情に殉じ、続成を夢みた漢史を未完のまま遺して――学者として強く、政治家として脆かった大儒の、それが幕引きであった。"}, {"id": 278, "name": "劉賢", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 2, 1, 2], "p": [1, 1, 1, 3, 2, 3], "scores": {"W": 1.0, "B": 1.7, "S": 1.35, "A": 1.4, "G": 1.67, "K": 1.8}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [52], "chapN": 1, "bio": "劉度の子。趙雲・張飛に敗れ降伏", "profile": "零陵太守劉度の子、劉賢。荊州南部の一郡を預かる地方豪族の御曹司であり、剣を帯びた将として登場するが、その本質は戦よりもむしろ降伏の橋渡しにある人物である。\n\n第五十二回、諸葛亮が荊南四郡を攻略する戦いで、劉度は子の劉賢と配下の猛将邢道栄に兵一万余を授け、城を離れて三十里、山に依り水を靠みに陣を布かせた。劉賢は父に楽観を語る。「父上、御安心あれ。彼に張飛・趙雲の勇ありとも、我が州上の邢道栄は力萬人に敵す、以て抵対すべし」と。だが頼みの綱はあくまで道栄であり、「力萬人に敵す」の評も劉賢自身のものではない。彼に与えられた武名は、何一つなかった。\n\n戦は将計就計の応酬となる。劉賢は道栄の立てた伏兵の火計に「計に依り」これを実行するが、二更、草把を抱えた一彪の軍が現れて火を放ったその先には、孔明の二重の計が待ち構えていた。趙雲・張飛に大敗を喫し、邢道栄は討死。劉賢自身も馬を撥して逃げるところを張飛に追われ、「活捉して馬を過ぎ、綁縛して孔明に見ゆ」――生け捕りにされ、縛り上げられて孔明の前へ引き出された。\n\nここから劉賢の真価が現れる。孔明は彼の縛を解き、衣を着せ、酒を賜って驚きを鎮めると、城へ送り返して父に投降を勧めさせた。降らねば城を破り満門ことごとく誅すという脅しを背負っての使者役である。零陵へ戻った劉賢は父劉度に孔明の徳を備さに述べ、降伏を勧めた。劉度はこれに従い、城上に降旗を立て、城門を大きく開いた。零陵一郡の民は、皆ことごとく喜んだという。\n\n抗戦に殉じる潔さはない。だが捕えられた窮地から一転、家と領と民の全てを保全する道を選んでみせた――武の手柄ではなく、降伏を仲立ちして一郡を無血で守った点にこそ、この地方豪族の子の数少ない値打ちがある。"}, {"id": 279, "name": "郝萌", "faction": 3, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 1, 1, 2, 1, 2], "p": [1, 1, 1, 2, 1, 1], "scores": {"W": 1.45, "B": 1.8, "S": 1.35, "A": 1.4, "G": 1.15, "K": 1.2}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.13, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [11, 12, 18, 19], "chapN": 4, "bio": "呂布配下の健将、張飛に生擒され斬られる", "profile": "呂布配下の「八員健将」の一人に数えられた郝萌。第十一回で「両将また各々六員の健将を引く――郝萌、曹性、成廉、魏続、宋憲、侯成」と、その名は驍勇の列に連ねられる。だが演義の郝萌に、固有の武勇のディテールも独自の称号もなく、その実態は呂布軍の頭数を埋める一員に近い。\n\n彼の働きは、もっぱら集団戦の一翼を担うことにあった。濮陽の戦いでは陳宮の火計に従い、伏兵として曹操の退路を断つ役を務める。曹操が北門へ走れば「道傍より郝萌・曹性転じ出で、また一陣を殺す」――味方とともに敵を追い討つ場面はあるが、計を立てたのは陳宮であり、郝萌はあくまで配された駒であった。後半では使者の護送・引率を任され、第十九回には張遼と並んで兵一千を率い、隘口の外まで使者を送り出している。\n\nその郝萌に訪れた唯一の一騎打ちが、彼の最期となった。「郝萌、馬を交うること只だ一合、張飛に生擒せられ過ぐ、五百人馬尽く殺散せらる」――張飛とわずか一合斬り結んだだけで生け捕りにされ、率いていた五百騎は散り散りに討ち散らされた。捕えられた郝萌は、そのまま軍門に引き出されて斬られる。\n\n濮陽では伏兵、後には護送役、そして張飛の前にあえなく一合で捕えられる。名のある敵を討つことも、独立した軍を率いて名を上げることもなかった。健将の列にその名を留めながら、呂布という巨星の周りを彩る端役として、郝萌は静かに演義から退場していった。"}, {"id": 280, "name": "関索", "faction": 0, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 1, 1, 2, 1, 2], "p": [1, 1, 1, 1, 2, 1], "scores": {"W": 1.45, "B": 1.8, "S": 1.35, "A": 1.4, "G": 1.13, "K": 1.5}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.13, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [87, 88, 89], "chapN": 3, "bio": "関羽の三男。南征で前部先鋒となる", "profile": "関索は、関羽の三男として演義の終盤に姿を現す蜀漢の若き将である。荊州が陥落し父・関羽が斃れたのち、「父帝に見え讎を報いん」と志して西川へ逕り、第八十七回、軍中に孔明を訪ねて世に出る。孔明は彼を南征軍の前部先鋒に任じ、ここから関索の戦場が始まる。\n\nその活躍は、南蛮平定という孔明の大きな計略の一翼を担うかたちで描かれる。第八十七回では孟獲勢との戦いで「略戰又走（少し戦ってはまた退く）」と敵を誘い込む囮役を務め、退いて二十余里、そこから王平とともに兵を返して挟撃に転じる。第八十八回では王平・馬忠とともに孔明から密かに計策を授けられ、それぞれ命のままに動いて酋長を擒にする一手を担った。父譲りの武勇譚を期待される血筋でありながら、本文の関索が果たすのは、知の将・孔明の盤上で正確に動く駒としての役回りである。\n\n人となりを語る逸話は多くないが、荊州を失ったのちわざわざ西川の劉備のもとを目指したという一点に、亡き父の遺志と旧主への忠を継ぐ姿が刻まれている。一騎打ちの無双も、武名の称号も本文は与えない。それでも「関公の第三子」という肩書きそのものが、彼を戦場へ押し上げる重みを持っていた。\n\n第八十九回では一軍の指揮ではなく「護車」、すなわち輜重の車を護る任を命じられる。華やかな見せ場ではないが、孟獲を七度擒にして放つあの大遠征を、後方から支えた一人として関索の名は残る。父・関羽の威光を背負いながら、自らは静かに南征を勤め上げた将――それが演義の描く関索の像である。"}, {"id": 281, "name": "師纂", "faction": 1, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [2, 1, 1, 1, 2, 1, 2], "p": [1, 1, 2, 1, 1, 1], "scores": {"W": 1.45, "B": 1.8, "S": 1.35, "A": 1.4, "G": 1.18, "K": 1.2}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.13, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [111, 113, 115, 117, 118], "chapN": 5, "bio": "鄧艾配下の校尉・将。蜀攻略に従軍、益州刺史となる", "profile": "師纂は、魏の名将・鄧艾に従う校尉あがりの将で、演義では終始その副将として鄧艾の子・鄧忠と組んで動く。蜀漢滅亡へ向かう最終盤、姜維の北伐を追い、祁山の寨を守り、ついには蜀の都へ攻め入る大作戦に名を連ねる。\n\n戦場での師纂は、勝者の側にいながら手柄の薄い苦労人として描かれる。第百十三回では鄧忠とともに各一万の兵を預けられ、左右の衝撃部隊として運用される。だが第百十五回、祁山の寨を守る彼を鄧艾自身が「兵少なく智寡く、必ず敗れん」と案じたとおり、自力では支えきれず救援を仰ぐ。第百十七回の綿竹では、諸葛瞻の子・諸葛尚がただ一騎で槍を振るって突き入り、師纂と鄧忠は二人がかりでありながら戦い退けられ、ともに傷を負って逃げ落ちる。さらに孔明の遺した木像に出くわした場面では、汗を全身に流して「孔明なお在りしか、我ら休せり」と震え上がる始末で、敵を恐れさせるどころか自らが怯える側に回っている。\n\nそれでも武功とは別に、彼にはひとつの到達点が与えられた。第百十八回、入蜀を果たした鄧艾は彼を益州刺史に封じる。一介の従軍校尉が、平定された蜀の地を治める要職に就いたのである。\n\nただし演義は、その後の師纂の最期を描かない。正史の伝える綿竹での戦死とは異なり、刺史に任じられたところで彼の物語は静かに途切れる。華々しい武名はなくとも、姜維の鋭鋒を追い、ついに蜀を陥れた征蜀軍の一翼として、その名は終幕の戦史に刻まれている。"}, {"id": 282, "name": "韓浩", "faction": 1, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 1, 1, 2, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.45, "B": 1.8, "S": 1.35, "A": 1.4, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.13, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [39, 70, 71], "chapN": 3, "bio": "夏侯惇の副将、趙雲の誘敵を見抜くも従われず", "profile": "韓浩は、演義に二つの異なる顔で現れる魏の武将である。一つは明察の士として、もう一つは仇討ちに逸って瞬殺される噛ませ役として。\n\n第三十九回、夏侯惇の副将として登場した韓浩は、博望坡で趙雲が誘いの兵を出すのを見て「趙雲が誘うておる、伏兵あるを恐る」と正しく見抜き、進撃を諫める。だが血気にはやる夏侯惇はこれを容れず、まんまと孔明の火計に焼かれて大敗を喫した。ここでの韓浩は、主将が聞き入れさえすれば災いを避けえた、戦術眼を備えた将だったのである。\n\nところが第七十回の韓浩は、まるで別人のように描かれる。長沙で討たれた韓玄の弟という設定を与えられ、兄の仇を討たんと逸って黄忠に挑む。陣前で「義なき老賊め」と罵り、馬を駆って槍をしごき突きかかるが、黄忠が刀を揮って真っ向から斬りに出ると、わずか一合――ただ一合で馬上から斬り落とされた。その後、彼の率いた軍は警戒を怠ったところを黄忠の夜襲に突かれ、「人は甲に及ばず、馬は鞍に及ばず」と総崩れになり、兵馬が互いを踏みつけ合って死者数知れずという惨状を招いている。\n\n正史が伝える、曹操に屯田を建言し軍を督した重臣としての韓浩の姿は、演義本文には一片も残らない。ここに描かれるのは、一度は鋭い読みを見せながら、私的な仇討ちの情に駆られてあっけなく散った一将である。第七十一回でその戦死が報じられ、韓浩の名は戦場の塵となって消えてゆく。"}, {"id": 283, "name": "逢紀", "faction": 3, "role": "軍師参謀", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 2, 2, 1], "p": [1, 1, 0, 2, 0, 2], "scores": {"W": 0.0, "B": 1.45, "S": 1.8, "A": 1.75, "G": 0.96, "K": 0.85}, "stat": {"dmg": 0.66, "area": 0.94, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.7}, "title": "軍師", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [7, 22, 30, 31, 32], "chapN": 5, "bio": "袁紹の謀臣、袁尚派、袁譚に斬らる", "profile": "逢紀は、河北の雄・袁紹に仕えた謀臣である。袁紹陣営の「智謀の士」の一人に数えられながら、演義が描くその実像は、輝かしい一計と、それに倍する内部抗争・讒言の影に彩られている。\n\n彼の名を不朽にしたのは、第七回の冀州奪取の献策である。糧に窮した袁紹に向かって「大丈夫天下を縦横するに、何ぞ人の糧を送るを待ちて食らわんや。冀州は銭糧広盛の地、将軍何ぞ之を取らざる」と説き、さらに公孫瓚に密書を送って進兵させ、挟撃を約させる奇略を授けた。臆病な韓馥は果たして袁紹に州事を委ね、こうして冀州は一兵も損なわず「唾手に得べし」と転がり込む。河北制覇の起点を据えた、見事な一手であった。\n\nだがその後の逢紀は、戦場ではなく謀略と讒言の場に立ち続ける。第二十二回、曹操の謀臣・荀彧は袁紹陣営を評して逢紀を「果にして用なし（決断は早いが役には立たぬ）」と切り捨て、審配・許攸・田豐と並べて「勢い相容れず、必ず内変を生ぜん」と予言した。その言葉どおり、逢紀は諫言の士・田豐を二度にわたって讒言で陥れ、ついに死へ追いやる。官渡の前、田豐が「静かに守りて天の時を待て」と説いた正論を、逢紀は「不祥の語」と難じて潰した。\n\n最期は、自らが招いた内紛の渦に呑まれる。第三十二回、袁紹危篤の枕頭に審配とともに召し出され、後事を議して末子・袁尚を擁立する。だがこれが長子・袁譚との骨肉の争いに火をつけ、袁家は内から崩れてゆく。やがて逢紀はくじ引きの運に任せて袁譚の軍へ送られ、怒った袁譚に「立ちどころに斬る」と一刀のもとに処断された。冀州を獲らせた知謀の士は、兄弟相争うその裂け目に、自ら蒔いた種で果てたのである。"}, {"id": 284, "name": "楊懐", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 2, 0, 1, 2, 1, 2], "p": [0, 0, 0, 0, 2, 2], "scores": {"W": 0.95, "B": 1.7, "S": 1.35, "A": 1.4, "G": 0.5, "K": 1.3}, "stat": {"dmg": 0.58, "area": 0.84, "cd": 1.16, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 0, "pwr": 0.85}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [61, 62], "chapN": 2, "bio": "涪水関を守る劉璋の名将。劉備に斬られる", "profile": "楊懐は、益州牧・劉璋の臣で、白水都督として要害の涪水関を守った将である。演義は龐統の口を借りて「楊懐・高沛は蜀中の名将、各おの強兵を仗みて関隘を拒守す」と評させ、劉備入蜀の前に立ちはだかる手強い守将として印象づける。\n\nだが楊懐の真価が最も光るのは、刀槍の場ではなく政の場であった。劉備が川に入ったのち、彼は劉璋に対し「劉備、入川より、広く恩徳を布き、以て民心を収む。其の意甚だ是れ善からず。今軍馬銭糧を求むるも、切に与うべからず。如し相助けなば、是れ薪を把りて火を助くるなり」と説く。劉備の長期的な脅威を「薪に火を添えるようなもの」と看破したこの諫言は、一介の関守の枠を超えた政治眼を示している。しかしこの正論は劉璋に容れられなかった。\n\nここから楊懐は誤った一手を踏む。第六十二回、高沛が「玄徳は死ぬべし。我ら各おの利刃を身に蔵し、送行の処にて之を刺さん」と暗殺を発議すると、楊懐は「此の計大いに妙なり」と乗った。だが龐統はあらかじめ二人の懐に刃あるを見抜いており、劉備は重鎧を着け宝剣を佩いて備えていた。送別の場に二百の手勢だけを連れて出向いた楊懐は、争おうとした瞬間に劉封・関平に取り押さえられ、一合も戦わぬまま帳前で斬られる。涪水関は無血で劉備の手に落ちた。\n\n称号だけは「蜀中の名将」、しかしその刃をついに抜けぬまま誅された関守――それが本文の描く楊懐である。劉備の野心をいち早く見抜いた眼を持ちながら、それを刺殺という拙策に賭けて散った。彼の警告どおり劉璋の基業はやがて滅び、楊懐の忠言の正しさだけが後に残った。"}, {"id": 285, "name": "楊修", "faction": 1, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 1], "p": [1, 2, 2, 3, 1, 2], "scores": {"W": 0.0, "B": 0.85, "S": 0.95, "A": 0.9, "G": 1.8, "K": 1.35}, "stat": {"dmg": 0.58, "area": 0.87, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [1, 23, 60, 72], "chapN": 4, "bio": "楊彪の子、丞相府主簿。張松と弁論し記憶力に驚嘆", "profile": "楊修、字は徳祖。太尉・楊彪の子という名門に生まれ、曹操の丞相府で掌庫主簿として軍政・銭糧の重きを委ねられた文人である。演義における彼の本領は剣戟ではなく、舌弁と博聞強記、そして人の心の奥を読み透かす機知にあった。\n\nその才知が遺憾なく発揮されるのが、第六十回、益州の使者・張松との応対である。曹操の著した兵法書『孟徳新書』を「丞相が古を酌み今に準じ、孫子十三篇に倣いて作れるもの」と誇り、また「丞相すら禰衡を容れり、何ぞ張松を納れざらん」と曹操に引見を進言する。もっとも、過目不忘の張松にこの兵書を一読で諳んじ返され、楊修の弁はかえって押し返されてしまう。それでも彼の才の冴えは折々に光り、曹操が門に「活」と書けば「闊」と読み解き、一盒の酥に「一合酥」と記せば一人一口と取り分けてみせた。\n\nしかしその才覚は、しだいに身を滅ぼす刃となる。第七十二回、漢中で進退に迷う曹操が夜の合言葉に「鶏肋」と発するや、楊修は「鶏肋は、之を食らうも味なく、之を棄つるも惜し。今進むも勝つ能わず、退かば人の笑いを恐る。此に在りて益なし、早く帰るに如かず」と退兵の意を読み解き、勝手に行装を収めさせた。これを聞いた曹操は「汝なんぞ敢えて謡を造り、我が軍心を乱すか」と激怒し、刀斧手に命じて斬らせ、その首を轅門の外に号令す。時に三十四歳であった。\n\n楊修の影には、もう一つの暗躍があった。曹操の三男・曹植の才を愛し、後継争いにおいて答教十余条を授け、門吏斬殺の入れ知恵まで仕込んで曹植を「能あり」と見せかけた。だが後にこれが露見し、曹操は「匹夫、安んぞ敢えて我を欺くや」と憤って、すでに楊修を殺す心を抱いていたという。後人は彼を「聡明なる楊徳祖、世代に簪纓あり……閑談は四座を驚かし、捷対は群英に冠たり」と詩に讃えた。才に恵まれながら、その才ゆえに主の忌諱に触れて散った――楊修は、知の輝きと危うさを一身に背負った文人として語り継がれる。"}, {"id": 286, "name": "帶來洞主", "faction": 3, "role": "武将", "rarity": 1, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [0, 0, 0, 0, 2, 2, 1], "p": [0, 1, 0, 3, 0, 2], "scores": {"W": 0.0, "B": 1.45, "S": 1.8, "A": 1.75, "G": 0.89, "K": 0.7}, "stat": {"dmg": 0.62, "area": 0.9, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 6.4, "pwr": 1.25}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [90], "chapN": 1, "bio": "孟獲の妻弟・八番部長。木鹿大王や烏戈国を孟獲に勧める", "profile": "帶來洞主は、南蛮王・孟獲の妻の弟にして八番部長の地位を持つ蛮地の長である。「洞主」の名は勇猛な蛮族の戦士を思わせるが、演義第九十回が描くその実態は、武人ではなく外征軍に対抗するための援軍を探し回る献策の口であった。\n\n南征の孔明に再三破れた孟獲の陣中で、彼が買って出るのは外部勢力の招聘である。「此より東南七百里に、烏戈国という一国あり。国主・兀突骨、人みな藤甲を穿ち、刀箭も入る能わず。これを号して藤甲軍と為す。今大王往きて之を求むべし……諸葛亮を擒にすること利刀の竹を破るがごとし」と説き、さらに八納洞の木鹿大王をも推挙する。木鹿大王のもとへは「某みずから親しく往きて求めん」と使者役を進んで引き受け、自ら同盟の橋渡しに動いた。本文において帶來洞主が担うのは、まさにこの援軍交渉という役回りである。\n\nだが彼の差し向けた援軍は、ことごとく孔明に各個撃破されてゆく。やがて孟獲は最後の手として、帶來洞主に蜀兵数百を縛らせ、偽りの降伏で孔明を洞中に誘い込んで殺す計を立てる。第九十回、帶來洞主が刀斧手に孟獲らを縛らせて殿下に拝した瞬間、孔明は「与に吾れに擒し下せ」と一喝し、続けて高らかに笑って「汝が些小の詭計を量るに、如何ぞ吾を瞞き過ぐることを得んや」と、その詐降をたちどころに見破った。\n\n最期に帶來洞主が果たしたのは、矛を収めることであった。降伏を肯んじない孟獲を諫めてついに帰順を勧め、蛮族の存続へと導いた一人として、その名は南征の幕引きに残る。武勲ではなく、援軍を求めて奔走し、最後は和を選んだ献策者――それが演義の帶來洞主である。"}, {"id": 287, "name": "劉氏", "faction": 3, "role": "婦人", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 1, 1, 1], "p": [1, 2, 1, 1, 2, 3], "scores": {"W": 0.1, "B": 0.9, "S": 1.0, "A": 1.0, "G": 1.57, "K": 1.8}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.23, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.75, "pwr": 1.0}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [9, 20, 31, 32, 33, 54, 56, 68, 78, 80], "chapN": 12, "bio": "袁紹の後妻、袁尚の母", "profile": "劉氏は、河北の雄・袁紹の後妻にして、末子・袁尚の生母である。武の記録は一切持たぬ婦人でありながら、演義はその継嗣をめぐる執念と苛烈さを通じて、袁家瓦解の引き金を引いた人物として彼女を刻む。\n\n彼女の物語は、後継争いとともに始まる。第三十一回、官渡の敗戦ののち、劉氏は袁紹に対し末子・袁尚を後嗣に立てるよう勧め続けた。そして第三十二回、袁紹が危篤に陥るや、彼女は審配と逢紀を急ぎ請じて病床のもとへ連れ、後事を議す。「尚、後嗣を継ぐべきや否や」と問えば、すでに口もきけぬ袁紹はただ頷くのみ。劉氏はその一頷きを取って審配に遺囑を書かせ、袁尚の擁立を固めた。だが長幼の序を覆して幼子を立てたこの工作こそが、長子・袁譚との骨肉の争いを呼び、袁家を内から崩してゆく。\n\n劉氏のもう一つの顔は、その嫉妬の苛烈さにある。袁紹が息を引き取った直後、彼女は紹の寵愛した妾五人をことごとく殺害し、さらに髪を剃り顔を刺し、屍をも傷つけたという。地の文はこれを「其の妒悪此くのごとし」と冷ややかに断罪する。河北の名門の奥に潜んだ、凄絶なまでの執着であった。\n\n冀州が陥落した第三十三回、劉氏は身を翻して生き延びる。子の嫁・甄氏を曹丕に献じて一家の保全を請い、曹操からはかえって金帛・糧米を賜った。武も知略も持たぬ一婦人が、後継の決定に能動的に手を突っ込み、結果として一大勢力を内側から滅ぼしたという点で、劉氏は演義に異彩を放つ。家を継がせようとした母の情念が、皮肉にもその家を亡ぼした――そこに彼女の物語の苦さがある。"}, {"id": 288, "name": "劉禅", "faction": 0, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 1], "p": [1, 2, 1, 2, 3, 1], "scores": {"W": 0.0, "B": 0.25, "S": 0.1, "A": 0.05, "G": 1.61, "K": 1.8}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.1}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [41, 61, 85, 86, 91, 97, 101, 105, 115, 117], "chapN": 34, "bio": "劉備の子、新野で誕生", "profile": "劉禅、幼名は阿斗。先主・劉備の子にして、蜀漢の第二代にして最後の皇帝である。演義における劉禅は、生涯を通じて「護られる側」「裁可を委ねる側」として描かれ、その受動の極致が、後世「庸才」と断ぜられる暗君の像を形づくった。\n\n彼の登場そのものが、その運命を象徴している。第四十一回、長坂の修羅場で、趙雲は懐に赤子の阿斗を抱いて重囲を突き破り、大旗を二面斬り倒し、槊を三条奪い取る。だが、武勲を立てるのはあくまで趙雲であり、阿斗は懐に抱かれて運ばれる嬰児に過ぎない。第六十一回でも孫夫人の懐に抱かれて呉へ連れ去られそうになるなど、彼は幾度も他者の腕に救われて生き延びてゆく。\n\n即位後の劉禅は、国政の一切を諸葛亮に委ねた。第八十五回、劉備の崩御を承けて帝位を継ぐと、「およそ一応の朝廷・選法・銭糧・詞訟等の事、皆な諸葛丞相の裁処に聴く」と、政の主体をことごとく丞相に預ける。孔明在世のうちは、その支えによって蜀は保たれた。だが孔明の死後、晩年の劉禅は宦官・黄皓の言を信じて酒色に溺れ、朝政を顧みなくなる。無功の閻宇を黄皓へのへつらいゆえに重用し、忠臣・姜維の諫めを退け、ついには孔明が陰平の険要に置いた二千の守備兵さえ廃して、鄧艾の奇襲路を自ら開いてしまう。\n\nそして最後の選択が、漢を亡ぼす。第百十八回、鄧艾が迫るや、北地王・劉諶が城を背に一戦して死すべしと血を吐いて諫めるのを、劉禅は「汝小児、豈に天時を識らんや」と退け、譙周の言に従って面縛輿櫬、すなわち自らを縛り棺を背負う降伏の礼をもって、群臣六十余人とともに城を出て魏に降った。劉備が打ち立てた漢室の正統は、ここに絶える。\n\n洛陽に移されたのちの一幕が、彼の人物を決定づけた。司馬昭の宴で蜀の楽が奏されるなか、旧臣が涙する傍らで劉禅は平然と「此間楽しく、蜀を思わず」と言い放つ。詩は彼を「後主は是れ庸才」と評し、「後主、生を偸みて自裁を失う」とその最期を惜しんだ。だが見方を変えれば、亡国の主でありながら天寿を全うしたその姿には、乱世を生き抜く一種のしたたかさを読む者もいる。賢臣の支えがある間だけ国を保った受動の帝――劉禅は、その光と影をともに体現する人物として、三国の幕引きに立つ。"}, {"id": 289, "name": "馬延", "faction": 1, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 0, 0, 3, 0, 1], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 0.65, "B": 1.7, "S": 0.85, "A": 1.1, "G": 0.0, "K": 0.2}, "stat": {"dmg": 0.55, "area": 0.81, "cd": 1.16, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 0.6}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [32, 33, 41, 50], "chapN": 4, "bio": "袁紹旧将の降将、長板坡で趙雲を阻み烏林で甘寧に斬られる", "profile": "馬延は、もとは袁紹・袁尚に仕え、のちに曹操へ降った末端の武将である。猛将の面影は演義にまるでなく、その実像は「すぐに寝返り、最後はあっけなく討たれる降将」というものであった。\n\n数少ない見せ場は、第三十二回の献策である。袁尚に対し「大路より去かば、曹操必ず伏兵あらん。小路を取り、西山より滏水口に出でて曹営を劫すべし、必ず囲みを解かん」と、奇襲によって包囲を破る一計を進言した。袁尚はこれを採るが、しかし曹操はすでに細作を通じてこの動きを読んでおり、「一戦にして擒うべし」と看破され、計は不発に終わる。\n\nその後の馬延は、武将としてはひたすら討たれ役に回る。第四十一回、長坂で趙雲を阻もうと四将がかりで挑むも、衆軍ごと殺し退けられて突破される。第五十回、赤壁に敗れた曹操を護って烏林を落ちのびる夜、馬延は満天に火の手が上がるのを見て「未だ敢えて転動せず」と立ちすくみ、曹操の指図を待ってようやく道を開く有り様であった。そしてその同じ夜、甘寧と渡り合おうとした刹那――まさに鋒を交えんとした瞬間に、甘寧の一刀で馬上から斬り落とされる。\n\n一度は奇襲を献じる知恵を見せながら、武勲を立てることなく、情勢に流されて主を替え、最後は刃を交える間もなく散った。馬延は、乱世の大波に翻弄された無数の末端の将の、その一典型として演義に名を留めている。"}, {"id": 290, "name": "蔡夫人", "faction": 3, "role": "婦人", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 1, 1, 2], "p": [1, 3, 0, 2, 1, 2], "scores": {"W": 0.1, "B": 1.15, "S": 1.1, "A": 1.05, "G": 1.49, "K": 1.75}, "stat": {"dmg": 0.6, "area": 0.87, "cd": 1.21, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.75, "pwr": 1.1}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [34, 35, 40, 41, 46], "chapN": 5, "bio": "劉表の後妻・劉琮の母、息子と共に于禁に殺される", "profile": "荊州の主・劉表の後妻にして、次男劉琮の母。弟に水軍を握る蔡瑁を持ち、外戚蔡氏の軍権を後ろ盾に、荊州の内宅で隠然たる権力をふるった女性である。戦場に立つことは一度もない。彼女の武器は屏風の陰での立ち聞きと、夜の枕辺でのささやき、そして遺言の偽造であった。\n\nその存在感が最初に際立つのは第三十四回。劉表が劉備を招いて後継の相談をした際、蔡夫人は屏風の裏で一部始終を聞いていた。劉備が「もし諸子に賢才あれば」と語るのを聞きとがめ、夜になって夫に「劉備こそ後患、今のうちに除かねば」とささやく。この一言が、やがて劉備を荊州から追い落とす力学を生む。第四十回、劉表が病没するや、彼女は蔡瑁・張允と謀って遺言を偽造し、長子劉琦を退けて我が子劉琮を荊州の主に立てた。幕僚の李珪は「汝ら内外朋み謀り、偽りて遺命と称し、長を廃して幼を立つ。荊襄九郡を蔡氏の手に送るか」と面罵し、斬られる。屏風の陰から進み出て「仲宣・公悌・異度の三人が同じ見立てなら、なぜ私に問うのか」と冷ややかに言い放つ場面は、この回の題「蔡夫人荊州を獻ずるを議す」そのものだ。彼女は曹操への降伏を主導し、荊州を戦わずして明け渡す道を選ぶ。\n\n通説では「劉備暗殺と荊州献上を裏で操る悪役」として語られる。実際の本文を追っても、その評価は揺らがない。ただし彼女を動かしていたのは大局の構想ではなく、我が子を立て一族を守るという私心であった。怒れば内門を閉ざして劉琦を締め出し、宗族に荊州の兵を分け領させ、治中鄧義・別駕劉先を要職に据える。縁故で固めた権力は、しかし人望を一片も伴わなかった。\n\nその構想はことごとく破滅を招く。曹操に降った荊州は劉琮もろとも飲み込まれ、于禁の手の者によって「軍士、劉琮及び蔡夫人を殺死す」と、母子はあっけなく斬り捨てられた。子を抱いて泣くしかなかった最期である。演義は詩に「牝晨（雌鶏が朝を告げる）家を致して累わす」と彼女を断じる。家を傾けた女として、三国の物語に名を刻んだ。"}, {"id": 291, "name": "龔都", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [2, 1, 1, 1, 1, 1, 3], "p": [1, 1, 2, 2, 2, 1], "scores": {"W": 1.45, "B": 1.6, "S": 1.2, "A": 1.1, "G": 1.46, "K": 1.7}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.13, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [26, 27, 28, 31], "chapN": 4, "bio": "汝南の劉備与党、夏侯淵に斬らる", "profile": "汝南を根城とした黄巾の残党あがりの頭目。劉辟と並んで数万の衆を擁し、後に流浪の劉備に帰順して、その一時の足場を支えた地方豪族である。\n\n第二十六回、官渡を前にした曹操の背後を脅かすため、袁紹は劉備を汝南へ送る。劉辟・龔都はこれに呼応し、荀彧が「汝南に黄巾の劉辟・龔都ありて、甚だ猖獗なり」と警戒を報じるほどの勢いを見せた。だが龔都自身の戦の腕は心もとない。関羽と相対した場面では「関公、更に打話せず、馬を拍ち刀を舞わせて前む。龔都便ち走る」と、一合も交えずに逃げ出す。もっともこれは偽りの敗走、関羽を誘い込む芝居であった。第二十七回には孫乾を河北の袁紹のもとへ遣わし、劉備との結好を取り持つ外交の橋渡し役も務めている。\n\n通説では劉備の客将、義に厚い豪傑として語られがちだが、本文の描写は思いのほか淡い。個人の武勇を称える言葉も、計略を立てた記録もない。彼の値打ちは、縁もゆかりもなかった劉備に数万の衆と汝南の地を差し出した、その一点に尽きる。後に孫乾は「汝南の劉辟・龔都、素より親故なきも、亦た死を以てこれに報ゆ」と評した。義によって主を選び、義のために最後まで働いた男であった。\n\n第三十一回、その最期が訪れる。糧を運ぶ兵站の役を担っていた龔都は、曹軍に包囲される。劉備は急ぎ張飛を救援に向かわせたが、間に合わなかった。「原と張飛、龔都を救いに去くに、龔都已に夏侯淵に殺さる」――名のある敵を一人も斬らぬまま、自らが討たれて退場する。数万を率いた頭目の幕引きとしては地味だが、流浪の英雄を陰で支えた脇役の死であった。"}, {"id": 292, "name": "侯成", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [2, 2, 1, 1, 1, 1, 1], "p": [0, 0, 1, 0, 0, 1], "scores": {"W": 1.65, "B": 1.1, "S": 1.0, "A": 1.0, "G": 0.3, "K": 0.35}, "stat": {"dmg": 0.65, "area": 0.88, "cd": 1.15, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.6}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [11, 12, 18, 19], "chapN": 4, "bio": "呂布配下の将、赤兎馬を盗み呂布を裏切る", "profile": "呂布配下の「八健将」の一人に数えられる将。第十一回、呂布が郝萌・曹性・成廉・魏続・宋憲らとともに引き連れた六将の中に、その名が並ぶ。武勇そのものより、呂布滅亡の引き金を引いた男として記憶される。\n\n武人としての見せ場は乏しい。第十二回の濮陽の戦いでは、曹操が典韋を出して侯成を討たせると、「侯成、敵するに過ぎず、馬を回らして城中に望み走る」――わずか一合で持ちこたえられず、城へ逃げ帰る。高順とともに「倒走して城を出づ」と逃げる姿ばかりが描かれ、敵将を斬る場面は一つもない。\n\n彼が物語を動かすのは、刀ではなく恨みによってだ。第十九回、下邳に籠城する呂布は酒色に溺れ、配下に飲酒禁令を出していた。これに触れた侯成は杖打ち五十の罰を受ける。「我れ馬を追いしによりて責めを受く。而して布の倚恃する所は、赤兎馬なり」――かつて盗まれた名馬を取り戻した功さえ咎められた恨みが、彼を裏切りへと駆り立てた。宋憲・魏続を誘い、「汝二人、果たして能く門を獻じて布を擒えなば、吾れ当に先ず馬を盗みて曹公に見えん」と離反を主導する。\n\nそして実行に移す。「是の夜、侯成、暗かに馬院に至り、かの一匹の赤兎馬を盗み、飛奔して東門に来たる」。呂布の象徴たる赤兎馬を奪って曹操陣に駆け込み、宋憲・魏続が呂布を縛り上げる手はずを整えた。天下無双の呂布を陥れたのは、強敵ではなく、足元の小さな恨みであった。籠城の危機にあって自己保身に走り、主君を売った将――侯成の名は、英雄の最期を彩る皮肉な一筆として残る。"}, {"id": 293, "name": "趙累", "faction": 0, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 2], "p": [1, 1, 3, 2, 1, 3], "scores": {"W": 0.0, "B": 1.1, "S": 1.05, "A": 0.95, "G": 1.75, "K": 1.5}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 1.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [73, 76, 77], "chapN": 3, "bio": "関羽の管糧都督、忠誠廉直、麦城脱出時に乱軍中で戦死", "profile": "関羽の幕下に仕えた糧料官、管糧都督。武の記録は一切なく、終始一貫して補佐に徹した文官である。第七十三回、王甫が関羽に人物を推挙する場面で「趙累、人と為り忠誠廉直、若し此の人を用いなば、万に一の失なからん」と評された、その忠廉こそが彼の人物像のすべてだ。\n\n彼が光るのは、荊州が呂蒙の奇襲に呑まれていく末期の局面である。第七十六回、孫呉が盟約を破って荊州を襲うと、趙累はまず「昔、呂蒙、陸口に在りし時、嘗て書を君侯に致し、両家好を約して共に操賊を誅せんと。今却って曹を助けて我を襲う。是れ盟に背くなり」と、敵の不義を突く一手を進言する。事態が逼迫すると「今、事急なり。一面、人を遣わして成都に救いを求め、一面、旱路より荊州を取るべし」と、援軍要請と陸路奪還の二段構えを示した。滅びゆく軍にあって、なお冷静に活路を探る幕僚であった。\n\n最も鮮烈なのは麦城での進言だ。第七十七回、援軍が来ぬ理由を「上庸の救兵至らざるは、乃ち劉封・孟達、兵を按じて動かざるの故なり」と看破し、「何ぞ此の孤城を棄てて西川に奔り入り、再び兵を整えて来たり、以て恢復を図らざる」と、城を捨てての再起を説く。原因を見抜き、最善の活路を指し示すこの一言は、孤城に追い詰められた者の知恵として鈍く光る。\n\nだが関羽はこの策を容れきれなかった。第七十七回、関羽・関平とともにわずか二百余の残卒を率いて北門を突出した趙累は、戦う術もないまま乱軍に巻き込まれ、「趙累、已に乱軍中に死す」と記される。主と運命を共にした忠臣の、静かな殉死であった。"}, {"id": 294, "name": "呂翔", "faction": 3, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 2, 1, 1, 1, 1, 2], "p": [0, 0, 0, 1, 0, 0], "scores": {"W": 1.65, "B": 1.35, "S": 1.1, "A": 1.05, "G": 0.15, "K": 0.4}, "stat": {"dmg": 0.65, "area": 0.88, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.6}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [32, 33, 35], "chapN": 3, "bio": "袁尚の大将、後に曹操へ降り新野で討死", "profile": "呂曠の弟。袁尚軍の大将として先鋒や殿軍を務め、やがて袁譚に降り、さらに曹操に転じて列侯となった、降将の典型である。常に兄と「二呂」「兄弟二人」と束ねて呼ばれ、独立した武勇も知略も与えられなかった端役だ。\n\n第三十二回、袁尚が「軍中、誰か敢えて前部と為らん」と問うと、呂曠・呂翔の兄弟が進んで先鋒を志願する。だが河北の内紛のなかで二人は袁譚のもとに下馬して降り、袁譚は「我に降るなかれ、曹丞相に降るべし」と曹操へ送り込んだ。功を立てる機会を求めた兄弟は、第三十五回、新野の劉備に矛先を向ける。「吾二人、丞相に降りて自り、未だ寸功あらず。願わくは精兵五千を請い、劉備の頭を取りて以て丞相に獻ぜん」――焦りのにじむ出兵であった。\n\nしかしこの挑戦は、軍師となったばかりの単福（徐庶）の分進策の前に脆くも崩れる。趙雲・関羽・張飛の前に「兵を折ること大半、路を奪いて走り脱る」と潰走し、兄呂曠を失う。本文は「二将、敵を欺いて亡ぶ」と、その無策を冷ややかに断じている。\n\nそして呂翔自身の最期も同じ第三十五回に訪れた。立ちふさがった猛将が矛を挺して大喝する。「張翼徳、此に在り」――張飛である。「直ちに呂翔を取る。翔、措手及ばず、張飛の一矛に刺中せられ、身を翻して馬を落ちて死す」。なすすべもなく一突きで貫かれ、馬から転げ落ちて果てた。主君を渡り歩いた降将の、あっけない幕切れであった。"}, {"id": 295, "name": "楽綝", "faction": 1, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 2, 1, 1, 1, 1, 2], "p": [1, 1, 1, 1, 2, 1], "scores": {"W": 1.65, "B": 1.35, "S": 1.1, "A": 1.05, "G": 1.13, "K": 1.5}, "stat": {"dmg": 0.65, "area": 0.88, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.6}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [100, 103, 106, 111], "chapN": 4, "bio": "楽進の子、副先鋒・八卦陣で捕らわれる", "profile": "魏の名将・楽進の子。父の威光という重い看板を背負って登場するが、演義における実態は終始受け身の端役であった。後に揚州刺史にまで上るその肩書きの重さと、本文に描かれる姿の頼りなさとの落差が、この人物の哀しみである。\n\n初登場の第百回からして振るわない。諸葛亮の八陣図（八門金鎖陣）を破るべく送り込まれた三将の一人として、「戴凌中に在り、張虎前に在り、楽綝後に在り、各々三十騎を引き、生門より打ち入る」と陣中へ突入するが、たちまち「魏軍、一個一個皆な縛らる」と全員が捕らえられてしまう。墨を塗られ、徒歩で送り返される醜態で初陣を終えた。第百三回・百六回でも、上方谷の接応や公孫淵の包囲で張虎とセットに名が並ぶばかりで、見せ場はない。\n\n最後の登場となる第百十一回、彼は揚州刺史として歴史の渦に巻き込まれる。司馬昭の密書を受け、諸葛誕の反乱に与せず魏の側に留まろうとした。だが諸葛誕が十数騎で河を渡り城壁を越えて急襲すると、楽綝は城門を閉じ吊橋を上げて籠るのみ。「城上、並びに一人の回答なし」と守りは沈黙し、あっという間に「軍士を殺散し、大いに城門を開く」と城を奪われる。諸葛誕は「汝が父・楽進、昔日、魏国の大恩を受く」と父の名を持ち出して詰り、「楽綝匹夫、安んぞ敢えて此くの如くならん」と罵った。\n\nそして「綝、未だ言を回らさざるに、誕の為に殺さる」――反論する間すら与えられず斬られて果てた。父の名声の残り火だけを浴び、自身は一片の武功も知略も示せぬまま消えた、名将の子の悲運であった。"}, {"id": 296, "name": "曹豹", "faction": 3, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 2, 1, 2, 1, 1], "p": [0, 0, 0, 1, 0, 1], "scores": {"W": 1.7, "B": 1.55, "S": 1.25, "A": 1.35, "G": 0.27, "K": 0.35}, "stat": {"dmg": 0.67, "area": 0.91, "cd": 1.14, "amount": 1, "knock": 0.79, "crit": 0.05, "duration": 0, "pwr": 1.75}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [10, 14, 16], "chapN": 3, "bio": "陶謙配下の将", "profile": "徐州の主・陶謙に仕えた武将。槍を取り馬を駆る将ではあったが、その名が物語に刻まれたのは武勇ゆえではない。張飛に鞭打たれた逆恨みから呂布を引き入れ、徐州を裏切った内通者として記憶される男だ。\n\n第十回、曹操が父の仇を討たんと徐州に攻め寄せた折、曹豹は「曹兵既に至る、豈に手を束ねて死を待つべけんや。某、願わくは使君を助けてこれを破らん」と勇んで出陣し、「鎗を挺し馬を躍らせて」夏侯惇に当たった。だが両軍が交わるや砂嵐が巻き起こって戦は中断、勝敗はうやむやのまま終わる。結局、彼の槍が冴えた場面は一度もなかった。\n\n彼の真の出番は第十四回、劉備が徐州を預かった後に訪れる。留守を任された張飛が酒に酔って曹豹に酒を強い、断られると鞭打った。これを深く恨んだ曹豹は「席散じて回り去き、深く張飛を恨み、連夜、人を差わして書一封を齎し、逕ちに小沛に投じて呂布に見え」る。密書には「今夜、飛の酔いに乗じ、兵を引きて来たり徐州を襲うべし。此の機を錯るべからず」とあった。そして城門の上から呂布の軍を認めるや、「便ち軍士をして門を開かしむ」――一軍を率いる将でありながら、その兵を主家の防衛ではなく裏切りの門開きに使ったのである。\n\nだが裏切り者に栄華は訪れない。徐州を取り戻そうとした張飛と再び相まみえた曹豹は、「戦うこと三合にして敗走し、飛、趕いて河辺に到り、一鎗、正に曹豹の後心を刺中し、人を連れ馬を帯び、河中に死す」。背中を一突きにされ、馬もろとも川へ沈んだ。私怨で主家を売った将の、惨めな末路であった。"}, {"id": 297, "name": "申儀", "faction": 1, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 2, 1, 2], "p": [1, 1, 1, 1, 1, 2], "scores": {"W": 1.0, "B": 1.7, "S": 1.35, "A": 1.4, "G": 1.12, "K": 1.35}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [79, 94, 95], "chapN": 3, "bio": "申耽の弟、房陵都尉、兄と共に魏へ降る", "profile": "兄の申耽と常に二人一組で動く郡守クラスの将。房陵都尉、後に金城太守を称した。剣を取る将でありながら白兵の見せ場は皆無で、彼の本領は刃ではなく「裏切りの実務」にあった。蜀に仕え、魏に降り、さらに旧主を売る――その手際こそが申儀という人物の核心である。\n\n最初の見せ場は第七十九回。上庸に逃れた劉封を罠に嵌める場面で、申儀は「敵楼上に在りて旗を一颭す」と合図を送り、「城後に一彪の軍出で、旗上に大書す『右将軍徐晃』」と伏兵を呼び込む。兄申耽が「吾れ已に魏に降れり」と城上から叫び、兄弟は劉封を見捨てて魏に寝返った。剣を交えることなく、旗一振りで味方を売る――それが彼の戦い方であった。\n\n第九十四回、その手腕がさらに発揮される。孟達が新城で謀反を企て、金城太守の申儀と上庸太守の申耽に挙兵を約させると、申儀は家人を司馬懿のもとへ走らせ、孟達の謀反を密告した。「忽ち報ず、金城太守申儀の家人、機密の事ありて見えんと求む」――この一手で司馬懿は電撃的に出兵し、孟達は内応の手の者に囲まれて乱軍に殺される。第九十五回の街亭でも、申儀は兄とともに「両路の兵を引きて山を囲み、先ず汲水の道路を断つ」役を担い、馬謖の軍が渇きと混乱で自壊するのを待った。司馬懿の駒として、敵の自滅を誘う別働隊に徹したのである。\n\n申儀単独の戦果は最後までゼロであった。孟達を実際に刺すのも兄申耽であり、彼が手にしたのは剣ではなく密告状であった。劉封を裏切り、孟達を売り、二度三度と主を替える内応専門の郡守――その立ち回りの巧みさこそが、乱世を生き延びた彼の唯一の武器であった。"}, {"id": 298, "name": "厳白虎", "faction": 3, "role": "君主", "rarity": 1, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [1, 1, 1, 1, 2, 1, 2], "p": [2, 1, 1, 2, 2, 1], "scores": {"W": 1.0, "B": 1.7, "S": 1.35, "A": 1.4, "G": 1.5, "K": 1.65}, "stat": {"dmg": 0.66, "area": 0.94, "cd": 1.16, "amount": 2, "knock": 0.72, "crit": 0.05, "duration": 6.8, "pwr": 1.65}, "title": "君主", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [15], "chapN": 1, "bio": "呉郡に拠る賊王、孫策に滅ぼされ首を献じられる", "profile": "「東呉徳王」を自称し、呉郡を占拠した山賊あがりの割拠者。烏程・嘉興に部将を置いて一応の地盤を構えたが、その実態は江東を席巻する若き孫策の前に各地で連戦連敗を重ねた小寇に過ぎない。登場は第十五回ただ一度きりである。\n\n孫策が江東平定に乗り出すと、厳白虎は弟の厳輿を出して楓橋に迎え撃つが、たちまち押し込まれる。弟の厳輿を使者に立て「将軍と江東を平分せん」と和議を申し入れさせたものの、孫策は「鼠輩、安んぞ敢えて吾と相等しからんや」と激怒し、その場で厳輿を斬って捨てた。厳白虎は会稽の王朗を頼り、「孫策の兵勢甚だ大なり。足下、只だ宜しく溝を深くし壘を高くし、堅壁して出づるなかれ。一月を消せずして、彼の軍糧尽き、自然に退き走らん」と籠城・持久の策を授ける。理屈は通っていた。だが孫策の偽りの退却と疑兵の計にまんまと乗せられ、王朗ともども追撃に出て伏兵に大敗する。\n\n戦場での厳白虎は、終始「恐れる側」であった。太史慈の弓に「大驚」し、密林に伏兵の鼓が鳴れば「白虎大いに驚き、便ち馬を勒して回り走る」。配下に「かの軍に此くの如き人あり、安んぞ能く敵せんや」と弱音を漏らす始末で、敵を畏怖させた場面は一つもない。孫策からは「鼠輩」、虞翻からは「暴虐の衆」と罵られ、その僭称はかえって反逆者の烙印を招いた。\n\n最期は哀れである。城を棄てて逃げ、余杭へ奔る途上では略奪を働き、土地の者の凌操に率いられた郷人にすら討ち敗られた。会稽へ逃れたものの、衆はことごとく降り、ついに配下の董襲に首を取られる。「一日を隔てず、一人、厳白虎の首級を将ち来たりて孫策の軍前に投獻す」――味方に首を献じられて滅んだ、自称王の末路であった。"}, {"id": 299, "name": "彭羕", "faction": 0, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 3, 1, 1], "p": [1, 0, 0, 1, 0, 0], "scores": {"W": 0.0, "B": 1.75, "S": 1.45, "A": 1.6, "G": 0.37, "K": 0.35}, "stat": {"dmg": 0.65, "area": 0.93, "cd": 1.2, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 1.6}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [62, 63, 65, 79], "chapN": 4, "bio": "広漢の豪傑。決水の計を劉備に警告", "profile": "広漢の出身、身の丈八尺の偉丈夫で「蜀中の豪傑」と称された才人。劉備の入蜀に際して法正に推挙され、その幕賓に取り立てられた文官である。自らは戦わず、将に計を授ける純然たる軍師肌だが、演義での出番は少なく、その才よりも身を滅ぼす末路の方が濃く描かれている。\n\n唯一の手柄は第六十三回に訪れる。涪関を攻めあぐねる劉備軍にあって、彭羕は冷苞の水攻めの企てを見抜き、地理の妙を説く。「将たるの道、豈に地理を知らざるべけんや。前寨、涪江に靠る。若し江水を決動せば、前後に兵を以てこれを塞ぎ、一人も逃るべきなし」――敵が川を切って攻めてくる前に、逆にその手を読んで挟撃せよという献策であった。これにより冷苞の決江は未然に防がれ、彭羕は幕賓に迎えられる。だが彼の活躍は、後にも先にもこの一度きりである。\n\n通説では「狂士・才ある異端児」として知られるが、演義はその慢心と酒癖が破滅を招く様を執拗に描く。第七十九回、待遇の悪化を恨んだ彭羕は、酔った勢いで主君を「老革荒悖（老いぼれの耄碌者）、吾れ必ず以てこれに報ゆることあらん」と罵り、馬超に「公、本部の軍を起こし、孟達に結連して外合と為し、某、川兵を領して内応と為さば、大事図るべし」と謀反を持ちかけた。\n\nだがこの密談は、信を得られなかった。馬超はただちにこれを劉備へ密告する。劉備が「彭羕に謀反の意あり、当に何を以てこれを治めん」と問うと、孔明は「羕は狂士なりと雖も、然れども之を留むれば久しくして必ず禍を生ぜん」と答えた。かくして彭羕は捕らえられ、獄中で生を終える。一度は地理の才で名を上げながら、酒と慢心で自ら活路を閉ざした才人の、ままならぬ最期であった。"}, {"id": 300, "name": "軻比能", "faction": 3, "role": "君主", "rarity": 1, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [1, 1, 0, 1, 1, 2, 2], "p": [0, 0, 0, 2, 2, 0], "scores": {"W": 0.75, "B": 1.4, "S": 1.7, "A": 1.55, "G": 0.56, "K": 1.0}, "stat": {"dmg": 0.56, "area": 0.83, "cd": 1.18, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 0, "pwr": 0.7}, "title": "君主", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [83, 85, 88], "chapN": 3, "bio": "鮮卑(羌)の王。羌兵十万で西平関を攻める五路の一。馬超に阻まれ退く", "profile": "鮮卑の王にして羌兵十万を擁する番王。演義では「西番国王軻比能」と呼ばれ、章ごとに羌王・番王・西番国王と呼び名が揺れる。一個の人物というよりも、漢土の北西に控える異民族勢力の頭目を象徴する名として置かれている。本人の台詞も、一騎打ちも、戦場での身振りも、演義の本文には一切描かれない。\n\nその名が物語に立ち上がるのは第85回、蜀へ五路から同時に攻め込む大策の一翼としてである。魏の司馬懿は劉備崩御の隙を突くべく、遼東鮮卑国の王軻比能に「金帛を賂(おく)りて遼西羌兵十万を起こさせ、旱路より西平関を取らしむ」という献策を立てる。第五路、すなわち番王軻比能が羌兵十万を起こして西平関を犯す——その設定だけが、彼の登場のほぼすべてである。\n\nところがこの一路、諸葛亮はあっさりと封じてみせる。「馬超は積祖西川の人氏、素より羌人の心を得たり」と読み、馬超に西平関を堅守させ四路の奇兵を日ごとに交換して当たらせる。羌兵を率いて直進してきた軻比能は、交戦に及ぶ前に退く。蜀の後主が「此の五路の軍馬、甚だ是れ利害なり」と大いに驚いた、その五路の一翼でありながら、最も早く、最も静かに消えた手駒であった。\n\n通説では鮮卑の大勢力を統一した梟雄として語られる人物だが、演義の中では金帛で動かされ、馬超の名一つで退いていく背景の王に徹している。十万の兵を起こし得る規模の勢力でありながら、その兵を生かす場面を一度も与えられなかった——名のみで五路に名を連ねた、北の番王の影である。"}, {"id": 301, "name": "梁虔", "faction": 1, "role": "文官", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 2, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.7, "S": 1.35, "A": 1.4, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "文官", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [92, 93], "chapN": 2, "bio": "天水主記、梁緒の弟・降って上邽令となる", "profile": "魏の天水郡に仕える主記。功曹をつとめた梁緒の実弟で、太守馬遵の配下にあって兄とともに郡務を支えた文官である。武器こそ剣を帯びるが、演義の本文で一騎打ちに臨む姿はなく、その役回りは終始、馬遵や姜維の指揮の下で一軍を動かす実務の将であった。\n\n天水を舞台に諸葛亮の北伐が迫ると、梁虔は三千の軍を率いて上邽を保つよう命じられる。第93回、姜維がすでに蜀へ降ったと知った彼は、城上から姜維を見るや「反国の賊、安んぞ敢えて来たって我が城池を賺(だま)さんや。吾れ已に汝の蜀に降りしを知れり」と大いに罵り、乱箭を射かけて寄せ手を退ける。趙雲の迎撃にあたっては馬遵とともに「軍を引きて殺し回」り、城外に伏兵を置く一手にも加わった。いずれも上官の策に従って兵を運ぶ役どころで、自前の計略が描かれることはない。\n\n魏への忠を口にして城上で姜維を罵ったその同じ口が、やがて兄梁緒の招きに応じて翻る。最後は上邽を蜀へ献じて降り、上邽令に任じられた。城を守りきる立場から、城を明け渡す立場へ——その転身もまた、兄に導かれての受け身のものであった。\n\n通説で語られるほどの存在感は持たず、姜維をめぐる天水攻略の挿話を彩る脇役にとどまる。それでも、城頭から賊を罵る一場の気概と、血を分けた兄に手を引かれて降る現実的な身の処し方とが、文官の小役にひとすじの人間味を残している。"}, {"id": 302, "name": "費耀", "faction": 1, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 1, 2, 1, 2], "p": [0, 0, 0, 1, 0, 1], "scores": {"W": 1.0, "B": 1.7, "S": 1.35, "A": 1.4, "G": 0.27, "K": 0.55}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.16, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [97], "chapN": 1, "bio": "中護軍大将、姜維の偽降に騙され自刎", "profile": "魏の中護軍大将。大司馬曹真の幕下にあって前部総督を権(かり)に摂(と)る重き任を負った武将である。演義に姿を見せるのは第97回ただ一度きりだが、その一章のうちに、慧眼を示した将がその慧眼を自ら裏切って滅びるという、苦い二面が凝縮されている。\n\nことの起こりは姜維の偽降であった。姜維からの降書を前に、費耀はまず正しく疑う。「諸葛亮は多謀、姜維は智広し。或いは是れ諸葛の使う所、恐らくは其の中に詐有らん」と。そして曹真に向かい「都督、軽進すべからず、只だ本案を守り定めよ。某(それがし)願わくは一軍を引きて姜維を接応せん。如し成功せば都督に帰し、倘(も)し奸計有らば某自ら支当(ひきう)けん」と進言する。慎重に守りを固めよ、という眼は確かに正しかった。\n\nところが彼は、自ら五万の大軍を率いて出撃してしまう。孔明の用いた誘いの退きは巧妙で、蜀兵は交戦に及ばぬうちに先んじて退くこと、かくのごとき者三たび。費耀はその罠に何の備えもなく追撃を重ね、ついに伏兵の中へ全軍を投じた。「魏兵大敗」、関興が生力の軍を率いて背後から追い迫り、谷に落ち自ら踏み合って死す者その数を知らず。費耀は計に陥ったと悟って山谷へ馬を走らせたが、谷中は火光天を沖(つ)き、退路は断たれていた。\n\n追い詰めた姜維は「反賊、信無し」と罵る費耀を笑い、「吾れ曹真を擒(とら)えんと欲して、誤って汝を賺せしのみ。速やかに馬を下りて降を受けよ」と迫る。曹真を狙った罠に誤って掛かった獲物——そう嘲られながら、費耀は馬上で自刎して果てた。残る衆はことごとく降った。正しい一言を口にしながら、それを自らの行いで踏みにじって滅んだ将として、孔明と姜維の智略をいっそう際立たせる役回りを背負った人物である。"}, {"id": 303, "name": "張寶", "faction": 3, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 0, 1, 2, 1, 2], "p": [1, 0, 0, 0, 2, 1], "scores": {"W": 0.75, "B": 1.7, "S": 1.35, "A": 1.4, "G": 0.6, "K": 1.3}, "stat": {"dmg": 0.64, "area": 0.9, "cd": 1.16, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.75, "pwr": 1.45}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [1, 2, 28], "chapN": 3, "bio": "黄巾の将、周倉がかつて配下にいたとされる故人", "profile": "黄巾の乱を起こした張角の弟にして、地公将軍を称した賊軍の頭目。演義の冒頭、第1回で兄が天公将軍、弟の張梁が人公将軍を称するなか、張寶は地公将軍を名乗り、「今、漢運将に終わり、大聖人出づ。汝等皆な宜しく天意に順従し、以て太平を漿(やしな)うべし」という蜂起の檄に名を連ねた。\n\n通説では妖術使いとして知られるが、演義の張寶もまた、自ら刃を交えることをしない。第2回、玄徳の軍と対するや、まず副将の高昇を出して搦戦させ、これは張飛に討たれる。張寶自身は馬上で「披髪仗剣」して妖法を発する。「風雷大いに作(おこ)り、一股の黒気、天より降る」——黒気・砂石・紙人草馬の幻術で官軍を一時混乱に陥れ、「軍中大いに乱れ、陣を敗りて帰る」ありさまであった。八九万の賊衆を率いて山後に屯し、術を頼みに先手を取る。それが張寶の戦いのほぼすべてである。\n\nだがその妖術も、豬羊狗血と穢物を浴びせられればたちまち破れた。種を見抜かれた張寶になすすべはなく、玄徳の箭を左の臂に受けて陽城へ逃げ込み、堅く守って出てこなくなる。籠城のうちに賊勢は危急となり、結末はあっけない。「賊将厳政、張寶を刺殺し、首を献じて投降す」——八九万を擁したはずの頭目は、危急に陥るや配下の手にかかって首を差し出される側に転じた。\n\n妖術頼みで早々に脱落した、黄巾の三兄弟の一人。漢室の衰えを叫ぶ大義も兄張角の宣言の余韻にすぎず、彼自身には国家の像も人を結ぶ力もなかった。なお後の物語では、関羽配下の周倉がかつてこの張寶のもとにいた身であったと語られ、その名は思わぬ形で蜀の物語へと細い糸を引いている。"}, {"id": 304, "name": "劉瑰", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 0, 1, 2, 1, 2], "p": [0, 0, 0, 0, 2, 1], "scores": {"W": 0.75, "B": 1.7, "S": 1.35, "A": 1.4, "G": 0.38, "K": 1.15}, "stat": {"dmg": 0.56, "area": 0.83, "cd": 1.16, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 0, "pwr": 0.7}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [60, 61, 62, 63, 64], "chapN": 5, "bio": "劉璋配下の将。劉備を防ぐよう進言", "profile": "益州の主劉璋に仕え、要衝雒城を守った輔将。役柄こそ「武将」だが、演義の劉瑰が刃を振るう場面は一度もなく、その出番の大半は軍議の席での発言、布陣の指図、そして占い問答に費やされる。劉備の入蜀を防ぐべく進言した将の一人でありながら、本文の彼は一貫して凡庸な小役として描かれる。\n\n雒城の防衛をめぐっては、劉瑰も一言の見識は示す。「雒城は成都の保障なり、此れを失えば則ち成都も保ち難し」と要衝の値打ちを口にし、「二人城を守り、二人は雒城前面に往き、山に依り険を傍(そ)いて両個の寨子を紮(きず)き、敵兵をして城に臨ましむる勿(なか)れ」と分屯を提案した。だが決水の計や伏兵といった具体策を出すのは冷苞や張任であり、劉瑰の案はあくまで通り一遍であった。なかでも象徴的なのは第62回、紫虛上人への執拗な吉凶占いである。その姿は張任から「狂叟(くるった老いぼれ)」と一蹴され、迷信家として笑われる。\n\n敵からの評も手厳しい。第64回、呉懿は「輔将は劉瑰、張任なり。劉瑰は打緊ならず(取るに足りぬ)、張任は乃ち蜀郡の人、極めて胆略有り、軽敵すべからず」と、同席の張任だけを警戒し、劉瑰を名指しで無視してよいと断じた。冷苞が敗れ鄧賢を喪う危機には成都へ救援を求めるのみで、自力では局面をひらけない。\n\n最期もまた、自ら戦って斃れるのではなかった。第64回、城上で降伏を拒み大いに罵る劉瑰を、厳顔が射ようとしたその時、城上の一将が剣を抜いて劉瑰を砍(き)り倒し、門を開いて降った。味方の張翼に斬られ、城ごと寝返られたのである。同じ章で張任が「忠臣豈に二主に事(つか)うるを肯(がえ)んぜんや」と称えられ詩に顕彰されるのと比べれば、罵るばかりで自軍に討たれた劉瑰の節義は影が薄い。劉璋配下の数多の将のなかで、敵にも味方にも軽んじられた将として、その名を留めている。"}, {"id": 305, "name": "穆順", "faction": 3, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 1, 1, 1, 1, 1], "p": [1, 1, 1, 3, 2, 3], "scores": {"W": 1.45, "B": 1.1, "S": 1.0, "A": 1.0, "G": 1.67, "K": 1.6}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.15, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [5, 66], "chapN": 2, "bio": "張楊の部将、呂布に刺殺される", "profile": "演義には同じ「穆順」の名を持つ者が二人いる。一人は第5回に現れる上党太守張楊の部将、もう一人は第66回で漢室の忠に殉じる宦官である。武将として名簿に載るのは前者だが、本文に残る印象の重さは、むしろ後者の忠義の死にある。\n\n部将穆順の出番は虎牢関の一瞬に尽きる。天下の諸侯が呂布に手を焼くなか、「上党太守張楊の部将穆順、馬を出だし槍を挺(ひっさ)げて迎戦す。呂布が手起一戟に被(あ)い、馬下に刺さる」。槍を構えて天下無双の呂布に挑み、ただ一戟で討たれて落馬する。戦果はなく、呂布の凄まじさを諸侯の眼前に焼きつける、その引き立て役としての一文である。\n\nそれから六十余回を隔てた第66回、もう一人の穆順——伏皇后に仕える宦官が、はるかに重い役を担う。曹操の専横に追い詰められた帝后は、忠義託すべき者として穆順を選ぶ。彼は密書を髪のなかに隠して皇后の父伏完のもとへ運び、「皇丈、書を作りて帝后に覆(こた)え、密詔を求め、人を呉蜀二処に遣り、約会して兵を起こし、賊を討ちて主を救わしむべし」と、呉蜀と結んで曹操を討つ謀(はかりごと)まで自ら献じる。「臣、陛下の大恩に感ず、敢えて死を以て報いざらんや。臣即ち行くを請う」と涙して身を投じた、漢室の忠臣であった。\n\nだがその使命は、皮肉な綻びから露見する。曹操の前で帽を倒さまに被ってしまい、疑いを招いて密室に引き据えられたのである。拷問にかけられても穆順は「招(はく)せず」、ついに口を割らなかった。仲間を一人も売ることなく、一族二百余口とともに斬られて果てる。槍一本で呂布に挑んで散った武将と、密書を髪に秘して帝后のために死んだ宦官——同じ名を負う二人は、いずれも武で名を成す者ではなく、それぞれの場で命を惜しまなかった者として、演義に刻まれている。"}, {"id": 306, "name": "貂蟬", "faction": 3, "role": "婦人", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 0, 0], "p": [0, 0, 0, 9, 1, 2], "scores": {"W": 0.1, "B": 0.05, "S": 0.05, "A": 0.1, "G": 1.72, "K": 0.6}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.1}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [8, 9, 16, 19], "chapN": 4, "bio": "王允の歌伎、連環の計の要となる美女", "profile": "司徒王允に仕えた歌伎にして、後世に四大美人の一人と謳われる傾国の佳人。だが演義の貂蟬は、ただ美しいだけの道具ではない。董卓と呂布という父子のごとき二人の紐帯を、その身と弁舌と涙で断ち切ってみせた、連環の計の現場の実行者である。\n\n漢室を蝕む董卓を除く策に、貂蟬は自ら身を投じた。第8回、王允の苦衷を察した彼女は「妾、大人に許す、万死も辞せず、望むらくは即ち妾を彼に献ぜよ。妾自ら道理有り」と覚悟を述べる。やがて呂布の前では「妾、深閨に在りて、将軍の名を聞くこと、雷の耳を灌(そそ)ぐが如し……誰か想わん、反って他人の制を受けんとは」と煽り立て、董卓の前では泣き、媚び、ときに自刎の芝居で情を縛る。鳳儀亭で二人を引き裂き、ついに呂布の手で董卓を討たせるまで、彼女は二大権力者を意のままに操り続けた。\n\n危機の捌きもまた鮮やかであった。第9回、鳳儀亭の現場を董卓に押さえられ計画露見の瀬戸際に立つや、即座に「此れ必ず李儒の計なり、儒は布と交わり厚し、故に此の計を設く」と罪を李儒へ転嫁し、董卓に「蟬を以て布に賜う」進言を退けさせる。さらに宝剣を掣(ぬ)いて自刎せんとする芝居で、董卓の情をもう一度己に縛りつけた。一人の女が、兵も干戈も用いずに天下の大敵を屠ったのである。\n\n後人はこの功を「司徒の妙算、紅裙に托す。干戈を用いず兵を用いず……凱歌却って奏す鳳儀亭」と讃えた。連環計を描いたのは王允であり、貂蟬はその大義を託されて「妾、若し大義に報いずんば、万刃の下に死せん」と誓った身ではある。だが計を生きた現場で動かし、成し遂げたのは紛れもなく彼女であった。董卓の死後、第16回・第19回に呂布の妾として名がよぎるのみで、その後の事績は静かに物語から消えていく。傾国の美貌の奥に、計を一人で完遂する胆と機転を秘めた女——それが演義の貂蟬である。"}, {"id": 307, "name": "凌操", "faction": 2, "role": "武将", "rarity": 1, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [3, 1, 0, 1, 1, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.65, "B": 1.45, "S": 1.1, "A": 1.05, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.65, "area": 0.83, "cd": 1.1, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 0, "pwr": 1.6}, "title": "突撃の将", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [15, 38, 39], "chapN": 3, "bio": "孫権の部将、甘寧に射殺さる、凌統の父", "profile": "呉の孫氏に仕えた武将で、後に虎臣と謳われる凌統の父。だが演義における彼は、自身の武勲よりも「その死」によって記憶される人物である。彼の最期が、息子凌統と甘寧のあいだに長く尾を引く遺恨の発端となるからだ。\n\n凌操が物語に現れるのは第15回、孫策が江東を平定していく頃である。会稽の白虎の残党が路で劫掠を働くと、土地の人凌操が郷人を率いてこれを討ち破った。「白虎、余杭に奔り、路に於いて劫掠す。土人凌操に鄉人を領(ひき)いて殺敗せられ、会稽に望みて走る」。この働きを買われ、凌操父子は孫策に従征校尉として迎えられ、ともに兵を引いて江を渡る。\n\nだが彼の武人としての道は、長くは続かなかった。第38回、孫権が黄祖を討つにあたり、凌操は先鋒として軽舟をもって真っ先に突き進む。「権の部将凌操、軽舟当先し、夏口に殺入す」——勢い込んで敵中へ斬り込んだその刹那、黄祖配下の甘寧が放った一矢を受けて射殺された。勇んで突出したことが、そのまま死を招いたのである。\n\n一騎打ちの誉れも、武勇を讃える称号も、彼には与えられなかった。呼ばれる名はただ「権の部将凌操」。猛将の像は通説の幻であり、本文の凌操は短命の先鋒将にすぎない。それでも、この一矢が呉軍の内に消えぬ遺恨を残した。父を喪った凌統は甘寧を不倶戴天の仇とし、両者の確執はやがて呉の物語を動かす火種となる。己の手柄よりも、己の死の重みで後の世代の物語を駆動した将——それが凌操の演義における立ち位置である。"}, {"id": 308, "name": "張虎", "faction": 1, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 0, 0, 2, 0, 2], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 1.1, "B": 1.6, "S": 0.7, "A": 0.8, "G": 0.0, "K": 0.4}, "stat": {"dmg": 0.6, "area": 0.81, "cd": 1.13, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 1.05}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [7, 98, 100, 102, 103, 106], "chapN": 6, "bio": "黄祖配下の将、韓当に斬られる", "profile": "魏の名将張遼の子。父の威名を継いで戦場に立つが、演義の張虎は一騎打ちで敵将を討つことのない、司馬懿幕下の指揮駒として描かれる。なお第7回には黄祖配下の同名「江夏張虎」が現れ韓当に斬られるが、これは別人であり、張遼の子の事績ではない。\n\n第98回、曹真は「張遼の子張虎」を先鋒に、「楽進の子楽琳」を副先鋒に抜擢する。ところが二人に下された命は「同に頭営を守り、出戦を許さず」というもので、父の威光ゆえの登用でありながら、戦うことすら許されなかった。以後の張虎は、伏兵・弓弩の射撃・木牛流馬の強奪といった補助の任務に終始する。\n\nその任務の成否も、彼一個の力では決まらない。第100回、戴凌・楽琳とともに各三十騎を率いて諸葛亮の八陣へ生門から打ち入るが、ことごとく縛られて生け捕られ、墨を塗られ徒歩で送り返される始末であった。第102回には司馬懿の細かな指図——「汝二人各おの五百軍を引き、斜谷の小路より抄出し……只だ三五匹を搶(うば)いて便ち回(かえ)れ」——を受け、蜀兵に扮して木牛流馬を奪う伏兵を成功させる。これは数少ない手柄だが、あくまで上官の策を遂行したにすぎない。第103回の上方谷では司馬懿親子の窮地に「亦た兵を引きて殺し来たりて接応」したが、これも命令への応答であった。\n\nつねに五百から二千ほどの小部隊を任され、命を受けて動く下級指揮官——それが本文の張虎である。名将の子という看板を背負いながら、独自の武名も計略も与えられず、北伐の盤上で魏の手駒として動き続けた一人であった。"}, {"id": 309, "name": "雅丹", "faction": 3, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 2, 2], "p": [1, 1, 1, 4, 1, 2], "scores": {"W": 0.0, "B": 1.25, "S": 1.65, "A": 1.45, "G": 1.57, "K": 1.35}, "stat": {"dmg": 0.64, "area": 0.91, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.45}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [94], "chapN": 1, "bio": "西羌の丞相、馬岱に生け捕られ孔明に放たれる", "profile": "西羌国王徹里吉に仕えた丞相。武を司る越吉元帥と対をなす「文」の筆頭であり、羌国の外交と軍政を束ねる立場にあった。演義に登場するのは第94回ただ一度きりだが、その一章のうちに、外交の窓口として国を動かし、戦場では罠を侮って大敗し、最後は敵将の徳に感じて転ぶという、起伏のある役回りを演じきっている。\n\n雅丹の最大の見せ場は、その外交の取次にある。蜀の北伐に苦しむ魏の曹真が、金珠と書を携えた使者を羌国へ送ると、使者はまず雅丹丞相のもとを訪れた。礼物を受け、救援の意を聞いた雅丹は、これを国王に引き合わせて書を呈し、「我、魏国と素より相往来す、今、曹都督救いを求め、且つ和親を許す。理として依允(承知)するに合(かな)う」と説いて、魏との和親を成立させる。こうして雅丹は越吉とともに羌兵十五万を起こし、出陣することとなった。\n\nところが戦場に出た雅丹は、参謀としては徹底して裏目を引く。諸葛亮の伏兵や空寨の計を前に、彼は「虚しく疑兵を設くるのみ」「懼るるに足らず」「縦(たと)い此の小伏兵有るとも、何ぞ懼るるに足らんや」と三たび侮ってみせる。だが結果は「鉄車兵大いに乱る」の壊滅であった。誇った鉄車の兵は崩れ、雅丹丞相は早くも馬岱に易々と生け捕られてしまう。\n\n捕われた彼を、諸葛亮は意外な厚遇で迎えた。武士に命じて縄を解かせ、酒を賜って驚きを鎮め、よい言葉で撫慰したのである。「爾(なんじ)如何ぞ反って逆を助くる」と一度は責められた雅丹も、この徳に「深く其の徳に感」じ、放免されて羌へ帰る。蜀との「永く盟好を結ぶ」を持ち帰り、魏が築いた同盟を逆しまに崩す結び目となった。武勇も戦略眼も持たぬ文官でありながら、外交の取次として国を戦に向かわせ、敵将の度量によって国の向きを転じさせた——孔明の人心掌握を映す鏡として、西羌の丞相はその役を全うした。"}, {"id": 310, "name": "後主劉禪", "faction": 0, "role": "君主", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 1], "p": [1, 2, 1, 2, 3, 0], "scores": {"W": 0.0, "B": 0.4, "S": 0.7, "A": 0.55, "G": 1.49, "K": 1.65}, "stat": {"dmg": 0.55, "area": 0.84, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.55}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [80, 81, 82, 85, 91, 101, 105, 115, 117, 118], "chapN": 49, "bio": "蜀漢の皇帝、劉備の子", "profile": "蜀漢の二代目皇帝。昭烈帝劉備の嫡子であり、白帝城に父を喪った後、丞相諸葛亮に支えられて成都の玉座に座った。漢室の血を継ぐ正統の君として「漢統を承く」べく擁立されながら、その治世はついに父の遺志を背負いきれず、亡国の君主としての名を後世に残すことになる。\n\n即位の場面で、孔明は「国は一日も君無かるべからず」と説いて太子禅を帝位に立て、年号を建興と改めた。だが新帝はまつりごとの一切を自ら執ろうとはしなかった。第八十五回には「凡そ一応の朝廷、選法、銭糧、詞訟等の事は、皆な諸葛丞相の裁処を聴く」とあり、官の選任から銭穀の出納、訴訟の裁きに至るまで、ことごとくを丞相に委ねたのである。孔明の存命中は朝野が清く治まり、北伐の旗が幾度も翻った。しかしその柱を失った晩年、後主は宦官黄皓を寵し酒色に溺れる。姜維が黄皓を誅せよと諫めても「黄皓は趨走の小臣、専権すと縦んば、亦た能く為す無し」と笑って退け、賢人は退き小人は日に進む朝廷を招いた。\n\n通説に言う「暗愚」「凡庸」の像は、演義の筆もおおむねこれを裏書きする。だが本文を細かく辿れば、その本質は「悪」よりも「受け身」にあった。国家存亡の岐路に立っても自ら策を示さず、群臣の議論をただ聞くばかり。第百十八回、魏兵が城下に迫ると「後主驚惶措く無し」と狼狽するのみで、ついに譙周の降伏案にそのまま従った。自ら戦わず、自ら決せず、ただ流れに身を任せる——それがこの帝の一貫した姿であった。\n\n最期は哀しくも象徴的である。後主は太子諸王および群臣六十余人を率い、面を縛し櫬を輿して北門の外十里に出で、自ら玉璽を差し出して魏に降った。漢室の名分を背負った血脈は、その手で社稷を畳んだのである。北地王劉諶が宗廟に泣いて妻子を斬り殉じた壮烈と引き比べられ、後主の「偸生」は際立つ。後に洛陽へ移されると、司馬昭が宴に蜀の楽を奏でさせた。旧臣がみな涙を堕とす中、後主ひとり「嬉笑自若」として、問われれば「此間楽しく、蜀を思わず」と答えた。安楽公の封を受けて天寿を全うしたこの帝を、後人は詩に「方めて知る後主は是れ庸才なるを」と断じた。亡国の悲哀すら感じぬ無心——それを愚と見るか、あるいは乱世を生き延びた一つの処世と見るか。後世の評はなお割れて尽きない。"}, {"id": 311, "name": "糜芳", "faction": 0, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 1, 1, 2, 1, 1], "p": [1, 1, 3, 1, 1, 1], "scores": {"W": 1.45, "B": 1.55, "S": 1.25, "A": 1.35, "G": 1.36, "K": 1.0}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [18, 22, 28, 31, 39, 40, 41, 73, 75, 76], "chapN": 16, "bio": "劉備配下の将、趙雲反逆の誤報を伝える", "profile": "劉備配下の将。兄の糜竺とともに早くから劉備に従い、中軍や家眷、糧道を預かる後方・兵站の役を担い続けた。荊州の留守を任され「武将糜芳」として廖化・関平・周倉らと並び雲長を輔けたが、その肩書きは留守番役の枠に過ぎず、武名を語る言葉は終ぞ与えられなかった。\n\n数少ない働きどころは新野の戦いにある。第四十回、孔明の差配で青旗紅旗の疑兵を布いた糜芳は、劉封と組んで敗走する曹仁の軍を突き、一陣を衝き殺した。だがこれも命を受けて動いた集団追撃であり、自ら計を立てた働きではない。翌第四十一回の長坂では趙雲を阻もうとして蹴散らされ、むしろ「面に数箭を帯び、踉蹌として来たる」と矢傷を負って逃げ帰り、あろうことか趙雲が曹操に降ったと誤って讒言する小心まで露わにした。守る役を任されては破綻させる——それがこの男の宿命であった。\n\nその破綻は荊州で決定的となる。第七十三回、出師の前に傅士仁とともに失火して軍器糧草を焼き、火砲で味方の兵馬を死なせ、雲長に「汝ら二人を要して何の用かあらん」と斬られかけて降格された。さらに第七十五・七十六回、関羽が南郡から白米十万石を求めても届けられず、呂蒙が兵を率いて城下に迫るや、「漢中王の厚恩を受く」と一旦は口にしながら、たちまち城を明け渡して呉に降った。預かった守りを二度まで破り、ついに関羽軍崩壊の引き金を引いたのである。\n\nその最期は演義屈指の凄惨をもって描かれる。呉軍の中で「恨む所の者は、糜芳・傅士仁なり」と兵卒に殺意を向けられた糜芳は、馬忠を斬って蜀へ駆け込み、「阿斗太子は我が外甥、国戚の情を念わば必ず害を加えじ」と縁故の情に縋った。だがそれは保身の博打に過ぎず、劉備は彼を剥皮・剮刑に処した。義を口にしては破り、守りを任されては潰した裏切り者として、その名は荊州陥落の汚点とともに永く語り継がれる。"}, {"id": 312, "name": "梁緒", "faction": 1, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 2, 1, 2], "p": [1, 2, 2, 1, 1, 2], "scores": {"W": 0.1, "B": 1.6, "S": 1.35, "A": 1.4, "G": 1.5, "K": 1.55}, "stat": {"dmg": 0.64, "area": 0.9, "cd": 1.2, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.75, "pwr": 1.45}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [92, 93], "chapN": 2, "bio": "天水功曹、城を献じ孔明に降り天水太守となる", "profile": "魏の天水郡の功曹。剣を振るう武人ではなく、郡政を司る純然たる文官である。登場は第九十二・九十三回のわずか二回、姜維帰順の劇を彩る脇役として描かれる。\n\n第九十二回、孔明の北伐に夏侯楙が窮地に陥ると、梁緒は主簿尹賞・主記梁虔らとともに太守馬遵に進言する。「夏侯駙馬は金枝玉葉、もし疏虞あらば坐視の罪を逃れ難し。太守なんぞ本部の兵を尽く起こして之を救わざる」と。だがこの出兵こそ孔明の罠であり、姜維にこそ止められる。続く第九十三回、城上から趙雲を「汝、吾が姜伯約の計に中りて、尚お然お知らざるか」と大笑して嘲る一幕を見せるが、これも姜維の計を背にした虚勢に過ぎなかった。\n\nやがて姜維との至厚の交わりが、梁緒の運命を決める。孔明の離間計によって姜維が魏に容れられなくなると、尹賞は「城を納れて蜀に降り、以て進用を図るに如かず」と説き、梁緒も同心した。夏侯楙に害されかける危機を察した二人は、先んじて甲を披き馬に上り、本部の軍を率いて城門を大きく開き、蜀兵を城内へ迎え入れたのである。\n\n孔明に降った梁緒は天水太守に任じられ、降伏後は弟の梁虔を上邽から招いて降らせ、城内の民を率いて守備にも当たった。武勲によってではなく、姜維という一人の英傑を蜀へ導く扉となったことで、その名は演義に刻まれている。一郡の功曹が時勢を読んで身を転じた、降伏要員としての小さな、しかし確かな役回りであった。"}, {"id": 313, "name": "王累", "faction": 3, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 2, 1], "p": [1, 0, 0, 2, 2, 4], "scores": {"W": 0.0, "B": 0.55, "S": 1.3, "A": 1.05, "G": 1.26, "K": 1.55}, "stat": {"dmg": 0.59, "area": 0.88, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [60], "chapN": 1, "bio": "劉璋の従事。城門に逆さ吊りで諫死する忠臣", "profile": "益州の主、劉璋に仕えた帳前従事官。登場は第六十回ただ一度きりだが、その一場面の壮絶さによって、忠烈の士として演義に名を刻んだ人物である。\n\n時に張松の献策により、劉璋は劉備を西川に迎え入れて張魯に当たらせようとしていた。これに王累は黄権・李恢らと並び、死を賭して諫めた。「張魯の界を犯すは、乃ち癬疥の疾。劉備の川に入るは、乃ち心腹の大患なり」——皮膚病に過ぎぬ張魯と、腹中に巣食う病たる劉備とを鋭く見分け、外敵に資を与える愚を説いたその眼は、後に現実となる益州奪取を見透かしていた。さらに「主公軽々しく大郡を離れ、劉備を涪城に迎えんと欲す。恐らくは去路ありて回路無からん」と、楚懐王の故事を引いて主君の身の危うさを諫めた。\n\nしかし忠言は容れられなかった。王累の諫めは届かず、劉璋には「再び乱道する休れ」と一喝されて退けられる。そこで彼は前代未聞の最期を選ぶ。みずから縄索で城門の上に逆さ吊りとなり、一手に諫章を執り、一手に剣を仗えて、「諫めて従われずば、自ら縄を割断して此地に撞死せん」と叫んだのである。そして言葉のとおり、縄を断ち切って身を投じ、地に撞きあたって死んだ。\n\n武歴も治政の実績もなく、ただ一度の諫言と倒掛諫死だけで記憶される。後人は詩に「矢節何ぞ王累の剛なるに如かん」と、その節義の固さを讃えた。主家の傾きを誰よりも早く見抜き、命を擲ってまで主君を翻意させようとしたその姿は、容れられなかったがゆえに、かえって悲壮な忠臣の鑑として語り継がれている。"}, {"id": 314, "name": "張南", "faction": 1, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [2, 1, 1, 1, 1, 1, 2], "p": [1, 1, 1, 1, 2, 1], "scores": {"W": 1.45, "B": 1.35, "S": 1.1, "A": 1.05, "G": 1.13, "K": 1.5}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [33, 41, 48, 81, 82, 83, 84, 85], "chapN": 8, "bio": "袁紹旧降将、焦觸と共に小舟で挑み周泰に斬られる", "profile": "もとは袁紹配下の将。第三十三回、袁氏が衰えると焦触とともに「戈を倒し甲を卸して」曹操に降り、列侯に封じられた魏の降将である。赤壁前夜、焦触と組んで小舟で呉陣へ挑む血気の勇将として記憶される。\n\nその武は、勇ばかりが描かれて実は伴わなかった。第四十一回の長坂坡では趙雲を阻もうとするが、「衆軍将を殺退し、直ちに重囲を透る」と一蹴され、戦果を一つも挙げられない。赤壁では、曹操に「汝ら皆な北方に生長す、舟に乗るに便ならざるを恐る……汝、軽々しく性命を以て児戯と為す勿かれ」と水戦の危うさを諫められながら、「もし勝たずんば、甘んじて軍法を受けん」と大言して強行した。「焦触・張南、一勇の気を憑み、棹を飛ばして小船にて来たる」——その無謀さこそが彼の本領であった。\n\n最期は呉の猛将たちの引き立て役に徹する。先んじた焦触は韓当の一槍に刺し殺され、後に続いた張南が大叫して追い迫ると、周泰が一臂に牌を挽き一手に刀を提げ、両船の相離るること七八尺の間合いを飛身一躍して飛び越え、「手起き刀落ちて、張南を水中に砍る」——船上で一刀のもとに斬り捨てられ、水底へ沈んだ。旗を奪い将を斬って還ると豪語した突撃は、二十余隻の小舟もろとも全滅に終わった。勇のみありて実無き、赤壁の捨て駒であった。"}, {"id": 315, "name": "劉巴", "faction": 3, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 2, 1], "p": [2, 0, 0, 0, 3, 1], "scores": {"W": 0.0, "B": 0.55, "S": 1.3, "A": 1.05, "G": 0.95, "K": 1.55}, "stat": {"dmg": 0.59, "area": 0.88, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 1.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [62, 65, 81, 91], "chapN": 4, "bio": "零陵烝陽人。劉璋に劉備を警戒させた文官、後に左将軍", "profile": "零陵烝陽の人。後に蜀漢に左将軍・征南将軍として仕えた文官だが、演義での出番は極小に絞られ、忠節と先見の一臣として描かれる。\n\n第六十二回、劉璋が劉備に軍馬銭糧を援助しようとした折、劉巴はこれを鋭く諫めた。「劉備は梟雄なり、久しく蜀に留めて遣らざるは、是れ虎を縦って室に入るるなり。今更に之を助くるに軍馬銭糧を以てするは、何ぞ虎に翼を添うるに異ならんや」——劉備の本性を「梟雄」と見抜き、資を与えれば虎に翼を添えるに等しいと警告したその眼は、劉璋陣営でもっとも的確な対劉備の見識であった。だが容れられず、構想は単発の警鐘に終わる。\n\n第六十五回、成都が陥落すると、劉巴は黄権とともに門を閉じて出でず、旧主への節を貫いた。降伏を説く者に対しては「皆な大いに怒り、之を斬らんと欲す」と最後まで抗戦の姿勢を崩さなかった。その忠節を劉備は重んじ、「もし此の二人を害する者あらば、其の三族を滅せん」と厚遇する。二人は玄徳の恩礼に感じてようやく出仕し、こうして劉巴の節は演義に承認されたのである。\n\n正史では蜀の財政・法制を支えた「蜀科」の立役者として名高いが、演義はその面を一切描かない。第九十一回の北伐出師の名簿に「征南将軍劉巴」と名を連ねるのみで、台詞も事績も伴わない。武人ではなく、旧主に節を尽くし新主に器量を認められた、寡黙な忠臣として演義にその姿をとどめている。"}, {"id": 316, "name": "媯覧", "faction": 2, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 2, 1, 1], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.45, "S": 1.25, "A": 1.35, "G": 1.0, "K": 1.0}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.18, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [38], "chapN": 1, "bio": "丹陽督将、孫翊を謀殺、徐氏に討たる", "profile": "呉の丹陽督将。肩書きこそ武将だが、演義での実態は主君を弑する逆臣の役回り一色で、登場は第三十八回ただ一度きりである。\n\n媯覧は郡丞の戴員とともに、かねて丹陽太守孫翊を殺す心を抱いていた。二人は孫翊の従者である辺洪を心腹に結び、ともに謀って孫翊を弑する。門外で辺洪が刀を抽いて孫翊を斬り殺すと、媯覧と戴員は罪を辺洪一人に帰し、これを市に斬って口を封じた。さらに二人は孫翊の家資侍妾を擄掠し、媯覧は孫翊の妻徐氏の美貌を見て「吾れ汝が夫の為に仇を報ず、汝当に我に従うべし。従わずんば則ち死せん」と、権を笠に着て迫った。\n\nだが徐氏は知勇の女であった。徐氏は喪を脱して身を浄める数日の猶予を願い、その間に孫翊の旧将である孫高・傅嬰を密かに招いて涙ながらに討伐を頼む。そして偽って媯覧の意に従うと見せかけ、夜に婢妾を遣って媯覧を府へ招き入れた。堂中に席を設けて酒を飲ませ、酔ったところで密室へ誘い込む。「聞きて甚だ喜ぶ」と何の疑いもなく入った媯覧に対し、徐氏が「孫・傅二将軍いずこに在りや」と大呼するや、二人は幃幕の中から刀を持して躍り出た。媯覧は手出しもできぬまま傅嬰の一刀に砍り倒され、孫高がさらに一刀を復して、たちまち斬り殺された。\n\n主君を内から弑し、家財侍妾を奪い、未亡人に色を迫った末に、その未亡人の偽計を見抜けず酔って討たれる——督将でありながら誰一人従える者なく孤立した、簒逆者の典型である。「江東の人、徐氏の徳を称せざる無し」と人心はことごとく徐氏に集い、後人の詩も媯覧を「姦回一旦摧鋤を受く」と断罪した。武名なき逆臣として、その最期だけが鮮烈に記憶される。"}, {"id": 317, "name": "陳應", "faction": 3, "role": "武将", "rarity": 1, "weapon": "chakram", "kind": "proj", "weaponName": "戦輪", "d": [2, 1, 1, 1, 2, 0, 1], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 1.45, "B": 1.4, "S": 0.65, "A": 0.85, "G": 0.0, "K": 0.2}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "戦輪の将", "skill": "戦輪", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [52], "chapN": 1, "bio": "趙範配下の将。趙雲に捕らえられ後に斬られる", "profile": "桂陽太守趙範の配下の管軍校尉。猟師の出という低い身分の武将で、登場は第五十二回のみ。趙雲を引き立てる噛ませ役として描かれる。\n\n趙雲が桂陽に攻め寄せると、陳応は三千の人馬を率いて城を出て迎え撃った。両馬相交えて戦うこと四五合、「敵に料るに過ぎず」と勝てぬと見て馬を撥して逃げ走る。なおも趙雲が追い迫ると、陳応は飛叉を擲って一矢を報いようとしたが、その叉は趙雲に素手で軽々と接住され、逆に投げ返されてしまう。膂力も技も完全に格下であった。ついに生け捕りにされ、陣中で「汝ごときが安んぞ敢えて我に敵せんや」と一喝されると、ただ謝罪して頭を抱え鼠の如く逃げ帰るほかなかった。\n\n一度放免された陳応は、鮑隆と謀って偽降の計を仕掛ける。第五十二回、夜に五百の軍を引いて趙雲の寨へ降を装って投じたが、趙雲はとうにその詐りを心に知って「喚び入れしむ」。立案は鮑隆が主導し、陳応は「必ず些かの人馬を帯すべし」と従うのみで、計はあっさり見破られて斬られた。武勇でも知略でも趙雲に完敗を喫した、一城の雑兵格の敵将であった。"}, {"id": 318, "name": "孟優", "faction": 3, "role": "その他", "rarity": 1, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [1, 1, 1, 1, 2, 1, 1], "p": [1, 1, 1, 2, 1, 1], "scores": {"W": 1.0, "B": 1.45, "S": 1.25, "A": 1.35, "G": 1.15, "K": 1.0}, "stat": {"dmg": 0.62, "area": 0.9, "cd": 1.18, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 6.4, "pwr": 1.3}, "title": "群雄", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [88, 89, 90], "chapN": 3, "bio": "孟獲の弟。詐降の使者となるが薬酒で眠らされ捕らわれる", "profile": "南蛮王孟獲の親弟。第八十八回から九十回にかけて、七擒七縦の物語に従属的な脇役として現れる。武将と呼ばれながら一度も白兵戦や一騎打ちをせず、もっぱら兄に付き従って策に翻弄される弟として描かれる。\n\nその本領は知勇よりも失態にあった。第八十八回、孟優は詐降の使者として金珠宝貝・象牙犀角の贈り物を携え、青眼黒面・黄髪紫鬚の蛮兵百余人を率いて孔明の陣へ潜入する。「家兄孟獲、丞相活命の恩に感じ……権りに軍を賞するの資と為す」と偽りの降意を述べたが、孔明はとうに見抜いていた。馬謖・呂凱に命じて楽人に雑劇を演じさせ、慇懃に酒を勧めつつ酒中に薬を下したところ、「孟優並びに番兵尽く皆な酔倒」——孟優は兄の劫営計画を内から破綻させ、趙雲にやすやすと生け捕りにされた。\n\n兄を頼みとする小知恵の進言役でもあった。第八十九回、孟優は兄に「ただ山陰の洞中に就いて退避して出でず。蜀兵は暑気に受け過ぎず、自然に退かん」と退避策を授け、さらに「西南に一洞悉あり、名づけて禿龍洞という。洞主朵思大王、弟と甚だ厚し、之に投ずべし」と、個人の厚誼を頼った逃避先を提案する。だがいずれも局所の小策で、孔明には「汝が兄は愚迷なり、汝当に之を諫むべし」と諭される受け身の立場に留まった。\n\n七擒のうち幾度も兄とともに生け捕られては釈され、自力の戦果はついに一つもない。武勇でも知略でも兄を救えず、孔明の手のひらの上で踊らされ続けた、南蛮平定譚の哀しき道化役であった。"}, {"id": 319, "name": "朱褒", "faction": 3, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 1, 2, 1, 1], "p": [1, 1, 1, 2, 1, 1], "scores": {"W": 1.0, "B": 1.45, "S": 1.25, "A": 1.35, "G": 1.15, "K": 1.0}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.18, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [87], "chapN": 1, "bio": "牂牁太守。反乱に加わるが鄂煥に刺し殺される", "profile": "牂牁郡の太守。第八十七回、孔明の南征に際して城を献じ、雍闓・孟獲の反乱に加担した叛将である。\n\n朱褒は越雋太守高定とともに城を献じ、雍闓・高定と三路に兵を分けてその右翼を任され、五六万を率いて蜀軍を迎えた。だがその戦は雍闓の主導で、朱褒独自の計略も布陣もなく、いたずらに孔明の反間計に踊らされて敗れる。やがて朱褒は密かに孔明へ降書を出し、「雍闓と生死の交わりを結ぶ、豈に肯えて一日に便ち此の人を殺さんや」と高定を讒して仲間を売った。同盟ではなく裏切りの密告であり、しかも孔明の離間の駒として利用された受け身の一手に過ぎなかった。\n\nその最期は狼狽のうちに訪れる。反間計に乗せられた高定が真偽を質すと、朱褒は「目瞪口呆、回答する能わず」と立ち竦むばかり。山後より一彪の軍を率いて現れたところで、高定配下の鄂煥が「馬後より転過し、朱褒を馬下に刺す」——身長九尺・万夫不当の勇を誇る鄂煥の一突きに、なすすべもなく馬から突き落とされて死んだ。主を失った軍は高定の「順わざる者は皆な之を戮せん」の一喝でたちまち一斉に降り、その統率は脆くも崩れた。個人の武勇も政治の手腕も描かれぬまま、反間計の駒として退場した典型的な噛ませ役であった。"}, {"id": 320, "name": "張達", "faction": 0, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [2, 1, 1, 1, 1, 1, 1], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.45, "B": 1.1, "S": 1.0, "A": 1.0, "G": 1.0, "K": 1.0}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.15, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [81, 83], "chapN": 2, "bio": "張飛の末将。范疆と共に張飛を暗殺し呉へ逃げる。後に張苞に処刑される", "profile": "張達は、蜀の猛将・張飛の麾下に連なる末将である。范疆と並んで名が挙がるものの、白兵の手柄も将としての事績も一切持たない、最下級の一兵卒同然の身であった。それでも彼の名が三国の物語に永く刻まれたのは、ただ一点、主君張飛を手にかけた男としてである。\n\n第八十一回、関羽の弔い合戦に逸る張飛は、三日のうちに白旗白甲を整えよと無理を命じ、間に合わぬと告げた范疆・張達を縛り上げて鞭打った。口から血を流して帳に戻った二人は、生きるか死ぬかを酒に酔って眠る張飛の様子に賭け、夜更けに短刀を手に忍び寄る。だが張飛は目を見開いたまま眠っており、二人は恐れて手を出せない。雷のごとき鼾を聞いてようやく近づき、その腹に刃を突き入れた。首級を提げ、数十人を連れて夜の闇を呉へと駆け落ちる――武勇ではなく、裏切りと暗殺によって歴史に名を残した瞬間であった。\n\n張飛に怯えて一度は刃を引いたという描写が、彼の小ささをそのまま映している。膂力も武名も、まして大局を見る器も持たぬ男が、ただ我が身可愛さの一念で天下の豪傑を闇討ちにした。\n\nその末路は無惨である。第八十三回、呉が蜀との講和の取引材料として范疆・張達の身柄を差し出すと、檻車に押し込まれて送還され、張飛の子・張苞の手によって万剮凌遅、すなわち鋸引きの極刑に処された。父の霊前への供物とされたのである。英雄の散り際を語る演義の中で、彼は「英雄を殺した小人」として、最も暗い対極に置かれた一人だった。"}, {"id": 321, "name": "戴陵", "faction": 1, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [2, 1, 1, 1, 1, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.45, "B": 1.35, "S": 1.1, "A": 1.05, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.64, "area": 0.87, "cd": 1.14, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.45}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [99, 100], "chapN": 2, "bio": "張郃の副将、夜襲・闘陣で活躍", "profile": "戴陵は、魏の名将・張郃に従い、大都督・司馬懿の指揮下で戦った副将である。第百回では「戴凌」とも記される。前線の一武将として出陣はするものの、自前の武名も戦果も持たず、登場するたびに諸葛亮の計に嵌まる役回りであった。\n\n第九十九回、張郃とともに副将数十人・精兵三万を率いて進軍した戴陵は、孔明に「汝二人は無名の下将なり、殺しはせぬ、馬を下りて早く降れ」と名指しで侮られる。やがて蜀兵に垓心へと追い込まれ、囲みの中で立ち往生したところを、張郃が単身で敵中へ斬り込み救い出した。第百回では八卦の陣へ生門から突入を命じられるが、これも孔明の術中で、麾下もろとも捕らえられてしまう。捕虜となった戴陵は、顔に墨を塗られ、徒歩のまま追い返されるという屈辱を受けた。\n\n率いた兵こそ多いものの、その軍は常に大敗・潰走を繰り返し、勝ち戦をひとつも知らない。挟撃も陣への突入も、すべては司馬懿の差配に動かされる駒としての働きであり、彼自身が策を立てた場面はない。諸葛亮という巨大な知略を引き立てるための、敗れ役の典型であった。\n\n華々しい最期も後日譚も語られぬまま、戴陵は北伐の章に現れては敗れ、静かに物語から退場していく。彼の名は、孔明の用兵がいかに鮮やかであったかを映す、ささやかな鏡として残されている。"}, {"id": 322, "name": "曹爽", "faction": 1, "role": "武将", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 1, 0, 0, 0, 1, 1], "p": [1, 2, 1, 0, 2, 0], "scores": {"W": 0.2, "B": 0.4, "S": 0.7, "A": 0.55, "G": 1.06, "K": 1.35}, "stat": {"dmg": 0.55, "area": 0.84, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.55}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [106, 107, 110], "chapN": 3, "bio": "曹真の子、大将軍として専権・司馬懿に誅される", "profile": "曹爽は、魏の名将・曹真の子として生まれ、明帝の遺託を受けて司馬懿とともに幼帝曹芳を輔けた大将軍である。武器に「陣」を冠する将でありながら、その実体は一騎打ちも会戦の指揮も知らぬ権臣であった。血統ゆえに最高位へ担ぎ上げられ、佞臣を周りに侍らせて専権と奢侈に溺れた、決断できぬ男の典型として演義は彼を描く。\n\n権力を握った曹爽は、腹心・何晏の「大権を他人に委ねてはなりませぬ」という入れ知恵に乗り、司馬懿を太傅へと祭り上げてその兵権を奪った。弟たちに禁軍を握らせ、要職を一族と取り巻きで固める。門下には五百人の食客を抱えたが、重んじたのは何晏・鄧颺ら「浮華を相尚ぶ」見栄えだけの徒で、智嚢と称された桓範の諫言は退けた。進貢の珍宝はまず自分が上等を抜き取ってから宮中へ回し、衣服も器も天子と変わらぬ贅を尽くし、府には美女を満たした。\n\nその破滅の舞台が、第百七回の高平陵の変である。司馬懿は病を装って曹爽を油断させ、「あの老いぼれが死ねば憂いはない」と侮らせておいて、曹爽が天子を奉じて狩りに出た隙を一気に突いた。手元には天子があり、大司馬の印綬も兵権もあった。桓範は「天子を許都へ移し、外の兵を集めて司馬懿を討て」と最善の策を授ける。だが曹爽は一昼夜うろたえ続け、ついに剣を投げ捨てて嘆いた――「兵を挙げぬ。官を棄てて、富家翁になれればそれで足りる」と。\n\n無抵抗で降った彼を待っていたのは、三族皆殺しであった。御林軍を率いる立場にありながら、自ら印綬を手放したために「衆軍、将印なきを見て、ことごとく四散す」と全軍は崩れ去った。桓範には「まことに豚犬の子よ」と罵られ、司馬懿の周到な隠忍の前に、曹爽はその名を「危機に臨んで何も決められなかった男」の代名詞として後世に残した。権勢の頂から滅亡まで、彼の転落は演義屈指の苦い教訓となっている。"}, {"id": 323, "name": "陳震", "faction": 0, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 0, 1], "p": [1, 0, 1, 4, 1, 2], "scores": {"W": 0.1, "B": 0.3, "S": 0.15, "A": 0.15, "G": 1.37, "K": 0.95}, "stat": {"dmg": 0.51, "area": 0.8, "cd": 1.24, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.2}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [26, 28, 29, 81, 91, 98], "chapN": 6, "bio": "袁紹配下の使者、関羽に劉備の書を届け孫策との同盟交渉に赴く", "profile": "陳震、字は南陽の人。武勲とは無縁の純然たる文官であり、終始「使者・文書官」として三国の各地を行き来した取次の人である。初めは袁紹の配下として現れ、のちに蜀漢へ移って侍中にまで上る。盟好を結ぶための弁舌こそ華やかには描かれぬが、書状を運び、勢力と勢力を繋ぐ地味な役どころを、彼は幾度も務め上げた。\n\nその本領が外交の場にあることは、初登場の第二十六回からうかがえる。袁紹の使者として関羽のもとを訪れ、劉備の書を届けて主従離別の取り次ぎ役を果たした。続く第二十八・二十九回では孫策・孫権のもとへ赴き、「東呉を結んで外応となし、共に曹操を攻めん」と連衡の交渉に当たる。孫策のもとへ「袁紹の使者陳震至る」と報が入り、招き入れられて袁紹の意を具に述べる場面は、彼の真骨頂であった。\n\n蜀へ転じてからも、その立ち位置は変わらない。第八十一回、伐呉の軍中では馬良とともに文書を掌り、悲嘆に沈む先主に神仙・李意を召して吉凶を問うよう献策し、自ら使者に立った。第九十一回には侍中に任じられ、第九十八回には呉への賀使を務める。剣を取り陣を布く場面は一度もなく、彼の働きはひたすら言葉と紙の上にあった。\n\n舌戦群儒の諸葛亮や、単身呉へ乗り込んだ鄧芝・闞沢のような劇的な名場面を、陳震は持たない。それでも、複数の章にまたがって使者の任を託され続けたという事実が、彼が両国に重んじられた誠実な外交吏であったことを静かに物語っている。派手さはないが信の置ける繋ぎ手――それが演義における陳震の姿である。"}, {"id": 324, "name": "張梁", "faction": 3, "role": "武将", "rarity": 1, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [1, 2, 0, 1, 1, 1, 2], "p": [1, 0, 0, 0, 1, 1], "scores": {"W": 0.95, "B": 1.25, "S": 1.1, "A": 1.05, "G": 0.47, "K": 1.0}, "stat": {"dmg": 0.63, "area": 0.91, "cd": 1.18, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 6.8, "pwr": 1.35}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [1, 2], "chapN": 2, "bio": "張角の弟、曲陽で戦死", "profile": "張梁は、黄巾の乱を起こした太平道の教祖・張角の末弟であり、自ら「人公将軍」を称した。三兄弟の一人として乱の中核に名を連ねるが、演義の本文では兄に従う影の薄い存在で、個人の武勇を示す場面はほとんど与えられていない。\n\n物語の幕開けたる第一回、漢の天運すでに尽きんとして大聖人が世に出る――そう天意を掲げて挙兵した張角三兄弟は、潁川で皇甫嵩・朱雋の官軍と対峙する。だが草に依って結んだ陣営を火攻めにされ、加えて駆けつけた曹操に大いに討たれて、張梁は兄の張宝とともに敗残の兵を率い、夜明けまで斬り立てられながら血路を開いて逃げ落ちた。自ら敵将を斬る見せ場はなく、火に焼かれ追われる側として描かれるばかりである。\n\n第二回で兄・張角が病没すると、張梁はその衆を統べて官軍と相対した。一軍を継いで抗戦を続けた点には、わずかながら統率の証が見える。しかし皇甫嵩に連戦連敗、七つの陣を続けざまに破られ、ついに曲陽で斬られた。残った兵もことごとく降り、ここに乱の一翼は潰えた。\n\n天下を覆さんとした大乱の象徴的な名のひとりでありながら、張梁の実像は「敗れ続けた将」である。掲げた太平の理想も挙兵の決断も、すべては兄・張角が握っていた。それでも兄の死後に最後まで衆を率いて散った姿には、滅びゆく者のひとつの意地が滲んでいる。"}, {"id": 325, "name": "郗慮", "faction": 3, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 0, 2], "p": [0, 1, 0, 0, 2, 1], "scores": {"W": 0.1, "B": 0.55, "S": 0.25, "A": 0.2, "G": 0.58, "K": 1.35}, "stat": {"dmg": 0.52, "area": 0.8, "cd": 1.23, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.3}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [40, 66], "chapN": 2, "bio": "御史大夫、孔融を恨み讒言", "profile": "郗慮は、曹操に与する後漢朝廷の御史大夫であり、御林軍を束ねる立場にもあった文官である。武勲とはまるで縁がなく、その名が物語に刻まれるのは、私怨による讒言と、後宮への武装侵入という、曹操の政治的暴力の手駒としての二場面によってである。\n\n第四十回、郗慮はかねて孔融に侮られ続けたことを深く恨んでいた。孔融の言葉が家客を通じて耳に入ると、それをそのまま曹操に告げ口し、孔融排除の口実を与える。人を見抜き登用するのではなく、人を陥れる側に立った男であった。\n\nその役回りが極まるのが第六十六回である。曹操が伏皇后の誅滅を決すると、郗慮は節を持し、三百の甲兵を率いて宮中へ直入した。外殿にあった献帝が「何事か」と問うと、「魏公の命を奉じて皇后の璽を収む」と答える。事の露見を悟った帝は「心胆みな砕け」、後宮で起き出したばかりの伏皇后のもとへ進み、璽綬を管する者を呼んで玉璽を取り上げて出た。帝が「郗公、天下にこのようなことがあってよいものか」と叫んで地に倒れ伏すと、郗慮は左右に命じて帝を宮へ扶け入れさせた――事態を淡々と処理する、冷ややかな実行役の姿である。\n\n帝を震撼させたのは郗慮個人の武威ではなく、背後に控える曹操の権威であった。彼は自らの構想も統治の事績も持たず、ただ漢室簒奪の歯車として、節を奉じ璽を扱う公的な権能を行使するのみ。学者・大臣でありながら、演義の中ではひたすら「曹操に従う収捕の使者」として描かれた、時代の暗部を担う一人である。"}, {"id": 326, "name": "劉辟", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [2, 1, 0, 0, 1, 1, 2], "p": [0, 1, 0, 2, 1, 1], "scores": {"W": 1.1, "B": 1.3, "S": 1.05, "A": 0.95, "G": 0.75, "K": 1.05}, "stat": {"dmg": 0.6, "area": 0.81, "cd": 1.14, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 1.05}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [26, 27, 28, 31], "chapN": 4, "bio": "汝南の劉備与党、高覧に斬らる", "profile": "劉辟は、汝南に拠った黄巾賊の残党の頭目であり、のちに劉備へ帰順して数万の衆を率いた一勢力の長である。賊上がりの群雄として龔都とともに名が挙がるが、武勇の見せ場はほとんどなく、その人物としての輝きは、ただ一点、主君劉備のために命を捨てる忠死の申し出にあった。\n\n第二十六回、「汝南に黄巾の劉辟・龔都あり、甚だ猖獗なり」と紹介された彼は、官を逃れて流浪する孫乾を匿うなど、人を受け入れる度量を見せる。第二十七回には孫乾を河北の袁紹のもとへ遣わし、劉備と結んで曹操を破る計を請うなど、同盟形成の動きにも関わった。だが第三十一回、劉備に汝南の守りを任されると、夏侯惇に攻められて城を棄てて逃げ、軍を保てぬまま、敗軍千余騎を率いて劉備の家族を護送する身となる。\n\nそして彼の最期は、その一瞬にすべてが凝縮されている。曹操軍に追い詰められた劉備が窮地に陥ると、劉辟は急ぎこれを押しとどめ、「某に死戦して血路を開き、君を救わせたまえ」と申し出た。言い終えるや高覧に斬りかかるが、三合と戦わぬうちに一刀のもとに馬上から斬り伏せられた。賊徒上がりの自分を収めてくれた主君に、文字通り命で報いた一刹那であった。\n\n武力も将才も最低の部類で、城を守れば棄て、剣を交えれば瞬殺される噛ませ役にすぎない。それでも演義は、汝南の劉辟・龔都は劉備に何の縁故もなかったのに死をもって報いた、と記す。出自の卑しさを超えて主君に殉じた忠の一念だけが、この端役を確かに人として光らせている。"}, {"id": 327, "name": "夏侯楙", "faction": 1, "role": "武将", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 1, 1, 1], "p": [1, 1, 1, 1, 2, 1], "scores": {"W": 1.0, "B": 1.0, "S": 1.0, "A": 1.0, "G": 1.13, "K": 1.3}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 2.75, "pwr": 1.0}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [81, 91, 92, 93, 102, 112], "chapN": 6, "bio": "夏侯淵の子・曹操の婿、無能な大都督で三城を失う", "profile": "夏侯楙、字は子休。魏の名将・夏侯淵の子にして夏侯惇の養子、さらに曹操の娘・清河公主を娶った駙馬（天子の婿）である。血筋も家柄も申し分ないこの貴公子は、しかし演義屈指の無能将として名を残した。本文は彼を「兵権を掌るといえども、いまだかつて陣に臨まず」と明記する。軍を握りながら、実戦の経験は皆無であった。\n\n第九十一回、孔明の北伐に対し、夏侯楙は「諸葛亮を生け捕りにせねば、誓って天子には見えぬ」と豪語して大都督に任じられ、二十余万を率いて出征する。だが第九十二回、鳳鳴山では先鋒に立てた韓徳とその四子が趙雲に一陣で討ち取られ、自身は趙雲に直取りされて「慌てて本陣へ逃げ込む」始末。参軍・程武の伏兵計に乗ってどうにか趙雲を囲んだものの戦果はなく、続く崔諒・楊陵らの偽降の策もことごとく孔明に看破される。軍が乱れると総大将の彼が真っ先に逃げ出し、「衆軍、主なきを見て、ことごとく逃げ散った」――全軍が瓦解した。やがて王平にわずか一合で生け捕りにされる。\n\n孔明はこの捕虜をまるで意に介さず、「夏侯楙を放つは、一羽の鴨を放つようなものよ」と言い放った。捕らえた姜維こそ鳳であり、夏侯楙など無価値だというのである。「無謀の人」「膏粱の子弟、懦弱無謀」と本文が重ねる否定の言葉どおり、敵に恐れられるどころか嘲笑の的であった。\n\n三郡を失った夏侯楙は羌中へ逃げ落ち、その失態は後の第百二回でも、曹叡が「軍機を誤り、多くの人馬を失わせた」失敗の代名詞として引かれるほどであった。武勇も将略も民政も、何ひとつ自前のものを持たず、ただ婿という血縁の地位だけで頂に据えられ、そして魏に甚大な損害をもたらして去った。名門の御曹司がいかに将器を欠いていたか――夏侯楙はその痛烈な見本として、北伐の物語に刻まれている。"}, {"id": 328, "name": "雷薄", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 1, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.25, "S": 1.1, "A": 1.05, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.18, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [15, 16, 17, 21], "chapN": 4, "bio": "袁術配下から嵩山に投じ、術の銭糧を奪う", "profile": "雷薄は、僭称の帝・袁術に仕えた将で、「上将」「副将」として陳蘭らと名を並べる一武将である。袁術配下の諸将の一人として軍に列するものの、個人の白兵や一騎打ちの見せ場は本文に描かれず、その実像は限りなく薄い。\n\n第十七回、袁術が大軍を七路に分けて進発させた際、雷薄は第四路の副将として左翼に配され、一軍を率いて瑯琊を取りに向かった。だが実際の交戦は、迎え撃つ張遼・臧霸との対峙が記されるのみで、雷薄自身が剣を振るって戦う描写はない。割り当てられた一路を担うだけの、名の挙がる程度の働きであった。\n\n彼が唯一、能動的に動くのは第二十一回である。袁術の勢いが傾くと、雷薄は陳蘭とともにこれを見限って嵩山へ投じた。さらに敗走する袁術の銭糧草料を奪い取る――主君を裏切り、その窮地に乗じて略奪を働くという、負の事績によって物語に足跡を残したのである。\n\n僭称の帝の凋落とともに離れていく将の一人として、雷薄は袁術の滅びを彩る脇役に徹した。武功も武名も、まして大義もそこにはない。袁術という虚栄の帝にどれほど人が集まり、そしてどれほど呆気なく離れていったか――雷薄の去り際は、その栄枯をささやかに映す一場面となっている。"}, {"id": 329, "name": "張著", "faction": 0, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 1, 1, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.25, "S": 1.1, "A": 1.05, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.18, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [71], "chapN": 1, "bio": "黄忠の副将、糧草劫掠で囲まれ趙雲に救われる", "profile": "張著は、蜀の老将・黄忠の副将として、漢水の戦いにただ一度だけ姿を見せる端役の武将である。槍を手に戦場へ動員されるが、自ら敵将を斬る見せ場はなく、彼の役割はむしろ、味方の名将・趙雲の武勇を鮮やかに引き立てることにあった。\n\n第七十一回、曹操が二十万の大軍を率いて夏侯淵の弔い合戦に出ると、牙将の張著が「張郃が米倉山の糧草を漢水北山の麓へ移している」と報じる。これを受けた黄忠は敵糧の劫掠を企て、孔明は張著を副将として同行させた。夜陰に乗じ、黄忠が前、張著が後に続いて漢水を渡り、北山の下へと忍び寄る。ところが作戦は曹軍に察知され、三百の軍を率いて脱出を図った張著は、文聘に行く手を遮られ、後ろからも曹兵が迫って、ついに囲まれてしまう。\n\n窮地の彼を救ったのが趙雲であった。槍ひとつで敵中へ斬り込み、張著を囲みから救い出すこの場面は、趙雲の勇を際立たせる名舞台となっている。張著自身は最後まで敵将を一人も討たず、立案も指揮もすべて黄忠と孔明に委ね、ただ命に従って後に続き、そして救われる側に回った。\n\n事績は漢水の一局面に尽き、後の章に彼の名はもう現れない。それでも、副将としてわずかな兵を率いて戦場に立ち、趙雲の武名を語り継ぐための一齣を担ったところに、この無名の槍の将のささやかな存在意義がある。"}, {"id": 330, "name": "陳蘭", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 1, 1, 2], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.25, "S": 1.1, "A": 1.05, "G": 1.0, "K": 1.2}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.18, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [15, 16, 17, 21], "chapN": 4, "bio": "袁術配下から嵩山に投じ、術の銭糧を奪う", "profile": "袁術配下の一将。第十五回・第十六回で、雷薄と並んで「上将雷薄、陳蘭」と名を連ねる、淮南勢の名簿に載る武人である。孫策が玉璽を質に兵を借りた一件をめぐる軍議の席にも「陳蘭ら三十余人」の一人として同席するが、策を述べるのは楊大将であり、陳蘭は終始その他大勢の列に身を置く。\n\n彼が最も前に出るのは第十七回、袁術が七路に兵を分けて徐州へ攻めかかる「七路征徐州」のくだりである。「第五路副将陳蘭、右に居る」と記され、雷薄が瑯琊を取る一方、陳蘭は一軍を率いて碣石を取る役を負った。だが呂布側が宋憲・魏続を出して碣石に当たらせると、それ以降の交戦も勝敗も本文は何ひとつ語らない。称号も台詞も白兵の働きもないまま、彼は名簿の一行として戦場を通り過ぎていく。\n\n転落はその後に来る。袁術の仲氏建国が傾くと、陳蘭は旧主を見限って雷薄とともに嵩山へ投じ、群盗に身を落とす。第二十一回、落ちぶれた袁術の一行は「嵩山の雷薄・陳蘭に銭糧草料を劫去せられ」、かつて仕えた主の最後の蓄えまで奪い取る側に回った。一軍を任された副将が、養ってくれた政権の崩壊を早める略奪者として演義の幕を引く——それが陳蘭という男の、本文に描かれた姿のすべてである。"}, {"id": 331, "name": "曹植", "faction": 1, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 1], "p": [1, 1, 0, 3, 2, 1], "scores": {"W": 0.0, "B": 0.4, "S": 0.7, "A": 0.55, "G": 1.25, "K": 1.3}, "stat": {"dmg": 0.55, "area": 0.84, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.55}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [13, 34, 44, 68, 72, 78, 79, 91], "chapN": 8, "bio": "曹操の子、銅雀台賦の作者として孔明に言及される", "profile": "曹操の三男、字は子建。臨淄侯に封じられた、魏きっての文の天才である。演義の曹植は一貫して「文才の人」として描かれ、武勇や用兵の事績は一切持たない。代わりに彼の名に刻まれるのは、筆を下せばそのまま文章になる才——「下筆して文を成す」と評された、言葉そのものの輝きだった。\n\nその文才が最も劇的に物語を動かすのは第四十四回、赤壁前夜である。曹操がかつて曹植に作らせた「銅雀台賦」の華麗な一節を、孔明はそらんじてみせ、「二喬を銅雀に囲わん」と読み替えて周瑜を激発させる。子建の美しい賦が、本人のあずかり知らぬところで呉を抗戦へと駆り立てる導火線になった。そしてもう一つの名場面が第七十九回、兄曹丕に詩才を試され、七歩あゆむ間に詩を成せと迫られた件である。曹植は歩を進めながら「本は是れ同根より生ず、相煎ること何ぞ太だ急なる」と詠み、骨肉相食む兄に己の死を思いとどまらせた。言葉が命を救った、まさにその瞬間だった。\n\nだが彼の実像は、才に酔い、才に溺れる男でもある。同じ第七十九回、使者が来ても臨淄侯は「端坐して動かず」、酒に乱れて使者を棒で打ち出す。許褚が城へ迫れば、曹植は丁儀・丁廙らと「ことごとく酔い倒れ」、抵抗もできぬまま縛り上げられた。母の卞氏は「平生酒を嗜み疏狂、ゆえに放縦なり」と嘆く。後継争いの陣営では楊脩や丁氏兄弟という与党を頼んだが、曹丕側の謀略に各個撃破され、政治の駆け引きでは完敗した。\n\n第九十一回では、司馬懿の偽告示が「太祖は陳思王子建を社稷の主に立てんと欲した」と、彼を本来の後継候補として持ち出す。だがそれも他者の政治宣伝に名を借りられただけのこと。文章の力では兄を泣かせ天下を動かしながら、自らの政治力には何ひとつ転化できなかった——曹植は、輝く才そのものが悲劇であった王族として演義に残る。"}, {"id": 332, "name": "袁熙", "faction": 3, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 0, 0, 1, 1, 2], "p": [0, 0, 0, 1, 1, 1], "scores": {"W": 0.65, "B": 1.2, "S": 1.05, "A": 0.95, "G": 0.4, "K": 0.85}, "stat": {"dmg": 0.55, "area": 0.81, "cd": 1.18, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 0.6}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [31, 32, 33, 91], "chapN": 4, "bio": "袁紹の次子、幽州守、遼東で斬らる", "profile": "袁紹の次子、字は顕奕。幽州を守る刺史として、河北の名門袁家の一翼を担う立場にあった。第三十一回、官渡敗北後の冀州攻防で「袁熙、兵六万を引き、幽州より来たる」と、兄弟を助けるため大軍を率いて参陣する。だが「武将」の肩書とは裏腹に、彼が自ら敵将を斬る一騎打ちの場面は本文のどこにも描かれない。\n\n袁熙の演義は、敗走と滅亡の連鎖である。第三十二回、黎陽の戦いでは高幹とともに「城を離るること三十里に寨を下し、虚しく声勢を張る」が、結局「袁譚・袁熙・袁尚・高幹みな大敗し、黎陽を棄てて走る」。第三十三回には部将の焦触・張南が「戈を倒し甲を卸して」曹操に投降し、軍の結束は内から崩れた。曹兵の接近に「迎え難しと料り、城を棄て兵を引いて」幽州を捨て、烏桓へ、さらに白狼山では張遼に撃たれて遼東へと逃れていく。\n\n最後の場面で、袁熙はわずかに大きなことを口にする。遼東の公孫康のもとへ身を寄せる際、弟袁尚と「いま暫くこれに投じ、後に当に公孫康を殺してその地を奪い、気力を養って中原に抗し、河北を復すべし」と密議するのだ。だがそれは敗者の願望にすぎず、実行に移す前に逆を取られる。公孫康は「賺して城中に入れこれを殺し、頭を曹公に献ぜん」と謀り、袁熙は弟もろとも誘い込まれて首を取られ、その首級は曹操のもとへ送られた。\n\n名門の血を引きながら、彼は終始受け身の負け役だった。むしろ後世に名が残るのは、妻の甄氏が曹丕に奪われたという挿話のほうかもしれない。河北の覇者袁紹の次子は、自らの武も計も示せぬまま、滅びの連鎖に呑み込まれて消えた。"}, {"id": 333, "name": "阿会喃", "faction": 3, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 0, 0, 1, 1, 2], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 0.65, "B": 1.2, "S": 1.05, "A": 0.95, "G": 0.0, "K": 0.4}, "stat": {"dmg": 0.55, "area": 0.81, "cd": 1.18, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 0.6}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [87, 88], "chapN": 2, "bio": "第三洞の元帥。董荼那と共に孟獲を捕らえるが後に殺される", "profile": "南蛮王孟獲に従う「三洞元帥」の一人、第三洞の元帥である。第八十七回、孔明の南征に対し、董荼那ら他の元帥とともに各々五万の蛮兵を率い、阿会喃は右路を担って迎え撃つ役を負った。元帥の称号を冠しながらも、彼の働きは終始、孔明の計略を成立させるための駒にとどまる。\n\nその実態は受動そのものだった。右路の寨は趙雲・馬忠の夾攻にあっさり破られ、趙雲が一半の兵を分けて西路から寨へ抄り来ると、蛮兵は大敗。阿会喃自身は「乱に乗じて走脱し」、兵を捨てて逃げ延びるしかなかった。自ら敵将を斬る白兵の戦果も、奇襲も火攻もなく、ただ命じられた路を進んでは破られる。第八十八回では瀘水の沙口を三千の兵で守るよう孟獲に命じられるが、これも主君の差配にすぎない。\n\n最期は味方の手にかかった。孟獲の召集を受けた阿会喃と董荼那は「二人懼怕」——敵を恐れるどころか自らの主を恐れる側に回り、それでも呼び出しに応じる。だが孟獲は二人を「大寨の帳下に賺し到し、ことごとくこれを殺して屍を澗に棄つ」。騙し討ちを見抜けぬまま無防備に呼ばれ、谷川に屍を捨てられて果てた。元帥の肩書だけを背負い、自身の危機にすら対応できずに散った蛮将である。"}, {"id": 334, "name": "杜襲", "faction": 1, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 1, 1, 1], "p": [1, 1, 2, 1, 1, 1], "scores": {"W": 1.0, "B": 1.0, "S": 1.0, "A": 1.0, "G": 1.18, "K": 1.0}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 2.75, "pwr": 1.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [66, 71], "chapN": 2, "bio": "曹操を魏王に推した文士の一人", "profile": "魏に仕えた文士。演義での杜襲は、文官と武人という二つの顔を、ごく薄い筆致で見せる人物である。第六十六回では侍中として登場し、王粲・衛凱・和洽とともに「曹操を尊んで魏王と為さん」と議する四人の一人に名を連ねる。曹操の進爵を後押しする廷臣の側に身を置く、知の人としての一面だ。\n\nところが第七十一回、漢中・定軍山の戦いになると、杜襲は一転して「夏侯淵の部将」として戦場に現れる。定軍山の西の対山を、わずか数百人で守る役を負ったのだ。だが黄忠の大隊が押し寄せると、彼は交戦することなく「ただ山を棄てて走る」ほかなく、敗れて夏侯淵のもとへ逃げ帰り、「黄忠、対山を奪う」と凶報を伝える伝令役に回る。\n\nその後、定軍山が法正の謀によって失われると、杜襲は張郃とともに「米倉山の糧草を北山の寨中に移して屯積し、然る後に兵を進めん」と進言する。兵糧を安全な地へ移すこの献策が、彼が本文で見せる唯一の知恵らしい知恵である。だが大勢は覆らず、「郃大いに驚き、ついに杜襲とともに敗兵を引いて漢水に営を紮く」と、敗走と飛報のうちに彼の出番は終わる。文官としての謀も武人としての戦果も大きくは描かれず、推戴の議に名を連ね、敗報を運ぶ実直な脇役として演義に残る人物である。"}, {"id": 335, "name": "楊脩", "faction": 1, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 1], "p": [1, 2, 1, 2, 0, 1], "scores": {"W": 0.0, "B": 0.85, "S": 0.95, "A": 0.9, "G": 1.22, "K": 0.9}, "stat": {"dmg": 0.58, "area": 0.87, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [23, 60, 71, 72], "chapN": 4, "bio": "曹操の主簿、才走り過ぎて鶏肋の件で曹操に斬られる", "profile": "曹操の行軍主簿。才気煥発という言葉がそのまま人になったような文官で、その鋭すぎる才知ゆえに主君の心を読みすぎ、ついに命を落とす。弔詩に「聡明なる楊徳祖」「捷対は群英に冠たり」と讃えられた、魏一の機知の人である。\n\nその才は早くから際立っていた。曹娥碑に刻まれた謎めいた八字「絶妙好辞」の意をたちどころに解き、第六十回では蜀の使者張松を応接する。曹操の兵法書「孟徳新書」を持ち出して見せると、張松はそれを一読してすらすらと暗誦してみせ、楊脩は「公は過目して忘れず、真に天下の奇才なり」と舌を巻いた。才を見せに行った場で、かえって才に驚かされるという、彼らしい一幕だった。\n\n運命を決したのが第七十二回、漢中の陣中である。曹操が何気なく発した夜の合言葉「鶏肋」を聞くや、楊脩は「鶏肋とは、これを食らえば味なく、これを棄つれば惜しし。今進んで勝つ能わず、退いては人に笑わるるを恐る。ここに在りて益なし、早く帰るに如かず」と、主君の退兵の腹を読み切って荷支度を始めさせた。主の意図を言い当てる占察の鋭さは見事だが、それは軍心を乱す行いでもあった。曹操は「汝、怎んぞ敢えて謡を造り、我が軍心を乱すか」と激怒し、刀斧手にその身を斬らせ、首級を轅門の外に晒した。\n\n彼の実像は、才に恃んで放埒に振る舞う「恃才放曠」の人である。曹植の世子擁立に深く肩入れし、答教十余条まで作って後継争いに踏み込んだが、曹丕陣営の呉質に出し抜かれ、「操、脩が曹丕を譖害せんとするを疑い、いよいよこれを悪む」と、主君の不信を募らせていった。誰よりも切れる頭脳を持ちながら、その切れ味で己の身を斬った——楊脩は、才に殉じた文人として三国志演義に名を刻む。"}, {"id": 336, "name": "馬援", "faction": 3, "role": "その他", "rarity": 1, "weapon": "charge", "kind": "dash", "weaponName": "突撃", "d": [0, 4, 0, 2, 0, 1, 1], "p": [0, 0, 0, 0, 1, 0], "scores": {"W": 1.0, "B": 0.5, "S": 0.8, "A": 0.75, "G": 0.13, "K": 0.5}, "stat": {"dmg": 0.57, "area": 0.88, "cd": 1.24, "amount": 1, "knock": 0.7, "crit": 0.06, "duration": 0, "pwr": 0.8}, "title": "群雄", "skill": "突撃", "skillDesc": "敵陣へ突き入る突進", "voice": "", "hist": "", "chapters": [19, 29, 57, 89, 91], "chapN": 5, "bio": "馬騰の先祖。後漢の伏波将軍として言及", "profile": "後漢の名将、伏波将軍。馬騰・馬超の先祖にあたる西涼の英雄である。ただし演義の作中時間に生身で登場することはなく、彼は「故事の引用名」として、また南蛮の地に祀られる廟神として物語に現れる、レジェンドの参照枠の人物である。\n\nまず武名の代名詞としての馬援。第九十一回、老いてなお戦場に立つ趙雲は、己を奮い立たせて「我、年邁ゆといえども、なお廉頗の勇、馬援の雄あり。この二古人みな老いに服せず」と言い放つ。趙の名将廉頗と並んで「雄＝武勇そのもの」を体現する古の豪傑として、その名が引かれるのだ。第二十九回では「臣もまた君を択ぶ」の名言の主としても登場する。馬援が光武帝に語ったというこの一句は、後世まで処世と忠義の規範として、人の口にのぼり続ける言葉となった。\n\nもう一つの顔が、南蛮を鎮めた先駆者にして守護神としての馬援である。第八十九回、孔明が南征で進軍する瘴癘の地は「ここ虫鳥みな無く、ただ漢の伏波将軍かつて到るあり」と語られ、かつてこの南方を平定した馬援の足跡だけが、人跡未踏の地に刻まれている。やがて孔明は、伏波将軍を祀る廟に行き当たる——「一将軍を塑して端坐せしめ、旁らに石碑あり、すなわち漢の伏波将軍馬援の廟」。蛮を平らげてこの地に至り、土人が廟を立てて祀ったというその社で、馬援の霊は山神を遣わして孔明の窮地を救い、「伏波将軍顕聖す」と霊威を示す。\n\n生身の事績は演義に描かれずとも、武勇の代名詞として、忠義の名言の主として、そして死してなお南方を守る神として——馬援は、時を越えて孔明の南征を助ける歴史の偉人として、演義の中に確かな存在感を放っている。"}, {"id": 337, "name": "甘夫人", "faction": 0, "role": "婦人", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 0], "p": [0, 0, 0, 0, 3, 2], "scores": {"W": 0.0, "B": 0.0, "S": 0.0, "A": 0.0, "G": 0.63, "K": 1.2}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.0}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [22, 25, 26, 28, 34, 41, 42, 54, 85], "chapN": 9, "bio": "劉備の夫人、長板で趙雲に救出され漢津へ送られる", "profile": "劉備の正夫人格にして、後主劉禅の生母。関羽が護送した「二嫂」の一人として、流転する劉備陣営をしのぎ支えた婦人である。自ら軍政を動かす場面はないが、彼女の存在は蜀漢の正統そのものに深く絡んでいる。\n\nその賢さがにじむのが、関羽の千里行のくだりである。曹操のもとに身を寄せた間も、甘夫人は皇叔劉備の安否を案じ続け、関羽に「叔よ、宜しく上緊すべし（早く皇叔を尋ねよ）」と促し、励ます。関羽が曹操から贈られた品々も「みな二嫂に送りて収貯せしむ」と、夫の留守を守る賢嫂として一行の心の支えとなった。そして第三十四回、建安十二年の春、新野で阿斗——のちの劉禅を産む。白鶴・異香・北斗を呑む夢という瑞兆に彩られた、蜀統の母としての誕生だった。\n\n彼女の名場面はやはり長坂である。曹操の大軍に追われ、甘夫人は「披頭跣足（髪を振り乱し裸足のまま）」歩いて逃げ惑い、「我ひとり逃げ生きてここに至る」と窮地に陥る。そこへ趙雲が単騎で乱軍に踏み込み、夫人を救い出して漢津へと送り届けた。趙子龍の長坂の奮戦を、被保護者の側から照らす場面である。第四十一回には阿斗を「劉嗣」と呼び、「一死を拚じても劉の嗣を存せん」と、わが身を捨てても世継ぎを守ろうとする母の姿も描かれる。\n\n最期と後の評価において、彼女は蜀の正統秩序に正式に位置づけられる。第五十四回では皮肉にも彼女の死が周瑜の美人計（孫夫人との縁組）の口実に使われ、外交の客体ともなるが、第八十五回、劉備の没後、その諡「昭烈」を冠して「甘夫人を昭烈皇后と為す」と追諡された。劉禅を産み、その継承の起点となった生母として、また昭烈皇后として蜀漢の名分に名を刻む——甘夫人は、武を持たずして蜀の血脈と正統を体現した婦人である。"}, {"id": 338, "name": "張允", "faction": 1, "role": "武将", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 2, 0, 1], "p": [0, 0, 1, 1, 0, 0], "scores": {"W": 0.1, "B": 1.2, "S": 0.65, "A": 0.85, "G": 0.33, "K": 0.2}, "stat": {"dmg": 0.58, "area": 0.86, "cd": 1.21, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.9}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [40, 41, 45, 47], "chapN": 4, "bio": "荊州の将で曹操に降る水軍副都督、蔡瑁と共に誅される", "profile": "荊州の将、のちに曹操に降る水軍副都督。演義の張允は、常に「蔡瑁、張允」と連名でのみ姿を現す、蔡瑁の影のような従属者である。個人の台詞も武勇の描写も持たず、荊州の水戦に長じた専門家という一点だけが、彼の能力として本文に残る。\n\nその経歴は売国と諂佞に彩られている。第四十回では蔡夫人らとともに遺命を偽造し、「次子劉琮を荊州の主と為さ」しめる廃長立幼に手を貸す。第四十一回、樊城に至って曹操に拝謁したときの二人の態度は「辞色はなはだ諂佞（へつらいに満ちる）」と断じられた。城楼に駆け上った魏延からは「蔡瑁、張允、売国の賊！」と名指しで罵られる始末である。荊州水軍の戦船七千余隻を蔡瑁とともに掌管していた軍備の実務者ではあったが、それも蔡瑁に従う立場でのことだった。\n\n曹操に降った後、張允は蔡瑁とともに荊州の水軍を率い、長江沿いに精巧な水寨を築く。「沿江一帯、二十四座の水門を分かち、大船を外に居して城郭と為し、小船を内に居して往来を通ず」——この見事な設営に、敵将周瑜さえ「これ深く水軍の妙を得たり」と嘆じた。だがそれゆえに周瑜は「この二人、久しく江東に居りて水戦に諳習す。吾、必ず計を設けてまずこの二人を除き、然る後に曹を破るべし」と、二人を真っ先に除くべき脅威と見定めたのである。\n\n彼の最期は、まさに反間の計の犠牲そのものだった。蒋幹が呉から持ち帰った偽の手紙にすっかり乗せられた曹操は、張允と蔡瑁を呼び出すや突然に斬首を命じる。「蔡、張二人、その意を知らず、驚慌して回答する能わず」——わけもわからぬまま狼狽し、弁明も自衛もできずに首を打たれた。荊州を売り、水寨を築いた専門家は、知らぬうちに敵の計に嵌められ、自らの愚かさも気づかぬまま処刑台に消えた。"}, {"id": 339, "name": "王粲", "faction": 1, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 2, 0], "p": [1, 0, 0, 2, 2, 0], "scores": {"W": 0.0, "B": 0.3, "S": 1.2, "A": 1.0, "G": 0.78, "K": 0.75}, "stat": {"dmg": 0.58, "area": 0.88, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 3.0, "pwr": 0.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [40, 41, 56, 66], "chapN": 4, "bio": "荊州の官、曹操に降り関内侯に封じられる", "profile": "「建安七子」の筆頭に数えられる天才文人。演義でも「異才あり」「博聞強記」「文詞は一時に妙絶す」と、その才を惜しみなく讃えられる純然たる文官である。「容貌は痩弱、身材は短小」と記される小柄で線の細い体つきだが、その内に宿る才知は荊州一州を動かすほどの重みを持っていた。\n\nその弁が最も光るのが第四十回、曹操の南下を前にした荊州である。王粲は若き主劉琮に向かい、「将軍、自ら料るに曹公に比して何如」と問いを突きつけ、曹操の戦歴を一気に数え上げる——「呂布を下邳に擒え、袁紹を官渡に摧き、劉備を隴右に逐い、烏桓を白狼に破る。梟除蕩定する者、勝げて計うべからず」。そのうえで「いま大軍をもって荊襄に南下す、勢い抵敵し難し」と大勢を読み切り、降伏こそ「長策なり」と説いた。この弁舌一つで荊州は無血のまま曹操に帰順し、王粲は一州の命運を言葉で動かしてみせた。\n\n曹操に降ってからは、その文才を魏の宮廷で発揮する。第五十六回、鄴の銅雀台の宴では「命を受くるに合当すべし」の意を込めた詩を献じ、曹操の権威を寿いだ。そして第六十六回、王粲は杜襲・衛凱・和洽とともに「曹操を尊んで魏王と為さん」と議する四人の主導者の一人となり、魏の正統と権威の確立に筆と弁を捧げる。\n\n武を一切持たぬ痩身の文人でありながら、彼は弁をもって一州を傾け、詩をもって覇府を彩り、議をもって主君を王へと押し上げた。戦場に立つことのなかった建安の才子は、言葉という武器だけで魏の歴史に確かな足跡を残した人物である。"}, {"id": 340, "name": "董荼那", "faction": 3, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 0, 0, 1, 0, 2], "p": [0, 2, 1, 0, 0, 2], "scores": {"W": 0.65, "B": 1.05, "S": 0.45, "A": 0.45, "G": 0.82, "K": 1.1}, "stat": {"dmg": 0.55, "area": 0.81, "cd": 1.18, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 0.6}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [87, 88], "chapN": 2, "bio": "第二洞の元帥。孔明の恩で孟獲を捕らえるが、後に孟獲に殺される", "profile": "南蛮の第二洞元帥。孟獲が蜀へ叛いた七擒七縦の戦いにおいて、五万の兵を率い左路を任された一洞の主である。雑兵の頭ではない。三路に分かれて進む蛮軍の一翼を、堂々と背負う立場の将であった。\n\n第87回、孟獲の三路分進の中で「董荼那、左路を取る」と命じられて出陣するが、待ち受けていたのは魏延・王平の夾攻であった。蠻兵は大敗し、董荼那自身も「奪路走脫」と血路を切り開いて逃げ延びるのがやっとであった。ここで彼の運命を分けたのは、武功ではなく恩義である。捕らわれて孔明に命を救われた経験が、続く第88回で彼を縛る。馬岱の軍と相対し、いざ応戦と名乗り出ながら、董荼那は刃を交えることができなかった。「満面に羞慚を帯び、言うべき言葉も無く、戦わずして退いた」。受けた恩に背けず、戦場で刀を引いたのである。\n\nこの珍しい心の揺れこそ、彼を単なる蛮将以上の存在にしている。だが孟獲はこれを「賣陣の計（敵に通じて陣を売る裏切り）」と疑い、董荼那を百棍に打ち据えた。立場を失った董荼那に、酋長たちが訴える。「いっそ一死を捨て、孟獲を殺して孔明に投じ、洞中の百姓を塗炭の苦しみから救おう」と。彼は「未だ汝らの心の底を知らず」と一同の意思を確かめてから決起する。鋼刀を手に百余人を率いて孟獲の大寨へ突入し、帳下に侍る二将にも「汝らもまた諸葛丞相の活命の恩を受けた身、宜しく報いるべし」と説いて味方に引き入れ、ついに孟獲を生擒して孔明に献じた。\n\n恩に殉じた一洞主の最期は、しかし報われなかった。後に孟獲の賺し討ちに遭い、大寨の帳下に賺し入れられて殺される。武勇の見せ場は皆無に等しく、戦果はすべて敗走と羞慚と寝返りに彩られている。それでも、戦場で刀を引いたあの一場面――武威ではなく恩義に動かされた一人の蛮将の姿は、七擒七縦という孔明の心攻の物語の中で、忘れがたい一片の人間味として残る。"}, {"id": 341, "name": "趙範", "faction": 3, "role": "君主", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 2, 0, 1], "p": [0, 1, 0, 3, 1, 1], "scores": {"W": 0.0, "B": 1.15, "S": 0.6, "A": 0.75, "G": 0.9, "K": 0.85}, "stat": {"dmg": 0.57, "area": 0.86, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.8}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [52], "chapN": 1, "bio": "桂陽太守。趙雲に降り嫂を娶らせようとして拒まれる", "profile": "桂陽太守。劉備が荊南四郡を平定する戦いの中、趙雲の前に現れる地方の小君主である。自ら戦う意志は薄く、「我れ本と降らんと欲す」と最初から降伏に傾いていた人物で、武勇も統率も自前の見せ場をほとんど持たない。\n\n第52回、趙雲が桂陽へ攻め寄せると、趙範は配下の陳應に押されて一戦を交えるが、陳應は四五合で趙雲に生け捕られてしまう。趙範は「我れ本と降らんと欲するに、汝強いて戦わんとし、以て此に致る」と責任を陳應に転嫁し、自らは十数騎を引いて出城し、大寨に降を納めた。ここからが趙範という男の唯一の見せ場――対人交渉である。彼は趙雲に取り入ろうと、「将軍は姓趙、某も亦た姓趙。五百年前は合わせて一家なり。将軍は真定の人、某も亦た真定の人、又た是れ同郷なり」と、同姓・同郷・同年を畳みかけ、兄弟の義を結ぼうとした。さらに寡婦となった嫂・樊氏を趙雲に嫁がせ、「累世の親を結ばん」と婚姻を持ちかける。\n\nだが趙範は相手の人柄を読み違えた。趙雲は節義の人であり、「汝の嫂は即ち吾が嫂なり」と一喝して拳一発で趙範を打ち倒す。面目を潰された趙範は鮑隆・陳應を呼んで「美人計が破れたなら詐降の伏兵で陣上にて趙雲を擒えよう」と相談するが、発案者の鮑隆ともども、その計は趙雲に「已に其の詐を心知す」と即座に見抜かれ、全員が斬られて完敗した。\n\n結末は、彼の小器ぶりをよく表している。趙雲を怒らせ、配下任せの謀略が悉く露見し、自身も捕縛される。だが劉備は「今日大事已に定まる」と趙範を釈し、なお桂陽太守に留任させ、趙雲を重く賞した。同郷・同姓を頼りに英傑へ取り入ろうとして断られ、謀殺を企てて失敗し、最後は赦されて職に戻る――武力ゼロに近い地方太守の、滑稽さと哀れさの同居した一席である。"}, {"id": 342, "name": "曹奐", "faction": 1, "role": "君主", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 1], "p": [0, 1, 0, 0, 2, 1], "scores": {"W": 0.0, "B": 0.25, "S": 0.1, "A": 0.05, "G": 0.58, "K": 1.15}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.1}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [2, 3, 4, 114, 118, 119, 120], "chapN": 7, "bio": "曹操の孫、燕王曹宇の子。魏最後の帝。司馬炎に禅譲し陳留王となる", "profile": "曹操の孫、燕王曹宇の子。魏最後の皇帝にして、王朝の幕を自らの手で下ろした傀儡の天子である。第114回、司馬昭によって帝位に立てられた時から、その運命は決まっていた。\n\n曹奐の時代、魏の実権はことごとく司馬氏が握っていた。演義は「奐、名は天子たるも、実は主張する能わず、政は皆な司馬氏に由り、敢えて従わざる無し」と、その無力を一句で言い切る。鄧艾を収監する第118回の動きも、御駕親征も、すべては司馬昭の主導であり、「昭乃ち魏主曹奐と同に御駕親征す」と記されるとおり、曹奐は名目上の存在として同行するにすぎなかった。彼が行う唯一の人事すら、司馬昭を晋王に封じ、その父司馬懿に宣王、兄司馬師に景王と諡を贈るという、司馬氏の権勢を追認する作業であった。\n\nそして第119回、ついにその日が来る。司馬炎は曹奐に「文は道を論ずる能わず、武は邦を経る能わず」と無能を面と向かって突きつけ、禅譲を迫った。曹奐は司馬炎の威に「大いに驚き、口噤して言う能わず」と怯えるばかり。賈充らの「漢の獻帝の故事に照らし、受禪台を重修し、大礼を具え、位を晋王に禅らば、陛下保ちて虞無かるべし」との進言に従うほかなかった。受禪台の上、曹奐は自ら伝国璽を捧げ持ち、文武を大会してこれを司馬炎に渡す。曹操が築き、曹丕・曹叡が継いだ魏の社稷は、ここに滅んだ。\n\n帝位を譲った曹奐は陳留王に封じられ、太康元年に世を去る。武の見せ場は生涯ただの一つもなく、政の主体性も持たなかった。それでも、帝璽の正統な継承者として禅譲の儀を全うし、命を保って善終を得た――抗うことを許されなかった一人の少帝が、せめて穏やかに歴史の幕引き役を演じきった、その静かな結末が魏王朝の最後の姿である。"}, {"id": 343, "name": "孫皓", "faction": 2, "role": "君主", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 3, 1, 1, 0], "p": [1, 1, 0, 0, 2, 1], "scores": {"W": 0.3, "B": 0.75, "S": 1.0, "A": 1.15, "G": 0.8, "K": 1.1}, "stat": {"dmg": 0.6, "area": 0.87, "cd": 1.24, "amount": 1, "knock": 0.74, "crit": 0.07, "duration": 2.75, "pwr": 1.1}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [113, 120], "chapN": 2, "bio": "孫和の子、烏程侯。呉最後の暴君。晋に降り帰命侯となる", "profile": "孫権の太子・孫和の子、烏程侯。呉の最後の皇帝にして、三国の物語を締めくくる亡国の暴君である。第120回、濮陽興らに迎えられて帝位に就いた時、孫皓は「才識明断、帝王たるに堪う」と評され、大いに期待された。だがその期待は、これ以上ないほど無残に裏切られることになる。\n\n帝位に就くや、孫皓は酒色に溺れ、忠臣を屠る恐怖政治を始める。自らを擁立した功臣・濮陽興と張布が諫言すれば、怒ってこの二人を斬り、三族もろとも滅ぼした。「是に由り廷臣口を緘し、敢えて再び諫めず」――以後、誰も諫言できなくなった。宴の後には臣下に互いの過失を密告させ、咎ある者は「或いは其の面を剥ぎ、或いは其の眼を鑿る」という凄惨な刑を加える。「是に由り国人大いに懼る」。前後十余年で殺した忠臣は四十余人、出入りには常に鉄騎五万を従え、群臣はただ恐怖し、なすすべもなかった。陸凱は上疏して「今、災い無くして民命尽き、為す無くして国財空し」と内政の破綻を直言したが、孫皓の奢侈は度を知らず、昭明宮の造営に文武百官を山へ木を伐りにやり、占い師に天下を問わせる始末であった。\n\n晋の大軍が迫っても、その器の小ささは変わらない。王濬の戦船が長江を順流に下る鋭鋒を前に、孫皓はただ憂色を浮かべ、岑昏の献じた鉄索・鉄錐の防衛策に頼るが、易々と焼き斬られてしまう。「漢土を兼并し、蜀主の讎を復さん」と拡張を口にしながら、その中身は術士の吉兆占い頼みで、諫める者を斬ると脅すばかりであった。ついに「江南の軍民、戦わずして降る」。全軍が一兵も交えず降伏したのである。\n\nそれでも、孫皓には不思議な才気の閃きがあった。晋帝の前に引き出され、座を勧められて「臣、南方に於いて、亦た此の座を設けて以て陛下を待てり」と言い返し、剥面の刑を問われては臆せず弁じたという。最後は自刎を思い止まり、棺を載せ身を縛って王濬の軍前に降った。帝王たる才を評されながら、その才を暴政にのみ費やし、孫権三世の江東を一代で滅ぼした――羊祜が「孫皓の暴、劉禅に過ぎたり」と評したとおり、三国の終焉に立つにふさわしい、栄光と暗黒の落差を体現した亡国の主である。"}, {"id": 344, "name": "楊陵", "faction": 1, "role": "文官", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [0, 0, 0, 0, 2, 0, 1], "p": [0, 0, 0, 0, 2, 1], "scores": {"W": 0.0, "B": 1.15, "S": 0.6, "A": 0.75, "G": 0.38, "K": 0.95}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 0.0}, "title": "文官", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [92], "chapN": 1, "bio": "南安太守、楊阜の族弟・関興に斬られる", "profile": "魏の南安太守。涼州の名臣・楊阜の族弟にあたる文官で、孔明の第一次北伐における「智取三城」の一幕に登場する。武勇や将才の見せ場を持たない端役だが、忠節と小才を見せて散った人物である。\n\n第92回、孔明は降った崔諒を通じて、楊陵に城ごと寝返るよう説かせた。だが楊陵はこれに表向き応じつつ、内心は揺るがなかった。「我等、魏主の大恩を受く、安んぞ忍びて之に背かんや」――魏帝への恩義を盾に裏切りを拒み、夏侯楙とともに「将計就計（孔明の計を逆手に取る計）」を巡らす。彼の策はこうであった。「只だ某が城門を献ずと推して、蜀兵を賺し入れ、却って城中に就きて之を殺さん」。府中に刀斧手百余人を伏せ、城外と城内で呼応して蜀軍を一網打尽にしようという、文官なりの伏兵の小計である。\n\nしかし相手が悪かった。孔明は崔諒の偽降を最初から見抜いており、「足りて其の詐を知る」とこの罠を完全に看破していた。逆手に取ったつもりが、さらに逆手に取られていたのである。城門に立って蜀軍を出迎えた楊陵を、関興が一刀のもとに斬り捨てる。「興、手起こし刀落ち、楊陵を馬下に斬る」。伏兵は発動する間もなく、夏侯楙は生擒され、守備兵も「余は皆殺し死す」と全滅した。\n\n武功も将才も大局の政治も、楊陵の本文には一片も残らない。だが「魏主の大恩」を口にして寝返りを拒んだあの一言には、一臣下の節義が確かに宿っていた。孔明の知略の引き立て役として一瞬で散りながら、その最期に忠の二字を刻んだ、智取三城の小さな犠牲者である。"}, {"id": 345, "name": "樊建", "faction": 0, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 1], "p": [0, 0, 1, 0, 2, 2], "scores": {"W": 0.0, "B": 0.25, "S": 0.1, "A": 0.05, "G": 0.68, "K": 1.1}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.1}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [87, 91, 99, 102, 111, 119], "chapN": 6, "bio": "掾史として南征に従軍", "profile": "蜀漢の文官。掾史に始まり、典軍書記、丞相令史、そして尚書令へと、官位の階梯を一段ずつ上っていった実務の人である。武勇や指揮の見せ場は一切なく、終始一貫して幕僚・筆記官として孔明と後主のかたわらに在り続けた。\n\n第87回の南征には掾史として従軍し、第91回では典軍書記として名を連ねる。彼が孔明の信任を受けていたことは、第99回の場面に表れる。病を得た孔明が「吾れ自ら昏沈を覚え、事を理むる能わず。漢中に回りて病を養い、再び良図を作すに如かず。汝等切に走泄する勿れ、司馬懿若し知らば、必ず来たりて攻撃せん」と、暗夜の撤退という最大の機密を、董厥とともに樊建に託したのである。一軍を率いる将ではないが、丞相が秘事を打ち明けるに足る幕僚であった。\n\n樊建の唯一の能動的な見せ場は、諫言である。第111回、姜維が度重なる出兵を繰り返すと、令史であった樊建はこれを諫めた。「将軍屢々出づるも、未だ全勝を獲ず。今日洮西の戦い、魏人既に威名に服す、何故ぞ又た出でんと欲するや。万一利あらずんば、前功尽く棄てん」。国の消耗を見据えた的確な諫言であったが、姜維に「衆敢えて諫めず」と退けられ、聞き入れられることはなかった。後の段谷の大敗を思えば、樊建の見通しは正しかったのである。\n\n蜀漢が滅びる時、樊建の真価は静かに現れた。第119回、後主が洛陽へ赴くにあたり、廖化や董厥が病と称して従わなかった中、尚書令である樊建は侍中張紹・光禄大夫譙周らとともに、最後まで君に随従した。具体的な治績を派手に語られることはなかったが、亡国の日まで主君を見捨てなかったその一貫した忠節こそ、樊建という文官の輪郭を成している。降った後、彼は侯爵を受けた。名を連ねるだけの場面が多い端役でありながら、諫言と随従の二点に、確かな筋の通った一人の実務官の姿がある。"}, {"id": 346, "name": "卞氏", "faction": 1, "role": "婦人", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 0], "p": [0, 1, 0, 0, 2, 2], "scores": {"W": 0.0, "B": 0.0, "S": 0.0, "A": 0.0, "G": 0.7, "K": 1.1}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.0}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [2, 3, 4, 78, 79, 85, 105, 107, 109, 111], "chapN": 19, "bio": "曹操の妾、四子を生み魏王妃となる", "profile": "曹操の妾から身を起こし、四子を生んで魏王妃に上った女性。曹丕・曹植らの母であり、後に王后・太后として遇された。演義における登場は数えるほどだが、その数少ない場面で、一人の母としての情愛を鮮烈に印象づける。\n\n政治や軍事の実権を、彼女が自ら振るう描写はない。曹操の薨去後、世継ぎを定めるにあたっても、「正に詔命を候つに及ばざるに因り、方に王后卞氏の慈旨を以て世子を立てて王と為さんと議す」と、その「慈旨」が曹丕の嗣位を裏づける名目として用いられるにとどまり、実際に漢帝の詔を取って事を運んだのは華歆らであった。卞氏は嗣位の正統性を支える器として機能したが、能動的にそれを主張する立場には立っていない。\n\n彼女の真の見せ場は、骨肉相残む悲劇の場にある。第79回、帝位に就いた曹丕が弟の曹植を七歩の詩で追い詰め、命を奪おうとした時、母卞氏は殿後から進み出て「兄、何ぞ弟を逼ること之れ甚だしきや」と長子を叱った。曹丕は慌てて座を離れ「国法廃すべからざるのみ」と答える。さらに卞氏は曹丕に泣いて訴える。「汝が弟植、平生酒を嗜み疏狂なるは、蓋し自ら胸中の才を恃むに因りてなり。汝、同胞の情を念い、其の性命を存せよ。吾れ九泉に至るも亦た瞑目せん」と。母の命に、曹丕は「母命違うべからず」と一旦これを容れた。\n\n恒久の継承体制を設計したわけでもなく、一族の権力を采配したわけでもない。卞氏が遺したのは、ただ一つ、わが子の命を救おうとする母の懇願であった。だがその一場面――兄弟が刃を向け合う冷たい宮廷に、ただ母性だけが緩衝として割って入ったあの瞬間は、権謀の渦巻く魏の物語の中で、温かく忘れがたい一筆として残っている。"}, {"id": 347, "name": "魏続", "faction": 1, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 0, 0, 1, 0, 2], "p": [0, 0, 1, 1, 0, 1], "scores": {"W": 0.65, "B": 1.05, "S": 0.45, "A": 0.45, "G": 0.45, "K": 0.55}, "stat": {"dmg": 0.55, "area": 0.81, "cd": 1.18, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 0.6}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [11, 16, 17, 18, 19, 25], "chapN": 6, "bio": "呂布の旧将、宋憲の仇討ちに出て顔良に斬られる", "profile": "呂布麾下の「八健将」の一人。第11回、呂布の陣に「両辺に排開する八員の健将」として、宋憲・侯成・郝萌・曹性・成廉らとともに名を連ねる武将である。とはいえ個人を称える武名は一切与えられず、常に宋憲とセットで動く副次的な存在であった。\n\n呂布の下では一軍の長として扱われる場面もある。第16回には呂布の命で山東へ赴き軍馬三百余匹を調達するが、その馬も掠奪で半数を失うという冴えない結末であった。同じ頃、呂布と袁術の縁談では、宋憲とともに呂布の娘を寿春へ送る護送役を務め、第17回では宋憲と一軍を率いて碣石に出て陳蘭に当たるなど、部隊指揮官らしき地位は名目上保っていた。\n\n魏続の名が物語に刻まれるのは、その忠ではなく、裏切りによってである。第19回、下邳が陥落寸前の危機に追い込まれると、彼は「丈夫に非ざるなり。呂布を擒えて曹公に献ずるに若かず」と保身の決断を口にし、宋憲・侯成と謀って動く。侯成が夜陰に乗じて赤兎馬を盗み出して東門へ駆けると、魏続が門を開いて放ち、佯って追う振りをした。こうして三人は主君呂布を縛り、曹操に献じて自らの活路を開いたのである。白門楼における呂布の最期は、この旧将たちの寝返りによってもたらされた。\n\n曹操に降って魏の武将に列したものの、活躍する間もなく、その末路はあっけなかった。第25回、宋憲が顔良に斬られると、魏続はその仇討ちに馬を進めて矛を持ち、陣前に出て顔良を罵る。だが顔良は言葉も交わさず、「交馬一合、頭を照らして一刀、魏続を馬下に劈く」――ただ一合で斬り落とされた。武勇の称号もなく、独力の戦果もなく、主君を売った手で得た新しい主のもとでも、引き立て役として瞬時に散る。呂布の凋落と関羽の武威、その双方を際立たせるために配された、八健将の一人の典型的な生涯である。"}, {"id": 348, "name": "劉琮", "faction": 3, "role": "君主", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 1], "p": [1, 0, 0, 0, 2, 1], "scores": {"W": 0.0, "B": 0.4, "S": 0.7, "A": 0.55, "G": 0.6, "K": 1.1}, "stat": {"dmg": 0.55, "area": 0.84, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.55}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [34, 40, 41, 42, 43, 118], "chapN": 6, "bio": "劉表の次子、曹操に降伏し青州への途上で于禁に殺される", "profile": "荊州牧・劉表の次子。父の死後、荊襄九郡を継いだものの、戦わずして曹操に降った少主である。通説では暗愚な君主として語られるが、本文の劉琮はむしろ「周囲に操られ、最後は処分された名目上の君主」という、哀れな傀儡の像に近い。\n\n劉表の死にあたり、母の蔡夫人・蔡瑁・蒯越ら一派は、長子の劉琦を退けて十四歳の劉琮を後継に立てた。劉琮自身は「頗る聡明」とされ、廢長立幼の不当さを誰よりも自覚していた。第40回、衆を集めて彼はこう問うている。「吾が父世を棄て、吾が兄は現に江夏に在り、更に叔父玄徳の新野に在る有り。汝等我を立てて主と為すに、倘し兄と叔父と兵を興して罪を問わば、如何に解釈せん」と。自らの正統性の脆さを、本人が問いただしていたのである。\n\n曹操の大軍が迫り、重臣たちが降伏を勧めると、劉琮は一度は叱って抵抗を見せた。「是れ何の言ぞや。孤、先君の基業を受け、坐すること尚お穏やかならざるに、豈に便ち之を他人に棄つべけんや」――先君の基業を簡単に手放せようか、と。だが決定権は彼にはなかった。荊州の兵権は「蔡氏の宗族、荊州の兵を分領す」と蔡氏が握り、劉琮は母と重臣に押し切られて、宋忠を使者に降書を曹操へ届けさせる。忠臣の王威が「将軍既に降り、玄徳又た走る、曹操必ず懈弛して備え無からん。願わくは奇兵を奮整し、険処に設けて之を撃たば、操獲べし」と起死回生の奇策を授けても、劉琮はこれを蔡瑁に告げて潰してしまう。自ら指揮することは、ついに一度もなかった。\n\n降伏の代償は、命であった。曹操に召されても「懼怕して敢えて往き見ず」と怯えるばかりの劉琮は、降った後に青州送りを命じられ、「再三推辭」して拒もうとするが容れられず、母子もろとも于禁に殺害される。基業を守ろうとする意識の片鱗を見せながら、実権なき少年として周囲に操られ、利用され尽くして処分された――荊州という大国が一兵も交えず曹操の手に落ちた、その静かな悲劇の中心に立たされた少主である。"}, {"id": 349, "name": "張顗", "faction": 1, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 0, 1, 0, 2], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 0.9, "B": 1.05, "S": 0.45, "A": 0.45, "G": 0.0, "K": 0.4}, "stat": {"dmg": 0.58, "area": 0.85, "cd": 1.18, "amount": 1, "knock": 0.67, "crit": 0.04, "duration": 0, "pwr": 0.9}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [32, 33, 41, 50], "chapN": 4, "bio": "袁紹旧将の降将、馬延と共に行動し甘寧に斬られる", "profile": "袁紹・袁尚配下の将。先鋒や斷後を任される雑兵格の武将で、常に馬延と組んで行動した。後に曹操へ降って列侯に封じられるが、終始「斬られ役・接応役」として描かれる、演義でも最弱級の一将である。\n\n袁氏の下では、第32回に袁尚が大軍を率いて先行する際、「馬延と張顗をして斷後せしむ」と殿軍を任されるなど、命じられるままに動く一兵卒的な将であった。袁氏が滅ぶと、彼は馬延とともに曹操に降る。第41回では「後面に趕う者は馬延・張顗、前面に阻む者は焦觸・張南、都て是れ袁紹手下の降将なり」と、降将の頭数の一人として名を連ねるにすぎない。三千の北地軍馬を率いて寨を構える程度の部隊長ではあったが、独力で軍を勝たせた記録は何一つない。\n\nその最期は、赤壁の敗走の中で訪れる。第50回、長江を逃れた曹操の敗軍に組み込まれていた張顗は、甘寧の軍と遭遇した。「張顗、槍を挺して来り迎う」と槍を構えて立ち向かうが、勝負にすらならなかった。「寧、大喝一声、顗、手を措くに及ばず、寧が手起こし一刀に被い、身を翻して馬に落つ」。甘寧の一喝に気圧され、手も足も出ぬまま、ただ一刀で斬り落とされて落馬したのである。一合も交えることなく散った。\n\n個人の武功も、軍の指揮も、政治の事績も、張顗の本文には一片も残らない。袁氏を見限って曹操に降り、その新しい主のもとでも見せ場なく斬られて終わる。甘寧の鋭さと赤壁の大勝を彩るために配された、無数の名もなき将の一人――その典型がこの張顗である。"}, {"id": 350, "name": "田楷", "faction": 3, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [0, 0, 0, 0, 1, 1, 2], "p": [0, 0, 0, 1, 0, 0], "scores": {"W": 0.0, "B": 1.1, "S": 1.05, "A": 0.95, "G": 0.15, "K": 0.4}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.21, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 0.0}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [11], "chapN": 1, "bio": "青州にあり陶謙を救援する公孫瓚配下の将", "profile": "公孫瓚配下にあって青州刺史の格を帯びた将。北方に勢力を張った公孫瓚陣営の一翼を担う州牧級の人物だが、演義の本文に姿を見せるのは第十一回のただ一度きりである。\n\n曹操が父の仇を名目に徐州へ大軍を差し向け、陶謙が窮地に陥ったとき、その救援の網が田楷のもとへも伸びる。陳元龍の報せに「欣然として兵を領いて来り救う」と、田楷は気持ちよく出陣を引き受けた。北海の孔融と犄角の勢を組み、雲長・子龍が両翼から接応するという布陣の一角に加わる。だが戦端を開く段になると、孔融と田楷の両軍は「曹兵の勢の猛きを懼怕し、遠遠として山に依りて寨を下し、未だ敢えて軽々しく進まず」と、山陰に陣を構えて様子をうかがうばかり。劉備の到来で局面が動いて曹操が退くと、田楷もまた「各々相別れ、軍を引きて自ら回る」と、来たときと同じように静かに引き揚げていった。\n\n自ら槍を振るって敵将を討った場面も、計を巡らせた台詞も、本文にはひとつも残っていない。陶謙の求めに「欣然」と応じた気のよさだけが、この将の人柄をかすかに伝える。\n\n救援に駆けつけながら、ついに大きく動くことのなかった脇役。それでも、群雄が雌雄を競い合った徐州攻防の一場面に、たしかに名を連ねた将である。"}, {"id": 351, "name": "胡班", "faction": 1, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [1, 1, 1, 1, 1, 1, 1], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.0, "S": 1.0, "A": 1.0, "G": 1.0, "K": 1.0}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 2.75, "pwr": 1.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [27, 73], "chapN": 2, "bio": "滎陽太守王植配下の従事、胡華の子で関羽を逃がす", "profile": "滎陽太守・王植の部下従事。胡華の子であり、関羽の千里行を語るうえで忘れられない、義に殉じた一人の文官である。\n\n第二十七回、関羽が劉備のもとへ戻ろうと五関を越えていく道中、滎陽の太守王植は表向き歓待を装いながら、深夜に館駅を四面から囲み、火を放って関羽を焼き殺す計を立てた。その実行役に選ばれたのが胡班である。彼は命を受け、軍士を点呼し、乾いた柴と引火の物を館駅の門前にひそかに積み上げ、合図とともに事を起こす手はずを整えた。ところが計を起こす前、燈下に書を読みふける関羽の姿を一目見て、胡班は思わず声を失い「真に天人なり」と歎じてしまう。さらに父・胡華の書状を得て、自分が殺そうとしていたのが恩ある忠良だと知り、「あやうく忠良を誤殺するところであった」と慄然とする。彼は関羽に王植の謀をひそかに告げ、「某まず行きて城門を開かん、将軍急ぎ収拾して城を出でよ」と、自ら城門を開いて関羽を逃がした。\n\nのち第七十三回、胡班は荊州へ来降して関羽に従い、入蜀の途につく。関羽もまた旧日に救われた情を念い、彼を深く愛したという。\n\n武勇を誇る描写も、軍を率いる場面もない。だが燈火のもとで一人の英傑の姿に胸を打たれ、主を裏切ってでも忠良を助けた——その義の一閃こそが、胡班という人物のすべてである。"}, {"id": 352, "name": "王忠", "faction": 1, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 1, 1, 1, 1, 1], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.0, "S": 1.0, "A": 1.0, "G": 1.0, "K": 1.0}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [22, 23], "chapN": 2, "bio": "曹操配下の将、劉岱と徐州を攻め関羽に生け捕られる", "profile": "曹操配下の将で、前後軍を率いる立場にあった。だが演義に描かれる王忠は、勇将というより、数合わせの疑兵役として遣わされた小物として記憶される。\n\n第二十二回、曹操は河北の動静をうかがう間の時間稼ぎに、前軍の劉岱と後軍の王忠に五万の兵を授け、丞相の旗号を高々と掲げさせて徐州の劉備を攻めさせた。しかしこの軍は「中軍に虚しく曹丞相の旗号を打ち、未だ敢えて進兵せず、ただ河北の消息を打聴するのみ」という張りぼての威勢にすぎない。先陣を誰が務めるかさえ、劉岱と王忠は「拈鬮（くじ引き）」で押し付け合う始末だった。やがて関羽が出てくると、王忠は槍を挺して迎えるが、両馬が交わるや関羽はわざと馬を撥して逃げる。追いかけて山坡を回ったところで関羽が馬を返し、大喝一声して刀を振るうと、王忠は防ぎきれない。関羽は左手で寶刀を逆さに提げたまま、右手で王忠の勒甲をむんずと掴み、鞍から引き摺り下ろして馬上に横抱きにし、悠々と本陣へ戻った。主将を失った王忠の軍は四散して逃げ走った。続く張飛の前でも王忠は劉岱ともども馬上に震え上がり、命乞いをして頭を抱えて逃げ惑う。\n\n第二十三回、許都へ送られた王忠は曹操に「犬豕いずくんぞ虎と鬥うに堪えん」と嘲られ、死は免じられたものの爵禄を剥奪された。\n\n槍を構えはしても一合も持たず、片手一本で生け捕られた将。三国志屈指の名場面の引き立て役として、その名はかえって人々の記憶に残った。"}, {"id": 353, "name": "朱讚", "faction": 1, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 1, 1, 1], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.0, "S": 1.0, "A": 1.0, "G": 1.0, "K": 1.0}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [93, 94], "chapN": 2, "bio": "盪寇将軍・副先鋒、趙雲に刺殺される", "profile": "魏の盪寇将軍。曹真が率いる二十万の蜀征伐軍にあって、副先鋒という肩書きを帯びた将である。\n\n第九十三回、曹真は宗弟の曹遵を先鋒に、盪寇将軍の朱讚を副先鋒に任じ、それぞれ一万の兵を率いて祁山の背後へ抄り出るよう命じた。これに郭淮の劫寨計が重なる——夜陰に乗じて蜀の陣を襲おうというのである。だが曹遵が先に斬り込んだ寨は人影ひとつない空寨で、孔明の罠と知って慌てて軍を返したところに火の手が上がった。そこへ朱讚の兵が到着し、暗がりの中で味方の曹遵軍と「自ら相掩殺し」、人馬は大いに乱れ、互いに踏み合う同士討ちの大混乱に陥る。魏将の死者ははなはだ多かった。\n\n第九十四回、敗走する蜀軍を追って朱讚が兵を引いて追撃したそのとき、不意に一彪の軍が現れる。先頭に立つ大将は趙雲であった。朱讚は手の施しようもなく、趙雲の一槍に貫かれて討ち死にする。\n\n戦果らしい戦果をひとつも挙げぬまま、味方を巻き込む失態の末に、老いてなお衰えぬ趙雲の槍に倒れた副先鋒。先鋒は武勇の士という期待に、ついに応えることのなかった将である。"}, {"id": 354, "name": "曹遵", "faction": 1, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 1, 1, 1], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 1.0, "B": 1.0, "S": 1.0, "A": 1.0, "G": 0.0, "K": 0.2}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [93, 94], "chapN": 2, "bio": "曹真の宗弟・先鋒、魏延に斬られる", "profile": "魏の曹真の宗弟。一族の縁につらなる血筋ゆえに先鋒へ抜擢された将である。\n\n第九十三回、蜀征伐に臨んだ曹真は、宗弟の曹遵を先鋒に、盪寇将軍の朱讚を副先鋒に据え、祁山の背後を衝かせようとした。そこに郭淮が劫寨の計を進言する。曹遵は意気込んで蜀の陣へ斬り込むが、そこは人っ子一人いない空寨であった。「料らずも計に中れり」と気づいて急ぎ軍を返したとき、すでに寨中に火が起こっていた。続いて到着した朱讚の軍とは暗闇で互いを敵と見誤り、「交馬して方めて自相踐踏なるを知る」——味方同士が斬り合い踏み合う惨状を招く。曹遵はこの一夜のしくじりを「郭都督真に神機妙算なり」と、罠を仕掛けられた側でありながら他人事のように嘆じるばかりだった。\n\n第九十四回、敗走する軍を率いて退くさなか、追ってきた魏延と鉢合わせる。曹遵は大いに驚いて馬を進め鋒を交えるが、「三合と持たず、魏延の一刀に馬下に斬らる」——あっけなく討ち取られて落命した。\n\n名門の縁故で先鋒の重職を得ながら、一合の戦果も挙げられず即座に斬られた将。語るべき個性すら描かれぬまま、戦場に消えた端役である。"}, {"id": 355, "name": "蔡和", "faction": 1, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 1, 1, 1], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.0, "S": 1.0, "A": 1.0, "G": 1.0, "K": 1.0}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [34, 46, 47, 49], "chapN": 4, "bio": "蔡瑁の族弟、詐降の内応者、祭旗の犠牲として斬られる", "profile": "荊州の実力者・蔡瑁の族弟。赤壁の戦いにおいて、曹操の放った詐降の間者として東呉に潜り込み、最後は祭旗の生贄として斬られた、薄幸の偽降将である。\n\n初登場の第三十四回では、荊州の東門・峴山の大路を守る一武将として、蔡瑁の口から「すでに吾が弟蔡和をして軍を引いて守り把らしむ」と紹介される。赤壁が近づく第四十六回、荀攸の発案により、蔡和は兄弟の蔡中とともに曹操に密かに召し出される。蔡瑁が殺されたのを恨み、その仇を報じるため投降してきた——そう涙ながらに装い、「某二人必ず周瑜・諸葛亮の首を取りて、麾下に献ぜん」と豪語して東呉に身を投じた。だがこの偽降は、魯粛にはじめから「多くは応に是れ詐ならん」と見抜かれ、周瑜と諸葛亮は逆にこれを利用する。重く賞されて甘寧の軍の前部に組み込まれた二人は、自分たちが計に当てたのだと得意になっていたが、実は将計就計に踊らされていたのである。\n\n第四十九回、いよいよ火攻の出陣という段に至り、周瑜は蔡和を江辺の皂纛旗の下に捕え引き出させる。「無罪」と叫ぶ蔡和に、周瑜は「汝は何等の人ぞ、敢えて来りて詐降す」と一喝し、「今、福物の旗を祭るに欠く、願わくは汝の首級を借りん」と告げた。観念した蔡和は「汝が家の闞澤・甘寧も、亦かつて与に謀れり」と仲間の名を叫んで道連れにしようとするが、もはや及ばない。一刀のもとに斬られ、その血が出陣の旗を祭った。\n\n利用され、見抜かれ、捨てられる——詐降役という損な役回りを最後まで全うした蔡和の最期は、赤壁の劫火を彩る一場の悲喜劇として、物語に刻まれている。"}, {"id": 356, "name": "賈華", "faction": 2, "role": "武将", "rarity": 1, "weapon": "summon", "kind": "summon", "weaponName": "伏兵", "d": [1, 1, 1, 1, 1, 1, 1], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.0, "S": 1.0, "A": 1.0, "G": 1.0, "K": 1.0}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 6.4, "pwr": 1.0}, "title": "伏兵の将", "skill": "伏兵", "skillDesc": "自律で戦う兵を率いる", "voice": "", "hist": "", "chapters": [53, 54], "chapN": 2, "bio": "孫権の護衛将。甘露寺で刀斧手を伏せる役", "profile": "孫権に近侍する呉の親衛・伏兵指揮役。君主の身辺を守る役どころで二度、物語に顔を出す。\n\n第五十三回、孫権が金の兜・金の鎧に身を固めて出馬したとき、その左には宋謙、右には賈華が立ち、二人は方天画戟を構えて両脇から主君を護衛した。だが曹操軍の楽進が一刀のもとに斬りかかると、宋謙・賈華は急いで画戟をかざして遮ろうとするものの、刀の届いたところで「両枝の戟斉しく断たれ」、二人は折れた戟の柄で辛うじて敵の馬の頭を打つほかなかった。重い得物を二人がかりで構えながら、主君を守りきれなかった一幕である。\n\n第五十四回、舞台は甘露寺へ移る。劉備を孫夫人に娶らせると見せかけて亡き者にしようという計のなか、呂範が「賈華をして三百の刀斧手を部領せしめ、両廊に伏せしめては」と進言し、賈華は孫権から「先ず準備せよ、ただ国太の挙動を看よ」と命じられて伏兵を整えた。ところがこの企みは趙雲に露見し、呉国太の知るところとなる。激怒した国太が責を問うと、呂範は賈華に押しつけ、国太に厳しく罵られても賈華は「黙然として言無し」とうつむくばかり。やがて国太は彼を斬れと喝するが、劉備が「もし大将を斬らば、親に利あらず」と取りなしたことで、賈華はかろうじて命を拾い、刀斧手ともども頭を抱えて逃げ散った。\n\n自ら計を立てた形跡はなく、命じられて伏兵を構えては露見し、責められても言葉ひとつ返せなかった将。孫権と劉備をめぐる縁談劇の陰で、損な役回りを黙々と背負った脇役である。"}, {"id": 357, "name": "范疆", "faction": 0, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 1, 1, 1, 1], "p": [1, 1, 1, 1, 1, 1], "scores": {"W": 1.0, "B": 1.0, "S": 1.0, "A": 1.0, "G": 1.0, "K": 1.0}, "stat": {"dmg": 0.59, "area": 0.87, "cd": 1.19, "amount": 1, "knock": 0.72, "crit": 0.05, "duration": 0, "pwr": 1.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [81, 83], "chapN": 2, "bio": "張飛の末将。鞭打ちを恨み張達と共に張飛を殺し呉へ逃げる。後に処刑", "profile": "張飛麾下の帳下にあった末将。私怨から主君を弑し、ついには張飛の子の手で凄惨な最期を遂げた、裏切りの賊として物語に刻まれる。\n\n第八十一回、関羽の仇を討たんと逸る張飛は、三日のうちに白旗・白甲を調えて全軍に喪に服させよと厳命する。だが范疆と張達は「須らく寛限あって方めて可なり」と猶予を乞うたため、激怒した張飛に縛りつけられ、樹に吊るして背を各々五十鞭——「打ちて二人満口に血を出だす」ほど打ち据えられた。この恨みから二人は主君殺害を謀る。「我ら両個もし死に当たらずんば、則ち他は床上に酔わん。若し是れ死に当たらば、則ち他は酔わず」と運を天に任せ、機密を稟すと偽って深夜に張飛の帳へ忍び入った。寝姿の張飛は鬚を逆立て目を見開いて眠っており、二人はその形相に怯えて手が出せなかったが、雷のような鼾を聞いてようやく近づき、短刀を腹に突き立てて刺殺した。そして張飛の首級を斬り取り、数十人を引き連れて夜陰に乗じ東呉へ亡命した。\n\n第八十三回、孫権が蜀との和睦を図るなか、范疆と張達は張飛の首級ともども縛り上げられ、沈香木の匣に首を納めて檻車に乗せられ、贈り物のごとく蜀へ送り返される。待っていたのは張飛の子・張苞であった。張苞は自ら利刀をとり、范疆・張達を「萬剮凌遅」——なます斬りにして、父の霊前に祭った。\n\n武人としての戦功はひとつもなく、唯一の「行動」が酔って眠る主君の暗殺であった男。怨恨に駆られて引いた短刀が、結局おのれをも引き裂いたのである。"}, {"id": 358, "name": "傅士仁", "faction": 0, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 1, 0, 1, 1, 1, 1], "p": [0, 0, 1, 1, 0, 1], "scores": {"W": 0.75, "B": 1.0, "S": 1.0, "A": 1.0, "G": 0.45, "K": 0.35}, "stat": {"dmg": 0.56, "area": 0.83, "cd": 1.19, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 0, "pwr": 0.7}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [73, 75, 76, 81, 83], "chapN": 5, "bio": "公安を守るが東呉に降り、糜芳も誘って投降させる", "profile": "公安を守る蜀の将。関羽に仕えながら、失火・降伏・寝返り・再びの寝返りという背信を重ね、最後は劉備の手で極刑に処された、荊州喪失の引き金を引いた一人である。\n\n第七十三回、関羽は樊城へ兵を進めるにあたり、傅士仁と糜芳を先鋒に任じた。ところが出師を前にして、傅士仁と糜芳は酒を飲み、その帳から火を遺して火砲に燃え移らせ、軍器糧草をことごとく焼き尽くす大失態を犯す。関羽は激怒し、二人の先鋒の印綬を取り上げ、杖四十を加えたうえ、糜芳に南郡を、傅士仁に公安を守らせた。やがて荊州が呂蒙に衝かれて陥落すると、傅士仁は呉の虞翻に説かれるや、ためらいなく「即ち虞翻と同に印綬を齎して荊州に来り投降」してしまう。さらに兵糧を求めにきた関羽の使者を堂上で剣を抜いて斬り捨て、その足で南郡の糜芳をも口説き落として降らせた。「吾は忠ならざるに非ず、勢危く力困しみて、支持する能わざるなり」——それが彼の弁であった。\n\n第八十一回、関羽の死を悼む劉備は、傅士仁・糜芳・潘璋・馬忠を切歯の讎人として名指しし、誅滅の対象に挙げる。追い詰められた傅士仁は、夷陵の陣で馬忠を殺し、その首を手土産に蜀へ再び降ろうと図った。一度は「行かば必ず禍あらん」と危うさを正しく見抜きながら、結局その企てに加担し、捕えられて劉備の前に引き出され、剮刑に処されて果てた。\n\n白兵の戦功も武名もなく、ただ失火から始まる裏切りの連鎖だけで彩られた生涯。守るべき荊州を戦わずして明け渡したこの将の名は、蜀漢の運命を暗転させた汚点として語り継がれている。"}, {"id": 359, "name": "糜夫人", "faction": 0, "role": "婦人", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 0, 0], "p": [0, 0, 0, 0, 2, 3], "scores": {"W": 0.1, "B": 0.05, "S": 0.05, "A": 0.1, "G": 0.62, "K": 1.05}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.1}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [22, 25, 28, 41, 42, 85], "chapN": 6, "bio": "劉備の夫人、阿斗を趙雲に託し枯井に身を投げて死ぬ", "profile": "劉備の夫人にして、麋竺の妹（第二十二回「糜夫人は乃ち糜竺の妹なり」）。長坂坡で幼い阿斗を趙雲に託し、自らは枯井に身を投じて散った烈女として、永く語り継がれる女性である。\n\n第二十五回・第二十八回では、徐州離散ののち甘夫人とともに曹操方に身を置き、やがて関羽に守られて劉備のもとへ戻る——その道中で身内と情誼を交わす、静かな婦人として描かれる。彼女の名を不滅にしたのは、第四十一回の長坂坡である。曹操の大軍に追われ民もろとも潰走する混乱のさなか、糜夫人は左の腿に槍を受けて「行走すること得ず」、もはや動けぬ身となっていた。そこへ単騎で乱軍を割って駆けつけたのが趙雲であった。糜夫人は阿斗を趙雲に手渡し、「此の子の性命は全く将軍の身上に在り」と託す。そして将軍が自分を庇えば子も自分も助からぬと悟るや、わが子を地に置き、身を翻して枯井に投じ、自ら命を絶った。趙雲はその井戸を土塀で覆って亡骸を隠し、阿斗を懐に抱いて血路を開く。この自己犠牲を、後人は「勇決還虧女丈夫（勇決なること還って女丈夫に虧くるなし）」と賛詩に詠んだ。\n\n第四十二回でその死は語り継がれ、月日を経た第八十五回、彼女は「糜夫人も亦た追諡して皇后と為す」と、甘夫人とともに皇后に追諡された。\n\n戦うことも政を執ることもなかった一人の婦人。だが、跡継ぎの一命を救うために自らの命を投げ出したその一瞬の決断が、蜀漢の未来を繋ぎ、彼女を「女丈夫」として三国志の物語に永遠に刻みつけたのである。"}, {"id": 360, "name": "曹芳", "faction": 1, "role": "君主", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 1], "p": [0, 0, 0, 0, 2, 1], "scores": {"W": 0.0, "B": 0.25, "S": 0.1, "A": 0.05, "G": 0.38, "K": 0.95}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.1}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [106, 107, 108, 109, 114], "chapN": 5, "bio": "曹叡の養子、魏帝・後に司馬師に廃される", "profile": "曹叡（明帝）の養子として迎えられ、わずか八歳で魏の帝位に即いた人物である。父帝の遺命により、曹爽と司馬懿の二人が幼帝を「扶」けるかたちで政が始まるが、幼くして社稷を掌るには至らず、その治世は終始、誰かに動かされる客体として描かれていく。\n\n即位後ほどなく、曹爽の上奏に従って司馬懿を太傅へと祭り上げる。表向きは栄誉だが、その実は実権の剥奪であり、本文は「芳これに從ふ。これより兵權みな爽に歸す」（第106回）と記す。やがて高平陵の変を経て今度は司馬氏が権を握ると、曹芳の立場はさらに細る。司馬師が朝に入るたびに帝は震えが止まらず、「魏主曹芳、師の入朝するを見るごとに、戰慄して已まず、針の背を刺すがごとし」（第109回）と、針で背を刺されるような恐怖に身を縮める。ついには夏侯玄・李豐・張緝の献策に乗り、龍鳳の汗衫を脱いで指先を咬み破り、血で詔を書いて司馬師討伐を図る。だが「機事密ならず」――董承の衣帯詔と同じ轍を踏み――密室の涙すら見破られて謀は潰え、三人の忠臣は腰斬・三族滅、皇后は絞殺される。\n\n血詔の故事になぞらえて自ら「朕が祖武皇帝、董承を誅せしは、けだし機事の密ならざるがためなり」と語る場面に、この帝の悲哀が凝縮される。漢の献帝がそうであったように、抵抗を試みる能動性だけはありながら、それを支える力も人もない。武器を取る場面は生涯一文も無く、震える身体だけが繰り返し描かれる。\n\n最期は司馬師に責められ、璽綬を返上して齊王へと格下げされる。「璽綬を納め、齊王の爵に復し、目下程を起こせ」と命じられ、太后に泣いて拝し、国宝を納め、王車に乗って大いに哭しながら去っていく。見送るのは「ただ數員の忠義の臣、淚を含んで送る」のみ。傀儡皇帝の典型として、その退場はかえって、力なき者が玉座に据えられることの残酷さを後世に伝えている。"}, {"id": 361, "name": "張英", "faction": 3, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [1, 2, 0, 0, 1, 0, 1], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 0.85, "B": 0.8, "S": 0.35, "A": 0.4, "G": 0.0, "K": 0.2}, "stat": {"dmg": 0.57, "area": 0.82, "cd": 1.19, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 0.75}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [15], "chapN": 1, "bio": "劉繇の部将、牛渚を守り陳武に刺殺される", "profile": "劉繇配下の部将で、揚州の要衝・牛渚を任された将である。第15回、孫策が江東へ進出してくると、牛渚に屯して糧十萬を邸閣に積み、ここを固めれば百萬の兵も近づけぬと豪語する自信家として登場する。一度は「驍將」（勇猛な将）と形容され、いかにも一軍を預かる気概を見せる。\n\nところが実態は、その豪語に届かない。孫策軍を牛渚灘上に迎え撃ち、黄蓋と数合も渡り合わぬうちに、味方の寨から火の手が上がる。「たちまち張英の軍中大いに亂れ、寨中に人ありて火を放つと報ず」――放火ひとつで全軍が崩れ立ち、為す術なく牛渚を棄て、深山を望んで単身逃げ落ちる。蓄えた糧も拠点も、戦わぬうちに失われた。\n\n後日、薛禮らとともに孫策死すの誤報に乗じて城を出、追撃に加わるも、これも罠であった。孫策はなお生きており、逆に追い詰められて部下は「みな驚き、ことごとく鎗刀を棄てて地下に拝す」と即座に降伏。張英自身は馬を返して逃げかけたところを、陳武に一鎗で刺し殺される。豪語と実態の落差だけを特徴として、噛ませ役の敗将らしく退場した一将である。"}, {"id": 362, "name": "金旋", "faction": 3, "role": "君主", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [1, 1, 1, 0, 0, 0, 1], "p": [0, 0, 0, 0, 1, 0], "scores": {"W": 0.9, "B": 0.35, "S": 0.1, "A": 0.05, "G": 0.13, "K": 0.5}, "stat": {"dmg": 0.58, "area": 0.85, "cd": 1.2, "amount": 1, "knock": 0.67, "crit": 0.04, "duration": 0, "pwr": 0.9}, "title": "君主", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [52, 53], "chapN": 2, "bio": "武陵太守。張飛に敗れ鞏志に城を閉ざされ討たれる", "profile": "荊南四郡のひとつ、武陵を治める太守である。第52回から第53回にかけて、赤壁後に荊州南部を平定してゆく劉備軍の前に立ちはだかる地方領主の一人として登場する。「太守」という肩書きこそ立派だが、本文が描く実態は、それに伴う統治も武勇も知略もほとんど見えない短命の敗北君主である。\n\n劉備が張飛を遣わして武陵に迫ると、従事の鞏志が的確に諫める。「劉玄德はすなはち大漢の皇叔、仁義は天下に布く。加ふるに張翼德は驍勇非常なり。敵を迎ふべからず、降を納るるに如かず」――勝ち目はない、降伏が上策だ、と。だが金旋はこれを「汝、賊と通連して内変を取らんと欲するか」と決めつけ、武士に命じて斬らせようとする。衆官が「先に家人を斬らば軍に利あらず」と止めてようやく思い止まるが、人心はすでに離れていた。\n\n部将に「誰か敢へて出戰せん」と問えば、皆畏懼して前に出る者なく、やむなく自ら馬を驅って刀を舞わせ出陣する。だが二十里で張飛と正面から遭遇し、その「大喝一聲、渾如巨雷」の一喝を浴びるや、金旋は失色し、剣も交えず「不敢交鋒」のまま馬を返して逃げ出す。\n\nその逃げ帰る城門は、もはや開かなかった。城上から鞏志が「汝、天時に順はず、自ら敗亡を取る。吾、百姓とともに自ら劉に降らん」と告げ、放った矢が顔面を貫いて、金旋は即死する。諫言を退け、降伏の道を自ら潰し、配下に背かれて討たれる――その最期は、肩書きだけの領主がいかに脆く崩れるかを示す一幕として置かれている。"}, {"id": 363, "name": "許褚張遼以外の幕賓蔣幹", "faction": 1, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 1], "p": [0, 1, 0, 2, 0, 0], "scores": {"W": 0.0, "B": 0.85, "S": 0.95, "A": 0.9, "G": 0.5, "K": 0.4}, "stat": {"dmg": 0.58, "area": 0.87, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.9}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [45, 46, 47, 57], "chapN": 4, "bio": "曹操の幕賓、周瑜の旧友。反間の計と連環の計に二度はまる", "profile": "曹操の幕下に侍る幕賓であり、九江の人、姓は蔣、名は幹、字は子翼。周瑜とは若き日に同じ窓辺で学んだ旧友であった。赤壁前夜、その旧縁を売り込んで二度も江東への使者を志願する自信家だが、演義は彼を、周瑜の計を成立させるための道具として徹底的に描いていく。\n\n第45回、群英會。蔣幹は「某、幼きより周郎と同窗の交契あり。願はくは三寸不爛の舌を憑んで、江東に往きてこの人を説いて降らしめん」と申し出て、小舟一隻に渡る。だが周瑜は会うなり「絃歌を聞いて雅意を知る」と見抜き、「子翼、良に苦しむ。遠く江湖を涉り、曹氏のために説客となるか」と先手を打って封じる。降伏交渉の一言も切り出せぬまま、酔ったふりの周瑜の枕元から偽の書状を盗み見て持ち帰り、その偽書を信じた曹操が、自らの手で水軍都督・蔡瑁と張允を「武士を喝して推し出だし斬らしむ」結果を招いてしまう。\n\n懲りずに第47回、「前日空しく東吳に往き、未だ成功を得ず、深く慚愧を懷く。今、身を捨てて再び往かん」と再度志願する。今度は連れ帰ったのが、隠者を装う龐統であった。「公の才を以て、何くに往くとして利あらざらん。もし曹に歸するを肯んぜば、幹まさに引進すべし」と紹介したその人物こそ、連環の計を授ける敵の間者。蔣幹はまたしても、敵の戦略を完成させる役回りを引き受けてしまう。\n\n唯一の本分であるはずの弁舌は、演義の中で一度も冴えを見せず、ことごとく空回りする。後に周瑜の祭文の中に「君を弔ふ、鄱陽の蔣幹來りて説く」と名が刻まれるあたり、この人物の存在意義が「周瑜に弄ばれた説客」に尽きることを、物語自身が証している。"}, {"id": 364, "name": "禰衡", "faction": 3, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 0, 0], "p": [0, 0, 0, 2, 3, 0], "scores": {"W": 0.1, "B": 0.05, "S": 0.05, "A": 0.1, "G": 0.69, "K": 0.9}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.1}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [23, 40, 60], "chapN": 3, "bio": "孔融の友（言及）、曹操を辱めた狂士", "profile": "孔融が「己に十倍する才あり」と推した、後漢末の名士にして狂士である。だが演義の禰衡は、終始「言葉だけの人物」として立ち現れる。実務や軍事、統治の事績はなく、その武器はただ舌――それも建設的な弁ではなく、痛烈な罵倒であった。\n\n第23回、曹操に召されると、禰衡は曹操陣営の名臣猛将を一人ずつ「衣架！飯囊！酒桶！肉袋耳！」と切って捨て、衣装掛け・飯袋・酒樽・肉袋にすぎぬと罵り尽くす。傍らの張遼が怒って剣を抜こうとするが、それすら畏怖ではなく純然たる憤りであった。辱められた曹操は彼を鼓吏に落として恥をかかせようとするが、禰衡は逆に衆人環視の中で衣を脱ぎ、「裸體にして立ち、渾身ことごとく露はる」――裸のまま漁陽の三撾を打ち鳴らし、その挑発で場を制してしまう。\n\n曹操は手を汚さぬよう、彼を荊州への使者に立てる。「汝をして荊州に往きて使たらしむ。もし劉表來り降らば、便ち汝を用ひて公卿となさん」と。だが禰衡は劉表のもとでも、頌徳と見せて実は譏諷し、表を不快にさせて追われるばかり。同盟をまとめるどころか、行く先々で人を敵に回し続ける。自らは「漢朝の臣たり、曹瞞の黨と作らず」と漢室の臣を貫く気概を一貫させるが、その正統の志も政権を担う立場には結びつかず、個人の気概に留まる。\n\n劉表はさらに彼を江夏の黄祖へと送る。そこでも禰衡は口を慎まず、黄祖を罵り、「死に至るまで罵りて口に絶えず」――最後まで悪態をやめぬまま斬られた。曹操が彼を評して「腐儒の舌劍、反って自ら殺すなり」と言ったとおり、舌を剣として振るい、その剣で己の身を貫いた狂士であった。"}, {"id": 365, "name": "楊松", "faction": 3, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 0], "p": [0, 0, 0, 1, 0, 1], "scores": {"W": 0.0, "B": 0.6, "S": 0.85, "A": 0.85, "G": 0.27, "K": 0.15}, "stat": {"dmg": 0.57, "area": 0.87, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.8}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [64, 65, 67], "chapN": 3, "bio": "張魯配下の貪欲な謀士。馬超・龐徳を讒言し主を売り処刑される", "profile": "漢中に拠る張魯配下の謀士である。だがその名が演義に刻まれた所以は知略ではなく、金銀に動かされて賢者を妨げ、ついには主君を売った「貪賄・賣主の奸臣」としての悪名にある。物語は彼を、裏切りの見せしめとして配置している。\n\n第64回、劉璋の使者・黄権が漢中を訪れると、楊松はまず賄賂で取り込まれ、「東西の兩川、實に脣齒たり。西川もし破れなば、東川もまた保ち難し」という救援の弁を張魯に取り次ぐ。だがそれは大局を見据えた進言ではなく、二十州を約された利目当ての追従であり、張魯も「その利を喜び、これに從ふ」。\n\n馬超が張魯のもとへ身を寄せると、楊松の本領たる讒言が動き出す。第65回、彼は張衛に命じて関隘を固めさせ、勇将・馬超を進退きわまる窮地へと追い込み、内側から味方を孤立させてゆく。せっかく得た猛将・龐徳までも疑いの目で見させ、有能な者を次々と排除していく。賢を妨げ、人材を腐らせるその働きだけが、彼の唯一際立つ「能力」であった。\n\nそして第67回、曹操が漢中に迫ると、楊松はついに自国を売る。曹操に密書を送って進兵を促し、自らは内応となる。だが裏切りの末に待っていたのは栄達ではなかった。漢中を平定した曹操は「楊松、主を賣りて榮を求む」として、即座にこれを市曹に斬って衆に示した。主を売った者が真っ先に誅される――その結末は、忠を捨てた者の行き着く先を、冷ややかに描き出している。"}, {"id": 366, "name": "崔州平", "faction": 3, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 1, 0], "p": [1, 0, 0, 0, 1, 0], "scores": {"W": 0.0, "B": 0.6, "S": 0.85, "A": 0.85, "G": 0.35, "K": 0.45}, "stat": {"dmg": 0.57, "area": 0.87, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.8}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [37, 113], "chapN": 2, "bio": "博陵の隠士、孔明の友、劉備と林間で問答", "profile": "博陵の隠士。諸葛孔明と親交を結んだ賢人の一人として知られるが、演義の本文では、ただ一度、劉備と林間の石上で問答を交わすのみの清談者として現れる。功名に背を向け、天命の理を静かに語る人物である。\n\n第37回、孔明を訪ねて隆中をさまよう劉備は、容貌軒昂、丰姿俊爽、頭に逍遙巾を戴き、皂布の袍を身にまとい、藜の杖をつく一人の隠者に出会う。これが崔州平であった。劉備が漢室を匡扶せんとする志を述べると、州平は「古より以來、治亂は常無し」と歴史の循環を説き、「順天者は逸し、逆天者は勞す」と天の理を諭す。今はまさに治より亂に入る時であり、「未だ猝かには定むべからず」――人の力で天地を斡旋し乾坤を補綴しようとしても、徒らに心力を費やすばかりだと、孔明の出廬の前途にすら静かな影を落とす。\n\nその識見は確かでありながら、彼は決して天下事の渦中に身を投じない。「山野の夫、ともに天下の事を論ずるに足らず。たまたま明問を承く、故に妄りにこれを言ふのみ」と自らを引き、「愚性、頗る閒散を樂しみ、功名に意無きこと久し」と仕官を退ける。せっかちな張飛には「腐儒と閒談すること許久」と煙たがられる始末で、その風采は終始、世を一歩離れたところに立っている。\n\n後に第113回、司馬望が蜀の長蛇捲地の陣を破る場面で、その陣法の素養を「かつて崔州平・石廣元と友たり、この陣を講論す」と回想する。陣を布いたのは司馬望であって州平ではないが、かつて友とともに兵法を談じた清雅な知の交わりが、ここに名残をとどめる。戦も統治も担わず、ただ天命を観じて去った隠者として、その姿は孔明という巨星の傍らに、ひとすじの静かな対比を残している。"}, {"id": 367, "name": "崔諒", "faction": 1, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 0, 1], "p": [0, 0, 1, 1, 1, 0], "scores": {"W": 0.0, "B": 0.7, "S": 0.35, "A": 0.4, "G": 0.46, "K": 0.5}, "stat": {"dmg": 0.54, "area": 0.83, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.45}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [92], "chapN": 1, "bio": "安定太守、孔明に降るも偽計で張苞に刺殺される", "profile": "魏の安定太守。第92回、諸葛亮の第一次北伐の冒頭で、孔明が安定・南安・天水の三城を智略で奪う「智取三城」の引立て役として登場する。一郡を預かる太守だが、物語の中では終始、智者に弄ばれて自滅する小太守として描かれる。\n\n蜀兵が南安を囲み、夏侯楙を困らせていると聞いた崔諒は、十分に慌懼しつつも、軍馬およそ四千を点呼して城を固める。そこへ偽の魏将・裴緒が急報を携えて現れ、救援を促す。崔諒はその偽書を「略ぼ一視」しただけで信じ込み、文官に城を任せて自ら出陣する。だが二十里も行かぬうちに関興・張苞の挟撃を受け、兵は四方に逃げ散り、手下百余人とともに小路を死戦してかろうじて安定へ奔り帰る。だが城はすでに魏延の手に落ちていた。\n\n退路を断たれた崔諒は、四面みな蜀兵なるを見て「不得已ついに降る」。だがここで一度だけ、知略を見せようと試みる。隣郡の南安太守・楊陵とは「交契甚だ厚し」という旧誼があり、楊陵が「我等、魏主の大恩を受く、いづくんぞ忍びてこれに背かんや。将計就計して行ふべし」と唱えると、崔諒もこれに同調する。関興・張苞を城内に誘い込んで斬り、火を挙げて合図とし、孔明をおびき寄せて討とう――そう企んだのである。\n\nしかしその逆計は、孔明の掌の上にあった。「吾、來情を見て、足くその詐を知る」と早々に看破され、城内では楊陵が関興に斬られ、崔諒自身は張苞の「賊子よ走るな。汝等が詭計、いかでか丞相を瞞き得んや」の一喝とともに、一鎗で馬下に刺し殺される。偽報を見破れず、城を奪われ、唯一の見せ場すら完全に上回られて即死した――北伐の幕開けを彩る、孔明の智の引き立て役であった。"}, {"id": 368, "name": "尹賞", "faction": 1, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 0, 1], "p": [0, 0, 2, 0, 0, 2], "scores": {"W": 0.0, "B": 0.7, "S": 0.35, "A": 0.4, "G": 0.6, "K": 0.5}, "stat": {"dmg": 0.54, "area": 0.83, "cd": 1.23, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.45}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [92, 93], "chapN": 2, "bio": "天水主簿、梁緒とともに降り冀城令となる", "profile": "魏の天水郡に仕える主簿。馬遵配下の純然たる文官で、自ら戦う描写はなく、第92回から第93回にかけて、姜維帰順という大筋の脇で天水陥落の鍵を握る端役として登場する。\n\n第92回、蜀兵が南安を囲み夏侯楙を困らせていると聞くと、尹賞は功曹の梁緒、主記の梁虔らと連名で太守・馬遵に進言する。「夏侯駙馬はすなはち金枝玉葉、もし疏虞あらば、坐視の罪を逃れ難し。太守、何ぞ本部の兵を盡く起こしてこれを救はざる」と。だがこの救援こそ孔明の計の入り口であり、天水郡はここから綻び始める。\n\n第93回、姜維が孔明に降ったかに見せかける離間の謀が巡らされ、馬遵と夏侯楙は梁緒・尹賞らを疑って「この二人を殺すべし」と動き出す。命を狙われていることを察した尹賞は、即座に梁緒に持ちかける。「城を納れて蜀に降り、もって進用を図るに如かず」と。保身と立身を秤にかけ、先手を打って主君を見限ったのである。事ここに至れりと覚った二人は、披挂して馬に上り、各々兵器を執って本部の軍を率い、城門を大きく開いて蜀兵を引き入れた。\n\nこうして天水郡は内側から瓦解した。降った尹賞は孔明に冀城令を与えられ、その身を全うする。主簿として民政の実務に在った官人が、危機を察するや迷わず城門を開いて寝返る――その身の処し方は、乱世の地方官が生き残るために選んだ現実の一つの姿として、淡々と描かれている。"}, {"id": 369, "name": "李豊", "faction": 0, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 1], "p": [0, 0, 2, 2, 0, 0], "scores": {"W": 0.0, "B": 0.25, "S": 0.1, "A": 0.05, "G": 0.66, "K": 0.2}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.1}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [17, 94, 101, 109, 110], "chapN": 5, "bio": "袁術の将、呂布に手を刺され壽春で斬られる", "profile": "蜀漢の重臣・李嚴の子で、後方の行政を担う文官である。武勇や指揮、献策の見せ場はなく、伝令と兵站を職掌とする脇役だが、北伐の物語の節目に二度、確かな足跡を残している。\n\n第94回、孔明の陣に「永安宮を鎮守する李嚴、子の李豐をして來見せしむ」との報が入る。父の使者として駆けつけた李豐が「特に喜びを報じに來る」と告げると、それは新城の孟達が魏に背いて蜀に内応するという、北伐の戦局を左右しかねない機密であった。李豐はこの重要な報せを孔明のもとへ運ぶ伝令の役を、過たず果たしている。\n\n第101回、父・李嚴が兵糧をめぐる失態で失脚した後、孔明は成都に帰るとその子・李豐を長史に登用する。「積草屯糧し、陣を講じ武を論じ、軍器を整治し、將士を存恤す」――兵糧を蓄え、武器を整え、将士を労わるという後方の支えを担わせたのである。父の罪に連座させず、その子を重用したところに、孔明の人の用い方の一端がうかがえる。\n\n華々しい武功も大局の構想も持たぬが、機密を運ぶ使者として、また北伐を支える兵站の長史として、李豐は蜀漢の屋台骨を地味に支え続けた。表舞台に立つ英雄たちの背後で、軍を回す実務に徹した一人の文官である。"}, {"id": 370, "name": "孫翊", "faction": 2, "role": "武将", "rarity": 1, "weapon": "spear", "kind": "proj", "weaponName": "槍", "d": [0, 1, 0, 1, 0, 0, 0], "p": [0, 0, 0, 0, 2, 0], "scores": {"W": 0.3, "B": 0.05, "S": 0.05, "A": 0.1, "G": 0.26, "K": 0.6}, "stat": {"dmg": 0.52, "area": 0.83, "cd": 1.25, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 0, "pwr": 0.25}, "title": "槍の将", "skill": "槍", "skillDesc": "前方/最寄りの敵を貫く", "voice": "", "hist": "", "chapters": [38], "chapN": 1, "bio": "孫権の弟、丹陽太守、暗殺さる", "profile": "孫権の弟であり、江東孫氏の一族として丹陽太守の座にあった人物。兄の孫策に似た剛勇の士という通説で語られることもあるが、演義に描かれる彼の姿は第三十八回のただ一場面に尽きる。\n\nその本文は彼を容赦なく描く。「翊性剛好酒、醉後嘗鞭撻士卒」——気性は激しく酒を好み、酔っては部下を鞭打つ。この乱暴が身を滅ぼした。丹陽督将の媯覽と郡丞の戴員の二人は常に孫翊を殺そうという心を抱き、その従人である邊洪を心腹に引き入れて謀殺をたくらむ。妻の徐氏が出立の朝に一卦を立てると「其象大凶」と出て、客との酒宴に出ぬよう諫めたが、孫翊は聞かなかった。果たして宴のあと、門外まで従いてきた邊洪が刀を抜き、一刀のもとに孫翊を斬り殺す。\n\n太守という地位にありながら、彼自身が敵を斬る場面も、軍を率いる場面も、政を布く場面も一切描かれない。むしろ近臣の心ひとつ御せず、酒席の乱暴が積もって謀殺を招いた。妻の凶兆の警告を退けて死地に出向いた点も、危うさを際立たせる。\n\n物語の見せ場は、孫翊本人ではなく、夫を喪った妻徐氏の復讐譚へと移っていく。剛勇と謳われた一族の血筋を引きながら、演義の孫翊は自らの事績を一行も残せぬまま、忠ならぬ従者の刃に斃れた悲運の被害者として、その短い登場を終える。"}, {"id": 371, "name": "費詩", "faction": 0, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 1], "p": [0, 0, 0, 2, 1, 1], "scores": {"W": 0.0, "B": 0.25, "S": 0.1, "A": 0.05, "G": 0.55, "K": 0.65}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.1}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [65, 73, 91], "chapN": 3, "bio": "劉璋から降った官員(擢用名簿)", "profile": "蜀漢の文官。もとは劉璋に仕え、劉備の入蜀後に「並皆擢用」された官員の一人として第六十五回の名簿に名を連ねる。武を執る人物ではなく、その本領は弁舌にあった。\n\n費詩の名を演義に刻んだのは第七十三回、漢中王に即位した劉備が前部司馬の彼を使者に立て、関羽に「五虎大将之首」の誥命を届けさせた場面である。荊州に着いた費詩を待っていたのは、自分が黄忠ら老兵と同列に並べられたと知って怒り、印綬を受けようとしない関羽だった。費詩は笑って言う——昔、蕭何と曹参は高祖と大事を挙げた最も親しい近臣であり、韓信はもとは楚の亡将に過ぎなかった。それでも韓信は王に立てられ、蕭何・曹参の上に居たが、二人がそれを怨んだとは聞かない、と。そして「漢中王即將軍也」「不宜計較官號之高下」と諭す。関羽はついに非を悟り、印を受けた。\n\n弁を一つ立てるだけで、たけり立つ古今無双の将を鎮めてみせる——その諍臣・直言の士としての面目は、もう一幕にも現れる。関羽が出師に先立って傅士仁・糜芳を斬ろうとしたとき、費詩は「未曾出師、先斬大將、於軍不利」と諫め、即時の処断を思いとどまらせた。戦の前に大将を斬れば軍に不利、という的確な一言が、無用の混乱を未然に防いだのである。\n\n正史でも諍臣・直言の士として知られる費詩だが、演義に描かれる彼はあくまで一場の説客にとどまる。それでも、剣を一度も抜かずに荊州の空気を動かした口舌は、武の物語が連なる三国の世にあって、確かな存在感を放っている。"}, {"id": 372, "name": "張溫", "faction": 2, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 0], "p": [0, 0, 0, 3, 0, 0], "scores": {"W": 0.0, "B": 0.15, "S": 0.6, "A": 0.5, "G": 0.45, "K": 0.0}, "stat": {"dmg": 0.54, "area": 0.84, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.45}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [8, 38, 43, 86], "chapN": 4, "bio": "呉の文官、舌戦群儒で問難しようとした一人", "profile": "呉の文官。字は惠恕、呉郡呉の人で、中郎将の任にあった。第三十八回では孫権が「敬禮甚厚」と遇した江東の賢士の一人として名を連ね、弁の立つ名士という像で語られがちな人物である。だが演義は、その評判をむしろ裏返しに描いてみせる。\n\n舞台は第八十六回。呉蜀の通好をめぐり、答礼の使者を募る場で、張溫は自ら進み出て「臣願為使」と志願する。「孔明亦人耳、臣何畏彼哉」——孔明とて同じ人間、何を畏れることがあろうか、と豪語した彼を孫権は大いに喜び、重く賞して鄧芝とともに入蜀させた。ところが蜀に着いた張溫は「昂然上殿」「喜笑自若」と傲慢に振る舞い、その鼻を益州の学士・秦宓がへし折る。秦宓の「天辯」の前に張溫はついに一言も返せず、「無言可對」となって席を避け、「不意蜀中多出俊傑」と頭を下げて非を認めるほかなかった。\n\n呉蜀同盟という大事業に使者として加わった点は確かに張溫の務めだが、その通好を実らせたのは孔明と鄧芝の働きであって、張溫自身は弁論で完敗し、外交家としての説得力を見せられぬまま蜀の人材の引き立て役に回った。武の記録は一切持たない純然たる文官であり、口で勝つはずの名士が口で負ける——その意外な転倒が、彼を演義に印象づけている。\n\nなお第八回に登場する董卓に斬られる「司空張溫」は後漢の重臣で、字も役回りも異なる同名の別人である。"}, {"id": 373, "name": "种輯", "faction": 3, "role": "武将", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 0, 0], "p": [0, 0, 0, 1, 2, 0], "scores": {"W": 0.1, "B": 0.05, "S": 0.05, "A": 0.1, "G": 0.41, "K": 0.6}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.1}, "title": "陣の将", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [20, 21, 23], "chapN": 3, "bio": "長水校尉、衣帯詔の同盟者", "profile": "後漢の朝廷に仕える長水校尉。武官の官職にありながら、演義に描かれる种輯は剣を執る将ではなく、漢室に殉じた義士の一人である。\n\nその名が物語に刻まれるのは、曹操打倒を期した衣帯詔の一件においてだ。董承の邸での密議に「心腹」として迎え入れられた种輯は、反曹操の同志結集の場で気概を吐く。王子服の「吾誓殺此賊、恨無助我者耳」という嘆きに、种輯は「為國除害、雖死無怨」——国のために害を除くなら、死すとも怨みはない、と応じた。第二十一回では、董承が掲げる義状にその名が連ねられる。車騎将軍董承を筆頭に六名、その三番目に「長水校尉种輯」と記された。\n\nやがて吉平の毒殺計画が露見し、衣帯詔の一味は曹操の手に落ちる。捕らえられてなお种輯はひるまない。「忠臣不怕死、吾等死做漢鬼、強似你阿附國賊」——忠臣は死を恐れぬ、我らは死して漢の鬼となる、国賊に媚びる貴様よりはるかにましだ、と言い放った。その言葉どおり、彼は董承ら五人とともに一族もろとも処刑された。\n\n戦場での働きも、計略も、本文には一行も描かれない。だが演義は种輯を、漢室の傾きに義を立てて命を捨てた連判の一人として配置している。死を前にした一喝に、武功とは別種の気骨が宿る人物である。"}, {"id": 374, "name": "管輅", "faction": 1, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 0], "p": [0, 0, 0, 0, 0, 1], "scores": {"W": 0.0, "B": 0.15, "S": 0.6, "A": 0.5, "G": 0.12, "K": 0.15}, "stat": {"dmg": 0.54, "area": 0.84, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.45}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [13, 16, 18, 28, 58, 67, 69, 71, 76, 106], "chapN": 11, "bio": "平原の神卜。曹操の運勢や戦況を占う", "profile": "平原の神卜と称された、三国一の占術師。武将でも政治家でもなく、ただ予言の的中だけで物語に機能する特異な人物である。曹操の運勢や戦況を占い、その言葉はことごとく現実となった。\n\n演義は第六十九回に半回を割いて、その異能を描き出す。容貌は粗醜で酒を好む奇人だが、少年の頃から失せた牛の在処を当て、印囊に隠した物を射覆で言い当て、趙顏という若者の寿命さえ延ばしてみせる——「神童」「神卜」と称えられた逸話が連ねられる。曹操が天下の事を占わせると、輅は「三八縱橫、黃豬遇虎、定軍之南、傷折一股」と卜した。果たして第七十一回、定軍山で夏侯淵が戦死し、曹操は「方悟管輅所言」とその的中に慄く。「操見輅言累驗、故不敢輕動」——曹操が軽々しく動けなくなるほど、その予言は当たり続けた。\n\n異能を持ちながら、管輅は徹底して在野に身を置いた。曹操が太吏に封じようとしても「命薄相窮、不稱此職、不敢受也」と固辞し、火災を予言した褒賞も受け取らない。第百六回では何晏・鄧颺の人相を見て「鬼幽」「鬼躁」の相を読み、「二人早晚必有殺身之禍」と破滅を予見した。これも第百七回で「果應管輅之言」と的中する。自らは官に就かず、舅にまで累が及ばぬよう身を慎んだ。\n\n剣も執らず、軍も率いず、政にも与らない。それでいて、彼の口から出る一言が曹操の判断を縛り、名将の死を、王朝の命運を言い当てる。占断の的中という一事だけで物語を動かした、三国志屈指の異色の術士である。"}, {"id": 375, "name": "厳氏", "faction": 3, "role": "婦人", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 1, 0], "p": [0, 0, 0, 2, 0, 2], "scores": {"W": 0.0, "B": 0.15, "S": 0.6, "A": 0.5, "G": 0.54, "K": 0.3}, "stat": {"dmg": 0.54, "area": 0.84, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.75, "pwr": 0.45}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [15, 16, 19], "chapN": 3, "bio": "呂布の正妻、出陣を引き止め敗北を招く", "profile": "呂布の正妻。「悍妻が呂布を惑わせ、その滅亡を早めた」と語られがちな人物だが、演義本文の彼女は武人ではなく、夫の決断に情で介入する閨閣の婦人である。\n\n第十六回、袁術が呂布の娘を我が子の嫁にと縁談を持ちかけたとき、厳氏は娘の将来を読んで言う。「吾聞袁公路久鎮淮南、兵多糧廣、早晚將為天子。若成大事、則吾女有后妃之望」——袁術は淮南に久しく拠り、兵も糧も多く、いずれ天子となろう。事が成れば娘は后妃となれる、と。そして「縱不為皇后、吾徐州亦無憂矣」と、たとえ后にならずとも徐州の憂いは無くなると見て、縁談を是とするよう呂布の決断を促した。一族の婚姻をめぐる打算ではあるが、相手の将来を見定める目の片鱗をのぞかせる場面である。\n\nしかし彼女の名を物語に深く刻むのは、その悲劇的な結末への一手だ。第十九回、曹操に下邳を包囲された呂布が城外へ出て掎角の計を試みようとしたとき、厳氏は涙ながらに引き止める。「將軍若出、陳宮、高順、安能堅守城池。倘有差失、悔無及矣」——あなたが出れば、陳宮や高順だけで城を守りきれましょうか、もし誤れば取り返しがつきません、と。情のこもったこの諫言が呂布を籠城へと向かわせ、結果として滅亡を早めた。\n\n軍を率いる力も、政の実権も、彼女は持たない。ただ夫を案じる情だけで重大な局面に割って入り、その情が皮肉にも破滅の引き金となった。武勇渦巻く呂布の周囲にあって、厳氏は最も人間的な弱さと愛情をもって物語に陰を落とす婦人である。"}, {"id": 376, "name": "韓胤", "faction": 3, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 0], "p": [0, 0, 0, 3, 0, 1], "scores": {"W": 0.0, "B": 0.0, "S": 0.0, "A": 0.0, "G": 0.57, "K": 0.15}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.0}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [16, 17], "chapN": 2, "bio": "袁術の使者・媒人、婚姻交渉。曹操に斬られる", "profile": "袁術配下の文官で、使者・婚姻仲介役を務めた人物。演義での出番は第十六回から第十七回に集中し、他人の計を運ぶ駒として、そして捨て駒として描かれる。\n\n最初の登場は、糧食と密書を呂布のもとへ届ける使者としてである。袁術は劉備を討つにあたり呂布を懐柔しようと、「具粟二十萬斛、令韓胤齎密書往見呂布」と二十万斛の粟を持たせて韓胤を遣わした。続く役回りが、彼の唯一の積極的な働きとなる婚姻の仲立ちだ。「即日遣韓胤為媒、齎禮物往徐州求親」——袁術は韓胤を媒として徐州へ送り、呂布の娘を我が子の嫁にと求めさせる。徐州に着いた韓胤は「主公仰慕將軍、欲求令嬡為兒婦、永結秦晉之好」と口上を述べた。両陣営を往復し、陳宮に縁談を急がされながらも「許了親事」と承諾まで漕ぎ着けた点は、使者として確かに機能している。\n\nだが弁舌は「秦晉之好」という定型句にとどまり、事態を見通す力はなかった。陳宮の催促という危うい兆しを見抜けぬまま縁談をまとめてしまい、呂袁の関係が破れると、韓胤は呂布に捕らえられる。「連韓胤都拏回監禁、不放歸去」——縁談ごと白紙に戻され、本人は監禁された。やがて許都へ送られ、「斬韓胤于市曹」と市場で曹操に斬られて果てる。仕える袁術が僭称の逆賊として描かれるため、その使者である韓胤もまた「反賊焉敢如此」と否定される側に立たされた。\n\n厚遇される場面はあっても、それは武名ゆえではなく使者への接待にすぎない。他人の戦略の運び手として動き、自らの危機さえ回避できぬまま処刑された——韓胤は、乱世に翻弄された脇役文官の典型である。"}, {"id": 377, "name": "黄皓", "faction": 0, "role": "宦官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 0, 0], "p": [0, 2, 0, 0, 0, 1], "scores": {"W": 0.1, "B": 0.05, "S": 0.05, "A": 0.1, "G": 0.52, "K": 0.55}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.1}, "title": "宦官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [112, 113, 115, 116, 117, 118, 119, 120], "chapN": 8, "bio": "蜀の中常侍。後主に寵愛され専権、亡国の元凶。最後は司馬昭に処刑される", "profile": "蜀漢末期の中常侍。後主劉禅に寵愛されて専権をふるい、亡国の元凶と評される宦官である。演義の通説像「蜀を滅ぼした奸宦」は、本文にも忠実に描かれる。\n\n注目すべきは、黄皓が自ら一兵も動かさず、ただ「奏言と隠匿」だけで国を傾けた点だ。後主は「不理國事、只圖歡樂」と政を顧みず、黄皓はその寵を背景に権を握る。第百十五回では、寸功もない右将軍の閻宇が「只因阿附黃皓、遂得重爵」と、ただ黄皓に阿ったがゆえに重爵を得て、祁山で戦う姜維を退けて代えようと画策する。前後して黄皓は讒言によって姜維を召還し(第百十三回)、師婆の託宣を信じて姜維の度重なる告急表を握りつぶした。「姜維履申告急表文、皆被黃皓隱匿、因此誤了大事」(第百十六回)——危機の知らせを隠蔽し、大事を誤らせたのである。鄧艾来襲の報さえ「詐傳」と退け(第百十七回)、蜀の防備を内側から空洞化させた。\n\n恐れられたのは黄皓ではなく、むしろ姜維が「我必殺此宦豎」と激怒すると、黄皓は「急避於湖山之側」と怯えて逃げ隠れた。姜維は後主に「黃皓奸巧專權、乃靈帝時十常侍也」「近則鑒於張讓、遠則鑒於趙高」と、漢を滅ぼした宦官になぞらえて諫めたが、その讒言と隠匿は止まらず、官僚の間に「避禍之心」を生んで蜀の結束を内から崩していった。\n\n蜀漢が滅びると、その報いが下る。「昭因黃皓蠹國害民、令武士押出市曹、凌遲處死」(第百十九回)——国を食い民を害したとして、司馬昭は黄皓を市場に引き出させ、凌遅の刑に処した。剣も計略も持たず、ただ君寵を盾に讒言と隠蔽を重ねるだけで一国を傾けてみせた——黄皓は、武力とは別の形で物語を動かした、滅亡を象徴する奸臣である。"}, {"id": 378, "name": "韓玄", "faction": 3, "role": "君主", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 1, 0, 0], "p": [0, 0, 0, 0, 1, 0], "scores": {"W": 0.1, "B": 0.5, "S": 0.3, "A": 0.45, "G": 0.13, "K": 0.3}, "stat": {"dmg": 0.54, "area": 0.83, "cd": 1.24, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.45}, "title": "君主", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [41, 53, 70], "chapN": 3, "bio": "長沙太守、行き場を失った魏延が身を寄せる", "profile": "長沙太守。劉表の死後にその地を継いだ群雄の一人で、行き場を失った魏延が一時身を寄せた相手でもある。通説では「無能で残虐な暗君」、黄忠を斬ろうとして魏延に殺される噛ませ役として知られる。\n\n演義本文も、おおむねこの像を裏づける。「平生性急、輕於殺戮、眾皆惡之」——気が短く、軽々しく人を斬り、誰もが彼を憎んだ。第五十三回、関羽が長沙へ攻め寄せると、韓玄は配下の楊齡や老将黄忠に出戦を任せ、自らは「玄自來城上觀看」と城上から戦を眺めるばかりである。黄忠が関羽と「戰一百餘合、不分勝負」と渡り合う中、「韓玄恐黃忠有失、鳴金收軍」と金を鳴らして兵を収めた——これが彼の数少ない戦場での指示だった。\n\n破滅は内から来る。韓玄は黄忠が敵に内通したと疑い、「若不斬汝、必為後患」と軍令で処断しようと刀斧手に引き出させる。実のところ黄忠は関羽に義気を示しており、その疑い自体が完全な見当違いとは言い切れないのだが、ここで魏延が立ち上がる。かつて「傲慢少禮」と嫌われ重用されなかった魏延は、百姓と諸将を煽り「黃漢升乃長沙之保障、今殺漢升、是殺長沙百姓也。韓玄殘暴不仁、輕賢慢士、當眾共殛之」と叫んで反乱を起こした。誰も韓玄を守ろうとせず、百姓までもが彼を殺す側に回り、城内で斬殺される。\n\n外敵の到来という危機に、内部の功臣を疑って斬ろうとし、自ら内乱を招いて滅んだ——韓玄は、軍と民を完全に離反させた「人心を失う暗君」の見本として描かれる。地位の形だけを残し、それを支える人望をすべて失っていた太守の、あっけない最期である。"}, {"id": 379, "name": "茍安", "faction": 0, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 0, 0], "p": [0, 1, 0, 0, 0, 1], "scores": {"W": 0.0, "B": 0.45, "S": 0.25, "A": 0.35, "G": 0.32, "K": 0.35}, "stat": {"dmg": 0.53, "area": 0.83, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.35}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [100, 101], "chapN": 2, "bio": "李嚴配下の都尉、糧運怠慢で罰され魏に降り流言を流す", "profile": "蜀の李厳配下の都尉。第四次北伐を内側から潰す触媒として機能した、裏切りと讒言の道具である。武勇も指揮も持たず、恨みから敵に降って流言を流した小人として描かれる。\n\nことの始まりは兵糧輸送だった。第百回、李厳が茍安に糧米を運ばせたが、「茍安好酒、於路怠慢、違限十日」——酒好きの彼は道中で怠け、期限を十日も過ぎてしまう。孔明は「軍中專以糧為大事、誤了三日、便該處斬」と激怒し、推し出して斬れと命じた。周囲のとりなしで「仗八十放之」と八十叩きで赦されたものの、茍安はこれを深く恨み、「連夜引親隨五六騎、逕奔魏寨投降」と、その夜のうちに数騎を引き連れて魏の陣へ寝返った。\n\n魏では司馬懿が彼を使う。「汝可回成都布散流言、說孔明有怨上之意、早晚欲稱為帝、使汝主詔回孔明、便是汝之功」——成都へ戻って孔明が帝位をうかがっているという流言を流し、後主に孔明を召還させれば、それがお前の手柄だ、と。茍安は成都へ戻ると宦官を通じて「孔明自倚大功、早晚必將篡國」という讒言をばらまく。これに驚いた宦官が後主に奏上し、孔明はついに北伐を中断して召還される。司馬懿の離間の計が、茍安という駒を通じて見事に効いたのである。\n\nだが流言はやがて露見する。「孔明遂喚眾宦官究問、方知是茍安流言、急令人補之、已投魏國去了」(第百一回)——孔明が宦官を問い質して真相を知り、捕えようとしたときには、茍安はすでに魏へ逃げ去っていた。\n\n自らの能力で何かを成したわけではない。兵糧を失敗させ、罰を恨み、敵の計の実行役となって流言を流しただけの男だ。それでも、その一つの裏切りが孔明の北伐を頓挫させた——茍安は、小人一人の讒言が大局を揺るがす、乱世の不気味さを体現する人物である。"}, {"id": 380, "name": "戴員", "faction": 2, "role": "文官", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 0, 0], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 0.0, "B": 0.45, "S": 0.25, "A": 0.35, "G": 0.0, "K": 0.0}, "stat": {"dmg": 0.53, "area": 0.83, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.35}, "title": "文官", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [38], "chapN": 1, "bio": "郡丞、孫翊謀殺の共犯、徐氏に討たる", "profile": "呉の丹陽郡丞、すなわち郡の次官を務めた文官である。といっても演義に名が残るのは、その職を全うしたからではない。主君を裏切った謀反人として、ただ一章にだけその姿を刻んでいる。\n\n第三十八回。丹陽の督將・媯覽とともに、戴員は太守孫翊を弒する陰謀をめぐらせる。孫翊の従者・邊洪を心腹に引き入れ、隙を突いて孫翊を討たせると、二人は手のひらを返して邊洪に罪を着せ、市で斬って口を封じた。そのうえで主君の家財と侍妾までも略奪する。背信に背信を重ねる、典型的な簒奪者の所業であった。\n\nだが、孫翊の妻・徐氏がただの婦人ではなかった。夫の死を悲しむふりをして喪服を解き、孫高・傅嬰の二将を伏せて媯覽と戴員を別々の宴に誘い出す。戴員が府に入り堂の中ほどまで進んだところで、伏兵が躍り出て斬り伏せた。罠を見抜くことすらできぬ、あっけない最期であった。\n\n徐氏は再び喪服をまとい、媯覽と戴員の首級を孫翊の霊前に供えて夫の仇を討つ。後世、この一件を詠んだ詩は彼を「庸臣賊に従う」と断じ、忠臣の死に対して東呉の女丈夫の見事さを際立たせる引き立て役として記憶した。戴員の名は、裏切りの愚かさと女性の烈しさを語るための一筆として、演義に残されている。"}, {"id": 381, "name": "黄承彦", "faction": 3, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 1, 0, 0], "p": [0, 0, 0, 1, 0, 2], "scores": {"W": 0.0, "B": 0.45, "S": 0.25, "A": 0.35, "G": 0.39, "K": 0.3}, "stat": {"dmg": 0.53, "area": 0.83, "cd": 1.24, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.35}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [37, 84, 117], "chapN": 3, "bio": "孔明の岳父、雪中に驢に乗り詩を詠む", "profile": "諸葛孔明の岳父にして、襄陽に隠れ住む高士。武人でも官人でもなく、世を避けて風雅に生きる隠逸の人である。演義に登場するのはわずか三章だが、そのどれもが彼の人となりを静かに照らし出している。\n\n最初に姿を見せるのは第三十七回。劉備が二度目に草廬を訪ねた帰り、風雪のなか驢に乗ってゆらりと現れ、橋のほとりで梅花を吟ずる老人がいる。劉備はこれを孔明かと早合点するが、それが孔明の岳父・黄承彦であった。雪中に梅を詠む――その一場面だけで、彼がどれほど浮世離れした雅人かが伝わってくる。\n\n最も印象深いのは第八十四回である。陸遜が蜀軍を追って白帝城近くまで攻め込んだとき、孔明がかつて布いた八陣図の石組みに迷い込み、出口を失って絶体絶命に陥る。そこへ杖をつき、ゆるゆると石陣の間を何の障りもなく歩き出てきたのが黄承彦だった。「老夫、平生善を好む」と語り、陸遜が死門から入ったのを見るに忍びず、生門から導き出してやる。孔明が臨終に「呉の大将が陣に迷っても出してやるな」と言い残した遺命を、あえて翻しての慈悲であった。救われた陸遜は慌てて馬を下り、拝謝して兵を退いた。\n\n孔明の遺託を託される唯一の人物であり、その善意が結果として呉軍の追撃を止めるという、戦の流れすら左右する一場面を生んだ。第百十七回では諸葛瞻の母方の祖父として名が触れられるのみだが、終始一貫して風流と好善の隠者として描かれた黄承彦は、英雄たちの修羅のなかにあって、ひときわ清らかな余白として演義に佇んでいる。"}, {"id": 382, "name": "于吉", "faction": 3, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 3, 0, 0, 0], "p": [0, 0, 2, 0, 0, 0], "scores": {"W": 0.3, "B": 0.15, "S": 0.15, "A": 0.3, "G": 0.36, "K": 0.0}, "stat": {"dmg": 0.52, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.74, "crit": 0.07, "duration": 2.5, "pwr": 0.3}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [29], "chapN": 1, "bio": "江東の道士、孫策に斬られ祟りとなって孫策を死に至らしめる", "profile": "江東に現れた瑯琊宮の道士であり、演義では「神仙」として描かれる超常の人物。符水をもって万病を癒し、雨を祈っては甘雨を降らせ、人々から篤く敬信された。武人でも将でもないが、その存在は江東の覇者・孫策の運命を根底から揺さぶることになる。\n\n物語の核は第二十九回にある。于吉が市中を歩けば、官民こぞって香を焚き地に伏して拝む。これを見た孫策は、人心を惑わす妖人と断じて捕らえる。折しも長く雨が降らず旱に苦しんでいた折、于吉は「我れ三尺の甘霖を求め、もって万民を救わん。然れども我れ終に一死を免れず」と告げ、雨を祈ると果たして三尺の甘雨が大地を潤した。万民は歓喜し、于吉のために助命を願う。だが孫策はかえって己の権威が脅かされることを恐れ、ついに于吉を斬らせた。\n\nここから演義屈指の怪異が始まる。斬られた于吉は怨霊となって孫策につきまとう。鏡に映る己の背後に于吉の姿を見た孫策は、剣を抜こうとしてそのまま昏倒する。以後、形容は日に日に憔悴し、傷口は破れ、ついに二十六歳の若さで世を去った。江東の小覇王と謳われた猛将が、一人の道士の祟りに斃れたのである。\n\n戦も指揮も知らぬ于吉が、演義の数ある豪傑のなかでも有数の「最期の凄み」を残したのは皮肉といえる。雨を呼んで万民を救う慈悲と、斬られてなお仇を討つ怨念――その二面が、孫策の死という大きな転換点に深い陰影を与えている。神仙の怪異譚として、于吉の名は永く語り継がれてきた。"}, {"id": 383, "name": "諸葛均", "faction": 3, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 0], "p": [0, 0, 1, 1, 0, 0], "scores": {"W": 0.0, "B": 0.0, "S": 0.0, "A": 0.0, "G": 0.33, "K": 0.0}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.0}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [36, 37, 38], "chapN": 3, "bio": "孔明の弟、隆中で躬耕", "profile": "諸葛孔明の実弟。隆中に兄とともに隠れ住み、田を耕して暮らす農夫である。天下にその名を知られた兄の影に隠れ、演義での出番も三顧の礼の場面に限られるが、あの名高い物語の傍らに静かに立つ脇役として、確かにその姿を留めている。\n\n第三十六回から第三十八回にかけて、劉備が三たび草廬を訪れる。そのたびに兄孔明は不在で、応対するのが弟の諸葛均であった。第三十七回では、雪のなか訪ねてきた劉備に「家兄は不在にて、車騎を久しく留め置くに忍びず。日を改めてこちらより返礼に参ります」と礼を尽くして迎え、文房四宝を進めて茶を勧める。兄の韜略を問われても「知らず」と謙虚に答えるばかりで、自らを語ろうとはしない。\n\n第三十八回でようやく劉備が孔明に会えたとき、孔明は出仕にあたって弟に「お前はここで田を耕し、田畝を荒らすことのないように」と言い残す。兄が天下に飛び立つのを、均は黙って田を守ることで支えた。張飛からは礼を知らぬと軽んじられる場面もあるが、終始一貫して、賓客に礼を尽くし、農を守る実直な人物として描かれている。\n\n派手な活躍も、語るべき武勲もない。だが三顧の礼という蜀漢創業の原点に、兄を待ち続ける弟がいたこと――その控えめな存在が、臥龍を世に送り出す物語に確かな奥行きを添えている。諸葛均は、英雄の物語を縁の下で支える者として、演義にその名を残した。"}, {"id": 384, "name": "甄氏", "faction": 1, "role": "婦人", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 0], "p": [0, 0, 0, 0, 1, 0], "scores": {"W": 0.0, "B": 0.0, "S": 0.0, "A": 0.0, "G": 0.13, "K": 0.3}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.0}, "title": "佳人", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [33, 91], "chapN": 2, "bio": "袁熙の妻、曹丕が娶る傾国の美女", "profile": "もとは袁紹の次男・袁熙の妻であり、後に魏の曹丕に娶られた傾国の美女。曹叡（明帝）の生母にして、死後に文昭皇后を追謚された女性である。後世には曹植の「洛神賦」のモデルとも語られる艶やかな伝承に彩られるが、演義本文のなかでは、自らの言葉も意志も与えられぬ受動の人として描かれている。\n\n最初の登場は第三十三回。曹操が袁氏の本拠・鄴城を陥としたとき、城内に取り残された一人の女がいた。玉のような肌、花のかんばせ、まさに「傾国の色」である。これを見初めたのが曹操の子・曹丕で、彼女を己のものとした。乱世の勝者が敗者の妻を奪うという、戦の非情がこの一場面に凝縮されている。\n\n二度目の登場は遠く第九十一回。すでに曹叡を生み、魏の後宮にあった甄氏だが、皇后の座を狙う郭貴妃の讒言の標的となる。桐の木で人形を彫って呪詛したという壓鎮の罪を着せられ、寵を失い、ついに死を賜った。栄華の頂にありながら、後宮の権力闘争に巻き込まれてあえなく散ったのである。\n\n子の曹叡が帝位に即くと、父曹丕に文皇帝、母甄氏に文昭皇后の謚を贈った。生前は何一つ自らの意志で動けなかった甄氏が、死してのち皇統の母として正統性の象徴に組み込まれる――そこにこの女性の運命の悲しみがある。傾国の美貌ゆえに奪われ、後宮の闇に呑まれて消えた甄氏は、乱世に翻弄された佳人として、演義に淡くも忘れがたい影を落としている。"}, {"id": 385, "name": "曹熊", "faction": 1, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 0], "p": [0, 0, 0, 0, 1, 0], "scores": {"W": 0.0, "B": 0.0, "S": 0.0, "A": 0.0, "G": 0.13, "K": 0.3}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.0}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [78, 79], "chapN": 2, "bio": "曹操の四子(卞氏所生)", "profile": "曹操の四男で、母は卞氏。曹丕・曹彰・曹植という名だたる兄たちの末に連なる皇子だが、演義に与えられた役割はあまりに薄い。生まれつき病弱で、後継を争う器とはみなされず、影のように物語を通り過ぎてゆく。\n\n第七十八回、曹操が己の死を前に後事を案ずる場面で、四子曹熊は「多病にして保ち難し」と評され、ただ名を挙げられるだけで後継候補から外される。彼自身が何かを語ることも、動くこともない。生まれもった病が、彼の存在を最初から物語の隅へと押しやっていた。\n\n第七十九回、曹操が世を去り曹丕が後を継ぐと、各地の諸侯や兄弟は喪に駆けつけねばならなかった。だが蕭懷侯に封じられていた曹熊は奔喪せず、兄曹丕の問罪を恐れるあまり、自ら首を縊って死を選んでしまう。罪を問われる前に、恐怖に追い詰められての自滅であった。\n\n死後、曹丕は曹熊に蕭懷王を追贈した。曹操の子という血統と封侯の名は形のうえで備わっていたが、彼はその正統性を一度も行使することなく、自らの命すら保てずに世を去った。豪傑ひしめく曹一族のなかで、最も儚く消えた皇子――曹熊の名は、権力の中枢に生まれながら何も成せなかった者の影として、わずかに演義に留められている。"}, {"id": 386, "name": "曹嵩", "faction": 3, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 0, 0, 0, 0], "p": [0, 0, 0, 0, 1, 0], "scores": {"W": 0.0, "B": 0.0, "S": 0.0, "A": 0.0, "G": 0.13, "K": 0.3}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 2.5, "pwr": 0.0}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [1, 5, 10, 11, 56], "chapN": 5, "bio": "曹操の父、徐州への道中で殺される", "profile": "曹操の実父である。もとの姓は夏侯氏だったが、中常侍・曹騰の養子となった縁で曹姓を名乗った。乱世の英雄を生んだ父でありながら、本人は終始、戦とも政とも無縁の受け身の人物として描かれる。その死が、息子の歴史を大きく動かすことになる。\n\n第一回では、幼い曹操が叔父の讒言を逃れるために中風を装ってみせ、まんまと騙される父として登場する。すでにこの時点で、曹嵩は息子の知略に翻弄される存在として位置づけられていた。\n\n彼の運命が決するのは第十回である。陳留を避けて瑯琊に隠居していた曹嵩は、兗州の曹操のもとへ向かうべく、一家四十余人と従者百余人、車百余輛を連ねて旅立つ。道中、徐州を通った際には太守陶謙が曹操に取り入る好機とばかりに手厚く饗応した。しかし護送を任された張闓ら黄巾の余党は、その輜重車の山なす財貨に目がくらむ。「曹嵩一家を殺して財を奪えば富貴は容易い」と謀り、夜半に襲いかかった。曹嵩は肥えた妾を連れて方丈の裏へ逃げ、塀を越えようとするも、妾が太って越えられない。やむなく厠に隠れたところを、乱軍に斬り殺された。\n\nこの惨劇は、息子曹操の心に消えぬ憎悪を刻んだ。曹嵩の死は徐州征伐の大義名分となり、曹操は陶謙を討つべく徐州の地に大虐殺を引き起こす。第十一回では劉備の書中に「曹侯」と侯位を冠して呼ばれ、その死が政争の口実として利用される。自らは一兵も動かさず、財ゆえに命を落とした老父の最期が、乱世の大きな血の流れの引き金となった――曹嵩は、そうした宿命の役回りを担って演義に名を残している。"}, {"id": 387, "name": "秦慶童", "faction": 3, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 1, 0, 0, 0, 0], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 0.25, "B": 0.0, "S": 0.0, "A": 0.0, "G": 0.0, "K": 0.0}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.67, "crit": 0.04, "duration": 2.5, "pwr": 0.0}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [23], "chapN": 1, "bio": "董承の家奴、密通を咎められた恨みで曹操に密告する", "profile": "国舅・董承に仕えた一人の家奴。演義第二十三回にのみ姿を見せる小人物だが、その一度きりの登場で、漢室復興を賭けた密謀を根こそぎ崩壊させる引き金を引いた、忘れがたい裏切り者である。\n\n事の起こりは私怨であった。秦慶童は董承の侍妾・雲英と密通していたところを主人に見咎められ、笞で打たれ、鎖につながれて幽閉される。恨みを募らせた彼は、夜陰に乗じて鉄の鎖を引きちぎり、塀を越えて逃げ出した。その足で向かった先が、曹操の屋敷である。\n\n秦慶童が曹操に告げたのは、董承ら一同が漢帝の血詔――衣帯詔を受け、曹操誅滅を誓った謀反の盟であった。家奴の一言が、忠臣たちの命運を決した。曹操は董承の屋敷を捜索させて連判状を押収し、対質の場では秦慶童に証言させて謀の全容を暴く。かくして董承をはじめとする盟約者の一門はことごとく誅され、衣帯詔の企ては露と消えた。\n\n武勲もなく、智略もなく、ただ主家を売った一人の下僕。だがその密告がもたらした波紋は、漢室の最後の抵抗を打ち砕き、曹操の専横をいっそう強めるという、物語上きわめて重い結果を生んだ。私的な恨みが天下の流れを変えてしまう――秦慶童は、乱世における小さな裏切りの大きな代償を体現する人物として、演義に刻まれている。"}, {"id": 388, "name": "華佗", "faction": 3, "role": "その他", "rarity": 1, "weapon": "array", "kind": "field", "weaponName": "陣", "d": [0, 0, 0, 1, 0, 0, 0], "p": [0, 0, 0, 0, 0, 1], "scores": {"W": 0.1, "B": 0.05, "S": 0.05, "A": 0.1, "G": 0.12, "K": 0.15}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.65, "crit": 0.05, "duration": 2.5, "pwr": 0.1}, "title": "群雄", "skill": "陣", "skillDesc": "周囲を縛る軍略の陣", "voice": "", "hist": "", "chapters": [15, 29, 75, 78], "chapN": 4, "bio": "名医、中原に去っていて孫策を治療できない", "profile": "後漢末の名医にして、演義では「当世の神医」と讃えられる人物。童顔鶴髪、飄然として世を超えた風姿をたたえ、陣営の別を問わず病を癒した。武も将も政も知らぬが、その医術の超越ぶりは、いかなる豪傑にも劣らぬ輝きを放っている。\n\n華佗の名を不朽にしたのが、第七十五回の「刮骨療毒」である。関羽が樊城攻めの最中、右腕に毒矢を受け、毒が骨にまで達して腕が利かなくなった。華佗はこれを診て、刀で皮肉を裂き、骨にまで及んだ毒を削り取らねば治らぬと告げる。関羽は平然と酒を飲み、馬良と碁を打ちながら腕を差し出した。華佗が骨を刮る刀の音が「悉悉」と響き、流れる血は盆にあふれたが、関羽は談笑して顔色一つ変えない。華佗は思わず嘆じた、まことに天神のごとき人だと。医の妙技と武人の胆力が火花を散らす、演義屈指の名場面である。\n\nだがその超絶の技が、華佗自身の死を招く。第七十八回、頭風に悩む曹操が華佗を召すと、華佗は斧で頭蓋を開いて病の根を取り除くべしと進言した。猜疑の塊である曹操はこれを暗殺の謀と疑い、「貴様、孤を殺す気か」と激怒して獄に下す。獄中、死を悟った華佗は秘伝の医書「青嚢書」を世に遺そうと、看守の呉押獄にこれを託した。\n\nしかし運命は非情であった。華佗の死後、その書は呉押獄の妻によって焼かれてしまい、神医の術はこの世から永遠に失われる。一身に天下無双の医術を宿しながら、権力者の猜疑に斃れ、遺そうとした叡智すら灰となって消えた――華佗の生涯は、才ある者の悲運と、それを容れぬ乱世の冷たさを、痛切に物語っている。"}, {"id": 389, "name": "蔡中", "faction": 1, "role": "武将", "rarity": 1, "weapon": "sword", "kind": "arc", "weaponName": "剣", "d": [0, 0, 0, 0, 0, 0, 0], "p": [0, 0, 0, 0, 0, 0], "scores": {"W": 0.0, "B": 0.0, "S": 0.0, "A": 0.0, "G": 0.0, "K": 0.0}, "stat": {"dmg": 0.5, "area": 0.8, "cd": 1.25, "amount": 1, "knock": 0.6, "crit": 0.04, "duration": 0, "pwr": 0.0}, "title": "剣の将", "skill": "剣", "skillDesc": "前方を扇状に薙ぎ払う", "voice": "", "hist": "", "chapters": [34, 40, 46, 47, 49, 50], "chapN": 6, "bio": "蔡瑁の族弟、曹操の命で呉に詐降する内応者、烏林で甘寧に斬られる", "profile": "荊州の水軍を率いた蔡瑁の族弟であり、曹操配下の副将。赤壁の戦いにおいて、東呉へ送り込まれた詐降の奸細として知られる。常に弟分の蔡和と一対で描かれ、独立した武勲を持たぬまま、火攻の捨て駒として生涯を終える役回りの人物である。\n\n第四十六回、曹操は荀攸の献策を容れ、兄蔡瑁の仇討ちを口実に蔡中・蔡和を東呉へ偽りの降伏に向かわせる。二人は周瑜の前で「我が兄は罪なくして曹賊に殺された。仇を報いんがため投降する」と涙ながらに拝した。だが、その底はとうに見透かされていた。魯肅は「この降は詐りでしょう、用いてはなりません」と進言する。それでも周瑜はあえて知らぬふりをして二人を受け入れ、逆にこちらの偽の情報を曹操へ流させる「将計就計」の道具として利用した。\n\n蔡中はそうとも知らず、闞澤が黄蓋の苦肉の計を持ち込んだ際にも、せっせと曹操へ通報する。だがそれこそが周瑜の狙いであり、彼は敵を欺くための駒として最後まで踊らされていた。第五十回、烏林での総攻めの夜、甘寧は降将となっていた蔡中を案内役として曹操の陣の奥深くまで引き入れ、頃合いを見て一刀のもとに馬から斬り落とすと、草に火を放った。詐降の奸細は、自ら導いた炎の口火とともに葬られたのである。\n\n個人の武勇を示す見せ場もなく、知略を巡らす場面もなく、終始他者の計略に操られて散った端役。だが赤壁という三国志最大の決戦のただなかで、敵味方双方の謀略が交錯する結節点に置かれた蔡中の存在は、あの壮大な火計がいかに緻密な騙し合いの果てに成ったかを、雄弁に物語っている。"}];
window.WTYPE = {"sword": {"kind": "arc", "jp": "剣"}, "spear": {"kind": "proj", "jp": "槍"}, "halberd": {"kind": "orbit", "jp": "戟"}, "podao": {"kind": "arc", "jp": "大刀"}, "twin": {"kind": "arc", "jp": "双"}, "bow": {"kind": "proj", "jp": "弓"}, "crossbow": {"kind": "proj", "jp": "弩"}, "chakram": {"kind": "proj", "jp": "戦輪"}, "mace": {"kind": "nova", "jp": "剛"}, "axe": {"kind": "arc", "jp": "斧"}, "charge": {"kind": "dash", "jp": "突撃"}, "summon": {"kind": "summon", "jp": "伏兵"}, "fire": {"kind": "zone", "jp": "火計"}, "array": {"kind": "field", "jp": "陣"}};
